function sod_has_arabic_chars(string $text): bool {
    return $text !== '' && preg_match('/\p{Arabic}/u', $text) === 1;
}

function sod_fix_mojibake_text($value): string {
    $text = trim((string)$value);
    if ($text === '') return '';

    $normalized = preg_replace('/\s+/u', ' ', $text);
    if (!is_string($normalized)) $normalized = $text;
    $text = trim($normalized);

    if (sod_has_arabic_chars($text)) return $text;
    if (!preg_match('/[ÃâØÙÐð]/u', $text) && strpos($text, '�') === false) return $text;

    $candidates = [];
    if (function_exists('iconv')) {
        $c1 = @iconv('Windows-1252', 'UTF-8//IGNORE', $text);
        if (is_string($c1) && $c1 !== '') $candidates[] = $c1;
        $c2 = @iconv('ISO-8859-1', 'UTF-8//IGNORE', $text);
        if (is_string($c2) && $c2 !== '') $candidates[] = $c2;
    }
    if (function_exists('mb_convert_encoding')) {
        $c3 = @mb_convert_encoding($text, 'UTF-8', 'Windows-1252');
        if (is_string($c3) && $c3 !== '') $candidates[] = $c3;
        $c4 = @mb_convert_encoding($text, 'UTF-8', 'ISO-8859-1');
        if (is_string($c4) && $c4 !== '') $candidates[] = $c4;
    }
    if (function_exists('utf8_encode')) {
        $c5 = @utf8_encode($text);
        if (is_string($c5) && $c5 !== '') $candidates[] = $c5;
    }
    foreach ($candidates as $fixed) {
        $fixed_norm = preg_replace('/\s+/u', ' ', $fixed);
        if (is_string($fixed_norm)) $fixed = trim($fixed_norm);
        if (sod_has_arabic_chars($fixed) || !preg_match('/[ÃâØÙÐð]/u', $fixed)) {
            return $fixed;
        }
    }

    return $text;
}

function sod_normalize_string_list(array $values): array {
    $out = [];
    $seen = [];
    foreach ($values as $value) {
        $value = sod_fix_mojibake_text($value);
        if ($value === '') continue;
        $key = function_exists('mb_strtolower') ? mb_strtolower($value, 'UTF-8') : strtolower($value);
        if (isset($seen[$key])) continue;
        $seen[$key] = true;
        $out[] = $value;
    }
    return $out;
}

function sod_json_flags(): int {
    $flags = 0;
    if (defined('JSON_UNESCAPED_UNICODE')) $flags |= JSON_UNESCAPED_UNICODE;
    if (defined('JSON_INVALID_UTF8_SUBSTITUTE')) $flags |= JSON_INVALID_UTF8_SUBSTITUTE;
    return $flags;
}

function sod_send_json_success($data = null, int $status_code = 200): void {
    wp_send_json_success($data, $status_code, sod_json_flags());
}

function sod_send_json_error($data = null, ?int $status_code = null): void {
    wp_send_json_error($data, $status_code, sod_json_flags());
}

function sod_contains_mojibake_markers(string $text): bool {
    return $text !== '' && !sod_has_arabic_chars($text) && preg_match('/[ØÙÃÐï¿½]/u', $text) === 1;
}

function sod_prepare_json_payload($value) {
    if (is_string($value)) {
        return sod_fix_mojibake_text($value);
    }
    if (!is_array($value)) {
        return $value;
    }

    $out = [];
    foreach ($value as $key => $item) {
        $fixed_key = is_string($key) ? sod_fix_mojibake_text($key) : $key;
        $out[$fixed_key] = sod_prepare_json_payload($item);
    }
    return $out;
}

function sod_clean_bank_value($value): string {
    $value = sod_fix_mojibake_text($value);
    $value = wp_strip_all_tags((string)$value);
    $value = preg_replace('/[\x{200B}-\x{200F}\x{202A}-\x{202E}\x{2066}-\x{2069}]/u', '', $value);
    $value = preg_replace('/\s+/u', ' ', $value);
    if (!is_string($value)) return '';
    return trim($value, " \t\n\r\0\x0B,.;:|/\\-–—()[]{}\"'`…");
}

function sod_is_valid_bank_value(string $canonical, string $value): bool {
    $value = sod_clean_bank_value($value);
    if ($value === '') return false;
    if (sod_contains_mojibake_markers($value)) return false;
    if (preg_match('/^(?:[\p{P}\p{S}\d\s]+)$/u', $value)) return false;
    if (preg_match('/https?:|www\.|admin-ajax|<script|<\/|^\W+$/iu', $value)) return false;
    if (preg_match('/\b\d{1,2}[-\/]\d{1,2}[-\/]\d{2,4}\b/u', $value)) return false;
    if (preg_match('/[#@]/u', $value)) return false;
    if (sod_safe_substr($value, 0, 1) === ',' || sod_safe_substr($value, -1, 1) === ',') return false;

    $word_count = count(array_filter(preg_split('/\s+/u', $value)));
    $len = sod_safe_strlen($value);
    $slash_count = substr_count($value, '/');
    $comma_count = substr_count($value, ',');

    if ($canonical === 'targets') {
        if ($len > 70 || $word_count > 8 || $comma_count > 3 || $slash_count > 3) return false;
        if (preg_match('/(?:المناطق المتأثرة|استهداف|الماضي|اليوم|هذا اليوم|خسائر بشرية|من دون|وقد|وأدى|ظهر اليوم)/u', $value)) return false;
        return true;
    }

    if ($canonical === 'regions') {
        if ($len > 40 || $word_count > 5 || $comma_count > 1 || $slash_count > 2) return false;
        return true;
    }

    if (in_array($canonical, ['actors', 'contexts', 'intents', 'weapons', 'types', 'levels'], true)) {
        if ($len > 60 || $word_count > 6 || $comma_count > 2 || $slash_count > 2) return false;
        return true;
    }

    return $len <= 60;
}

function sod_filter_bank_values(array $values, string $canonical): array {
    $out = [];
    $seen = [];
    foreach ($values as $value) {
        $value = sod_clean_bank_value($value);
        if (!sod_is_valid_bank_value($canonical, $value)) continue;
        $key = function_exists('mb_strtolower') ? mb_strtolower($value, 'UTF-8') : strtolower($value);
        if (isset($seen[$key])) continue;
        $seen[$key] = true;
        $out[] = $value;
    }
    return $out;
}

function sod_safe_strlen($text): int {
    $text = (string)$text;
    if (function_exists('mb_strlen')) return (int)mb_strlen($text, 'UTF-8');
    return strlen($text);
}

function sod_safe_substr($text, int $start, int $length): string {
    $text = (string)$text;
    if (function_exists('mb_substr')) return (string)mb_substr($text, $start, $length, 'UTF-8');
    return (string)substr($text, $start, $length);
}

function sod_repair_option_payload($value) {
    if (is_string($value)) return sod_fix_mojibake_text($value);
    if (!is_array($value)) return $value;

    $out = [];
    foreach ($value as $key => $item) {
        $fixed_key = is_string($key) ? sod_fix_mojibake_text($key) : $key;
        $out[$fixed_key] = sod_repair_option_payload($item);
    }
    return $out;
}

function sod_self_heal_mojibake_options(): void {
    static $done = false;
    if ($done) return;
    $done = true;

    $flag = 'sod_mojibake_self_heal_v4';
    if (get_option($flag, 0)) return;

    $option_keys = [
        'sod_bank_actors',
        'sod_bank_targets',
        'sod_bank_contexts',
        'sod_bank_intents',
        'sod_bank_weapons',
        'sod_bank_types',
        'sod_bank_levels',
        'sod_bank_regions',
        'sod_visible_learning_banks',
        'so_focus_regions',
        'so_exec_reports_footer',
    ];

    $canonical_map = [
        'sod_bank_actors' => 'actors',
        'sod_bank_targets' => 'targets',
        'sod_bank_contexts' => 'contexts',
        'sod_bank_intents' => 'intents',
        'sod_bank_weapons' => 'weapons',
        'sod_bank_types' => 'types',
        'sod_bank_levels' => 'levels',
        'sod_bank_regions' => 'regions',
    ];

    foreach ($option_keys as $option_key) {
        $current = get_option($option_key, null);
        if ($current === null) continue;
        $fixed = sod_repair_option_payload($current);
        if (is_array($fixed)) {
            foreach ($fixed as $k => $vals) {
                $canon = $canonical_map[$option_key] ?? sod_normalize_bank_key((string)$k);
                if (is_array($vals)) {
                    $fixed[$k] = sod_filter_bank_values(sod_normalize_string_list($vals), $canon);
                }
            }
        }
        if ($fixed !== $current) update_option($option_key, $fixed, false);
    }

    update_option($flag, time(), false);
}

add_action('init', 'sod_self_heal_mojibake_options', 1);

function sod_force_clean_learning_banks(): void {
    $option_keys = [
        'sod_bank_actors',
        'sod_bank_targets',
        'sod_bank_contexts',
        'sod_bank_intents',
        'sod_bank_weapons',
        'sod_bank_types',
        'sod_bank_levels',
        'sod_bank_regions',
        'sod_visible_learning_banks',
    ];

    delete_option('sod_mojibake_self_heal_v4');
    sod_self_heal_mojibake_options();
    foreach ($option_keys as $key) {
        $current = get_option($key, null);
        if ($current === null) continue;
        if ($key === 'sod_visible_learning_banks' && is_array($current)) {
            sod_save_visible_learning_banks($current);
            continue;
        }
        if (is_array($current)) {
            update_option($key, sod_normalize_string_list($current), false);
        }
    }
    sod_save_visible_learning_banks(sod_get_visible_learning_banks());
}

function sod_clean_entity_graph_records(): int {
    global $wpdb;
    $table = $wpdb->prefix . 'so_entity_graph';
    $rows = $wpdb->get_results("SELECT id, actor_name, target_name, region FROM {$table}", ARRAY_A);
    if (!is_array($rows) || empty($rows)) return 0;
    $updated = 0;
    foreach ($rows as $row) {
        $actor = sod_fix_mojibake_text((string)($row['actor_name'] ?? ''));
        $target = sod_fix_mojibake_text((string)($row['target_name'] ?? ''));
        $region = sod_fix_mojibake_text((string)($row['region'] ?? ''));
        if ($actor === ($row['actor_name'] ?? '') && $target === ($row['target_name'] ?? '') && $region === ($row['region'] ?? '')) {
            continue;
        }
        $wpdb->update($table, [
            'actor_name' => $actor,
            'target_name' => $target,
            'region' => $region,
        ], ['id' => (int)$row['id']]);
        $updated++;
    }
    return $updated;
}

function sod_should_inject_frontend_ui(): bool {
    if (is_admin() || sod_is_dashboard_route()) return true;
    global $post;
    if (!$post || empty($post->post_content)) return false;
    foreach ([
        'sod_powerbi','sod_ticker','sod_threat_analyzer','sod_command_deck',
        'osint_dashboard','osint_map','osint_command_center','osint_dashboard_panel',
        'strategic_osint_powerbi','strategic_osint_ticker','strategic_osint_v7_brief'
    ] as $tag) {
        if (has_shortcode((string)$post->post_content, $tag)) return true;
    }
    return false;
}

function sod_should_enqueue_public_assets(): bool {
    if (sod_is_dashboard_route()) return true;
    if (is_admin()) return false;
    global $post;
    if (!$post || empty($post->post_content)) return false;
    return sod_should_inject_frontend_ui();
}

function sod_reclassify_event_after_insert(int $event_id): bool {
    global $wpdb;
    if ($event_id <= 0) return false;
    $table = $wpdb->prefix . 'so_news_events';
    $row = $wpdb->get_row($wpdb->prepare("SELECT * FROM {$table} WHERE id = %d", $event_id), ARRAY_A);
    if (!$row) return false;

    $item = [
        'title' => (string)($row['title'] ?? ''),
        'link' => (string)($row['link'] ?? ''),
        'source' => (string)($row['source_name'] ?? $row['source'] ?? ''),
        'source_name' => (string)($row['source_name'] ?? $row['source'] ?? ''),
        'date' => (string)($row['event_timestamp'] ?? ''),
        'image_url' => (string)($row['image_url'] ?? ''),
    ];
    $pipeline = sod_ingest_and_publish_canonical_item($item, $row, ['status' => (string)($row['status'] ?? 'published')]);
    if (empty($pipeline['ok']) || empty($pipeline['canonical'])) return false;
    $update = (array)$pipeline['canonical'];
    unset($update['hash_id']);
    $result = sod_save_canonical_event_state($table, $update, ['id' => $event_id]);
    return !empty($result['ok']);
}

add_action('so_reclassify_event_after_insert', function ($event_id) {
    sod_reclassify_event_after_insert((int)$event_id);
}, 10, 1);


