function sod_get_all_banks(){
    sod_self_heal_mojibake_options();
    return [
        'actors' => sod_filter_bank_values(sod_normalize_string_list((array)get_option('sod_bank_actors', [])), 'actors'),
        'targets' => sod_filter_bank_values(sod_normalize_string_list((array)get_option('sod_bank_targets', [])), 'targets'),
        'contexts' => sod_filter_bank_values(sod_normalize_string_list((array)get_option('sod_bank_contexts', [])), 'contexts'),
        'intents' => sod_filter_bank_values(sod_normalize_string_list((array)get_option('sod_bank_intents', [])), 'intents'),
        'weapons' => sod_filter_bank_values(sod_normalize_string_list((array)get_option('sod_bank_weapons', [])), 'weapons'),
    ];
}

/**
 * مطابقة متقدمة مع دعم الأوزان والكلمات المفتاحية والسياق
 */
function sod_match_bank($text, $bank_values, $options = []) {
    $matches = [];
    $text = (string)$text;
    $text_lower = mb_strtolower($text);
    $text_clean = so_clean_text($text);

    foreach ($bank_values as $key => $value) {
        // دعم المصفوفات ذات المفاتيح والقيم (للأوزان المخصصة)
        if (is_array($value)) {
            $term = trim((string)($value['term'] ?? ''));
            $weight = (float)($value['weight'] ?? 1.0);
            $keywords = isset($value['keywords']) ? (array)$value['keywords'] : [$term];
        } else {
            $term = trim((string)$value);
            $weight = 1.0;
            $keywords = [$term];
        }

        if ($term === '') continue;

        $score = 0;
        $matched_keyword = '';

        // 1. مطابقة الكلمات المفتاحية داخل النص
        foreach ($keywords as $kw) {
            $kw = trim((string)$kw);
            if ($kw === '') continue;

            if (mb_stripos($text, $kw) !== false) {
                $score += 15 * $weight;
                if ($matched_keyword === '') $matched_keyword = $kw;

                if (preg_match('/(^|[^\p{L}\p{N}_])' . preg_quote($kw, '/') . '([^\p{L}\p{N}_]|$)/ui', $text)) {
                    $score += 10 * $weight;
                }
            }
        }

        // 2. مطابقة مباشرة للـ term بدل similar_text المكلف
        if ($score === 0 && mb_stripos($text_clean, $term) !== false) {
            $score += 6 * $weight;
        }

        // 3. مطابقة الجذور (للغة العربية)
        if (function_exists('sod_arabic_root_match')) {
            $root_score = sod_arabic_root_match($text_clean, $term);
            if ($root_score > 0) {
                $score += $root_score * $weight;
            }
        }

        // 4. مكافأة السياق القريب
        if (!empty($options['context_words']) && $score > 0) {
            foreach ((array)$options['context_words'] as $ctx_word) {
                if ($ctx_word !== '' && mb_stripos($text, $ctx_word) !== false) {
                    $score += 5 * $weight;
                    break;
                }
            }
        }

        // 5. عقوبة للمدخلات العامة جداً ضمن بنك الفاعلين
        if (!empty($options['bank']) && $options['bank'] === 'actors') {
            $generic_actor_terms = ['إسرائيل', 'اسرائيل', 'أمريكا', 'امريكا', 'الولايات المتحدة', 'إيران', 'ايران'];
            if (in_array($term, $generic_actor_terms, true)) {
                $score *= 0.55;
            }
        }

        if ($score > 0) {
            $matches[$term] = [
                'score' => round($score, 2),
                'keyword' => $matched_keyword,
                'weight' => $weight,
            ];
        }
    }

    // ترتيب حسب النتيجة
    uasort($matches, function($a, $b) {
        return $b['score'] <=> $a['score'];
    });

    return $matches;
}

/**
 * استخراج الجذر العربي للمطابقة الدلالية
 */
function sod_arabic_root_match($text, $term) {
    // جذور شائعة للأفعال المتعلقة بالصراع
    $roots = [
        'قصف' => ['يقصف', 'قصف', 'تقصف', 'مقصف'],
        'ضرب' => ['يضرب', 'ضرب', 'تضرب', 'مضروب'],
        'استهد' => ['يستهدف', 'استهدف', 'تستهدف', 'مستهدف'],
        'أطل' => ['يطلق', 'أطلق', 'تطلق', 'إطلاق'],
        'داهم' => ['يداهم', 'داهم', 'تداهم', 'مداهمة'],
        'اغت' => ['يغتال', 'اغتيال', 'تغتال', 'مغتال'],
    ];
    
    $score = 0;
    foreach ($roots as $root => $variations) {
        if (stripos($term, $root) !== false) {
            foreach ($variations as $var) {
                if (stripos($text, $var) !== false) {
                    $score += 8;
                }
            }
        }
    }
    return $score;
}

function sod_resolve_field($text, $bank){
    $banks = sod_get_all_banks();
    $vals = isset($banks[$bank]) ? $banks[$bank] : [];
    $m = sod_match_bank($text, $vals, ['bank' => $bank]);
    return !empty($m) ? array_key_first($m) : '';
}

function sod_detect_action_type($text) {
    $text = so_clean_text((string)$text);

    if (preg_match('/(غارة|غارات|قصف|استهداف|هجوم|اشتباك|كمين|إطلاق صواريخ|إطلاق نار|مسيّرة|مسيرة|توغل|اقتحام|اغتيال|تفجير|قنص|اعتقال|اعتراض|طيران حربي|طيران معاد|عدوان|اعتداء إسرائيلي|اعتداء اسرائيلي|مدفعية|دبابات)/ui', $text)) {
        return 'military';
    }

    if (preg_match('/(تصريح|قال|أكد|صرح|أعلن|أفاد|نقل عن|بحسب|وفق|ذكر|كشف|رويترز|وسائل إعلام|وسائل اعلام|تقرير|تحليل|مراسل|صحيفة|قناة|إذاعة|تغطية خاصة)/ui', $text)) {
        return 'statement';
    }

    if (preg_match('/(مفاوضات|محادثات|لقاء|اجتماع|اتفاق|قمة|وفد|دبلوماسي|ديبلوماسي|مؤتمر|وزارة الخارجية)/ui', $text)) {
        return 'diplomatic';
    }

    return 'unknown';
}


function sod_detect_event_mode($text) {
    $text = so_clean_text((string)$text);

    if (preg_match('/(لقد انتهى الحدث|انتهى الحدث|انذار احمر|إنذار أحمر|صفارات الإنذار|صافرات الإنذار|الجبهة الداخلية|تسوفار|خشية تسلل|تسلل طائرة بدون طيار|منطقة إنذار)/ui', $text)) {
        return 'defensive_alert';
    }

    if (
        preg_match('/(مفاوضات|محادثات|لقاء|اجتماع|وفد|قمة|مؤتمر|تصريح|قال|أكد|صرح|أعلن|أفاد|رويترز|مصدر دبلوماسي|وزارة الخارجية|وقف إطلاق النار|هدنة|ترحب|نأمل|يلتقي|التقى|المتحدثة باسم|المتحدث باسم|مستشار|البيت الأبيض|البيت الابيض|الحكومة الإيرانية|الخارجية الإيرانية|وزارة الصحة|وزارة الخدمة المدنية|تقرير|تحليل|صورة|صور)/ui', $text)
        && !preg_match('/(غارة|قصف|استهداف|هجوم|اشتباك|اقتحام|توغل|صاروخ|صواريخ|مسيّرة|مسيرة|دبابة|ثكنة|رشقة|صلية|كمين|أغار|اعتداء إسرائيلي|تم رصد غارة|تم رصد قصف|تم رصد اقتحام|تم رصد هجوم|استهدفنا|استهدف مجاهدونا)/ui', $text)
    ) {
        return 'political';
    }

    if (preg_match('/(غارة|قصف|استهداف|هجوم|اشتباك|اقتحام|توغل|صاروخ|صواريخ|مسيّرة|مسيرة|دبابة|ثكنة|رشقة|صلية|كمين|أغار|اعتداء إسرائيلي|تم رصد غارة|تم رصد قصف|تم رصد اقتحام|تم رصد هجوم|استهدفنا|استهدف مجاهدونا|إطلاق نار|استطلاع بطائرة مسيّرة)/ui', $text)) {
        return 'kinetic';
    }

    return 'unknown';
}

function sod_is_non_military_context($text) {
    $text = so_clean_text((string)$text);

    if (preg_match('/(مفاوضات|محادثات|وفد|اجتماع|لقاء|قمة|مؤتمر|وزارة الخارجية|دبلوماسي|ديبلوماسي|رئيس الوزراء|الرئيس|وقف إطلاق النار|وقف اطلاق النار|هدنة|اتفاق|البيت الأبيض|البيت الابيض|المتحدثة باسم|المتحدث باسم|مستشار|صورة|صور|تقرير|تحليل|تغطية خاصة|كاتب|محلل سياسي)/ui', $text)) {
        return true;
    }

    if (preg_match('/(تصريح|قال|أكد|صرح|أعلن|أفاد|نقل عن|بحسب|وفق|ذكر|كشف|شجب|استنكر|أدان|رحب|حث|دعا|طالب|ينفي|يرفض|لن تتنازل|لن تتراجع)/ui', $text) && !preg_match('/(غارة|قصف|استهداف|هجوم|اشتباك|إطلاق صواريخ|إطلاق نار|توغل|اقتحام|اغتيال|كمين)/ui', $text)) {
        return true;
    }

    if (preg_match('/(وسائل إعلام|وسائل اعلام|صحيفة|قناة|إذاعة|تحليل|تقرير إعلامي|تغطية خاصة|كاتب|محلل سياسي|رويترز|الغارديان|نيويورك تايمز|العربية|الميادين|الجزيرة|نتبلوكس|سي بي اس|سی‌بی‌اس)/ui', $text) && !preg_match('/(غارة|قصف|استهداف|هجوم|اشتباك|إطلاق صواريخ|توغل|اقتحام|اغتيال|كمين)/ui', $text)) {
        return true;
    }

    return false;
}

function sod_prepare_actor_bank($actors_bank) {
    $prepared = [];
    foreach ((array)$actors_bank as $item) {
        if (is_array($item)) {
            $term = trim((string)($item['term'] ?? ''));
            $keywords = isset($item['keywords']) ? array_values(array_filter(array_map('trim', (array)$item['keywords']))) : [];
            $weight = (float)($item['weight'] ?? 1.0);
        } else {
            $term = trim((string)$item);
            $keywords = [$term];
            $weight = 1.0;
        }

        if ($term === '') continue;

        if ($term === 'جيش العدو الإسرائيلي') {
            $keywords = array_values(array_unique(array_filter(array_merge($keywords, ['الجيش الإسرائيلي','جيش الاحتلال','قوات الاحتلال','طيران الاحتلال','الطائرات الحربية الإسرائيلية','الطيران الحربي المعادي','العدو الإسرائيلي','الاحتلال الإسرائيلي']))));
            $weight = max($weight, 1.2);
        }

        if (in_array($term, ['إسرائيل','اسرائيل'], true)) {
            $keywords = array_values(array_filter($keywords, function($kw) {
                return !in_array(trim((string)$kw), ['إسرائيل','اسرائيل'], true);
            }));
            $weight = min($weight, 0.45);
        }

        $prepared[] = [
            'term' => $term,
            'keywords' => !empty($keywords) ? $keywords : [$term],
            'weight' => $weight,
        ];
    }

    return $prepared;
}

function sod_extract_actors_ranked($text, $bank) {
    $matches = sod_match_bank($text, $bank, ['bank' => 'actors']);
    if (empty($matches)) return [];
    return array_slice(array_keys($matches), 0, 3);
}

function sod_detect_target_from_text($text, $targets_bank = []) {
    $text = so_clean_text((string)$text);

    if (preg_match('/(?:استهدف(?:ت)?|قصف(?:ت)?|هاجم(?:ت)?|أغار(?:ت)? على|شن(?:ت)? غارة على|توغل(?:ت)? في|اقتحم(?:ت)?|ضرب(?:ت)?|اعترض(?:ت)?)(?:\s+[^\s]+){0,4}\s+(?:على|في)?\s*([^\.،
]{2,120})/ui', $text, $m)) {
        $candidate = trim((string)$m[1]);
        $candidate = preg_replace('/\s+(?:مما|ما أدى|ما ادى|وذلك|حيث|بعد|قبل).*$/u', '', $candidate);
        if ($candidate !== '') return $candidate;
    }

    if (!empty($targets_bank)) {
        $target_matches = sod_match_bank($text, $targets_bank, ['bank' => 'targets']);
        if (!empty($target_matches)) return (string)array_key_first($target_matches);
    }

    return '';
}


function sod_context_memory_get(): array {
    $memory = get_option('sod_context_memory_patterns', []);
    return is_array($memory) ? $memory : [];
}

function sod_context_memory_save_feedback(string $title, array $payload = []): void {
    $title = so_clean_text($title);
    if ($title === '') return;

    $patterns = sod_context_memory_get();
    $entry = [
        'fingerprint' => so_build_title_fingerprint($title),
        'title' => $title,
        'actor_v2' => trim((string)($payload['actor_v2'] ?? '')),
        'intel_type' => trim((string)($payload['intel_type'] ?? '')),
        'region' => trim((string)($payload['region'] ?? '')),
        'context_actor' => trim((string)($payload['context_actor'] ?? '')),
        'intent' => trim((string)($payload['intent'] ?? '')),
        'weapon_v2' => trim((string)($payload['weapon_v2'] ?? '')),
        'saved_at' => time(),
    ];

    if ($entry['actor_v2'] === '') return;

    $patterns[] = $entry;
    if (count($patterns) > 400) {
        $patterns = array_slice($patterns, -400);
    }
    update_option('sod_context_memory_patterns', $patterns, false);
}





function sod_auto_dataset_training_from_newslog(int $limit = 2500): array {
    global $wpdb;
    $table = $wpdb->prefix . 'so_news_events';
    $rows = $wpdb->get_results($wpdb->prepare(
        "SELECT id,title,source_name,intel_type,tactical_level,region,actor_v2,weapon_v2,target_v2,context_actor,intent,score,war_data,field_data
         FROM {$table}
         ORDER BY id DESC
         LIMIT %d",
        max(100, $limit)
    ), ARRAY_A);

    if (empty($rows)) return ['scanned'=>0,'learned'=>0];

    $learned = 0;
    foreach ($rows as $row) {
        $title = so_clean_text((string)($row['title'] ?? ''));
        if ($title === '') continue;

        $manual = sod_get_manual_override_state($row);
        $wd = sod_parse_json_array($row['war_data'] ?? '');
        $evaluationMode = (string)($wd['evaluation_mode'] ?? '');

        $trusted = !empty($manual['enabled'])
            || $evaluationMode === 'manual_override'
            || ((int)($row['score'] ?? 0) >= 130 && !empty($row['actor_v2']) && (string)$row['actor_v2'] !== 'فاعل غير محسوم');

        if (!$trusted) continue;

        $payload = [
            'title' => $title,
            'actor_v2' => (string)($row['actor_v2'] ?? ''),
            'region' => (string)($row['region'] ?? ''),
            'intel_type' => (string)($row['intel_type'] ?? ''),
            'tactical_level' => (string)($row['tactical_level'] ?? ''),
            'score' => (int)($row['score'] ?? 0),
            'target_v2' => (string)($row['target_v2'] ?? ''),
            'context_actor' => (string)($row['context_actor'] ?? ''),
            'intent' => (string)($row['intent'] ?? ''),
            'weapon_v2' => (string)($row['weapon_v2'] ?? ''),
        ];

        SO_Manual_Learning::save_feedback(['title'=>$title,'source_name'=>(string)($row['source_name'] ?? '')], $payload);
        sod_context_memory_save_feedback($title, $payload);

        foreach ([['types',$payload['intel_type']],['levels',$payload['tactical_level']],['regions',$payload['region']],['actors',$payload['actor_v2']],['targets',$payload['target_v2']],['contexts',$payload['context_actor']],['intents',$payload['intent']],['weapons',$payload['weapon_v2']]] as $pair) {
            [$bank, $value] = $pair;
            if ($value !== '' && $value !== 'فاعل غير محسوم' && $value !== 'غير محدد') {
                sod_add_bank_value($bank, $value);
            }
        }
        $learned++;
    }

    update_option('sod_auto_dataset_training_summary', [
        'time' => time(),
        'scanned' => count($rows),
        'learned' => $learned,
    ], false);

    return ['scanned'=>count($rows),'learned'=>$learned];
}


function sod_actor_engine_v2($text) {
    $text = so_clean_text((string)$text);
    $banks = sod_get_all_banks();
    $actors_bank = sod_prepare_actor_bank($banks['actors']);
    $mode = sod_detect_event_mode($text);
    $target = sod_detect_target_from_text($text, $banks['targets']);

    $memory_hit = sod_context_memory_infer($text);
    if (!empty($memory_hit)) {
        return $memory_hit;
    }

    if ($mode === 'defensive_alert') {
        if ($target === '') {
            if (preg_match('/(?:في|خط(?: ?المواجهة)?[:：]?)\s*([^\.
]{2,80})/ui', $text, $m)) {
                $target = trim((string)$m[1]);
            }
        }
        $alert_actor = sod_infer_actor_strict($text, '', 'الأراضي المحتلة (إسرائيل)', '', '');
        if ($alert_actor === '' || sod_is_unknown_actor_label($alert_actor) || sod_is_media_source_actor($alert_actor) || preg_match('/(منظومة الإنذار|الجبهة الداخلية)/ui', $alert_actor)) {
            $alert_actor = 'محور المقاومة (استنتاج)';
        }
        return [
            'primary_actor' => $alert_actor,
            'secondary_actor' => 'الأراضي المحتلة (إسرائيل)',
            'target' => $target !== '' ? $target : 'منطقة إنذار',
            'confidence' => 91,
            'reason' => 'defensive-alert-inferred',
            'actor_matches' => [],
        ];
    }

    $hard_non_military = sod_is_non_military_context($text)
        || preg_match('/(صورة\s+لل?وفد|الوفد\s+الإيراني\s+المفاوض|إعلام\s+إيراني|رويترز\s+عن\s+مصدر|مصدر\s+دبلوماسي|الجزيرة|العربية|الميادين|تغطية\s+خاصة|كاتب|محلل سياسي|نتبلوكس|وزارة الخدمة المدنية|المؤتمر الشعبي|النائب فضل الله|تاكر كارلسون|ولايتي|المتحدثة باسم الحكومة الإيرانية|البيت الأبيض|البيت الابيض|مستشار المرشد الإيراني|مستشار قائد الثورة الإسلامية)/ui', $text);

    if ($mode === 'political' || $hard_non_military) {
        $named_actor = sod_extract_named_nonmilitary_actor($text);
        return [
            'primary_actor' => $named_actor !== '' ? $named_actor : 'فاعل غير محسوم',
            'secondary_actor' => '',
            'target' => '',
            'confidence' => $named_actor !== '' ? 88 : 96,
            'reason' => $named_actor !== '' ? 'non-military-named-actor' : 'non-military-context',
            'actor_matches' => [],
        ];
    }

    $actor_matches = sod_match_bank($text, $actors_bank, ['bank' => 'actors']);

    if (preg_match('/(المقاومة الإسلامية|حزب الله|مجاهدونا|استهدفنا|استهدف مجاهدونا|بيان صادر عن المقاومة الإسلامية|استهدفنا دبابة|استهدفنا تجمّع|ثكنة|مستوطنة|جنود وآليات جيش العدو)/ui', $text)) {
        $actor_matches = ['المقاومة الإسلامية (حزب الله)' => ['score' => 120, 'keyword' => 'المقاومة الإسلامية', 'weight' => 1.6]] + $actor_matches;
    }
    if (preg_match('/(الجيش الإسرائيلي|جيش الاحتلال|قوات الاحتلال|طيران الاحتلال|غارة إسرائيلية|قصف إسرائيلي|اعتداء إسرائيلي|توغل قوات الاحتلال|مستوطنون يقتحمون|الطيران الحربي المعادي|طائرات الاحتلال|طيران العدو|العدو شن غارة|قصف طيران الاحتلال)/ui', $text)) {
        $actor_matches = ['جيش العدو الإسرائيلي' => ['score' => 120, 'keyword' => 'الجيش الإسرائيلي', 'weight' => 1.6]] + $actor_matches;
    }
    if (preg_match('/(^|\s)(حماس|حركة حماس|كتائب القسام)(\s|:|$)/ui', $text)) {
        $actor_matches = ['كتائب القسام (حماس)' => ['score' => 116, 'keyword' => 'حماس', 'weight' => 1.5]] + $actor_matches;
    }
    if (preg_match('/(^|\s)(سرايا القدس|الجهاد الإسلامي)(\s|:|$)/ui', $text)) {
        $actor_matches = ['سرايا القدس (الجهاد الإسلامي)' => ['score' => 114, 'keyword' => 'سرايا القدس', 'weight' => 1.5]] + $actor_matches;
    }

    $actors = array_slice(array_keys($actor_matches), 0, 3);
    $primary = $actors[0] ?? 'فاعل غير محسوم';
    $secondary = $actors[1] ?? '';

    if ($primary === 'فاعل غير محسوم') {
        if (preg_match('/(استهداف دبابة إسرائيلية|استهداف موقع|استهدفنا تجمعا|استهدفنا تجمّعا|ثكنة يعرا|مستوطنة نهاريا|جنود وآليات جيش العدو)/ui', $text)) {
            $primary = 'المقاومة الإسلامية (حزب الله)';
        } elseif (preg_match('/(غارة إسرائيلية|طيران الاحتلال|الطيران الحربي المعادي|طائرات الاحتلال|قوات الاحتلال|مستوطنون يقتحمون)/ui', $text)) {
            $primary = 'جيش العدو الإسرائيلي';
        }
    }

    if (preg_match('/(إعلام|قناة|رويترز|العربية|الميادين|الجزيرة|صحيفة|تغطية|محلل|كاتب)/ui', $primary)) {
        $primary = 'فاعل غير محسوم';
        $secondary = '';
    }

    $confidence = 42;
    if (!empty($actor_matches) && $primary !== 'فاعل غير محسوم') {
        $top_score = (float)($actor_matches[$primary]['score'] ?? 0);
        $confidence += min(35, (int)round($top_score));
    }
    if ($target !== '') $confidence += 10;
    if ($secondary !== '') $confidence += 4;
    if ($primary === 'فاعل غير محسوم') $confidence = min($confidence, 45);
    $confidence = max(15, min(96, $confidence));

    $result = [
        'primary_actor' => $primary,
        'secondary_actor' => $secondary,
        'target' => $target,
        'confidence' => $confidence,
        'reason' => 'kinetic-or-operational-context',
        'actor_matches' => $actor_matches,
    ];

    return sod_governor_ai($result, $text);
}


function sod_resolve_actor_final($title, $content = '', $region = '') {
    $text = so_clean_text((string)$title . ' ' . (string)$content);
    if (class_exists('\\App\\Engines\\ActorDecisionEngineV3')) {
        try {
            $engine = new \App\Engines\ActorDecisionEngineV3();
            $v3 = $engine->decide((string)$title, (string)$content, (string)$region);
            $actor = trim((string)($v3['actor'] ?? ''));
            if ($actor !== '') {
                return ['actor_final'=>$actor,'confidence'=>(int)($v3['confidence']??0),'reason'=>(string)($v3['reason']??'actor-engine-v3'),'source'=>'actor_engine_v3'];
            }
        } catch (\Throwable $e) {}
    }
    $legacy = function_exists('sod_actor_engine_v2') ? sod_actor_engine_v2($text) : [];
    return ['actor_final'=>trim((string)($legacy['primary_actor'] ?? '')) ?: 'فاعل غير محسوم','confidence'=>(int)($legacy['confidence']??0),'reason'=>(string)($legacy['reason']??'actor-engine-v2'),'source'=>'actor_engine_v2'];
}

function sod_resolve_actor($text){
    $resolved = sod_resolve_actor_final($text, '', '');
    return trim((string)($resolved['actor_final'] ?? '')) ?: 'فاعل غير محسوم';
}

function sod_classify_event_v3($event){
    $text = so_clean_text((string)($event['title'] ?? '') . ' ' . (string)($event['content'] ?? ''));

    // استخراج سياق إضافي لتحسين المطابقة
    $context_words = [];
    if (preg_match('/(لبنان|فلسطين|سوريا|العراق|اليمن|إيران|ايران|إسرائيل|اسرائيل)/u', $text, $m)) {
        $context_words[] = $m[1];
    }

    $bucket = function_exists('so_detect_content_bucket') ? so_detect_content_bucket($text) : 'general';
    $mode = sod_detect_event_mode($text);
    $resolved_region = (string)sod_resolve_field($text, 'regions');
    $actor_final_data = sod_resolve_actor_final((string)($event['title'] ?? ''),(string)($event['content'] ?? ''),$resolved_region);
    $actor_ai = ['primary_actor'=>$actor_final_data['actor_final'],'secondary_actor'=>'','target'=>'','confidence'=>(int)$actor_final_data['confidence'],'reason'=>(string)$actor_final_data['reason'],'actor_matches'=>[],'source'=>(string)$actor_final_data['source']];

    $target_v2 = $actor_ai['target'] !== '' ? $actor_ai['target'] : sod_resolve_field($text, 'targets');
    $context_actor = ($bucket === 'statement' || $bucket === 'report') ? '' : sod_resolve_field($text, 'contexts');
    $intent = sod_resolve_field($text, 'intents');
    $weapon_v2 = sod_resolve_field($text, 'weapons');

    if ($mode === 'defensive_alert') {
        $context_actor = 'إنذار دفاعي';
        $intent = 'دفاع';
        if ($weapon_v2 === '') $weapon_v2 = 'إنذار / اعتراض';
    } elseif ($mode === 'kinetic') {
        if ($intent === '') $intent = 'هجوم';
    }

    if ($bucket === 'statement' || $bucket === 'report' || sod_is_non_military_context($text)) {
        $named_actor = sod_extract_named_nonmilitary_actor($text);
        if ($mode !== 'kinetic') {
            $actor_ai['primary_actor'] = $named_actor !== '' ? $named_actor : 'فاعل غير محسوم';
            $actor_ai['secondary_actor'] = '';
            $actor_ai['target'] = '';
            $actor_ai['confidence'] = $named_actor !== '' ? max((int)($actor_ai['confidence'] ?? 20), 70) : min((int)($actor_ai['confidence'] ?? 20), 35);
            $actor_ai['reason'] = $named_actor !== '' ? 'statement-named-actor' : 'statement-or-report-context';
        }
    }

    $resolved_region = (string)sod_resolve_field($text, 'regions');
    $early_warning = sod_early_warning_ai($text, [
        'actor' => (string)($actor_ai['primary_actor'] ?? ''),
        'region' => $resolved_region,
        'intel_type' => (string)$bucket,
    ]);
    $prediction = sod_prediction_layer($text, [
        'actor' => (string)($actor_ai['primary_actor'] ?? ''),
        'region' => $resolved_region,
        'intel_type' => (string)$bucket,
        'target' => (string)$target_v2,
        'weapon' => (string)$weapon_v2,
        'early_warning' => $early_warning,
    ]);

    return [
        'actor_final' => $actor_ai['primary_actor'],
        'actor_v2' => $actor_ai['primary_actor'],
        'target_v2' => $target_v2,
        'context_actor' => $actor_ai['secondary_actor'] !== '' ? $actor_ai['secondary_actor'] : $context_actor,
        'intent' => $intent,
        'weapon_v2' => $weapon_v2,
        '_ai_v2' => [
            'confidence' => (int)($actor_ai['confidence'] ?? 20),
            'reason' => (string)($actor_ai['reason'] ?? ''),
            'bucket' => $bucket,
        ],
        '_early_warning' => $early_warning,
        '_prediction' => $prediction,
        '_match_details' => [
            'actor_matches' => !empty($actor_ai['actor_matches']) ? $actor_ai['actor_matches'] : sod_match_bank($text, sod_prepare_actor_bank(sod_get_all_banks()['actors']), ['context_words' => $context_words, 'bank' => 'actors']),
            'weapon_matches' => sod_match_bank($text, sod_get_all_banks()['weapons'], ['context_words' => $context_words, 'bank' => 'weapons']),
        ]
    ];
}


function sod_early_warning_normalize_window($hours) {
    $hours = max(1, (int)$hours);
    if ($hours <= 3) return 'قصير جدًا (1–3 ساعات)';
    if ($hours <= 6) return 'قصير (3–6 ساعات)';
    if ($hours <= 12) return 'قصير/متوسط (6–12 ساعة)';
    if ($hours <= 24) return 'متوسط (12–24 ساعة)';
    return 'أبعد من 24 ساعة';
}

function sod_early_warning_ai($text, $context = []) {
    $text = so_clean_text((string)$text);
    $lower = mb_strtolower($text);

    $score = 0;
    $indicators = [];
    $scenario = 'مراقبة اعتيادية';
    $direction = 'مستقر/غير محسوم';
    $time_hours = 24;
    $confidence = 35;

    $is_alert_end = preg_match('/(لقد انتهى الحدث|انتهى الحدث|تم رفع الانذار|تم رفع الإنذار|زوال الخطر|عودة الحياة إلى طبيعتها)/ui', $lower) === 1;
    $is_defensive_alert = preg_match('/(انذار|إنذار|صفارات|صافرات|الجبهة الداخلية|تسوفار|اعتراض|رصد إطلاق|تسلل طائرة|خطالمواجهة|خط المواجهة)/ui', $lower) === 1;
    $is_kinetic = preg_match('/(غارة|قصف|استهداف|هجوم|اشتباك|توغل|اقتحام|إطلاق صواريخ|صلية صاروخية|مسيّرة|مسيرة|تفجير|اغتيال)/ui', $lower) === 1;
    $is_statement = preg_match('/(مفاوضات|محادثات|تصريح|قال|أكد|رويترز|اجتماع|لقاء|وفد|مؤتمر صحفي)/ui', $lower) === 1 && !$is_kinetic;

    if ($is_alert_end) {
        return [
            'level' => 'منخفض',
            'score' => 8,
            'confidence' => 90,
            'direction' => 'انحسار فوري',
            'window_hours' => 1,
            'window_label' => sod_early_warning_normalize_window(1),
            'scenario' => 'انتهاء حدث إنذاري/دفاعي بدون إشارة تصعيد فوري',
            'indicators' => ['انتهاء الحدث', 'رفع/انحسار الإنذار'],
            'reason' => 'alert-ended',
        ];
    }

    if ($is_statement) {
        $score += 12;
        $confidence += 5;
        $indicators[] = 'سياق سياسي/إعلامي';
        if (preg_match('/(تهديد|توعد|لن نسمح|سنرد|الرد قادم|سندفع الثمن|خط أحمر)/ui', $lower)) {
            $score += 20;
            $time_hours = min($time_hours, 24);
            $scenario = 'تصعيد لفظي قد يتحول إلى فعل ميداني';
            $direction = 'تصعيد سياسي';
            $indicators[] = 'تهديد مباشر';
        }
    }

    $rules = [
        ['pattern' => '/(استنفار|رفع الجهوزية|رفع الجهوزيه|تعزيزات|حشد|تحريك قوات|حشود|إخلاء|إخلاءات|فتح الملاجئ|إغلاق المجال الجوي|تعليق الرحلات)/ui', 'add' => 22, 'indicator' => 'تهيئة/تحضير ميداني', 'window' => 12],
        ['pattern' => '/(انذار|إنذار|صفارات|صافرات|الجبهة الداخلية|تسوفار|اعتراض|رصد إطلاق|تسلل طائرة|طائرة بدون طيار)/ui', 'add' => 18, 'indicator' => 'إشارة إنذار/دفاع جوي', 'window' => 6],
        ['pattern' => '/(غارة|قصف|استهداف|هجوم|اشتباك|توغل|اقتحام|إطلاق صواريخ|صلية صاروخية|اغتيال|تفجير)/ui', 'add' => 28, 'indicator' => 'فعل هجومي قائم', 'window' => 6],
        ['pattern' => '/(رد|رداً على|انتقام|ثأر|الرد قادم|في إطار الرد|ضمن الرد)/ui', 'add' => 20, 'indicator' => 'حلقة رد/رد مقابل', 'window' => 12],
        ['pattern' => '/(دبابة|ميركافا|ثكنة|موقع عسكري|قاعدة|مطار|منشأة|بنية تحتية|مفاعل|منصة غاز|ميناء)/ui', 'add' => 14, 'indicator' => 'أهداف حساسة/عسكرية', 'window' => 12],
        ['pattern' => '/(باليستي|فرط صوتي|كروز|مسيرة انتحارية|صاروخ موجّه|مضاد للدروع)/ui', 'add' => 16, 'indicator' => 'وسيلة عالية الخطورة', 'window' => 12],
        ['pattern' => '/(لبنان|فلسطين|غزة|الضفة|الأراضي المحتلة|إسرائيل|اسرائيل|إيران|ايران|سوريا|العراق|اليمن)/ui', 'add' => 6, 'indicator' => 'ساحة توتر معروفة', 'window' => 24],
    ];

    foreach ($rules as $rule) {
        if (preg_match($rule['pattern'], $lower)) {
            $score += $rule['add'];
            $indicators[] = $rule['indicator'];
            $time_hours = min($time_hours, (int)$rule['window']);
        }
    }

    $actor = trim((string)($context['actor'] ?? $context['actor_v2'] ?? ''));
    $region = trim((string)($context['region'] ?? ''));
    $intel_type = trim((string)($context['intel_type'] ?? ''));

    if ($actor !== '' && !in_array($actor, ['فاعل غير محسوم', 'فاعل سياقي غير مباشر', 'جهة غير معلنة', 'غير محدد'], true)) {
        $score += 10;
        $confidence += 8;
        $indicators[] = 'فاعل محدد';
    }
    if ($region !== '' && $region !== 'غير محدد') {
        $score += 6;
        $confidence += 4;
    }
    if (in_array($intel_type, ['عسكري/أمني', 'تكتيكي/ميداني', 'رصد/إنذار'], true)) {
        $score += 8;
        $confidence += 4;
    }

    if ($is_defensive_alert && !$is_kinetic) {
        $scenario = 'احتمال تجدّد الإنذار أو انتقاله إلى رشقة/اختراق قريب';
        $direction = 'توتر دفاعي';
    } elseif ($is_kinetic) {
        $scenario = 'خطر استمرار الضربات أو موجة رد مقابلة في المدى القريب';
        $direction = 'تصاعد ميداني';
    } elseif ($scenario === 'مراقبة اعتيادية') {
        $scenario = 'لا توجد دلائل كافية على حدث وشيك، لكن الساحة تحتاج متابعة';
    }

    if (preg_match('/(حشد|تعزيزات|استنفار|إخلاء)/ui', $lower) && preg_match('/(غارة|قصف|صاروخ|مسيّرة|اشتباك)/ui', $lower)) {
        $score += 12;
        $confidence += 8;
        $indicators[] = 'تلازم التحضير مع الفعل الميداني';
        $time_hours = min($time_hours, 6);
    }

    $score = max(0, min(100, (int)round($score)));
    $confidence = max(20, min(95, (int)round($confidence + ($score / 8))));

    if ($score >= 75) $level = 'حرج';
    elseif ($score >= 55) $level = 'مرتفع';
    elseif ($score >= 30) $level = 'متوسط';
    else $level = 'منخفض';


    return [
        'level' => $level,
        'score' => $score,
        'confidence' => $confidence,
        'direction' => $direction,
        'window_hours' => (int)$time_hours,
        'window_label' => sod_early_warning_normalize_window($time_hours),
        'scenario' => $scenario,
        'indicators' => array_values(array_unique($indicators)),
        'reason' => $is_kinetic ? 'kinetic-pattern' : ($is_defensive_alert ? 'defensive-pattern' : ($is_statement ? 'statement-pattern' : 'baseline-monitoring')),
    ];
}

function sod_rule_engine_scores($text, $context = []) {
    $text = so_clean_text((string)$text);
    $scores = [
        'attack' => 0,
        'defensive' => 0,
        'political' => 0,
        'media' => 0,
        'logistics' => 0,
    ];

    $rules = [
        'attack' => [
            '/(غارة|قصف|استهداف|هجوم|اشتباك|توغل|اقتحام|إطلاق صواريخ|صلية صاروخية|اغتيال|تفجير|قصف مدفعي|إطلاق نار من دبابات|استهداف دبابة|ثكنة|موقع عسكري)/ui' => 26,
            '/(مسيّرة|مسيرة|صاروخ|صاروخي|مضاد للدروع|ميركافا|محلّقة انقضاضية)/ui' => 18,
            '/(الجيش الإسرائيلي|طيران العدو|طائرات الاحتلال|قوات الاحتلال|المقاومة الإسلامية|حزب الله|استهدفنا|استهدف مجاهدونا)/ui' => 20,
        ],
        'defensive' => [
            '/(انذار|إنذار|صفارات|صافرات|الجبهة الداخلية|تسوفار|خطالمواجهة|خط المواجهة|لقد انتهى الحدث|تسلل طائرة بدون طيار|اعتراض)/ui' => 26,
            '/(انذار احمر|إنذار أحمر|رفع الإنذار|زوال الخطر|خشية تسلل)/ui' => 16,
        ],
        'political' => [
            '/(مفاوضات|محادثات|وفد|اجتماع|لقاء|وزارة|وزير|الرئيس|رئيس الوزراء|الخارجية|هدنة|وقف إطلاق النار|مصدر دبلوماسي)/ui' => 24,
            '/(رويترز|تسنيم|أكد|قال|أعلن|أفاد|أوضح|رحب|طالب|ندد|استنكر)/ui' => 12,
        ],
        'media' => [
            '/(تقرير|تحليل|تغطية خاصة|برنامج|مقابلة|مراسل|وسائل إعلام|صحيفة|وكالة|الكاتب والمحلل السياسي)/ui' => 22,
            '/(إعلام إيراني|إعلام العدو|القناة 12|فوكس نيوز|بلومبرغ|واشنطن بوست|الغارديان)/ui' => 12,
        ],
        'logistics' => [
            '/(مضيق هرمز|الملاحة|الموانئ|الوقود|الغاز|النفط|إمدادات|ناقلة|ناقلات|شحن|بنوك أجنبية|أصول مجمدة)/ui' => 18,
        ],
    ];

    foreach ($rules as $type => $patterns) {
        foreach ($patterns as $pattern => $points) {
            if (preg_match($pattern, $text)) {
                $scores[$type] += $points;
            }
        }
    }

    $actor = trim((string)($context['actor'] ?? ''));
    $region = trim((string)($context['region'] ?? ''));
    $intel_type = trim((string)($context['intel_type'] ?? ''));
    if ($actor !== '' && !in_array($actor, ['فاعل غير محسوم', 'جهة غير معلنة', 'غير محدد'], true)) {
        if (mb_stripos($actor, 'الإنذار') !== false) $scores['defensive'] += 12;
        elseif (preg_match('/(حزب الله|المقاومة|جيش العدو الإسرائيلي)/ui', $actor)) $scores['attack'] += 14;
    }
    if ($region !== '' && $region !== 'غير محدد') {
        $scores['attack'] += 4;
        $scores['defensive'] += 4;
    }
    if (in_array($intel_type, ['عسكري/أمني', 'أمني', 'رصد/إنذار'], true)) $scores['attack'] += 10;
    if ($intel_type === 'سياسي') $scores['political'] += 12;
    if ($intel_type === 'إعلامي') $scores['media'] += 12;

    arsort($scores);
    return $scores;
}

function sod_confidence_system($scores, $boost = 0) {
    $vals = array_values((array)$scores);
    $top = (int)($vals[0] ?? 0);
    $second = (int)($vals[1] ?? 0);
    $gap = max(0, $top - $second);

    $confidence = 35;
    if ($top >= 70) $confidence = 92;
    elseif ($top >= 50) $confidence = 82;
    elseif ($top >= 35) $confidence = 72;
    elseif ($top >= 20) $confidence = 58;

    if ($gap >= 18) $confidence += 8;
    elseif ($gap <= 6) $confidence -= 12;

    $confidence += (int)$boost;
    return max(20, min(97, $confidence));
}

function sod_prediction_layer($text, $context = []) {
    $text = so_clean_text((string)$text);
    $scores = sod_rule_engine_scores($text, $context);
    $mode = array_key_first($scores);
    $early = (isset($context['early_warning']) && is_array($context['early_warning'])) ? $context['early_warning'] : [];
    $confidence = sod_confidence_system($scores, (int)($early['confidence'] ?? 0) / 10);
    $risk = max((int)($early['score'] ?? 0), (int)($scores[$mode] ?? 0));
    $window = (int)($early['window_hours'] ?? 12);
    $actor = trim((string)($context['actor'] ?? 'فاعل غير محسوم')) ?: 'فاعل غير محسوم';
    $region = trim((string)($context['region'] ?? 'غير محدد')) ?: 'غير محدد';
    $target = trim((string)($context['target'] ?? ''));
    $weapon = trim((string)($context['weapon'] ?? ''));
    $scenario = 'مراقبة اعتيادية';
    $next_step = 'استمرار المراقبة';
    $direction = (string)($early['direction'] ?? 'مستقر/غير محسوم');

    if ($mode === 'attack') {
        $scenario = 'احتمال استمرار الضربات أو الرد المقابل خلال نافذة قصيرة';
        $next_step = 'تعزيز المراقبة التكتيكية ومقارنة النمط بآخر 6–12 ساعة';
        $window = min($window, 6);
        if ($weapon !== '') $scenario .= ' باستخدام ' . $weapon;
    } elseif ($mode === 'defensive') {
        $scenario = 'المرجح تجدّد الإنذار أو انتقاله إلى اعتراض/رشقة محدودة';
        $next_step = 'مراقبة صفارات الإنذار وتقاطعات الرصد مع إطلاقات فعلية';
        $window = min($window, 3);
    } elseif ($mode === 'political') {
        $scenario = 'المشهد سياسي/تفاوضي؛ الخطر المباشر أقل ما لم تظهر لغة تهديد أو تحضير ميداني';
        $next_step = 'تخفيض وزن الفاعل العسكري ومراقبة أي انتقال إلى لهجة تهديد أو حشد';
        $window = max($window, 12);
        $actor = 'فاعل غير محسوم';
    } elseif ($mode === 'media') {
        $scenario = 'الخبر إعلامي/تفسيري؛ لا توجد دلالة كافية على فعل وشيك دون مؤشرات مساندة';
        $next_step = 'عدم ترقية الخبر إلى تهديد إلا إذا ترافق مع إنذار أو فعل ميداني';
        $window = max($window, 12);
        $actor = 'فاعل غير محسوم';
    } elseif ($mode === 'logistics') {
        $scenario = 'مؤشر لوجستي/اقتصادي قد يسبق ضغطاً سياسياً أو تصعيداً على المدى المتوسط';
        $next_step = 'ربط الحدث بمؤشرات الملاحة والإمداد والأسواق قبل رفع الإنذار';
        $window = max($window, 12);
    }

    if (preg_match('/(تهديد|توعد|الرد قادم|لن نسمح|سندفع الثمن|خط أحمر)/ui', $text)) {
        $risk = min(100, $risk + 12);
        $confidence = min(97, $confidence + 6);
        $scenario .= ' مع لهجة تهديد واضحة';
    }

    if (preg_match('/(حشد|تعزيزات|رفع الجهوزية|استنفار|إخلاء|فتح الملاجئ)/ui', $text)) {
        $risk = min(100, $risk + 10);
        $window = min($window, 6);
        $next_step = 'رفع أولوية الإنذار لأن الخبر يجمع بين تحضير وإشارة تصعيد';
    }

    if ($risk >= 80) $level = 'حرج';
    elseif ($risk >= 60) $level = 'مرتفع';
    elseif ($risk >= 35) $level = 'متوسط';
    else $level = 'منخفض';

    return [
        'mode' => (string)$mode,
        'confidence' => (int)$confidence,
        'risk_score' => (int)$risk,
        'risk_level' => $level,
        'expected_window_hours' => (int)$window,
        'expected_window_label' => sod_early_warning_normalize_window($window),
        'predicted_actor' => $actor,
        'predicted_region' => $region,
        'predicted_target' => $target,
        'predicted_weapon' => $weapon,
        'direction' => $direction,
        'scenario' => $scenario,
        'next_step' => $next_step,
        'rule_scores' => $scores,
    ];
}


// ==========================================================================
// 1. الثوابت الموحدة — Unified Constants
// ==========================================================================
define('SO_VERSION',          '17.3.1');
define('SO_PLUGIN_DIR',       plugin_dir_path(__FILE__));
define('SO_PLUGIN_URL',       plugin_dir_url(__FILE__));
define('SO_TELEGRAM_LINK',    'https://t.me/osint_lb');
define('SO_SYNC_LOCK_TTL',    120);

define('SOD_VERSION',         '21.3.0');
define('SOD_PLUGIN_DIR',      plugin_dir_path(__FILE__));
define('SOD_PLUGIN_URL',      plugin_dir_url(__FILE__));
define('SOD_TG_LINK',         'https://t.me/osint_lb');
define('SOD_AJAX_NONCE_ACTION', 'sod_ajax_v13');

// ==========================================================================
// 2. الدوال المساعدة العامة — General Utility Functions
// ==========================================================================

function so_array_get($array, $key, $default = null) {
    return is_array($array) && array_key_exists($key, $array) ? $array[$key] : $default;
}

function so_safe_remote_get($url, $args = []) {
    $defaults = [
        'timeout'     => 10,
        'redirection' => 3,
        'sslverify'   => true,
        'headers'     => ['User-Agent' => 'Beiruttime-OSINT/' . SO_VERSION . '; ' . home_url('/')],
    ];
    return wp_remote_get(esc_url_raw($url), wp_parse_args($args, $defaults));
}

function so_safe_remote_post($url, $args = []) {
    $defaults = [
        'timeout'     => 12,
        'redirection' => 2,
        'sslverify'   => true,
        'headers'     => ['User-Agent' => 'Beiruttime-OSINT/' . SO_VERSION . '; ' . home_url('/')],
    ];
    return wp_remote_post(esc_url_raw($url), wp_parse_args($args, $defaults));
}

function so_normalize_event_link($link) {
    if (!empty($link) && filter_var($link, FILTER_VALIDATE_URL)) return esc_url_raw($link);
    return SO_TELEGRAM_LINK;
}

function so_generate_api_key() { return wp_generate_password(48, false, false); }

function so_extract_telegram_message_link($username, $chunk_html) {
    if (preg_match('/href="(https:\/\/t\.me\/[^"]+)"/i', (string)$chunk_html, $m)) return esc_url_raw($m[1]);
    if (!empty($username) && preg_match('/data-post="([^"]+)"/i', (string)$chunk_html, $m2)) return 'https://t.me/' . ltrim($m2[1], '/');
    return !empty($username) ? 'https://t.me/s/' . sanitize_title($username) : SO_TELEGRAM_LINK;
}

function so_normalize_remote_media_url($url) {
    $url = html_entity_decode((string)$url, ENT_QUOTES | ENT_HTML5, 'UTF-8');
    $url = trim($url, "\"' ");
    if (strpos($url, '//') === 0) $url = 'https:' . $url;
    return esc_url_raw($url);
}

function so_extract_telegram_media_url($chunk_html) {
    $html = (string)$chunk_html;
    if (preg_match('/<a[^>]+class="tgme_widget_message_photo_wrap"[^>]+style="[^"]*url\(([^)]+)\)/i', $html, $m)) return so_normalize_remote_media_url($m[1]);
    if (preg_match('/<video[^>]+src="([^"]+)"/i', $html, $m)) return so_normalize_remote_media_url($m[1]);
    if (preg_match('/<img[^>]+src="([^"]+)"/i', $html, $m)) return so_normalize_remote_media_url($m[1]);
    return '';
}

function so_extract_remote_media_urls($value) {
    $value = trim((string)$value);
    if ($value === '') return [];
    $parts = preg_split('/[\r\n,|]+/', $value);
    $out = [];
    foreach ($parts as $part) { $u = so_normalize_remote_media_url($part); if ($u) $out[] = $u; }
    return array_values(array_unique($out));
}

function so_detect_remote_media_type($url) {
    $url = (string)$url;
    if (!$url) return '';
    if (preg_match('/\.(mp4|mov|webm)(\?|$)/i', $url)) return 'video';
    return 'photo';
}

function so_source_items_limit() { return get_option('so_fetch_latest_only', 1) ? 1 : 5; }

function so_diag_record($type, $source, $status, $items = 0, $http = '', $message = '', $title = '') {
    $log = get_option('so_diag_events', []);
    if (!is_array($log)) $log = [];
    $log[] = [
        'time'    => time(), 'type' => sanitize_text_field((string)$type),
        'source'  => sanitize_text_field((string)$source), 'status' => sanitize_text_field((string)$status),
        'items'   => (int)$items, 'http' => sanitize_text_field((string)$http),
        'message' => sanitize_text_field((string)$message), 'title' => sanitize_text_field((string)$title),
    ];
    if (count($log) > 30) $log = array_slice($log, -30);
    update_option('so_diag_events', $log, false);
}

function so_update_last_sync_summary($raw_count, $inserted, $message = '') {
    update_option('so_last_sync_summary', [
        'time' => time(), 'raw_count' => (int)$raw_count, 'inserted' => (int)$inserted,
        'message' => sanitize_text_field((string)$message),
    ], false);
}

function so_update_insert_pipeline_summary($stats = []) {
    if (!is_array($stats)) $stats = [];
    $defaults = ['raw_count'=>0,'candidate_items'=>0,'skipped_old'=>0,'skipped_keyword'=>0,'process_null'=>0,'duplicate_hash'=>0,'inserted'=>0,'db_failed'=>0];
    $stats = array_merge($defaults, $stats);
    $stats['time'] = time();
    update_option('so_last_insert_pipeline', $stats, false);
}

function so_build_insert_hash($candidate_item, $analyzed) {
    $title  = so_normalize_title_for_dedupe((string)($candidate_item['title'] ?? ''));
    $source = sanitize_title((string)($candidate_item['source'] ?? 'unknown'));
    $actor  = trim((string)($analyzed['actor_v2'] ?? ''));
    $region = trim((string)($analyzed['region'] ?? ''));
    $intel  = trim((string)($analyzed['intel_type'] ?? ''));
    $truth  = trim((string)($analyzed['truth_layer'] ?? ''));
    $bucket = floor(((int)($candidate_item['date'] ?? time())) / 900);
    if ($truth === 'defensive_alert') return so_build_alert_signature((string)($candidate_item['title'] ?? ''));
    return md5($source . '|' . $title . '|' . $actor . '|' . $region . '|' . $intel . '|' . $truth . '|' . $bucket);
}

function so_get_news_events_schema_columns() {
    static $cols = null;
    if ($cols !== null) return $cols;
    global $wpdb;
    $results = $wpdb->get_results("SHOW COLUMNS FROM {$wpdb->prefix}so_news_events", ARRAY_A);
    $cols = [];
    if (is_array($results)) foreach ($results as $row) if (!empty($row['Field'])) $cols[$row['Field']] = true;
    return $cols;
}

function so_filter_news_event_row_for_schema($row) {
    $row = is_array($row) ? $row : [];
    $allowed = so_get_news_events_schema_columns();
    if (empty($allowed)) return $row;
    return array_intersect_key($row, $allowed);
}



function sod_hybrid_arabic_map(): array {
    return [
        'military' => 'عسكري',
        'security' => 'أمني',
        'cyber' => 'سيبراني',
        'political' => 'سياسي',
        'economic' => 'اقتصادي',
        'social' => 'اجتماعي',
        'media_psychological' => 'إعلامي/نفسي',
        'energy' => 'طاقة',
        'geostrategic' => 'جيوستراتيجي',
    ];
}

function sod_translate_hybrid_value($value): string {
    $map = sod_hybrid_arabic_map();
    $normalized = sod_normalize_hybrid_layers_value($value);
    if (empty($normalized)) {
        if (is_string($value)) {
            $value = trim($value);
            if ($value === '' || $value === '0') return '—';
            $parts = preg_split('/\s*\+\s*/u', $value);
            $translated = [];
            foreach ((array)$parts as $part) {
                $part = trim((string)$part);
                if ($part === '' || is_numeric($part)) continue;
                $translated[] = $map[$part] ?? $part;
            }
            return !empty($translated) ? implode(' + ', array_unique($translated)) : '—';
        }
        return '—';
    }
    $translated = [];
    foreach ($normalized as $item) {
        $translated[] = $map[$item] ?? $item;
    }
    return !empty($translated) ? implode(' + ', array_unique($translated)) : '—';
}

function sod_translate_hybrid_combo_label(string $combo): string {
    $parts = preg_split('/\s*\+\s*/u', trim($combo));
    $clean = [];
    foreach ((array)$parts as $part) {
        $part = trim((string)$part);
        if ($part === '' || is_numeric($part)) continue;
        $clean[] = $part;
    }
    return sod_translate_hybrid_value($clean);
}

function sod_normalize_hybrid_layers_value($value): array {
    if (is_string($value)) {
        $trim = trim($value);
        if ($trim === '' || $trim === '0' || $trim === '[]' || $trim === '{}') return [];
        if (preg_match('/^(?:layer_scores|multi_domain|active_layers|general|1layer_scores)+$/u', $trim)) return [];
        $decoded = json_decode($trim, true);
        if (json_last_error() === JSON_ERROR_NONE) {
            $value = $decoded;
        } else {
            if (preg_match('/(layer_scores|multi_domain|active_layers|general)/u', $trim) && !preg_match('/[,|\[]/u', $trim)) {
                return [];
            }
            if (!preg_match('/[,|+]/u', $trim)) {
                $probe = function_exists('mb_strtolower') ? mb_strtolower($trim) : strtolower($trim);
                $detected = [];
                if (preg_match_all('/media_psychological|geostrategic|military|security|political|economic|social|energy|cyber/u', $probe, $m) && !empty($m[0])) {
                    $detected = $m[0];
                }
                if (empty($detected) && preg_match_all('/إعلامي\/نفسي|إعلامي نفسي|جيوستراتيجي|عسكري|أمني|سياسي|اقتصادي|اجتماعي|طاقة|سيبراني/u', $trim, $m2) && !empty($m2[0])) {
                    $detected = $m2[0];
                }
                $value = !empty($detected) ? $detected : preg_split('/\s*[,|+]\s*/u', $trim);
            } else {
                $value = preg_split('/\s*[,|+]\s*/u', $trim);
            }
        }
    }
    if (!is_array($value)) return [];

    $aliases = [
        'military' => 'military', 'عسكري' => 'military', 'العسكرية' => 'military', 'الطبقة العسكرية' => 'military',
        'security' => 'security', 'أمني' => 'security', 'الأمنية' => 'security', 'الامنية' => 'security', 'الطبقة الأمنية' => 'security',
        'cyber' => 'cyber', 'سيبراني' => 'cyber', 'السيبرانية' => 'cyber', 'الطبقة السيبرانية' => 'cyber',
        'political' => 'political', 'سياسي' => 'political', 'السياسية' => 'political', 'الطبقة السياسية' => 'political',
        'economic' => 'economic', 'اقتصادي' => 'economic', 'الاقتصادية' => 'economic', 'الطبقة الاقتصادية' => 'economic',
        'social' => 'social', 'اجتماعي' => 'social', 'الاجتماعية' => 'social', 'الطبقة الاجتماعية' => 'social',
        'media_psychological' => 'media_psychological', 'media' => 'media_psychological', 'psychological' => 'media_psychological', 'إعلامي' => 'media_psychological', 'نفسي' => 'media_psychological', 'الإعلامية/النفسية' => 'media_psychological', 'الاعلامية/النفسية' => 'media_psychological', 'الطبقة الإعلامية والنفسية' => 'media_psychological',
        'energy' => 'energy', 'طاقة' => 'energy', 'الطاقة' => 'energy', 'طبقة الطاقة' => 'energy', 'الطبقة الطاقة' => 'energy',
        'geostrategic' => 'geostrategic', 'جيوستراتيجي' => 'geostrategic', 'الجيوستراتيجية' => 'geostrategic', 'الطبقة الجيوستراتيجية' => 'geostrategic',
    ];

    $out = [];
    foreach ($value as $key => $entry) {
        $candidate = '';

        if (is_array($entry)) {
            $candidate = (string)($entry['name_ar'] ?? $entry['name'] ?? $entry['layer'] ?? $entry['value'] ?? $entry['key'] ?? '');
        } elseif (is_string($entry) || is_numeric($entry)) {
            $candidate = (string)$entry;
        }

        if ($candidate === '' && !is_numeric($key) && !is_array($entry)) {
            $candidate = (string)$key;
        }
        if ($candidate === '' && !is_numeric($key) && (is_numeric($entry) || $entry === true || $entry === '1')) {
            $candidate = (string)$key;
        }

        $candidate = trim($candidate);
        if ($candidate === '' || $candidate === '0') continue;
        if (preg_match('/^(?:layer_scores|multi_domain|active_layers|general|1layer_scores)+$/u', $candidate)) continue;
        $candidate = $aliases[$candidate] ?? $aliases[mb_strtolower($candidate)] ?? $candidate;
        $out[] = $candidate;
    }

    return array_values(array_unique($out));
}


function sod_get_hybrid_layers_arabic(array $layers): array {
    $map = sod_hybrid_arabic_map();
    $out = [];
    foreach ($layers as $layer) {
        $layer = trim((string)$layer);
        if ($layer === '') continue;
        $out[] = $map[$layer] ?? $map[mb_strtolower($layer)] ?? $layer;
    }
    return array_values(array_unique(array_filter($out)));
}

function sod_rebuild_hybrid_archive_batch(int $offset = 0, int $limit = 400): array {
    global $wpdb;
    $table = $wpdb->prefix . 'so_news_events';
    $rows = $wpdb->get_results($wpdb->prepare("SELECT id, hybrid_layers, war_data, field_data FROM {$table} ORDER BY id ASC LIMIT %d OFFSET %d", $limit, $offset), ARRAY_A);
    if (empty($rows)) {
        return ['processed' => 0, 'updated' => 0, 'next_offset' => null, 'done' => true];
    }
    $updated = 0;
    foreach ($rows as $row) {
        $war = sod_parse_json_array($row['war_data'] ?? '{}');
        $field = sod_parse_json_array($row['field_data'] ?? '{}');
        $layers = [];
        foreach ([$row['hybrid_layers'] ?? null, $war['hybrid_layers'] ?? null, $field['hybrid_layers'] ?? null, $field['active_layers'] ?? null] as $candidate) {
            $layers = sod_normalize_hybrid_layers_value($candidate);
            if (!empty($layers)) break;
        }
        $layers_ar = sod_get_hybrid_layers_arabic($layers);
        $encoded = !empty($layers_ar) ? wp_json_encode($layers_ar, JSON_UNESCAPED_UNICODE) : null;
        $war['hybrid_layers'] = $layers_ar;
        $field['hybrid_layers'] = $layers_ar;
        $field['active_layers'] = $layers_ar;
        $field['hybrid_layers_count'] = count($layers_ar);
        $field['is_hybrid_event'] = !empty($layers_ar);
        $data = [
            'hybrid_layers' => $encoded,
            'war_data' => wp_json_encode($war, JSON_UNESCAPED_UNICODE),
            'field_data' => wp_json_encode($field, JSON_UNESCAPED_UNICODE),
        ];
        $result = $wpdb->update($table, $data, ['id' => (int)$row['id']], ['%s','%s','%s'], ['%d']);
        if ($result !== false) $updated++;
    }
    return ['processed' => count($rows), 'updated' => $updated, 'next_offset' => $offset + count($rows), 'done' => count($rows) < $limit];
}

function sod_handle_hybrid_archive_rebuild_request(): void {
    if (!is_admin()) return;
    if (!current_user_can('manage_options')) return;
    if (empty($_GET['page']) || $_GET['page'] !== 'strategic-osint') return;
    if (empty($_GET['so_action']) || $_GET['so_action'] !== 'rebuild_hybrid_archive') return;
    check_admin_referer('so_rebuild_hybrid_archive');
    $offset = max(0, intval($_GET['offset'] ?? 0));
    $batch = sod_rebuild_hybrid_archive_batch($offset, 400);
    $args = [
        'page' => 'strategic-osint',
        'rebuilt_hybrid' => 1,
        'processed' => (int)($batch['processed'] ?? 0),
        'updated' => (int)($batch['updated'] ?? 0),
    ];
    if (!empty($batch['done'])) {
        $args['rebuild_done'] = 1;
    } else {
        $args['continue_rebuild'] = 1;
        $args['offset'] = (int)($batch['next_offset'] ?? ($offset + 400));
    }
    wp_safe_redirect(add_query_arg($args, admin_url('admin.php')));
    exit;
}
add_action('admin_init', 'sod_handle_hybrid_archive_rebuild_request');

function sod_get_unified_event_state(array $row): array {
    $field = sod_parse_json_array($row['field_data'] ?? '{}');
    $war = sod_parse_json_array($row['war_data'] ?? '{}');
    $title = (string)($row['title'] ?? '');
    $content = (string)($row['content'] ?? ($field['content'] ?? ''));
    $source_name = (string)($row['source_name'] ?? '');

    $region = trim((string)($field['region'] ?? ($row['region'] ?? '')));
    $region = sod_infer_region_strict($title, $content, $region);

    $actor = trim((string)($field['actor_v2'] ?? ($row['actor_v2'] ?? '')));
    $actor = sod_infer_actor_strict($title, $content, $region, $actor, $source_name);
    if (sod_is_media_source_actor($actor) || preg_match('/(منظومة الإنذار|الجبهة الداخلية)/ui', $actor)) {
        $actor = sod_infer_actor_strict($title, $content, $region, '', $source_name);
    }
    if ($actor === '' || sod_is_unknown_actor_label($actor)) {
        $actor = 'محور المقاومة (استنتاج)';
    }

    $layers = [];
    foreach ([
        $row['hybrid_layers'] ?? null,
        $war['hybrid_layers'] ?? null,
        $field['hybrid_layers'] ?? null,
        $field['active_layers'] ?? null,
    ] as $candidate) {
        $layers = sod_normalize_hybrid_layers_value($candidate);
        if (!empty($layers)) break;
    }

    $score = (int)max((int)($row['score'] ?? 0), (int)($field['score'] ?? 0));
    $threat_score = (int)max((int)($row['threat_score'] ?? 0), (int)($field['threat_score'] ?? 0), $score);
    $intel_type = trim((string)($row['intel_type'] ?? '')) ?: trim((string)($field['intel_type'] ?? '')) ?: 'عام';

    $actor_confidence = (int)($row['actor_confidence'] ?? ($field['actor_confidence'] ?? ($war['actor_confidence'] ?? 0)));
    $actor_confidence_label = trim((string)($row['actor_confidence_label'] ?? ($field['actor_confidence_label'] ?? ($war['actor_confidence_label'] ?? ''))));
    if ($actor_confidence <= 0 || $actor_confidence_label === '') {
        $built = function_exists('so_build_actor_confidence') ? so_build_actor_confidence($title, $region, $actor) : ['confidence'=>75,'label'=>'مرجّح'];
        $actor_confidence = (int)($built['confidence'] ?? 75);
        $actor_confidence_label = (string)($built['label'] ?? ($actor_confidence >= 90 ? 'مؤكد' : ($actor_confidence >= 75 ? 'مرجّح' : 'استنتاج')));
    }

    return [
        'title' => $title,
        'region' => $region,
        'actor' => $actor,
        'hybrid_layers' => $layers,
        'score' => $score,
        'threat_score' => $threat_score,
        'intel_type' => $intel_type,
        'actor_confidence' => $actor_confidence,
        'actor_confidence_label' => $actor_confidence_label,
        'field_data' => $field,
        'war_data' => $war,
    ];
}

function sod_build_canonical_event_state(array $row, array $item, array $analyzed, array $options = []): array {
    $analyzed = sod_finalize_reanalysis_payload($row, $item, $analyzed);
    $war_data = sod_parse_json_array($analyzed['war_data'] ?? ($row['war_data'] ?? '{}'));
    $field_data = sod_parse_json_array($analyzed['field_data'] ?? ($row['field_data'] ?? '{}'));

    $hybrid_layers = [];
    foreach ([
        $analyzed['hybrid_analysis']['layers'] ?? null,
        $analyzed['hybrid_layers'] ?? null,
        $war_data['hybrid_layers'] ?? null,
        $field_data['hybrid_layers'] ?? null,
        $row['hybrid_layers'] ?? null,
    ] as $candidate) {
        $hybrid_layers = sod_normalize_hybrid_layers_value($candidate);
        if (!empty($hybrid_layers)) break;
    }

    $score = (int)($analyzed['score'] ?? ($row['score'] ?? 0));
    $threat_score = (int)($analyzed['threat_score'] ?? ($row['threat_score'] ?? $score));
    $severity_score = (int)($analyzed['severity_score'] ?? ($field_data['severity_score'] ?? $threat_score));
    $importance_score = (int)($analyzed['importance_score'] ?? ($field_data['importance_score'] ?? $score));
    $confidence_score = (int)($analyzed['confidence_score'] ?? ($field_data['confidence_score'] ?? 0));
    $decision_source = (string)($options['decision_source'] ?? (sod_is_manual_locked_row($row) ? 'manual_locked' : 'auto'));
    $analysis_status = (string)($options['analysis_status'] ?? 'complete');
    $status = (string)($options['status'] ?? ($row['status'] ?? 'published'));
    if (!in_array($status, ['published','pending','draft'], true)) $status = 'published';
    $now_mysql = current_time('mysql');

    $war_data['hybrid_layers'] = $hybrid_layers;
    $war_data['hybrid_combinations'] = $war_data['hybrid_combinations'] ?? ($analyzed['hybrid_analysis']['layer_combinations'] ?? []);
    $war_data['actor'] = (string)($analyzed['actor_v2'] ?? ($field_data['actor_v2'] ?? ($row['actor_v2'] ?? '')));
    if (!empty($analyzed['target_v2'])) $war_data['target'] = (string)$analyzed['target_v2'];
    if (!empty($analyzed['context_actor'])) $war_data['context_actor'] = (string)$analyzed['context_actor'];
    if (!empty($analyzed['intent'])) $war_data['intent'] = (string)$analyzed['intent'];
    if (!empty($analyzed['weapon_v2'])) $war_data['weapon_means'] = (string)$analyzed['weapon_v2'];
    $war_data['evaluation_mode'] = $decision_source;
    $war_data['analysis_status'] = $analysis_status;
    $war_data['processed_at'] = $now_mysql;

    $field_data['canonical_version'] = 'v18.1-unified-core-beta.1';
    $field_data['decision_source'] = $decision_source;
    $field_data['analysis_status'] = $analysis_status;
    $field_data['processed_at'] = $now_mysql;
    $field_data['hybrid_layers'] = $hybrid_layers;
    $field_data['hybrid_layers_count'] = count($hybrid_layers);
    $field_data['is_hybrid_event'] = !empty($hybrid_layers);
    $field_data['score'] = $score;
    $field_data['threat_score'] = $threat_score;
    $field_data['severity_score'] = $severity_score;
    $field_data['importance_score'] = $importance_score;
    $field_data['confidence_score'] = $confidence_score;
    if (!empty($options['needs_review'])) $field_data['needs_review'] = 1;

    $title = (string)($analyzed['title'] ?? ($item['title'] ?? ($row['title'] ?? '')));
    $content_for_inference = (string)($analyzed['content'] ?? ($item['content'] ?? ($row['content'] ?? '')));
    $title_for_inference = sod_apply_learning_bank_to_text($title);
    $content_for_inference = sod_apply_learning_bank_to_text($content_for_inference);
    $canonical_region = sod_infer_region_strict($title_for_inference, $content_for_inference, (string)($analyzed['region'] ?? ($row['region'] ?? '')));
    $canonical_actor  = sod_infer_actor_strict($title_for_inference, $content_for_inference, $canonical_region, (string)($analyzed['actor_v2'] ?? ($field_data['actor_v2'] ?? ($row['actor_v2'] ?? ''))), (string)($analyzed['source_name'] ?? ($item['source_name'] ?? $item['source'] ?? ($row['source_name'] ?? ''))));
    if (sod_is_media_source_actor($canonical_actor) || preg_match('/(منظومة الإنذار|الجبهة الداخلية)/ui', $canonical_actor) || sod_is_unknown_actor_label($canonical_actor)) {
        $canonical_actor = sod_infer_actor_strict($title_for_inference, $content_for_inference, $canonical_region, '', (string)($analyzed['source_name'] ?? ($item['source_name'] ?? $item['source'] ?? ($row['source_name'] ?? ''))));
    }
    $actor_confidence = function_exists('so_build_actor_confidence') ? so_build_actor_confidence($title, $canonical_region, $canonical_actor) : ['confidence'=>85,'source'=>'inferred','nature'=>'contextual','primary'=>$canonical_actor];
    $war_data['actor'] = $canonical_actor;
    $war_data['actor_confidence'] = (int)($actor_confidence['confidence'] ?? 85);
    $war_data['actor_confidence_label'] = ((int)($actor_confidence['confidence'] ?? 85) >= 90 ? 'مؤكد' : (((int)($actor_confidence['confidence'] ?? 85) >= 75) ? 'مرجّح' : 'استنتاج'));
    $field_data['region'] = $canonical_region;
    $field_data['actor_v2'] = $canonical_actor;
    $field_data['actor_confidence'] = (int)($actor_confidence['confidence'] ?? 85);
    $field_data['actor_confidence_source'] = (string)($actor_confidence['source'] ?? 'inferred');
    $field_data['actor_confidence_nature'] = (string)($actor_confidence['nature'] ?? 'contextual');
    $field_data['actor_confidence_label'] = ((int)($actor_confidence['confidence'] ?? 85) >= 90 ? 'مؤكد' : (((int)($actor_confidence['confidence'] ?? 85) >= 75) ? 'مرجّح' : 'استنتاج'));
    $canonical = [
        'hash_id' => (string)($analyzed['hash_id'] ?? ($row['hash_id'] ?? '')),
        'title' => $title,
        'title_fingerprint' => (string)($analyzed['title_fingerprint'] ?? ($row['title_fingerprint'] ?? (function_exists('so_build_title_fingerprint') ? so_build_title_fingerprint($title) : md5($title)))),
        'link' => so_normalize_event_link((string)($analyzed['link'] ?? ($item['link'] ?? ($row['link'] ?? '')))),
        'source_name' => (string)($analyzed['source_name'] ?? ($item['source_name'] ?? $item['source'] ?? ($row['source_name'] ?? ''))),
        'source_color' => (string)($analyzed['source_color'] ?? ($item['color'] ?? ($row['source_color'] ?? '#1da1f2'))),
        'event_timestamp' => (int)($analyzed['event_timestamp'] ?? $item['date'] ?? ($row['event_timestamp'] ?? time())),
        'agency_loc' => (string)($analyzed['agency_loc'] ?? ($item['agency_loc'] ?? ($row['agency_loc'] ?? ''))),
        'region' => $canonical_region,
        'actor_v2' => $canonical_actor,
        'score' => $score,
        'threat_score' => $threat_score,
        'severity_score' => $severity_score,
        'importance_score' => $importance_score,
        'confidence_score' => $confidence_score,
        'actor_confidence' => (int)($actor_confidence['confidence'] ?? 85),
        'actor_confidence_label' => (string)($field_data['actor_confidence_label'] ?? 'مرجّح'),
        'tactical_level' => (string)($analyzed['tactical_level'] ?? ($row['tactical_level'] ?? '')),
        'target_v2' => (string)($analyzed['target_v2'] ?? ($war_data['target'] ?? ($row['target_v2'] ?? ''))),
        'context_actor' => (string)($analyzed['context_actor'] ?? ($war_data['context_actor'] ?? ($row['context_actor'] ?? ''))),
        'intent' => (string)($analyzed['intent'] ?? ($war_data['intent'] ?? ($row['intent'] ?? ''))),
        'weapon_v2' => (string)($analyzed['weapon_v2'] ?? ($war_data['weapon_means'] ?? ($row['weapon_v2'] ?? ''))),
        'intel_type' => (string)($analyzed['intel_type'] ?? ($row['intel_type'] ?? 'عام')),
        'strategic_frame' => (string)($analyzed['strategic_frame'] ?? ($row['strategic_frame'] ?? '')),
        'conflict_context' => (string)($analyzed['conflict_context'] ?? ($row['conflict_context'] ?? '')),
        'war_direction' => (string)($analyzed['war_direction'] ?? ($row['war_direction'] ?? '')),
        'sentiment_score' => (int)($analyzed['sentiment_score'] ?? ($row['sentiment_score'] ?? 0)),
        'war_data' => wp_json_encode($war_data, JSON_UNESCAPED_UNICODE),
        'field_data' => wp_json_encode($field_data, JSON_UNESCAPED_UNICODE),
        'hybrid_layers' => wp_json_encode($hybrid_layers, JSON_UNESCAPED_UNICODE),
        'image_url' => (string)($analyzed['image_url'] ?? ($item['image_url'] ?? ($row['image_url'] ?? ''))),
        'llm_verified' => !empty($analyzed['llm_verified']) ? 1 : (int)($row['llm_verified'] ?? 0),
        'status' => !empty($options['needs_review']) ? 'pending' : $status,
        'processed_at' => $now_mysql,
        'reindexed_at' => $now_mysql,
        'analysis_status' => $analysis_status,
        'decision_source' => $decision_source,
    ];

    $canonical = sod_registry_apply_canonical_resolution($canonical);
    return so_filter_news_event_row_for_schema($canonical);
}

function sod_save_canonical_event_state(string $table, array $canonical, array $where = []) {
    global $wpdb;
    $canonical = so_filter_news_event_row_for_schema($canonical);
    if (empty($canonical)) return ['ok' => false, 'error' => 'empty_payload'];
    if (!empty($where)) {
        $result = sod_db_safe_update($table, $canonical, $where);
        return ['ok' => !empty($result['ok']), 'result' => $result];
    }
    $inserted = $wpdb->insert($table, $canonical, sod_db_build_formats($canonical));
    if ($inserted === false) return ['ok' => false, 'error' => $wpdb->last_error];
    return ['ok' => true, 'insert_id' => (int)$wpdb->insert_id];
}


function sod_extract_entity_bank_payload(array $event): array {
    $title = (string)($event['title'] ?? '');
    $war = sod_parse_json_array($event['war_data'] ?? '{}');
    $field = sod_parse_json_array($event['field_data'] ?? '{}');
    $text = trim($title . ' ' . (string)($war['summary'] ?? '') . ' ' . (string)($war['details'] ?? '') . ' ' . (string)($field['summary'] ?? ''));

    $payload = [
        'actors' => [],
        'locations' => [],
        'weapons' => [],
        'tactics' => [],
        'times' => [],
        'motives' => [],
    ];

    foreach ([$field['military_5ws_v1']['entities'] ?? null, $field['5w1h_validation']['entities'] ?? null, $war['5w1h_validation']['entities'] ?? null] as $candidate) {
        if (!is_array($candidate)) {
            continue;
        }
        foreach (array_keys($payload) as $bucket) {
            if (!empty($candidate[$bucket]) && is_array($candidate[$bucket])) {
                $payload[$bucket] = array_merge($payload[$bucket], array_map('strval', $candidate[$bucket]));
            }
        }
    }

    foreach ([(string)($event['actor_v2'] ?? ''), (string)($field['actor_v2'] ?? ''), (string)($war['actor'] ?? '')] as $actor) {
        $actor = trim($actor);
        if ($actor !== '' && $actor !== 'فاعل غير محسوم') {
            $payload['actors'][] = $actor;
        }
    }
    foreach ([(string)($event['region'] ?? ''), (string)($field['region'] ?? '')] as $loc) {
        $loc = trim($loc);
        if ($loc !== '') {
            $payload['locations'][] = $loc;
        }
    }
    foreach ([(string)($event['weapon_v2'] ?? ''), (string)($war['weapon_means'] ?? '')] as $weapon) {
        $weapon = trim($weapon);
        if ($weapon !== '') {
            $payload['weapons'][] = $weapon;
        }
    }
    foreach ([(string)($event['intent'] ?? ''), (string)($war['intent'] ?? '')] as $motive) {
        $motive = trim($motive);
        if ($motive !== '') {
            $payload['motives'][] = $motive;
        }
    }
    if (!empty($event['event_timestamp'])) {
        $payload['times'][] = gmdate('Y-m-d H:i:s', (int)$event['event_timestamp']);
    }

    $pattern_map = [
        'weapons' => '/(طائرة مسيرة|مسيرة انتحارية|صاروخ(?:\s+[\p{L}\-]+)?|قذيفة|مدفعية|دبابة ميركافا|دبابة|راجمة|عبوة ناسفة|هجوم سيبراني|منظومة دفاع جوي|قناص|طيران حربي|صاروخ مضاد للدروع|صاروخ باليستي)/u',
        'tactics' => '/(قصف|استهداف|توغل|اغتيال|كمين|اشتباك|حشد|اعتراض|تسلل|تحليق|تموضع|إعادة انتشار|حصار|إغلاق|مناورة|إنزال)/u',
        'motives' => '/(رداً على|انتقاماً|بسبب|نتيجة|على خلفية|في إطار|دعماً لـ|استجابة لـ|تمهيداً لـ)/u',
        'times' => '/(اليوم|الأمس|غداً|الآن|قبل قليل|صباحاً|مساءً|ليلاً|فجر اليوم|\d{1,2}:\d{2}|\d{1,2}[\/\-]\d{1,2}[\/\-]\d{2,4})/u',
        'locations' => '/(?:في|إلى|من|على|قرب|داخل|محيط|جنوب|شمال|شرق|غرب)\s+([\p{L}\p{N}\-]{2,40}(?:\s+[\p{L}\p{N}\-]{2,40}){0,3})/u',
    ];

    foreach ($pattern_map as $bucket => $pattern) {
        if (preg_match_all($pattern, $text, $matches) && !empty($matches[1] ?? $matches[0])) {
            $values = $matches[1] ?? $matches[0];
            foreach ($values as $value) {
                $value = trim((string)$value);
                if ($value !== '') {
                    $payload[$bucket][] = $value;
                }
            }
        }
    }

    foreach ($payload as $bucket => $values) {
        $payload[$bucket] = array_values(array_unique(array_filter(array_map('trim', $values))));
    }

    return $payload;
}

function sod_store_event_entities_in_memory(array $event, bool $force = false): array {
    global $wpdb;

    $event_id = (int)($event['id'] ?? 0);
    if ($event_id <= 0) {
        return ['ok' => false, 'stored' => 0, 'reason' => 'missing_event_id'];
    }

    $entities = sod_extract_entity_bank_payload($event);
    $table = $wpdb->prefix . 'so_actor_memory';
    $timestamp = (int)($event['event_timestamp'] ?? time());
    $threat_score = (int)($event['threat_score'] ?? ($event['score'] ?? 0));
    $action = !empty($entities['tactics']) ? (string)reset($entities['tactics']) : '';
    $weapon = !empty($entities['weapons']) ? implode(' | ', array_slice(array_map(static function($v){ return sod_resolve_registry_canonical('weapons', (string)$v); }, $entities['weapons']), 0, 3)) : '';
    $target = !empty($entities['locations']) ? implode(' | ', array_slice(array_map(static function($v){ return sod_resolve_registry_canonical('locations', (string)$v); }, $entities['locations']), 0, 3)) : '';
    $intent = !empty($entities['motives']) ? implode(' | ', array_slice($entities['motives'], 0, 3)) : '';

    if ($force) {
        $wpdb->delete($table, ['event_id' => $event_id], ['%d']);
    }

    $stored = 0;
    foreach ($entities['actors'] as $actor_name) {
        $actor_name = sod_resolve_registry_canonical('actors', trim((string)$actor_name));
        if ($actor_name === '' || $actor_name === 'فاعل غير محسوم') {
            continue;
        }

        $exists = (int)$wpdb->get_var($wpdb->prepare(
            "SELECT id FROM {$table} WHERE event_id = %d AND actor_name = %s LIMIT 1",
            $event_id,
            $actor_name
        ));
        if ($exists > 0) {
            $updated = $wpdb->update(
                $table,
                [
                    'action' => $action,
                    'weapon' => $weapon,
                    'target' => $target,
                    'intent_level' => min(300, max(0, $threat_score)),
                    'threat_score' => $threat_score,
                    'timestamp' => $timestamp,
                ],
                ['id' => $exists],
                ['%s','%s','%s','%d','%d','%d'],
                ['%d']
            );
            if ($updated !== false) {
                $stored++;
            }
            continue;
        }

        $inserted = $wpdb->insert(
            $table,
            [
                'actor_name' => $actor_name,
                'event_id' => $event_id,
                'action' => $action,
                'weapon' => $weapon,
                'target' => $target,
                'intent_level' => min(300, max(0, $threat_score)),
                'threat_score' => $threat_score,
                'timestamp' => $timestamp,
            ],
            ['%s','%d','%s','%s','%s','%d','%d','%d']
        );
        if ($inserted !== false) {
            $stored++;
        }
    }

    return ['ok' => true, 'stored' => $stored, 'entities' => $entities];
}



function sod_get_unified_registry_labels(): array {
    return [
        'actors' => 'الجهات الفاعلة',
        'locations' => 'المواقع',
        'weapons' => 'الأسلحة / الوسائط',
    ];
}

/**
 * Return persistent alias map stored in wp_options.
 */
function sod_get_unified_registry_alias_map(): array {
    $map = get_option('sod_unified_registry_alias_map', []);
    return is_array($map) ? $map : [];
}

function sod_save_unified_registry_alias_map(array $map): bool {
    return update_option('sod_unified_registry_alias_map', $map, false);
}

function sod_get_unified_registry_blocklist(): array {
    $items = get_option('sod_unified_registry_blocklist', []);
    return is_array($items) ? $items : [];
}

function sod_save_unified_registry_blocklist(array $items): bool {
    return update_option('sod_unified_registry_blocklist', $items, false);
}

function sod_add_registry_blocked_phrase(string $type, string $phrase, string $canonical = ''): bool {
    $type = sanitize_key($type);
    $phrase = trim(sanitize_text_field($phrase));
    $canonical = trim(sanitize_text_field($canonical));
    if ($type === '' || $phrase === '') return false;
    $items = sod_get_unified_registry_blocklist();
    if (!isset($items[$type]) || !is_array($items[$type])) $items[$type] = [];
    $key = function_exists('mb_strtolower') ? mb_strtolower($phrase, 'UTF-8') : strtolower($phrase);
    $items[$type][$key] = [
        'phrase' => $phrase,
        'canonical' => $canonical,
        'blocked_at' => current_time('mysql'),
    ];
    return sod_save_unified_registry_blocklist($items);
}

function sod_remove_registry_blocked_phrase(string $type, string $phrase): bool {
    $type = sanitize_key($type);
    $phrase = trim(sanitize_text_field($phrase));
    if ($type === '' || $phrase === '') return false;
    $items = sod_get_unified_registry_blocklist();
    if (!isset($items[$type]) || !is_array($items[$type])) return false;
    $key = function_exists('mb_strtolower') ? mb_strtolower($phrase, 'UTF-8') : strtolower($phrase);
    $changed = false;
    if (isset($items[$type][$key])) { unset($items[$type][$key]); $changed = true; }
    foreach ((array)$items[$type] as $row_key => $row) {
        if (trim((string)($row['phrase'] ?? '')) === $phrase) { unset($items[$type][$row_key]); $changed = true; }
    }
    return $changed ? sod_save_unified_registry_blocklist($items) : false;
}

function sod_is_registry_phrase_blocked(string $type, string $phrase, string $canonical = ''): bool {
    $type = sanitize_key($type);
    $phrase = trim(sanitize_text_field($phrase));
    $canonical = trim(sanitize_text_field($canonical));
    if ($type === '' || $phrase === '') return false;
    $items = sod_get_unified_registry_blocklist();
    $bucket = isset($items[$type]) && is_array($items[$type]) ? $items[$type] : [];
    $key = function_exists('mb_strtolower') ? mb_strtolower($phrase, 'UTF-8') : strtolower($phrase);
    $row = isset($bucket[$key]) && is_array($bucket[$key]) ? $bucket[$key] : [];
    if (empty($row)) {
        foreach ($bucket as $cand) {
            if (trim((string)($cand['phrase'] ?? '')) === $phrase) { $row = is_array($cand) ? $cand : []; break; }
        }
    }
    if (empty($row)) return false;
    $blocked_canonical = trim((string)($row['canonical'] ?? ''));
    return $canonical === '' || $blocked_canonical === '' || $blocked_canonical === $canonical;
}


function sod_get_unified_learning_bank(): array {
    $bank = get_option('sod_unified_learning_bank', []);
    return is_array($bank) ? $bank : [];
}

function sod_save_unified_learning_bank(array $bank): bool {
    return update_option('sod_unified_learning_bank', $bank, false);
}

function sod_store_learning_mapping(string $type, string $phrase, string $unified_name, string $source = 'merge'): bool {
    $type = sanitize_key($type);
    $phrase = trim(sanitize_text_field($phrase));
    $unified_name = trim(sanitize_text_field($unified_name));
    if ($type === '' || $phrase === '' || $unified_name === '') return false;
    $bank = sod_get_unified_learning_bank();
    if (!isset($bank[$type]) || !is_array($bank[$type])) $bank[$type] = [];
    $key = function_exists('mb_strtolower') ? mb_strtolower($phrase, 'UTF-8') : strtolower($phrase);
    $existing = isset($bank[$type][$key]) && is_array($bank[$type][$key]) ? $bank[$type][$key] : [];
    $bank[$type][$key] = [
        'phrase' => $phrase,
        'unified_name' => $unified_name,
        'hits' => max(1, (int)($existing['hits'] ?? 0)),
        'last_used' => (string)($existing['last_used'] ?? ''),
        'source' => (string)($existing['source'] ?? $source),
        'updated_at' => current_time('mysql'),
    ];
    return sod_save_unified_learning_bank($bank);
}

function sod_touch_learning_mapping(string $type, string $phrase): void {
    $type = sanitize_key($type);
    $phrase = trim(sanitize_text_field($phrase));
    if ($type === '' || $phrase === '') return;
    $bank = sod_get_unified_learning_bank();
    $key = function_exists('mb_strtolower') ? mb_strtolower($phrase, 'UTF-8') : strtolower($phrase);
    if (!isset($bank[$type][$key]) || !is_array($bank[$type][$key])) return;
    $bank[$type][$key]['hits'] = (int)($bank[$type][$key]['hits'] ?? 0) + 1;
    $bank[$type][$key]['last_used'] = current_time('mysql');
    $bank[$type][$key]['updated_at'] = current_time('mysql');
    sod_save_unified_learning_bank($bank);
}

function sod_get_learning_bank_for_type(string $type): array {
    $bank = sod_get_unified_learning_bank();
    $type = sanitize_key($type);
    return isset($bank[$type]) && is_array($bank[$type]) ? $bank[$type] : [];
}

function sod_remove_learning_mapping(string $type, string $phrase, bool $remove_alias = true): array {
    $type = sanitize_key($type);
    $phrase = trim(sanitize_text_field($phrase));
    if ($type === '' || $phrase === '') {
        return ['ok' => false, 'message' => 'العبارة المراد حذفها غير صالحة.'];
    }

    $bank = sod_get_unified_learning_bank();
    $key = function_exists('mb_strtolower') ? mb_strtolower($phrase, 'UTF-8') : strtolower($phrase);
    $existing = isset($bank[$type][$key]) && is_array($bank[$type][$key]) ? $bank[$type][$key] : [];
    $found = false;

    if (isset($bank[$type][$key])) {
        unset($bank[$type][$key]);
        $found = true;
    }

    if (!$found && isset($bank[$type]) && is_array($bank[$type])) {
        foreach ((array)$bank[$type] as $row_key => $row) {
            if (trim((string)($row['phrase'] ?? '')) === $phrase) {
                unset($bank[$type][$row_key]);
                $existing = is_array($row) ? $row : $existing;
                $found = true;
            }
        }
    }

    if ($found) {
        sod_save_unified_learning_bank($bank);
    }

    if ($remove_alias) {
        sod_remove_registry_alias($type, $phrase);
    }

    if ($found) {
        $canonical = trim((string)($existing['unified_name'] ?? ''));
        return ['ok' => true, 'message' => $canonical !== ''
            ? sprintf('تم حذف العبارة "%s" من بنك التعلّم وإيقاف توحيدها التلقائي مع "%s" للأخبار الجديدة.', $phrase, $canonical)
            : sprintf('تم حذف العبارة "%s" من بنك التعلّم.', $phrase)];
    }

    return ['ok' => false, 'message' => 'لم يتم العثور على العبارة داخل بنك التعلّم.'];
}

function sod_apply_learning_bank_to_text(string $text, string $type = ''): string {
    $text = (string)$text;
    if (trim($text) === '') return $text;
    $types = $type !== '' ? [sanitize_key($type)] : ['actors','locations','weapons'];
    foreach ($types as $current_type) {
        $items = sod_get_learning_bank_for_type($current_type);
        if (empty($items)) continue;
        uasort($items, static function($a, $b){
            return mb_strlen((string)($b['phrase'] ?? '')) <=> mb_strlen((string)($a['phrase'] ?? ''));
        });
        foreach ($items as $row) {
            $phrase = trim((string)($row['phrase'] ?? ''));
            $unified_name = trim((string)($row['unified_name'] ?? ''));
            if ($phrase === '' || $unified_name === '' || $phrase === $unified_name) continue;
            if (sod_is_registry_phrase_blocked($current_type, $phrase, $unified_name)) continue;
            $text = str_replace($phrase, $unified_name, $text);
        }
    }
    return $text;
}

function sod_get_unified_registry_merge_log(int $limit = 50): array {
    $entries = get_option('sod_unified_registry_merge_log', []);
    $entries = is_array($entries) ? $entries : [];
    return array_slice($entries, 0, max(1, min(200, $limit)));
}

function sod_append_unified_registry_merge_log(array $entry): void {
    $entries = get_option('sod_unified_registry_merge_log', []);
    $entries = is_array($entries) ? $entries : [];
    array_unshift($entries, $entry);
    update_option('sod_unified_registry_merge_log', array_slice($entries, 0, 200), false);
}

function sod_get_registry_aliases_for_type(string $type): array {
    $map = sod_get_unified_registry_alias_map();
    $type = sanitize_key($type);
    $items = isset($map[$type]) && is_array($map[$type]) ? $map[$type] : [];
    return $items;
}

function sod_set_registry_alias(string $type, string $alias, string $canonical): bool {
    $type = sanitize_key($type);
    $alias = trim(sanitize_text_field($alias));
    $canonical = trim(sanitize_text_field($canonical));
    if ($type === '' || $alias === '' || $canonical === '') return false;
    if (sod_is_registry_phrase_blocked($type, $alias, $canonical)) return false;
    $map = sod_get_unified_registry_alias_map();
    if (!isset($map[$type]) || !is_array($map[$type])) $map[$type] = [];
    $lower_alias = function_exists('mb_strtolower') ? mb_strtolower($alias, 'UTF-8') : strtolower($alias);
    $lower_canonical = function_exists('mb_strtolower') ? mb_strtolower($canonical, 'UTF-8') : strtolower($canonical);
    $canonical = isset($map[$type][$canonical]) && trim((string)$map[$type][$canonical]) !== '' ? trim((string)$map[$type][$canonical]) : $canonical;
    if (isset($map[$type][$lower_canonical]) && trim((string)$map[$type][$lower_canonical]) !== '') {
        $canonical = trim((string)$map[$type][$lower_canonical]);
    }
    foreach ((array)$map[$type] as $existing_alias => $existing_canonical) {
        if (trim((string)$existing_canonical) === $alias) {
            $map[$type][$existing_alias] = $canonical;
        }
    }
    $map[$type][$alias] = $canonical;
    $map[$type][$lower_alias] = $canonical;
    $saved = sod_save_unified_registry_alias_map($map);
    if ($saved) {
        sod_store_learning_mapping($type, $alias, $canonical, 'merge');
    }
    return $saved;
}

function sod_remove_registry_alias(string $type, string $alias): bool {
    $type = sanitize_key($type);
    $alias = trim(sanitize_text_field($alias));
    $map = sod_get_unified_registry_alias_map();
    if (!isset($map[$type]) || !is_array($map[$type])) return false;
    unset($map[$type][$alias]);
    unset($map[$type][function_exists('mb_strtolower') ? mb_strtolower($alias, 'UTF-8') : strtolower($alias)]);
    return sod_save_unified_registry_alias_map($map);
}

function sod_registry_detach_alias(string $type, string $alias, string $canonical = ''): array {
    $type = sanitize_key($type);
    $alias = trim(sanitize_text_field($alias));
    $canonical = trim(sanitize_text_field($canonical));
    if ($type === '' || $alias === '') {
        return ['ok' => false, 'message' => 'الاسم المراد فصله غير صالح.'];
    }

    $removed_alias = sod_remove_registry_alias($type, $alias);
    $learning_result = sod_remove_learning_mapping($type, $alias, false);
    $blocked = sod_add_registry_blocked_phrase($type, $alias, $canonical);

    global $wpdb;
    if ($type === 'actors') {
        $wpdb->query($wpdb->prepare("UPDATE {$wpdb->prefix}so_news_events SET actor_v2 = %s WHERE actor_v2 = %s", $alias, $canonical));
        $wpdb->query($wpdb->prepare("UPDATE {$wpdb->prefix}so_actor_memory SET actor_name = %s WHERE actor_name = %s", $alias, $canonical));
    } elseif ($type === 'weapons') {
        $wpdb->query($wpdb->prepare("UPDATE {$wpdb->prefix}so_news_events SET weapon_v2 = REPLACE(weapon_v2, %s, %s) WHERE weapon_v2 LIKE %s", $canonical, $alias, '%' . $wpdb->esc_like($canonical) . '%'));
        $wpdb->query($wpdb->prepare("UPDATE {$wpdb->prefix}so_actor_memory SET weapon = REPLACE(weapon, %s, %s) WHERE weapon LIKE %s", $canonical, $alias, '%' . $wpdb->esc_like($canonical) . '%'));
    } elseif ($type === 'locations') {
        $wpdb->query($wpdb->prepare("UPDATE {$wpdb->prefix}so_news_events SET region = CASE WHEN region = %s THEN %s ELSE region END, target_v2 = REPLACE(target_v2, %s, %s) WHERE region = %s OR target_v2 LIKE %s", $canonical, $alias, $canonical, $alias, $canonical, '%' . $wpdb->esc_like($canonical) . '%'));
        $wpdb->query($wpdb->prepare("UPDATE {$wpdb->prefix}so_actor_memory SET target = REPLACE(target, %s, %s) WHERE target LIKE %s", $canonical, $alias, '%' . $wpdb->esc_like($canonical) . '%'));
    }

    if (!$removed_alias && empty($learning_result['ok']) && !$blocked) {
        return ['ok' => false, 'message' => 'لم يتم العثور على هذا الاسم داخل مصادر الدمج القابلة للفصل.'];
    }

    sod_append_unified_registry_merge_log([
        'time' => time(),
        'type' => $type,
        'alias' => $alias,
        'canonical' => $canonical,
        'action' => 'detach_alias',
    ]);

    return ['ok' => true, 'message' => $canonical !== ''
        ? sprintf('تم فصل "%s" بالكامل عن "%s"، وحُفظ في قائمة منع إعادة الدمج، ولن يعود تلقائيًا حتى بعد تعديل الخبر أو إعادة الفهرسة.', $alias, $canonical)
        : sprintf('تم فصل "%s" بالكامل وحُفظ في قائمة منع إعادة الدمج.', $alias)];
}


/**
 * Resolve a term to its canonical value using the persistent alias map.
 */
function sod_resolve_registry_canonical(string $type, string $value): string {
    $value = trim(sanitize_text_field($value));
    if ($value === '') return '';
    $aliases = sod_get_registry_aliases_for_type($type);
    $learning = sod_get_learning_bank_for_type($type);
    $lookup = function_exists('mb_strtolower') ? mb_strtolower($value, 'UTF-8') : strtolower($value);
    if (isset($aliases[$value]) && trim((string)$aliases[$value]) !== '') {
        $resolved = trim((string)$aliases[$value]);
        if (!sod_is_registry_phrase_blocked($type, $value, $resolved)) {
            sod_touch_learning_mapping($type, $value);
            return $resolved;
        }
    }
    if (isset($aliases[$lookup]) && trim((string)$aliases[$lookup]) !== '') {
        $resolved = trim((string)$aliases[$lookup]);
        if (!sod_is_registry_phrase_blocked($type, $value, $resolved)) {
            sod_touch_learning_mapping($type, $value);
            return $resolved;
        }
    }
    if (isset($learning[$lookup]['unified_name']) && trim((string)$learning[$lookup]['unified_name']) !== '') {
        $resolved = trim((string)$learning[$lookup]['unified_name']);
        if (!sod_is_registry_phrase_blocked($type, $value, $resolved)) {
            sod_touch_learning_mapping($type, $value);
            return $resolved;
        }
    }
    return $value;
}

function sod_registry_apply_canonical_resolution(array $payload): array {
    foreach (['actor_v2' => 'actors', 'region' => 'locations', 'weapon_v2' => 'weapons'] as $field => $type) {
        if (!empty($payload[$field])) {
            $payload[$field] = sod_resolve_registry_canonical($type, (string)$payload[$field]);
        }
    }
    foreach (['target_v2'] as $field) {
        if (!empty($payload[$field])) {
            $parts = preg_split('/\s*\|\s*/u', (string)$payload[$field]);
            $parts = array_filter(array_map(static function($part){ return sod_resolve_registry_canonical('locations', (string)$part); }, (array)$parts));
            $payload[$field] = implode(' | ', array_values(array_unique($parts)));
        }
    }
    return $payload;
}

function sod_get_unified_registry_bank_key(string $type): string {
    switch ($type) {
        case 'actors': return 'actors';
        case 'locations': return 'regions';
        case 'weapons': return 'weapons';
        default: return '';
    }
}

function sod_registry_stripos(string $haystack, string $needle): bool {
    if ($needle === '') return true;
    if (function_exists('mb_stripos')) return mb_stripos($haystack, $needle, 0, 'UTF-8') !== false;
    return stripos($haystack, $needle) !== false;
}

function sod_render_unified_registry_rows(string $registry_type, array $registry_items): string {
    ob_start();
    if (empty($registry_items)) {
        ?>
        <tr><td colspan="8" style="text-align:center; padding:22px; color:#646970;">لا توجد نتائج في هذا القسم.</td></tr>
        <?php
    } else {
