                            <?php if (!empty($aliases_remaining)): ?>
                                <span style="background:#f3f4f6; color:#374151; border-radius:999px; padding:3px 8px; font-size:12px;">+<?php echo esc_html((string)count($aliases_remaining)); ?> إضافية</span>
                            <?php endif; ?>
