                            <summary style="cursor:pointer; color:#1d4ed8; font-size:12px; user-select:none;">إدارة الأسماء المدموجة (<?php echo esc_html((string)count($aliases)); ?>)</summary>
                            <div style="display:grid; gap:6px; margin-top:8px; max-height:160px; overflow:auto; padding-inline-start:2px;">
                                <?php foreach ($aliases as $alias_name): ?>
