                                        <span style="font-size:12px; line-height:1.5;"><?php echo esc_html(sod_fix_mojibake_text((string)$alias_name)); ?></span>
                                        <button type="submit" class="button-link-delete" style="padding:0 2px; text-decoration:none; line-height:1; white-space:nowrap;" title="إزالة من الدمج">حذف</button>
                                    </form>
                                <?php endforeach; ?>
                            </div>
                        </details>
                    <?php else: ?>—<?php endif; ?>
                </td>
                <td><?php echo esc_html((string)((int)($item['hits'] ?? 0))); ?></td>
                <td><?php echo esc_html(implode(' + ', array_map('strval', (array)($item['sources'] ?? [])))); ?></td>
                <td><?php echo !empty($item['last_seen']) ? esc_html(date_i18n('Y/m/d H:i', (int)$item['last_seen'])) : '—'; ?></td>
                <td>
