function sod_render_unified_learning_bank_table(string $type): string {
    $items = array_values(sod_get_learning_bank_for_type($type));
    usort($items, static function($a, $b){ return ((int)($b['hits'] ?? 0)) <=> ((int)($a['hits'] ?? 0)); });
    $items = array_slice($items, 0, 50);
    ob_start();
    if (empty($items)) {
        echo '<p style="margin:0; color:#646970;">لا توجد عناصر محفوظة في بنك التعلّم بعد.</p>';
    } else {
        echo '<p style="margin:0 0 10px; color:#646970; font-size:12px;">لحذف عبارة دُمجت بالخطأ، استخدم زر <strong>حذف من التعلّم</strong>. هذا يوقف التوحيد التلقائي لهذه العبارة في الأخبار الجديدة دون تحديث الصفحة.</p>';
        echo '<table class="widefat striped"><thead><tr><th>#</th><th>العبارة المتعلَّمة</th><th>الاسم الموحد</th><th>مرات الاستخدام</th><th>آخر استخدام</th><th>إجراء</th></tr></thead><tbody>';
        foreach ($items as $i => $row) {
            $phrase = (string)($row['phrase'] ?? '');
            echo '<tr>';
            echo '<td>' . esc_html((string)($i + 1)) . '</td>';
            echo '<td>' . esc_html($phrase) . '</td>';
            echo '<td><strong>' . esc_html((string)($row['unified_name'] ?? '')) . '</strong></td>';
            echo '<td>' . esc_html((string)((int)($row['hits'] ?? 0))) . '</td>';
            echo '<td>' . (!empty($row['last_used']) ? esc_html((string)$row['last_used']) : '—') . '</td>';
            echo '<td>';
            echo "<form method=\"post\" class=\"sod-registry-ajax-form\" data-registry-action=\"remove_learning\" onsubmit=\"return confirm('حذف هذه العبارة من بنك التعلّم وإيقاف دمجها التلقائي مستقبلًا؟');\" style=\"display:inline;\">";
            ob_start(); wp_nonce_field('sod_unified_registry_save'); $nonce_html = ob_get_clean(); echo $nonce_html;
            echo '<input type="hidden" name="sod_registry_action" value="remove_learning">';
            echo '<input type="hidden" name="registry_type" value="' . esc_attr($type) . '">';
            echo '<input type="hidden" name="registry_phrase" value="' . esc_attr($phrase) . '">';
            echo '<button class="button button-small">حذف من التعلّم</button>';
            echo '</form>';
            echo '</td>';
            echo '</tr>';
        }
        echo '</tbody></table>';
    }
    return (string)ob_get_clean();
}


function sod_export_learning_bank_payload(string $type = ''): array {
    $labels = sod_get_unified_registry_labels();
    $payload = [
        'exported_at' => current_time('mysql'),
        'site' => home_url('/'),
        'version' => 1,
        'types' => [],
    ];
    $types = $type && isset($labels[$type]) ? [$type] : array_keys($labels);
    foreach ($types as $registry_type) {
        $payload['types'][$registry_type] = array_values(sod_get_learning_bank_for_type($registry_type));
    }
    return $payload;
}

function sod_import_learning_bank_payload(array $payload, string $mode = 'merge'): array {
    $labels = sod_get_unified_registry_labels();
    $types = isset($payload['types']) && is_array($payload['types']) ? $payload['types'] : [];
    if (empty($types)) {
        return ['ok' => false, 'message' => 'ملف بنك التعلّم غير صالح أو لا يحتوي على بيانات قابلة للاستيراد.'];
    }

    $all = get_option('sod_learning_bank', []);
    if (!is_array($all)) {
        $all = [];
    }
    if ($mode === 'replace') {
        foreach (array_keys($labels) as $label_type) {
            $all[$label_type] = [];
        }
    }

    $imported = 0;
    $updated = 0;
    foreach ($types as $type => $rows) {
        $type = sanitize_key((string)$type);
        if (!isset($labels[$type]) || !is_array($rows)) {
            continue;
        }
        if (!isset($all[$type]) || !is_array($all[$type])) {
            $all[$type] = [];
        }
        foreach ($rows as $row) {
            if (!is_array($row)) continue;
            $phrase = trim(sanitize_text_field((string)($row['phrase'] ?? '')));
            $unified = trim(sanitize_text_field((string)($row['unified_name'] ?? '')));
            if ($phrase === '' || $unified === '') continue;
            $lookup = function_exists('mb_strtolower') ? mb_strtolower($phrase, 'UTF-8') : strtolower($phrase);
            $incoming_hits = max(1, (int)($row['hits'] ?? 1));
            $incoming_last = trim((string)($row['last_used'] ?? current_time('mysql')));
            if (!isset($all[$type][$lookup]) || !is_array($all[$type][$lookup])) {
                $all[$type][$lookup] = [
                    'phrase' => $phrase,
                    'unified_name' => $unified,
                    'hits' => $incoming_hits,
                    'last_used' => $incoming_last,
                    'source' => trim((string)($row['source'] ?? 'import')),
                ];
                $imported++;
                continue;
            }
            $existing = $all[$type][$lookup];
            if ($mode === 'newer') {
                $existing_ts = !empty($existing['last_used']) ? strtotime((string)$existing['last_used']) : 0;
                $incoming_ts = !empty($incoming_last) ? strtotime($incoming_last) : 0;
                if ($incoming_ts >= $existing_ts) {
                    $all[$type][$lookup] = array_merge($existing, [
                        'phrase' => $phrase,
                        'unified_name' => $unified,
                        'hits' => max((int)($existing['hits'] ?? 0), $incoming_hits),
                        'last_used' => $incoming_last,
                        'source' => trim((string)($row['source'] ?? 'import')),
                    ]);
                    $updated++;
                }
            } else {
                $all[$type][$lookup] = array_merge($existing, [
                    'phrase' => $phrase,
                    'unified_name' => $unified,
                    'hits' => max((int)($existing['hits'] ?? 0), $incoming_hits),
                    'last_used' => !empty($incoming_last) ? $incoming_last : (string)($existing['last_used'] ?? current_time('mysql')),
                ]);
                $updated++;
            }
        }
    }

    update_option('sod_learning_bank', $all, false);
    return ['ok' => true, 'message' => sprintf('تم استيراد %d سجل وتحديث %d سجل في بنك التعلّم.', $imported, $updated)];
}

function sod_registry_ajax_payload(string $type, string $search = ''): array {
    $labels = sod_get_unified_registry_labels();
    if (!isset($labels[$type])) {
        $type = 'actors';
    }
    $items = sod_get_unified_registry_items($type, $search, 120);
    $stats = [
        'actors' => count(sod_get_unified_registry_items('actors', '', 80)),
        'locations' => count(sod_get_unified_registry_items('locations', '', 80)),
        'weapons' => count(sod_get_unified_registry_items('weapons', '', 80)),
    ];
    return [
        'type' => $type,
        'search' => $search,
        'stats' => $stats,
        'rows_html' => sod_render_unified_registry_rows($type, $items),
        'log_html' => sod_render_unified_registry_merge_log_table(sod_get_unified_registry_merge_log(20), $labels, $type),
        'learning_html' => sod_render_unified_learning_bank_table($type),
    ];
}

function sod_registry_bulk_merge_terms(string $type, array $aliases, string $canonical): array {
    $type = sanitize_key($type);
    $canonical = trim(sanitize_text_field($canonical));
    $aliases = array_values(array_unique(array_filter(array_map(static function($v){ return trim(sanitize_text_field((string)$v)); }, $aliases))));
    if ($canonical === '') return ['ok' => false, 'message' => 'الاسم الموحد مطلوب للدمج الجماعي.'];
    if (count($aliases) < 2) return ['ok' => false, 'message' => 'اختر سطرين على الأقل لتنفيذ الدمج الجماعي.'];
    $merged = 0;
    foreach ($aliases as $alias) {
        if ($alias === '' || $alias === $canonical) continue;
        $result = sod_registry_merge_term($type, $alias, $canonical);
        if (!empty($result['ok'])) $merged++;
    }
    if ($merged <= 0) return ['ok' => false, 'message' => 'لم يتم دمج أي سجل. تأكد أن الاسم القياسي يختلف عن العناصر المحددة.'];
    return ['ok' => true, 'message' => sprintf('تم دمج %d سجل داخل الاسم الموحد المحدد.', $merged)];
}

function sod_ajax_registry_manage() {
    if (!current_user_can('manage_options')) {
        wp_send_json_error(['message' => 'غير مصرح لك بتنفيذ هذا الإجراء.'], 403);
    }
    check_ajax_referer('sod_unified_registry_save', 'nonce');
    $action_kind = sanitize_key($_POST['registry_action_kind'] ?? '');
    $type = sanitize_key($_POST['registry_type'] ?? 'actors');
    $search = sanitize_text_field($_POST['registry_search'] ?? '');
    if ($action_kind === 'search' || $action_kind === 'switch_type') {
        wp_send_json_success(array_merge(['message' => 'تم تحديث الفلتر.'], sod_registry_ajax_payload($type, $search)));
    }
    if ($action_kind === 'bulk_merge') {
        $selected = isset($_POST['selected_rows']) ? (array)$_POST['selected_rows'] : [];
        $result = sod_registry_bulk_merge_terms($type, $selected, (string)($_POST['registry_canonical'] ?? ''));
    } elseif ($action_kind === 'add') {
        $result = sod_registry_upsert_term($type, (string)($_POST['registry_value'] ?? ''));
    } elseif ($action_kind === 'remove') {
        $result = sod_registry_remove_term($type, (string)($_POST['registry_value'] ?? ''));
    } elseif ($action_kind === 'merge') {
        $result = sod_registry_merge_term($type, (string)($_POST['registry_alias'] ?? ''), (string)($_POST['registry_canonical'] ?? ''));
    } elseif ($action_kind === 'rollback') {
        $result = sod_registry_rollback_merge((int)($_POST['registry_log_index'] ?? -1));
    } elseif ($action_kind === 'remove_learning') {
        $result = sod_remove_learning_mapping($type, (string)($_POST['registry_phrase'] ?? ''), true);
    } elseif ($action_kind === 'remove_alias') {
        $result = sod_registry_detach_alias($type, (string)($_POST['registry_alias'] ?? ''), (string)($_POST['registry_canonical'] ?? ''));
    } elseif ($action_kind === 'export_learning') {
        $payload = sod_registry_ajax_payload($type, $search);
        $payload['export_data'] = sod_export_learning_bank_payload($type);
        wp_send_json_success(array_merge(['message' => 'تم تجهيز ملف بنك التعلّم للتصدير.'], $payload));
    } elseif ($action_kind === 'import_learning') {
        $raw = wp_unslash((string)($_POST['learning_import_json'] ?? ''));
        $decoded = json_decode($raw, true);
        if (!is_array($decoded)) {
            wp_send_json_error(array_merge(['message' => 'ملف JSON غير صالح.'], sod_registry_ajax_payload($type, $search)), 200);
        }
        $mode = sanitize_key((string)($_POST['import_mode'] ?? 'merge'));
        if (!in_array($mode, ['merge','replace','newer'], true)) {
            $mode = 'merge';
        }
        $result = sod_import_learning_bank_payload($decoded, $mode);
    } else {
        wp_send_json_error(['message' => 'إجراء غير صالح.'], 400);
    }
    $payload = sod_registry_ajax_payload($type, $search);
    if (!empty($result['ok'])) {
        wp_send_json_success(array_merge(['message' => (string)($result['message'] ?? 'تم التحديث.')], $payload));
    }
    wp_send_json_error(array_merge(['message' => (string)($result['message'] ?? 'تعذر تنفيذ العملية.')], $payload), 200);
}
add_action('wp_ajax_sod_registry_manage', 'sod_ajax_registry_manage');

function sod_get_unified_registry_items(string $type, string $search = '', int $limit = 120): array {
    global $wpdb;
    $type = sanitize_key($type ?: 'actors');
    $search = trim((string)$search);
    $limit = max(20, min(300, (int)$limit));
    $items = [];

    if ($type === 'actors') {
        $rows = (array)$wpdb->get_results("SELECT actor_name AS item_name, COUNT(*) AS hits, MAX(timestamp) AS last_seen FROM {$wpdb->prefix}so_actor_memory WHERE actor_name IS NOT NULL AND actor_name != '' GROUP BY actor_name ORDER BY hits DESC, last_seen DESC LIMIT {$limit}", ARRAY_A);
        foreach ($rows as $row) {
            $name = trim((string)($row['item_name'] ?? ''));
            if ($name === '' || $name === 'فاعل غير محسوم') continue;
            $items[$name] = ['name' => $name, 'hits' => (int)($row['hits'] ?? 0), 'last_seen' => (int)($row['last_seen'] ?? 0), 'sources' => ['memory']];
        }
        foreach ((array)$wpdb->get_col("SELECT name_ar FROM {$wpdb->prefix}so_dict_actors ORDER BY name_ar ASC LIMIT {$limit}") as $name) {
            $name = trim((string)$name);
            if ($name === '') continue;
            if (!isset($items[$name])) $items[$name] = ['name' => $name, 'hits' => 0, 'last_seen' => 0, 'sources' => []];
            $items[$name]['sources'][] = 'dictionary';
        }
    } elseif ($type === 'weapons') {
        $rows = (array)$wpdb->get_results("SELECT weapon, COUNT(*) AS hits, MAX(timestamp) AS last_seen FROM {$wpdb->prefix}so_actor_memory WHERE weapon IS NOT NULL AND weapon != '' GROUP BY weapon ORDER BY hits DESC, last_seen DESC LIMIT {$limit}", ARRAY_A);
        foreach ($rows as $row) {
            foreach (preg_split('/\s*\|\s*/u', (string)($row['weapon'] ?? '')) as $piece) {
                $name = trim((string)$piece);
                if ($name === '') continue;
                if (!isset($items[$name])) $items[$name] = ['name' => $name, 'hits' => 0, 'last_seen' => 0, 'sources' => []];
                $items[$name]['hits'] += (int)($row['hits'] ?? 0);
                $items[$name]['last_seen'] = max((int)$items[$name]['last_seen'], (int)($row['last_seen'] ?? 0));
                $items[$name]['sources'][] = 'memory';
            }
        }
        foreach ((array)$wpdb->get_col("SELECT name_ar FROM {$wpdb->prefix}so_dict_weapons ORDER BY name_ar ASC LIMIT {$limit}") as $name) {
            $name = trim((string)$name);
            if ($name === '') continue;
            if (!isset($items[$name])) $items[$name] = ['name' => $name, 'hits' => 0, 'last_seen' => 0, 'sources' => []];
            $items[$name]['sources'][] = 'dictionary';
        }
    } else {
        $rows = (array)$wpdb->get_results("SELECT region AS item_name, COUNT(*) AS hits, MAX(event_timestamp) AS last_seen FROM {$wpdb->prefix}so_news_events WHERE region IS NOT NULL AND region != '' GROUP BY region ORDER BY hits DESC, last_seen DESC LIMIT {$limit}", ARRAY_A);
        foreach ($rows as $row) {
            $name = trim((string)($row['item_name'] ?? ''));
            if ($name === '') continue;
            $items[$name] = ['name' => $name, 'hits' => (int)($row['hits'] ?? 0), 'last_seen' => (int)($row['last_seen'] ?? 0), 'sources' => ['events']];
        }
        $rows = (array)$wpdb->get_results("SELECT target, COUNT(*) AS hits, MAX(timestamp) AS last_seen FROM {$wpdb->prefix}so_actor_memory WHERE target IS NOT NULL AND target != '' GROUP BY target ORDER BY hits DESC, last_seen DESC LIMIT {$limit}", ARRAY_A);
        foreach ($rows as $row) {
            foreach (preg_split('/\s*\|\s*/u', (string)($row['target'] ?? '')) as $piece) {
                $name = trim((string)$piece);
                if ($name === '') continue;
                if (!isset($items[$name])) $items[$name] = ['name' => $name, 'hits' => 0, 'last_seen' => 0, 'sources' => []];
                $items[$name]['hits'] += (int)($row['hits'] ?? 0);
                $items[$name]['last_seen'] = max((int)$items[$name]['last_seen'], (int)($row['last_seen'] ?? 0));
                $items[$name]['sources'][] = 'memory';
            }
        }
    }

    $bank_key = sod_get_unified_registry_bank_key($type);
    if ($bank_key !== '') {
        foreach ((array)sod_get_bank_values($bank_key) as $name) {
            $name = trim((string)$name);
            if ($name === '') continue;
            if (!isset($items[$name])) $items[$name] = ['name' => $name, 'hits' => 0, 'last_seen' => 0, 'sources' => []];
            $items[$name]['sources'][] = 'bank';
        }
    }

    $alias_map = sod_get_registry_aliases_for_type($type);
    $reverse_aliases = [];
    foreach ($alias_map as $alias_name => $canonical_name) {
        $alias_name = trim((string)$alias_name);
        $canonical_name = trim((string)$canonical_name);
        if ($alias_name === '' || $canonical_name === '' || $alias_name === $canonical_name) continue;
        if (sod_is_registry_phrase_blocked($type, $alias_name, $canonical_name)) continue;
        $reverse_aliases[$canonical_name][] = $alias_name;
    }

    // إذا كان الاسم قد دُمج كاسم بديل، لا نُظهره كسطر مستقل؛
    // بل نضمّ إحصاءه ومصادره وآخر ظهوره إلى الاسم الموحد نفسه.
    foreach ($alias_map as $alias_name => $canonical_name) {
        $alias_name = trim((string)$alias_name);
        $canonical_name = trim((string)$canonical_name);
        if ($alias_name === '' || $canonical_name === '' || $alias_name === $canonical_name) continue;
        if (sod_is_registry_phrase_blocked($type, $alias_name, $canonical_name)) continue;
        if (!isset($items[$alias_name])) continue;
        if (!isset($items[$canonical_name])) {
            $items[$canonical_name] = ['name' => $canonical_name, 'hits' => 0, 'last_seen' => 0, 'sources' => []];
        }
        $items[$canonical_name]['hits'] += (int)($items[$alias_name]['hits'] ?? 0);
        $items[$canonical_name]['last_seen'] = max((int)($items[$canonical_name]['last_seen'] ?? 0), (int)($items[$alias_name]['last_seen'] ?? 0));
        $items[$canonical_name]['sources'] = array_values(array_unique(array_merge(
            (array)($items[$canonical_name]['sources'] ?? []),
            (array)($items[$alias_name]['sources'] ?? [])
        )));
        unset($items[$alias_name]);
    }

    $out = [];
    foreach ($items as $name => $item) {
        $item['sources'] = array_values(array_unique(array_filter(array_map('strval', (array)($item['sources'] ?? [])))));
        $item['aliases'] = array_values(array_unique(array_filter(array_map('strval', (array)($reverse_aliases[$name] ?? [])))));
        $item['alias_count'] = count($item['aliases']);
        if ($search !== '' && !sod_registry_stripos($name, $search) && !sod_registry_stripos(implode(' ', $item['aliases']), $search)) continue;
        $out[] = $item;
    }
    usort($out, static function ($a, $b) {
        if ((int)$a['hits'] === (int)$b['hits']) return strcmp((string)$a['name'], (string)$b['name']);
        return (int)$b['hits'] <=> (int)$a['hits'];
    });
    return array_slice($out, 0, $limit);
}

function sod_registry_upsert_term(string $type, string $value): array {
    global $wpdb;
    $type = sanitize_key($type);
    $value = trim(sanitize_text_field($value));
    if ($value === '') return ['ok' => false, 'message' => 'القيمة فارغة'];
    $bank_key = sod_get_unified_registry_bank_key($type);
    if ($bank_key !== '') sod_add_bank_value($bank_key, $value);
    if ($type === 'actors') {
        $exists = (int)$wpdb->get_var($wpdb->prepare("SELECT id FROM {$wpdb->prefix}so_dict_actors WHERE name_ar = %s LIMIT 1", $value));
        if ($exists <= 0) {
            $wpdb->insert("{$wpdb->prefix}so_dict_actors", ['actor_id' => (sanitize_title($value) ?: md5($value)), 'name_ar' => $value, 'threat_weight' => 0.5, 'keywords' => $value, 'base_threat' => 30], ['%s','%s','%f','%s','%d']);
        }
    } elseif ($type === 'weapons') {
        $exists = (int)$wpdb->get_var($wpdb->prepare("SELECT id FROM {$wpdb->prefix}so_dict_weapons WHERE name_ar = %s LIMIT 1", $value));
        if ($exists <= 0) {
            $wpdb->insert("{$wpdb->prefix}so_dict_weapons", ['weapon_id' => (sanitize_title($value) ?: md5($value)), 'name_ar' => $value, 'impact_score' => 30, 'keywords' => $value], ['%s','%s','%d','%s']);
        }
    }
    return ['ok' => true, 'message' => 'تمت إضافة السجل إلى بنك المعلومات الموحّد.'];
}

function sod_registry_remove_term(string $type, string $value): array {
    global $wpdb;
    $type = sanitize_key($type);
    $value = trim(sanitize_text_field($value));
    if ($value === '') return ['ok' => false, 'message' => 'القيمة فارغة'];
    $bank_key = sod_get_unified_registry_bank_key($type);
    if ($bank_key !== '') sod_remove_bank_value($bank_key, $value);
    if ($type === 'actors') $wpdb->delete("{$wpdb->prefix}so_dict_actors", ['name_ar' => $value], ['%s']);
    if ($type === 'weapons') $wpdb->delete("{$wpdb->prefix}so_dict_weapons", ['name_ar' => $value], ['%s']);
    return ['ok' => true, 'message' => 'تم حذف السجل من بنك المعلومات الموحّد.'];
}

function sod_registry_merge_term(string $type, string $alias, string $canonical): array {
    global $wpdb;
    $type = sanitize_key($type);
    $alias = trim(sanitize_text_field($alias));
    $canonical = trim(sanitize_text_field($canonical));
    if ($alias === '' || $canonical === '') return ['ok' => false, 'message' => 'الاسم البديل أو الاسم الموحد فارغ.'];
    if ($alias === $canonical) return ['ok' => false, 'message' => 'الاسمان متطابقان بالفعل.'];
    if (sod_is_registry_phrase_blocked($type, $alias, $canonical)) return ['ok' => false, 'message' => 'هذا الاسم موجود في قائمة منع إعادة الدمج. أزله من المنع أولًا إذا أردت دمجه من جديد.'];

    $snapshot = [
        'time' => time(),
        'type' => $type,
        'alias' => $alias,
        'canonical' => $canonical,
        'bank_key' => sod_get_unified_registry_bank_key($type),
    ];

    sod_registry_upsert_term($type, $canonical);
    sod_set_registry_alias($type, $alias, $canonical);
    $bank_key = sod_get_unified_registry_bank_key($type);
    if ($bank_key !== '') sod_remove_bank_value($bank_key, $alias);

    if ($type === 'actors') {
        $snapshot['news_events_ids'] = array_map('intval', (array)$wpdb->get_col($wpdb->prepare("SELECT id FROM {$wpdb->prefix}so_news_events WHERE actor_v2 = %s ORDER BY id DESC LIMIT 5000", $alias)));
        $snapshot['memory_ids'] = array_map('intval', (array)$wpdb->get_col($wpdb->prepare("SELECT id FROM {$wpdb->prefix}so_actor_memory WHERE actor_name = %s ORDER BY id DESC LIMIT 5000", $alias)));
        $wpdb->update("{$wpdb->prefix}so_dict_actors", ['name_ar' => $canonical], ['name_ar' => $alias], ['%s'], ['%s']);
        $wpdb->query($wpdb->prepare("UPDATE {$wpdb->prefix}so_news_events SET actor_v2 = %s WHERE actor_v2 = %s", $canonical, $alias));
        $wpdb->query($wpdb->prepare("UPDATE {$wpdb->prefix}so_actor_memory SET actor_name = %s WHERE actor_name = %s", $canonical, $alias));
    } elseif ($type === 'weapons') {
        $snapshot['news_events_ids'] = array_map('intval', (array)$wpdb->get_col($wpdb->prepare("SELECT id FROM {$wpdb->prefix}so_news_events WHERE weapon_v2 = %s ORDER BY id DESC LIMIT 5000", $alias)));
        $snapshot['memory_ids'] = array_map('intval', (array)$wpdb->get_col($wpdb->prepare("SELECT id FROM {$wpdb->prefix}so_actor_memory WHERE weapon LIKE %s ORDER BY id DESC LIMIT 5000", '%' . $wpdb->esc_like($alias) . '%')));
        $wpdb->update("{$wpdb->prefix}so_dict_weapons", ['name_ar' => $canonical], ['name_ar' => $alias], ['%s'], ['%s']);
        $wpdb->query($wpdb->prepare("UPDATE {$wpdb->prefix}so_news_events SET weapon_v2 = %s WHERE weapon_v2 = %s", $canonical, $alias));
        $wpdb->query($wpdb->prepare("UPDATE {$wpdb->prefix}so_actor_memory SET weapon = REPLACE(weapon, %s, %s) WHERE weapon LIKE %s", $alias, $canonical, '%' . $wpdb->esc_like($alias) . '%'));
    } elseif ($type === 'locations') {
        $snapshot['news_events_ids'] = array_map('intval', (array)$wpdb->get_col($wpdb->prepare("SELECT id FROM {$wpdb->prefix}so_news_events WHERE region = %s OR target_v2 LIKE %s ORDER BY id DESC LIMIT 5000", $alias, '%' . $wpdb->esc_like($alias) . '%')));
        $snapshot['memory_ids'] = array_map('intval', (array)$wpdb->get_col($wpdb->prepare("SELECT id FROM {$wpdb->prefix}so_actor_memory WHERE target LIKE %s ORDER BY id DESC LIMIT 5000", '%' . $wpdb->esc_like($alias) . '%')));
        $wpdb->query($wpdb->prepare("UPDATE {$wpdb->prefix}so_news_events SET region = %s WHERE region = %s", $canonical, $alias));
        $wpdb->query($wpdb->prepare("UPDATE {$wpdb->prefix}so_news_events SET target_v2 = REPLACE(target_v2, %s, %s) WHERE target_v2 LIKE %s", $alias, $canonical, '%' . $wpdb->esc_like($alias) . '%'));
        $wpdb->query($wpdb->prepare("UPDATE {$wpdb->prefix}so_actor_memory SET target = REPLACE(target, %s, %s) WHERE target LIKE %s", $alias, $canonical, '%' . $wpdb->esc_like($alias) . '%'));
    } else {
        return ['ok' => false, 'message' => 'نوع السجل غير مدعوم.'];
    }

    sod_append_unified_registry_merge_log($snapshot);
    return ['ok' => true, 'message' => 'تم دمج الاسم البديل داخل الاسم القياسي وتحديث السجل القديم مع حفظ سجل تراجع.'];
}

function sod_registry_rollback_merge(int $index): array {
    global $wpdb;
    $log = get_option('sod_unified_registry_merge_log', []);
    $log = is_array($log) ? array_values($log) : [];
    if (!isset($log[$index]) || !is_array($log[$index])) return ['ok' => false, 'message' => 'سجل الدمج غير موجود.'];
    $entry = $log[$index];
    $type = sanitize_key((string)($entry['type'] ?? ''));
    $alias = trim((string)($entry['alias'] ?? ''));
    $canonical = trim((string)($entry['canonical'] ?? ''));
    if ($type === '' || $alias === '' || $canonical === '') return ['ok' => false, 'message' => 'سجل الدمج ناقص.'];

    if ($type === 'actors') {
        foreach ((array)($entry['news_events_ids'] ?? []) as $id) {
            $wpdb->update("{$wpdb->prefix}so_news_events", ['actor_v2' => $alias], ['id' => (int)$id], ['%s'], ['%d']);
        }
        foreach ((array)($entry['memory_ids'] ?? []) as $id) {
            $wpdb->update("{$wpdb->prefix}so_actor_memory", ['actor_name' => $alias], ['id' => (int)$id], ['%s'], ['%d']);
        }
    } elseif ($type === 'weapons') {
        foreach ((array)($entry['news_events_ids'] ?? []) as $id) {
            $wpdb->update("{$wpdb->prefix}so_news_events", ['weapon_v2' => $alias], ['id' => (int)$id], ['%s'], ['%d']);
        }
        foreach ((array)($entry['memory_ids'] ?? []) as $id) {
            $wpdb->query($wpdb->prepare("UPDATE {$wpdb->prefix}so_actor_memory SET weapon = REPLACE(weapon, %s, %s) WHERE id = %d", $canonical, $alias, (int)$id));
        }
    } elseif ($type === 'locations') {
        foreach ((array)($entry['news_events_ids'] ?? []) as $id) {
            $wpdb->query($wpdb->prepare("UPDATE {$wpdb->prefix}so_news_events SET region = CASE WHEN region = %s THEN %s ELSE region END, target_v2 = REPLACE(target_v2, %s, %s) WHERE id = %d", $canonical, $alias, $canonical, $alias, (int)$id));
        }
        foreach ((array)($entry['memory_ids'] ?? []) as $id) {
            $wpdb->query($wpdb->prepare("UPDATE {$wpdb->prefix}so_actor_memory SET target = REPLACE(target, %s, %s) WHERE id = %d", $canonical, $alias, (int)$id));
        }
    } else {
        return ['ok' => false, 'message' => 'نوع السجل غير مدعوم للتراجع.'];
    }

    sod_remove_registry_alias($type, $alias);
    unset($log[$index]);
    update_option('sod_unified_registry_merge_log', array_values($log), false);
    return ['ok' => true, 'message' => 'تم التراجع عن الدمج وإرجاع الاسم البديل في السجلات الموثقة.'];
}

function sod_ingest_and_publish_canonical_item(array $item, array $existing_row = [], array $options = []): array {
    $analyzed = SO_OSINT_Engine::process_event($item);
    if ($analyzed) $analyzed = SO_Manual_Learning::apply_to_analyzed($item, $analyzed);
    if (!$analyzed || !is_array($analyzed) || empty($analyzed['title'])) {
        return ['ok' => false, 'error' => 'analysis_failed'];
    }
    $canonical = sod_build_canonical_event_state($existing_row, $item, $analyzed, $options);
    return ['ok' => true, 'canonical' => $canonical, 'analyzed' => $analyzed];
}

function so_get_log_file() {
    $upload_dir = wp_upload_dir();
    $log_dir = $upload_dir['basedir'] . '/beiruttime-osint-logs';
    if (!file_exists($log_dir)) { wp_mkdir_p($log_dir); file_put_contents($log_dir . '/.htaccess', "Deny from all\n"); }
    return $log_dir . '/so_debug.log';
}

function so_log($message, $level = 'INFO') {
    if (!get_option('so_enable_logging', true)) return;
    file_put_contents(so_get_log_file(), '[' . gmdate('Y-m-d H:i:s') . "] [$level] $message\n", FILE_APPEND);
}

function so_limit_text($text, $limit = 500) {
    if (sod_safe_strlen($text) > $limit) return sod_safe_substr($text, 0, $limit) . ' ...';
    return $text;
}

function so_clean_text($text) {
    if (empty($text)) return '';
    $text = html_entity_decode($text, ENT_QUOTES | ENT_HTML5, 'UTF-8');
    $text = wp_strip_all_tags($text);
    $text = preg_replace("/\b(?:https?|ftp):\/\/[a-z0-9\-+&@#\/%?=~_|!:,.;]*[a-z0-9\-+&@#\/%=~_|]/i", '', $text);
    $text = preg_replace("/(?:[0-9٠-٩]{1,2}:[0-9٠-٩]{2})\s*(?:ص|م|صباحا|مساء|am|pm)?/ui", '', $text);
    $promotional = ["/قناة\s+.*?على\s+واتساب/ui", "/للاشتراك\s+في\s+قناة/ui", "/عبر\s+الرابط/ui", "/telegram\.me/ui", "/t\.me/ui"];
    $text = preg_replace($promotional, '', $text);
    $text = preg_replace("/[\x{1F300}-\x{1F6FF}\x{2600}-\x{26FF}\x{2700}-\x{27BF}]/u", '', $text);
    $text = str_replace(["'s","عاجل","عاجل:","عاجل |","🚨","📲","🔴","🟢","💥","⚔️","📌","📊","🎯","▪️"], '', $text);
    $lines = preg_split('/\r\n|\r|\n/', $text);
    $arabic_lines = [];
    foreach ($lines as $line) {
        if (preg_match("/[\p{Arabic}]/u", $line)) {
            $line = preg_replace("/\b[a-zA-Z]{2,}\b/", '', $line);
            $arabic_lines[] = trim($line);
        }
    }
    if (empty($arabic_lines)) return trim(preg_replace('/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/', '', $text));
    return preg_replace(["/\(\s*\)/","/\[\s*\]/","/\s+/","/[!]{3,}/"], ['','', ' ','!!!'], trim(implode(' ', $arabic_lines)));
}

function so_normalize_title_for_dedupe($title) {
    $title = so_clean_text((string)$title);
    $title = html_entity_decode($title, ENT_QUOTES | ENT_HTML5, 'UTF-8');
    $title = preg_replace('/#[^\s]+/u', ' ', $title);
    $title = preg_replace('/\b(?:عاجل|خبر عاجل|متداول|أنباء أولية|أولية|حصري|متابعة|تحديث|وسائل إعلام|إعلام العدو|وكالة|رويترز|أ\s*ف\s*ب|القناة\s*\d+|صحيفة|مراسل|نقلاً عن|قال|صرح|أعلن|أكد|أفاد)\b/iu', ' ', $title);
    $title = preg_replace('/\b(?:الولايات المتحدة الأميركية|الولايات المتحدة|إيران|لبنان|فلسطين|الأراضي المحتلة|إسرائيل|غزة|الضفة الغربية|سوريا)\s*[:\-–|]+\s*/iu', ' ', $title);
    $title = preg_replace('/\d+[.:]\d+|\d+/u', ' ', $title);
    $title = preg_replace('/[\p{P}\p{S}]+/u', ' ', $title);
    $title = preg_replace('/\s+/u', ' ', trim(mb_strtolower($title)));
    return $title;
}

function so_build_alert_signature($title) {
    $normalized = so_normalize_title_for_dedupe((string)$title);
    $normalized = preg_replace('/\([0-9\/\-: ]+\)/u', '', $normalized);
    return md5(trim(preg_replace('/\s+/u', ' ', $normalized)));
}

// Cross-source title fingerprint — strips 50% of words and hashes for fuzzy dedup
function so_build_title_fingerprint($title) {
    if (empty($title)) return '';
    $n = so_normalize_title_for_dedupe((string)$title);
    // Remove very common stop-words that don't carry meaning
    $stop = ['في','من','إلى','على','عن','مع','هذا','هذه','ذلك','التي','الذي','كان','يكون',
              'قد','أن','أو','لم','لن','هو','هي','هم','بعد','قبل','حتى','عند','الذين',
              'وفي','وعلى','وإلى','وعن','ويؤكد','ويقول','وأضاف','وأوضح','كما','بين','لكن'];
    $words = array_filter(explode(' ', $n));
    $words = array_values(array_filter($words, fn($w)=>!in_array($w,$stop,true)&&mb_strlen($w)>2));
    if (count($words) < 2) return '';
    // Sort words so "استهداف موقع" == "موقع استهداف" → same fingerprint
    sort($words);
    $significant = array_slice($words, 0, 8); // top 8 unique words
    return md5(implode('|', $significant));
}


function so_title_similarity_percent($a, $b) {
    $a = so_normalize_title_for_dedupe((string)$a);
    $b = so_normalize_title_for_dedupe((string)$b);
    if ($a === '' || $b === '') return 0;
    similar_text($a, $b, $percent);
    return (float) $percent;
}

function so_duplicate_candidate_signature($title, $actor = '', $region = '', $intel = '') {
    $n = so_normalize_title_for_dedupe((string)$title);
    $n = preg_replace('/\b(?:لبنان|فلسطين|الأراضي المحتلة|إسرائيل|اسرائيل|سوريا|إيران|حيفا|نهاريا|كريات شمونة|تل أبيب|تل ابيب|الجنوب|الجليل)\b/iu', ' ', $n);
    $n = preg_replace('/\s+/u', ' ', trim($n));
    return md5($n . '|' . trim((string)$actor) . '|' . trim((string)$region) . '|' . trim((string)$intel));
}

function so_cleanup_duplicate_news_events($limit = 1200) {
    global $wpdb;
    $table = $wpdb->prefix . 'so_news_events';
    $rows = $wpdb->get_results($wpdb->prepare(
        "SELECT id,title,actor_v2,region,intel_type,event_timestamp,title_fingerprint,image_url
         FROM {$table}
         ORDER BY event_timestamp DESC
         LIMIT %d",
        (int)$limit
    ), ARRAY_A);

    if (empty($rows)) return ['deleted' => 0, 'kept' => 0];

    $seen = [];
    $delete_ids = [];

    foreach ($rows as $row) {
        $title = (string)($row['title'] ?? '');
        $actor = (string)($row['actor_v2'] ?? '');
        $region = (string)($row['region'] ?? '');
        $intel = (string)($row['intel_type'] ?? '');
        $tfp = (string)($row['title_fingerprint'] ?? '');
        if ($tfp === '') $tfp = so_build_title_fingerprint($title);
        $sig = so_duplicate_candidate_signature($title, $actor, $region, $intel);
        $bucket = floor(((int)$row['event_timestamp']) / 14400);
        $image = trim((string)($row['image_url'] ?? ''));
        $key = ($tfp ?: $sig) . '|' . $bucket;

        $is_dup = false;
        if ($image !== '' && isset($seen['img:' . $image])) {
            $is_dup = true;
        } elseif (isset($seen[$key])) {
            $is_dup = true;
        } else {
            foreach ($seen as $prev) {
                if (!is_array($prev) || empty($prev['title'])) continue;
                if (($prev['region'] ?? '') !== $region) continue;
                $a = so_normalize_title_for_dedupe($title);
                $b = so_normalize_title_for_dedupe($prev['title']);
                similar_text($a, $b, $sim);
                if ($sim >= 92) { $is_dup = true; break; }
            }
        }

        if ($is_dup) {
            $delete_ids[] = (int)$row['id'];
            continue;
        }

        $seen[$key] = ['title' => $title, 'region' => $region, 'actor' => $actor];
        if ($image !== '') $seen['img:' . $image] = ['title' => $title, 'region' => $region, 'actor' => $actor];
    }

    if (!empty($delete_ids)) {
        $in = implode(',', array_map('intval', $delete_ids));
        $wpdb->query("DELETE FROM {$table} WHERE id IN ({$in})");
    }

    return ['deleted' => count($delete_ids), 'kept' => count($rows) - count($delete_ids)];
}



function sod_v22_media_actor_blacklist(): array {
    return ['العربية','قناة العربية','الميادين','المنار','رويترز','سكاي نيوز','الجزيرة','فرانس برس','ا ف ب','أسوشيتد برس','وكالة فارس','وكالة تسنيم','إيران الآن','ايران الان','ايران بالعربي','قناة الساحات','روسيا الاتحادية','beiruttime','R @Irannow_'];
}

function sod_v22_region_override_from_text(string $title, string $content = '', string $current = ''): string {
    $text = so_clean_text(trim($title . ' ' . $content));
    $pairs = [
        '/(أربيل|كردستان العراق|السليمانية|بغداد|البصرة|النجف|الموصل|كركوك)/ui' => 'العراق',
        '/(تل أبيب|تل ابيب|حيفا|عكا|صفد|بئر السبع|نهاريا|الجليل|الأراضي المحتلة|إسرائيل|اسرائيل)/ui' => 'الأراضي المحتلة (إسرائيل)',
        '/(رفح|غزة|خان يونس|جباليا|بيت حانون|الضفة الغربية|نابلس|جنين|قلقيلية|فلسطين المحتلة|فلسطين)/ui' => 'فلسطين',
        '/(بيروت|الضاحية|الجنوب|جنوب لبنان|صيدا|صور|بعلبك|النبطية|لبنان)/ui' => 'لبنان',
        '/(طهران|إيران|ايران|أصفهان|نطنز|بوشهر|مشهد|تبريز)/ui' => 'إيران',
        '/(واشنطن|البيت الأبيض|البنتاغون|الولايات المتحدة|أميركا|امريكا)/ui' => 'الولايات المتحدة',
        '/(مضيق هرمز|هرمز|الخليج العربي|الخليج)/ui' => 'الخليج',
        '/(البحر الأحمر|البحر الاحمر|صنعاء|عدن|الحديدة|اليمن)/ui' => 'اليمن',
        '/(بكين|الصين|تايوان|بحر الصين)/ui' => 'الصين',
        '/(موسكو|روسيا|أوكرانيا|كييف)/ui' => 'روسيا/أوروبا الشرقية',
    ];
    foreach ($pairs as $rx => $region) {
        if (preg_match($rx, $text)) return $region;
    }
    return $current;
}

function sod_v22_improve_reanalysis_payload(array $row, array $item, array $analyzed): array {
    $title = (string)($item['title'] ?? ($row['title'] ?? ''));
    $content = (string)($item['content'] ?? ($row['content'] ?? ''));
    $source = trim((string)($item['source'] ?? ($row['source_name'] ?? '')));
    $actor = trim((string)($analyzed['actor_v2'] ?? ($row['actor_v2'] ?? '')));
    $region = trim((string)($analyzed['region'] ?? ($row['region'] ?? '')));
    $fallback_actor = function_exists('sod_infer_actor_fallback') ? trim((string)sod_infer_actor_fallback($title, $region, $source)) : '';
    $speaker_actor = function_exists('sod_extract_speaker_actor') ? trim((string)sod_extract_speaker_actor($title)) : '';
    $media = sod_v22_media_actor_blacklist();

    if ($speaker_actor !== '' && !in_array($speaker_actor, $media, true)) {
        $actor = $speaker_actor;
    }
    if ($actor === '' || sod_is_unknown_actor_label($actor) || in_array($actor, $media, true)) {
        if ($fallback_actor !== '' && !in_array($fallback_actor, $media, true)) {
            $actor = $fallback_actor;
        } elseif (preg_match('/(جيش الاحتلال|قوات الاحتلال|العدو الإسرائيلي|الاحتلال الإسرائيلي|آليات الاحتلال)/ui', $title)) {
            $actor = 'جيش العدو الإسرائيلي';
        } elseif (preg_match('/(الحرس الثوري|الجيش الإيراني|الخارجية الايرانية|إيران الآن|ايران الان|إيرانيون|إيرانية)/ui', $title) && !preg_match('/(رويترز|العربية|الميادين|المنار)/ui', $title)) {
            $actor = 'إيران';
        }
    }

    $forced_region = sod_v22_region_override_from_text($title, $content, $region);
    if ($forced_region !== '') $region = $forced_region;

    $intel_type = trim((string)($analyzed['intel_type'] ?? ($row['intel_type'] ?? '')));
    if ($intel_type === '' || $intel_type === 'عام') {
        if (preg_match('/(اشتباك|قصف|غارة|استهداف|اقتحام|إطلاق نار|مسيرة|مسيّرة|صاروخ|رشاشات)/ui', $title)) {
            $intel_type = 'عسكري/أمني';
        } elseif (preg_match('/(نفط|غاز|عقوبات|صادرات|واردات|اقتصاد|سعر البرميل|أسعار النفط)/ui', $title)) {
            $intel_type = 'اقتصادي/لوجستي';
        } elseif (preg_match('/(تصريح|قال|أعلن|أكد|المتحدث|الخارجية|محادثات|مفاوضات|اتفاق)/ui', $title)) {
            $intel_type = 'سياسي/إعلامي';
        }
    }

    $wd = sod_parse_json_array($analyzed['war_data'] ?? ($row['war_data'] ?? '{}'));
    $hybrid = $wd['hybrid_layers'] ?? ($row['hybrid_layers'] ?? []);
    if (function_exists('sod_newslog_normalize_layers')) {
        $layers = sod_newslog_normalize_layers($hybrid);
        if ($intel_type === 'عسكري/أمني' && !in_array('عسكري', $layers, true)) $layers[] = 'عسكري';
        if ($intel_type === 'اقتصادي/لوجستي' && !in_array('اقتصادي', $layers, true)) $layers[] = 'اقتصادي';
        if (str_contains($intel_type, 'إعلامي') && !in_array('إعلامي/نفسي', $layers, true)) $layers[] = 'إعلامي/نفسي';
        $layers = array_values(array_unique(array_filter($layers)));
        $wd['hybrid_layers'] = $layers;
        $analyzed['hybrid_layers'] = wp_json_encode($layers, JSON_UNESCAPED_UNICODE);
    }
    $analyzed['war_data'] = wp_json_encode($wd, JSON_UNESCAPED_UNICODE);
    $analyzed['actor_v2'] = $actor !== '' ? $actor : 'فاعل غير محسوم';
    $analyzed['region'] = $region !== '' ? $region : 'غير محدد';
    $analyzed['intel_type'] = $intel_type !== '' ? $intel_type : 'عام';
    return $analyzed;
}

function so_reanalyze_all_news_events($limit = 3000, $offset = 0) {
    global $wpdb;
    $table = $wpdb->prefix . 'so_news_events';
    $rows = $wpdb->get_results($wpdb->prepare(
        "SELECT * FROM {$table}
         ORDER BY id DESC
         LIMIT %d OFFSET %d",
        (int)$limit,
        (int)$offset
    ), ARRAY_A);

    if (empty($rows)) return ['updated' => 0, 'scanned' => 0, 'next_offset' => $offset, 'total' => 0, 'done' => true];

    $updated = 0;
    $locked = 0;
    $rejected_5w1h = 0;
    
    // تحميل محقق 5W1H إذا كان موجوداً
    $validator_class_exists = class_exists('Sod_5W1H_Validator');
    
    foreach ($rows as $row) {
        $title = (string)($row['title'] ?? '');
        if ($title === '') continue;

        if (sod_is_manual_locked_row($row)) {
            $update = sod_mark_evaluation_state($row, [
                'war_data' => (string)($row['war_data'] ?? '{}'),
                'field_data' => (string)($row['field_data'] ?? '{}'),
            ], 'manual_override');
            sod_db_safe_update($table, $update, ['id' => (int)$row['id']]);
            $locked++;
            continue;
        }

        $item = [
            'title'      => (string)($row['title'] ?? ''),
            'link'       => (string)($row['link'] ?? ''),
            'source'     => (string)($row['source_name'] ?? $row['source'] ?? ''),
            'color'      => (string)($row['source_color'] ?? '#1da1f2'),
            'date'       => (string)($row['event_timestamp'] ?? ''),
            'agency_loc' => (string)($row['agency_loc'] ?? ''),
            'image_url'  => (string)($row['image_url'] ?? ''),
            'content'    => (string)($row['content'] ?? ''),
        ];

        $analyzed = SO_OSINT_Engine::process_event($item);
        if (!$analyzed || !is_array($analyzed)) continue;
        
        $analyzed = sod_finalize_reanalysis_payload($row, $item, $analyzed);
        $analyzed = sod_v22_improve_reanalysis_payload($row, $item, $analyzed);
        
        // === إصلاح 1: تطبيق تحقق 5W1H الصارم ===
        if ($validator_class_exists) {
            $validation_data = [
                'title' => $item['title'],
                'content' => $item['content'],
                'actor' => $analyzed['actor_v2'] ?? '',
                'region' => $analyzed['region'] ?? '',
                'intel_type' => $analyzed['intel_type'] ?? '',
                'meta' => [
                    'when' => $item['date'],
                    'where' => $analyzed['region'] ?? '',
                    'who' => $analyzed['actor_v2'] ?? '',
                    'what' => $analyzed['intel_type'] ?? '',
                ]
            ];
            
            $validation_result = Sod_5W1H_Validator::validate_before_publish($validation_data);
            
            // حفظ نتيجة البوابة العسكرية دائماً، ثم اتخاذ القرار بحسب المستوى الناتج.
            $fd = sod_parse_json_array($analyzed['field_data'] ?? '{}');
            $fd['5w1h_validation'] = [
                'score' => (int)($validation_result['score'] ?? 0),
                'approved' => !empty($validation_result['approved']),
                'decision' => (string)($validation_result['decision'] ?? 'reject'),
                'decision_label' => (string)($validation_result['decision_label'] ?? ''),
                'missing' => (array)($validation_result['missing_elements'] ?? []),
                'checked_at' => current_time('mysql'),
                'hard_reject' => !empty($validation_result['hard_reject']),
                'rejection_reason' => (string)($validation_result['rejection_reason'] ?? ''),
                'title_audit' => (array)($validation_result['title_audit'] ?? []),
                'military_classification' => (string)($validation_result['military_classification'] ?? 'general'),
                'strategic_priority' => (string)($validation_result['strategic_priority'] ?? 'normal'),
                'strategic_boost' => (int)($validation_result['strategic_boost'] ?? 0),
                'entities' => (array)($validation_result['entities'] ?? []),
            ];
            $analyzed['field_data'] = wp_json_encode($fd, JSON_UNESCAPED_UNICODE);

            if (!empty($validation_result['suggested_actor'])) {
                $analyzed['actor_v2'] = $validation_result['suggested_actor'];
            }

            if (!$validation_result['approved']) {
                $rejected_5w1h++;
                $decision = (string)($validation_result['decision'] ?? 'reject');

                if (!empty($validation_result['hard_reject']) || $decision === 'reject') {
                    $analyzed['evaluation_status'] = 'rejected';
                    $analyzed['evaluation_reason'] = 'MILITARY 5W GATE REJECTED: ' . (string)($validation_result['rejection_reason'] ?? implode(',', (array)($validation_result['missing_elements'] ?? [])));
                } elseif ($decision === 'review' || $decision === 'draft') {
                    $analyzed['evaluation_status'] = 'needs_review';
                    $analyzed['evaluation_reason'] = 'MILITARY 5W GATE ' . strtoupper($decision) . ': ' . implode(',', (array)($validation_result['missing_elements'] ?? []));
                }
            }
        }
        
        $wd = sod_parse_json_array($analyzed['war_data'] ?? '{}');
        $target_v2 = (string)($wd['target'] ?? ($analyzed['target_v2'] ?? ''));
        $context_actor = (string)($wd['context_actor'] ?? ($analyzed['context_actor'] ?? ''));
        $intent = (string)($wd['intent'] ?? ($analyzed['intent'] ?? ''));
        $weapon_v2 = (string)($wd['weapon_means'] ?? ($analyzed['weapon_v2'] ?? ''));

        $update_payload = [
            'title_fingerprint' => function_exists('so_build_title_fingerprint') ? so_build_title_fingerprint($title) : md5($title),
            'intel_type'     => (string)($analyzed['intel_type'] ?? ($row['intel_type'] ?? '')),
            'tactical_level' => (string)($analyzed['tactical_level'] ?? ($row['tactical_level'] ?? '')),
            'region'         => (string)($analyzed['region'] ?? ($row['region'] ?? '')),
            'actor_v2'       => (string)($analyzed['actor_v2'] ?? ($row['actor_v2'] ?? 'فاعل غير محسوم')),
            'score'          => (int)($analyzed['score'] ?? ($row['score'] ?? 0)),
            'war_data'       => (string)($analyzed['war_data'] ?? '{}'),
            'field_data'     => (string)($analyzed['field_data'] ?? '{}'),
            'target_v2'      => $target_v2,
            'context_actor'  => $context_actor,
            'intent'         => $intent,
            'weapon_v2'      => $weapon_v2,
            'hybrid_layers'  => (string)($analyzed['hybrid_layers'] ?? ($row['hybrid_layers'] ?? '[]')),
        ];
        $update_payload = sod_mark_evaluation_state($row, $update_payload, 'auto');
        $res = sod_db_safe_update($table, $update_payload, ['id' => (int)$row['id']]);
        if (!empty($res['ok'])) {
            $updated++;
            foreach ([['types',$update_payload['intel_type']],['levels',$update_payload['tactical_level']],['regions',$update_payload['region']],['actors',$update_payload['actor_v2']],['targets',$target_v2],['contexts',$context_actor],['intents',$intent],['weapons',$weapon_v2]] as $pair) {
                [$bk,$val] = $pair;
                if ($val !== '' && $val !== 'فاعل غير محسوم' && $val !== 'غير محدد') sod_add_bank_value($bk, $val);
            }
        }
    }

    $next_offset = $offset + count($rows);
    $total = (int) $wpdb->get_var("SELECT COUNT(*) FROM {$table}");
    $done = $next_offset >= $total;

    $train = ['scanned' => 0, 'learned' => 0, 'deferred' => 1];
    if ($done) {
        $train = sod_auto_dataset_training_from_newslog(min(2500, max(400, (int)$limit)));
    }

    update_option('so_last_reanalysis_summary', [
        'time' => time(),
        'updated' => (int)$updated,
        'locked' => (int)$locked,
        'rejected_5w1h' => (int)$rejected_5w1h,
        'scanned' => (int)count($rows),
        'limit' => (int)$limit,
        'offset' => (int)$offset,
        'next_offset' => (int)$next_offset,
        'total' => (int)$total,
        'done' => (bool)$done,
        'engine' => 'sod_auto_eval_v17_5_5w1h',
        'training' => $train,
    ], false);

    return [
        'updated' => (int)$updated,
        'locked' => (int)$locked,
        'rejected_5w1h' => (int)$rejected_5w1h,
        'scanned' => (int)count($rows),
        'next_offset' => (int)$next_offset,
        'total' => (int)$total,
        'done' => (bool)$done,
        'training' => $train,
    ];
}

function sod_finalize_reanalysis_payload(array $row, array $item, array $analyzed): array {
    $title = (string)($item['title'] ?? ($row['title'] ?? ''));
    $semantic = sod_classify_event_v3($item);
    $explicit_actor = function_exists('sod_infer_explicit_speaker_actor') ? trim((string)sod_infer_explicit_speaker_actor($title)) : '';

    $analyzed = SO_Manual_Learning::apply_to_analyzed($item, $analyzed);
    $analyzed = sod_apply_manual_override_to_analyzed($analyzed, $row);

    $current_actor = trim((string)($analyzed['actor_v2'] ?? ''));
    $semantic_actor = trim((string)($semantic['actor_v2'] ?? ''));
    $fallback_actor = function_exists('sod_infer_actor_fallback')
        ? trim((string)sod_infer_actor_fallback($title, (string)($analyzed['region'] ?? ($row['region'] ?? '')), (string)($item['source'] ?? '')))
        : '';
    $unknown_actor_values = ['','غير محدد','عام/مجهول','فاعل غير محسوم','فاعل قيد التقييم','جهة غير معلنة','فاعل سياقي','فاعل سياقي غير مباشر'];

    if ($semantic_actor !== '' && (
        in_array($current_actor, $unknown_actor_values, true)
        || ($current_actor === 'جيش العدو الإسرائيلي' && (sod_is_non_military_context($title) || $semantic_actor !== 'جيش العدو الإسرائيلي'))
        || $semantic_actor !== $current_actor
    )) {
        $analyzed['actor_v2'] = $semantic_actor;
    }
    if ($fallback_actor !== '' && (
        trim((string)($analyzed['actor_v2'] ?? '')) === ''
        || in_array(trim((string)($analyzed['actor_v2'] ?? '')), $unknown_actor_values, true)
        || (trim((string)($analyzed['actor_v2'] ?? '')) === 'جيش العدو الإسرائيلي' && $fallback_actor !== 'جيش العدو الإسرائيلي')
    )) {
        $analyzed['actor_v2'] = $fallback_actor;
    }

    $context_actor_v2 = sod_resolve_actor_from_context_v2(
        $title,
        (string)($analyzed['region'] ?? ($row['region'] ?? '')),
        (string)($analyzed['actor_v2'] ?? ''),
        (string)($item['source_name'] ?? $item['source'] ?? '')
    );
    if ($context_actor_v2 !== '' && (
        trim((string)($analyzed['actor_v2'] ?? '')) === ''
        || in_array(trim((string)($analyzed['actor_v2'] ?? '')), $unknown_actor_values, true)
        || sod_is_bad_actor_candidate((string)($analyzed['actor_v2'] ?? ''))
        || (sod_is_media_source_actor((string)($analyzed['actor_v2'] ?? '')) && !sod_is_media_source_actor($context_actor_v2))
    )) {
        $analyzed['actor_v2'] = sod_apply_actor_canonical_if_available($context_actor_v2);
    }

    foreach (['target_v2', 'context_actor', 'intent', 'weapon_v2'] as $field) {
        $semantic_value = trim((string)($semantic[$field] ?? ''));
        if ($semantic_value !== '') {
            $analyzed[$field] = $semantic_value;
        }
    }

    $semantic_intel = trim((string)($semantic['intel_type'] ?? ''));
    if ($semantic_intel !== '' && ($semantic_intel !== 'عام' || trim((string)($analyzed['intel_type'] ?? '')) === '')) {
        if (in_array(trim((string)($analyzed['intel_type'] ?? '')), ['', 'عام', 'غير محدد'], true) || $semantic_intel !== 'عام') {
            $analyzed['intel_type'] = $semantic_intel;
        }
    }
    $semantic_level = trim((string)($semantic['tactical_level'] ?? ''));
    if ($semantic_level !== '' && in_array(trim((string)($analyzed['tactical_level'] ?? '')), ['', 'عام', 'تكتيكي'], true)) {
        $analyzed['tactical_level'] = $semantic_level;
    }
    $semantic_region = trim((string)($semantic['region'] ?? ''));
    if ($semantic_region !== '' && in_array(trim((string)($analyzed['region'] ?? '')), ['', 'غير محدد'], true)) {
        $analyzed['region'] = $semantic_region;
    }

    if (empty($analyzed['context_actor']) && sod_is_non_military_context($title)) {
        $bucket = (string)($semantic['_ai_v2']['bucket'] ?? '');
        if (in_array($bucket, ['statement', 'report'], true)) {
            $analyzed['context_actor'] = 'سياق تصريحي/إعلامي';
        }
    }

    if (empty($analyzed['intent'])) {
        $bucket = (string)($semantic['_ai_v2']['bucket'] ?? '');
        $intel_type = trim((string)($analyzed['intel_type'] ?? ''));
        $mode = sod_detect_event_mode($title);
        if ($mode === 'defensive_alert') {
            $analyzed['intent'] = 'دفاع';
        } elseif ($mode === 'kinetic') {
            $analyzed['intent'] = 'هجوم';
        } elseif (in_array($bucket, ['statement', 'report'], true) || sod_is_non_military_context($title)) {
            $analyzed['intent'] = 'تموضع/رسائل سياسية';
        } elseif ($intel_type === 'إعلامي') {
            $analyzed['intent'] = 'تغطية/رسائل إعلامية';
        } elseif (in_array($intel_type, ['عسكري/أمني', 'تكتيكي/ميداني', 'رصد/إنذار'], true)) {
            $analyzed['intent'] = 'نشاط ميداني';
        }
    }

    $region_for_rule = (string)($analyzed['region'] ?? ($row['region'] ?? ''));
    $analyzed['actor_v2'] = sod_force_requested_actor_rule((string)($analyzed['actor_v2'] ?? ''), $region_for_rule, $title);
    if ($explicit_actor !== '') {
        $analyzed['actor_v2'] = $explicit_actor;
    }
    $actor_after_rule = trim((string)($analyzed['actor_v2'] ?? ''));
    $is_media_actor = in_array($actor_after_rule, ['المنار', 'الميادين', 'قناة العربية', 'التلفزيون الإيراني', 'إعلام إسرائيلي', 'وكالة فارس', 'وكالة تسنيم'], true);
    $is_kinetic_title = preg_match('/(غارة|غارات|قصف|استهداف|اقتحام|عدوان|اعتداء|هجوم|اشتباكات|نيران مشاة|قصف مدفعي|طيران حربي|مسيّرة|مسيرة)/ui', $title) === 1;
    if ($is_media_actor && $is_kinetic_title && function_exists('sod_infer_actor_fallback')) {
        $media_safe_actor = trim((string)sod_infer_actor_fallback($title, $region_for_rule, ''));
        if ($media_safe_actor !== '' && !in_array($media_safe_actor, ['المنار', 'الميادين', 'قناة العربية', 'التلفزيون الإيراني', 'إعلام إسرائيلي', 'وكالة فارس', 'وكالة تسنيم'], true)) {
            $analyzed['actor_v2'] = $media_safe_actor;
        }
    }
    if ($is_media_actor && !$is_kinetic_title) {
        $media_safe_actor = function_exists('sod_infer_actor_fallback') ? trim((string)sod_infer_actor_fallback($title, $region_for_rule, '')) : '';
        if ($media_safe_actor !== '' && !in_array($media_safe_actor, ['المنار', 'الميادين', 'قناة العربية', 'التلفزيون الإيراني', 'إعلام إسرائيلي', 'وكالة فارس', 'وكالة تسنيم'], true)) {
            $analyzed['actor_v2'] = $media_safe_actor;
        } elseif (preg_match('/(وكالة\s*[\"“”]?\s*تسنيم|تسنيم|وكالة فارس|فارس|التلفزيون الإيراني|إيرنا|إعلام إيراني)/ui', $title)) {
            $analyzed['actor_v2'] = 'إيران';
        }
    }

    $wd = sod_parse_json_array($analyzed['war_data'] ?? '{}');
    $fd = sod_parse_json_array($analyzed['field_data'] ?? '{}');
    $wd['actor'] = (string)($analyzed['actor_v2'] ?? '');
    if (!empty($analyzed['target_v2'])) $wd['target'] = (string)$analyzed['target_v2'];
    if (!empty($analyzed['context_actor'])) $wd['context_actor'] = (string)$analyzed['context_actor'];
    if (!empty($analyzed['intent'])) $wd['intent'] = (string)$analyzed['intent'];
    if (!empty($analyzed['weapon_v2'])) $wd['weapon_means'] = (string)$analyzed['weapon_v2'];
    if (!isset($wd['early_warning'])) {
        $wd['early_warning'] = sod_early_warning_ai($title, [
            'actor' => (string)($analyzed['actor_v2'] ?? ''),
            'region' => $region_for_rule,
            'intel_type' => (string)($analyzed['intel_type'] ?? ''),
        ]);
    }
    if (!isset($wd['prediction_layer'])) {
        $wd['prediction_layer'] = sod_prediction_layer($title, [
            'actor' => (string)($analyzed['actor_v2'] ?? ''),
            'region' => $region_for_rule,
            'intel_type' => (string)($analyzed['intel_type'] ?? ''),
            'target' => (string)($analyzed['target_v2'] ?? ''),
            'weapon' => (string)($analyzed['weapon_v2'] ?? ''),
            'early_warning' => $wd['early_warning'],
        ]);
    }
    $fd['reanalysis_engine'] = 'sod_finalize_reanalysis_payload_v1';
    $analyzed['war_data'] = wp_json_encode($wd, JSON_UNESCAPED_UNICODE);
    $analyzed['field_data'] = wp_json_encode($fd, JSON_UNESCAPED_UNICODE);

    return $analyzed;
}


function so_reanalyze_dirty_news_events($limit = 300, $offset = 0) {
    global $wpdb;
    $table = $wpdb->prefix . 'so_news_events';
    $scan_limit = max((int)$limit * 6, 300);
    $rows = $wpdb->get_results($wpdb->prepare(
        "SELECT * FROM {$table} ORDER BY id DESC LIMIT %d OFFSET %d",
        (int)$scan_limit,
        (int)$offset
    ), ARRAY_A);

    if (empty($rows)) return ['updated' => 0, 'scanned' => 0, 'next_offset' => $offset, 'total' => 0, 'done' => true, 'matched' => 0];

    $updated = 0;
    $locked = 0;
    $matched = 0;
    foreach ($rows as $row) {
        if (!function_exists('bt_v24_row_needs_targeted_cleanup') || !bt_v24_row_needs_targeted_cleanup($row)) {
            continue;
        }
        $matched++;
        if ($matched > (int)$limit) break;

        $title = (string)($row['title'] ?? '');
        if ($title === '') continue;

        if (sod_is_manual_locked_row($row)) {
            $update = sod_mark_evaluation_state($row, [
                'war_data' => (string)($row['war_data'] ?? '{}'),
                'field_data' => (string)($row['field_data'] ?? '{}'),
            ], 'manual_override');
            sod_db_safe_update($table, $update, ['id' => (int)$row['id']]);
            $locked++;
            continue;
        }

        $item = [
            'title'      => (string)($row['title'] ?? ''),
            'link'       => (string)($row['link'] ?? ''),
            'source'     => (string)($row['source_name'] ?? $row['source'] ?? ''),
            'color'      => (string)($row['source_color'] ?? '#1da1f2'),
            'date'       => (string)($row['event_timestamp'] ?? ''),
            'agency_loc' => (string)($row['agency_loc'] ?? ''),
            'image_url'  => (string)($row['image_url'] ?? ''),
            'content'    => (string)($row['content'] ?? ''),
        ];

        $analyzed = SO_OSINT_Engine::process_event($item);
        if (!$analyzed || !is_array($analyzed)) continue;
        $analyzed = sod_finalize_reanalysis_payload($row, $item, $analyzed);
        $analyzed = sod_v22_improve_reanalysis_payload($row, $item, $analyzed);
        $wd = sod_parse_json_array($analyzed['war_data'] ?? '{}');
        $target_v2 = (string)($wd['target'] ?? ($analyzed['target_v2'] ?? ''));
        $context_actor = (string)($wd['context_actor'] ?? ($analyzed['context_actor'] ?? ''));
        $intent = (string)($wd['intent'] ?? ($analyzed['intent'] ?? ''));
        $weapon_v2 = (string)($wd['weapon_means'] ?? ($analyzed['weapon_v2'] ?? ''));

        $update_payload = [
            'title_fingerprint' => function_exists('so_build_title_fingerprint') ? so_build_title_fingerprint($title) : md5($title),
            'intel_type'     => (string)($analyzed['intel_type'] ?? ($row['intel_type'] ?? '')),
            'tactical_level' => (string)($analyzed['tactical_level'] ?? ($row['tactical_level'] ?? '')),
            'region'         => (string)($analyzed['region'] ?? ($row['region'] ?? '')),
            'actor_v2'       => (string)($analyzed['actor_v2'] ?? ($row['actor_v2'] ?? 'فاعل غير محسوم')),
            'score'          => (int)($analyzed['score'] ?? ($row['score'] ?? 0)),
            'war_data'       => (string)($analyzed['war_data'] ?? '{}'),
            'field_data'     => (string)($analyzed['field_data'] ?? '{}'),
            'target_v2'      => $target_v2,
            'context_actor'  => $context_actor,
            'intent'         => $intent,
            'weapon_v2'      => $weapon_v2,
            'hybrid_layers'  => (string)($analyzed['hybrid_layers'] ?? ($row['hybrid_layers'] ?? '[]')),
        ];
        $update_payload = sod_mark_evaluation_state($row, $update_payload, 'auto');
        $res = sod_db_safe_update($table, $update_payload, ['id' => (int)$row['id']]);
        if (!empty($res['ok'])) {
            $updated++;
        }
    }

    $next_offset = $offset + count($rows);
    $total = (int) $wpdb->get_var("SELECT COUNT(*) FROM {$table}");
    $done = $next_offset >= $total || count($rows) === 0;

    return [
        'updated' => (int)$updated,
        'locked' => (int)$locked,
        'matched' => (int)$matched,
        'scanned' => (int)count($rows),
        'next_offset' => (int)$next_offset,
        'total' => (int)$total,
        'done' => (bool)$done,
    ];
}

function so_reanalyze_dirty_news_events_full($batch = 100, $reset = false) {
    global $wpdb;
    $table = $wpdb->prefix . 'so_news_events';
    $batch = max(10, min(300, (int)$batch));

    if ($reset) {
        update_option('so_dirty_reanalyze_cursor', 0, false);
        update_option('so_dirty_reanalyze_running', 1, false);
    }

    $offset = (int) get_option('so_dirty_reanalyze_cursor', 0);
    $total = (int) $wpdb->get_var("SELECT COUNT(*) FROM {$table}");

    $result = so_reanalyze_dirty_news_events($batch, $offset);
    $next_offset = (int)($result['next_offset'] ?? $offset);
    $done = !empty($result['done']);

    update_option('so_dirty_reanalyze_cursor', $done ? 0 : $next_offset, false);
    update_option('so_dirty_reanalyze_running', $done ? 0 : 1, false);

    $processed = min($done ? $total : $next_offset, $total);
    $percent = $total > 0 ? (int) round(($processed / $total) * 100) : 100;

    $progress = [
        'time' => time(),
        'batch' => $batch,
        'processed' => (int)$processed,
        'total' => (int)$total,
        'percent' => (int)$percent,
        'updated' => (int)($result['updated'] ?? 0),
        'matched' => (int)($result['matched'] ?? 0),
        'done' => (bool)$done,
        'next_offset' => (int)($done ? 0 : $next_offset),
        'running' => $done ? 0 : 1,
    ];
    update_option('so_dirty_reanalyze_progress', $progress, false);

    return $progress;
}

function so_reanalyze_all_news_events_full($batch = 1000, $reset = false) {
    global $wpdb;
    $table = $wpdb->prefix . 'so_news_events';
    $batch = max(10, (int)$batch);

    if ($reset) {
        update_option('so_reanalyze_cursor', 0, false);
        update_option('so_reanalyze_running', 1, false);
    }

    $offset = (int) get_option('so_reanalyze_cursor', 0);
