function so_headline_word_count($text) {
    $text = so_clean_text((string)$text);
    $text = preg_replace('/[\p{P}\p{S}]+/u', ' ', $text);
    $text = preg_replace('/\s+/u', ' ', trim($text));
    if ($text === '') return 0;
    return count(array_filter(explode(' ', $text), function($w) { return trim($w) !== ''; }));
}

function so_is_substantial_headline($text) {
    $text = so_clean_text((string)$text);
    if ($text === '' || mb_strlen($text) < 8) return false;
    return so_headline_word_count($text) >= 3;
}

function so_is_lenient_source_name($source_name) {
    $source_name = trim((string)$source_name);
    if ($source_name === '') return false;
    return preg_match('/(الاعلام العبري بالعربي|نوفوستي|روسيا الاتحادية|قناة الحرس الثوري|الاعلام الحربي|الميادين|ايران بالعربي|RNN_Alerts_AR|قناة الساحات|قناة العربية|bintjbeil)/ui', $source_name) === 1;
}

function so_filter_source_candidate($candidate) {
    $title       = so_clean_text((string)($candidate['title'] ?? ''));
    $source_name = (string)($candidate['source'] ?? '');
    $media       = trim((string)($candidate['image_url'] ?? ''));
    $is_lenient  = so_is_lenient_source_name($source_name);
    if ($title === '') return false;
    if (so_is_substantial_headline($title)) return true;
    if ($is_lenient && mb_strlen($title) >= 14 && so_headline_word_count($title) >= 2) return true;
    if ($media !== '' && mb_strlen($title) >= 10) return true;
    if (preg_match('/(غارة|قصف|هجوم|استهداف|اشتباك|كمين|بيان صادر|مسيّرة|مسيرة|صاروخ|صواريخ|اقتحام|انذار|إنذار|صفارات|المتحدث باسم|الناطق العسكري|مقر خاتم الأنبياء|الحرس الثوري)/ui', $title)) return true;
    return false;
}

function so_should_publish_raw_item($item) {
    $title = so_clean_text((string)($item['title'] ?? ''));
    if (!so_filter_source_candidate(array_merge((array)$item, ['title' => $title]))) return false;
    $ts = (int)($item['date'] ?? 0);
    if (!$ts) return false;
    $source_name = trim((string)($item['source'] ?? ''));
    $max_age = so_is_lenient_source_name($source_name) ? 6 * HOUR_IN_SECONDS : 2 * HOUR_IN_SECONDS;
    if ((time() - $ts) > $max_age) return false;
    static $seen_runtime = [];
    $normalized = so_normalize_title_for_dedupe($title);
    if ($normalized === '') return false;
    $runtime_key = md5(($source_name ?: 'unknown') . '|' . $normalized . '|' . gmdate('Y-m-d H', $ts));
    if (isset($seen_runtime[$runtime_key])) return false;
    $seen_runtime[$runtime_key] = 1;
    return true;
}

function so_detect_strategic_frame($title) {
    $lower = mb_strtolower((string)$title);
    if (preg_match('/(رد|انتقام|ثأر|الموجة|رداً على|ضمن الرد|انتقامية)/ui', $lower)) return 'retaliation';
    if (preg_match('/(هدنة|وقف إطلاق|تهدئة|اتفاق|حوار|مفاوضات)/ui', $lower)) return 'de_escalation';
    if (preg_match('/(سيصعّد|تصعيد|مرحلة ثانية|أشد|أوسع|سنفجر|سنرد|توعد|تهديد)/ui', $lower)) return 'escalation';
    if (preg_match('/(حصيلة|إحصائية|تقرير|متابعة|عمليات الإغاثة|لا تزال مستمرة)/ui', $lower)) return 'aftermath';
    return 'continuity';
}

function so_detect_conflict_context($title) {
    $lower = mb_strtolower((string)$title);
    if (preg_match('/(رداً على|في إطار الرد|انتقام|انتقامية|الموجة\s*\d+|وعد صادق|ضمن الرد)/ui', $lower)) return 'linked_retaliation_cycle';
    if (preg_match('/(استمرار|لا تزال|متواصلة|يتواصل|مستمرة|اليوم الثالث|اليوم الرابع|منذ)/ui', $lower)) return 'ongoing_conflict';
    if (preg_match('/(هدنة|وقف إطلاق|مفاوضات|اتفاق|حوار)/ui', $lower)) return 'diplomatic_phase';
    if (preg_match('/(إنذار مبكر|صفارات الإنذار|قيادة الجبهة الداخلية|رصد إطلاق)/ui', $lower)) return 'defensive_alert_phase';
    if (preg_match('/(حصيلة|شهداء|جرحى|إغاثة|إنقاذ)/ui', $lower)) return 'post_strike_aftermath';
    return 'standalone_or_unclear';
}

function so_detect_war_direction($title) {
    $lower = mb_strtolower((string)$title);
    if (preg_match('/(هدنة|وقف إطلاق|مفاوضات|اتفاق|حوار)/ui', $lower)) return 'de-escalating';
    if (preg_match('/(مرحلة ثانية|أشد|أوسع|تصعيد|توعد|سنفجر|سنرد|عدوان|غارة|قصف|استهداف)/ui', $lower)) return 'escalating';
    if (preg_match('/(حصيلة|إغاثة|إنقاذ|عمليات الإغاثة|لا تزال مستمرة)/ui', $lower)) return 'aftermath';
    return 'stable_or_unclear';
}

function so_detect_verification_nature($title) {
    $lower = mb_strtolower((string)$title);
    if (preg_match('/(قيادة الجبهة الداخلية|الإنذار المبكر|تسوفار|انذار احمر|إنذار أحمر|صفارات(?: الإنذار)?)/ui', $lower)) return 'defensive_alert';
    if (preg_match('/(نظرًا لرصد إطلاق صواريخ|رصد إطلاق صواريخ|من المحتمل تفعيل الإنذارات)/ui', $lower)) return 'detected_launch';
    if (preg_match('/(أطلقنا|استهدفنا|هجوم صاروخي|غارة|قصف|تفجير|استهداف مباشر|صلية صاروخية|مسيّرة انقضاضية)/ui', $lower)) return 'confirmed_attack';
    if (preg_match('/(قال|صرح|أعلن|أكد|في مقابلة|البابا|الفاتيكان|الكرسي الرسولي|لاوون|ترامب|ترمب|الرئيس عون|ولايتي)/ui', $lower)) return 'statement';
    if (preg_match('/(وزارة الصحة|الصحة اللبنانية|الهلال الأحمر|إحصائية|حصيلة|تقرير|متابعة|عمليات الإغاثة)/ui', $lower)) return 'report';
    return 'unknown';
}

function so_detect_content_bucket($title, $source_name = '') {
    $text = so_clean_text((string)$title . ' ' . (string)$source_name);
    if (preg_match('/\b(?:متداول|أنباء أولية|أولي(?:ة)?|غير مؤكد|يُتداول|مزاعم|شائعات?)\b/iu', $text)) return 'rumor';
    if (preg_match('/\b(?:قال|قالت|صرح|صرحت|أعلن|أعلنت|أكد|أكدت|أفاد|أفادت|كشف|هدد|توعد|ترامب|ترمب|بوتين|مدفيديف|البيت الأبيض|وزارة الخارجية|في مقابلة|تعليقاً على|ولايتي|الرئيس عون|البابا|الفاتيكان|نرحب|نرفض|ندين|نطالب|يطالب|يدين|يرفض|يرحب|مؤتمر صحفي|لقاء دبلوماسي|قمة ثنائية|اتفاقية|بروتوكول|مذكرة تفاهم|اتفاق سلام|مباحثات|محادثات|زعيم|رئيس حزب|قائد حزب|زعيم حزب|وزير خارجية|ناطق باسم|متحدث|رئيس الوزراء|إخفاق|انتقد|انتقدت|أسوأ|فشل سياسي|إخفاق استراتيجي|كنيست|برلمان|حزب ديمقراطي|حزب ليكود|لن يكون|أعلنا|أوضح)\b/iu', $text) && !preg_match('/\b(?:استهدفنا|نفذنا|شنّينا|أطلقنا|قصفنا|استهدفت القواعد|نفذت عملية)\b/iu', $text)) return 'statement';
    if (preg_match('/\b(?:رويترز|وكالة|صحيفة|القناة\s*\d+|تقرير|تحليل|إحاطة|ملخص|نقلاً عن|وسائل إعلام|إعلام العدو|إحصائية|وزارة الصحة|الهلال الأحمر)\b/iu', $text) && !preg_match('/\b(?:استهدفنا|قصف|غارة|هجوم|اشتباك|انفجار|اغتيال|اقتحام|إطلاق)\b/iu', $text)) return 'report';
    if (preg_match('/\b(?:زلزال|هزة|فيضانات|إعصار|عاصفة|حرائق غابات|بركان|تسونامي|انهيار أرضي)\b/iu', $text)) return 'disaster';
    if (preg_match('/\b(?:غارة|قصف|هجوم|استهداف|اشتباك|كمين|إطلاق|اعتقال|اقتحام|انفجار|اغتيال|توغل|اعتراض|مسيّرة|مسيرة|صاروخ|صلية صاروخية)\b/iu', $text)) return 'field';
    return 'general';
}



function so_is_non_intel_noise($title) {
    $text = so_clean_text((string)$title);
    if ($text === '') return true;
    $negative = [
        'درب التبانة','مجرة','رواد الفضاء','رائد فضاء','أرتيميس','وكالة ناسا','ناسا','القمر','فضاء','كوكب','كسوف','خسوف',
        'طقس','الأرصاد الجوية','رياضة','مباراة','كرة القدم','الدوري',
        'فنان','فنانة','ممثل','ممثلة','مسلسل','ترفيه','برجك','أبراج','طبخ','وصفة','منوعات',
        'الدورات الصيفية','الأنشطة الصيفية','الأنشطة الثقافية','تدشين الدورات','الأنشطة التربوية',
        'ندعوكم للاشتراك','للاشتراك','تابعونا','سعيا منا لنشر','سعياً منا لنشر','تنويه','اعادة النشر',
        'live from the international space station','space station','iss'
    ];
    foreach ($negative as $term) {
        if (mb_stripos($text, $term) !== false) return true;
    }
    return false;
}

function so_classify_editorial_axis($title, $source_name = '') {
    $text = so_clean_text((string)$title . ' ' . (string)$source_name);
    $lower = mb_strtolower($text);

    if (so_is_non_intel_noise($text)) return 'غير استخباراتي';

    // رسمي/سياسي أولاً قبل أي fallback ميداني
    if (preg_match('/(يعلن الحداد|الحداد الوطني|الاتحاد العمالي العام|تعطيل|إقفال|قرار رسمي|بيان حكومي|إعلان الحداد)/ui', $lower)) return 'سياسي';
    if (preg_match('/(وزير الخارجية|بحث هاتفيا|بحث هاتفي|بحث هاتفياً|بحث هاتفيًا|مستجدات الأوضاع|مباحثات|اجتماع|لقاء|اتصال هاتفي|تصريح|أكد|أكدت|قال|قالت|الرئيس بري|الرئيس|دبلوماسي|ديبلوماسي)/ui', $lower) && !preg_match('/(غارة|قصف|هجوم|اغتيال|اشتباك|اقتحام|صاروخ|مسيرة|مسيّرة|رصد)/ui', $lower)) return 'سياسي';

    if (preg_match('/(شجب|يشجب|ندد|تنديد|يدين|إدانة|ندين|استنكار|تستنكر|مستنكر|نندد)/ui', $lower)) return 'شجب/استنكار';

    if (preg_match('/(بيان صادر|بيان|المكتب السياسي|العلاقات العامة|أصدر|أصدرت|أعلنت|أعلن)/ui', $lower) && !preg_match('/(غارة|قصف|هجوم|اغتيال|اشتباك|اقتحام|صاروخ|مسيرة|مسيّرة|رصد)/ui', $lower)) return 'بيان';

    if (preg_match('/(وكالة|وسائل إعلام|وسائل اعلام|مراسل|فيديو|يوثق|مشاهد|لقطة|تسنيم|منصات للمستوطنين|إعلام العدو|اعلام العدو|ذا أتلانتيك)/ui', $lower) && !preg_match('/(غارة|قصف|هجوم|اغتيال|اشتباك|اقتحام|صاروخ|مسيرة|مسيّرة|رصد قصف|رصد غارة|رصد ضربة)/ui', $lower)) return 'إعلامي';

    if (preg_match('/(نووي|نووية|يوراني|مفاعل|تخصيب|سلاح نووي)/ui', $lower)) return 'نووي';

    if (preg_match('/(سفينة|سفن|المضيق|مضيق هرمز|ناقلات النفط|المرور|شحن|إمداد|إمدادات|لوجستي|اقتصادي)/ui', $lower)) return 'اقتصادي/لوجستي';

    if (preg_match('/(تم رصد|صافرات الإنذار|صافرات الانذار|إنذار|انذار|اعتراض|صاروخ اعتراضي|حدث أمني|حدث امني)/ui', $lower)) return 'رصد/إنذار';

    if (preg_match('/(غارة|غارة جوية|قصف مدفعي|قصف|هجوم|اغتيال|اشتباك|كمين|توغل|اقتحام|صاروخ|مسيرة|مسيّرة|استهداف|ضربة بطائرة مسيّرة|ضربة بطائرة مسيرة|سقوط صواريخ|انفجارات قوية)/ui', $lower)) return 'عسكري/أمني';

    return 'تكتيكي/ميداني';
}


function so_bt_contains_any($text, array $terms) {
    foreach ($terms as $term) {
        if ($term !== '' && mb_stripos($text, $term) !== false) return true;
    }
    return false;
}

function so_bt_detect_region_v2($title) {
    $t = so_clean_text((string)$title);
    $map = [
