        'عكا','الزيب','رأس الناقورة','راس الناقورة','متسوفا','بيتست','معالوت ترشيحا'
    ],
        'إيران' => ['إيران','ايران','طهران','مضيق هرمز','هرمز','بوشهر','نطنز','أصفهان','خارك','عبادان','شيراز','تبريز'],
        'الأردن' => ['الأردن','الأردنية','العاصمة الأردنية','عمان'],
        'الخليج' => ['السعودية','السعودي','الكويت','الكويتي','سلطنة عمان','عمان الخليجية','الخليج'],
        'تركيا' => ['تركيا','تركي','تركية','سفينة تركية','سفن تركية'],
        'سوريا' => ['سوريا','دمشق','حمص','حلب','درعا','اللاذقية','القنيطرة'],
        'العراق' => ['العراق','بغداد','البصرة','أربيل','الأنبار','كركوك'],
        'اليمن' => ['اليمن','صنعاء','الحديدة','صعدة','تعز'],
    ];
    foreach ($map as $region => $terms) {
        if (so_bt_contains_any($t, $terms)) return $region;
    }
    return 'غير محدد';
}

function so_normalize_actor_label($actor) {
    $actor = trim((string)$actor);
    $unknowns = ['', 'جهة غير معلنة', 'عام/مجهول', 'غير محدد', 'مجهول', 'عام', 'فاعل غير محسوم', 'فاعل قيد التقييم', 'فاعل سياقي', 'فاعل سياقي غير مباشر'];
    if (in_array($actor, $unknowns, true)) {
        return 'فاعل سياقي غير مباشر';
    }
    return $actor;
}

function sod_is_unknown_actor_label($actor) {
    $actor = trim((string)$actor);
    return in_array($actor, ['', 'جهة غير معلنة', 'عام/مجهول', 'غير محدد', 'مجهول', 'عام', 'فاعل غير محسوم', 'فاعل قيد التقييم', 'فاعل سياقي', 'فاعل سياقي غير مباشر', 'الجبهة الداخلية الإسرائيلية'], true);
}

function sod_is_unknown_region_label($region) {
    $region = trim((string)$region);
    return in_array($region, ['', 'غير محدد', 'عام', 'مجهول', 'ساحة غير معروفة'], true);
}


function sod_is_rnn_event_shell_actor($actor) {
    $actor = trim(so_clean_text((string)$actor));
    if ($actor === '') return false;

    if (preg_match('/^(تم\s+رصد|رصد|ورد الآن|عاجل|متابعة|تنويه|سجل|سُجل|تم\s+تسجيل|المناطق\s+المتاثره|المناطق\s+المتأثرة|المتاثره:|المتأثرة:)/ui', $actor)) {
        return true;
    }

    if (preg_match('/(المناطق\s+المتاثره|المناطق\s+المتأثرة|المتاثره:|المتأثرة:)/ui', $actor)) {
        return true;
    }

    if (preg_match('/^(تم\s+رصد\s+)?(اقتحام|قصف|غاره|غارة|استهداف|هجوم|توغل|عمليه\s+نسف|عملية\s+نسف|اطلاق\s+نار|إطلاق\s+نار|رشقات|رشقه|رشقة|قصف\s+مدفعي)(?:\s|$)/ui', $actor)) {
        return true;
    }

    $wc = preg_match_all('/[\p{L}\p{N}_]+/u', $actor, $m);
    if ($wc > 6 && preg_match('/(اقتحام|قصف|غاره|غارة|استهداف|هجوم|توغل|عمليه\s+نسف|عملية\s+نسف|اطلاق\s+نار|إطلاق\s+نار|المناطق\s+المتأثرة|المناطق\s+المتاثره)/ui', $actor)) {
        return true;
    }

    return false;
}

function sod_strip_rnn_event_shell($title) {
    $title = trim((string)$title);
    if ($title === '') return '';

    $patterns = [
        '/^(?:RNN_Alerts_AR\s*[:|\-–—]\s*)+/ui',
        '/^(?:تم\s+رصد|رصد)\s+/ui',
        '/\s+المناطق\s+المتاثره\s*:\s*.+$/ui',
        '/\s+المناطق\s+المتأثرة\s*:\s*.+$/ui',
    ];

    foreach ($patterns as $pattern) {
        $title = preg_replace($pattern, '', $title);
    }

    return trim($title, " \t\n\r\0\x0B:-،,.");
}

function sod_override_rnn_actor_from_event($title, $region = '', $source_name = '') {
    $title = so_clean_text((string)$title);
    $region = trim((string)$region);
    $source_name = trim((string)$source_name);
    $shell_free = sod_strip_rnn_event_shell($title);
    $text = so_clean_text(trim($title . ' ' . $shell_free . ' ' . $region . ' ' . $source_name));

    $is_rnn_style = preg_match('/(^\s*(?:تم\s+رصد|رصد)\s+)|RNN_Alerts_AR/ui', $title . ' ' . $source_name) === 1;
    if (!$is_rnn_style) {
        return '';
    }

    if (($region === 'فلسطين' || preg_match('/(الضفه\s+الغربيه|الضفة\s+الغربية|فلسطين|جنين|نابلس|الخليل|رام\s*الله|البيره|البيرة|قلقيليه|قلقيلية|طولكرم|بيت\s*لحم|غزه|غزة)/ui', $text))
        && preg_match('/(اقتحام|مداهمه|مداهمة|اعتقال|اعتقالات|هدم|نسف|توغل|اطلاق\s+نار|إطلاق\s+نار|قصف\s+مدفعي|قصف)/ui', $text)) {
        return 'جيش العدو الإسرائيلي';
    }

    if (($region === 'لبنان' || preg_match('/(لبنان|الجنوب|بنت\s*جبيل|النبطيه|النبطية|مرجعيون|صور|صيدا|دير\s*سريان|زوطر|يحمر|عيترون|كونين|مركبا|مركبه|شقيف)/ui', $text))
        && preg_match('/(قصف|غاره|غارة|استهداف|رشقات|رشقه|رشقة|إطلاق\s+نار|اطلاق\s+نار|توغل|نسف|قصف\s+مدفعي|فوسفوري)/ui', $text)) {
        return 'جيش العدو الإسرائيلي';
    }

    if (($region === 'الأراضي المحتلة (إسرائيل)' || preg_match('/(الاراضي\s+المحتله|الأراضي\s+المحتلة|اسرائيل|إسرائيل|الجليل|حيفا|عكا|صفد|كريات\s*شمونه|كريات\s*شمونة|نهاريا|تل\s*ابيب|تل\s*أبيب)/ui', $text))
        && preg_match('/(إطلاق\s+صواريخ|اطلاق\s+صواريخ|صاروخ|صواريخ|رشقات|رشقه|رشقة|طائرة\s+مسيّرة|طائرة\s+مسيرة|مسيّرة|مسيرة)/ui', $text)) {
        if (preg_match('/(من\s+لبنان|لبنان|الجنوب\s+اللبناني)/ui', $text)) {
            return 'المقاومة الإسلامية (حزب الله)';
        }
        return 'جهة مقاومة';
    }

    return '';
}

function sod_infer_region_strict($title, $content = '', $current = '') {
    $current = trim((string)$current);
    $text = so_clean_text(trim((string)$title . ' ' . (string)$content));

    if (!sod_is_unknown_region_label($current)) {
        return $current;
    }

    if (preg_match('/(السعديات|الجية|أنصارية|انصارية|دبعال|ميدون|برعشيت|كفرتبنيت|القنطرة|الشهابية|دبين|بنت جبيل|النبطية|الجنوب|جنوب لبنان|لبنان|بيروت|الضاحية|صور|صيدا|البقاع|بعلبك|الهرمل)/ui', $text)) {
        return 'لبنان';
    }
    if (preg_match('/(غلاف غزة|محيط الغلاف|سديروت|عسقلان|أشكول|نير عوز|كيسوفيم|بيت حانون|جباليا|رفح|خان يونس|غزة)/ui', $text)) {
        return 'فلسطين';
    }
    if (preg_match('/(صفد|كريات شمونة|المطلة|نهاريا|الجليل|حيفا|عكا|تل أبيب|تل ابيب|بئر السبع|كاديتا|حتسور هجليلت|مرغليوت|الأراضي المحتلة|إسرائيل|اسرائيل)/ui', $text)) {
        return 'الأراضي المحتلة (إسرائيل)';
    }
    if (preg_match('/(طهران|إيران|ايران|أصفهان|نطنز|بوشهر|هرمز|غيلان)/ui', $text)) {
        return 'إيران';
    }
    if (preg_match('/(صنعاء|اليمن|الحوثي|الحوثيين|إيلات|البحر الأحمر|البحر الاحمر)/ui', $text)) {
        return 'اليمن';
    }
    if (preg_match('/(الولايات المتحدة|أمريكا|امريكا|واشنطن|البيت الأبيض|البنتاغون)/ui', $text)) {
        return 'الولايات المتحدة';
    }
    if (preg_match('/(مضيق هرمز|الخليج|البحر العربي)/ui', $text)) {
        return 'الخليج';
    }

    $det = so_bt_detect_region_v2($text);
    if (!sod_is_unknown_region_label($det)) return $det;
    return 'الساحة المرتبطة بالحدث (استنتاج)';
}

function sod_extract_speaker_actor($title) {
    $title = trim((string)$title);
    if ($title === '') return '';
    if (preg_match('/^[#\s]*(?:لبنان|إيران|فلسطين المحتلة|غزة|اليمن|سوريا|العراق|جنيف|طهران)\s*[:：]\s*(.+)$/u', $title, $m)) {
        $title = trim((string)$m[1]);
    }
    if (preg_match('/^([^:：]{3,80})\s*[:：]/u', $title, $m)) {
        $speaker = trim((string)$m[1], " \t\n\r\0\x0B#-*–—\"'");



        // التحقق من أن المتحدث ليس وسيلة إعلامية
        if (preg_match('/(وسائل إعلام|إعلام العدو|إعلام إسرائيلي|صحيفة|إذاعة|قناة|رويترز|أكسيوس|بوليتيكو|بلومبرغ|العربية|الميادين|المنار|إيران الآن|ايران الان|beiruttime|bintjbeil|قناة الساحات|الاعلام الحربي|الاعلام العبري بالعربي|روسيا الاتحادية|مراسل)/ui', $speaker)) {
            // محاولة استخراج الفاعل الحقيقي من بقية العنوان
            // نمط 1: بعد النقطتين قبل أفعال القول
            if (preg_match('/[:：]\s*(.+?)(?:يقول|يؤكد|يعلن|صرّح|أكّد|ذكر|أفاد|عن|$)/u', $title, $m2)) {
                $real_actor = trim($m2[1]);
                if ($real_actor !== '' && 
                    !preg_match('/(وسائل إعلام|إعلام العدو|إعلام إسرائيلي|صحيفة|إذاعة|قناة|رويترز|أكسيوس|بوليتيكو|بلومبرغ|العربية|الميادين|المنار|إيران الآن|ايران الان|beiruttime|bintjbeil|قناة الساحات|الاعلام الحربي|الاعلام العبري بالعربي|روسيا الاتحادية|مراسل)/ui', $real_actor) &&
                    mb_strlen($real_actor) < 60) {
                    return $real_actor;
                }
            }
            // نمط 2: إذا احتوى النص على كلمات عسكرية/أمنية، لا نعتبر المراسل فاعلاً
            if (preg_match('/(شهيد|جريح|قوات الاحتلال|رشاش|قصف|غارة|استهداف|إطلاق نار)/ui', $title)) {
                return ''; // نترك للمحركات الأخرى تحديد الفاعل
            }
            return '';
        }
        
        return $speaker;
    }
    return '';
}

/**
 * استنتاج الفاعل الصريح من العنوان - دالة مساعدة
 */
if (!function_exists('sod_infer_explicit_speaker_actor')) {
    function sod_infer_explicit_speaker_actor($title) {
        return sod_extract_speaker_actor($title);
    }
}

function sod_is_media_source_actor($actor) {
    $actor = trim((string)$actor);
    if ($actor === '') return true;
    return preg_match('/(إعلام إسرائيلي|وسائل إعلام إسرائيلية|صحيفة|إذاعة|قناة|رويترز|أكسيوس|بوليتيكو|بلومبرغ|العربية|الميادين|المنار|إيران الآن|ايران الان|beiruttime|bintjbeil|قناة الساحات|الاعلام الحربي|الاعلام العبري بالعربي|روسيا الاتحادية|تسنيم|فارس|إرنا|واس|سانا|معاً|وطن|دنيا الوطن|عربي21|الخليج أونلاين|العين الإخبارية|المشهد|دهشة|Mashhad|Al-Mayadeen|Al-Alam|Press TV|Wall Street Journal|New York Times|Washington Post|CNN|BBC|Guardian|Reuters|AP|AFP|Xinhua|RT|Sputnik|تانكر تراكرز|الشمال نيوز|جيروزاليم بوست|وول ستريت جورنال|واشنطن بوست|اللواء)/ui', $actor) === 1;
}


function sod_actor_context_bad_tokens(): array {
    return [
        'أجواء','اجواء','عاجل','الآن','الان','توتر','تصعيد','مناطق','منطقة','المناطق','مصدر','مصادر','مصدر عسكري','مصدر أمني','مصدر امني',
        'الخارجية الإيرانية','الخارجية الايرانية','وزارة الدفاع الإيرانية','وزارة الدفاع الايرانية','المتحدث باسم وزارة الدفاع الإيرانية','المتحدث باسم الدفاع الإيرانية',
        'المتحدث باسم وزارة الخارجية الإيرانية','المتحدث باسم الخارجية الإيرانية','المتحدث باسم مقر خاتم الأنبياء','المتحدث باسم مقر خاتم الانبياء',
        'المتحدث باسم وزارة الدفاع','المتحدث باسم الخارجية','المتحدث باسم الدفاع'
    ];
}

function sod_is_bad_actor_candidate($actor): bool {
    $actor = trim((string)$actor);
    if ($actor === '' || sod_is_unknown_actor_label($actor) || sod_is_media_source_actor($actor)) {
        return true;
    }
    foreach (sod_actor_context_bad_tokens() as $bad) {
        if ($actor === $bad) {
            return true;
        }
    }
    if (preg_match('/^(?:-|—|–|:|\.|،|,)+/u', $actor)) {
        return true;
    }
    if (preg_match('/^(?:في|من|عن|على|الى|إلى)\s+/u', $actor)) {
        return true;
    }
    return preg_match('/^(?:أجواء|اجواء|عاجل|الآن|الان|توتر|تصعيد|مناطق|المناطق|مصدر|مصادر)(?:\s|$)/ui', $actor) === 1;
}

function sod_apply_actor_canonical_if_available($actor) {
    $actor = trim((string)$actor);
    if ($actor === '') {
        return '';
    }
    if (function_exists('sod_resolve_registry_canonical')) {
        $resolved = trim((string)sod_resolve_registry_canonical('actors', $actor));
        if ($resolved !== '') {
            return $resolved;
        }
    }
    return $actor;
}

function sod_resolve_actor_from_context_v2($title, $region = '', $current_actor = '', $source_name = '') {
    $title = so_clean_text((string)$title);
    $region = trim((string)$region);
    $current_actor = trim((string)$current_actor);
    $source_name = trim((string)$source_name);
    $text = so_clean_text(trim($title . ' ' . $source_name . ' ' . $region));

    if ($current_actor !== '' && !sod_is_bad_actor_candidate($current_actor)) {
        return sod_apply_actor_canonical_if_available($current_actor);
    }

    if (preg_match('/(المتحدث باسم|الخارجية الإيرانية|الخارجية الايرانية|وزارة الدفاع الإيرانية|وزارة الدفاع الايرانية|مجلس الأمن القومي الإيراني|المجلس الأعلى للأمن القومي|الرئيس الايراني|الرئيس الإيراني|محمد باقر قاليباف|قاليباف|مسعود بزشكيان|إسماعيل بقائي|غلام حسين محسني إيجئي|الخارجية الإيرانية|الجيش الإيراني|السلطة القضائية الإيرانية)/ui', $text)) {
        return 'إيران';
    }

    if (preg_match('/(الحرس الثوري|حرس الثورة|حرس الثورة الإسلامية|الحرس الثوري الإيراني|استخبارات حرس الثورة|مقر خاتم الأنبياء|مقر خاتم الانبياء|قوة القدس|القوة الجوفضائية|قائد القوة الجوفضائية|مجيد موسوي)/ui', $text)) {
        return 'الحرس الثوري الإيراني';
    }

    if (preg_match('/(البيت الأبيض|البيت الابيض|البنتاغون|وزارة الدفاع الأميركية|وزارة الدفاع الأمريكية|القيادة المركزية الأميركية|القيادة المركزية الأمريكية|واشنطن|ترامب|ترمب)/ui', $text)) {
        return 'الولايات المتحدة';
    }

    if (preg_match('/(المتحدث باسم جيش الاحتلال|الجيش الإسرائيلي|الجيش الاسرائيلي|جيش الاحتلال|قوات الاحتلال|جيش العدو الإسرائيلي|المتحدث باسم الجيش الإسرائيلي|المتحدث باسم الجيش الاسرائيلي)/ui', $text)) {
        return 'جيش العدو الإسرائيلي';
    }

    if (preg_match('/(حزب الله|المقاومة الإسلامية|المقاومة الاسلامية|مجاهدو المقاومة|الإعلام الحربي|الاعلام الحربي)/ui', $text)) {
        return 'المقاومة الإسلامية (حزب الله)';
    }

    if (preg_match('/(?:عن|بحسب|وفق|نقلاً عن|نقلا عن)\s+مصدر(?:\s+(?:عسكري|أمني|امني))?/ui', $title)) {
        if (preg_match('/(تسنيم|فارس|إرنا|إيرنا|التلفزيون الإيراني|إعلام إيراني|ايران|إيران|طهران)/ui', $text)) {
            return 'إيران';
        }
        if (preg_match('/(مصدر عسكري إسرائيلي|مصدر أمني إسرائيلي|مصدر امني إسرائيلي|إذاعة الجيش الإسرائيلي|اعلام عبري|إعلام إسرائيلي)/ui', $text)) {
            return 'جيش العدو الإسرائيلي';
        }
    }

    if (($region === 'إيران' || preg_match('/(إيران|ايران|طهران|أصفهان|نطنز|بوشهر)/ui', $text))
        && !preg_match('/(غارة إسرائيلية|غاره اسرائيلية|قصف إسرائيلي|قصف اسرائيلي|استهداف إسرائيلي|استهداف اسرائيلي|هجوم إسرائيلي|هجوم اسرائيلي)/ui', $text)
        && preg_match('/(أعلن|أكد|صرح|قال|أفاد|كشف|شدد|توعد|اعتبر|أوضح)/ui', $text)) {
        return 'إيران';
    }

    return '';
}

function sod_infer_actor_strict($title, $content = '', $region = '', $current_actor = '', $source_name = '') {
    $current_actor = trim((string)$current_actor);
    $region = trim((string)$region);
    $title = trim((string)$title);
    $source_name = trim((string)$source_name);
    $text = so_clean_text(trim($title . ' ' . (string)$content . ' ' . $source_name . ' ' . $region));

    $rnn_override = sod_override_rnn_actor_from_event($title, $region, $source_name);
    if ($rnn_override !== '') {
        return $rnn_override;
    }

    $context_actor = sod_resolve_actor_from_context_v2($title, $region, $current_actor, $source_name);
    if ($context_actor !== '') {
        return $context_actor;
    }

    $speaker_actor = sod_extract_speaker_actor($title);
    if ($speaker_actor !== '') {
        $speaker_actor = sod_resolve_actor_from_context_v2($title, $region, $speaker_actor, $source_name) ?: $speaker_actor;
        if (!sod_is_bad_actor_candidate($speaker_actor)) {
            return sod_apply_actor_canonical_if_available($speaker_actor);
        }
    }

    if (!sod_is_unknown_actor_label($current_actor) && !sod_is_media_source_actor($current_actor)
        && !preg_match('/(منظومة الإنذار|الجبهة الداخلية)/ui', $current_actor)
        && mb_strlen($current_actor) <= 60
        && !sod_is_rnn_event_shell_actor($current_actor)
        && !sod_is_bad_actor_candidate($current_actor)) {
        return sod_apply_actor_canonical_if_available($current_actor);
    }

    // Reject long accidental fragments from title/body parsing.
    if (mb_strlen($current_actor) > 60) {
        $current_actor = '';
    }

    $has_sirens = preg_match('/(صفارات(?:\s*الإنذار)?|صافرات(?:\s*الإنذار)?|سيتم اطلاق صافرات|خلال الدقائق التالية|تفعيل صفارات|البقاء قرب الملاجئ|انذار احمر|إنذار أحمر|تسوفار)/ui', $text);
    $has_missile_detection = preg_match('/(رصد صواريخ|رصد إطلاق صواريخ|رصد اطلاق صواريخ|صواريخ سيتم اعتراضها|صاروخ بالستي|إطلاق صاروخي بعيد|إطلاق\s+\d+\s+صاروخ|صلية صاروخية|إطلاق صواريخ)/ui', $text);
    $has_drones = preg_match('/(تسلل طائرات|تسلل طائرة|طائرة مسيّرة|طائرة مسيرة|مسيّرة|مسيرة)/ui', $text);
    $has_immediate_fire = preg_match('/(رمايات فورية|رمايات|رشقة|رشقات|صلية|إطلاق مباشر|نيران فورية|صاروخ مضاد للدروع|استهداف دبابة|إصابة دبابة|أصابت دبابته|قائد الكتيبة|اللواء 401|كمين|اشتباك)/ui', $text);
    $is_north = preg_match('/(صفد|كريات شمونة|المطلة|نهاريا|الجليل|الحدود اللبنانية|شمال فلسطين|كاديتا|حتسور هجليلت|مرغليوت|أفيفيم|مسكافعام|راموت نفتالي|سهل الحولة)/ui', $text);
    $is_gaza = preg_match('/(غزة|غلاف غزة|محيط الغلاف|سديروت|عسقلان|أشكول|نير عوز|كيسوفيم|خان يونس|رفح|بيت حانون|جباليا|حماس|القسام|سرايا القدس)/ui', $text);
    $mentions_iran = preg_match('/(إيران|ايران|طهران|الحرس الثوري|حرس الثورة)/ui', $text);
    $mentions_yemen = preg_match('/(اليمن|الحوثي|الحوثيين|صنعاء|إيلات|البحر الأحمر|البحر الاحمر|أنصار الله)/ui', $text);
    $mentions_hezb = preg_match('/(حزب الله|المقاومة الإسلامية|الاعلام الحربي|الإعلام الحربي|الحز\.?\s*ب|مجاهدونا|المقاومة في لبنان)/ui', $text);
    $is_israeli_attack_in_lebanon = preg_match('/(غارة|غارات|قصف|استهداف|استهدفت|عدوان|اعتداء|طيران حربي|طيران معاد|مسيرة إسرائيلية|مسيّرة إسرائيلية)/ui', $text) && preg_match('/(لبنان|الجنوب|النبطية|بنت جبيل|السعديات|الجية|أنصارية|كفرتبنيت|دبعال|ميدون|برعشيت|الدوير|الشهابية|القنطرة|دبين|صور|صيدا|مرجعيون)/ui', $text);

    if ($is_israeli_attack_in_lebanon) {
        return 'جيش العدو الإسرائيلي';
    }
    if ($is_gaza) {
        return 'الفصائل الفلسطينية';
    }
    if ($has_sirens) {
        if ($is_north || preg_match('/(من\s+لبنان|من لبنان|شمال فلسطين|الجبهة الشمالية|سهل الحولة|كريات شمونه|كريات شمونة|صفد|الجليل الأعلى|الجليل الغربي)/ui', $text)) {
            return 'المقاومة الإسلامية (حزب الله)';
        }
        if ($mentions_yemen) return 'اليمن';
        if ($mentions_iran) return 'إيران';
        if ($has_missile_detection) return 'محور المقاومة (استنتاج)';
        return 'محور المقاومة (استنتاج)';
    }
    if ($mentions_hezb || $has_drones || $has_immediate_fire || $is_north) {
        return 'المقاومة الإسلامية (حزب الله)';
    }
    if ($has_missile_detection) {
        if ($mentions_yemen) return 'اليمن';
        if ($mentions_iran) return 'إيران';
        if ($region === 'لبنان' || preg_match('/(من لبنان|الجنوب اللبناني)/ui', $text)) return 'المقاومة الإسلامية (حزب الله)';
        return 'محور المقاومة (استنتاج)';
    }
    if ($mentions_yemen) return 'اليمن';
    if ($mentions_iran) return 'إيران';
    if ($region === 'لبنان') {
        return 'المقاومة الإسلامية (حزب الله)';
    }
    if ($region === 'فلسطين') {
        return 'الفصائل الفلسطينية';
    }
    if ($region === 'الأراضي المحتلة (إسرائيل)' && preg_match('/(الجيش الإسرائيلي|جيش العدو الإسرائيلي|الحكومة الإسرائيلية|الاحتلال|المستوطنين)/ui', $text)) {
        if (preg_match('/(الجيش الإسرائيلي|جيش العدو الإسرائيلي)/ui', $text)) return 'جيش العدو الإسرائيلي';
        if (preg_match('/(الحكومة الإسرائيلية|رئيس الوزراء الإسرائيلي|البيت الأبيض|القيادة المركزية الأميركية)/ui', $text, $m)) return trim($m[1]);
        return 'الاحتلال الإسرائيلي';
    }

    return sod_apply_actor_canonical_if_available('محور المقاومة (استنتاج)');
}


function so_force_actor_not_unknown($actor, $title, $region='', $source_name='') {
    $actor = trim((string)$actor);
    if ($actor !== '') return $actor;
    
    $title = so_clean_text((string)$title);
    $t = $title . ' ' . trim((string)$source_name);
    $lower = mb_strtolower($t);
    
    // استبعاد الأحداث الدبلوماسية/السياسية أولاً - هذه لا تُنسب لإسرائيل أبداً
    $is_diplomatic = preg_match('/(مفاوضات|محادثات|وفد|اجتماع|لقاء|قمة|مؤتمر|بيان سياسي|تصريح|وزارة الخارجية|الرئيس|رئيس الوزراء|الأمم المتحدة|الاتحاد الأوروبي|جامعة الدول العربية)/ui', $t);
    $is_economic = preg_match('/(اقتصاد|نفط|غاز|طاقة|أسعار|سوق|تجارة|استثمار|بنك|صندوق|عملة|تضخم|مالية|ميزانية)/ui', $t);
    $is_media_report = preg_match('/(وسائل إعلام|تقرير إعلامي|تحليل|صحيفة|قناة|إذاعة|موقع إخباري|رويترز|غارديان|نيويورك تايمز|وول ستريت جورنال|أكسيوس|بوليتيكو)/ui', $t);
    $is_political_statement = preg_match('/(قال|أكد|صرح|أعلن|أفاد|نقل عن|بحسب|وفق|ذكر|كشف|شجب|استنكر|أدان|رحب|حث|دعا|طالب|طالبوا)/ui', $t);
    
    // لا تُطبَّق القواعد الاستنتاجية على الأحداث غير العسكرية
    if ($is_diplomatic || $is_economic || $is_media_report || $is_political_statement) {
        return sod_infer_actor_strict($title, '', $region, '', $source_name);
    }
    
    // لبنان: غارات/قصف → إسرائيل (فقط مع أفعال عسكرية صريحة)
    if (($region === 'لبنان' || preg_match('/(لبنان|بيروت|الضاحية|الجنوب|النبطية|بنت جبيل|الخيام|شقرا|عدشيت|صور|صيدا|جبل لبنان)/ui', $t))
        && preg_match('/(غارة|غارات|قصف|استهداف|طيران حربي|طيران الاحتلال|طيران معادي|مسيّرة معادية|مسيرة معادية|عدوان|اعتداء إسرائيلي|اعتداء اسرائيلي)/ui', $t)) {
        return 'جيش العدو الإسرائيلي';
    }
    
    // فلسطين: اقتحامات/قصف → إسرائيل (فقط مع أفعال عسكرية صريحة)
    if (($region === 'فلسطين' || preg_match('/(غزة|الضفة الغربية|جنين|نابلس|الخليل|رفح|خان يونس|بيت لاهيا|جباليا|طولكرم)/ui', $t))
        && preg_match('/(اقتحام|اعتقالات|اعتقال|إطلاق نار من دبابات|إطلاق نار بحري|قصف مدفعي|قصف|نسف|جرافات|توغل)/ui', $t)) {
        return 'جيش العدو الإسرائيلي';
    }
    
    return sod_infer_actor_strict($title, '', $region, '', $source_name);
}

function so_bt_detect_actor_v2($title, $source_name = '') {
    $title = so_clean_text((string)$title);
    $source_name = trim((string)$source_name);
    $t = so_clean_text($title . ' ' . $source_name);
    $region = so_bt_detect_region_v3_patch($title, so_bt_detect_region_v2($title));
    $named_nonmilitary = sod_extract_named_nonmilitary_actor($t);
    $has_attack_markers = preg_match('/(غارة|غارات|قصف|استهداف|استهدفت|عدوان|اشتباك|توغل|اقتحام|صاروخ|صواريخ|طيران حربي|الطيران الحربي|مسيرة|مسيّرة|هجوم|اغتيال|إطلاق نار|استطلاع بطائرة مسيّرة|تم رصد)/ui', $title) === 1;

    $rnn_override = sod_override_rnn_actor_from_event($title, $region, $source_name);
    if ($rnn_override !== '') {
        return $rnn_override;
    }

    $context_actor = sod_resolve_actor_from_context_v2($title, $region, '', $source_name);
    if ($context_actor !== '' && !sod_is_bad_actor_candidate($context_actor)) {
        return sod_apply_actor_canonical_if_available($context_actor);
    }

    if (sod_is_non_military_context($t) && !$has_attack_markers) {
        if ($named_nonmilitary !== '') {
            return $named_nonmilitary;
        }
        if (preg_match('/(إيران|ايران|طهران)/ui', $title)) {
            return 'إيران';
        }
        if (preg_match('/(الولايات المتحدة|أمريكا|امريكا|واشنطن|البيت الأبيض|ترامب|ترمب)/ui', $title)) {
            return 'الولايات المتحدة';
        }
        if (preg_match('/(باكستان|إسلام آباد|اسلام آباد)/ui', $title)) {
            return 'باكستان';
        }
        return sod_infer_actor_strict($title, '', $region, '', $source_name);
    }

    // بيانات الصفارات / الإنذارات: الفاعل يُستنتج ولا يُسند إلى الإعلام الناقل
    if (preg_match('/(صفارات(?: الإنذار)?|صافرات(?: الإنذار)?|إنذار|انذار|الجبهة الداخلية|خشية تسلل)/ui', $title)) {
        return sod_infer_actor_strict($title, '', $region, '', $source_name);
    }

    // أفعال هجومية إسرائيلية داخل لبنان
    if (
        ($region === 'لبنان' || preg_match('/(لبنان|بيروت|الضاحية|صور|النبطية|بنت جبيل|الخيام|دير الزهراني|المنصوري|كونين|قانا|حناويه|بشامون|سن الفيل|تلة الخياط|الأنصارية|الجناح|حي السلم|زحلة|بعلبك|الهرمل|صيدا|العباسية|حاصبيا|مرج الزهور)/ui', $title)) &&
        preg_match('/(غارة|غارات|قصف|استهداف|استهدفت|عدوان|اعتداء إسرائيلي|اعتداء اسرائيلي|طيران حربي|الطيران الحربي المعادي|مسيّرة|مسيرة|تحليق حربي|حربي فوق)/ui', $title)
    ) {
        return 'جيش العدو الإسرائيلي';
    }

    // مقاومة لبنانية
    if (preg_match('/(مراسل المنار|الإعلام الحربي|الاعلام الحربي|المقاومة الإسلامي(?:ة)?|حزب الله|مجاهدو المقاومة|مجاهدونا|استهدف مجاهدو|استهدف مجاهدو|صلية صاروخية من لبنان|إطلاق صواريخ من لبنان|أطلق من لبنان|باتجاه الأراضي المحتلة|باتجاه فلسطين المحتلة|تدمير دبابة ميركافا)/ui', $title . ' ' . $source_name)) {
        return 'المقاومة الإسلامية (حزب الله)';
    }

    // سقوط صاروخ / رشقات على الداخل المحتل
    if (
        ($region === 'الأراضي المحتلة (إسرائيل)' || preg_match('/(كريات شمونة|نهاريا|حيفا|عكا|تل أبيب|بتاح تكفا|بئر السبع|المنارة|مرغليوت|أفيفيم|مسكافعام|راموت نفتالي|الجليل|النقب|القدس المحتلة)/ui', $title)) &&
        preg_match('/(سقوط صاروخ|إطلاق صواريخ|صواريخ|رشقة|رشقات|صلية|صلية صاروخية)/ui', $title)
    ) {
        return 'جهة مقاومة من لبنان';
    }

    // اقتحامات واعتقالات في فلسطين
    if (($region === 'فلسطين' || preg_match('/(الضفة الغربية|غزة|جنين|نابلس|طولكرم|الخليل|قلقيلية|رفح|خان يونس|جباليا)/ui', $title))
        && preg_match('/(اقتحام|اعتقال|اعتقالات|قصف|نسف|إطلاق نار من دبابات|إطلاق نار بحري)/ui', $title)) {
        return 'جيش العدو الإسرائيلي';
    }

    // جهات رسمية لبنانية
    if ($region === 'لبنان' && preg_match('/(مصادر رسمية لبنانية|مصدر رسمي لبناني|وزارة الصحة اللبنانية|الجيش اللبناني|رئاسة الجمهورية|الرئيس|مجلس الوزراء|نواف سلام|قيادة الجيش|وزارة الصحة|لبنان: وزير|مسؤول لبناني)/ui', $title)) {
        return 'لبنان';
    }

    // إيران: فقط في السياق الدبلوماسي/السياسي (وفود، مفاوضات، لقاءات) - لا تُنسب للأحداث العسكرية
    if (preg_match('/(وفد|مفاوضات|محادثات|اجتماع|لقاء|زيارة|قمة|مؤتمر|وزير الخارجية|الرئيس|رئيس الوزراء|خامنئي|بزشكيان|عراقجي|قاليباف)/ui', $title)) {
        // استبعاد أي سياق عسكري لإيران
        if (preg_match('/(غارة|قصف|استهداف|صاروخ|مسيرات|حرب|قتل|اغتيال)/ui', $title)) {
            // هذا حدث عسكري، لا تُنسب لإيران الدبلوماسية
            return 'فاعل سياقي غير مباشر';
        }
        if (preg_match('/(إيران|ايران|طهران)/ui', $title)) {
            return 'إيران';
        }
        if (preg_match('/(الولايات المتحدة|أمريكا|امريكا|واشنطن|البيت الأبيض|ترامب|ترمب|فيتكوف|كوشنر|فانس)/ui', $title)) {
            return 'الولايات المتحدة';
        }
        if (preg_match('/(باكستان|إسلام آباد)/ui', $title)) {
            return 'باكستان';
        }
        return $named_nonmilitary !== '' ? $named_nonmilitary : 'فاعل غير محسوم';
    }
    
    // إيران العسكرية (الحرس الثوري)
    if (preg_match('/(الحرس الثوري|حرس الثورة|خاتم الأنبياء|قائد قوة القدس|قاآني)/ui', $title)) {
        return 'الحرس الثوري الإيراني';
    }

    return $named_nonmilitary !== '' ? $named_nonmilitary : sod_infer_actor_strict($title, '', $region, '', $source_name);
}

function so_bt_score_news_v2($title, $classification, $actor, $region, $source_name = '') {
    $t = so_clean_text((string)$title . ' ' . (string)$source_name);
    if ($classification === 'غير استخباراتي') return 0;

    // حالات خاصة أولاً
    if (preg_match('/(الحداد الوطني|يعلن الحداد|الاتحاد العمالي العام)/ui', $t)) return 18;

    $score = 10;
    switch ($classification) {
        case 'إعلامي': $score += 8; break;
        case 'سياسي': $score += 22; break;
        case 'بيان': $score += 24; break;
        case 'شجب/استنكار': $score += 14; break;
        case 'اقتصادي/لوجستي': $score += 38; break;
        case 'رصد/إنذار': $score += 48; break;
        case 'عسكري/أمني': $score += 95; break;
        case 'تكتيكي/ميداني': $score += 58; break;
        case 'نووي': $score += 120; break;
        default: $score += 15; break;
    }

    if ($actor === 'جيش العدو الإسرائيلي') $score += 25;
    elseif ($actor === 'إيران') $score += 18;
    elseif ($actor === 'الحرس الثوري الإيراني') $score += 20;
    elseif ($actor === 'الولايات المتحدة') $score += 15;
    elseif ($actor === 'فلسطينيون' || $actor === 'فصائل المقاومة الفلسطينية') $score += 18;
    elseif ($actor === 'المقاومة الإسلامية (حزب الله)') $score += 30;
    elseif ($actor === 'الجبهة الداخلية الإسرائيلية') $score += 8;
    elseif ($actor === 'مستوطنون إسرائيليون') $score += 10;
    elseif ($actor === 'فاعل غير محسوم' || $actor === 'فاعل سياقي غير مباشر' || $actor === 'فاعل سياقي') $score -= 2;
    elseif ($actor === 'سوق / قطاع طاقة ونقل') $score += 6;
    elseif ($actor === 'محتوى إعلامي / غير عملياتي') $score -= 18;
    elseif (in_array($actor, ['لبنان','إسبانيا','فرنسا','ألمانيا','المملكة المتحدة','إيطاليا','الاتحاد الأوروبي','الإمارات','قطر','الكويت','العراق','سلطنة عمان','السعودية','روسيا','الهند','باكستان','كولومبيا','البحرين','أدنوك / الإمارات','السلطة الفلسطينية','الجبهة الشعبية لتحرير فلسطين','الجبهة الديمقراطية لتحرير فلسطين','المقاومة العراقية'], true)) $score += 6;

    if (in_array($region, ['لبنان','فلسطين','الأراضي المحتلة (إسرائيل)','إيران','الخليج'], true)) $score += 12;
    elseif ($region === 'غير محدد') $score -= 5;

    if (preg_match('/(مقتل|قتيل|قتلى|شهيد|شهداء|استشهاد|إصابة|إصابات|اغتيال|انهيار مبنى|ضربة مباشرة|حريق كبير|أعمدة النيران)/ui', $t)) $score += 30;
    if (preg_match('/(صلية صاروخية|صليّات صاروخية|عدة صواريخ|رشقة صاروخية)/ui', $t)) $score += 20;
    if (preg_match('/(عشرات الصواريخ|صواريخ باليستية|أوسع قصف|غارة عنيفة|غارتان|سلسلة من 21 غارة|قصف متعدد|قصف واسع)/ui', $t)) $score += 22;

    // تقليل الإعلامي المحض
    if (preg_match('/(فيديو يوثق|لحظة شن|منصات للمستوطنين|إعلام العدو:|اعلام العدو:|مراسل)/ui', $t) && $classification === 'إعلامي') $score -= 12;

    // رفع محدود لمضيق هرمز
    if (preg_match('/(مضيق هرمز|حشود من السفن|السفن متوقفة|ناقلات النفط)/ui', $t)) $score += 12;

    if ($classification === 'رصد/إنذار' && !preg_match('/(تم رصد غارة|تم رصد قصف|إطلاق صواريخ|صلية صاروخية|اقتحام|اعتقالات|إطلاق نار من دبابات)/ui', $t)) $score -= 10;
    if (preg_match('/(تنويه|ندعوكم|للاشتراك|ناسا|القمر|رواد فضاء|درب التبانة)/ui', $t)) $score = 0;

    return max(0, min(200, (int)$score));
}


function so_bt_classify_v4($title, $source_name = '', $region = '', $actor = '') {
    $t = so_clean_text((string)$title);
    $s = so_clean_text((string)$source_name);
    $a = so_clean_text((string)$actor);
    $full = trim($t . ' ' . $s);
    
    // Check actor for resistance/military actors first
    $is_resistance_actor = preg_match('/(المقاومة الإسلامية|حزب الله|حماس|الجهاد الإسلامي|كتائب القسام|سرايا القدس|الحرس الثوري|قوة القدس)/ui', $a);
    $is_enemy_actor = preg_match('/(جيش العدو الإسرائيلي|الجيش الإسرائيلي|الجبهة الداخلية| IDF |Israel)/ui', $a);

    // 0) Non-intel / technical / awareness content
    if (preg_match('/(حماية_الخصوصية|أمن_المعلومات|أندرويد|هذا الفيديو يعرض|إعدادات مهم(?:ة|ّة)|نشرة تقنية|نصائح تقنية|خصوصية|التكنولوجيا)/ui', $full)) {
        return 'غير استخباراتي';
    }

    // 1) Military / security FIRST - Enhanced to catch resistance operations even with media sources
    $military_keywords = '(غارة|غارات|قصف|استهداف|اعتداء إسرائيلي|اعتداء اسرائيلي|صاروخ|صواريخ|صلية|مسيّرة|مسيرة|فسفوري|ميركافا|أغار|اغار|ضربة|اغتيال|هجوم مزدوج|محلّقة انقضاضية|طيران حربي|الطيران الحربي المعادي|استهدف بلد|استهدف بلدة|استهدفت بلدة|مجزرة|اقتحام|اعتقالات|دبابات|مدفعي|رصد قصف|raid|strike|bombing|missile|drone)';
    
    if (preg_match('/'.$military_keywords.'/ui', $full)) {
        return 'عسكري/أمني';
    }
    
    // Also classify as military if actor is resistance/enemy and title mentions attack/target
    if (($is_resistance_actor || $is_enemy_actor) && preg_match('/(استهدف|استهداف|ضرب|قصف|أطلق|صاروخ|مسيّرة|عملية|كمين|اشتباك)/ui', $t)) {
        return 'عسكري/أمني';
    }

    // 2) Alerts / warning / detection
    if (preg_match('/(صفارات الإنذار|صافرات الإنذار|انذار|إنذار|خشية تسلل|تم رصد|الجبهة الداخلية|تجدد دوي صفارات|دخول طائرات مسيّرة|إطلاق نار كواد كوبتر|إطلاق نار بحري|إطلاق نار من آليات)/ui', $full)) {
        return 'رصد/إنذار';
    }

    // 3) Economic / logistics
    if (preg_match('/(خام برنت|العقود الآجلة|النفط|الغاز|الشحنات|الملاحة|إمدادات|مضيق هرمز|ناقلات|أسواق|للبرميل|الطاقة|مشاريع نفطية|وقود|اقتصادي|اقتصادية)/ui', $full)) {
        return 'اقتصادي/لوجستي';
    }

    // 4) Condemnation / denunciation
    if (preg_match('/(ندين|نستنكر|شجب|استنكار|نندد|إدانة)/ui', $full)) {
        return 'شجب/استنكار';
    }

    // 5) Political / diplomatic / official - Enhanced
    $political_keywords = '(وزارة الخارجية|وزير|رئيس|حكومة|بيان|الفاتيكان|بابا الفاتيكان|مجموعة السبع|السفارة|روبيو|السفير|الدفاع|الخارجية|الرئاسة|مجلس الأمن|المستشار الألماني|الحكومة الألمانية|وزراء خارجية|وزيرة الجيوش|الدبلوماسي|مصدر دبلوماسي|الجيش الأردني|وزارة الدفاع|وزارة النفط|وزير الصحة|رئيس الجمهورية|قيادة الجيش|حرس الثورة|قائد قوة القدس|مفاوضات|وفد|محادثات|قمة|اجتماع دولي|مبادرة|وساطة|هدنة|وقف إطلاق النار)';
    
    if (preg_match('/'.$political_keywords.'/ui', $full)) {
        // But override if it's clearly about a military action
        if (!preg_match('/'.$military_keywords.'/ui', $full)) {
            return 'سياسي';
        }
        return 'عسكري/أمني'; // Military takes precedence
    }

    // 6) Media / coverage / commentary - Only if no military content
    if (preg_match('/(مراسل|وسائل إعلام|وسائل اعلام|إعلام العدو|اعلام العدو|القناة 12|يديعوت|فوكس نيوز|تغطية خاصة|آخر مستجدات العمليات العسكرية|رويترز|بلومبرغ|أكسيوس|واشنطن بوست|صحيفة|وكالة)/ui', $full)) {
        // Check if the actual content is about military action despite being from media source
        if (preg_match('/'.$military_keywords.'/ui', $t) || $is_resistance_actor || $is_enemy_actor) {
            return 'عسكري/أمني';
        }
        return 'إعلامي';
    }

    return 'تكتيكي/ميداني';
}



function so_bt_analyze_news_v2($title, $source_name = '') {
    $title = so_clean_text((string)$title);
    if (so_is_non_intel_noise($title)) {
        return ['ignored'=>true,'classification'=>'غير استخباراتي','region'=>'غير محدد','actor'=>'مستبعد/غير استخباراتي','score'=>0];
    }
    $region = function_exists('so_bt_detect_region_v3_patch') ? so_bt_detect_region_v3_patch($title, so_bt_detect_region_v2($title)) : so_bt_detect_region_v2($title);
    $class = sod_classify_event_v3(['title'=>$title,'content'=>'']);
    $actor = $class['actor_v2'] ?: 'فاعل غير محسوم';
    $classification = so_bt_classify_v4($title, $source_name, $region, $actor);
    $score = so_bt_score_news_v2($title, $classification, $actor, $region, $source_name);
    return ['ignored'=>false,'classification'=>$classification,'region'=>$region,'actor'=>$actor,'score'=>$score];
}


function so_build_dynamic_recommendations($stats) {
    $rec = [];
    $top_regions = $stats['top_regions'] ?? [];
    $threat_level = (string)($stats['threat_level'] ?? '');
    $avg_score = (int)($stats['avg_score'] ?? 0);
    $critical = (int)($stats['critical'] ?? 0);
    $trend = (string)($stats['trend'] ?? '');
    $has_il = !empty($stats['has_il']);
    $has_us = !empty($stats['has_us']);
    $has_iran = !empty($stats['has_iran']);
    $unattr_ratio = (float)($stats['unattributed_ratio'] ?? 0);
    $dominant_type = (string)($stats['dominant_type'] ?? '');
    $lebanon_count = (int)($top_regions['لبنان'] ?? 0);
    $duplicate_like_ratio = (float)($stats['duplicate_like_ratio'] ?? 0);

    if ($lebanon_count >= 25 && $avg_score >= 85) {
        $rec[] = 'تركيز الجهد التنفيذي على الساحة اللبنانية بسبب كثافة الضربات وارتفاع متوسط الخطورة.';
    }
    if ($trend === 'تصاعدي ↑' && $critical >= 10) {
        $rec[] = 'رفع وتيرة التحديث التنفيذي لأن المؤشرات تدل على تصاعد سريع في الساعات الأخيرة.';
    }
    if ($trend === 'هبوطي ↓' && $critical < 8) {
        $rec[] = 'الحفاظ على الرصد المكثف مع تجنب تضخيم سيناريوهات التصعيد ما لم تظهر موجة جديدة.';
    }
    if ($unattr_ratio >= 0.35) {
        $rec[] = 'إعطاء أولوية لتدقيق الأخبار غير المنسوبة وتجميع المتشابه منها قبل اعتمادها في الاستنتاج النهائي.';
    }
    if ($duplicate_like_ratio >= 0.28) {
        $rec[] = 'تقليل أثر الأخبار المتشابهة عبر التجميع قبل إدخالها في التقييم حتى لا يتضخم المشهد اصطناعياً.';
    }
    if ($has_il && $dominant_type === 'عسكري/أمني') {
        $rec[] = 'تركيز المراقبة على الضربات الجوية والأهداف المتحركة والبنى الحساسة ضمن مناطق النشاط الإسرائيلي المكثف.';
    }
    if ($has_us && $has_iran) {
        $rec[] = 'تعزيز الربط بين المؤشرات السياسية الأميركية–الإيرانية وبين التغيرات الميدانية قبل تثبيت أي تقدير نهائي.';
    }
    if ($dominant_type === 'سياسي') {
        $rec[] = 'تقديم التحليل السياسي والدبلوماسي على التقديرات الميدانية لأن النشاط التصريحي هو المهيمن حالياً.';
    }
    if ($dominant_type === 'شجب/استنكار' || $dominant_type === 'بيان') {
        $rec[] = 'عدم مساواة بيانات الشجب والاستنكار بالأحداث الميدانية عند حساب مستوى التهديد التنفيذي.';
    }
    if ($critical >= 20 && str_contains($threat_level, 'حرج')) {
        $rec[] = "ارتفاع غير اعتيادي في الأحداث الحرجة ({$critical} حدث) — إبقاء التصعيد التنفيذي عند المستوى الأعلى.";
    }
    if (empty($rec)) {
        $rec[] = 'لا توجد مؤشرات كافية على تغير نوعي يستدعي توصيات استثنائية — يُكتفى بالرصد الاعتيادي.';
    }
    return array_values(array_unique($rec));
}

function so_pick_top_developments($events, $limit = 8) {
    $picked = [];
    $seen = [];
    foreach ($events as $e) {
        $fp = so_build_title_fingerprint((string)($e['title'] ?? ''));
        if ($fp && isset($seen[$fp])) continue;
        $seen[$fp ?: md5((string)($e['title'] ?? ''))] = 1;
        $picked[] = $e;
        if (count($picked) >= $limit) break;
    }
    return $picked;
}

function so_extract_rss_items_fallback($xml_body, $source = []) {
    $items = [];
    if (!preg_match_all('/<item\b[\s\S]*?<\/item>/i', (string)$xml_body, $matches)) return [];
    foreach (($matches[0] ?? []) as $chunk) {
        $title = ''; $link = ''; $pub = '';
        if (preg_match('/<title>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/title>/i', $chunk, $m)) $title = so_clean_text($m[1]);
        if (preg_match('/<link>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/link>/i', $chunk, $m)) $link = so_normalize_event_link(trim(html_entity_decode($m[1], ENT_QUOTES | ENT_HTML5, 'UTF-8')));
        if (preg_match('/<pubDate>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/pubDate>/i', $chunk, $m)) $pub = trim($m[1]);
        $candidate = ['title'=>$title,'link'=>$link?:so_normalize_event_link((string)($source['url']??'')),'source'=>$source['name']??'','color'=>$source['color']??'','date'=>strtotime($pub)?:time(),'agency_loc'=>$source['location']??'','image_url'=>''];
        if (!so_should_publish_raw_item($candidate)) continue;
        $items[] = $candidate;
        if (count($items) >= so_source_items_limit()) break;
    }
    return $items;
}

function so_extract_origin_target_layer_simple($title, $region = '', $actor = '') {
    $text = so_clean_text((string)$title);
    $lower = mb_strtolower($text);
    $origin = ''; $target = ''; $battlefield = (string)$region; $classification = 'general';
    if (preg_match('/(أبو عبيدة|كتائب القسام|حماس|حركة حماس)/ui', $lower)) { $origin = 'فلسطين'; $classification = 'palestinian_statement'; }
    elseif (preg_match('/(سرايا القدس|أبو حمزة|الجهاد الإسلامي)/ui', $lower)) { $origin = 'فلسطين'; $classification = 'palestinian_statement'; }
    elseif (preg_match('/(الحرس الثوري|حرس الثورة|الجمهورية الإسلامية|إيران|خاتم الأنبياء)/ui', $lower)) {
        $origin = 'إيران';
        $classification = preg_match('/(بيان|أعلن|أفاد|كشف|صرح|أكد)/ui', $lower) ? 'origin_statement' : 'iran_related';
    }
    elseif (preg_match('/(وزارة الصحة اللبنانية|الرئيس عون|الجيش اللبناني|لبنان:)/ui', $lower)) $origin = 'لبنان';
    if (preg_match('/(إسرائيل|الاحتلال|تل أبيب|حيفا|الأراضي المحتلة|الجبهة الداخلية)/ui', $lower)) $target = 'الأراضي المحتلة (إسرائيل)';
    elseif (preg_match('/(لبنان|بيروت|الضاحية|الجنوب|صور|النبطية)/ui', $lower)) $target = 'لبنان';
    elseif (preg_match('/(إيران|بوشهر|طهران|نطنز|منظمة الطاقة الذرية)/ui', $lower)) $target = 'إيران';
    elseif (preg_match('/(غزة|الضفة|فلسطين|رفح|خان يونس|جباليا)/ui', $lower)) $target = 'فلسطين';
    if (preg_match('/(غارة|قصف|استهداف|هجوم|اشتباك|انفجار|اغتيال|توغل|إطلاق صواريخ|مسيّرة|مسيرة)/ui', $lower) && $target !== '') { $battlefield = $target; $classification = 'kinetic_event'; }
    elseif ($origin !== '' && preg_match('/(بيان|أعلن|أفاد|صرح|أكد|قال)/ui', $lower)) $battlefield = $origin;
    return ['origin_country'=>$origin?:'غير محدد','target_country'=>$target?:'غير محدد','battlefield_location'=>$battlefield?:($region?:'غير محدد'),'classification'=>$classification];
}

function so_get_source_reliability_meta($source_name) {
    $source_name = trim((string)$source_name);
    $search_sets = [get_option('so_sources',[]),get_option('so_tg_sources',[]),get_option('so_x_sources',[]),get_option('so_yt_sources',[])];
    foreach ($search_sets as $set) {
        if (!is_array($set)) continue;
        foreach ($set as $src) {
            if (!is_array($src)) continue;
            if (trim((string)($src['name']??'')) === $source_name) {
                $label = trim((string)($src['reliability']??''));
                if ($label !== '') {
                    $weight = 0;
                    if ($label === 'موثوق') $weight = 15; elseif ($label === 'محايد') $weight = 5; elseif ($label === 'غير موثوق') $weight = -25; elseif ($label === 'غير محايد') $weight = -15;
                    return ['label'=>$label,'weight'=>$weight];
                }
            }
        }
    }
    $rels  = get_option('so_source_reliability', []);
    $label = trim((string)($rels[$source_name]??'غير محدد'));
    $weight = 0;
    if ($label === 'موثوق') $weight = 15; elseif ($label === 'محايد') $weight = 5; elseif ($label === 'غير موثوق') $weight = -25; elseif ($label === 'غير محايد') $weight = -15;
    return ['label'=>$label===''?'غير محدد':$label,'weight'=>$weight];
}

function so_extract_best_datetime_from_text($title, $fallback_ts) {
    $title = (string)$title; $fallback_ts = (int)$fallback_ts ?: time();
    if (preg_match('/([0-9٠-٩]{1,2})[\/-]([0-9٠-٩]{1,2})[\/-]([0-9٠-٩]{2,4})(?:[^0-9٠-٩]{1,12}([0-9٠-٩]{1,2}:[0-9٠-٩]{2}))?/u', $title, $m)) {
        $day = intval(strtr($m[1],'٠١٢٣٤٥٦٧٨٩','0123456789'));
        $mon = intval(strtr($m[2],'٠١٢٣٤٥٦٧٨٩','0123456789'));
        $yr  = intval(strtr($m[3],'٠١٢٣٤٥٦٧٨٩','0123456789'));
        if ($yr < 100) $yr += 2000;
        $hm = !empty($m[4]) ? strtr($m[4],'٠١٢٣٤٥٦٧٨٩','0123456789') : gmdate('H:i', $fallback_ts);
        return sprintf('%04d-%02d-%02d %s', $yr, max(1,min(12,$mon)), max(1,min(31,$day)), $hm);
    }
    return gmdate('Y-m-d H:i', $fallback_ts);
}

function so_pick_brief_location_from_text($title, $fallback = '') {
    $title = so_clean_text((string)$title);
    $places = ['عيناتا','عكا','مركبا','المرج','الطيبة','حاروف','النبطية','السلطانية','أرزون','الضفة الغربية','طولكرم','الخليل','قطاع غزة','حي التفاح','أصفهان','بوشهر','مطار بغداد','بغداد','حيفا','نهاريا','عسقلان','تل أبيب','مضيق هرمز'];
    foreach ($places as $place) if (mb_stripos($title, $place) !== false) return $place;
    return $fallback;
}

function so_extract_precise_5w1h($title, $item, $actor, $region, $entities, $flags, $why, $confidence) {
    $title = so_clean_text((string)$title); $lower = mb_strtolower($title);
    $source_name = (string)($item['source'] ?? $item['source_name'] ?? '');
    $source_meta = so_get_source_reliability_meta($source_name);
    $layer = so_extract_origin_target_layer_simple($title, (string)$region, (string)$actor);
    $who_primary = (string)$actor; $who_secondary = '';
    
    // كشف السياق الدبلوماسي/السياسي - لا تُنسب الأحداث السياسية لإسرائيل
    $is_diplomatic_political = preg_match('/(مفاوضات|محادثات|وفد|اجتماع|لقاء|قمة|مؤتمر|تصريح|قال|أكد|صرح|أعلن|أفاد|نقل عن|بحسب|وفق|ذكر|كشف|شجب|استنكر|أدان|رحب|حث|دعا|طالب|وزارة الخارجية|الرئيس|رئيس الوزراء|الأمم المتحدة|الاتحاد الأوروبي|جامعة الدول العربية|بيان سياسي|تقرير إعلامي|وسائل إعلام|صحيفة|قناة|إذاعة|تحليل|رويترز|غارديان|نيويورك تايمز|وول ستريت جورنال|أكسيوس|بوليتيكو|اقتصاد|نفط|غاز|طاقة|أسعار|سوق|تجارة|استثمار|بنك|صندوق|عملة|تضخم|مالية)/ui', $lower);
    
    if (preg_match('/(أبو عبيدة|كتائب القسام|ناطق القسام)/ui', $lower)) { $who_primary = 'كتائب القسام (حماس)'; $who_secondary = 'حماس'; }
    elseif (preg_match('/(أبو حمزة|سرايا القدس)/ui', $lower)) { $who_primary = 'سرايا القدس (الجهاد الإسلامي)'; $who_secondary = 'الجهاد الإسلامي'; }
    elseif (preg_match('/(خاتم الأنبياء|الحرس الثوري|حرس الثورة|العلاقات العامة في حرس الثورة)/ui', $lower)) { $who_primary = 'مقر خاتم الأنبياء / الحرس الثوري الإيراني'; $who_secondary = 'إيران'; }
    elseif (preg_match('/(بيان صادر عن المقاومة الإسلامية|المقاومة الإسلامية في لبنان|دفاعًا عن لبنان)/ui', $lower)) { $who_primary = 'المقاومة الإسلامية (حزب الله)'; $who_secondary = 'لبنان'; }
    // الشرط الحرجة: لا تُنسب إسرائيل إلا في الأحداث العسكرية الحركية الصريحة
    elseif (!$is_diplomatic_political && preg_match('/(الجيش الإسرائيلي|جيش الاحتلال|طيران الاحتلال|سلاح الجو الإسرائيلي|القوات الإسرائيلية|مقاتلات الاحتلال|مدفعية الاحتلال|قصف إسرائيلي|قصف اسرائيلي|غارة إسرائيلية|غارة اسرائيلية|غارات إسرائيلية|غارات اسرائيلية|عدوان إسرائيلي|عدوان اسرائيلي)/ui', $lower)) {
        $who_primary = 'جيش العدو الإسرائيلي';
    }
    elseif (preg_match('/(وزارة الصحة اللبنانية)/ui', $lower)) { $who_primary = 'وزارة الصحة اللبنانية / تقرير'; $who_secondary = 'لبنان'; }
    $has_action_verbs   = preg_match('/(استهدف|قصف|هاجم|أطلق|نفذ|أغار|اغار|اغتيال|اقتحام|دمر|فجر|أسقط|اعترض|كمين|اشتباك|غارة|هجوم|صلية|مسيرات)/ui', $lower) === 1;
    $has_statement_verbs = preg_match('/(قال|صرح|أكد|أفاد|أعلن|الناطق|بيان|العلاقات العامة|المتحدث)/ui', $lower) === 1;
    $what_class = 'general';
    if (!empty($flags['has_direct_kinetic']) || $has_action_verbs) $what_class = 'kinetic';
    elseif (!empty($flags['has_alert_only'])) $what_class = 'alert';
    elseif (!empty($flags['is_summary_report'])) $what_class = 'report';
    elseif (!empty($flags['is_rumor'])) $what_class = 'rumor';
    elseif (!empty($flags['is_statement']) || $has_statement_verbs) $what_class = 'statement';
    if ($has_statement_verbs && !$has_action_verbs) $what_class = 'statement';
    $what_type = 'حدث عام';
    if ($what_class === 'statement') $what_type = 'تصريح / بيان';
    elseif ($what_class === 'report') $what_type = 'تقرير / متابعة';
    elseif ($what_class === 'alert') $what_type = 'إنذار / رصد';
    elseif (preg_match('/(غارة)/ui', $lower)) $what_type = 'غارة';
    elseif (preg_match('/(اقتحام)/ui', $lower)) $what_type = 'اقتحام';
    elseif (preg_match('/(استهدف|استهداف)/ui', $lower)) $what_type = 'استهداف';
    elseif (preg_match('/(هجوم)/ui', $lower)) $what_type = 'هجوم';
    elseif (preg_match('/(كمين)/ui', $lower)) $what_type = 'كمين';
    elseif (!empty($entities['actions'])) $what_type = (string)reset($entities['actions']);
    $why_reason = (string)$why;
    if (preg_match('/(دفاعًا عن[^\.,،\n]+)/u', $title, $m)) $why_reason = trim($m[1]);
    elseif (preg_match('/(رد(?:اً)? على[^\.,،\n]+)/u', $title, $m)) $why_reason = trim($m[1]);
    $how_weapon = !empty($entities['weapons']) ? implode('، ', array_unique(array_filter($entities['weapons']))) : 'غير محدد';
    $how_method = $what_class === 'statement' ? 'خطاب / بيان رسمي' : ($what_class === 'report' ? 'متابعة / نقل معلومات' : ($what_class === 'alert' ? 'رصد / إنذار مبكر' : $how_weapon));
    $where_origin = $layer['origin_country'] ?? 'غير محدد'; $where_target = $layer['target_country'] ?? 'غير محدد';
    $where_event = $layer['battlefield_location'] ?? ($region ?: 'غير محدد');
    $brief_place = so_pick_brief_location_from_text($title, '');
    if ($brief_place !== '') $where_event = $brief_place;
    $where_summary = $where_event;
    if ($what_class === 'statement' && $where_origin !== 'غير محدد' && $where_target !== 'غير محدد' && $where_origin !== $where_target) $where_summary = $where_origin . ' → ' . $where_target;
    $when_event    = so_extract_best_datetime_from_text($title, (int)($item['date'] ?? $item['event_timestamp'] ?? time()));
    $when_publish  = gmdate('Y-m-d H:i', (int)($item['date'] ?? $item['event_timestamp'] ?? time()));
    $confidence_overall = max(10, min(99, intval($confidence) + (int)$source_meta['weight']));
    return [
        'who_primary'=>$who_primary?:'غير محدد','who_secondary'=>$who_secondary,'who_source'=>$source_name?:'غير محدد',
        'what_type'=>$what_type?:'غير محدد','what_class'=>$what_class,'why_reason'=>$why_reason?:'غير محدد',
        'how_method'=>$how_method,'how_weapon'=>$how_weapon,'when_event'=>$when_event,'when_publish'=>$when_publish,
        'where_origin'=>$where_origin?:'غير محدد','where_target'=>$where_target?:'غير محدد',
        'where_event'=>$where_event?:'غير محدد','where_summary'=>$where_summary?:'غير محدد',
        'source_reliability'=>$source_meta['label'],'source_reliability_weight'=>(int)$source_meta['weight'],
        'confidence_who'=>$confidence_overall,'confidence_what'=>$confidence_overall,
        'confidence_where'=>$confidence_overall,'confidence_why'=>$confidence_overall,'confidence_overall'=>$confidence_overall,
    ];
}

function so_narrative_clean_title($title) {
    $title = so_clean_text((string)$title);
    $title = html_entity_decode($title, ENT_QUOTES | ENT_HTML5, 'UTF-8');
    $title = preg_replace('/\s+/u', ' ', trim($title));
    $title = preg_replace('/^(?:#\S+\s*)+/u', '', $title);
    $title = preg_replace('/^(?:إيران|لبنان|فلسطين|الأراضي المحتلة \(إسرائيل\)|سوريا|العراق)\s*[:\-–|]\s*/u', '', $title);
    return trim($title);
}

function so_narrative_limit($text, $limit = 170) {
    $text = trim((string)$text);
    if (mb_strlen($text) <= $limit) return $text;
    $cut = sod_safe_substr($text, 0, $limit);
    $cut = preg_replace('/\s+\S*$/u', '', $cut);
    return rtrim($cut, " .،:-") . '...';
}

function so_build_event_narrative_line($event) {
    $title = so_narrative_clean_title((string)($event['title'] ?? ''));
    $wd = [];
    if (!empty($event['war_data']) && is_string($event['war_data'])) $wd = json_decode($event['war_data'], true) ?: [];
    $p = is_array($wd['5w1h'] ?? null) ? $wd['5w1h'] : [];
    $who = trim((string)($p['who_primary'] ?? ($event['actor_v2'] ?? '')));
    $what = trim((string)($p['what_type'] ?? ''));
    $what_class = trim((string)($p['what_class'] ?? ''));
    $where = trim((string)($p['where_event'] ?? ($p['where_summary'] ?? '')));
    if ($what_class === 'statement') {
        if (strpos($who, 'كتائب القسام') !== false) return so_narrative_limit('كتائب القسام (حماس): ' . $title, 175);
        if (strpos($who, 'خاتم الأنبياء') !== false || strpos($who, 'الحرس الثوري') !== false) return so_narrative_limit('مقر خاتم الأنبياء / الحرس الثوري الإيراني: ' . $title, 175);
        if (strpos($who, 'حزب الله') !== false) return so_narrative_limit('المقاومة الإسلامية (حزب الله): ' . $title, 175);
        return so_narrative_limit(($who !== '' && $who !== 'غير محدد' ? $who . ': ' : '') . $title, 175);
    }
    if ($what_class === 'alert') return so_narrative_limit('إنذار ميداني في ' . ($where ?: 'المنطقة المحددة') . ': ' . $title, 175);
    if ($what_class === 'report') return so_narrative_limit($title, 175);
    if ($what !== '' && $what !== 'حدث عام' && $where !== '' && $where !== 'غير محدد' && $who !== '' && $who !== 'غير محدد') return so_narrative_limit($who . ' نفّذت ' . $what . ' في ' . $where, 175);
    return so_narrative_limit($title, 175);
}

function so_build_actor_confidence($title, $region, $actor) {
    $lower = mb_strtolower((string)$title);
    $primary = so_normalize_actor_label((string)$actor);
    $source = 'inferred';
    $confidence = 78;
    $nature = so_detect_verification_nature($title);

    if ($primary === '' || sod_is_unknown_actor_label($primary) || sod_is_media_source_actor($primary)) {
        $primary = sod_infer_actor_strict($title, '', (string)$region, '', '');
        $source = 'context';
        $confidence = 72;
    }

    if (preg_match('/^(.*?):/u', (string)$title, $m)) {
        $speaker = trim((string)$m[1]);
        if ($speaker !== '' && !sod_is_media_source_actor($speaker) && mb_strlen($speaker) <= 60) {
            $primary = $speaker;
            $source = 'explicit';
            $confidence = 96;
        }
    }

    if (preg_match('/(حزب الله|المقاومة الإسلامية|جيش العدو الإسرائيلي|الحرس الثوري|الخارجية الإيرانية|البيت الأبيض|دونالد ترامب|ترمب|الرئيس اللبناني|وزارة الخارجية|النائب|الحكومة الإسرائيلية)/ui', $lower)) {
        $source = 'explicit';
        $confidence = max($confidence, 93);
    }
    if (preg_match('/(صفارات الإنذار|انذار احمر|تسوفار|رصد صواريخ|صلية صاروخية|إطلاق صواريخ|صاروخ مضاد للدروع|إصابة دبابة|اشتباك|كمين|طائرة مسيّرة|غارة|قصف)/ui', $lower)) {
        $source = $source === 'explicit' ? 'explicit' : 'operational_inference';
        $confidence = max($confidence, 88);
    }
    if ($primary === 'محور المقاومة (استنتاج)') {
        $source = 'context';
        $confidence = min($confidence, 74);
    }
    if ($primary === 'المقاومة الإسلامية (حزب الله)' && preg_match('/(صفد|كريات شمونة|الجليل|بنت جبيل|الجنوب|لبنان|من لبنان)/ui', $lower)) {
        $confidence = max($confidence, 91);
    }
    if ($primary === 'الفصائل الفلسطينية' && preg_match('/(غزة|الغلاف|سديروت|عسقلان|حماس|القسام)/ui', $lower)) {
        $confidence = max($confidence, 91);
    }
    if ($primary === 'جيش العدو الإسرائيلي' && preg_match('/(غارة|قصف|استهداف|عدوان|طيران حربي|مسيرة إسرائيلية)/ui', $lower)) {
        $confidence = max($confidence, 92);
    }

    $label = $confidence >= 90 ? 'مؤكد' : ($confidence >= 75 ? 'مرجّح' : 'استنتاج');
    return [
        'primary' => $primary,
        'secondary' => '',
        'source' => $source,
        'confidence' => (int)$confidence,
        'label' => $label,
        'nature' => $nature,
    ];
}

// ==========================================================================
// دالة الإسناد الاحترافي — Attribution Engine (Rules v2)
// ==========================================================================
function so_extract_actor_attribution(string $text): array {
    $result = ['name'=>null,'raw'=>null,'status'=>'unattributed','confidence'=>0.0,'evidence'=>[]];
    $lower  = mb_strtolower(trim($text));

    // ── قواعد فلسطينية/استيطانية صريحة ───────────────────────────────────
    if (preg_match('/(من قبل فلسطيني|فلسطينيون|فلسطينيين|فلسطيني\b|شاب فلسطيني|مقاوم فلسطيني)/ui', $lower)) {
        return ['name'=>'فلسطينيون','raw'=>'فلسطيني','status'=>'confirmed','confidence'=>0.94,'evidence'=>['فلسطيني']];
    }
    if (preg_match('/(مستوطن|مستوطنين|بؤرة استيطانية)/ui', $lower) && preg_match('/(الضفة الغربية|طوباس|تياسير|حزما|جنين|نابلس|الخليل|رام الله)/ui', $lower)) {
        return ['name'=>'فلسطينيون','raw'=>'مستوطن/الضفة الغربية','status'=>'inferred','confidence'=>0.78,'evidence'=>['مستوطن','الضفة الغربية']];
    }

    

    // ── جدول توحيد الأسماء ──────────────────────────────────────────────────
    $PERSON_TO_ACTOR = [
        'نتنياهو'=>'جيش العدو الإسرائيلي','بن غفير'=>'جيش العدو الإسرائيلي',
        'غالانت'=>'جيش العدو الإسرائيلي','كوهين'=>'جيش العدو الإسرائيلي',
        'ترامب'=>'الولايات المتحدة','ترمب'=>'الولايات المتحدة',
        'جي دي فانس'=>'الولايات المتحدة','فانس'=>'الولايات المتحدة',
        'ستيف ويتكوف'=>'الولايات المتحدة','ويتكوف'=>'الولايات المتحدة',
        'بلينكن'=>'الولايات المتحدة','البيت الأبيض'=>'الولايات المتحدة',
        'خامنئي'=>'إيران','بزشكيان'=>'إيران','أمير عبداللهيان'=>'إيران',
        'عراقجي'=>'إيران','قاليباف'=>'إيران',
        'السيسي'=>'مصر','الملك عبدالله'=>'الأردن',
        'روبرت بيب'=>'الولايات المتحدة',
    ];

    // ── قرائن مؤكدة (confirmed) ─────────────────────────────────────────────
    // ملاحظة حرجة: لا تُنسب الأحداث الدبلوماسية/السياسية لإسرائيل أبداً
    // فقط الأحداث العسكرية الحركية الصريحة تُنسب لإسرائيل
    $is_diplomatic_political = preg_match('/(مفاوضات|محادثات|وفد|اجتماع|لقاء|قمة|مؤتمر|تصريح|قال|أكد|صرح|أعلن|أفاد|نقل عن|بحسب|وفق|ذكر|كشف|شجب|استنكر|أدان|رحب|حث|دعا|طالب|وزارة الخارجية|الرئيس|رئيس الوزراء|الأمم المتحدة|الاتحاد الأوروبي|جامعة الدول العربية|بيان سياسي|تقرير إعلامي|وسائل إعلام|صحيفة|قناة|إذاعة|تحليل|رويترز|غارديان|نيويورك تايمز|وول ستريت جورنال|أكسيوس|بوليتيكو|اقتصاد|نفط|غاز|طاقة|أسعار|سوق|تجارة|استثمار|بنك|صندوق|عملة|تضخم|مالية)/ui', $lower);
    
    $CONFIRMED = [
        'جيش العدو الإسرائيلي' => [
            // أفعال عسكرية صريحة فقط - لا تشمل التصريحات أو الأخبار الدبلوماسية
            'الجيش الإسرائيلي','جيش الاحتلال','قصف إسرائيلي',
            'قصف اسرائيلي','غارة إسرائيلية','غارة اسرائيلية','عدوان إسرائيلي',
            'عدوان اسرائيلي','سلاح الجو الإسرائيلي','مقاتلات الاحتلال',
            'طيران الاحتلال','مدفعية الاحتلال','الدبابات الإسرائيلية',
            'المسيّرات الإسرائيلية','مسيّرة إسرائيلية','مسيرة إسرائيلية',
            'قوات الاحتلال','الاحتلال الإسرائيلي',
        ],
        'الولايات المتحدة' => [
            'الولايات المتحدة','الإدارة الأميركية','الإدارة الأمريكية',
            'واشنطن','أميركا','أمريكا','البيت الأبيض',
        ],
        'إيران' => [
            'إيران','طهران','الجمهورية الإسلامية',
            'وزارة الخارجية الإيرانية',
        ],
        'الحرس الثوري الإيراني' => [
            'الحرس الثوري','حرس الثورة','فيلق القدس','خاتم الأنبياء',
        ],
        'حزب الله' => ['حزب الله','المقاومة الإسلامية في لبنان','نصرالله'],
        'الجيش اللبناني' => ['الجيش اللبناني','قوى الأمن الداخلي'],
        'أنصار الله (الحوثيون)' => ['أنصار الله','الحوثي','يحيى سريع','القوات المسلحة اليمنية'],
        'كتائب القسام (حماس)' => ['كتائب القسام','أبو عبيدة','حركة حماس'],
    ];

    // ── قرائن استنتاجية (inferred) ──────────────────────────────────────────
    $INFERRED = [
        'جيش العدو الإسرائيلي' => [
            'الطيران المعادي','الطيران المسير المعادي','مسيّرة معادية',
            'مسيرة معادية','المعادي','المعادية','دبابة معادية','مدفعية معادية',
            'الاحتلال استهدف','قصف من مواقع الاحتلال','الاحتلال يقصف',
        ],
        'الولايات المتحدة' => [
            'القواعد الأميركية','القواعد الأمريكية',
            'قصف أميركي','هجوم على قاعدة أميركية',
        ],
    ];

    // ── ألفاظ المصادر والادعاء (claimed) ────────────────────────────────────
    $CLAIM_VERBS = ['أعلن','أعلنت','قال','قالت','صرح','صرحت','بحسب','وفق','وفقاً','أفادت','ذكرت','نقلت','أكد','أكدت','كشف','نفذنا','استهدفنا','نفذت','تبنّت'];

    // ── ألفاظ التنازع والشك (contested) ─────────────────────────────────────
    $CONTESTED = ['نفى','نفت','روايات متضاربة','تضارب','لم يتسن التأكد','غير مؤكد','يُعتقد','على الأرجح','ربما','قد يكون'];

    // ── 1. تحقق من التنازع أولاً ─────────────────────────────────────────────
    foreach ($CONTESTED as $term) {
        if (mb_strpos($lower, mb_strtolower($term)) !== false) {
            $result['status'] = 'contested'; $result['confidence'] = 0.40;
            $result['evidence'][] = $term;
        }
    }

    // ── 2. إسناد مؤكد (confirmed) ────────────────────────────────────────────
    // ملاحظة حرجة: لا تُطبَّق قواعد الإسناد لإسرائيل على الأحداث الدبلوماسية/السياسية
    foreach ($CONFIRMED as $actor => $patterns) {
        foreach ($patterns as $p) {
            if (mb_strpos($lower, mb_strtolower($p)) !== false) {
                // استثناء حرجة: إذا كان الفاعل إسرائيل والحدث دبلوماسي/سياسي، لا تُنسب له
                if ($actor === 'جيش العدو الإسرائيلي' && $is_diplomatic_political) {
                    continue; // تخطي هذا النمط لإسرائيل في الأحداث غير العسكرية
                }
                $result['name']   = $actor;
                $result['raw']    = $p;
                $result['status'] = ($result['status'] === 'contested') ? 'contested' : 'confirmed';
                $result['confidence'] = ($result['status'] === 'contested') ? 0.40 : 0.95;
                $result['evidence'][] = $p;
                return $result;
            }
        }
    }

    // ── 3. ربط الأشخاص بجهاتهم ──────────────────────────────────────────────
    // استثناء حرجة: لا تُنسب تصريحات المسؤولين الإسرائيليين للأحداث الدبلوماسية كـ "جيش العدو"
    foreach ($PERSON_TO_ACTOR as $person => $actor) {
        if (mb_strpos($lower, mb_strtolower($person)) !== false) {
            // إذا كان الشخص إسرائيلي والحدث دبلوماسي/سياسي، لا تُنسب للجيش
            if ($actor === 'جيش العدو الإسرائيلي' && $is_diplomatic_political) {
                // تعيين فاعل بديل أو تركه غير محسوم
                $result['name']       = 'فاعل غير محسوم';
                $result['raw']        = $person . ' (دبلوماسي/سياسي)';
                $result['status']     = 'inferred';
                $result['confidence'] = 0.60;
                $result['evidence'][] = $person;
                return $result;
            }
            $result['name']       = $actor;
            $result['raw']        = $person;
            $result['status']     = 'confirmed';
            $result['confidence'] = 0.93;
            $result['evidence'][] = $person;
            return $result;
        }
    }

    // ── 4. إسناد استنتاجي (inferred) ─────────────────────────────────────────
    // ملاحظة حرجة: لا تُطبَّق قواعد الإسناد الاستنتاجي لإسرائيل على الأحداث الدبلوماسية/السياسية
    foreach ($INFERRED as $actor => $patterns) {
        foreach ($patterns as $p) {
            if (mb_strpos($lower, mb_strtolower($p)) !== false) {
                // استثناء حرجة: إذا كان الفاعل إسرائيل والحدث دبلوماسي/سياسي، لا تُنسب له
                if ($actor === 'جيش العدو الإسرائيلي' && $is_diplomatic_political) {
                    continue; // تخطي هذا النمط لإسرائيل في الأحداث غير العسكرية
                }
                $result['name']       = $actor;
                $result['raw']        = $p;
                $result['status']     = 'inferred';
                $result['confidence'] = 0.75;
                $result['evidence'][] = $p;
                return $result;
            }
        }
    }

    // ── 5. إسناد منسوب (claimed) — فعل ادعاء موجود لكن لا فاعل محدد ─────────
    foreach ($CLAIM_VERBS as $verb) {
        if (mb_strpos($lower, mb_strtolower($verb)) !== false) {
            $result['status']     = 'claimed';
            $result['confidence'] = 0.65;
            $result['evidence'][] = $verb;
            break;
        }
    }

    return $result; // unattributed إذا لم يُطابَق شيء
}

// ترجمة حالة الإسناد إلى نص عربي
function so_attribution_label(string $status): string {
    return match($status) {
        'confirmed'    => 'مؤكد',
        'inferred'     => 'استنتاجي',
        'claimed'      => 'منسوب',
        'contested'    => 'متنازع عليه',
        'unattributed' => 'غير منسوب',
        default        => 'غير محدد',
    };
}

function so_attribution_icon(string $status): string {
    return match($status) {
        'confirmed'    => '✅',
        'inferred'     => '🔷',
        'claimed'      => '📣',
        'contested'    => '⚠️',
        'unattributed' => '🕳️',
        default        => '❓',
    };
}

/**
 * استخراج الموقع التفصيلي (بلدة/منطقة محددة) من عنوان الخبر
 * يُستخدم لبناء الهدف بصيغة "لبنان / مجدل سلم"
 */
function so_extract_specific_location(string $title): string {
    $lower = mb_strtolower($title, 'UTF-8');
    // نمط 1: "المناطق المتأثرة: مكان" أو "المنطقة المتأثرة: مكان"
    if (preg_match('/المناطق? المتأثر[ةه][:\s]+([^\n،.()]{3,30})/u', $title, $m)) {
        return trim($m[1]);
    }
    // نمط 2: "في بلدة/قرية/مدينة/منطقة X" / "في ضيعة X"
    if (preg_match('/في (?:بلدة|قرية|قضاء|ضيعة|محيط|حي|بلدية|مدينة|قرب|منطقة|أحياء)\s+([^\s،.()]{3,25})/u', $title, $m)) {
        return trim($m[1]);
    }
    // نمط 3: "استهداف X" / "سقوط قذيفة/صاروخ في X"
    if (preg_match('/(?:سقوط|استهداف|تدمير|قصف)\s+(?:قذيفة|صاروخ|مسيرة|آلية|مركبة|مبنى|منزل)\s+في\s+([^\s،.()]{3,25})/u', $title, $m)) {
        return trim($m[1]);
    }
    // نمط 4: "الجنوب" / "البقاع" / "الضاحية" ← مناطق لبنانية عامة
    $subregions = [
        'الجنوب'          => 'الجنوب',
        'جنوب لبنان'      => 'الجنوب',
        'الضاحية الجنوبية'=> 'الضاحية الجنوبية',
        'البقاع'          => 'البقاع',
        'بعلبك'           => 'البقاع (بعلبك)',
        'الهرمل'          => 'البقاع (الهرمل)',
        'صيدا'            => 'صيدا',
        'صور'             => 'صور',
        'النبطية'         => 'النبطية',
        'بنت جبيل'        => 'بنت جبيل',
        'مرجعيون'         => 'مرجعيون',
        'عيتا الشعب'      => 'عيتا الشعب',
        'بلدة شبعا'       => 'شبعا',
        'شبعا'            => 'شبعا',
        'يارون'           => 'يارون',
        'عيناثا'          => 'عيناثا',
        'ميس الجبل'       => 'ميس الجبل',
        'كفركلا'          => 'كفركلا',
        'مجدل سلم'        => 'مجدل سلم',
        'تبنين'           => 'تبنين',
        'علما الشعب'      => 'علما الشعب',
        'الناقورة'        => 'الناقورة',
        'معركة'           => 'معركة',
        'قانا'            => 'قانا',
        'حولا'            => 'حولا',
        'طيرحرفا'         => 'طيرحرفا',
        'الخيام'          => 'الخيام',
        'الطيبة'          => 'الطيبة',
        'شمع'             => 'شمع',
        'حلوسية'          => 'حلوسية',
        'جبيل'            => 'جبيل',
        'الشوف'           => 'الشوف',
        'عاليه'           => 'عاليه',
        'الكيلة'          => 'الكيلة',
        'المطلة'          => 'المطلة',
        'رميش'            => 'رميش',
