        'عرسال'           => 'عرسال',
        'ترمانين'         => 'ترمانين',
        'الرياق'          => 'البقاع (الرياق)',
    ];
    foreach ($subregions as $pattern => $label) {
        if (mb_stripos($lower, $pattern) !== false) return $label;
    }
    return '';
}

/**
 * بناء حقل الهدف الذكي من العنوان والبيانات المستخرجة
 * يدعم: اكتشاف المدنيين، الموقع التفصيلي، والهدف العسكري
 */
function so_build_smart_target(string $title, string $region, array $entity_targets, string $where_target): string {
    $lower = mb_strtolower($title, 'UTF-8');

    // 1. اكتشاف المدنيين كهدف رئيسي
    $is_civilian_target = preg_match('/(?:ارتقى|ارتقوا|استشهد|شهيد|شهداء|شهيدًا|شهيدة|ضحايا|ضحية|جرحى|جريح|مدني|مدنيون|مدنيين|أبناء|أهالي|عائلة|لقوا حتفهم|لقي حتفه)/ui', $title);
    $is_residential    = preg_match('/(?:منزل|مبنى سكني|حي سكني|تجمع|خيمة|مخيم|سوق شعبي|سيارة مدنية)/ui', $title);

    // 2. استخراج الموقع التفصيلي
    $specific_loc = so_extract_specific_location($title);

    // 3. بناء الهدف
    if ($is_civilian_target) {
        // حدد نوع الضحايا
        if (preg_match('/(?:طاقم|عنصر|مقاتل|مسلح|قائد|مسؤول)/ui', $title)) {
            $base_target = 'عناصر مسلحة';
        } else {
            $base_target = 'مدنيون';
        }
        if ($specific_loc) return $base_target . ' / ' . $specific_loc;
        if ($region && $region !== 'غير محدد') return $base_target . ' / ' . $region;
        return $base_target;
    }

    // 4. إذا وُجد هدف عسكري محدد + موقع تفصيلي
    if (!empty($entity_targets)) {
        $main_target = implode(', ', array_unique($entity_targets));
        if ($specific_loc) return $main_target . ' / ' . $specific_loc;
        return $main_target;
    }

    // 5. الهدف من 5W1H + موقع تفصيلي
    if ($specific_loc) {
        if ($region && $region !== 'غير محدد' && $region !== $specific_loc) {
            return $region . ' / ' . $specific_loc;
        }
        return $specific_loc;
    }

    // 6. الإسقاط الاحتياطي
    if ($where_target && $where_target !== 'غير محدد') return $where_target;
    if ($region && $region !== 'غير محدد') return $region;
    return 'غير محدد';
}

function so_get_regions_hierarchy_html($selected = '') {
    $hierarchy = [
        'ساحة غرب آسيا' => ['لبنان','الأراضي المحتلة (إسرائيل)','إيران','سوريا','العراق','اليمن','السعودية','الإمارات'],
        'ساحة المحيط الهادئ' => ['الولايات المتحدة','الصين','اليابان','كوريا الجنوبية','تايوان','أستراليا'],
        'ساحة الجبهة الشرقية للناتو' => ['روسيا','أوكرانيا','بولندا','رومانيا','ليتوانيا','لاتفيا','إستونيا'],
    ];
    $html = '';
    foreach ($hierarchy as $parent => $children) {
        $p_val = 'PARENT:' . $parent;
        $html .= "<option value='" . esc_attr($p_val) . "' style='font-weight:bold;color:#6fbf73;' " . selected($selected, $p_val, false) . ">🌍 " . esc_html($parent) . " (الكل)</option>";
        foreach ($children as $child) $html .= "<option value='" . esc_attr($child) . "' " . selected($selected, $child, false) . ">&nbsp;&nbsp;-- " . esc_html($child) . "</option>";
    }
    return $html;
}

