if (!class_exists('SO_Cache_Manager')) {
class SO_Cache_Manager {
    private static $instance = null;
    public static function get_instance() { if (self::$instance === null) self::$instance = new self(); return self::$instance; }
    public function get($key, $group = 'raw_data') {
        $found = false; $cache = wp_cache_get($key, $group, false, $found);
        if ($found) return $cache;
        return get_transient('so_cache_' . $group . '_' . md5($key));
    }
    public function set($key, $data, $group = 'raw_data', $expire = 60) {
        wp_cache_set($key, $data, $group, $expire);
        set_transient('so_cache_' . $group . '_' . md5($key), $data, $expire);
    }
    public function invalidate($group = null) {
        global $wpdb;
        $pattern = $group ? "_transient_so_cache_{$group}_%" : "_transient_so_cache_%";
        $wpdb->query($wpdb->prepare("DELETE FROM {$wpdb->options} WHERE option_name LIKE %s", $pattern));
    }

    public static function send_word_ajax_v2() {
        if (!current_user_can('manage_options') || !check_ajax_referer('so_exec_report_ajax', 'nonce', false)) {
            wp_send_json_error(['message' => 'غير مصرح'], 403, JSON_UNESCAPED_UNICODE | (defined('JSON_INVALID_UTF8_SUBSTITUTE') ? JSON_INVALID_UTF8_SUBSTITUTE : 0));
        }
        try {
            $report = self::get_or_build_report();
            $token = trim(get_option('so_tg_token', ''));
            $exec_chat = trim(get_option('so_exec_reports_chat_id', ''));
            $chats_str = $exec_chat !== '' ? $exec_chat : get_option('so_tg_chat', '');
            $chats = array_filter(array_map('trim', explode(',', $chats_str)));
            if (empty($token) || empty($chats)) {
                wp_send_json_error(['message' => 'بيانات تيليغرام غير مكتملة'], 400, JSON_UNESCAPED_UNICODE | (defined('JSON_INVALID_UTF8_SUBSTITUTE') ? JSON_INVALID_UTF8_SUBSTITUTE : 0));
            }
            $file = self::create_word_report_file($report);
            if (!$file || !file_exists($file)) {
                wp_send_json_error(['message' => 'تعذر إنشاء ملف Word'], 500, JSON_UNESCAPED_UNICODE | (defined('JSON_INVALID_UTF8_SUBSTITUTE') ? JSON_INVALID_UTF8_SUBSTITUTE : 0));
            }
            $name = 'beiruttime-executive-brief-' . gmdate('Ymd-His') . '.doc';
            $ok = true;
            $last_error = '';
            foreach ($chats as $chat_id) {
                $sent = self::telegram_send_local_document($token, $chat_id, $file, 'application/msword', $name, 'Beiruttime OSINT Executive Brief');
                if (empty($sent['ok'])) {
                    $ok = false;
                    $last_error = (string)($sent['message'] ?? 'فشل إرسال ملف Word');
                }
            }
            @unlink($file);
            if ($ok) {
                update_option('so_exec_last_report_time', time(), false);
                wp_send_json_success(['message' => 'تم إرسال ملف Word بنجاح'], 200, JSON_UNESCAPED_UNICODE | (defined('JSON_INVALID_UTF8_SUBSTITUTE') ? JSON_INVALID_UTF8_SUBSTITUTE : 0));
            }
            wp_send_json_error(['message' => $last_error !== '' ? $last_error : 'فشل إرسال ملف Word'], 500, JSON_UNESCAPED_UNICODE | (defined('JSON_INVALID_UTF8_SUBSTITUTE') ? JSON_INVALID_UTF8_SUBSTITUTE : 0));
        } catch (\Throwable $e) {
            wp_send_json_error(['message' => 'فشل إرسال ملف Word: ' . $e->getMessage()], 500, JSON_UNESCAPED_UNICODE | (defined('JSON_INVALID_UTF8_SUBSTITUTE') ? JSON_INVALID_UTF8_SUBSTITUTE : 0));
        }
    }

    public static function send_pdf_ajax_v2() {
        if (!current_user_can('manage_options') || !check_ajax_referer('so_exec_report_ajax', 'nonce', false)) {
            wp_send_json_error(['message' => 'غير مصرح'], 403, JSON_UNESCAPED_UNICODE | (defined('JSON_INVALID_UTF8_SUBSTITUTE') ? JSON_INVALID_UTF8_SUBSTITUTE : 0));
        }
        try {
