                wp_send_json_error(['message' => 'بيانات تيليغرام غير مكتملة'], 400, JSON_UNESCAPED_UNICODE | (defined('JSON_INVALID_UTF8_SUBSTITUTE') ? JSON_INVALID_UTF8_SUBSTITUTE : 0));
