                if (empty($sent['ok'])) {
                    $ok = false;
                    $last_error = (string)($sent['message'] ?? 'فشل إرسال ملف PDF');
                }
            }
            @unlink($file);
            if ($ok) {
                update_option('so_exec_last_report_time', time(), false);
