if (!class_exists('SO_DB_Manager')) {
class SO_DB_Manager {
    public static function create_tables() {
        global $wpdb; $collate = $wpdb->get_charset_collate();
        require_once ABSPATH . 'wp-admin/includes/upgrade.php';
        dbDelta("CREATE TABLE {$wpdb->prefix}so_news_events (
            id bigint(20) NOT NULL AUTO_INCREMENT, hash_id varchar(64) NOT NULL, title text NOT NULL,
            link varchar(500) NOT NULL, source_name varchar(100) NOT NULL, source_color varchar(20),
            intel_type varchar(100), tactical_level varchar(50) DEFAULT 'تكتيكي', war_data text NULL,
            region varchar(100), agency_loc varchar(100), score int(11) DEFAULT 0, event_timestamp bigint(20) NOT NULL,
            status varchar(20) DEFAULT 'published', image_url varchar(500), actor_v2 varchar(100),
            weapon_v2 varchar(100), target_v2 varchar(100), sentiment_score float DEFAULT 0, field_data text NULL,
            llm_verified tinyint(1) DEFAULT 0, title_fingerprint varchar(64) DEFAULT NULL,
            PRIMARY KEY (id), UNIQUE KEY hash_id (hash_id), KEY event_timestamp (event_timestamp),
            KEY region_time (region, event_timestamp), KEY title_fp (title_fingerprint),
            FULLTEXT KEY idx_search (title, war_data)
        ) $collate;");
        dbDelta("CREATE TABLE {$wpdb->prefix}so_sent_alerts (
            id bigint(20) NOT NULL AUTO_INCREMENT, news_hash varchar(64) NOT NULL, source_name varchar(255) NOT NULL,
            sent_time datetime DEFAULT CURRENT_TIMESTAMP, PRIMARY KEY (id), UNIQUE KEY news_hash (news_hash)
        ) $collate;");
        dbDelta("CREATE TABLE {$wpdb->prefix}so_actor_memory (
            id bigint(20) NOT NULL AUTO_INCREMENT, actor_name varchar(100) NOT NULL, event_id bigint(20) NOT NULL DEFAULT 0,
            action varchar(100), weapon varchar(100), target varchar(100), intent_level int, threat_score int,
            timestamp bigint(20) NOT NULL, PRIMARY KEY (id), KEY actor_name (actor_name), KEY timestamp (timestamp)
        ) $collate;");
        dbDelta("CREATE TABLE {$wpdb->prefix}so_predictions (
            id bigint(20) NOT NULL AUTO_INCREMENT, prediction_hash varchar(64) NOT NULL, region varchar(100),
            actor varchar(100), event_type varchar(100), probability float, confidence float, predicted_time bigint(20),
            created_at bigint(20) NOT NULL, status varchar(20) DEFAULT 'pending', PRIMARY KEY (id)
        ) $collate;");
        dbDelta("CREATE TABLE {$wpdb->prefix}so_dict_actors (
            id bigint(20) NOT NULL AUTO_INCREMENT, actor_id varchar(50) NOT NULL, name_ar varchar(100) NOT NULL,
            threat_weight float NOT NULL DEFAULT 0.5, keywords text NOT NULL, base_threat int(11) DEFAULT 0,
            PRIMARY KEY (id), UNIQUE KEY actor_id (actor_id)
        ) $collate;");
        dbDelta("CREATE TABLE {$wpdb->prefix}so_dict_weapons (
            id bigint(20) NOT NULL AUTO_INCREMENT, weapon_id varchar(50) NOT NULL, name_ar varchar(100) NOT NULL,
            impact_score int(11) NOT NULL DEFAULT 30, keywords text NOT NULL,
            PRIMARY KEY (id), UNIQUE KEY weapon_id (weapon_id)
        ) $collate;");
        dbDelta("CREATE TABLE {$wpdb->prefix}so_manual_learning (
            id bigint(20) NOT NULL AUTO_INCREMENT, title_fingerprint varchar(64) NOT NULL,
            source_name varchar(100) NOT NULL DEFAULT '', corrected_title text NULL, corrected_actor varchar(150) NULL,
            corrected_region varchar(150) NULL, corrected_intel_type varchar(150) NULL, corrected_level varchar(100) NULL,
            corrected_score int(11) DEFAULT NULL, corrected_weapon varchar(150) NULL, corrected_target varchar(150) NULL,
            corrected_war_data longtext NULL, learn_weight int(11) NOT NULL DEFAULT 1,
            created_at datetime DEFAULT CURRENT_TIMESTAMP, updated_at datetime DEFAULT CURRENT_TIMESTAMP,
            PRIMARY KEY (id), UNIQUE KEY uniq_rule (title_fingerprint, source_name)
        ) $collate;");
        update_option('so_db_version', SO_VERSION);
        self::ensure_runtime_defaults();
    }

    public static function ensure_runtime_defaults() {
        if (!get_option('so_external_api_key')) update_option('so_external_api_key', so_generate_api_key(), false);
        if (!get_option('so_editorial_scope_profile')) update_option('so_editorial_scope_profile', 'global_conflict_disasters_west_asia', false);
        if (!get_option('so_focus_regions')) update_option('so_focus_regions', ['غرب آسيا','ساحات التوتر العالمية','فلسطين','الأراضي المحتلة (إسرائيل)','لبنان','إيران','سوريا','العراق','اليمن'], false);
        if (get_option('so_popup_enabled', null) === null) update_option('so_popup_enabled', 1, false);
        if (!get_option('so_popup_threshold')) update_option('so_popup_threshold', 170, false);
        if (!get_option('so_popup_recent_minutes')) update_option('so_popup_recent_minutes', 20, false);
        if (!get_option('so_popup_telegram_link')) update_option('so_popup_telegram_link', SO_TELEGRAM_LINK, false);
        if (get_option('so_exec_reports_enabled', null) === null) update_option('so_exec_reports_enabled', 1, false);
        if (!get_option('so_exec_reports_frequency')) update_option('so_exec_reports_frequency', 'every_six_hours', false);
        if (!get_option('so_exec_reports_window_hours')) update_option('so_exec_reports_window_hours', 72, false);
        if (!get_option('so_exec_reports_critical_threshold')) update_option('so_exec_reports_critical_threshold', 140, false);
        if (!get_option('so_exec_reports_footer')) update_option('so_exec_reports_footer', 'Beiruttime OSINT Executive Brief', false);
        if (get_option('so_fetch_latest_only', null) === null) update_option('so_fetch_latest_only', 1, false);
        if (!get_option('so_exec_reports_chat_id')) update_option('so_exec_reports_chat_id', '', false);
        if (!get_option('so_diag_events')) update_option('so_diag_events', [], false);
        if (!get_option('so_last_sync_summary')) update_option('so_last_sync_summary', [], false);
        // قالب تيليغرام
        if (get_option('so_tg_template_fields', null) === null) {
            $default_tpl = ['classification'=>true,'level'=>true,'actor'=>true,'region'=>true,'score'=>true,'weapon'=>true,'target'=>true,'verified'=>true,'link'=>true,'image'=>true,'threat_score'=>true,'risk_level'=>true,'osint_type'=>true,'hybrid_layers'=>true,'primary_actor'=>true];
            update_option('so_tg_template_fields', wp_json_encode($default_tpl), false);
        }
        if (get_option('so_tg_min_score', null) === null) update_option('so_tg_min_score', 0, false);
        if (get_option('so_tg_header_text', null) === null) update_option('so_tg_header_text', '', false);
        if (get_option('so_tg_blocked_types', null) === null) update_option('so_tg_blocked_types', '', false);
        if (get_option('so_tg_force_martyrdom', null) === null) update_option('so_tg_force_martyrdom', 1, false);
        if (get_option('so_tg_channel_link', null) === null) update_option('so_tg_channel_link', '', false);
        if (get_option('so_tg_wa_channel', null) === null) update_option('so_tg_wa_channel', '', false);
        if (get_option('so_tg_footer_notes', null) === null) update_option('so_tg_footer_notes', '', false);
    }

