// ==========================================================================
// 5. محرك الذكاء الاصطناعي — LLM AI Engine (OpenAI)
// ==========================================================================
if (!class_exists('SO_LLM_Engine')) {
class SO_LLM_Engine {
    private static function get_model() { return apply_filters('so_llm_model', 'gpt-4o-mini'); }
    private static function normalize_result($payload) {
        if (!is_array($payload)) return null;
        $payload['is_real_action'] = !empty($payload['is_real_action']);
        $payload['confidence'] = max(0, min(100, intval($payload['confidence'] ?? 0)));
        $payload['reason'] = sanitize_text_field($payload['reason'] ?? '');
        return $payload;
    }
    public static function verify_critical_event($text) {
        $api_key = get_option('so_llm_api_key', '');
        if (empty($api_key)) return null;
        $prompt = "أنت محلل استخباراتي. قم بتحليل الخبر التالي بدقة. هل هو حدث ميداني حقيقي (مثل غارة، قصف، استهداف، اغتيال) أم مجرد تصريح سياسي أو تهديد إعلامي؟ أجب بصيغة JSON فقط: {\"is_real_action\": true/false, \"confidence\": 90, \"reason\": \"السبب باختصار\"}. الخبر: " . wp_strip_all_tags($text);
        $response = so_safe_remote_post('https://api.openai.com/v1/chat/completions', [
            'headers' => ['Authorization'=>'Bearer '.$api_key,'Content-Type'=>'application/json'],
            'body' => wp_json_encode(['model'=>self::get_model(),'messages'=>[['role'=>'user','content'=>$prompt]],'temperature'=>0.1,'response_format'=>['type'=>'json_object']]),
            'timeout' => 10
        ]);
        if (!is_wp_error($response)) {
            $body = json_decode(wp_remote_retrieve_body($response), true);
            if (isset($body['choices'][0]['message']['content'])) return self::normalize_result(json_decode($body['choices'][0]['message']['content'], true));
        }
        return null;
    }
    public static function generate_intel_brief($events_data) {
        $api_key = get_option('so_llm_api_key', '');
        if (empty($api_key) || !get_option('so_llm_brief_enabled', 0)) return null;
        $summary_text = '';
        foreach (array_slice($events_data, 0, 10) as $ev) $summary_text .= '- [' . ($ev['score'] ?? 0) . '] ' . ($ev['title'] ?? '') . ' (' . ($ev['region'] ?? '') . ")\n";
        $prompt = "أنت محلل استخباراتي استراتيجي. بناءً على الأحداث التالية من آخر 24 ساعة، قدّم موجزاً تحليلياً موجزاً باللغة العربية (لا تتجاوز 150 كلمة)، يشمل: 1) التطور الميداني الرئيسي 2) أبرز الفاعلين 3) توجه الصراع (تصاعد/انفراج) 4) توصية استخباراتية واحدة.\n\nالأحداث:\n" . $summary_text;
        $response = so_safe_remote_post('https://api.openai.com/v1/chat/completions', [
            'headers' => ['Authorization'=>'Bearer '.$api_key,'Content-Type'=>'application/json'],
            'body' => wp_json_encode(['model'=>self::get_model(),'messages'=>[['role'=>'user','content'=>$prompt]],'temperature'=>0.3,'max_tokens'=>400]),
            'timeout' => 20
        ]);
        if (!is_wp_error($response)) {
            $body = json_decode(wp_remote_retrieve_body($response), true);
            if (isset($body['choices'][0]['message']['content'])) return sanitize_textarea_field($body['choices'][0]['message']['content']);
        }
        return null;
    }
}
}

// ==========================================================================
// 6. جلب البيانات الميدانية — Field Data (Weather, Earthquakes)
// ==========================================================================
if (!class_exists('SO_Field_Data')) {
class SO_Field_Data {
    public static function fetch_earthquakes($days = 1) {
        $url = 'https://earthquake.usgs.gov/fdsnws/event/1/query?format=geojson&minmagnitude=4.0&limit=20&starttime=' . gmdate('Y-m-d', strtotime("-$days days"));
        $response = so_safe_remote_get($url, ['timeout' => 5]);
        if (is_wp_error($response)) return [];
        $data = json_decode(wp_remote_retrieve_body($response), true);
        $earthquakes = [];
        if ($data && isset($data['features'])) foreach ($data['features'] as $feature) $earthquakes[] = ['magnitude'=>$feature['properties']['mag'],'place'=>$feature['properties']['place'],'time'=>$feature['properties']['time']/1000,'lat'=>$feature['geometry']['coordinates'][1],'lon'=>$feature['geometry']['coordinates'][0]];
        return $earthquakes;
    }
    public static function fetch_weather($lat, $lon) {
        $api_key = get_option('so_openweather_api_key', '');
        if (empty($api_key)) return null;
        $url = "https://api.openweathermap.org/data/2.5/weather?lat=$lat&lon=$lon&appid=$api_key&units=metric";
        $response = so_safe_remote_get($url, ['timeout' => 5]);
        if (is_wp_error($response)) return null;
        $data = json_decode(wp_remote_retrieve_body($response), true);
        if (!$data || $data['cod'] != 200) return null;
        return ['temp'=>$data['main']['temp'],'description'=>$data['weather'][0]['description'],'wind_speed'=>$data['wind']['speed']];
    }
}
}

// ==========================================================================
// 7. جلب البيانات — Data Fetcher (RSS, Telegram, X)
// ==========================================================================
if (!class_exists('SO_Data_Fetcher')) {
class SO_Data_Fetcher {
    public static function get_all_raw_data($fresh_only = false) {
        $cache = SO_Cache_Manager::get_instance();
        if (!$fresh_only && ($cached = $cache->get('all_raw_data_v13', 'raw_data')) !== false) return $cached;
        $data = [];
        foreach (get_option('so_sources', []) as $s) if (!empty($s['url'])) $data = array_merge($data, self::fetch_rss($s));
        foreach (get_option('so_tg_sources', []) as $s) if (!empty($s['username'])) $data = array_merge($data, self::fetch_telegram($s));
        foreach (get_option('so_x_sources', []) as $s) if (!empty($s['username'])) $data = array_merge($data, self::fetch_x($s));
        $data = self::deduplicate_items($data);
        $data = self::relax_latest_per_source($data);
        usort($data, function($a, $b) { return ((int)($b['date']??0)) <=> ((int)($a['date']??0)); });
        $cache->set('all_raw_data_v13', $data, 'raw_data', 45);
        return $data;
    }

    private static function relax_latest_per_source($items) {
        $by_source = [];
        foreach ($items as $item) { $source = trim((string)($item['source']??'')); if ($source === '') $source = 'unknown'; $by_source[$source][] = $item; }
        $out = [];
        foreach ($by_source as $source_items) { usort($source_items, function($a,$b){ return ((int)($b['date']??0)) <=> ((int)($a['date']??0)); }); $out = array_merge($out, array_slice($source_items, 0, 3)); }
        return $out;
    }

    private static function deduplicate_items($items) {
        $seen = []; $out = [];
        foreach ($items as $item) {
            $title = mb_strtolower(so_clean_text((string)($item['title']??'')));
            if ($title === '') continue;
            $source = trim((string)($item['source']??'unknown'));
            $date_bucket = gmdate('Y-m-d H', (int)($item['date']??time()));
            $key = md5($source.'|'.$title.'|'.$date_bucket);
            if (isset($seen[$key])) continue;
            $seen[$key] = 1; $out[] = $item;
        }
        return $out;
    }

    private static function fetch_rss($source) {
        so_diag_record('RSS', $source['name']??'', 'attempt', 0, '', '', '');
        $response = so_safe_remote_get($source['url'], ['timeout'=>10,'redirection'=>4,'headers'=>['Accept-Language'=>'ar,en-US;q=0.9,en;q=0.8','Cache-Control'=>'no-cache']]);
        if (is_wp_error($response)) { so_diag_record('RSS', $source['name']??'', 'error', 0, '', $response->get_error_message(), ''); return []; }
        $http = wp_remote_retrieve_response_code($response);
        $body = (string)wp_remote_retrieve_body($response);
        $items = []; libxml_use_internal_errors(true);
        $xml = simplexml_load_string($body);
        if ($xml && isset($xml->channel->item)) {
            foreach ($xml->channel->item as $item) {
                $item_date = strtotime((string)$item->pubDate) ?: time();
                $clean_title = so_clean_text((string)$item->title);
                $image_url = '';
                if (isset($item->enclosure)) { $attrs = $item->enclosure->attributes(); if (!empty($attrs['url'])) $image_url = so_normalize_remote_media_url((string)$attrs['url']); }
                if (!$image_url) {
                    $ns = $item->getNamespaces(true);
                    if (!empty($ns['media'])) { $media = $item->children($ns['media']); if (!empty($media->content)) { $attrs = $media->content->attributes(); if (!empty($attrs['url'])) $image_url = so_normalize_remote_media_url((string)$attrs['url']); } }
                }
                $candidate = ['title'=>$clean_title,'link'=>so_normalize_event_link((string)$item->link),'source'=>$source['name'],'color'=>$source['color'],'date'=>$item_date,'agency_loc'=>$source['location'],'image_url'=>$image_url];
                if (!so_should_publish_raw_item($candidate)) continue;
                $items[] = $candidate;
                if (count($items) >= so_source_items_limit()) break;
            }
        }
        if (empty($items) && $body !== '' && $http === 200) { $items = so_extract_rss_items_fallback($body, $source); if (!empty($items)) { so_diag_record('RSS', $source['name']??'', 'success', count($items), (string)$http, 'نجح fallback parser', $items[0]['title']??''); return array_slice($items, 0, so_source_items_limit()); } }
        if (empty($items)) { so_diag_record('RSS', $source['name']??'', 'empty', 0, (string)$http, 'لا توجد عناصر مطابقة', ''); return []; }
        so_diag_record('RSS', $source['name']??'', 'success', count(array_slice($items,0,so_source_items_limit())), (string)$http, '', $items[0]['title']??'');
        return array_slice($items, 0, so_source_items_limit());
    }

    private static function fetch_telegram($source) {
        $username = trim((string)($source['username']??'')); if ($username === '') return [];
        so_diag_record('TELEGRAM', $source['name']??'', 'attempt', 0, '', '', '');
        $url = 'https://t.me/s/' . $username;
        $response = so_safe_remote_get($url, ['timeout'=>14,'redirection'=>4]);
        if (is_wp_error($response)) { so_diag_record('TELEGRAM', $source['name']??'', 'error', 0, '', $response->get_error_message(), ''); return []; }
        $http = wp_remote_retrieve_response_code($response);
        if ($http != 200) { so_diag_record('TELEGRAM', $source['name']??'', 'error', 0, (string)$http, 'HTTP غير ناجح', ''); return []; }
        $html = (string)wp_remote_retrieve_body($response);
        $messages = [];
        if (!preg_match_all('/<div class="tgme_widget_message[\s\S]*?<time datetime="([^"]+)"[\s\S]*?<\/time>[\s\S]*?<\/div>\s*<\/div>/i', $html, $matches)) {
            so_diag_record('TELEGRAM', $source['name']??'', 'empty', 0, (string)$http, 'لم يتم العثور على كتل رسائل', ''); return [];
        }
        $chunks = $matches[0] ?? [];
        for ($i = count($chunks)-1; $i >= 0; $i--) {
            $chunk = $chunks[$i];
            $msg_time = 0;
            if (preg_match('/<time datetime="([^"]+)"/i', $chunk, $tm)) $msg_time = strtotime($tm[1]) ?: time();
            $msg_html = '';
            if (preg_match('/<div class="tgme_widget_message_text[^>]*>([\s\S]*?)<\/div>/i', $chunk, $text_m)) $msg_html = $text_m[1];
            elseif (preg_match('/<div class="tgme_widget_message_caption[^>]*>([\s\S]*?)<\/div>/i', $chunk, $cap_m)) $msg_html = $cap_m[1];
            $msg_text = so_clean_text(wp_strip_all_tags(str_replace(['<br>','<br/>','<br />','</div>','</p>'], ' ', $msg_html)));
            if ($msg_text === '' && preg_match('/aria-label="([^"]+)"/i', $chunk, $alt_m)) $msg_text = so_clean_text($alt_m[1]);
            $candidate = ['title'=>$msg_text,'link'=>so_extract_telegram_message_link($username,$chunk),'source'=>$source['name'],'color'=>$source['color'],'date'=>$msg_time,'agency_loc'=>$source['location'],'image_url'=>so_extract_telegram_media_url($chunk)];
            if (!so_should_publish_raw_item($candidate)) continue;
            $messages[] = $candidate;
            if (count($messages) >= so_source_items_limit()) break;
        }
        if (empty($messages)) { so_diag_record('TELEGRAM', $source['name']??'', 'empty', 0, (string)$http, 'لا توجد رسائل مطابقة بعد الفلترة', ''); return []; }
        so_diag_record('TELEGRAM', $source['name']??'', 'success', count(array_slice($messages,0,so_source_items_limit())), (string)$http, '', $messages[0]['title']??'');
        return array_slice($messages, 0, so_source_items_limit());
    }

    private static function fetch_x($source) {
        $username = trim((string)($source['username']??'')); if ($username === '') return [];
        so_diag_record('X', $source['name']??'', 'attempt', 0, '', '', '');
        $token = trim((string)get_option('so_twitter_bearer_token', ''));
        if (!empty($token)) {
            $headers = ['Authorization'=>'Bearer '.$token];
            $user_lookup = so_safe_remote_get('https://api.twitter.com/2/users/by/username/'.rawurlencode($username).'?user.fields=id', ['headers'=>$headers,'timeout'=>12]);
            if (!is_wp_error($user_lookup) && wp_remote_retrieve_response_code($user_lookup) === 200) {
                $user_body = json_decode(wp_remote_retrieve_body($user_lookup), true);
                $user_id = $user_body['data']['id'] ?? '';
                if ($user_id) {
                    $tweet_url = 'https://api.twitter.com/2/users/'.rawurlencode($user_id).'/tweets?max_results=5&exclude=replies,retweets&tweet.fields=created_at,attachments&expansions=attachments.media_keys&media.fields=url,preview_image_url,type';
                    $tweet_res = so_safe_remote_get($tweet_url, ['headers'=>$headers,'timeout'=>12]);
                    if (!is_wp_error($tweet_res) && wp_remote_retrieve_response_code($tweet_res) === 200) {
                        $body = json_decode(wp_remote_retrieve_body($tweet_res), true);
                        $items = self::map_x_tweets($body, $username, $source);
                        if (!empty($items)) { so_diag_record('X', $source['name']??'', 'success', count(array_slice($items,0,so_source_items_limit())), '200', 'نجح API', $items[0]['title']??''); return array_slice($items, 0, so_source_items_limit()); }
                    }
                }
            }
        }
        $instances = ['https://nitter.poast.org/'.rawurlencode($username).'/rss','https://nitter.privacyredirect.com/'.rawurlencode($username).'/rss','https://nitter.net/'.rawurlencode($username).'/rss','https://rsshub.app/twitter/user/'.rawurlencode($username)];
        foreach ($instances as $url) { $src = $source; $src['url'] = $url; $res = self::fetch_rss($src); if (!empty($res)) return array_slice($res, 0, 3); }
        return [];
    }

    private static function map_x_tweets($body, $username, $source) {
        $media_map = [];
        foreach (($body['includes']['media']??[]) as $media) if (!empty($media['media_key'])) $media_map[$media['media_key']] = $media;
        $items = [];
        foreach (($body['data']??[]) as $tweet) {
            $item_date = strtotime((string)($tweet['created_at']??'')) ?: time();
            if (time() - $item_date > 7200) continue;
            $media_urls = [];
            foreach (($tweet['attachments']['media_keys']??[]) as $media_key) { if (!empty($media_map[$media_key])) { $m = $media_map[$media_key]; $u = $m['url'] ?? ($m['preview_image_url']??''); if ($u) $media_urls[] = so_normalize_remote_media_url($u); } }
            $title = so_clean_text((string)($tweet['text']??''));
            if (!so_is_substantial_headline($title)) continue;
            $tweet_id = (string)($tweet['id']??'');
            $candidate = ['title'=>$title,'link'=>$tweet_id?'https://x.com/'.rawurlencode($username).'/status/'.$tweet_id:'https://x.com/'.rawurlencode($username),'source'=>$source['name'],'color'=>$source['color'],'date'=>$item_date,'agency_loc'=>$source['location'],'image_url'=>implode('|',array_values(array_unique(array_filter($media_urls))))];
            if (!so_should_publish_raw_item($candidate)) continue;
            $items[] = $candidate;
        }
        usort($items, function($a,$b){ return ((int)($b['date']??0)) <=> ((int)($a['date']??0)); });
        return $items;
    }
}
}

// ==========================================================================
// 8. محرك التحليل OSINT — OSINT Analysis Engine
// ==========================================================================
if (!class_exists('SO_OSINT_Engine')) {
class SO_OSINT_Engine {
    private static $weapon_impact_cache = null;
    private static $actor_threat_cache = null;

    public static function process_event($item) {
        $source = (string)($item['source'] ?? '');
        $raw_title = so_clean_text((string)($item['title'] ?? ''));
        $title = function_exists('bt_v24_strip_source_prefixes') ? bt_v24_strip_source_prefixes($raw_title, $source) : $raw_title;
        if (!$title) return null;
        $lower = str_replace('ـ', '', mb_strtolower($title)); // شطب التطويل العربي أولاً

        $analysis = so_bt_analyze_news_v2($title, $source);
        if (!empty($analysis['ignored'])) return null;

        // Advanced Analysis Core Engine V2 — المحرك الأساسي الآن
        $fusion = so_fusion_analysis($title);
        $fusion = so_confidence_filter($fusion);

        $bucket = so_detect_content_bucket($title, $source);
        $strategic_axis = (string)($fusion['type'] ?? $analysis['classification'] ?? 'عام');
        $region = (string)($fusion['region'] ?? $analysis['region'] ?? 'غير محدد');
        $actor = (string)($fusion['actor'] ?? $analysis['actor'] ?? 'فاعل سياقي غير مباشر');
        $actor_final_data = sod_resolve_actor_final($title, (string)($item['content'] ?? ''), $region);
        $actor = trim((string)($actor_final_data['actor_final'] ?? '')) ?: 'فاعل غير محسوم';
        if (function_exists('bt_v24_resolve_region')) {
            $region = bt_v24_resolve_region($title, $region, $actor, $source);
        }
        if (function_exists('bt_v24_resolve_actor')) {
            $actor = bt_v24_resolve_actor($title, $actor, $source, $region);
        }
        $pre_score = (int) so_advanced_score([
            'title' => $title,
            'actor' => $actor,
            'region' => $region,
            'type' => $strategic_axis,
            'actor_conf' => (int)($fusion['actor_conf'] ?? 0),
            'type_conf' => (int)($fusion['type_conf'] ?? 0),
            'region_conf' => (int)($fusion['region_conf'] ?? 0),
        ]);

        $is_rumor         = $bucket === 'rumor';
        $is_statement     = in_array($strategic_axis, ['سياسي','بيان','شجب/استنكار','إعلامي'], true) || $bucket === 'statement';
        $is_summary_report = $bucket === 'report' || $strategic_axis === 'إعلامي';
        $is_economic_news = $strategic_axis === 'اقتصادي/لوجستي' || preg_match('/(بورصة|أسواق|نفط|خام|ذهب|اقتصاد|عملة|دولار|يورو|تضخم|ميزانية|شحن|سفن|ناقلة|مضيق|إمدادات|تجارة|صادرات|واردات|ملاحة|تجاري|تضخم)/ui', $lower) === 1;

        $has_direct_kinetic = in_array($strategic_axis, ['عسكري/أمني','تكتيكي/ميداني'], true) || (!$is_statement && !$is_summary_report && !$is_rumor && preg_match('/(غارة|قصف|استهدف|استهدفت|استهداف|تفجير|انفجار|اغتيال|اقتحام|اشتباك|كمين|إطلاق صواريخ|مسيرات هجومية|استهدفنا|نفذنا|غارات|إطلاق|توغل|هجوم صاروخي|صلية صاروخية|الطيران المسير|طيران مسير|مسيرة|مسيرة معادية|ضربة جوية|ضربة صاروخية|سقوط شهيد|سقوط اصابات|اصابات بالغة|نفذت عملية|نفذ عملية|شنت عملية|استهدفت القواعد|مجاهدون نفذ)/ui', $lower) === 1);
        $has_alert_only    = $strategic_axis === 'رصد/إنذار' || (!$has_direct_kinetic && preg_match('/(صفارات الإنذار|صافرات الإنذار|انذار احمر|إنذار أحمر|قيادة الجبهة الداخلية|الإنذار المبكر|تسوفار|رصد إطلاق صواريخ|من المحتمل تفعيل الإنذارات|سقوط شضايا صاروخ اعتراضي)/ui', $lower) === 1);
        $is_rumor          = $is_rumor || preg_match('/(متداول|أنباء أولية|غير مؤكد|شائعة)/ui', $lower) === 1;

        $actor_conf = so_build_actor_confidence($title, $region, $actor);
        $verification_nature = $actor_conf['nature'];
        if (in_array($actor, ['جهة غير معلنة','فاعل قيد التقييم','غير محدد'], true) && !empty($actor_conf['primary']) && $actor_conf['primary'] !== 'فاعل قيد التقييم') {
            $actor = $actor_conf['primary'];
        }
        if (function_exists('bt_v24_resolve_actor')) {
            $actor = bt_v24_resolve_actor($title, $actor, $source, $region);
        }

        $entities = self::extract_entities($lower);
        $semantic = sod_classify_event_v3([
            'title' => $title,
            'content' => (string)($item['content'] ?? ''),
        ]);
        $semantic_target = trim((string)($semantic['target_v2'] ?? ''));
        $semantic_context = trim((string)($semantic['context_actor'] ?? ''));
        $semantic_intent = trim((string)($semantic['intent'] ?? ''));
        $semantic_weapon = trim((string)($semantic['weapon_v2'] ?? ''));

        $momentum = 1.0;
        $sentiment = ['u_score'=>0,'e_score'=>0,'d_score'=>0,'stance'=>'محايد'];
        $base_score = 12;
        $action_weights = ['اغتيال'=>85,'غارة'=>70,'إغارة'=>70,'غارات'=>75,'اقتحام'=>48,'تفجير'=>80,'نسف'=>78,'قصف'=>65,'استهداف'=>58,'مقتل'=>45,'تدمير'=>55,'إسقاط'=>52,'إطلاق نار'=>46,'عملية عسكرية/هجوم'=>55,'عدوان'=>60,'اعتراض'=>34,'تحليق استطلاعي'=>24,'بحث'=>16,'إخلاء'=>18,'أسر'=>55,'تغريدة'=>8,'تصريح سياسي / إعلامي'=>10,'تهديد سياسي / إعلامي'=>14,'دعم / تسليح غير مباشر'=>26,'تفعيل إنذار أمني'=>14,'اشتباك'=>52,'كمين'=>68,'توغل'=>58,'إصابة'=>24,'انفجار'=>50,'أزمة اقتصادية / تقلبات'=>32];
        foreach ($entities['actions'] as $act) $base_score += (int)($action_weights[$act] ?? 18);
        foreach ($entities['weapons'] as $weap) $base_score += min(85, max(0, self::get_weapon_impact($weap)));
        foreach ($entities['targets'] as $targ) {
            if (in_array($targ, ['قاعدة أميركية','قاعدة أمريكية','سفارة','بنية تحتية','مفاعل','منشأة نفطية','محطة كهرباء','تل أبيب','حيفا','صفد','مضيق هرمز','بوشهر','منظمة الطاقة الذرية'], true)) $base_score += 45;
            elseif (in_array($targ, ['مراكز القيادة','قيادي','شخصية بارزة','مستشفى','مستوطنة','مستوطنات','ثكنة','مصنع','مبنى'], true)) $base_score += 26;
            elseif ($targ === 'إعلامي / نفسي') $base_score += 8;
            else $base_score += 14;
        }
        $axis_weights = ['نووي'=>80,'عسكري/أمني'=>40,'اقتصادي/لوجستي'=>26,'سياسي'=>16,'بيان'=>12,'شجب/استنكار'=>8,'إعلامي'=>9,'رصد/إنذار'=>22,'تكتيكي/ميداني'=>18,'غير استخباراتي'=>-120];
        $base_score += (int)($axis_weights[$strategic_axis] ?? 16);
        $base_score += min(35, (int)self::get_actor_base_threat($actor));
        $casualties = preg_match_all('/(شهيد|شهداء|قتلى|جرحى|مصابين|مقتل|إصابة|مجزرة)/ui', $lower, $m);
        if ($casualties > 0) $base_score += min(70, 18 + ($casualties * 12));
        if ($has_alert_only) $base_score += 10;
        if ($is_statement) $base_score *= $is_economic_news ? 0.85 : 0.45;
        elseif ($is_summary_report) $base_score *= 0.72;
        elseif ($has_alert_only) $base_score *= 0.62;
        else $base_score *= 1.08;
        $raw_score = $base_score * $momentum;
        if ($is_statement && $strategic_axis !== 'نووي') $raw_score = min($raw_score, 38);
        if ($is_summary_report && !$has_direct_kinetic) $raw_score = min($raw_score, 55);
        if ($has_alert_only && !$has_direct_kinetic) $raw_score = min($raw_score, preg_match('/(صاروخ|صواريخ|مسيرة|مسيّرة|اعتراض)/ui', $lower) ? 120 : 85);
        if ($strategic_axis === 'نووي') $raw_score = min(220, max($raw_score, 140));
        else $raw_score = min($raw_score, 220);
        $calc_score = min(220, max(0, (int)round($raw_score)));
        if (function_exists('bt_v24_score_event')) {
            $final_score = bt_v24_score_event([
                'title' => $title,
                'strategic_axis' => $strategic_axis,
                'bucket' => $bucket,
                'pre_score' => $pre_score,
                'calc_score' => $calc_score,
                'region' => $region,
                'actor' => $actor,
                'source' => $source,
                'has_direct_kinetic' => $has_direct_kinetic,
                'has_alert_only' => $has_alert_only,
                'is_statement' => $is_statement,
                'is_summary_report' => $is_summary_report,
                'is_rumor' => $is_rumor,
                'is_economic_news' => $is_economic_news,
            ]);
        } elseif (in_array($strategic_axis, ['سياسي','بيان','شجب/استنكار','إعلامي'], true)) {
            $final_score = min(80, max($pre_score, (int)round(($pre_score * 0.8) + ($calc_score * 0.2))));
        } elseif ($strategic_axis === 'اقتصادي/لوجستي') {
            $final_score = min(120, max($pre_score, (int)round(($pre_score * 0.7) + ($calc_score * 0.3))));
        } else {
            $final_score = min(200, max($pre_score, (int)round(($pre_score * 0.65) + ($calc_score * 0.35))));
        }

        $llm_verified = 0;
        if ($final_score >= 170 && !$is_statement) {
            $ai_check = SO_LLM_Engine::verify_critical_event($title);
            if ($ai_check && isset($ai_check['is_real_action'])) {
                $llm_verified = 1;
                if (!$ai_check['is_real_action']) { $final_score = (int)round($final_score * 0.55); $is_statement = true; }
            }
        }

        $capability = count($entities['weapons']) > 0 || count($entities['targets']) > 0 ? 'HIGH' : 'LOW';
        $true_threat = (!$is_statement && ($has_direct_kinetic || $has_alert_only) && $capability === 'HIGH') ? 'REAL (تهديد حقيقي)' : 'POTENTIAL (تهديد محتمل/إعلامي)';
        $tactical_level = $final_score >= 220 ? 'استراتيجي' : ($final_score >= 90 ? 'عملياتي' : 'تكتيكي');
        $confidence = 50;

        $why = 'سياق عملياتي روتيني';
        if (preg_match('/(رد|انتقام|ثأر)/ui', $lower)) $why = 'رد انتقامي';
        elseif (preg_match('/(دفاع|تصد|إحباط|اعتراض)/ui', $lower)) $why = 'دفاعي / صد هجوم';
        elseif (preg_match('/(اغتيال|تصفية)/ui', $lower)) $why = 'عملية تصفية مركزة';
        elseif ($is_statement) $why = 'تصريح / رسالة إعلامية';

        $precision_5w1h = so_extract_precise_5w1h($title, $item, $actor, $region, $entities, ['is_statement'=>$is_statement,'is_summary_report'=>$is_summary_report,'has_alert_only'=>$has_alert_only,'has_direct_kinetic'=>$has_direct_kinetic,'is_rumor'=>$is_rumor], $why, $confidence);
        $truth_layer = $is_rumor ? 'rumor' : ($is_statement ? 'statement' : ($is_summary_report ? 'report' : ($has_direct_kinetic ? 'field_action' : ($has_alert_only ? 'defensive_alert' : 'general'))));

        // ── تحسين الفاعل النهائي: يُفضَّل نتيجة 5W1H إذا كانت أكثر دقة ────
        $p5_actor = trim((string)($precision_5w1h['who_primary'] ?? ''));
        $unknown_vals = ['فاعل قيد التقييم', 'غير محدد', '', 'جهة غير معلنة', 'عام/مجهول', 'فاعل غير محسوم', 'فاعل سياقي', 'فاعل سياقي غير مباشر'];
        if (!in_array($p5_actor, $unknown_vals, true) && in_array($actor, $unknown_vals, true)) {
            $actor = $p5_actor;
        }
        // ── استنتاج احتياطي: عملية حركية في لبنان بلا فاعل واضح = إسرائيل ──
        $actor = so_force_actor_not_unknown($actor, $title, $region, $item['source'] ?? '');
        $in_lebanese_theater = $region === 'لبنان' || preg_match('/(لبنان|بيروت|الضاحية|صور|النبطية|جنوب لبنان|الجنوب اللبناني|صيدا|طرابلس|بنت جبيل|ميس الجبل|عيتا الشعب|الناقورة|كفرشوبا|شبعا|الخيام|مرجعيون|تبنين|قانا|القليلة|شقرا|الجميجمة|البقاع|زحلة|بعلبك|الهرمل|حاصبيا|جزين)/ui', $lower);
        if (in_array($actor, $unknown_vals, true) && $has_direct_kinetic && $in_lebanese_theater) {
            $no_resistance = !preg_match('/(المقاومة|حزب الله|أنصار الله|القسام|الجهاد الإسلامي|سرايا القدس)/ui', $lower);
            if ($no_resistance) {
                $actor = 'جيش العدو الإسرائيلي';
                if ($region === 'غير محدد') $region = 'لبنان';
            }
        }

        $early_warning = sod_early_warning_ai($title, [
            'actor' => $actor,
            'region' => $region,
            'intel_type' => $strategic_axis,
        ]);

        // ── دمج تحليل طبقات الحرب المركبة ────
        $hybrid_analysis = [];
        if (class_exists('\\Beiruttime\\OSINT\\Services\\HybridWarfareEngine')) {
            $hybrid_engine = \Beiruttime\OSINT\Services\HybridWarfareEngine::instance();
            $event_data = [
                'title' => $title,
                'description' => (string)($item['content'] ?? ''),
                'source' => (string)($item['source'] ?? ''),
            ];
            $hybrid_analysis = $hybrid_engine->analyzeLayers($event_data);
        }

        $resolved_target = $semantic_target !== '' ? $semantic_target : so_build_smart_target($title, $region, $entities['targets'], $precision_5w1h['where_target']??'');
        $resolved_context = $semantic_context;
        $resolved_intent = $semantic_intent;
        $resolved_weapon = $semantic_weapon !== '' ? $semantic_weapon : (!empty($entities['weapons']) ? implode(', ', array_unique($entities['weapons'])) : $precision_5w1h['how_weapon']);

        if ($resolved_context === '' && !empty($semantic['_ai_v2']['bucket']) && in_array((string)$semantic['_ai_v2']['bucket'], ['statement','report'], true)) {
            $resolved_context = 'سياق تصريحي/إعلامي';
        }
        if ($resolved_intent === '' && $strategic_axis === 'سياسي') {
            $resolved_intent = 'تموضع/رسائل سياسية';
        } elseif ($resolved_intent === '' && $strategic_axis === 'إعلامي') {
            $resolved_intent = 'تغطية/رسائل إعلامية';
        } elseif ($resolved_intent === '' && in_array($strategic_axis, ['عسكري/أمني','تكتيكي/ميداني','رصد/إنذار'], true)) {
            $resolved_intent = 'نشاط ميداني';
        }

        $actor = function_exists('bt_v24_unify_actor')
            ? bt_v24_unify_actor($title, [$actor, $precision_5w1h['who_primary'] ?? '', $semantic['actor_v2'] ?? '', $semantic_context], $source, $region)
            : $actor;
        $region = function_exists('bt_v24_resolve_region') ? bt_v24_resolve_region($title, $region, $actor, $source) : $region;
        $final_hybrid_layers = function_exists('bt_v24_unify_hybrid_layers')
            ? bt_v24_unify_hybrid_layers($title, $strategic_axis, !empty($hybrid_analysis['layers']) ? (array)$hybrid_analysis['layers'] : [])
            : (!empty($hybrid_analysis['layers']) ? (array)$hybrid_analysis['layers'] : []);
        
        // تحويل مصفوفة الحرب المركبة إلى نص عربي مفصول بفواصل للحفظ في قاعدة البيانات
        $final_hybrid_layers_text = '';
        if (!empty($final_hybrid_layers) && is_array($final_hybrid_layers)) {
            $hybrid_map = [
                'political' => 'سياسي',
                'economic' => 'اقتصادي',
                'energy' => 'طاقة',
                'media_psychological' => 'إعلامي/نفسي',
                'security' => 'أمني',
                'military' => 'عسكري',
                'cyber' => 'سيبراني',
                'geostrategic' => 'جيوستراتيجي',
                'social' => 'اجتماعي',
            ];
            $arabic_layers = [];
            foreach ($final_hybrid_layers as $layer) {
                $layer_key = is_array($layer) ? ($layer['name'] ?? key($layer)) : $layer;
                $arabic_layers[] = $hybrid_map[$layer_key] ?? $layer_key;
            }
            $final_hybrid_layers_text = implode('', array_unique($arabic_layers));
        } elseif (is_string($final_hybrid_layers)) {
            $final_hybrid_layers_text = $final_hybrid_layers;
        }
        $precision_5w1h['who_primary'] = $actor;
        $precision_5w1h['where_event'] = $region;
        $precision_5w1h['where_summary'] = $region;
        if (empty($precision_5w1h['where_target']) || $precision_5w1h['where_target'] === 'غير محدد') {
            $precision_5w1h['where_target'] = $resolved_target !== '' ? $resolved_target : $region;
        }
        $precision_5w1h['confidence_overall'] = max((int)($precision_5w1h['confidence_overall'] ?? 0), (int)($actor_conf['confidence'] ?? 0));

        $war_data = wp_json_encode([
            'who'=>$precision_5w1h['who_primary'],'what'=>$precision_5w1h['what_type'],'where'=>$precision_5w1h['where_summary'],'when'=>$precision_5w1h['when_event'],'how'=>$precision_5w1h['how_method'],'why'=>$precision_5w1h['why_reason'],
            'action'=>!empty($entities['actions'])?implode(', ',array_unique($entities['actions'])):$precision_5w1h['what_type'],
            'weapon_means'=>$resolved_weapon,
            'target'=>$resolved_target,
            'context_actor'=>$resolved_context,
            'intent'=>$resolved_intent,
            'strategic_main'=>$strategic_axis,
            'contextual_war_engine'=>['strategic_frame'=>so_detect_strategic_frame($title),'conflict_context'=>so_detect_conflict_context($title),'war_direction'=>so_detect_war_direction($title)],
            'actor'=>$precision_5w1h['who_primary'],'confidence'=>$precision_5w1h['confidence_overall'].'%',
            'signal_strength'=>'MEDIUM','capability'=>$capability,'true_threat'=>$true_threat,'stance'=>$sentiment['stance'],
            'truth_layer'=>$truth_layer,'5w1h'=>$precision_5w1h,'source_reliability'=>$precision_5w1h['source_reliability'],
            'early_warning'=>$early_warning,
            'hybrid_layers' => $final_hybrid_layers_text,
            'hybrid_combinations' => !empty($hybrid_analysis['layer_combinations']) ? $hybrid_analysis['layer_combinations'] : [],
            'multi_domain_score' => (float)($hybrid_analysis['composite_score'] ?? 0.0),
            'actor_final_source' => (string)($actor_final_data['source'] ?? 'unknown'),
            'actor_final_reason' => (string)($actor_final_data['reason'] ?? ''),
            'actor_final_confidence' => (int)($actor_final_data['confidence'] ?? 0),
        ], JSON_UNESCAPED_UNICODE);

        $payload = [
            'title'=>$title,'link'=>so_normalize_event_link((string)($item['link']??'')),
            'source_name'=>$item['source']??'','source_color'=>$item['color']??'#1da1f2',
            'event_timestamp'=>(int)($item['date']??time()),'agency_loc'=>$item['agency_loc']??'',
            'region'=>$region,'actor_v2'=>$actor,'score'=>$final_score,'tactical_level'=>$tactical_level,
            'target_v2'=>$resolved_target,'context_actor'=>$resolved_context,'intent'=>$resolved_intent,'weapon_v2'=>$resolved_weapon,
            'intel_type'=>$strategic_axis,'strategic_frame'=>so_detect_strategic_frame($title),
            'conflict_context'=>so_detect_conflict_context($title),'war_direction'=>so_detect_war_direction($title),
            'sentiment_score'=>0,'war_data'=>$war_data,'image_url'=>$item['image_url']??'',
            'field_data'=>wp_json_encode([
                'truth_layer'=>$truth_layer,
                'actor_confidence'=>(int)($actor_final_data['confidence'] ?? $actor_conf['confidence'] ?? 0),
                'actor_source'=>(string)($actor_final_data['source'] ?? $actor_conf['source'] ?? 'unknown'),
                'actor_reason'=>(string)($actor_final_data['reason'] ?? ''),
                'verification_nature'=>(string)($verification_nature??'unknown'),
                'attribution'=>so_extract_actor_attribution($title),
                'fusion_actor_conf'=>(int)($fusion['actor_conf']??0),
                'fusion_type_conf'=>(int)($fusion['type_conf']??0),
                'fusion_region_conf'=>(int)($fusion['region_conf']??0),
                'fusion_engine'=>'advanced_v2',
                'early_warning'=>$early_warning,
                'semantic_context_actor'=>$resolved_context,
                'semantic_intent'=>$resolved_intent,
                'semantic_target'=>$resolved_target,
                'semantic_weapon'=>$resolved_weapon,
                'hybrid_layers_count' => (int)($hybrid_analysis['active_layers_count'] ?? 0),
                'is_hybrid_event' => (bool)($hybrid_analysis['is_hybrid'] ?? false),
                'multi_domain_score' => (float)($hybrid_analysis['composite_score'] ?? 0.0),
                'region'=>$region,
                'actor_v2'=>$actor,
                'actor_final'=>$actor,
                'actor_final_unified'=>true,
                'hybrid_layers'=>$final_hybrid_layers_text,
            ],JSON_UNESCAPED_UNICODE),
            'llm_verified'=>$llm_verified,
            'hybrid_analysis' => $hybrid_analysis,
        ];
        if (function_exists('bt_v24_presave_lockdown')) {
            $payload = bt_v24_presave_lockdown($payload, $title, $source);
        }
        if (function_exists('bt_v24_master_return_override')) {
            $payload = bt_v24_master_return_override($payload, $title, $source);
        }
        return $payload;
    }

    private static function extract_entities($lower) {
        global $wpdb;
        $entities = ['actions'=>[],'weapons'=>[],'targets'=>[]];
        $actions = ['إغارة','اقتحام','مداهمة','اشتباك','كمين','قنص','تفجير','انفجار','قصف','غارة','غارات','اعتراض','استطلاع','اغتيال','توغل','هجوم','استهداف','تدمير','مقتل','إصابة','بحث','إخلاء','أسر','إسقاط','سقوط','إطلاق نار','انسحاب','إنزال','إطلاق','عدوان'];
        $targets = ['قاعدة','قاعدة امريكية','قاعدة أمريكية','مستوطنة','مستوطنات','مراكز القيادة','مطار','بنية تحتية','منشأة نفطية','مستشفى','قيادي','سفارة','محطة كهرباء','تل أبيب','حيفا','صفد','طيار','جندي','أربيل','مضيق هرمز','سيارة','آلية','ثكنة','مصنع','مبنى','موقع','بوشهر','منظمة الطاقة الذرية'];
        foreach ($actions as $k) if (preg_match('/(?<!نفي |لم يتم |كاذب |شائعة )' . preg_quote($k,'/') . '/ui', $lower)) $entities['actions'][] = $k;
        foreach ($targets as $k) if (mb_stripos($lower, $k) !== false) $entities['targets'][] = $k;
        
        // مطابقة الأسلحة الموسعة - v17.3
        if (preg_match('/(مسير|مسيّر|درون|طائرة بدون طيار)/ui', $lower)) { 
            if (preg_match('/(هجوم|انقضاض|مفخخ|سرب|استهداف|أطلق|انتحارية|كاميكازي)/ui', $lower)) {
                $entities['weapons'][] = preg_match('/(انتحارية|كاميكازي)/ui', $lower) ? 'مسيرة انتحارية' : 'مسيرة هجومية';
            } else {
                $entities['weapons'][] = 'طائرات مسيرة';
            }
        }
        if (preg_match('/(صاروخ|صواريخ|مقذوفات)/ui', $lower)) { 
            if (preg_match('/(باليست|بالست)/ui', $lower)) {
                $entities['weapons'][] = preg_match('/(عابر|للقارات|ICBM)/ui', $lower) ? 'صاروخ عابر للقارات' : 'صاروخ باليستي';
            } elseif (preg_match('/(فرط|هايبر|hyper)/ui', $lower)) {
                $entities['weapons'][] = 'صاروخ فرط صوتي';
            } elseif (preg_match('/(كروز|cruise)/ui', $lower)) {
                $entities['weapons'][] = 'صاروخ كروز';
            } else {
                $entities['weapons'][] = 'صاروخ / قذائف';
            }
        }
        if (preg_match('/(غارة|طيران حربي|مقاتل|إف-15|إف-35|إف 15|إف 35|طائرات الاحتلال|سوخوي|ميج|رافال|تايفون)/ui', $lower)) {
            $entities['weapons'][] = 'طيران حربي';
        }
        if (preg_match('/(زورق|زوارق|بحرية|غواصة|طوربيد)/ui', $lower)) {
            if (preg_match('/(غواصة|طوربيد)/ui', $lower)) {
                $entities['weapons'][] = preg_match('/(طوربيد)/ui', $lower) ? 'طوربيد' : 'غواصة';
            } else {
                $entities['weapons'][] = 'زوارق حربية';
            }
        }
        if (preg_match('/(مدفعي|قذائف مدفعية|هاون|MLRS|grad|راجمات)/ui', $lower)) {
            $entities['weapons'][] = preg_match('/(هاون)/ui', $lower) ? 'هاون' : (preg_match('/(راجمات|MLRS|grad)/ui', $lower) ? 'راجمات صواريخ' : 'مدفعية');
        }
        if (preg_match('/(اشتباك|اشتباكات|إغارة|رشاش|متوسط|RPG|أر بي جي)/ui', $lower) && !in_array('أسلحة رشاشة / متوسطة', $entities['weapons'])) {
            $entities['weapons'][] = preg_match('/(RPG|أر بي جي)/ui', $lower) ? 'قاذف RPG' : 'أسلحة رشاشة / متوسطة';
        }
        if (preg_match('/(انذار احمر|اللون الأحمر|صفارات الإنذار|صفارات|الجبهة الداخلية)/ui', $lower)) { 
            $entities['actions'][] = 'تفعيل إنذار أمني'; 
            $entities['targets'][] = 'الجبهة الداخلية'; 
        }
        if (preg_match('/(ميركافا|دبابة|دبّابة|آلية|ناقلة جنود)/ui', $lower) && !in_array('دبابات / آليات', $entities['weapons'])) {
            $entities['weapons'][] = 'دبابات / آليات';
        }
        // دفاعات جوية
        if (preg_match('/(قبة حديدية|Iron Dome|باتريوت|PAC|ثاد|THAAD|مقلاع داود|David Sling|سهم|Arrow|S 300|S 400|بوك|patriot)/ui', $lower)) {
            if (preg_match('/(قبة حديدية|Iron Dome)/ui', $lower)) $entities['weapons'][] = 'قبة حديدية';
            elseif (preg_match('/(باتريوت|PAC)/ui', $lower)) $entities['weapons'][] = 'بطارية باتريوت';
            elseif (preg_match('/(ثاد|THAAD)/ui', $lower)) $entities['weapons'][] = 'نظام ثاد';
            elseif (preg_match('/(مقلاع داود|David Sling)/ui', $lower)) $entities['weapons'][] = 'مقلاع داود';
            elseif (preg_match('/(سهم|Arrow)/ui', $lower)) $entities['weapons'][] = 'سهم';
            else $entities['weapons'][] = 'دفاعات جوية';
        }
        // حرب إلكترونية وسيبرانية
        if (preg_match('/(حرب إلكترونية|تشويش|EW|cyber|قرصنة|اختراق|سيبراني)/ui', $lower)) {
            $entities['weapons'][] = preg_match('/(cyber|قرصنة|اختراق|سيبراني)/ui', $lower) ? 'هجوم سيبراني' : 'حرب إلكترونية';
        }
        // ذخائر خاصة
        if (preg_match('/(عنقودية|cluster|وقودية|حرارية|thermobaric|موجهة|guided)/ui', $lower)) {
            if (preg_match('/(عنقودية|cluster)/ui', $lower)) $entities['weapons'][] = 'قنبلة عنقودية';
            elseif (preg_match('/(وقودية|حرارية|thermobaric)/ui', $lower)) $entities['weapons'][] = 'قنبلة وقودية';
            elseif (preg_match('/(موجهة|guided)/ui', $lower)) $entities['weapons'][] = 'قنبلة موجهة';
        }
        // صواريخ مضادة
        if (preg_match('/(مضاد للدروع|ATGM|تاو|كورنت|جابولين|مضاد للسفن|harpoon|exocet|أرض-جو|SAM|جو-جو|AAM)/ui', $lower)) {
            if (preg_match('/(مضاد للدروع|ATGM|تاو|كورنت|جابولين)/ui', $lower)) $entities['weapons'][] = 'صاروخ مضاد للدروع';
            elseif (preg_match('/(مضاد للسفن|harpoon|exocet)/ui', $lower)) $entities['weapons'][] = 'صاروخ مضاد للسفن';
            elseif (preg_match('/(أرض-جو|SAM)/ui', $lower)) $entities['weapons'][] = 'صاروخ أرض-جو';
            elseif (preg_match('/(جو-جو|AAM)/ui', $lower)) $entities['weapons'][] = 'صاروخ جو-جو';
        }
        // MANPADS
        if (preg_match('/(ستيرنغر|stinger|إيغلا|igla|كتف|MANPADS)/ui', $lower)) {
            $entities['weapons'][] = preg_match('/(ستيرنغر|stinger)/ui', $lower) ? 'صاروخ ستينغر' : 'صاروخ إيغلا';
        }
        // ألغام
        if (preg_match('/(لغم|ألغام|mine)/ui', $lower)) {
            $entities['weapons'][] = 'لغم بحري';
        }
        
        $entities['actions'] = array_values(array_unique($entities['actions']));
        $entities['weapons'] = array_values(array_unique($entities['weapons']));
        $entities['targets'] = array_values(array_unique($entities['targets']));
        return $entities;
    }

    private static function get_actor_base_threat($actor_name) {
        if (self::$actor_threat_cache === null) {
            global $wpdb;
            self::$actor_threat_cache = [];
            $rows = $wpdb->get_results("SELECT name_ar, keywords, base_threat FROM {$wpdb->prefix}so_dict_actors", ARRAY_A);
            foreach ($rows as $row) {
                self::$actor_threat_cache[$row['name_ar']] = (int)$row['base_threat'];
                foreach (array_map('trim', explode(',', $row['keywords'])) as $kw) if ($kw) self::$actor_threat_cache[$kw] = (int)$row['base_threat'];
            }
        }
        return (int)(self::$actor_threat_cache[$actor_name] ?? 0);
    }

    private static function get_weapon_impact($weapon_name) {
        if (self::$weapon_impact_cache === null) {
            global $wpdb;
            self::$weapon_impact_cache = [];
            $rows = $wpdb->get_results("SELECT name_ar, keywords, impact_score FROM {$wpdb->prefix}so_dict_weapons", ARRAY_A);
            foreach ($rows as $row) {
                self::$weapon_impact_cache[$row['name_ar']] = (int)$row['impact_score'];
                foreach (array_map('trim', explode(',', $row['keywords'])) as $kw) if ($kw) self::$weapon_impact_cache[$kw] = (int)$row['impact_score'];
            }
        }
        return (int)(self::$weapon_impact_cache[$weapon_name] ?? 0);
    }
}
}

