// 11. مدير الكرون — Cron Manager
// ==========================================================================
add_filter('cron_schedules', function($schedules) {
    $schedules['every_five_minutes'] = ['interval'=>300,'display'=>'كل ٥ دقائق'];
    return $schedules;
});

if (!class_exists('SO_Cron_Manager')) {
class SO_Cron_Manager {
    public static function init() {
        add_action('so_cron_fetch_news_v5', [__CLASS__, 'safe_sync_news']);
        add_action('so_cron_daily_cleanup', [__CLASS__, 'cleanup']);
        if (function_exists('sod_schedule_event_once')) {
            sod_schedule_event_once(time() + 30, 'every_five_minutes', 'so_cron_fetch_news_v5');
            sod_schedule_event_once(time() + 90, 'daily', 'so_cron_daily_cleanup');
        } else {
            if (!wp_next_scheduled('so_cron_fetch_news_v5')) wp_schedule_event(time(), 'every_five_minutes', 'so_cron_fetch_news_v5');
            if (!wp_next_scheduled('so_cron_daily_cleanup')) wp_schedule_event(time(), 'daily', 'so_cron_daily_cleanup');
        }
    }
    public static function safe_sync_news() {
        if (get_transient('so_sync_process_lock')) { so_log('Cron skipped - Lock active.'); return 0; }
        set_transient('so_sync_process_lock', true, SO_SYNC_LOCK_TTL);
        if (function_exists('sod_watchdog_touch')) sod_watchdog_touch('pipeline');
        $inserted = 0; $stats = ['raw_count'=>0,'candidate_items'=>0,'skipped_old'=>0,'skipped_keyword'=>0,'process_null'=>0,'duplicate_hash'=>0,'inserted'=>0,'db_failed'=>0];
        try {
            $raw_data = SO_Data_Fetcher::get_all_raw_data(true);
            $stats['raw_count'] = is_array($raw_data) ? count($raw_data) : 0;
            if (!empty($raw_data)) {
                global $wpdb; $table = $wpdb->prefix . 'so_news_events';
                $earthquakes = SO_Field_Data::fetch_earthquakes(1);
                $exclude_keywords = array_filter(array_map('trim', explode(',', get_option('so_filter_keywords',''))));
                foreach ($raw_data as $item) {
                    $candidate_items = SO_Multi_Event_Parser::split_item($item);
                    if (empty($candidate_items)) $candidate_items = [$item];
                    foreach ($candidate_items as $candidate_item) {
                        $stats['candidate_items']++;
                        if (time() - ((int)($candidate_item['date']??0)) > 259200) { $stats['skipped_old']++; continue; }
                        if (!empty($exclude_keywords)) {
                            $should_exclude = false;
                            foreach ($exclude_keywords as $kw) if ($kw !== '' && mb_stripos((string)($candidate_item['title']??''), $kw) !== false) { $should_exclude = true; break; }
                            if ($should_exclude) { $stats['skipped_keyword']++; continue; }
                        }
                        $pipeline = function_exists('sod_pipeline_process_candidate') ? sod_pipeline_process_candidate($candidate_item) : sod_ingest_and_publish_canonical_item($candidate_item, [], ['status' => 'published', 'decision_source' => 'auto']);
                        if (empty($pipeline['ok']) || empty($pipeline['canonical'])) {
                            $reason = (string)($pipeline['reason'] ?? 'pipeline_null');
                            if ($reason === 'probable_duplicate') { $stats['duplicate_hash']++; } else { $stats['process_null']++; }
                            continue;
                        }
                        $analyzed = (array)($pipeline['analyzed'] ?? []);
                        $canonical = (array)$pipeline['canonical'];
                        $hash = so_build_insert_hash($candidate_item, $canonical);
                        if ($wpdb->get_var($wpdb->prepare("SELECT id FROM $table WHERE hash_id = %s", $hash))) { $stats['duplicate_hash']++; continue; }
                        // Cross-source title fingerprint dedup — prevents same event from different sources
                        $tfp = so_build_title_fingerprint((string)($canonical['title']??($candidate_item['title']??'')));
                        if ($tfp && $wpdb->get_var($wpdb->prepare("SELECT id FROM $table WHERE title_fingerprint = %s AND event_timestamp >= %d", $tfp, time()-10800))) { $stats['duplicate_hash']++; continue; }
                        $canonical['title_fingerprint'] = $tfp;
                        $canonical['hash_id'] = $hash;
                        $save = sod_save_canonical_event_state($table, $canonical);
                        if (!empty($save['ok'])) {
                            $canonical['id'] = (int)($save['insert_id'] ?? 0); $inserted++; $stats['inserted']++;
                            sod_store_event_entities_in_memory($canonical, true);
                            wp_schedule_single_event(time() + 5, 'so_reclassify_event_after_insert', [$canonical['id']]);

                            // Self-learning مباشرة من مسار الإدخال
                            so_ai_learn([
                                'title' => (string)($canonical['title'] ?? ''),
                                'actor' => (string)($canonical['actor_v2'] ?? ''),
                                'type'  => (string)($canonical['intel_type'] ?? 'عام'),
                                'score' => (int)($canonical['threat_score'] ?? $canonical['score'] ?? 0),
                                'time'  => (int)($canonical['event_timestamp'] ?? time()),
                            ]);

                            SO_Alert_Dispatcher::dispatch(array_merge($analyzed, $canonical));
                        } else { $stats['db_failed']++; so_log('DB insert failed: '.($save['error'] ?? $wpdb->last_error), 'ERROR'); }
                    }
                }
            }
            update_option('so_last_sync_time', time());
            so_update_insert_pipeline_summary($stats);
            $message = $stats['inserted'] > 0 ? 'تمت الدورة بنجاح: أُدخل '.intval($stats['inserted']).' خبر جديد' : 'انتهت الدورة بدون إدخالات جديدة';
            so_update_last_sync_summary($stats['raw_count'], $inserted, $message);
        } catch (Exception $e) { so_log('Cron Error: '.$e->getMessage(), 'ERROR'); } finally { delete_transient('so_sync_process_lock'); if (function_exists('sod_watchdog_touch')) sod_watchdog_touch('pipeline'); }
        return $inserted;
    }
    public static function cleanup() {
        global $wpdb;
        $wpdb->query($wpdb->prepare("DELETE FROM {$wpdb->prefix}so_sent_alerts WHERE sent_time < %s", gmdate('Y-m-d H:i:s', time()-7*86400)));
        $wpdb->query($wpdb->prepare("DELETE FROM {$wpdb->prefix}so_news_events WHERE event_timestamp < %d AND score < 140", time()-15*86400));
        // intentionally keep so_actor_memory as a long-lived strategic memory bank during archive cleanup.
        // Remove cross-source duplicates: keep highest scored event per title_fingerprint per 3h window
        self::deduplicate_existing_events();
    }

    public static function deduplicate_existing_events() {
        global $wpdb;
        $t = "{$wpdb->prefix}so_news_events";
        // Find fingerprints with more than 1 event in last 30 days
        $dupes = $wpdb->get_results(
            "SELECT title_fingerprint, COUNT(*) as cnt
             FROM $t
             WHERE title_fingerprint IS NOT NULL AND title_fingerprint != ''
               AND event_timestamp >= ".( time()-30*86400 )."
             GROUP BY title_fingerprint HAVING cnt > 1
             LIMIT 300",
            ARRAY_A
        );
        if (empty($dupes)) return;
        $removed = 0;
        foreach ($dupes as $row) {
            $fp = $row['title_fingerprint'];
            // Get all events with this fingerprint, keep the one with highest score (or newest if tied)
            $events = $wpdb->get_results(
                $wpdb->prepare(
                    "SELECT id FROM $t WHERE title_fingerprint = %s ORDER BY score DESC, event_timestamp DESC",
                    $fp
                ),
                ARRAY_A
            );
            if (count($events) <= 1) continue;
            $keep_id = (int)$events[0]['id'];
            $del_ids = array_map(fn($e)=>(int)$e['id'], array_slice($events, 1));
            if (!empty($del_ids)) {
                $placeholders = implode(',', $del_ids);
                $wpdb->query("DELETE FROM $t WHERE id IN ($placeholders) AND score < 140");
                $removed += count($del_ids);
            }
        }
        if ($removed > 0) so_log("Dedup cleanup: removed $removed duplicate events.");
    }
}
}

// ==========================================================================
// 12. مرسل التنبيهات — Alert Dispatcher (Telegram + Discord)
// ==========================================================================
if (!class_exists('SO_Alert_Dispatcher')) {
class SO_Alert_Dispatcher {
    // أنماط رسائل الشهداء/الضحايا المدنيين — تتجاوز عتبة النقاط
    private static $martyrdom_patterns = [
        '/ارتق(وا|ى|ت)\s/ui',
        '/استشه(د|دوا|دت|دا)\s/ui',
        '/شهيد(ة|اً|ان|ون|ات)?\b/ui',
        '/شهداء\b/ui',
        '/جث(ة|ث|امين)\s/ui',
        '/سقوط\s+(شهيد|ضحاي|قتل|جر)/ui',
        '/ضحاي(ا|ة)\s+مدني/ui',
        '/مجزرة\b/ui',
        '/حصيلة\s+(شهداء|ضحايا|قتلى)/ui',
    ];
    private static function is_martyrdom_message(string $title): bool {
        foreach (self::$martyrdom_patterns as $pat) {
            if (preg_match($pat, $title)) return true;
        }
        return false;
    }

    private static function parse_delivery_type_list($raw) {
        if (is_array($raw)) $parts = $raw;
        else $parts = preg_split('/[,

	]+/u', (string)$raw);
        $out = [];
        foreach ((array)$parts as $part) {
            $v = trim(wp_strip_all_tags((string)$part));
            if ($v === '') continue;
            $out[] = $v;
        }
        return array_values(array_unique($out));
    }

    private static function item_delivery_classification($item): string {
        $candidates = [
            (string)($item['intel_type'] ?? ''),
            (string)($item['osint_type'] ?? ''),
            (string)($item['strategic_category'] ?? ''),
            (string)($item['hybrid_primary_domain'] ?? ''),
        ];
        foreach ($candidates as $candidate) {
            $candidate = trim(wp_strip_all_tags($candidate));
            if ($candidate !== '') return $candidate;
        }
        return 'غير محدد';
    }

    private static function delivery_type_allowed(array $allowed_types, string $item_type): bool {
        if (empty($allowed_types)) return true;
        $item_type = trim($item_type);
        if ($item_type === '') $item_type = 'غير محدد';
        foreach ($allowed_types as $allowed) {
            if ($allowed === '') continue;
            if (mb_stripos($item_type, $allowed) !== false || mb_stripos($allowed, $item_type) !== false) {
                return true;
            }
        }
        return false;
    }


    private static function item_delivery_actor($item): string {
        $candidates = [
            (string)($item['actor_v2'] ?? ''),
            (string)($item['actor'] ?? ''),
            (string)($item['primary_actor'] ?? ''),
        ];
        foreach ($candidates as $candidate) {
            $candidate = trim(wp_strip_all_tags($candidate));
            if ($candidate !== '' && !in_array($candidate, ['عام/مجهول','غير محدد','مجهول','فاعل غير محسوم'], true)) return $candidate;
        }
        return 'غير محدد';
    }

    private static function item_delivery_region($item): string {
        $candidates = [
            (string)($item['region'] ?? ''),
            (string)($item['country'] ?? ''),
            (string)($item['location'] ?? ''),
        ];
        foreach ($candidates as $candidate) {
            $candidate = trim(wp_strip_all_tags($candidate));
            if ($candidate !== '') return $candidate;
        }
        return 'غير محدد';
    }

    private static function list_value_matches(array $allowed_values, string $item_value): bool {
        if (empty($allowed_values)) return true;
        $item_value = trim($item_value);
        if ($item_value === '') $item_value = 'غير محدد';
        foreach ($allowed_values as $allowed) {
            if ($allowed === '') continue;
            if (mb_stripos($item_value, $allowed) !== false || mb_stripos($allowed, $item_value) !== false) {
                return true;
            }
        }
        return false;
    }

    private static function platform_delivery_allowed(string $platform, array $item): bool {
        $prefix = $platform === 'discord' ? 'so_discord_' : 'so_tg_';
        $score = (int)($item['score'] ?? 0);
        $min_score = (int)get_option($prefix . 'min_score', 0);
        if ($min_score > 0 && $score < $min_score) return false;

        $item_type = self::item_delivery_classification($item);
        $allowed_types = self::parse_delivery_type_list(get_option($prefix . 'allowed_types', ''));
        if (!self::delivery_type_allowed($allowed_types, $item_type)) return false;

        $allowed_actors = self::parse_delivery_type_list(get_option($prefix . 'allowed_actors', ''));
        if (!self::list_value_matches($allowed_actors, self::item_delivery_actor($item))) return false;

        $allowed_regions = self::parse_delivery_type_list(get_option($prefix . 'allowed_regions', ''));
        if (!self::list_value_matches($allowed_regions, self::item_delivery_region($item))) return false;

        if ($platform !== 'discord') {
            $blocked_types_raw = trim((string)get_option($prefix . 'blocked_types', ''));
            if ($blocked_types_raw !== '') {
                $blocked_types = self::parse_delivery_type_list($blocked_types_raw);
                foreach ($blocked_types as $bt) {
                    if ($bt !== '' && (mb_stripos($item_type, $bt) !== false || mb_stripos($bt, $item_type) !== false)) return false;
                }
            }
        }
        return true;
    }

    private static function get_delivery_template_fields(): array {
        $raw = (string)get_option('so_delivery_template_fields', '');
        $tpl = $raw !== '' ? json_decode($raw, true) : null;
        if (!is_array($tpl) || empty($tpl)) {
            $tpl = json_decode((string)get_option('so_tg_template_fields', '{}'), true) ?: [];
        }
        return is_array($tpl) ? $tpl : [];
    }

    private static function get_delivery_header_text(): string {
        $header = trim((string)get_option('so_delivery_header_text', ''));
        if ($header === '') $header = trim((string)get_option('so_tg_header_text', ''));
        return $header;
    }

    public static function dispatch($item) {
        $score = (int)($item['score']??0);
        $threshold = (int)get_option('so_alert_threshold', 140);
        // تجاوز عتبة النقاط لرسائل الشهداء/الضحايا المدنيين
        $force_martyrdom = (bool)get_option('so_tg_force_martyrdom', 1);
        $is_martyrdom = $force_martyrdom && self::is_martyrdom_message((string)($item['title']??''));
        if (!$is_martyrdom && $score < $threshold) return;
        if (self::already_sent($item['hash_id']??'')) return;
        // وسم تجاوز العتبة في البيانات لتوضيح السبب في الرسالة
        if ($is_martyrdom && $score < $threshold) $item['_martyrdom_bypass'] = true;
        $telegram_ok = self::send_telegram($item);
        $discord_ok  = self::send_discord($item);
        if ($telegram_ok || $discord_ok) self::mark_sent($item['hash_id']??'', $item['source_name']??'');
    }
    private static function already_sent($hash) {
        global $wpdb;
        return (bool)$wpdb->get_var($wpdb->prepare("SELECT id FROM {$wpdb->prefix}so_sent_alerts WHERE news_hash = %s", $hash));
    }
    private static function mark_sent($hash, $source) {
        global $wpdb;
        $wpdb->replace("{$wpdb->prefix}so_sent_alerts", ['news_hash'=>$hash,'source_name'=>$source,'sent_time'=>current_time('mysql')]);
    }
    public static function send_telegram($item) {
        $token = trim(get_option('so_tg_token', '')); if (empty($token)) return false;
        $chats = array_filter(array_map('trim', explode(',', get_option('so_tg_chat', '')))); if (empty($chats)) return false;

        // ── فلترة موحّدة: تصنيف / فاعل / منطقة / خطورة ───────────────────
        if (!self::platform_delivery_allowed('telegram', (array)$item)) return false;
        $item_type = self::item_delivery_classification($item);

        // ── إعدادات الحقول الظاهرة (قالب موحّد لتلغرام + ديسكورد) ───────────
        $tpl = self::get_delivery_template_fields();
        $show = function($key) use ($tpl) { return isset($tpl[$key]) ? (bool)$tpl[$key] : true; };

        $wd = json_decode((string)($item['war_data']??'{}'), true) ?: [];
        $score_ar = number_format((int)($item['score']??0));

        // ── بناء رسالة تيليغرام ─────────────────────────────────────────────
        $header_custom = self::get_delivery_header_text();
        $header = $header_custom !== '' ? $header_custom : '🚨 <b>تنبيه استخباراتي | Beiruttime OSINT</b>';
        $text = $header . "\n";
        $text .= '<b>' . htmlspecialchars(so_limit_text($item['title']??'', 900), ENT_QUOTES, 'UTF-8') . "</b>\n\n";
        $text .= "📰 <b>المصدر:</b> " . esc_html($item['source_name']??'مجهول') . "\n";
        if ($show('classification')) $text .= "📌 <b>التصنيف:</b> " . esc_html($item['intel_type']??'غير محدد') . "\n";
        if ($show('level'))          $text .= "🎯 <b>المستوى:</b> " . esc_html($item['tactical_level']??'تكتيكي') . "\n";
        if ($show('actor')) {
            $actor_val = trim((string)($item['actor_v2']??''));
            $unknown_actors = ['عام/مجهول','غير محدد','مجهول',''];
            if (!in_array($actor_val, $unknown_actors, true)) {
                // فاعل محدد — اعرضه مع حالة الإسناد
                $fd_attr = [];
                $fd_raw  = json_decode((string)($item['field_data']??'{}'), true);
                if (!empty($fd_raw['attribution'])) $fd_attr = $fd_raw['attribution'];
                $attr_status = $fd_attr['status'] ?? 'confirmed';
                $attr_icon   = so_attribution_icon($attr_status);
                $attr_label  = so_attribution_label($attr_status);
                $text .= "🎭 <b>الفاعل:</b> {$attr_icon} " . esc_html($actor_val) . " <i>({$attr_label})</i>\n";
            } else {
                // لا فاعل — اعرض حالة الإسناد مباشرة
                $fd_raw  = json_decode((string)($item['field_data']??'{}'), true);
                $attr    = $fd_raw['attribution'] ?? [];
                $status  = $attr['status'] ?? 'unattributed';
                $text .= "🕳️ <b>حالة الإسناد:</b> " . so_attribution_label($status) . "\n";
            }
        }
        if ($show('region'))         $text .= "📍 <b>المنطقة:</b> " . esc_html($item['region']??'غير محدد') . "\n";
        if ($show('score'))          $text .= "⚠️ <b>مؤشر الخطورة:</b> {$score_ar} نقطة\n";
        if ($show('weapon') && !empty($wd['weapon_means']) && $wd['weapon_means'] !== 'غير محدد') $text .= "⚙️ <b>الوسيلة:</b> " . esc_html($wd['weapon_means']) . "\n";
        if ($show('target') && !empty($wd['target']) && $wd['target'] !== 'غير محدد') $text .= "🎯 <b>الهدف:</b> " . esc_html($wd['target']) . "\n";
        if ($show('verified') && !empty($item['llm_verified']) && (int)$item['llm_verified'] === 1) $text .= "🤖 <b>تم التحقق بالذكاء الاصطناعي</b>\n";
        if ($show('link')) $text .= "\n🔗 <a href='" . esc_url(so_normalize_event_link($item['link']??'')) . "'>رابط المصدر</a>";
        // وسم تجاوز عتبة الشهداء
        if (!empty($item['_martyrdom_bypass'])) $text .= "\n<i>📌 إرسال تلقائي — رسالة شهداء/ضحايا</i>";
        // ── التذييل ─────────────────────────────────────────────────────────
        $tg_link  = trim((string)get_option('so_tg_channel_link',''));
        $wa_link  = trim((string)get_option('so_tg_wa_channel',''));
        $notes    = trim((string)get_option('so_tg_footer_notes',''));
        $footer_parts = [];
        if ($notes    !== '') $footer_parts[] = esc_html($notes);
        if ($tg_link  !== '') $footer_parts[] = "📢 <a href='" . esc_url($tg_link) . "'>قناة تلغرام</a>";
        if ($wa_link  !== '') $footer_parts[] = "💬 <a href='" . esc_url($wa_link) . "'>قناة واتساب</a>";
        if (!empty($footer_parts)) {
            $text .= "\n\n" . str_repeat('—', 20) . "\n" . implode("  |  ", $footer_parts);
        }
        // ── إرسال الصورة إن وُجدت (sendPhoto بدل sendMessage) ───────────────
        $image_url = trim((string)($item['image_url']??''));
        // أولوية: صورة قناة تلغرام الخاصة إن كانت من رابط t.me
        if ($show('image') && $image_url !== '' && filter_var($image_url, FILTER_VALIDATE_URL)) {
            $ok = false;
            foreach ($chats as $chat_id) {
                $res = so_safe_remote_post("https://api.telegram.org/bot{$token}/sendPhoto", [
                    'headers' => ['Content-Type'=>'application/json'],
                    'body'    => wp_json_encode(['chat_id'=>$chat_id,'photo'=>$image_url,'caption'=>sod_safe_substr($text,0,1024),'parse_mode'=>'HTML']),
                    'timeout' => 25,
                ]);
                if (!is_wp_error($res)) {
                    $body = json_decode(wp_remote_retrieve_body($res), true);
                    if (!empty($body['ok'])) { $ok = true; continue; }
                }
                // fallback: sendMessage إذا فشل sendPhoto
                $res2 = so_safe_remote_post("https://api.telegram.org/bot{$token}/sendMessage", ['headers'=>['Content-Type'=>'application/json'],'body'=>wp_json_encode(['chat_id'=>$chat_id,'text'=>$text,'parse_mode'=>'HTML','disable_web_page_preview'=>false]),'timeout'=>20]);
                if (!is_wp_error($res2)) { $b2 = json_decode(wp_remote_retrieve_body($res2),true); if (!empty($b2['ok'])) $ok = true; }
            }
            return $ok;
        }
        // ── إرسال نصي عادي ──────────────────────────────────────────────────
        $ok = false;
        foreach ($chats as $chat_id) {
            $res = so_safe_remote_post("https://api.telegram.org/bot{$token}/sendMessage", ['headers'=>['Content-Type'=>'application/json'],'body'=>wp_json_encode(['chat_id'=>$chat_id,'text'=>$text,'parse_mode'=>'HTML','disable_web_page_preview'=>false]),'timeout'=>20]);
            if (!is_wp_error($res)) { $body = json_decode(wp_remote_retrieve_body($res),true); if (!empty($body['ok'])) $ok = true; }
        }
        return $ok;
    }
    private static function discord_color_for_score(int $score): int {
        if ($score >= 180) return 0xDC2626;
        if ($score >= 140) return 0xF97316;
        if ($score >= 100) return 0xEAB308;
        return 0x2563EB;
    }
    
    /**
     * إرسال إلى ديسكورد مع قالب مخصص
     */
    public static function send_discord($item, $template_fields = []): bool {
        $webhook = trim((string)get_option('so_discord_webhook', ''));
        if ($webhook === '' || !filter_var($webhook, FILTER_VALIDATE_URL)) return false;

        if (!self::platform_delivery_allowed('discord', (array)$item)) return false;
        $item_type = self::item_delivery_classification($item);

        if (empty($template_fields) || !is_array($template_fields)) {
            $template_fields = self::get_delivery_template_fields();
        }

        $wd = json_decode((string)($item['war_data'] ?? '{}'), true) ?: [];
        $title  = wp_strip_all_tags((string)($item['title'] ?? ''));
        $score  = (int)($item['score'] ?? 0);
        $region = sanitize_text_field((string)($item['region'] ?? 'غير محدد'));
        $intel  = sanitize_text_field((string)($item['intel_type'] ?? 'عام'));
        $level  = sanitize_text_field((string)($item['tactical_level'] ?? 'عملياتي'));
        $actor  = sanitize_text_field((string)($item['actor_v2'] ?? 'فاعل غير محسوم'));
        $source = sanitize_text_field((string)($item['source_name'] ?? 'غير محدد'));
        $target = sanitize_text_field((string)($wd['target'] ?? ($item['target_v2'] ?? '')));
        $intent = sanitize_text_field((string)($wd['intent'] ?? ($item['intent'] ?? '')));
        $context = sanitize_text_field((string)($wd['context_actor'] ?? ($item['context_actor'] ?? '')));
        $weapon = sanitize_text_field((string)($wd['weapon_means'] ?? ($item['weapon_v2'] ?? '')));
        $link = so_normalize_event_link((string)($item['link'] ?? ''));
        $image_url = trim((string)($item['image_url'] ?? ''));
        $timestamp = !empty($item['event_timestamp']) ? gmdate('c', (int)$item['event_timestamp']) : gmdate('c');
        
        // حقول الحرب المركبة
        $hybrid_layers = !empty($item['hybrid_layers']) ? json_decode($item['hybrid_layers'], true) : [];
        $osint_type = sanitize_text_field($item['osint_type'] ?? '');
        $threat_score = (int)($item['threat_score'] ?? 0);
        $risk_level = sanitize_text_field($item['risk_level'] ?? '');
        $primary_actor = sanitize_text_field($item['primary_actor'] ?? '');

        // بناء الحقول بناءً على القالب المخصص
        $fields = [];
        
        // إذا تم تحديد حقول مخصصة
        if (!empty($template_fields) && is_array($template_fields)) {
            foreach ($template_fields as $field_key => $show_field) {
                if (!$show_field) continue;
                
                switch ($field_key) {
                    case 'source':
                        $fields[] = ['name' => 'المصدر', 'value' => $source !== '' ? $source : 'غير محدد', 'inline' => true];
                        break;
                    case 'classification':
                        $fields[] = ['name' => 'التصنيف', 'value' => $intel !== '' ? $intel : 'غير محدد', 'inline' => true];
                        break;
                    case 'level':
                        $fields[] = ['name' => 'المستوى', 'value' => $level !== '' ? $level : 'غير محدد', 'inline' => true];
                        break;
                    case 'actor':
                        $fields[] = ['name' => 'الفاعل', 'value' => $actor !== '' ? $actor : 'فاعل غير محسوم', 'inline' => true];
                        break;
                    case 'region':
                        $fields[] = ['name' => 'المنطقة', 'value' => $region !== '' ? $region : 'غير محدد', 'inline' => true];
                        break;
                    case 'score':
                        $fields[] = ['name' => 'الخطورة', 'value' => (string)$score, 'inline' => true];
                        break;
                    case 'threat_score':
                        if ($threat_score > 0) {
                            $fields[] = ['name' => 'درجة التهديد', 'value' => $threat_score . '/100', 'inline' => true];
                        }
                        break;
                    case 'risk_level':
                        if (!empty($risk_level)) {
                            $fields[] = ['name' => 'مستوى الخطر', 'value' => $risk_level, 'inline' => true];
                        }
                        break;
                    case 'osint_type':
                        if (!empty($osint_type)) {
                            $layer_name = self::get_osint_type_name($osint_type);
                            $fields[] = ['name' => 'نوع OSINT', 'value' => $layer_name, 'inline' => true];
                        }
                        break;
                    case 'hybrid_layers':
                        if (!empty($hybrid_layers) && is_array($hybrid_layers)) {
                            $layers_text = implode(', ', array_keys($hybrid_layers));
                            $fields[] = ['name' => 'طبقات الحرب المركبة', 'value' => $layers_text, 'inline' => false];
                        }
                        break;
                    case 'target':
                        if ($target !== '') $fields[] = ['name' => 'الهدف', 'value' => $target, 'inline' => true];
                        break;
                    case 'intent':
                        if ($intent !== '') $fields[] = ['name' => 'النية', 'value' => $intent, 'inline' => true];
                        break;
                    case 'context':
                        if ($context !== '') $fields[] = ['name' => 'السياق', 'value' => $context, 'inline' => true];
                        break;
                    case 'weapon':
                        if ($weapon !== '') $fields[] = ['name' => 'الوسيلة', 'value' => $weapon, 'inline' => true];
                        break;
                    case 'primary_actor':
                        if (!empty($primary_actor)) {
                            $fields[] = ['name' => 'الفاعل الرئيسي', 'value' => $primary_actor, 'inline' => false];
                        }
                        break;
                }
            }
        } else {
            // الحقول الافتراضية
            $fields = [
                ['name' => 'المصدر', 'value' => $source !== '' ? $source : 'غير محدد', 'inline' => true],
                ['name' => 'التصنيف', 'value' => $intel !== '' ? $intel : 'غير محدد', 'inline' => true],
                ['name' => 'المستوى', 'value' => $level !== '' ? $level : 'غير محدد', 'inline' => true],
                ['name' => 'الفاعل', 'value' => $actor !== '' ? $actor : 'فاعل غير محسوم', 'inline' => true],
                ['name' => 'المنطقة', 'value' => $region !== '' ? $region : 'غير محدد', 'inline' => true],
                ['name' => 'الخطورة', 'value' => (string)$score, 'inline' => true],
            ];
            if ($threat_score > 0) $fields[] = ['name' => 'درجة التهديد', 'value' => $threat_score . '/100', 'inline' => true];
            if (!empty($risk_level)) $fields[] = ['name' => 'مستوى الخطر', 'value' => $risk_level, 'inline' => true];
            if ($target !== '')  $fields[] = ['name' => 'الهدف', 'value' => $target, 'inline' => true];
            if ($intent !== '')  $fields[] = ['name' => 'النية', 'value' => $intent, 'inline' => true];
            if ($context !== '') $fields[] = ['name' => 'السياق', 'value' => $context, 'inline' => true];
            if ($weapon !== '')  $fields[] = ['name' => 'الوسيلة', 'value' => $weapon, 'inline' => true];
            
            // إضافة طبقات الحرب المركبة إذا وجدت
            if (!empty($hybrid_layers) && is_array($hybrid_layers)) {
                $layers_ar = [];
                foreach (array_keys($hybrid_layers) as $layer_key) {
                    $layers_ar[] = self::get_osint_type_name($layer_key);
                }
                if (!empty($layers_ar)) {
                    $fields[] = ['name' => '🎯 طبقات الحرب المركبة', 'value' => implode(' • ', $layers_ar), 'inline' => false];
                }
            }
        }

        $embed = [
            'title' => sod_safe_substr($title !== '' ? $title : 'Beiruttime OSINT Alert', 0, 250),
            'url' => $link,
            'description' => "تنبيه استخباراتي من Beiruttime OSINT",
            'color' => self::discord_color_for_score($score),
            'fields' => $fields,
            'footer' => ['text' => 'Beiruttime OSINT - Hybrid Warfare Intelligence'],
            'timestamp' => $timestamp,
        ];

        if ($image_url !== '' && preg_match('/\.(jpg|jpeg|png|gif|webp)(\?|$)/i', $image_url)) {
            $embed['image'] = ['url' => esc_url_raw($image_url)];
        } elseif ($image_url !== '') {
            $embed['description'] .= "\nرابط الوسائط: " . esc_url_raw($image_url);
        }

        $discord_header = wp_strip_all_tags(self::get_delivery_header_text());
        if ($discord_header === '') $discord_header = '🚨 Beiruttime OSINT Alert';

        $payload = [
            'content' => $discord_header,
            'embeds' => [$embed],
            'allowed_mentions' => ['parse' => []],
        ];

        $response = so_safe_remote_post($webhook, [
            'timeout' => 20,
            'headers' => ['Content-Type' => 'application/json'],
            'body' => wp_json_encode($payload, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES),
        ]);
        if (is_wp_error($response)) return false;
        $code = (int)wp_remote_retrieve_response_code($response);
        return $code >= 200 && $code < 300;
    }
    
    /**
     * الحصول على اسم نوع OSINT بالعربية
     */
    private static function get_osint_type_name($type_key) {
        $names = [
            'military' => 'العسكرية',
            'security' => 'الأمنية',
            'cyber' => 'السيبرانية',
            'political' => 'السياسية',
            'economic' => 'الاقتصادية',
            'social' => 'الاجتماعية',
            'media_psychological' => 'الإعلامية والنفسية',
            'energy' => 'الطاقة',
            'geostrategic' => 'الجيوستراتيجية'
        ];
        return $names[$type_key] ?? $type_key;
    }
}
}

