// 13. REST API Manager
// ==========================================================================
if (!class_exists('SO_API_Manager')) {
class SO_API_Manager {
    public static function init() { add_action('rest_api_init', [__CLASS__,'register_routes']); }
    public static function register_routes() {
        register_rest_route('osint/v1', '/events', ['methods'=>'GET','callback'=>[__CLASS__,'get_events'],'permission_callback'=>[__CLASS__,'check_auth']]);
        register_rest_route('osint/v1', '/analytics', ['methods'=>'GET','callback'=>[__CLASS__,'get_analytics'],'permission_callback'=>[__CLASS__,'check_auth']]);
        register_rest_route('osint/v1', '/trigger-cron', ['methods'=>'GET','callback'=>[__CLASS__,'run_external_cron'],'permission_callback'=>[__CLASS__,'check_auth']]);
        register_rest_route('osint/v1', '/brief', ['methods'=>'GET','callback'=>[__CLASS__,'get_brief'],'permission_callback'=>[__CLASS__,'check_auth']]);
        register_rest_route('osint/v1', '/archive-import', ['methods'=>'POST','callback'=>[__CLASS__,'archive_import'],'permission_callback'=>[__CLASS__,'check_auth']]);
    }
    public static function check_auth($request) {
        if (current_user_can('manage_options')) return true;
        $saved = get_option('so_external_api_key','');
        $prov  = $request->get_header('X-OSINT-API-KEY');
        $auth  = $request->get_header('Authorization');
        if ($prov && hash_equals($saved, $prov)) return true;
        if ($auth) { $token = str_replace('Bearer ','', $auth); if (hash_equals($saved, trim($token))) return true; }
        if ($request->get_param('key') && hash_equals($saved, (string)$request->get_param('key'))) return true;
        return new WP_Error('rest_forbidden','Unauthorized',['status'=>401]);
    }
    public static function run_external_cron() { return rest_ensure_response(['success'=>true,'inserted'=>SO_Cron_Manager::safe_sync_news()]); }
    public static function get_events($request) {
        global $wpdb; $limit = min((int)($request->get_param('limit')?:50),200);
        $events = $wpdb->get_results($wpdb->prepare("SELECT * FROM {$wpdb->prefix}so_news_events ORDER BY event_timestamp DESC LIMIT %d",$limit),ARRAY_A);
        return rest_ensure_response(['success'=>true,'data'=>$events]);
    }
    public static function get_analytics($request) {
        global $wpdb; $events = $wpdb->get_results("SELECT * FROM {$wpdb->prefix}so_news_events WHERE event_timestamp >= ".(time()-86400),ARRAY_A);
        return rest_ensure_response(['success'=>true,'data'=>sod_build_analytics($events?:[])]);
    }
    public static function get_brief($request) {
        $events = sod_get_events(['hours'=>24,'limit'=>20,'min_score'=>80]);
        $brief = SO_LLM_Engine::generate_intel_brief($events);
        return rest_ensure_response(['success'=>true,'brief'=>$brief,'generated_at'=>time()]);
    }
    public static function archive_import($request) {
        $params = $request->get_json_params();
        if (!is_array($params) || ($params['_type'] ?? '') !== 'archive_export' || empty($params['events']) || !is_array($params['events'])) {
            return new WP_REST_Response(['success'=>false,'message'=>'invalid archive payload'], 400);
        }
        if (class_exists('SO_Admin_UI') && method_exists('SO_Admin_UI', 'import_archive_events')) {
            $result = SO_Admin_UI::import_archive_events($params['events']);
            return rest_ensure_response(['success'=>true,'received'=>count($params['events']),'inserted'=>(int)($result['inserted'] ?? 0),'updated'=>(int)($result['updated'] ?? 0),'skipped'=>(int)($result['skipped'] ?? 0)]);
        }
        return new WP_REST_Response(['success'=>false,'message'=>'import handler unavailable'], 500);
    }
}
}

