// ==========================================================================
// 15. AJAX Handlers (V12 + V13 combined) - Security Hardened
// ==========================================================================

// Rate limiting helper function
function sod_check_rate_limit($action, $limit = 60, $window = 60) {
    $user_id = get_current_user_id();
    $ip = $_SERVER['REMOTE_ADDR'] ?? '0.0.0.0';
    $key = 'sod_rate_limit_' . md5($action . '_' . ($user_id ?: $ip));
    $attempts = (int)get_transient($key);
    
    if ($attempts >= $limit) {
        return false; // Rate limit exceeded
    }
    
    set_transient($key, $attempts + 1, $window);
    return true;
}

// Dashboard Data - Requires authentication and proper permissions
sod_register_ajax_once('sod_get_dashboard_data', 'sod_ajax_dashboard_data_v2', true);
// REMOVED: wp_ajax_nopriv_sod_get_dashboard_data - no longer available to unauthenticated users
function sod_ajax_dashboard_data_v2(): void {
    // Rate limiting check
    if (!sod_check_rate_limit('dashboard_data', 60, 60)) {
        wp_send_json_error(['message' => 'too_many_requests'], 429);
        return;
    }
    
    // Verify nonce for CSRF protection
    $nonce = sanitize_text_field(wp_unslash($_POST['nonce'] ?? $_GET['nonce'] ?? ''));
    if (empty($nonce) || wp_verify_nonce($nonce, SOD_AJAX_NONCE_ACTION) === false) {
        wp_send_json_error(['message' => 'خطأ في التحقق'], 403);
        return;
    }
    
    // Allow public dashboard rendering when a valid nonce is present; keep logged-in privilege check minimal
    if (is_user_logged_in() && !current_user_can('read')) {
        wp_send_json_error(['message' => 'غير مصرح'], 403);
        return;
    }
    
    $hours=(int)($_POST['hours']??24); $region=sanitize_text_field(wp_unslash($_POST['region']??'all')); $min_score=max(0,(int)($_POST['min_score']??0));
    $events=sod_get_events(['hours'=>max(1,min(8760,$hours)),'region'=>$region,'min_score'=>$min_score,'limit'=>2000]);
    $analytics=sod_build_analytics($events);
    $safe_events=array_map(function($ev){$wd=sod_parse_json_array($ev['war_data']??'{}');return['id'=>(int)$ev['id'],'title'=>wp_strip_all_tags((string)$ev['title']),'link'=>esc_url_raw((string)($ev['link']??SOD_TG_LINK)),'source_name'=>sanitize_text_field((string)$ev['source_name']),'source_color'=>sanitize_hex_color((string)($ev['source_color']??'#1da1f2'))?:'#1da1f2','intel_type'=>sanitize_text_field((string)$ev['intel_type']),'tactical_level'=>sanitize_text_field((string)$ev['tactical_level']),'region'=>sanitize_text_field((string)$ev['region']),'actor_v2'=>sanitize_text_field((string)$ev['actor_v2']),'score'=>(int)$ev['score'],'event_timestamp'=>(int)$ev['event_timestamp'],'image_url'=>esc_url_raw((string)($ev['image_url']??'')),'llm_verified'=>(bool)$ev['llm_verified'],'evaluation_mode'=>(string)($wd['evaluation_mode']??'auto'),'evaluation_label'=>(string)($wd['evaluation_label']??'آلي'),'has_manual_override'=>!empty(($wd['manual_override']['enabled']??false)),'war_data'=>$ev['war_data']??'{}','field_data'=>$ev['field_data']??'{}'];},array_slice($events,0,500));
    wp_send_json_success(['events'=>$safe_events,'analytics'=>$analytics,'time'=>time()]);
}

// Ticker Data - Requires authentication and proper permissions
sod_register_ajax_once('sod_get_ticker_data', 'sod_ajax_ticker_data_v2', true);
// REMOVED: wp_ajax_nopriv_sod_get_ticker_data - no longer available to unauthenticated users
function sod_ajax_ticker_data_v2(): void {
    // Rate limiting check
    if (!sod_check_rate_limit('ticker_data', 60, 60)) {
        wp_send_json_error(['message' => 'too_many_requests'], 429);
        return;
    }
    
    // Verify nonce for CSRF protection
    $nonce = sanitize_text_field(wp_unslash($_POST['nonce'] ?? $_GET['nonce'] ?? ''));
    if (empty($nonce) || wp_verify_nonce($nonce, SOD_AJAX_NONCE_ACTION) === false) {
        wp_send_json_error(['message' => 'خطأ في التحقق'], 403);
        return;
    }
    
    // Allow public dashboard rendering when a valid nonce is present; keep logged-in privilege check minimal
    if (is_user_logged_in() && !current_user_can('read')) {
        wp_send_json_error(['message' => 'غير مصرح'], 403);
        return;
    }
    
    $events=sod_get_events(['hours'=>6,'min_score'=>0,'limit'=>80]);
    $critical=array_filter($events,fn($e)=>(int)($e['score']??0)>=140);
    $region_scores=[];
    foreach($events as $ev){$r=sanitize_text_field((string)($ev['region']??'غير محدد'));$region_scores[$r]=($region_scores[$r]??0)+(int)($ev['score']??0);}
    arsort($region_scores);
    $map_headline=fn($e)=>['title'=>wp_strip_all_tags((string)$e['title']),'link'=>esc_url_raw((string)($e['link']??SOD_TG_LINK)),'score'=>(int)$e['score'],'region'=>sanitize_text_field((string)$e['region']),'source'=>sanitize_text_field((string)($e['source_name']??'')),'ts'=>(int)$e['event_timestamp']];
    $headlines=array_values(array_map($map_headline,array_slice($events,0,30)));
    wp_send_json_success(['critical'=>array_values(array_map($map_headline,$critical)),'headlines'=>$headlines,'region_scores'=>$region_scores,'total'=>count($events),'time'=>time()]);
}

// Threat Analysis - Requires authentication and proper permissions
sod_register_ajax_once('sod_get_threat_analysis', 'sod_ajax_threat_analysis_v2', true);
// REMOVED: wp_ajax_nopriv_sod_get_threat_analysis - no longer available to unauthenticated users
function sod_ajax_threat_analysis_v2(): void {
    // Rate limiting check
    if (!sod_check_rate_limit('threat_analysis', 60, 60)) {
        wp_send_json_error(['message' => 'too_many_requests'], 429);
        return;
    }
    
    // Verify nonce for CSRF protection
    $nonce = sanitize_text_field(wp_unslash($_POST['nonce'] ?? $_GET['nonce'] ?? ''));
    if (empty($nonce) || wp_verify_nonce($nonce, SOD_AJAX_NONCE_ACTION) === false) {
        wp_send_json_error(['message' => 'خطأ في التحقق'], 403);
        return;
    }
    
    // Allow public dashboard rendering when a valid nonce is present; keep logged-in privilege check minimal
    if (is_user_logged_in() && !current_user_can('read')) {
        wp_send_json_error(['message' => 'غير مصرح'], 403);
        return;
    }
    
    $events_72h=sod_get_events(['hours'=>72,'limit'=>1000]);
    $events_24h=array_values(array_filter($events_72h,fn($e)=>(int)($e['event_timestamp']??0)>=time()-86400));
    $analytics_24h=sod_build_analytics($events_24h);$analytics_72h=sod_build_analytics($events_72h);
    $actor_threats=[];
    foreach($analytics_24h['actors'] as $actor=>$score){$actor_threats[$actor]=['actor'=>$actor,'score'=>$score,'events'=>count(array_filter($events_24h,fn($e)=>$e['actor_v2']===$actor))];}
    arsort($actor_threats);
    $trend_data=[];
    for($i=11;$i>=0;$i--){$h_start=strtotime("-{$i} hours");$h_key=gmdate('Y-m-d H:00',$h_start);$trend_data[$h_key]=$analytics_72h['hourly'][$h_key]??0;}
    $top_regions=array_slice($analytics_24h['region_scores'],0,8,true);
    $momentum_change=0;
    if(!empty($analytics_72h['total'])&&!empty($analytics_24h['total'])){$expected_24h=$analytics_72h['total']/3;$momentum_change=$expected_24h>0?round((($analytics_24h['total']-$expected_24h)/$expected_24h)*100):0;}
    wp_send_json_success(['analytics_24h'=>$analytics_24h,'analytics_72h'=>$analytics_72h,'actor_threats'=>array_values(array_slice($actor_threats,0,10)),'trend_data'=>$trend_data,'top_regions'=>$top_regions,'momentum_change'=>$momentum_change,'time'=>time()]);
}

// Critical Popup - Requires authentication with proper permissions
sod_register_ajax_once('so_get_critical_popup', 'so_ajax_get_critical_popup_v2');
function so_ajax_get_critical_popup_v2(): void {
    // Verify nonce for CSRF protection
    $nonce = sanitize_text_field(wp_unslash($_POST['nonce'] ?? $_GET['nonce'] ?? ''));
    if (empty($nonce) || wp_verify_nonce($nonce, SOD_AJAX_NONCE_ACTION) === false) {
        wp_send_json_error(['message' => 'خطأ في التحقق'], 403);
        return;
    }
    
    if (is_user_logged_in() && !current_user_can('read')) {
        wp_send_json_error(['message' => 'غير مصرح'], 403);
        return;
    }
    
    $threshold=(int)get_option('so_popup_threshold',170);
    $recent_minutes=(int)get_option('so_popup_recent_minutes',20);
    $cutoff=time()-($recent_minutes*60);
    $events=sod_get_events(['hours'=>1,'min_score'=>$threshold,'limit'=>5]);
    $ev=null;
    foreach($events as $e){if((int)($e['event_timestamp']??0)>=$cutoff){$ev=['id'=>(int)$e['id'],'title'=>wp_strip_all_tags((string)$e['title']),'score'=>(int)$e['score'],'region'=>sanitize_text_field((string)$e['region']),'source_name'=>sanitize_text_field((string)$e['source_name']),'event_timestamp'=>(int)$e['event_timestamp'],'link'=>esc_url_raw((string)($e['link']??SOD_TG_LINK)),'telegram_link'=>esc_url(get_option('so_popup_telegram_link',SO_TELEGRAM_LINK))];break;}}
    wp_send_json_success(['event'=>$ev]);
}

