function sod_collect_bank_values_from_runtime(string $canonical): array {
    global $wpdb;
    $table = $wpdb->prefix . 'so_news_events';
    $values = [];
    switch ($canonical) {
        case 'actors':
            $values = array_merge(
                (array)$wpdb->get_col("SELECT DISTINCT name_ar FROM {$wpdb->prefix}so_dict_actors ORDER BY name_ar"),
                (array)$wpdb->get_col("SELECT DISTINCT actor_v2 FROM {$table} WHERE actor_v2 IS NOT NULL AND actor_v2 NOT IN ('','غير محدد','عام/مجهول','فاعل غير محسوم') ORDER BY actor_v2 LIMIT 300")
            );
            break;
        case 'types':
            $values = (array)$wpdb->get_col("SELECT DISTINCT intel_type FROM {$table} WHERE intel_type IS NOT NULL AND intel_type != '' ORDER BY intel_type");
            break;
        case 'levels':
            $values = (array)$wpdb->get_col("SELECT DISTINCT tactical_level FROM {$table} WHERE tactical_level IS NOT NULL AND tactical_level != '' ORDER BY tactical_level");
            break;
        case 'regions':
            $values = (array)$wpdb->get_col("SELECT DISTINCT region FROM {$table} WHERE region IS NOT NULL AND region != '' ORDER BY region");
            break;
        case 'targets':
            $values = (array)$wpdb->get_col("SELECT DISTINCT target_v2 FROM {$table} WHERE target_v2 IS NOT NULL AND target_v2 != '' ORDER BY target_v2 LIMIT 300");
            break;
        case 'contexts':
            $values = (array)$wpdb->get_col("SELECT DISTINCT context_actor FROM {$table} WHERE context_actor IS NOT NULL AND context_actor != '' ORDER BY context_actor LIMIT 300");
            break;
        case 'intents':
            $values = (array)$wpdb->get_col("SELECT DISTINCT intent FROM {$table} WHERE intent IS NOT NULL AND intent != '' ORDER BY intent LIMIT 300");
            break;
        case 'weapons':
            $values = array_merge(
                (array)$wpdb->get_col("SELECT DISTINCT name_ar FROM {$wpdb->prefix}so_dict_weapons ORDER BY name_ar"),
                (array)$wpdb->get_col("SELECT DISTINCT weapon_v2 FROM {$table} WHERE weapon_v2 IS NOT NULL AND weapon_v2 != '' ORDER BY weapon_v2 LIMIT 300")
            );
            break;
    }
    $values = sod_filter_bank_values(sod_normalize_string_list($values), $canonical);
    sort($values);
    return $values;
}

function sod_get_visible_learning_banks(): array {
    $defaults = sod_get_visible_learning_banks_seed();
    sod_self_heal_mojibake_options();
    $saved = get_option('sod_visible_learning_banks', []);
    if (!is_array($saved)) $saved = [];
    $registry = sod_get_bank_registry();
    $out = [];
    foreach (array_keys($registry) as $k) {
        $vals = [];
        foreach ($registry[$k]['aliases'] as $alias) {
            if (isset($saved[$alias]) && is_array($saved[$alias])) $vals = array_merge($vals, $saved[$alias]);
        }
        if (isset($saved[$k]) && is_array($saved[$k])) $vals = array_merge($vals, $saved[$k]);
        $vals = array_merge($defaults[$k] ?? [], $vals, sod_collect_bank_values_from_runtime($k));
        $vals = sod_filter_bank_values(sod_normalize_string_list($vals), $k);
        sort($vals);
        $out[$k] = $vals;
    }
    return $out;
}

function sod_save_visible_learning_banks(array $banks): void {
    $registry = sod_get_bank_registry();
    $normalized = [];
    foreach ($banks as $k => $vals) {
        $canon = sod_normalize_bank_key((string)$k);
        if (!isset($registry[$canon])) continue;
        if (!is_array($vals)) $vals = [];
        $vals = sod_filter_bank_values(sod_normalize_string_list($vals), $canon);
        sort($vals);
        $normalized[$canon] = $vals;
    }
    foreach (array_keys($registry) as $k) {
        if (!isset($normalized[$k])) $normalized[$k] = sod_get_visible_learning_banks_seed()[$k] ?? [];
    }
    update_option('sod_visible_learning_banks', $normalized, false);
}

function sod_get_bank_values(string $key): array {
    $banks = sod_get_visible_learning_banks();
    $canon = sod_normalize_bank_key($key);
    return $banks[$canon] ?? [];
}

function sod_add_bank_value(string $key, string $value, array $extra = []): array {
    global $wpdb;
    $canon = sod_normalize_bank_key($key);
    $value = trim((string)$value);
    if ($value === '') return sod_get_visible_learning_banks();
    
    $banks = sod_get_visible_learning_banks();
    if (!isset($banks[$canon])) $banks[$canon] = [];
    
    // دعم إضافة قيمة مع أوزان وكلمات مفتاحية مخصصة
    $entry = !empty($extra) ? array_merge(['term' => $value], $extra) : $value;
    
    if (!in_array($value, $banks[$canon], true) && !in_array($entry, $banks[$canon], true)) {
        $banks[$canon][] = $entry;
    }
    
    if ($canon === 'actors') {
        $exists = $wpdb->get_var($wpdb->prepare("SELECT id FROM {$wpdb->prefix}so_dict_actors WHERE name_ar=%s", $value));
        if (!$exists) {
            $next_id = (int)$wpdb->get_var("SELECT COALESCE(MAX(id),0)+1 FROM {$wpdb->prefix}so_dict_actors");
            $actor_id = 'ACT_CUSTOM_' . $next_id;
            $keywords = $extra['keywords'] ?? $value;
            $threat_weight = (float)($extra['threat_weight'] ?? 1.0);
            $base_threat = (int)($extra['base_threat'] ?? 50);
            $_res_actor = sod_db_safe_insert("{$wpdb->prefix}so_dict_actors", [
                'actor_id' => $actor_id,
                'name_ar' => $value,
                'threat_weight' => $threat_weight,
                'base_threat' => $base_threat,
                'keywords' => is_array($keywords) ? implode(',', $keywords) : $keywords
            ]);
        }
    } elseif ($canon === 'weapons') {
        $exists = $wpdb->get_var($wpdb->prepare("SELECT id FROM {$wpdb->prefix}so_dict_weapons WHERE name_ar=%s", $value));
        if (!$exists) {
            $next_id = (int)$wpdb->get_var("SELECT COALESCE(MAX(id),0)+1 FROM {$wpdb->prefix}so_dict_weapons");
            $weapon_id = 'WPN_CUSTOM_' . $next_id;
            $keywords = $extra['keywords'] ?? $value;
            $impact_score = (int)($extra['impact_score'] ?? 50);
            $_res_weapon = sod_db_safe_insert("{$wpdb->prefix}so_dict_weapons", [
                'weapon_id' => $weapon_id,
                'name_ar' => $value,
                'impact_score' => $impact_score,
                'keywords' => is_array($keywords) ? implode(',', $keywords) : $keywords
            ]);
        }
    }
    
    sod_save_visible_learning_banks($banks);
    return sod_get_visible_learning_banks();
}

function sod_remove_bank_value(string $key, string $value): array {
    global $wpdb;
    $canon = sod_normalize_bank_key($key);
    $value = trim((string)$value);
    $banks = sod_get_visible_learning_banks();
    if (!isset($banks[$canon])) return $banks;
    $banks[$canon] = array_values(array_filter($banks[$canon], function($v) use ($value) { return $v !== $value; }));
    sod_save_visible_learning_banks($banks);
    if ($canon === 'actors') {
        $wpdb->delete("{$wpdb->prefix}so_dict_actors", ['name_ar'=>$value]);
    } elseif ($canon === 'weapons') {
        $wpdb->delete("{$wpdb->prefix}so_dict_weapons", ['name_ar'=>$value]);
    }
    return sod_get_visible_learning_banks();
}



function sod_db_table_columns(string $table): array {
    global $wpdb;
    static $cache = [];
    if (isset($cache[$table])) return $cache[$table];
    $cols = $wpdb->get_col("DESC {$table}", 0);
    if (!is_array($cols)) $cols = [];
    $cache[$table] = $cols;
    return $cols;
}

function sod_db_filter_data_by_columns(string $table, array $data): array {
    $columns = sod_db_table_columns($table);
    $filtered = [];
    foreach ($data as $key => $value) {
        if (!in_array($key, $columns, true)) continue;
        if (is_array($value) || is_object($value)) {
            $value = wp_json_encode($value, JSON_UNESCAPED_UNICODE);
        }
        if ($value === null) $value = '';
        $filtered[$key] = $value;
    }
    return $filtered;
}

function sod_db_guess_format($value): string {
    if (is_int($value)) return '%d';
    if (is_float($value)) return '%f';
    return '%s';
}

function sod_db_build_formats(array $data): array {
    $formats = [];
    foreach ($data as $value) $formats[] = sod_db_guess_format($value);
    return $formats;
}

function sod_db_safe_insert(string $table, array $data): array {
    global $wpdb;
    $data = sod_db_filter_data_by_columns($table, $data);
    if (empty($data)) return ['ok'=>false,'error'=>'Insert skipped: no valid columns'];
    $result = $wpdb->insert($table, $data, sod_db_build_formats($data));
    if ($result === false) return ['ok'=>false,'error'=>$wpdb->last_error];
    return ['ok'=>true,'id'=>$wpdb->insert_id];
}

function sod_db_safe_update(string $table, array $data, array $where): array {
    global $wpdb;
    $data = sod_db_filter_data_by_columns($table, $data);
    $where = sod_db_filter_data_by_columns($table, $where);
    if (empty($data)) return ['ok'=>false,'error'=>'Update skipped: no valid data columns'];
    if (empty($where)) return ['ok'=>false,'error'=>'Update blocked: empty WHERE'];
    $result = $wpdb->update($table, $data, $where, sod_db_build_formats($data), sod_db_build_formats($where));
    if ($result === false) return ['ok'=>false,'error'=>$wpdb->last_error];
    return ['ok'=>true,'updated'=>$result];
}

function sod_db_safe_replace(string $table, array $data): array {
    global $wpdb;
    $data = sod_db_filter_data_by_columns($table, $data);
    if (empty($data)) return ['ok'=>false,'error'=>'Replace skipped: no valid columns'];
    $result = $wpdb->replace($table, $data, sod_db_build_formats($data));
    if ($result === false) return ['ok'=>false,'error'=>$wpdb->last_error];
    return ['ok'=>true,'updated'=>$result];
}

function sod_db_log_error(string $context, string $error, array $payload = []): void {
    error_log('[SOD_DB]['.$context.'] '.$error.' | '.wp_json_encode($payload, JSON_UNESCAPED_UNICODE));
}

function sod_db_ensure_news_events_columns(): void {
    global $wpdb;
    $table = $wpdb->prefix . 'so_news_events';
    $cols  = sod_db_table_columns($table);
    $queries = [];
    if (!in_array('actor_v2', $cols, true))      $queries[] = "ALTER TABLE {$table} ADD actor_v2 VARCHAR(255) NULL";
    if (!in_array('target_v2', $cols, true))     $queries[] = "ALTER TABLE {$table} ADD target_v2 TEXT NULL";
    if (!in_array('context_actor', $cols, true)) $queries[] = "ALTER TABLE {$table} ADD context_actor VARCHAR(255) NULL";
    if (!in_array('intent', $cols, true))        $queries[] = "ALTER TABLE {$table} ADD intent VARCHAR(255) NULL";
    if (!in_array('weapon_v2', $cols, true))     $queries[] = "ALTER TABLE {$table} ADD weapon_v2 VARCHAR(255) NULL";
    if (!in_array('status', $cols, true))        $queries[] = "ALTER TABLE {$table} ADD status VARCHAR(100) NULL";
    foreach ($queries as $sql) $wpdb->query($sql);
}

add_action('admin_init', function() {
    if (!get_option('sod_db_migrated_v32_safe')) {
        sod_db_ensure_news_events_columns();
        update_option('sod_db_migrated_v32_safe', 1);
    }
});


// ==========================================================================
// 15b. SO_Executive_Reports — التقارير الدورية للمجتمع الاستخباراتي
// ==========================================================================
if (!class_exists('SO_Executive_Reports')) {
class SO_Executive_Reports {
    const CRON_HOOK = 'so_cron_executive_report';

    public static function init() {
        add_filter('cron_schedules', [__CLASS__, 'register_schedules']);
        add_action(self::CRON_HOOK, [__CLASS__, 'maybe_send_scheduled_report']);
        add_action('so_exec_refresh_cache', [__CLASS__, 'refresh_cached_report_async']);
        add_action('init', [__CLASS__, 'queue_auto_refresh_if_needed']);
        add_action('admin_post_so_send_exec_report_now', [__CLASS__, 'send_now']);
        add_action('wp_ajax_so_send_exec_report_ajax', [__CLASS__, 'send_now_ajax']);
        add_action('wp_ajax_so_exec_generate_report_ajax', [__CLASS__, 'generate_report_ajax']);
        add_action('wp_ajax_so_send_exec_report_word_ajax', [__CLASS__, 'send_word_ajax_v2']);
        add_action('wp_ajax_so_send_exec_report_pdf_ajax', [__CLASS__, 'send_pdf_ajax_v2']);
    }

    public static function register_schedules($schedules) {
        $custom_hours = max(1, (int) get_option('so_exec_reports_custom_hours', 6));
        $schedules['every_hour']       = ['interval' => HOUR_IN_SECONDS, 'display' => 'كل ساعة'];
        $schedules['every_six_hours']  = ['interval' => 6 * HOUR_IN_SECONDS, 'display' => 'كل 6 ساعات'];
        $schedules['every_custom']     = ['interval' => $custom_hours * HOUR_IN_SECONDS, 'display' => "كل {$custom_hours} ساعة"];
        return $schedules;
    }

    public static function activate() { self::reschedule(); }
    public static function deactivate() { wp_clear_scheduled_hook(self::CRON_HOOK); }

    public static function reschedule() {
        wp_clear_scheduled_hook(self::CRON_HOOK);
        if (!get_option('so_exec_reports_enabled', 1)) return;
        $freq = get_option('so_exec_reports_frequency', 'every_custom');
        if (!in_array($freq, ['every_hour', 'every_six_hours', 'every_custom', 'daily', 'hourly'], true)) $freq = 'every_custom';
        if (!wp_next_scheduled(self::CRON_HOOK)) wp_schedule_event(time() + 300, $freq, self::CRON_HOOK);
    }

    public static function get_dataset_signature() {
        global $wpdb;
        $window_hours = max(1, intval(get_option('so_exec_reports_window_hours', 72)));
        $cutoff = time() - ($window_hours * HOUR_IN_SECONDS);
        $row = $wpdb->get_row($wpdb->prepare(
            "SELECT COUNT(*) AS total_count, MAX(event_timestamp) AS max_ts, MAX(id) AS max_id, SUM(COALESCE(threat_score,0)) AS score_sum FROM {$wpdb->prefix}so_news_events WHERE status='published' AND event_timestamp >= %d",
            $cutoff
        ), ARRAY_A);
        $parts = [
            'w' . $window_hours,
            'c' . (int)($row['total_count'] ?? 0),
            'ts' . (int)($row['max_ts'] ?? 0),
            'id' . (int)($row['max_id'] ?? 0),
            's' . (int)($row['score_sum'] ?? 0),
        ];
        return md5(implode('|', $parts));
    }

    public static function get_cached_report() {
        $report = get_option('so_exec_cached_report_payload', []);
        return is_array($report) ? $report : [];
    }

    public static function refresh_cached_report($force = false) {
        $lock_key = 'so_exec_report_build_lock';
        if (get_transient($lock_key)) {
            return self::get_cached_report();
        }
        $current_sig = self::get_dataset_signature();
        $saved_sig = (string) get_option('so_exec_cached_report_signature', '');
        if (!$force && $saved_sig !== '' && hash_equals($saved_sig, $current_sig)) {
            return self::get_cached_report();
        }
        set_transient($lock_key, 1, 120);
        try {
            $report = self::build_report();
            if (!is_array($report)) $report = ['text' => ''];
            update_option('so_exec_cached_report_payload', $report, false);
            update_option('so_exec_cached_report_signature', $current_sig, false);
            update_option('so_exec_cached_report_built_at', time(), false);
            return $report;
        } finally {
            delete_transient($lock_key);
        }
    }

    public static function get_or_build_report($force = false) {
        $cached = self::get_cached_report();
        $cached_sig = (string) get_option('so_exec_cached_report_signature', '');
        $current_sig = self::get_dataset_signature();
        if (!$force && !empty($cached) && $cached_sig !== '' && hash_equals($cached_sig, $current_sig)) {
            return $cached;
        }
        return self::refresh_cached_report(true);
    }

    public static function queue_auto_refresh_if_needed() {
        if (!get_option('so_exec_reports_enabled', 1)) return;
        $current_sig = self::get_dataset_signature();
        $saved_sig = (string) get_option('so_exec_cached_report_signature', '');
        if ($saved_sig !== '' && hash_equals($saved_sig, $current_sig)) return;
        if (!wp_next_scheduled('so_exec_refresh_cache')) {
            wp_schedule_single_event(time() + 20, 'so_exec_refresh_cache');
        }
    }

    public static function refresh_cached_report_async() {
        self::refresh_cached_report(true);
    }

    public static function build_report() {
        global $wpdb;
        $window_hours       = max(1, intval(get_option('so_exec_reports_window_hours', 72)));
        $critical_threshold = max(1, intval(get_option('so_exec_reports_critical_threshold', 140)));
        $cutoff = time() - ($window_hours * HOUR_IN_SECONDS);

        $events = $wpdb->get_results($wpdb->prepare(
            "SELECT * FROM {$wpdb->prefix}so_news_events WHERE status='published' AND event_timestamp >= %d ORDER BY event_timestamp DESC LIMIT 250",
            $cutoff
        ), ARRAY_A);

        if (empty($events)) {
            return ['text' => "🧭 التقدير الاستخباراتي — Beiruttime OSINT\n\nلا توجد أحداث منشورة كافية خلال آخر {$window_hours} ساعة."];
        }

        $events = array_values(array_filter($events, function($e){
            return function_exists('so_is_non_intel_noise') ? !so_is_non_intel_noise((string)($e['title'] ?? '')) : true;
        }));

        if (empty($events)) {
            return ['text' => "🧭 التقدير الاستخباراتي — Beiruttime OSINT\n\nلا توجد أحداث استخباراتية صالحة خلال آخر {$window_hours} ساعة."];
        }

        $total = count($events);
        $sum = 0;
        $critical = 0;
        $max_score = 0;
        $max_event = null;
        $region_map = [];
        $actor_map = [];
        $type_map = [];
        $target_map = [];
        $context_actor_map = [];
        $intent_map = [];
        $unknown_actors = ['عام/مجهول','غير محدد','مجهول','','عام','فاعل غير محسوم','فاعل سياقي غير مباشر','فاعل سياقي','جهة غير معلنة','محتوى إعلامي / غير عملياتي'];
        $attr_counts = ['confirmed'=>0,'inferred'=>0,'claimed'=>0,'contested'=>0,'unattributed'=>0];
        
        // دمج تحليل الحرب المركبة والتحقق والإنذار المبكر
        $hybrid_layers_count = [
            'military' => 0, 'security' => 0, 'cyber' => 0, 'political' => 0,
            'economic' => 0, 'social' => 0, 'media_psychological' => 0,
            'energy' => 0, 'geostrategic' => 0
        ];
        $hybrid_combinations = [];
        $verification_stats = ['verified'=>0, 'partial'=>0, 'unverified'=>0, 'avg_confidence'=>0];
        $confidence_sum = 0;
        $early_warnings = [];
        $actor_networks = [];
        $hybrid_theater_index = [];

        foreach ($events as $e) {
            $u = sod_get_unified_event_state($e);
            $fd = $u['field_data'];
            $war = $u['war_data'];
            $s = (int)max((int)($u['threat_score'] ?? 0), (int)($u['score'] ?? 0));
            $sum += $s;
            if ($s >= $critical_threshold) $critical++;
            if ($s > $max_score) { $max_score = $s; $max_event = array_merge($e, ['region'=>$u['region'], 'actor_v2'=>$u['actor']]); }

            $r = trim((string)$u['region']);
            if ($r === '') $r = 'ساحة الصراع (استنتاج)';
            $region_map[$r] = ($region_map[$r] ?? 0) + 1;

            $a = trim((string)$u['actor']);
            if ($a !== '' && !in_array($a, $unknown_actors, true) && !sod_is_media_source_actor($a) && !preg_match('/(منظومة الإنذار|الجبهة الداخلية)/ui', $a)) {
                $actor_map[$a] = ($actor_map[$a] ?? 0) + 1;
            }

            $t = trim((string)$u['intel_type']);
            if ($t === '') $t = 'عام';
            $type_map[$t] = ($type_map[$t] ?? 0) + 1;

            $attr_label = trim((string)($u['actor_confidence_label'] ?? ''));
            if ($attr_label === 'مؤكد') $attr_counts['confirmed']++;
            elseif ($attr_label === 'مرجّح') $attr_counts['inferred']++;
            elseif ($attr_label === 'استنتاج') $attr_counts['claimed']++;
            else $attr_counts['unattributed']++;

            $ma = $fd['multi_actor'] ?? [];
            $target = trim((string)($e['target_v2'] ?? ($ma['target'] ?? '')));
            if ($target !== '') $target_map[$target] = ($target_map[$target] ?? 0) + 1;
            $ctx = trim((string)($e['context_actor'] ?? ($ma['context_actor'] ?? '')));
            if ($ctx !== '') $context_actor_map[$ctx] = ($context_actor_map[$ctx] ?? 0) + 1;
            $intent = trim((string)($e['intent'] ?? ($ma['intent'] ?? '')));
            if ($intent !== '') $intent_map[$intent] = ($intent_map[$intent] ?? 0) + 1;

            $normalized_layers = (array)($u['hybrid_layers'] ?? []);
            foreach ($normalized_layers as $canonical) {
                if (isset($hybrid_layers_count[$canonical])) {
                    $hybrid_layers_count[$canonical]++;
                }
            }
            $normalized_layers = array_values(array_unique(array_filter($normalized_layers)));
            if (count($normalized_layers) >= 2) {
                sort($normalized_layers);
                $combo_key = implode('+', array_slice($normalized_layers, 0, 2));
                $hybrid_combinations[$combo_key] = ($hybrid_combinations[$combo_key] ?? 0) + 1;
            }

            $conf = (float)($u['actor_confidence'] ?? 0);
            if ($conf >= 90) {
                $verification_stats['verified']++;
            } elseif ($conf >= 75) {
                $verification_stats['partial']++;
            } else {
                $verification_stats['unverified']++;
            }
            $confidence_sum += $conf;

            if (!empty($ma['network']) && is_array($ma['network'])) {
                foreach ($ma['network'] as $net_item) {
                    $actor_name = is_array($net_item) ? ($net_item['actor'] ?? '') : $net_item;
                    if ($actor_name && !sod_is_media_source_actor($actor_name)) {
                        $actor_networks[$actor_name] = ($actor_networks[$actor_name] ?? 0) + 1;
                    }
                }
            }
        }

        
        // حساب متوسط الثقة
        $verification_stats["avg_confidence"] = $total > 0 ? round($confidence_sum / $total, 2) : 0;
        
        // توليد تحذيرات مبكرة بناءً على الأنماط
        arsort($hybrid_layers_count);
        arsort($hybrid_combinations);
        $top_layers = array_slice($hybrid_layers_count, 0, 3, true);
        $top_combos = array_slice($hybrid_combinations, 0, 3, true);
        
        if (!empty($top_combos)) {
            foreach ($top_combos as $combo => $count) {
                if ($count >= 3) {
                    $early_warnings[] = [
                        "type" => "hybrid_combo",
                        "level" => $count >= 5 ? "critical" : "high",
                        "message" => "توليفة مركبة متكررة: " . sod_translate_hybrid_combo_label((string)$combo) . " ({$count} مرات)",
                        "recommendation" => "مراقبة التصعيد متعدد الأبعاد"
                    ];
                }
            }
        }
        
        if ($verification_stats["avg_confidence"] < 0.5 && $total > 10) {
            $early_warnings[] = [
                "type" => "low_confidence",
                "level" => "medium",
                "message" => "متوسط الثقة منخفض: {$verification_stats["avg_confidence"]}",
                "recommendation" => "تشديد التحقق قبل الاستنتاج"
            ];
        }

        $hybrid_theater_index = function_exists('sod_compute_hybrid_theater_index') ? sod_compute_hybrid_theater_index($events, $critical_threshold) : [];
        $top_hybrid_theaters = array_slice($hybrid_theater_index, 0, 3, true);
        foreach ($top_hybrid_theaters as $theater_name => $theater_data) {
            if (($theater_data['index'] ?? 0) >= 75) {
                $early_warnings[] = [
                    "type" => "hybrid_theater",
                    "level" => (($theater_data['index'] ?? 0) >= 90 ? "critical" : "high"),
                    "message" => "ساحة {$theater_name}: مؤشر الحرب المركبة {$theater_data['index']}/100 — {$theater_data['alert']}",
                    "recommendation" => "مراقبة الساحة الأعلى تركّزًا وتوليفاتها الغالبة"
                ];
            }
        }
        arsort($region_map);
        arsort($actor_map);
        arsort($type_map);
        arsort($target_map);
        arsort($context_actor_map);
        arsort($intent_map);

        $avg_score = $total ? (int) round($sum / $total) : 0;
        $top_regions = array_slice($region_map, 0, 5, true);
        $top_actors = array_slice($actor_map, 0, 5, true);
        $top_types = array_slice($type_map, 0, 5, true);
        $top_targets = array_slice($target_map, 0, 5, true);
        $top_context = array_slice($context_actor_map, 0, 5, true);
        $top_intents = array_slice($intent_map, 0, 5, true);

        $half = $cutoff + (int)(($window_hours * HOUR_IN_SECONDS) / 2);
        $older = array_values(array_filter($events, fn($e) => (int)$e['event_timestamp'] < $half));
        $newer = array_values(array_filter($events, fn($e) => (int)$e['event_timestamp'] >= $half));

        $older_critical = count(array_filter($older, fn($e) => (int)($e['score'] ?? 0) >= $critical_threshold));
        $newer_critical = count(array_filter($newer, fn($e) => (int)($e['score'] ?? 0) >= $critical_threshold));
        $older_avg = count($older) ? (array_sum(array_map(fn($e)=>(int)($e['score']??0), $older)) / count($older)) : 0;
        $newer_avg = count($newer) ? (array_sum(array_map(fn($e)=>(int)($e['score']??0), $newer)) / count($newer)) : 0;
        $critical_delta = $older_critical > 0 ? (($newer_critical - $older_critical) / $older_critical) : ($newer_critical > 0 ? 1 : 0);
        $avg_delta = $newer_avg - $older_avg;

        if ($critical_delta >= 0.20 || $avg_delta >= 12) $trend = 'تصاعدي ↑';
        elseif ($critical_delta <= -0.20 || $avg_delta <= -12) $trend = 'متراجع ↓';
        elseif ($critical >= 20 || $avg_score >= 140) $trend = 'ثابت تحت ضغط';
        else $trend = 'متذبذب ↕';

        if ($critical >= 30 || $avg_score >= 170) $threat_level = 'حرج جدًا';
        elseif ($critical >= 15 || $avg_score >= 130) $threat_level = 'مرتفع جدًا';
        elseif ($critical >= 6 || $avg_score >= 90) $threat_level = 'مرتفع';
        elseif ($avg_score >= 55) $threat_level = 'متوسط';
        else $threat_level = 'منخفض';

        $months_ar = ['','يناير','فبراير','مارس','أبريل','مايو','يونيو','يوليو','أغسطس','سبتمبر','أكتوبر','نوفمبر','ديسمبر'];
        $month_ar = $months_ar[(int)wp_date('n')] ?? wp_date('F');
        $date_str = wp_date('d') . ' ' . $month_ar . ' ' . wp_date('Y') . ' — ' . wp_date('H:i');

        $unattributed_ratio = $total ? (($attr_counts['unattributed'] ?? 0) / $total) : 0;
        $top_region = (string)(array_key_first($top_regions) ?: 'غير محدد');
        $dominant_type = (string)(array_key_first($top_types) ?: 'عام');
        $top_intent = (string)(array_key_first($top_intents) ?: '');

        $lead = 'المشهد ضمن هذه النافذة يميل إلى ضغط تشغيلي واضح دون دلائل كافية على انحسار قريب.';
        if ($top_region === 'لبنان' && $dominant_type === 'عسكري/أمني') {
            $lead = 'الثقل الرئيسي يتمركز على الساحة اللبنانية بطابع عسكري/أمني صريح، مع استمرار الضغط الميداني بوتيرة مرتفعة.';
        } elseif ($top_region === 'الأراضي المحتلة (إسرائيل)') {
            $lead = 'النافذة الحالية تعكس ضغطًا مباشرًا على الجبهة الداخلية في الأراضي المحتلة أكثر من كونها مجرد متابعة إعلامية.';
        } elseif ($dominant_type === 'سياسي') {
            $lead = 'الحضور السياسي في هذه النافذة بارز، ما يشير إلى مشهد تدفعه الرسائل والتفاوض أكثر من الاشتباك المباشر.';
        }

        $analysis = [];
        $analysis[] = $lead;
        if ($newer_critical > $older_critical) $analysis[] = 'مقارنة بالنصف الأول من النافذة، ارتفع عدد الأحداث الحرجة في النصف الأخير، ما يدعم قراءة اتجاه تصاعدي.';
        elseif ($newer_critical < $older_critical) $analysis[] = 'وتيرة الأحداث الحرجة في النصف الأخير أقل من النصف الأول، ما يشير إلى تباطؤ نسبي لا إلى هدوء فعلي.';
        else $analysis[] = 'عدد الأحداث الحرجة بقي قريبًا من النصف الأول، ما يعكس ثباتًا تحت ضغط أكثر من كونه استقرارًا مريحًا.';
        if ($unattributed_ratio >= 0.60) $analysis[] = 'حجم الأخبار غير المنسوبة ما زال مرتفعًا جدًا، ما يفرض تخفيض الثقة في بعض الاستنتاجات السريعة.';
        if ($top_intent !== '') $analysis[] = 'النية التشغيلية الأكثر حضورًا في هذه النافذة تبدو: ' . $top_intent . '.';

        $recommendations = [];
        if ($critical >= 25) $recommendations[] = 'رفع مستوى الجهوزية التشغيلية فورًا لأن كثافة الأحداث الحرجة تجاوزت النطاق الاعتيادي بوضوح.';
        elseif ($critical >= 10) $recommendations[] = 'الحفاظ على تحديث تقدير الموقف على فواصل زمنية أقصر لأن مستوى الخطورة ما زال مرتفعًا.';
        else $recommendations[] = 'الإبقاء على المراقبة المركزة دون توسيع الاستجابة قبل ظهور مؤشرات إضافية.';
        if ($top_region === 'لبنان') $recommendations[] = 'توجيه جهد الرصد الأساسي إلى الساحة اللبنانية لأنها ما زالت مركز الثقل الميداني الأبرز.';
        elseif ($top_region === 'الأراضي المحتلة (إسرائيل)') $recommendations[] = 'تكثيف متابعة الجبهة الداخلية في الأراضي المحتلة وربط الإنذارات بالأثر الميداني الفعلي.';
        else $recommendations[] = 'رفع أولوية المتابعة على الساحة الأكثر نشاطًا في هذه النافذة: ' . $top_region . '.';
        if ($dominant_type === 'عسكري/أمني') $recommendations[] = 'تركيز الرصد على الضربات الجوية، الصليات، الأهداف الحساسة، والتحركات الميدانية السريعة.';
        elseif ($dominant_type === 'سياسي') $recommendations[] = 'زيادة وزن متابعة التصريحات والتفاهمات والوفود لأنها تشكل المحرك الرئيسي للمشهد الحالي.';
        if ($unattributed_ratio >= 0.55) $recommendations[] = 'تعليق أي استنتاج حاسم على الأخبار غير المنسوبة إلى حين تجميع المتشابه منها والتحقق المتقاطع من مصادرها.';

        $top_developments = function_exists('so_pick_top_developments') ? so_pick_top_developments($events, 8) : array_slice($events, 0, 8);
        $footer = trim((string) get_option('so_exec_reports_footer', 'Beiruttime OSINT Executive Brief'));
        $recommendations = array_values(array_unique($recommendations));
        $decision_points = [];
        $decision_points[] = 'الاتجاه العام خلال النافذة الحالية: ' . $trend . ' مع مستوى خطر ' . $threat_level . '.';
        $decision_points[] = 'الساحة الأكثر نشاطا في هذه النافذة: ' . $top_region . '.';
        $decision_points[] = !empty($top_actors) ? 'الفاعل الأكثر حضورا: ' . (string)array_key_first($top_actors) . '.' : 'لا يوجد فاعل مهيمن بشكل كاف ضمن هذه النافذة.';
        if ($top_intent !== '') $decision_points[] = 'النية التشغيلية الأكثر تكرارا: ' . $top_intent . '.';
        $what_changed = [];
        if ($newer_critical > $older_critical) $what_changed[] = 'ارتفع حجم الأحداث الحرجة في النصف الأخير من النافذة مقارنة بالنصف الأول.';
        elseif ($newer_critical < $older_critical) $what_changed[] = 'تراجع حجم الأحداث الحرجة في النصف الأخير، لكن دون مؤشرات كافية على انفراج مستدام.';
        else $what_changed[] = 'بقي مستوى الضغط الحرج مستقرا نسبيا بين شطري النافذة الزمنية.';
        $what_changed[] = 'استمر تمركز النشاط حول ' . $top_region . ' بوصفها الساحة الأعلى كثافة.';
        if (!empty($top_actors)) $what_changed[] = 'الفاعل الأبرز في هذه النافذة كان ' . (string)array_key_first($top_actors) . '.';

        $why_matters = [];
        $why_matters[] = 'هذا النمط يعني أن هامش المناورة السياسية والأمنية ما زال ضيقا ضمن المدى القريب.';
        if ($dominant_type === 'عسكري/أمني') $why_matters[] = 'غلبة الطابع العسكري/الأمني ترفع احتمالات الانزلاق أو سوء التقدير الميداني.';
        if ($dominant_type === 'سياسي') $why_matters[] = 'غلبة المسار السياسي تعني أن الرسائل والتموضع التفاوضي قد يسبقان أي تحول ميداني مباشر.';
        if ($unattributed_ratio >= 0.55) $why_matters[] = 'ارتفاع نسبة الإسناد الضعيف يفرض حذرا أكبر في القرارات الحساسة ويستدعي تحققًا تقاطعيًا.';

        $strategic_implications = [];
        $strategic_implications[] = 'المدى القصير: بقاء وتيرة الضغط مرتفعة مع حساسية عالية لأي حادث نوعي إضافي.';
        $strategic_implications[] = 'المدى المتوسط: استمرار هذا المسار قد يعيد ترتيب أولويات الفاعلين واتجاهات الردع والاحتواء.';
        if ($top_region === 'إيران') $strategic_implications[] = 'الثقل المتركز على الساحة الإيرانية يجعلها محور قراءة التأثيرات السياسية والإقليمية المباشرة.';
        if ($top_region === 'لبنان') $strategic_implications[] = 'الثقل المتركز على الساحة اللبنانية يعني أن أي توسع موضعي قد ينعكس بسرعة على الإقليم.';

        $decision_options = [];
        $decision_options[] = 'الخيار 1: الحفاظ على المراقبة المشددة دون إعلان إجراءات تصعيدية إضافية.';
        $decision_options[] = 'الخيار 2: رفع الإيقاع الدبلوماسي/الإعلامي الاستباقي لاحتواء التصعيد وإعادة ضبط السردية.';
        $decision_options[] = 'الخيار 3: تفعيل مراجعة يومية مختصرة على مستوى القيادة مع تحديث تقدير الموقف كل 12 إلى 24 ساعة.';

        $collection_gaps = [];
        if ($unattributed_ratio >= 0.55) $collection_gaps[] = 'فجوة إسناد: نسبة معتبرة من الأحداث ما زالت غير منسوبة بما يكفي للحسم السريع.';
        if (empty($top_targets)) $collection_gaps[] = 'فجوة أهداف: لا يظهر نمط أهداف متكرر بما يسمح ببناء مصفوفة استهداف مستقرة.';
        if (empty($top_context)) $collection_gaps[] = 'فجوة سياق: لا توجد جهة سياقية مهيمنة بما يكفي لربط المشهد بخط حملة واضح.';
        if (empty($top_intents)) $collection_gaps[] = 'فجوة نوايا: النية الغالبة لا تزال أقل وضوحا من المطلوب لبناء تقدير نوايا حاسم.';
        if (empty($collection_gaps)) $collection_gaps[] = 'فجوات الجمع ضمن هذه النافذة محدودة نسبيًا، لكن التحقق المتقاطع يبقى مطلوبًا.';

        $L = [];
        $L[] = '🧭 الإحاطة التنفيذية متعددة الفاعلين — Beiruttime OSINT';
        $L[] = '⏱️ نافذة التقييم: آخر ' . $window_hours . ' ساعة | 📅 ' . $date_str;
        $L[] = '';
        $L[] = '🔴 مستوى الخطر: ' . $threat_level . ' — الاتجاه: ' . $trend;
        $L[] = '';
        $L[] = '━━━━━━━━━━━━━━━━';
        $L[] = '📌 الحكم التنفيذي:';
        $L[] = '• ' . $lead;
        foreach (array_slice($decision_points, 0, 3) as $point) $L[] = '• ' . $point;
        $L[] = '';
        $L[] = '📊 المؤشرات الأساسية:';
        $L[] = '• إجمالي الأحداث: ' . $total;
        $L[] = '• الأحداث الحرجة (≥' . $critical_threshold . '): ' . $critical;
        $L[] = '• متوسط الخطورة: ' . $avg_score;
        if ($max_event) {
            $max_title_short = sod_safe_substr(wp_strip_all_tags((string)($max_event['title'] ?? '')), 0, 110);
            $max_region = trim((string)($max_event['region'] ?? ''));
            $L[] = '• الحدث الأعلى تأثيرا: [' . $max_score . '] ' . $max_title_short . (($max_region && $max_region !== 'غير محدد') ? ' — ' . $max_region : '');
        }
        $L[] = '';
        $L[] = '🌍 البؤر الرئيسية:';
        foreach ($top_regions as $r => $cnt) $L[] = '• ' . $r . ': ' . $cnt . ' حدث';
        $L[] = '';
        $L[] = '🎯 الفاعلون الرئيسيون:';
        if (!empty($top_actors)) foreach ($top_actors as $a => $cnt) $L[] = '• ' . $a . ': ' . $cnt . ' ظهور';
        else $L[] = '• لا توجد جهة فاعلة مرجحة بما يكفي ضمن هذه النافذة.';
        $L[] = '';
        $L[] = '🛡️ الأهداف/الجهات المتأثرة:';
        if (!empty($top_targets)) foreach ($top_targets as $a => $cnt) $L[] = '• ' . $a . ': ' . $cnt;
        else $L[] = '• لا توجد أهداف متكررة كفاية لاستخلاص نمط واضح.';
        $L[] = '';
        $L[] = '🧠 الجهات/السياقات المؤثرة:';
        if (!empty($top_context)) foreach ($top_context as $a => $cnt) $L[] = '• ' . $a . ': ' . $cnt;
        else $L[] = '• لا توجد جهة سياقية مهيمنة بوضوح.';
        $L[] = '';
        $L[] = '🎯 النوايا/الوظائف الغالبة:';
        if (!empty($top_intents)) foreach ($top_intents as $a => $cnt) $L[] = '• ' . $a . ': ' . $cnt;
        else $L[] = '• لا توجد نية تشغيلية واضحة بما يكفي.';
        $L[] = '';
        $L[] = '🏟️ أخطر 3 ساحات في الحرب المركبة:';
        if (!empty($top_hybrid_theaters)) {
            foreach ($top_hybrid_theaters as $theater_name => $theater_data) {
                $line = '• ' . $theater_name . ': ' . $theater_data['index'] . '/100 — ' . $theater_data['alert'];
                if (!empty($theater_data['top_combo_label'])) {
                    $line .= ' | التوليفة الأبرز: ' . $theater_data['top_combo_label'];
                }
                $L[] = $line;
            }
        } else {
            $L[] = '• لا توجد ساحات مركبة كافية للحساب.';
        }
        $L[] = '';
        $L[] = '🧩 الأنماط الغالبة:';
        foreach ($top_types as $t => $cnt) $L[] = '• ' . $t . ': ' . $cnt . ' حدث';
        $L[] = '';
        $L[] = '⚡ التطورات الأبرز:';
        foreach ($top_developments as $e) {
            $s = (int)($e['score'] ?? 0);
            $title = trim((string)($e['title'] ?? ''));
            $region = trim((string)($e['region'] ?? ''));
            $L[] = '• [' . $s . '] ' . sod_safe_substr($title, 0, 110) . (($region && $region !== 'غير محدد') ? ' — ' . $region : '');
        }
        $L[] = '';
        $L[] = '🧠 القراءة التحليلية:';
        foreach ($analysis as $line) $L[] = '• ' . $line;
        $L[] = '';
        $L[] = '🕳️ جودة الإسناد:';
        $L[] = '• مؤكد: ' . (int)($attr_counts['confirmed'] ?? 0);
        $L[] = '• استنتاجي: ' . (int)($attr_counts['inferred'] ?? 0);
        $L[] = '• منسوب: ' . (int)($attr_counts['claimed'] ?? 0);
        $L[] = '• غير منسوب: ' . (int)($attr_counts['unattributed'] ?? 0);
        $L[] = '';
        $L[] = '🟢 أولويات العمل:';
        foreach ($recommendations as $rec) $L[] = '• ' . $rec;
        $L[] = '';
        $L[] = '— ' . $footer;

        $report = [
            'text' => implode("\n", $L),
            'generated_at' => $date_str,
            'window_hours' => $window_hours,
            'threat_level' => $threat_level,
            'trend' => $trend,
            'lead' => $lead,
            'decision_points' => $decision_points,
            'what_changed' => $what_changed,
            'why_matters' => $why_matters,
            'strategic_implications' => $strategic_implications,
            'decision_options' => $decision_options,
            'collection_gaps' => $collection_gaps,
            'total' => $total,
            'critical' => $critical,
            'critical_threshold' => $critical_threshold,
            'avg_score' => $avg_score,
            'max_score' => $max_score,
            'max_event' => $max_event,
            'top_regions' => $top_regions,
            'top_actors' => $top_actors,
            'top_targets' => $top_targets,
            'top_context' => $top_context,
            'top_intents' => $top_intents,
            'top_types' => $top_types,
            'analysis' => $analysis,
            'recommendations' => $recommendations,
            'top_developments' => $top_developments,
            'attr_counts' => $attr_counts,
            'footer' => $footer,
            // بيانات الحرب المركبة والتحقق والإنذار المبكر
            'hybrid_layers_count' => $hybrid_layers_count,
            'hybrid_combinations' => $hybrid_combinations,
            'verification_stats' => $verification_stats,
            'early_warnings' => $early_warnings,
            'actor_networks' => $actor_networks,
            'hybrid_theater_index' => $hybrid_theater_index,
            'top_hybrid_theaters' => $top_hybrid_theaters,
        ];
        $local_brief = self::generate_local_exec_brief($report);
        if ($local_brief !== '') {
            $report['local_brief'] = $local_brief;
            $report['lead'] = $local_brief;
        }
        $mode = (string) get_option('so_exec_report_generation_mode', 'local');
        if ($mode === 'ai') {
            $ai_brief = self::generate_ai_exec_brief($events, $report);
            if (is_string($ai_brief) && trim($ai_brief) !== '') {
                $report['ai_brief'] = trim($ai_brief);
                $report['lead'] = trim($ai_brief);
                $report['text'] = "🧠 موجز تنفيذي مولّد بالذكاء الاصطناعي:\n" . trim($ai_brief) . "\n\n" . $report['text'];
            } elseif ($local_brief !== '') {
                $report['text'] = "🧠 موجز تنفيذي محلي محسّن:\n" . $local_brief . "\n\n" . $report['text'];
            }
        } elseif ($local_brief !== '') {
            $report['text'] = "🧠 موجز تنفيذي محلي محسّن:\n" . $local_brief . "\n\n" . $report['text'];
        }
        return $report;
    }

    private static function generate_local_exec_brief(array $report): string {
        $total = (int)($report['total'] ?? 0);
        $critical = (int)($report['critical'] ?? 0);
        $threat = (string)($report['threat_level'] ?? 'غير محدد');
        $trend = (string)($report['trend'] ?? 'غير واضح');
        $top_region = (string)(array_key_first((array)($report['top_regions'] ?? [])) ?? 'غير محدد');
        $top_actor = (string)(array_key_first((array)($report['top_actors'] ?? [])) ?? 'غير محدد');
        $top_intent = (string)(array_key_first((array)($report['top_intents'] ?? [])) ?? '');
        $avg_conf = (float)($report['verification_stats']['avg_confidence'] ?? 0);
        $warnings = (array)($report['early_warnings'] ?? []);
        $top_theater = (array)($report['top_hybrid_theaters'] ?? []);
        $top_theater_name = (string)(array_key_first($top_theater) ?? '');
        $top_theater_idx = (int)($top_theater[$top_theater_name]['index'] ?? 0);
        $recs = (array)($report['recommendations'] ?? []);
        $first_rec = (string)($recs[0] ?? '');

        $lines = [];
        $lines[] = "المشهد خلال النافذة الحالية عند مستوى خطر {$threat} باتجاه {$trend}، مع {$critical} حدثًا حرجًا من أصل {$total}.";
        $lines[] = "مركز الثقل الميداني يتموضع في {$top_region}، والفاعل الأكثر حضورًا هو {$top_actor}.";
        if ($top_intent !== '') $lines[] = "النية التشغيلية الأبرز تشير إلى: {$top_intent}.";
        if ($top_theater_name !== '') $lines[] = "في الحرب المركبة، تتصدر ساحة {$top_theater_name} بمؤشر {$top_theater_idx}/100 ما يرفع حساسية التصعيد متعدد الأبعاد.";
        if (!empty($warnings)) $lines[] = "تم رصد " . count($warnings) . " إشارات إنذار مبكر تستدعي مراقبة لصيقة وتحديثًا أسرع لتقدير الموقف.";
        $lines[] = ($avg_conf >= 75)
            ? "جودة الإسناد مرتفعة نسبيًا، ما يسمح ببناء قرارات أسرع مع استمرار التحقق التقاطعي."
            : "جودة الإسناد متوسطة/منخفضة نسبيًا، لذا يُفضّل تجنب الأحكام الحاسمة قبل التحقق المتقاطع.";
        if ($first_rec !== '') $lines[] = "أولوية العمل المباشرة: {$first_rec}";
        return trim(implode(' ', array_filter(array_map('trim', $lines))));
    }

    private static function generate_ai_exec_brief(array $events, array $report): ?string {
        $preferred_provider = (string) get_option('so_llm_provider', 'openai');
        $max_events = array_slice($events, 0, 12);
        $events_text = [];
        foreach ($max_events as $e) {
            $events_text[] = '- [' . (int)($e['score'] ?? 0) . '] ' . wp_strip_all_tags((string)($e['title'] ?? ''));
        }
        $prompt = "أنشئ موجزًا تنفيذيًا عربيًا قصيرًا (4-6 جمل) عن المخاطر والاتجاه والمسرح الأهم والتوصية.\n" .
            "البيانات:\n" .
            "إجمالي الأحداث: " . (int)($report['total'] ?? 0) . "\n" .
            "الأحداث الحرجة: " . (int)($report['critical'] ?? 0) . "\n" .
            "المستوى: " . (string)($report['threat_level'] ?? '') . "\n" .
            "الاتجاه: " . (string)($report['trend'] ?? '') . "\n" .
            implode("\n", $events_text);
        $providers = ['openai', 'anthropic', 'gemini', 'openrouter', 'groq', 'perplexity', 'unli'];
        foreach ((array)get_option('so_llm_custom_providers', []) as $cp) {
            if (!is_array($cp)) continue;
            $cid = sanitize_key((string)($cp['id'] ?? ''));
            if ($cid !== '') $providers[] = $cid;
        }
        $providers = array_values(array_unique($providers));
        usort($providers, static function($a, $b) use ($preferred_provider) {
            if ($a === $preferred_provider) return -1;
            if ($b === $preferred_provider) return 1;
            return 0;
        });
        foreach ($providers as $provider) {
            try {
                if ($provider === 'openai' && class_exists('SO_LLM_Engine')) {
                    $brief = SO_LLM_Engine::generate_intel_brief($max_events);
                    if (is_string($brief) && trim($brief) !== '') return trim($brief);
                }
                $requests = self::build_provider_requests($provider, $prompt);
                foreach ($requests as $req) {
                    if (empty($req['url'])) continue;
                    $res = wp_remote_post($req['url'], [
                        'timeout' => 25,
                        'headers' => $req['headers'],
                        'body' => wp_json_encode($req['body'], JSON_UNESCAPED_UNICODE),
                    ]);
                    if (is_wp_error($res)) continue;
                    $status = (int) wp_remote_retrieve_response_code($res);
                    if ($status < 200 || $status >= 300) continue;
                    $body = json_decode((string)wp_remote_retrieve_body($res), true);
                    if (!is_array($body)) continue;
                    $text = self::extract_provider_text($provider, $body);
                    if (is_string($text) && trim($text) !== '') return trim($text);
                }
            } catch (\Throwable $e) {
                error_log('[SO_Executive_Reports] Provider failed (' . $provider . '): ' . $e->getMessage());
                continue;
            }
        }
        return null;
    }

    private static function parse_model_candidates(string $raw, string $fallback = 'gpt-4o-mini'): array {
        $parts = preg_split('/[\r\n,]+/', $raw) ?: [];
        $models = [];
        foreach ($parts as $part) {
            $m = sanitize_text_field(trim((string)$part));
            if ($m === '') continue;
            $models[$m] = true;
        }
        if (empty($models)) {
            $m = sanitize_text_field(trim($fallback));
            if ($m !== '') $models[$m] = true;
        }
        return array_keys($models);
    }

    private static function build_provider_requests(string $provider, string $prompt): array {
        if (str_starts_with($provider, 'custom_')) {
            $custom = (array)get_option('so_llm_custom_providers', []);
            foreach ($custom as $cp) {
                if (!is_array($cp)) continue;
                $cid = sanitize_key((string)($cp['id'] ?? ''));
                if ($cid !== $provider) continue;
                $token = trim((string)($cp['api_key'] ?? ''));
                $url = esc_url_raw((string)($cp['url'] ?? ''));
                if ($token === '' || $url === '') return [];
                $models = self::parse_model_candidates((string)($cp['model'] ?? ''), 'gpt-4o-mini');
                $default_system = 'أنت محلل استخباراتي استراتيجي. اكتب خلاصة دقيقة بلا حشو.';
                $out = [];
                foreach ($models as $model) {
                    $out[] = [
                        'url' => $url,
                        'headers' => ['Authorization' => 'Bearer ' . $token, 'Content-Type' => 'application/json'],
                        'body' => ['model' => $model, 'messages' => [['role' => 'system', 'content' => $default_system], ['role' => 'user', 'content' => $prompt]], 'temperature' => 0.2, 'max_tokens' => 500],
                    ];
                }
                return $out;
            }
            return [];
        }
        $req = self::build_provider_request($provider, $prompt);
        return empty($req['url']) ? [] : [$req];
    }

    private static function build_provider_request(string $provider, string $prompt): array {
        $default_system = 'أنت محلل استخباراتي استراتيجي. اكتب خلاصة دقيقة بلا حشو.';
        switch ($provider) {
            case 'anthropic':
                $key = trim((string)get_option('so_llm_anthropic_api_key', ''));
                if ($key === '') return ['url' => ''];
                return [
                    'url' => 'https://api.anthropic.com/v1/messages',
                    'headers' => ['x-api-key' => $key, 'anthropic-version' => '2023-06-01', 'Content-Type' => 'application/json'],
                    'body' => ['model' => (string)get_option('so_llm_anthropic_model', 'claude-3-5-sonnet-latest'), 'max_tokens' => 500, 'system' => $default_system, 'messages' => [['role' => 'user', 'content' => $prompt]]],
                ];
            case 'gemini':
                $key = trim((string)get_option('so_llm_gemini_api_key', ''));
                if ($key === '') return ['url' => ''];
                return [
                    'url' => add_query_arg('key', rawurlencode($key), 'https://generativelanguage.googleapis.com/v1beta/models/' . rawurlencode((string)get_option('so_llm_gemini_model', 'gemini-1.5-pro')) . ':generateContent'),
                    'headers' => ['Content-Type' => 'application/json'],
                    'body' => ['contents' => [['parts' => [['text' => $default_system . "\n\n" . $prompt]]]]],
                ];
            case 'openrouter':
            case 'groq':
            case 'perplexity':
            case 'unli':
            case 'openai':
            default:
                $config = [
                    'openai' => ['key' => 'so_llm_api_key', 'url' => 'https://api.openai.com/v1/chat/completions', 'model' => (string)get_option('so_llm_model', 'gpt-4o-mini')],
                    'openrouter' => ['key' => 'so_llm_openrouter_api_key', 'url' => 'https://openrouter.ai/api/v1/chat/completions', 'model' => (string)get_option('so_llm_openrouter_model', 'openai/gpt-4o-mini')],
                    'groq' => ['key' => 'so_llm_groq_api_key', 'url' => 'https://api.groq.com/openai/v1/chat/completions', 'model' => (string)get_option('so_llm_groq_model', 'llama-3.1-70b-versatile')],
                    'perplexity' => ['key' => 'so_llm_perplexity_api_key', 'url' => 'https://api.perplexity.ai/chat/completions', 'model' => (string)get_option('so_llm_perplexity_model', 'sonar')],
                    'unli' => ['key' => 'so_llm_unli_api_key', 'url' => (string)get_option('so_llm_unli_base_url', 'https://unli.dev/api/v1/chat/completions'), 'model' => (string)get_option('so_llm_unli_model', 'gpt-4o-mini')],
                ];
                $cfg = $config[$provider] ?? $config['openai'];
                $token = trim((string)get_option($cfg['key'], ''));
                if ($token === '') return ['url' => ''];
                return [
                    'url' => $cfg['url'],
                    'headers' => ['Authorization' => 'Bearer ' . $token, 'Content-Type' => 'application/json'],
                    'body' => ['model' => $cfg['model'], 'messages' => [['role' => 'system', 'content' => $default_system], ['role' => 'user', 'content' => $prompt]], 'temperature' => 0.2, 'max_tokens' => 500],
                ];
        }
    }

    private static function extract_provider_text(string $provider, array $body): ?string {
        if ($provider === 'anthropic') {
            $raw = $body['content'][0]['text'] ?? '';
            if (is_string($raw)) return trim($raw);
            if (is_array($raw)) {
                $chunks = [];
                foreach ($raw as $item) {
                    if (is_array($item) && isset($item['text']) && is_string($item['text'])) $chunks[] = $item['text'];
                }
                return trim(implode("\n", $chunks));
            }
            return null;
        }
        if ($provider === 'gemini') {
            $parts = $body['candidates'][0]['content']['parts'] ?? [];
            if (is_array($parts)) {
                $chunks = [];
                foreach ($parts as $part) {
                    if (is_array($part) && isset($part['text']) && is_string($part['text'])) $chunks[] = $part['text'];
                }
                if (!empty($chunks)) return trim(implode("\n", $chunks));
            }
            return trim((string)($body['candidates'][0]['content']['parts'][0]['text'] ?? ''));
        }
        $content = $body['choices'][0]['message']['content'] ?? null;
        if (is_string($content)) return trim($content);
        if (is_array($content)) {
            $chunks = [];
            foreach ($content as $item) {
                if (is_array($item) && isset($item['text']) && is_string($item['text'])) $chunks[] = $item['text'];
            }
            if (!empty($chunks)) return trim(implode("\n", $chunks));
        }
        $alt = $body['choices'][0]['text'] ?? '';
        if (is_string($alt) && trim($alt) !== '') return trim($alt);
        return null;
    }

    public static function render_exec_report_list(array $items, string $suffix = '', string $empty = 'لا يوجد معطى كاف'): string {
        if (empty($items)) {
            return '<li>' . esc_html($empty) . '</li>';
        }
        $html = '';
        foreach ($items as $label => $count) {
            $html .= '<li><span>' . esc_html(sod_fix_mojibake_text((string)$label)) . '</span><strong>' . esc_html((string)$count) . ($suffix !== '' ? ' ' . esc_html($suffix) : '') . '</strong></li>';
        }
        return $html;
    }

