                            <li><?php echo esc_html((string)$line); ?></li>
                        <?php endforeach; ?>
                    </ul>
                </section>
            </div>

            <div class="so-exec-footer"><?php echo esc_html((string)($report['footer'] ?? 'Beiruttime OSINT Executive Brief')); ?></div>
        </div>
        <?php
        return (string)ob_get_clean();
    }

    public static function build_report_document_html(array $report): string {
        $body = self::render_exec_report_html($report);
        return '<!doctype html><html dir="rtl" lang="ar"><head><meta charset="utf-8"><title>Beiruttime Executive Brief</title></head><body>' . $body . '</body></html>';
    }

    public static function create_word_report_file(array $report) {
        if (!function_exists('wp_tempnam')) return false;
        $tmp = wp_tempnam('beiruttime-exec-report.doc');
        if (!$tmp) return false;
        $html = self::build_report_document_html($report);
        $written = @file_put_contents($tmp, $html);
        if ($written === false) return false;
        return $tmp;
    }

    public static function create_pdf_report_file_from_base64(string $payload) {
        if (!function_exists('wp_tempnam')) return false;
        $payload = trim($payload);
        if ($payload === '') return false;
        if (strpos($payload, 'base64,') !== false) {
            $parts = explode('base64,', $payload, 2);
            $payload = (string)($parts[1] ?? '');
        }
        // التحقق من أن البيانات base64 صالحة قبل فك التشفير
        if (!preg_match('/^[A-Za-z0-9+\/=]+$/', $payload)) return false;
        
        // SECURITY: Limit payload size before decoding to prevent memory exhaustion attacks
        // Max 10MB for PDF files (adjustable based on needs)
        $max_payload_length = 13981013; // ~10MB in base64
        if (strlen($payload) > $max_payload_length) {
            return false;
        }
        
        $binary = base64_decode($payload, true);
        if ($binary === false || $binary === '') return false;
        
        // SECURITY: Verify decoded file size is within acceptable limits (max 10MB)
        $max_file_size = 10 * 1024 * 1024; // 10MB
        if (strlen($binary) > $max_file_size) {
            return false;
        }
        
        // التحقق من أن الملف هو PDF صالح (magic bytes)
        if (strlen($binary) < 4 || substr($binary, 0, 4) !== '%PDF') return false;
        $tmp = wp_tempnam('beiruttime-exec-report.pdf');
        if (!$tmp) return false;
        $written = @file_put_contents($tmp, $binary);
        if ($written === false) return false;
        return $tmp;
    }

    private static function telegram_send_local_document(string $token, string $chat_id, string $file, string $mime, string $name, string $caption = ''): array {
        if (!file_exists($file)) return ['ok' => false, 'message' => 'الملف غير موجود'];
        if (!function_exists('curl_init') || !function_exists('curl_file_create')) {
            return ['ok' => false, 'message' => 'بيئة السيرفر لا تدعم رفع الملفات عبر cURL'];
        }
        
        // SECURITY: Validate token format (alphanumeric only) to prevent SSRF injection
        if (!preg_match('/^[A-Za-z0-9:_-]+$/', $token)) {
            return ['ok' => false, 'message' => 'رمز تيليغرام غير صالح'];
        }
        
        $ch = curl_init("https://api.telegram.org/bot{$token}/sendDocument");
        $post = [
            'chat_id' => $chat_id,
            'caption' => $caption,
            'parse_mode' => 'HTML',
            'document' => curl_file_create($file, $mime, $name),
        ];
        curl_setopt($ch, CURLOPT_POST, true);
        curl_setopt($ch, CURLOPT_POSTFIELDS, $post);
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
        curl_setopt($ch, CURLOPT_CONNECTTIMEOUT, 15);
        curl_setopt($ch, CURLOPT_TIMEOUT, 60);
        // تعطيل إعادة التوجيه التلقائي لأسباب أمنية
        curl_setopt($ch, CURLOPT_FOLLOWLOCATION, false);
        curl_setopt($ch, CURLOPT_REDIR_PROTOCOLS, CURLPROTO_HTTP | CURLPROTO_HTTPS);
        curl_setopt($ch, CURLOPT_PROTOCOLS, CURLPROTO_HTTP | CURLPROTO_HTTPS);
        $body = curl_exec($ch);
        $errno = curl_errno($ch);
        $error = curl_error($ch);
        $http = (int) curl_getinfo($ch, CURLINFO_HTTP_CODE);
        curl_close($ch);
        if ($errno) return ['ok' => false, 'message' => 'cURL error: ' . $error];
        if ($http < 200 || $http >= 300) return ['ok' => false, 'message' => 'HTTP ' . $http . ': ' . (string)$body];
        $decoded = json_decode((string)$body, true);
        if (!is_array($decoded) || empty($decoded['ok'])) {
            return ['ok' => false, 'message' => is_array($decoded) ? (string)($decoded['description'] ?? 'فشل إرسال المستند') : (string)$body];
        }
        return ['ok' => true, 'message' => 'تم الإرسال بنجاح'];
    }

    public static function send_document_to_telegram(array $report, string $format = 'word'): array {
        $token = trim(get_option('so_tg_token', ''));
        $exec_chat = trim(get_option('so_exec_reports_chat_id', ''));
        $chats_str = $exec_chat !== '' ? $exec_chat : get_option('so_tg_chat', '');
        $chats = array_filter(array_map('trim', explode(',', $chats_str)));
        if (empty($token) || empty($chats)) return ['ok' => false, 'message' => 'بيانات تيليغرام غير مكتملة'];
        if ($format !== 'word') return ['ok' => false, 'message' => 'صيغة غير مدعومة'];

        $file = self::create_word_report_file($report);
        if (!$file || !file_exists($file)) return ['ok' => false, 'message' => 'تعذر إنشاء ملف Word'];

        $ok = true;
        $last_error = '';
        $name = 'beiruttime-executive-brief-' . gmdate('Ymd-His') . '.doc';
        foreach ($chats as $chat_id) {
            $body = [
                'chat_id' => $chat_id,
                'caption' => 'Beiruttime OSINT Executive Brief',
                'parse_mode' => 'HTML',
            ];
            if (function_exists('curl_file_create')) {
                $body['document'] = curl_file_create($file, 'application/msword', $name);
            } else {
                $ok = false;
                $last_error = 'بيئة السيرفر لا تدعم رفع الملفات عبر cURL';
                break;
            }
            $response = wp_remote_post("https://api.telegram.org/bot{$token}/sendDocument", [
                'timeout' => 30,
                'body' => $body,
            ]);
            if (is_wp_error($response)) {
                $ok = false;
                $last_error = $response->get_error_message();
                continue;
            }
            $code = (int)wp_remote_retrieve_response_code($response);
            if ($code < 200 || $code >= 300) {
                $ok = false;
                $last_error = 'HTTP ' . $code . ': ' . wp_remote_retrieve_body($response);
            }
        }
        @unlink($file);
        return ['ok' => $ok, 'message' => $ok ? 'تم إرسال ملف Word بنجاح' : ($last_error !== '' ? $last_error : 'فشل إرسال المستند')];
    }

    public static function send_to_telegram($text) {
        $token = trim(get_option('so_tg_token', ''));
        $exec_chat = trim(get_option('so_exec_reports_chat_id', ''));
        $chats_str = $exec_chat !== '' ? $exec_chat : get_option('so_tg_chat', '');
        $chats = array_filter(array_map('trim', explode(',', $chats_str)));
        if (empty($token) || empty($chats)) return false;
        $ok = true;
        foreach ($chats as $chat_id) {
            $chunks = [];
            if (sod_safe_strlen($text) > 3800) {
                $offset = 0;
                $length = sod_safe_strlen($text);
                while ($offset < $length) {
                    $chunks[] = sod_safe_substr($text, $offset, 3800);
                    $offset += 3800;
                }
            } else {
                $chunks = [$text];
            }
            foreach ($chunks as $chunk) {
                $response = wp_remote_post("https://api.telegram.org/bot{$token}/sendMessage", [
                    'timeout' => 15, 'body' => ['chat_id' => $chat_id, 'text' => $chunk, 'parse_mode' => 'HTML'],
                ]);
                if (is_wp_error($response)) {
                    $ok = false;
                    if (function_exists('so_log_event')) {
                        so_log_event('exec_report_telegram_error', ['chat_id' => $chat_id, 'message' => $response->get_error_message()]);
                    }
                    continue;
                }
                $code = (int)wp_remote_retrieve_response_code($response);
                if ($code < 200 || $code >= 300) {
                    $ok = false;
                    if (function_exists('so_log_event')) {
                        so_log_event('exec_report_telegram_http', ['chat_id' => $chat_id, 'code' => $code, 'body' => wp_remote_retrieve_body($response)]);
                    }
                }
            }
        }
        return $ok;
    }

    public static function maybe_send_scheduled_report() {
        if (!get_option('so_exec_reports_enabled', 1)) return false;
        $report = self::get_or_build_report(); $text = trim((string)($report['text']??''));
        if (!$text) return false;
        $hash = md5($text);
        if (!get_option('so_exec_reports_force_repeat', 0) && $hash === get_option('so_exec_last_report_hash', '')) return false;
        $sent = self::send_to_telegram($text);
        if ($sent) { update_option('so_exec_last_report_hash', $hash, false); update_option('so_exec_last_report_time', time(), false); }
        return $sent;
    }

    public static function send_now() {
        if (!current_user_can('manage_options')) wp_die('Unauthorized');
        check_admin_referer('so_send_exec_report_now');
        $report = self::get_or_build_report(); $text = trim((string)($report['text']??''));
        $ok = $text ? self::send_to_telegram($text) : false;
        if ($ok) { update_option('so_exec_last_report_hash', md5($text), false); update_option('so_exec_last_report_time', time(), false); }
        wp_safe_redirect(add_query_arg(['exec_report_sent' => $ok ? '1' : '0'], wp_get_referer() ?: admin_url('admin.php?page=strategic-osint')));
        exit;
    }

    public static function send_now_ajax() {
        if (!current_user_can('manage_options') || !check_ajax_referer('so_exec_report_ajax', 'nonce', false)) {
            wp_send_json_error(['message' => 'غير مصرح'], 403, JSON_UNESCAPED_UNICODE | (defined('JSON_INVALID_UTF8_SUBSTITUTE') ? JSON_INVALID_UTF8_SUBSTITUTE : 0));
        }
        try {
            $report = self::get_or_build_report();
            $text = trim((string)($report['text'] ?? ''));
            $ok = $text ? self::send_to_telegram($text) : false;
            if ($ok) {
                update_option('so_exec_last_report_hash', md5($text), false);
                update_option('so_exec_last_report_time', time(), false);
            }
            wp_send_json_success(['sent' => $ok, 'message' => $ok ? 'تم الإرسال بنجاح' : 'فشل الإرسال أو لا توجد بيانات'], 200, JSON_UNESCAPED_UNICODE | (defined('JSON_INVALID_UTF8_SUBSTITUTE') ? JSON_INVALID_UTF8_SUBSTITUTE : 0));
        } catch (\Throwable $e) {
            if (function_exists('so_log_event')) {
                so_log_event('exec_report_send_ajax_error', ['message' => $e->getMessage(), 'file' => $e->getFile(), 'line' => $e->getLine()]);
