        }
    }

    public static function generate_report_ajax() {
        if (!current_user_can('manage_options') || !check_ajax_referer('so_exec_report_ajax', 'nonce', false)) {
            wp_send_json_error(['message' => 'غير مصرح'], 403, JSON_UNESCAPED_UNICODE | (defined('JSON_INVALID_UTF8_SUBSTITUTE') ? JSON_INVALID_UTF8_SUBSTITUTE : 0));
        }
        $mode_before = (string) get_option('so_exec_report_generation_mode', 'local');
        update_option('so_exec_report_generation_mode', 'ai', false);
        try {
            $report = self::build_report(); // AI mode with fallback to local inside build_report
            if (!is_array($report) || empty($report['text'])) {
                wp_send_json_error(['message' => 'تعذر توليد التقرير'], 500, JSON_UNESCAPED_UNICODE | (defined('JSON_INVALID_UTF8_SUBSTITUTE') ? JSON_INVALID_UTF8_SUBSTITUTE : 0));
            }
            $html = self::render_exec_report_html($report);
            wp_send_json_success([
                'message' => !empty($report['ai_brief']) ? 'تم توليد التقرير عبر وكيل AI المتاح.' : 'تعذر الوصول لـ AI، تم التوليد محليًا.',
                'mode' => !empty($report['ai_brief']) ? 'ai' : 'local',
                'report_text' => (string)($report['text'] ?? ''),
                'report_html' => (string)$html,
            ], 200, JSON_UNESCAPED_UNICODE | (defined('JSON_INVALID_UTF8_SUBSTITUTE') ? JSON_INVALID_UTF8_SUBSTITUTE : 0));
        } catch (\Throwable $e) {
            error_log('[SO_Executive_Reports] generate_report_ajax failure: ' . $e->getMessage());
            wp_send_json_error(['message' => 'فشل توليد التقرير بسبب خطأ داخلي.'], 500, JSON_UNESCAPED_UNICODE | (defined('JSON_INVALID_UTF8_SUBSTITUTE') ? JSON_INVALID_UTF8_SUBSTITUTE : 0));
        } finally {
            update_option('so_exec_report_generation_mode', $mode_before, false);
        }
    }

