function sod_dashboard_selected_panels(): array {
    $available = sod_available_dashboard_panels();
    $allowed = ['powerbi','world_monitor','ticker','threat_analyzer','command_deck','osint_dashboard','osint_map','osint_command_center'];
    $selected = get_option('sod_dashboard_selected_panels', ['world_monitor']);
    if (!is_array($selected)) $selected = ['world_monitor'];
    $selected = array_values(array_filter(array_map('sanitize_key', $selected), function($key) use ($available){
        return isset($available[$key]);
    }));
    $selected = array_values(array_filter($selected, function($key) use ($allowed){
        return in_array($key, $allowed, true);
    }));
    if (empty($selected)) $selected = ['world_monitor'];
    return $selected;
}

function sod_get_dashboard_route_shortcodes(): array {
    $available = sod_available_dashboard_panels();
    $powerbi = $available['powerbi']['shortcode'];
    $world_monitor = $available['world_monitor']['shortcode'];
    $ticker = $available['ticker']['shortcode'];
    $threat = $available['threat_analyzer']['shortcode'];
    $mode = sod_dashboard_display_mode();
    $selected = sod_dashboard_selected_panels();

    if ($mode === 'custom') {
        $parts = [];
        foreach ($selected as $key) {
            if (!empty($available[$key]['shortcode'])) {
                $parts[] = $available[$key]['shortcode'];
            }
        }
        if (!empty($parts)) return $parts;
        return [$world_monitor];
    }

    if ($mode === 'powerbi') return [$powerbi];
    if ($mode === 'world_monitor') return [$world_monitor];
    if ($mode === 'command_deck') return [$available['command_deck']['shortcode']];
    return [$world_monitor];
}

function sod_render_dashboard_route_content(): string {
    $parts = [];
    $top_ad = trim((string)get_option('sod_dashboard_top_ad_code', ''));
    $bottom_ad = trim((string)get_option('sod_dashboard_bottom_ad_code', ''));
    $ga_code = trim((string)get_option('sod_dashboard_ga_code', ''));
    
    // إضافة كود تتبع جوجل في البداية
    if ($ga_code !== '') {
        $parts[] = '<!-- Google Analytics -->' . $ga_code;
    }
    
    if ($top_ad !== '') {
        $parts[] = '<div class="sod-dashboard-ad sod-dashboard-ad-top">' . $top_ad . '</div>';
    }
    foreach (sod_get_dashboard_route_shortcodes() as $shortcode) {
        $html = do_shortcode($shortcode);
        if (trim((string) $html) !== '') $parts[] = $html;
    }

    if (empty($parts)) {
        return '<div class="sod-dashboard-route-empty" style="padding:24px;border:1px solid rgba(148,163,184,.18);border-radius:16px;background:#0f172a;color:#e2e8f0;text-align:center;">لم يتم اختيار أي لوحة للعرض في إعدادات الإضافة.</div>';
    }

    if ($bottom_ad !== '') {
        $parts[] = '<div class="sod-dashboard-ad sod-dashboard-ad-bottom">' . $bottom_ad . '</div>';
    }

    $footer_bits = [];
    $designer_name = trim((string)get_option('sod_dashboard_designer_name', ''));
    $designer_phone = preg_replace('/\s+/u', '', trim((string)get_option('sod_dashboard_designer_phone', '')));
    $wa_link = trim((string)get_option('sod_dashboard_whatsapp_url', ''));
    if ($wa_link === '' && $designer_phone !== '') {
        $wa_link = 'https://wa.me/' . preg_replace('/[^\d]/', '', str_replace('+', '', $designer_phone));
    }
    if ($designer_name !== '') $footer_bits[] = '<span class="sod-dashboard-credit-name">' . esc_html($designer_name) . '</span>';
    if ($designer_phone !== '') {
        $phone_html = esc_html($designer_phone);
        if ($wa_link !== '') $phone_html = '<a href="' . esc_url($wa_link) . '" target="_blank" rel="noopener">' . $phone_html . '</a>';
        $footer_bits[] = '<span class="sod-dashboard-credit-phone">' . $phone_html . '</span>';
    }

    $socials = [
        'x' => ['label' => 'X', 'url' => get_option('sod_dashboard_x_url', '')],
        'instagram' => ['label' => 'Instagram', 'url' => get_option('sod_dashboard_instagram_url', '')],
        'facebook' => ['label' => 'Facebook', 'url' => get_option('sod_dashboard_facebook_url', '')],
        'pinterest' => ['label' => 'Pinterest', 'url' => get_option('sod_dashboard_pinterest_url', '')],
        'discord' => ['label' => 'Discord', 'url' => get_option('sod_dashboard_discord_url', '')],
    ];
    $social_links = [];
    foreach ($socials as $social) {
        $url = trim((string)$social['url']);
        if ($url === '') continue;
        $social_links[] = '<a href="' . esc_url($url) . '" target="_blank" rel="noopener" class="sod-dashboard-social-link">' . esc_html($social['label']) . '</a>';
    }
    if (!empty($social_links)) {
        $footer_bits[] = '<span class="sod-dashboard-socials">' . implode('', $social_links) . '</span>';
    }
    if (!empty($footer_bits)) {
        $parts[] = '<footer class="sod-dashboard-footer">' . implode('', $footer_bits) . '</footer>';
    }

    return implode("\n<div style=\"height:16px\"></div>\n", $parts);
}

function sod_register_dashboard_rewrite_rule(): void {
    add_rewrite_tag('%sod_dashboard_route%', '1');
    if (sod_dashboard_route_enabled()) {
        add_rewrite_rule('^' . preg_quote(sod_dashboard_slug(), '/') . '/?$', 'index.php?sod_dashboard_route=1', 'top');
    }
}

add_action('init', 'sod_register_dashboard_rewrite_rule');

register_activation_hook(__FILE__, function () {
    sod_register_dashboard_rewrite_rule();
    flush_rewrite_rules();
    
    // تفعيل تحديثات الحرب المركبة
    if (function_exists('sod_activate_hybrid_warfare_update')) {
        sod_activate_hybrid_warfare_update();
    }
    
    // إنشاء جدول سجلات تنظيف الأرشيف
    if (class_exists('SO_Archive_Cleanup_Tool')) {
        SO_Archive_Cleanup_Tool::ensure_log_table_exists();
    }
});

register_deactivation_hook(__FILE__, function () {
    flush_rewrite_rules();
});

add_filter('query_vars', function ($vars) {
    $vars[] = 'sod_dashboard_route';
    return $vars;
});

// ==========================================================================
// إضافة Content-Security-Policy (CSP) للوحة OSINT
// ==========================================================================
add_action('send_headers', function () {
    // تطبيق CSP فقط على صفحة لوحة OSINT
    if (sod_is_dashboard_route()) {
        header("Content-Security-Policy: default-src 'self' https: data: blob:; script-src 'self' 'unsafe-inline' 'unsafe-eval' https: blob:; style-src 'self' 'unsafe-inline' https: data:; img-src 'self' data: blob: https:; font-src 'self' data: https://fonts.gstatic.com https:; connect-src 'self' https: wss: ws: blob: data: https://api.telegram.org; frame-src 'self' https://widgets.wp.com https:; media-src 'self' blob: data: https:; worker-src 'self' blob:; frame-ancestors 'self'; base-uri 'self'; form-action 'self' https:;");
    }
});

add_action('template_redirect', function () {
    if (!sod_is_dashboard_route()) return;

    status_header(200);
    nocache_headers();

    wp_enqueue_style('dashicons');
    do_action('wp_enqueue_scripts');

    $mode_label_map = [
        'powerbi' => 'PowerBI',
        'world_monitor' => 'World Monitor',
        'command_deck' => 'مركز القرار',
        'all' => 'All Dashboards',
        'custom' => 'Custom Dashboards',
    ];
    $mode = sod_dashboard_display_mode();
    $title = apply_filters('sod_dashboard_page_title', 'Beiruttime Display — ' . ($mode_label_map[$mode] ?? 'Dashboard'));
    ?>
    <!DOCTYPE html>
    <html <?php language_attributes(); ?>>
