    exit;
});

// ==========================================================================
// 16. تحميل الأصول — Asset Enqueue
// ==========================================================================
add_action('wp_enqueue_scripts', 'sod_enqueue_assets');
function sod_enqueue_assets(): void {
    if (!sod_should_enqueue_public_assets()) return;
    // Google Fonts - load custom font from admin settings
    $custom_font = get_option('so_custom_font', 'Noto Naskh Arabic');
    $font_slug = urlencode(str_replace(' ', '+', $custom_font));
    wp_enqueue_style('sod-custom-font', "https://fonts.googleapis.com/css2?family={$font_slug}:wght@400;500;600;700&display=swap", [], null);
    // ── Leaflet — unique handles to avoid conflicts with other plugins ──────
    wp_enqueue_style('sod-leaflet-css','https://unpkg.com/leaflet@1.9.4/dist/leaflet.css',[],'sod1.9.4');
    wp_enqueue_script('sod-leaflet','https://unpkg.com/leaflet@1.9.4/dist/leaflet.js',[],'sod1.9.4',false);
    wp_enqueue_script('sod-leaflet-heat','https://unpkg.com/leaflet.heat@0.2.0/dist/leaflet-heat.js',['sod-leaflet'],'sod0.2.0',false);
    wp_enqueue_script('sod-topojson-client','https://unpkg.com/topojson-client@3/dist/topojson-client.min.js',[],'3.1.0',false);
    // ── Chart.js v4 — unique handle 'sod-chartjs-v4' to avoid conflicts ─────
    wp_enqueue_style('sod-cairo-font','https://fonts.googleapis.com/css2?family=Cairo:wght@300;400;600;700;900&family=Tajawal:wght@300;400;700&display=swap',[],null);
    wp_enqueue_script('sod-chartjs-v4','https://cdn.jsdelivr.net/npm/chart.js@4.4.3/dist/chart.umd.min.js',[],'sod4.4.3',false);
    // ── HLS.js for live streams ──────────────────────────────────────────────
    wp_enqueue_script('sod-hls-js','https://cdn.jsdelivr.net/npm/hls.js@1.5.15/dist/hls.min.js',[],'sod1.5.15',true);
    // ── Config object — localized to sod-chartjs-v4 so it's available early ─
    wp_localize_script('sod-chartjs-v4','SOD_CONFIG',['ajaxUrl'=>admin_url('admin-ajax.php'),'nonce'=>wp_create_nonce(SOD_AJAX_NONCE_ACTION),'tgLink'=>SOD_TG_LINK,'version'=>SOD_VERSION]);
    // Inject custom CSS variables from admin appearance settings
    $primary_color  = get_option('so_custom_primary_color', '#dc2626');
    $bg_color       = get_option('so_custom_bg_color', '#0f172a');
    $tc_heading     = get_option('so_text_color_heading', '#e0f2ff');
    $tc_body        = get_option('so_text_color_body',    '#94a3b8');
    $tc_accent      = get_option('so_text_color_accent',  '#60a5fa');
    $tc_muted       = get_option('so_text_color_muted',   '#64748b');
    $tc_score       = get_option('so_text_color_score',   '#ef4444');
    $frontend_theme = get_option('so_frontend_default_theme', 'dark');
    $custom_css  = ":root{--sod-red:{$primary_color};--sod-bg:{$bg_color};--sod-font:'{$custom_font}',serif;--sod-default-theme:{$frontend_theme};";
    $custom_css .= "--sod-tc-heading:{$tc_heading};--sod-tc-body:{$tc_body};--sod-tc-accent:{$tc_accent};--sod-tc-muted:{$tc_muted};--sod-tc-score:{$tc_score};}";
    $custom_css .= ".sod-powerbi-wrap,.sod-ticker-wrap,.sod-threat-wrap{font-family:'{$custom_font}',sans-serif !important;background:{$bg_color} !important;}";
    $custom_css .= ".sod-powerbi-wrap .sod-card-header,.sod-powerbi-wrap .sod-nav-btn,.sod-powerbi-wrap .sod-topbar-title{color:{$tc_heading} !important;}";
    $custom_css .= ".sod-powerbi-wrap .sod-news-card p,.sod-powerbi-wrap .sod-actor-name,.sod-powerbi-wrap .sod-region-name,.sod-powerbi-wrap .sod-setting-label{color:{$tc_body} !important;}";
    $custom_css .= ".sod-powerbi-wrap a,.sod-powerbi-wrap .sod-nav-btn.active,.sod-powerbi-wrap .sod-badge-gray{color:{$tc_accent} !important;}";
    $custom_css .= ".sod-powerbi-wrap .sod-kpi-label,.sod-powerbi-wrap .sod-ticker-bar-label,.sod-powerbi-wrap .sod-page-subtitle{color:{$tc_muted} !important;}";
    $custom_css .= ".sod-powerbi-wrap .sod-kpi-val,.sod-powerbi-wrap .sod-badge-red,.sod-powerbi-wrap .sod-actor-score{color:{$tc_score} !important;}";
    $custom_css .= ".sod-sidebar-nav,.sod-kpi-card,.so-alert-strip,.sod-news-card,.sod-tab-btn.active{border-color:{$primary_color} !important;}";
    $custom_css .= ".sod-tab-btn.active,.sod-badge-red,.sod-live-dot{background:{$primary_color} !important;}";
    $custom_css .= ".sod-theme-light,.sod-theme-light .sod-shell,.sod-theme-light.sod-powerbi-wrap{background:#f8fafc !important;color:#111827 !important;}";
    $custom_css .= ".sod-theme-light .sod-card,.sod-theme-light .sod-kpi-card,.sod-theme-light .sod-news-card,.sod-theme-light .sod-sidebar-nav{background:#ffffff !important;border-color:#dbe3ee !important;}";
    $custom_css .= ".sod-theme-light .sod-card-header,.sod-theme-light .sod-topbar-title,.sod-theme-light .sod-kpi-val,.sod-theme-light .sod-actor-name,.sod-theme-light .sod-region-name{color:#111827 !important;}";
    $custom_css .= ".sod-theme-light p,.sod-theme-light .sod-kpi-label,.sod-theme-light .sod-page-subtitle,.sod-theme-light .sod-setting-label{color:#334155 !important;}";
    $custom_css .= "@media (max-width:900px){.sod-powerbi-wrap,.sod-ticker-wrap,.sod-threat-wrap,.so-dashboard-wrap,.osint-dashboard{max-width:100% !important;overflow:hidden}.sod-powerbi-wrap .sod-grid,.so-dashboard-wrap .so-grid,.osint-dashboard .so-grid{grid-template-columns:1fr !important}.sod-powerbi-wrap .sod-topbar,.sod-powerbi-wrap .sod-header-actions{flex-wrap:wrap !important;gap:8px !important}.sod-powerbi-wrap iframe,.so-dashboard-wrap iframe,.osint-dashboard iframe{max-width:100% !important}}";
    $custom_css .= "@media (max-width:640px){.sod-powerbi-wrap .sod-card,.sod-powerbi-wrap .sod-kpi-card,.so-dashboard-wrap .so-card,.osint-dashboard .so-card{padding:12px !important;border-radius:12px !important}.sod-powerbi-wrap .sod-topbar-title{font-size:18px !important}.sod-powerbi-wrap canvas,.so-dashboard-wrap canvas,.osint-dashboard canvas{max-width:100% !important;height:auto !important}}";
    wp_add_inline_style('sod-leaflet-css', $custom_css);
}

// ==========================================================================
// 17. الأنماط المشتركة — Shared Styles
// ==========================================================================
function sod_get_shared_styles(): string {
    ob_start(); ?>
    <style>
    /* =====================================================================
       OSINT-LB PRO V15 — واجهة مطابقة للوحة React
    ===================================================================== */
    *{box-sizing:border-box;}
    .sod-powerbi-wrap,.sod-ticker-wrap,.sod-threat-wrap{
        font-family:'Noto Naskh Arabic','Cairo','Tajawal',sans-serif;
        direction:rtl;
    }
    /* Shell / container */
    .sod-shell{
        background:#0f172a;
        color:#e2e8f0;
        min-height:600px;
        border-radius:12px;
        overflow:hidden;
        display:flex;
        flex-direction:column;
        border:1px solid #1e293b;
        margin-bottom:24px;
    }
    /* Ticker bar — خبر واحد يصعد للأعلى */
    .sod-ticker-bar{
        background:#dc2626;
        color:#fff;
        font-size:13px;
        font-weight:700;
        display:flex;
        align-items:center;
        gap:10px;
        padding:0 16px;
        overflow:hidden;
        flex-shrink:0;
        height:42px;
    }
    .sod-ticker-bar-label{white-space:nowrap!important;flex-shrink:0!important;font-size:12px;}
    .sod-ticker-scroll-wrap{flex:1!important;overflow:hidden!important;position:relative!important;height:36px!important;}
    .sod-ticker-scroll{position:relative!important;height:36px!important;overflow:hidden!important;}
    /* عنصر خبر واحد */
    .sod-tick-item{
        position:absolute!important;width:100%!important;height:36px!important;
        display:flex!important;align-items:center!important;
        white-space:nowrap!important;overflow:hidden!important;text-overflow:ellipsis!important;
        font-size:12px!important;transition:transform .55s cubic-bezier(.4,0,.2,1),opacity .45s ease!important;
        padding:0 4px!important;
    }
    .sod-tick-item.sod-entering{transform:translateY(110%)!important;opacity:0!important;}
    .sod-tick-item.sod-active  {transform:translateY(0)!important;  opacity:1!important;}
    .sod-tick-item.sod-leaving {transform:translateY(-110%)!important;opacity:0!important;}
    /* Top bar */
    .sod-topbar{
        background:#1e293b;
        border-bottom:1px solid #334155;
        padding:10px 20px;
        display:flex;
        align-items:center;
        justify-content:space-between;
        flex-wrap:wrap;
        gap:10px;
        flex-shrink:0;
    }
    .sod-logo{display:flex;align-items:center;gap:10px;}
    .sod-logo-icon{font-size:20px;}
    .sod-logo-title{font-size:15px;font-weight:700;color:#f8fafc;}
    .sod-logo-sub{font-size:10px;color:#64748b;}
    .sod-live-badge{
        display:flex;align-items:center;gap:5px;
        background:#0f3a1a;border:1px solid #16a34a;border-radius:20px;
        padding:3px 10px;font-size:10px;font-weight:700;color:#4ade80;
    }
    .sod-live-dot{width:7px;height:6px;background:#22c55e;border-radius:50%;animation:sod-blink 1.4s infinite;flex-shrink:0;}
    .sod-topbar-controls{display:flex;align-items:center;gap:8px;flex-wrap:wrap;}
    .sod-select,.sod-input-sm{
        background:#0f172a;border:1px solid #334155;color:#cbd5e1;
        padding:3px 7px;border-radius:6px;font-size:10px;font-family:inherit;
    }
    .sod-btn{
        background:#1e293b;border:1px solid #334155;color:#cbd5e1;
        padding:5px 12px;border-radius:6px;cursor:pointer;font-size:10px;
        font-family:inherit;font-weight:600;transition:.15s;
    }
    .sod-btn:hover{background:#334155;color:#f8fafc;}
    .sod-btn-danger{background:#991b1b;border-color:#dc2626;color:#fecaca;}
    .sod-btn-danger:hover{background:#b91c1c;}
    .sod-time-label{font-size:10px;color:#475569;white-space:nowrap;}
    /* Body: sidebar + content */
    .sod-body{display:flex;flex:1;min-height:0;overflow:hidden;}
    /* Sidebar */
    .sod-sidebar{
        width:200px;flex-shrink:0;
        background:#1e293b;
        border-left:1px solid #334155;
        display:flex;flex-direction:column;
        overflow-y:auto;
    }
    .sod-sidebar-nav{list-style:none;margin:0;padding:8px 0;}
    .sod-sidebar-nav li{margin:0;}
    .sod-nav-btn{
        display:flex;align-items:center;gap:10px;
        width:100%;padding:10px 16px;
        background:none;border:none;cursor:pointer;
        font-family:inherit;font-size:12px;font-weight:600;
        color:#94a3b8;text-align:right;
        border-radius:0;transition:.15s;
    }
    .sod-nav-btn:hover{background:rgba(255,255,255,.05);color:#e2e8f0;}
    .sod-nav-btn.active{
        background:rgba(220,38,38,.15);
        color:#f87171;
        border-right:3px solid #dc2626;
    }
    .sod-nav-icon{font-size:16px;flex-shrink:0;}
    /* Popup overlay */
    .sod-popup-overlay{
        position:fixed;inset:0;background:rgba(0,0,0,.7);
        z-index:9999;display:flex;align-items:center;justify-content:center;
    }
    .sod-popup-overlay.hidden{display:none;}
    .sod-popup-box{
        background:#1e293b;border:1px solid #dc2626;border-radius:12px;
        padding:0;width:min(420px,90vw);overflow:hidden;
        box-shadow:0 20px 60px rgba(0,0,0,.6);
    }
    .sod-popup-header{
        background:#dc2626;padding:12px 16px;
        display:flex;align-items:center;justify-content:space-between;
    }
    .sod-popup-title{color:#fff;font-weight:700;font-size:13px;display:flex;align-items:center;gap:6px;}
    .sod-popup-close{
        background:none;border:none;color:#fecaca;font-size:17px;
        cursor:pointer;line-height:1;padding:0;
    }
    .sod-popup-body{padding:20px;}
    .sod-popup-event-title{font-size:15px;font-weight:700;color:#f8fafc;margin-bottom:8px;text-align:center;}
    .sod-popup-event-desc{font-size:12px;color:#94a3b8;line-height:1.7;margin-bottom:16px;text-align:center;}
    .sod-popup-actions{display:flex;gap:8px;justify-content:center;}
    .sod-popup-btn-primary{
        background:#dc2626;border:none;color:#fff;
        padding:8px 20px;border-radius:8px;cursor:pointer;
        font-family:inherit;font-weight:700;font-size:13px;
    }
    .sod-popup-btn-secondary{
        background:#334155;border:none;color:#cbd5e1;
        padding:8px 20px;border-radius:8px;cursor:pointer;
        font-family:inherit;font-weight:600;font-size:13px;
    }
    /* Page content */
    .sod-page{display:none;flex:1;overflow-y:auto;padding:16px;flex-direction:column;gap:14px;}
    .sod-page.active{display:flex;}
    /* Cards */
    .sod-card{
        background:#1e293b;border:1px solid #334155;
        border-radius:10px;overflow:hidden;
    }
    .sod-card-header{
        padding:10px 14px;font-size:13px;font-weight:700;
        color:#f8fafc;background:rgba(0,0,0,.2);
        border-bottom:1px solid #334155;
        display:flex;justify-content:center;align-items:center;
        text-align:center;position:relative;
    }
    .sod-card-header > span:first-child,
    .sod-card-header > div:first-child{
        margin:0 auto;
    }
    .sod-card-header .sod-feed-controls,
    .sod-card-header .sod-map-controls{
        position:absolute;
        inset-inline-start:12px;
        top:50%;
        transform:translateY(-50%);
    }
    .sod-card-header-red{background:rgba(220,38,38,.15);border-bottom-color:rgba(220,38,38,.3);}
    .sod-card-body{padding:14px;}
    /* KPI Grid */
    .sod-kpi-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(160px,1fr));gap:10px;}
    .sod-kpi-card{
        background:#0f172a;border:1px solid #334155;border-radius:8px;
        padding:10px 12px;display:flex;align-items:center;justify-content:center;gap:10px;
        transition:.2s;text-align:center;min-height:84px;
    }
    .sod-kpi-card:hover{border-color:#475569;transform:translateY(-1px);}
    .sod-kpi-icon{font-size:20px;flex-shrink:0;}
    .sod-kpi-label{font-size:10px;color:#cbd5e1;font-weight:700;margin-bottom:4px;}
    .sod-kpi-value{font-size:24px;font-weight:800;color:#f8fafc;line-height:1.1;}
    .sod-kpi-desc{font-size:10px;color:#94a3b8;margin-top:4px;}
    .kpi-danger .sod-kpi-value{color:#f87171;}
    .kpi-warn .sod-kpi-value{color:#fbbf24;}
    .kpi-hot .sod-kpi-value{color:#f97316;font-size:13px;}
    .kpi-info .sod-kpi-value{color:#60a5fa;}
    .kpi-esc .sod-kpi-value{color:#c084fc;}
    /* News cards */
    .sod-news-grid{display:flex;flex-direction:column;gap:10px;}
    .sod-news-card{
        background:#0f172a;border:1px solid #1e293b;border-radius:8px;
        padding:10px 12px;display:flex;flex-direction:column;gap:6px;
        transition:.2s;
    }
    .sod-news-card:hover{border-color:#334155;}
    .sod-news-card-meta{display:flex;align-items:center;gap:8px;flex-wrap:wrap;}
    .sod-badge{
        display:inline-flex;align-items:center;padding:2px 7px;
        border-radius:10px;font-size:10px;font-weight:700;
    }
    .sod-badge-red{background:rgba(220,38,38,.2);color:#f87171;border:1px solid rgba(220,38,38,.3);}
    .sod-badge-orange{background:rgba(249,115,22,.2);color:#fb923c;border:1px solid rgba(249,115,22,.3);}
    .sod-badge-yellow{background:rgba(234,179,8,.2);color:#fbbf24;border:1px solid rgba(234,179,8,.3);}
    .sod-badge-green{background:rgba(34,197,94,.2);color:#4ade80;border:1px solid rgba(34,197,94,.3);}
    .sod-badge-blue{background:rgba(59,130,246,.2);color:#60a5fa;border:1px solid rgba(59,130,246,.3);}
    .sod-badge-purple{background:rgba(139,92,246,.2);color:#c084fc;border:1px solid rgba(139,92,246,.3);}
    .sod-badge-gray{background:rgba(100,116,139,.15);color:#94a3b8;border:1px solid rgba(100,116,139,.3);}
    .sod-news-title{font-size:13px;font-weight:600;color:#e2e8f0;line-height:1.5;}
    .sod-news-title a{color:#e2e8f0;text-decoration:none;}
    .sod-news-title a:hover{color:#60a5fa;}
    .sod-news-footer{display:flex;align-items:center;gap:8px;font-size:10px;color:#475569;}
    .sod-confidence-bar-wrap{display:flex;align-items:center;gap:6px;margin-top:4px;}
    .sod-confidence-label{font-size:10px;color:#64748b;white-space:nowrap;}
    .sod-confidence-bar{flex:1;height:3px;background:#1e293b;border-radius:2px;overflow:hidden;}
    .sod-confidence-fill{height:100%;border-radius:2px;background:#3b82f6;transition:width .4s;}
    /* Map */
    .sod-map-container{height:420px;border-radius:8px;overflow:hidden;}
    .sod-map-controls{display:flex;gap:6px;}
    .sod-map-btn{
        background:#0f172a;border:1px solid #334155;color:#94a3b8;
        padding:4px 10px;border-radius:6px;cursor:pointer;font-size:10px;
        font-family:inherit;transition:.15s;
    }
    .sod-map-btn.active{background:#dc2626;color:#fff;border-color:#dc2626;}
    /* Charts */
    .sod-charts-grid{display:grid;grid-template-columns:1fr 1fr;gap:12px;}
    .sod-chart-wrap{height:200px;padding:8px;position:relative;}
    .sod-chart-wrap canvas{cursor:pointer;transition:opacity .15s;}
    .sod-chart-wrap canvas:hover{opacity:.85;}
    /* ── Chart Modal ── */
    #sod-chart-modal{position:fixed;inset:0;z-index:999999;background:rgba(0,0,0,.8);display:flex;align-items:center;justify-content:center;animation:sod-modal-in .2s ease;}
    @keyframes sod-modal-in{from{opacity:0;transform:scale(.95)}to{opacity:1;transform:scale(1)}}
    .sod-cm-box{background:#0d1b2a;border:1px solid #1e3a5f;border-radius:12px;width:92vw;max-width:1280px;max-height:90vh;display:flex;flex-direction:column;overflow:hidden;box-shadow:0 24px 60px rgba(0,0,0,.8);}
    .sod-cm-hdr{display:flex;align-items:center;gap:10px;padding:12px 16px;border-bottom:1px solid #1e3a5f;background:#0a1522;flex-shrink:0;}
    .sod-cm-title{font-size:15px;font-weight:700;color:#e0f2ff;flex:1;}
    .sod-cm-btn{padding:6px 14px;border-radius:6px;border:none;cursor:pointer;font-size:12px;font-weight:700;}
    .sod-cm-btn-print{background:#1d4ed8;color:#fff;}
    .sod-cm-btn-print:hover{background:#2563eb;}
    .sod-cm-btn-close{background:#1e293b;color:#94a3b8;}
    .sod-cm-btn-close:hover{background:#dc2626;color:#fff;}
    .sod-cm-chart{height:240px;padding:12px;flex-shrink:0;position:relative;}
    .sod-cm-filters{display:flex;gap:8px;flex-wrap:wrap;padding:8px 14px;border-bottom:1px solid #1e3a5f;flex-shrink:0;background:#060e18;}
    .sod-cm-filter{background:#0f1e2e;border:1px solid #1e3a5f;color:#94a3b8;border-radius:6px;padding:3px 7px;font-size:10px;flex:1;min-width:100px;}
    .sod-cm-filter::placeholder{color:#475569;}
    .sod-cm-events{flex:1;overflow-y:auto;padding:0;}
    table.sod-cm-tbl{width:100%;border-collapse:collapse;font-size:10px;}
    table.sod-cm-tbl th{position:sticky;top:0;background:#0a1522;color:#60a5fa;padding:7px 10px;text-align:right;border-bottom:1px solid #1e3a5f;font-weight:600;}
    table.sod-cm-tbl td{padding:6px 10px;border-bottom:1px solid rgba(30,58,95,.4);color:#94a3b8;vertical-align:top;}
    table.sod-cm-tbl tr:hover td{background:rgba(30,58,95,.3);}
    table.sod-cm-tbl td.sod-cm-score{font-weight:700;text-align:center;white-space:nowrap;}
    .sod-cm-pg{display:flex;gap:6px;justify-content:center;padding:8px;flex-shrink:0;border-top:1px solid #1e3a5f;}
    .sod-cm-pg-btn{background:#0f1e2e;border:1px solid #1e3a5f;color:#60a5fa;padding:4px 10px;border-radius:4px;cursor:pointer;font-size:10px;}
    .sod-cm-pg-btn.active{background:#1d4ed8;border-color:#1d4ed8;color:#fff;}
    @media print{
        @page{size:A3 landscape;margin:10mm;}
        body>*{display:none!important;}
        #sod-chart-modal{display:flex!important;position:static!important;background:#fff!important;}
        .sod-cm-box{max-height:none!important;max-width:none!important;width:100%!important;border:none!important;background:#fff!important;color:#000!important;}
        .sod-cm-hdr{background:#1d4ed8!important;color:#fff!important;-webkit-print-color-adjust:exact;}
        .sod-cm-title{color:#fff!important;}
        .sod-cm-btn-close,.sod-cm-pg{display:none!important;}
        table.sod-cm-tbl th{background:#1e3a5f!important;color:#fff!important;-webkit-print-color-adjust:exact;}
        table.sod-cm-tbl td{color:#1e293b!important;border-bottom:1px solid #cbd5e1!important;}
        table.sod-cm-tbl tr:hover td{background:none!important;}
    }
    /* Feed table */
    .sod-feed-table-wrap{max-height:420px;overflow-y:auto;}
    .sod-feed-table{width:100%;border-collapse:collapse;font-size:12px;}
    .sod-feed-table th{
        background:#0f172a;color:#dbeafe;padding:8px 10px;
        text-align:center;font-weight:700;position:sticky;top:0;z-index:1;
        border-bottom:1px solid #1e293b;
    }
    .sod-feed-table td{padding:8px 10px;border-bottom:1px solid #1e293b;vertical-align:middle;color:#cbd5e1;}
    .sod-feed-table tr:hover td{background:rgba(255,255,255,.03);}
    .sod-feed-table a{color:#60a5fa;text-decoration:none;}
    .sod-feed-table a:hover{color:#93c5fd;text-decoration:underline;}
    .sod-score-badge{
        display:inline-flex;align-items:center;justify-content:center;
        min-width:44px;padding:3px 6px;border-radius:6px;
        font-weight:700;font-size:10px;
    }
    .sod-level-chip{
        display:inline-block;padding:2px 7px;border-radius:8px;
        font-size:10px;font-weight:700;
        background:rgba(51,65,85,.6);color:#94a3b8;
    }
    .sod-loading-row{text-align:center;padding:28px;color:#475569;}
    /* Actors / regions lists */
    .sod-actors-list,.sod-regions-list,.sod-cats-list{padding:8px 0;}
    .sod-actor-row,.sod-region-row{
        display:flex;align-items:center;justify-content:space-between;
        padding:7px 14px;border-bottom:1px solid #1e293b;
    }
    .sod-actor-row:last-child,.sod-region-row:last-child{border-bottom:none;}
    .sod-actor-name,.sod-region-name{font-size:12px;color:#cbd5e1;flex:1;}
    .sod-actor-score,.sod-region-score{font-size:12px;font-weight:700;}
    .sod-actor-bar{height:3px;background:#1e293b;border-radius:2px;margin-top:4px;}
    .sod-actor-bar-fill{height:100%;border-radius:2px;transition:width .6s;}
    /* Brief */
    .sod-brief-container{padding:14px;font-size:12px;line-height:1.8;color:#94a3b8;max-height:300px;overflow-y:auto;}
    .sod-brief-loading{color:#475569;text-align:center;padding:20px;}
    /* Pagination */
    .sod-feed-controls{display:flex;gap:6px;align-items:center;}
    .sod-feed-pagination{padding:8px 12px;display:flex;gap:5px;flex-wrap:wrap;}
    .sod-page-btn{
        background:#0f172a;border:1px solid #334155;color:#94a3b8;
        padding:3px 8px;border-radius:5px;cursor:pointer;font-size:10px;
    }
    .sod-page-btn.active{background:#dc2626;border-color:#dc2626;color:#fff;}
    /* Alert strip */
    .sod-alert-strip{
        display:flex;align-items:center;gap:10px;
        padding:7px 16px;background:rgba(220,38,38,.15);
        border-bottom:1px solid rgba(220,38,38,.3);overflow:hidden;
    }
    .sod-alert-icon{font-size:16px;animation:sod-blink 1.4s infinite;flex-shrink:0;}
    .sod-alert-marquee{flex:1;overflow:hidden!important;position:relative!important;height:30px!important;}
    /* KPI / Stats row */
    .sod-stats-row{display:flex;gap:10px;flex-wrap:wrap;}
    .sod-stat-box{
        flex:1;min-width:120px;background:#0f172a;border:1px solid #334155;
        border-radius:8px;padding:10px 12px;display:flex;flex-direction:column;gap:2px;
    }
    .sod-stat-label{font-size:10px;color:#64748b;font-weight:600;}
    .sod-stat-value{font-size:17px;font-weight:700;color:#f8fafc;}
    /* Settings page */
    .sod-settings-grid{display:grid;grid-template-columns:1fr 1fr;gap:12px;}
    .sod-setting-item{background:#0f172a;border:1px solid #1e293b;border-radius:8px;padding:10px 12px;}
    .sod-setting-label{font-size:10px;color:#64748b;font-weight:600;margin-bottom:4px;}
    .sod-setting-value{font-size:13px;color:#e2e8f0;}
    /* Alerts page */
    .sod-alert-card{
        background:#0f172a;border:1px solid #334155;border-radius:8px;
        padding:10px 12px;display:flex;gap:12px;align-items:flex-start;
    }
    .sod-alert-card.critical{border-color:rgba(220,38,38,.5);background:rgba(220,38,38,.05);}
    .sod-alert-score-circle{
        width:48px;height:48px;border-radius:50%;
        display:flex;align-items:center;justify-content:center;
        font-weight:700;font-size:13px;flex-shrink:0;
    }
    /* Reports page */
    .sod-report-card{background:#0f172a;border:1px solid #1e293b;border-radius:8px;padding:14px;}
    /* Video page */
    .sod-video-grid{display:grid;grid-template-columns:1fr;gap:14px;}
    .sod-video-wall{display:grid;grid-template-columns:1.6fr .9fr;gap:12px;align-items:stretch;}
    .sod-video-featured{background:#020617;border:1px solid #1e3a5f;border-radius:12px;overflow:hidden;display:flex;flex-direction:column;min-width:0;}
    .sod-video-featured-media{aspect-ratio:16/9;position:relative;background:#000;}
    .sod-video-featured-meta{display:flex;align-items:center;gap:8px;padding:10px 12px;border-top:1px solid #1e293b;background:#081120;}
    .sod-video-stack{display:grid;grid-template-columns:1fr;gap:10px;min-width:0;}
    .sod-video-live-grid,
    .sod-video-embed-grid{display:grid;gap:12px;}
    .sod-video-live-grid{grid-template-columns:repeat(auto-fit,minmax(240px,1fr));}
    .sod-video-embed-grid{grid-template-columns:repeat(auto-fit,minmax(280px,1fr));align-items:start;}
    .sod-video-section-title{grid-column:1/-1;font-size:13px;font-weight:700;margin-bottom:4px;display:flex;align-items:center;gap:8px;justify-content:center;text-align:center;}
    .sod-video-section-live{color:#dc2626;}
    .sod-video-section-embed{color:#60a5fa;margin-top:6px;}
    .sod-video-embed-card{background:#0a1929;border:1px solid #334155;border-radius:10px;overflow:hidden;display:flex;flex-direction:column;min-width:0;}
    .sod-video-embed-frame{width:100%;aspect-ratio:16/9;background:#fff;overflow:hidden;}
    .sod-video-embed-frame iframe{width:100% !important;height:100% !important;border:0;display:block;}
    .sod-tg-widget{width:100%;aspect-ratio:16/9;background:#fff;padding:6px;overflow:hidden;display:flex;align-items:flex-start;justify-content:center;}
    .sod-tg-widget > div,
    .sod-tg-widget iframe{max-width:100% !important;width:100% !important;}
    .sod-video-thumb{
        background:#0f172a;border:1px solid #1e293b;border-radius:8px;
        overflow:hidden;aspect-ratio:16/9;display:flex;align-items:center;
        justify-content:center;font-size:36px;cursor:pointer;
    }
    /* Misc */
    .sod-pbi-loading{display:none;}
    .sod-pbi-loading.show{display:inline;animation:sod-spin 1s linear infinite;}
    .sod-divider{height:1px;background:#1e293b;margin:8px 0;}
    .sod-text-muted{color:#475569;font-size:10px;}
    .sod-section-title{font-size:12px;font-weight:700;color:#94a3b8;margin-bottom:8px;display:block;}
    .sod-two-col{display:grid;grid-template-columns:1fr 1fr;gap:12px;}
    .sod-three-col{display:grid;grid-template-columns:2fr 1fr 1fr;gap:12px;}
    @keyframes sod-spin{to{transform:rotate(360deg)}}
    @keyframes sod-blink{0%,100%{opacity:1}50%{opacity:.2}}
    @media(max-width:900px){
        .sod-body{flex-direction:column;}
        .sod-sidebar{width:100%;border-left:none;border-top:1px solid #334155;order:2;}
        .sod-sidebar-nav{display:flex;overflow-x:auto;padding:3px 7px;}
        .sod-nav-btn{white-space:nowrap;padding:7px 12px;border-right:none !important;border-bottom:2px solid transparent;}
        .sod-nav-btn.active{border-bottom-color:#dc2626;border-right:none !important;}
        .sod-page{order:1;}
        .sod-charts-grid,.sod-two-col,.sod-three-col,.sod-settings-grid{grid-template-columns:1fr;}
        .sod-video-wall{grid-template-columns:1fr;}
        .sod-video-live-grid{grid-template-columns:repeat(2,minmax(0,1fr));}
        .sod-video-embed-grid{grid-template-columns:repeat(2,minmax(0,1fr));}
    }
    @media(max-width:600px){
        .sod-kpi-grid{grid-template-columns:repeat(2,1fr);}
        .sod-map-container{height:260px;}
        .sod-video-live-grid,
        .sod-video-embed-grid{grid-template-columns:1fr;}
        .sod-video-featured-meta{flex-wrap:wrap}
    }
