function sod_render_powerbi(array $atts = []): string {
    $atts = shortcode_atts([
        'default_hours' => 24,
        'auto_refresh'  => 60,
        'show_map'      => 'yes',
        'show_charts'   => 'yes',
        'show_feed'     => 'yes',
        'ticker_speed'  => 35,
        'wm_mode'       => 'no',
        'theme'         => 'dark',
    ], $atts);
    $uid           = 'sod_pbi_' . uniqid();
    $default_hours = max(1, (int) $atts['default_hours']);
    $auto_refresh  = max(15, (int) $atts['auto_refresh']);
    $show_map      = $atts['show_map'] === 'yes';
    $show_charts   = $atts['show_charts'] === 'yes';
    $show_feed     = $atts['show_feed'] === 'yes';
    $ticker_speed  = max(8, min(120, (int) $atts['ticker_speed']));
    $wm_mode       = ($atts['wm_mode'] ?? 'no') === 'yes';
    ob_start(); ?>
