function renderKPI(id,val){const el=$id('kpi-'+id);if(el)el.textContent=val;}

/* ── Feed (dashboard page) ── */
function renderFeed(){
    const tbody=$id('feed-tbody');if(!tbody)return;
    const scoreFilter=parseInt($id('feed-filter-score')?.value||0);
    const searchTerm=($id('feed-search')?.value||'').toLowerCase().trim();
    let filtered=allEvents.filter(e=>{
        if(e.score<scoreFilter)return false;
        const title=(e.title||'').toLowerCase();
        const actor=(e.actor_v2||'').toLowerCase();
        const region=(e.region||'').toLowerCase();
        if(searchTerm && !title.includes(searchTerm) && !actor.includes(searchTerm) && !region.includes(searchTerm)) return false;
        return true;
    });
    const total=filtered.length;
    const pages=Math.ceil(total/FEED_PER_PAGE);
    feedPage=Math.min(feedPage,Math.max(0,pages-1));
    const slice=filtered.slice(feedPage*FEED_PER_PAGE,(feedPage+1)*FEED_PER_PAGE);
    if(!slice.length){tbody.innerHTML='<tr><td colspan="6" class="sod-loading-row">لا توجد أحداث مطابقة</td></tr>';return;}
    tbody.innerHTML=slice.map(ev=>{
        const col=scoreColor(ev.score);
        const lbl=scoreLabel(ev.score);
        const aiB=ev.llm_verified?'<span title="تم التحقق بالذكاء الاصطناعي" style="color:#60a5fa;margin-inline-end:4px;">🤖</span>':'';
        const actorLabel=(ev.actor_v2||'—');
        const regionLabel=(ev.region||'—');
        const levelLabel=ev.tactical_level||'—';
        const title = String(ev.title||'');
        return `<tr>
            <td style="text-align:center;"><span class="sod-score-badge" style="background:${col}20;color:${col};border:1px solid ${col}40;">${ar(ev.score)}</span><br><small style="font-size:9px;color:#94a3b8;">${lbl}</small></td>
            <td style="color:#94a3b8;font-size:10px;text-align:center;white-space:nowrap;">${timeAgo(ev.event_timestamp)}</td>
            <td style="font-size:12px;color:#e5edf9;text-align:center;font-weight:700;">${esc(String(actorLabel))}</td>
            <td><a href="${esc(ev.link)}" target="_blank" rel="noopener noreferrer" style="font-size:12px;display:inline-block;max-width:100%;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;vertical-align:middle;">${aiB}${esc(title)}</a></td>
            <td style="font-size:10px;color:#cbd5e1;text-align:center;">${esc(String(regionLabel))}</td>
            <td style="text-align:center;"><span class="sod-level-chip">${esc(String(levelLabel).substring(0,14))}</span></td>
        </tr>`;
    }).join('');
    const pag=$id('feed-pagination');if(!pag)return;
    if(pages>1){pag.innerHTML=Array.from({length:pages},(_,i)=>`<button class="sod-page-btn${i===feedPage?' active':''}" onclick="sod_feedpage_${UID}(${i})">${ar(i+1)}</button>`).join('');}
    else pag.innerHTML='';
}
window['sod_feedpage_'+UID]=(p)=>{feedPage=p;renderFeed();};

function renderCommandDeck(analytics,events){
    const total=analytics?.total||0;
    const gci=analytics?.gci||0;
    const hotRegions=Object.entries(analytics?.regions||{}).sort((a,b)=>b[1]-a[1]).slice(0,5);
    const topActors=Object.entries(analytics?.actors||{}).sort((a,b)=>b[1]-a[1]).slice(0,5);
    const truth=analytics?.truth_layers||{};
    const totalBase=Math.max(1,total);
    const escalation=Math.min(100,Math.round((analytics?.escalation_index||0)));
    const deception=Math.min(100,Math.round((analytics?.deception_index||0)));
    const hybridData=[
        Math.min(100,Math.round(((truth.field_action||0)/totalBase)*100)),
        Math.min(100,Math.round(((truth.statement||0)/totalBase)*100)),
        Math.min(100,Math.round(((truth.report||0)/totalBase)*100)),
        deception,
        escalation,
    ];

    const set=(id,val)=>{const el=$id(id); if(el) el.textContent=val;};
    ['cmd-total','bi-cmd-total'].forEach(id=>set(id, ar(total)));
    ['cmd-gci','bi-cmd-gci'].forEach(id=>set(id, ar(gci)));
    ['cmd-hot-count','bi-cmd-hot-count'].forEach(id=>set(id, ar(hotRegions.length)));
    ['cmd-top-actor','bi-cmd-top-actor'].forEach(id=>set(id, topActors[0] ? topActors[0][0].substring(0,16) : '—'));
    ['bi-cmd-escalation'].forEach(id=>set(id, ar(escalation)+'%'));
    ['bi-cmd-deception'].forEach(id=>set(id, ar(deception)+'%'));

    const regionHTML=hotRegions.length ? hotRegions.map(([name,count],i)=>`<div class="sod-strategic-row"><strong>${ar(i+1)}. ${esc(name)}</strong><span class="sod-soft-badge">${ar(count)}</span></div>`).join('') : '<div class="sod-loading-row">لا توجد بيانات كافية.</div>';
    ['cmd-regions-list','bi-cmd-regions-list'].forEach(id=>{const el=$id(id); if(el) el.innerHTML=regionHTML;});
    const actorHTML=topActors.length ? topActors.map(([name,count],i)=>`<div class="sod-strategic-row"><strong>${ar(i+1)}. ${esc(name)}</strong><span class="sod-soft-badge">${ar(count)}</span></div>`).join('') : '<div class="sod-loading-row">لا توجد بيانات كافية.</div>';
    ['cmd-actors-list','bi-cmd-actors-list'].forEach(id=>{const el=$id(id); if(el) el.innerHTML=actorHTML;});
    const hot=hotRegions[0]?.[0]||'الساحة العامة';
    const actor=topActors[0]?.[0]||'الفاعل غير المحسوم';
    const brief=`تشير القراءة الحالية إلى أن <strong>${esc(hot)}</strong> هي الساحة الأكثر اشتعالًا، مع بروز <strong>${esc(actor)}</strong> كأكثر الجهات نشاطًا. يظهر المسار العام <strong>${(analytics?.escalation_index||0)>=60?'تصعيدًا مرتفعًا':'ضغطًا متدرجًا'}</strong>، فيما يظل البعد الإعلامي/النفسي حاضرًا بقوة ضمن المشهد.`;
    ['cmd-brief','bi-cmd-brief'].forEach(id=>{const el=$id(id); if(el) el.innerHTML=brief;});

    const forecast=[
      ['تصعيد خلال 24 ساعة', Math.min(100, Math.max(15, escalation + 12))],
      ['ضغط نفسي / إعلامي', Math.min(100, Math.max(10, deception + 8))],
      ['مخاطر اقتصادية', Math.min(100, Math.round((((analytics?.hybrid_layers?.economic)||0)/totalBase)*100))],
      ['نشاط سيبراني', Math.min(100, Math.round((((analytics?.hybrid_layers?.cyber)||0)/totalBase)*100))],
    ];
    const forecastHTML=forecast.map(([label,val])=>`<div class="sod-forecast-item"><span>${label}</span><div class="sod-forecast-bar"><div class="sod-forecast-fill" style="width:${val}%"></div></div><strong>${ar(val)}%</strong></div>`).join('');
    ['cmd-forecast','bi-cmd-forecast'].forEach(id=>{const el=$id(id); if(el) el.innerHTML=forecastHTML;});

    ['cmd-hybrid-chart','bi-cmd-hybrid-chart'].forEach((chartId,idx)=>{
        const chartEl=$id(chartId);
        if(chartEl && window.Chart){
            const key=(idx===0?'cmdHybrid_':'biCmdHybrid_')+UID;
            if(window[key]){window[key].destroy();}
            window[key]=new Chart(chartEl.getContext('2d'),{
                type:'bar',
                data:{labels:['ميداني','تصريحي','تقاريري','تضليل','تصعيد'],datasets:[{data:hybridData,backgroundColor:['#2f2f8f','#5062b8','#7b89d1','#9aa8eb','#c5cef8'],borderWidth:0}]},
                options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{display:false}},scales:{y:{beginAtZero:true,max:100,ticks:{color:'#334155'},grid:{color:'#e2e8f0'}},x:{ticks:{color:'#1d2f6f',font:{weight:'700'}},grid:{display:false}}}}
            });
        }
    });
}



function inferCentralStates(events){
    const map = {};
    const aliases = {
        'الولايات المتحدة':'الولايات المتحدة','أمريكا':'الولايات المتحدة','واشنطن':'الولايات المتحدة',
        'إسرائيل':'إسرائيل','العدو الإسرائيلي':'إسرائيل','جيش العدو الإسرائيلي':'إسرائيل','إعلام إسرائيلي':'إسرائيل','الأراضي المحتلة (إسرائيل)':'إسرائيل',
        'إيران':'إيران','أوكرانيا':'أوكرانيا','روسيا':'روسيا','الصين':'الصين','لبنان':'لبنان'
    };
    const allowed = ['الولايات المتحدة','إسرائيل','إيران','أوكرانيا','روسيا','الصين','لبنان'];
    function norm(v){
        v = String(v||'').trim();
        for (const k in aliases){ if(v.includes(k)) return aliases[k]; }
        return '';
    }
    function add(name, weight){
        if(!name || !allowed.includes(name)) return;
        map[name] = (map[name]||0) + (weight||1);
    }
    (events||[]).forEach(ev=>{
        add(norm(ev.actor_v2), 5);
        add(norm(ev.actor_primary), 4);
        add(norm(ev.source_name), 2);
        add(norm(ev.target_v2), 2);
        add(norm(ev.context_v2), 1);
        // region gets the smallest weight to avoid false "central state" bias
        add(norm(ev.region), 0.5);
        // title is useful but noisy
        const title = String(ev.title||'');
        Object.keys(aliases).forEach(k=>{
            if(title.includes(k)) add(aliases[k], 1.5);
        });
    });
    return Object.entries(map).sort((a,b)=>b[1]-a[1]);
}
function normalizeStateName(name){
    const s = String(name||'').trim();
    const map = {
        'أمريكا':'الولايات المتحدة','واشنطن':'الولايات المتحدة','USA':'الولايات المتحدة','US':'الولايات المتحدة',
        'العدو الإسرائيلي':'إسرائيل','جيش العدو الإسرائيلي':'إسرائيل','الأراضي المحتلة (إسرائيل)':'إسرائيل','إعلام إسرائيلي':'إسرائيل',
        'بريطانيا':'المملكة المتحدة','UK':'المملكة المتحدة','الإتحاد الأوروبي':'الاتحاد الأوروبي'
    };
    return map[s] || s;
}
function detectConflictTheater(ev){
    const hay = [ev.region, ev.actor_v2, ev.actor_primary, ev.target_v2, ev.context_v2, ev.title, ev.source_name].map(v=>String(v||'')).join(' | ');
    const rules = [
        ['غرب آسيا', /(لبنان|فلسطين|غزة|الضفة|إسرائيل|إيراني?|إيران|سوريا|العراق|اليمن|الحوثي|الخليج|السعودية|قطر|الإمارات|البحرين|الأردن|هرمز|البحر الأحمر|حزب الله|حماس|الجهاد الإسلامي)/i],
        ['ساحة الهادئ', /(الصين|تايوان|اليابان|الكوريتين|كوريا|الفلبين|بحر الصين|المحيط الهادئ|أستراليا|اندونيسيا|الهند-الهادئ|indopacific|pacific)/i],
        ['الجبهة الشرقية للناتو', /(بولندا|إستونيا|لاتفيا|ليتوانيا|رومانيا|مولدوفا|فنلندا|بيلاروسيا|كالينينغراد|شرق أوروبا|الجبهة الشرقية للناتو|nato eastern flank)/i],
        ['ساحة أوروبا', /(أوكرانيا|روسيا|أوروبا|بروكسل|فرنسا|ألمانيا|المملكة المتحدة|بريطانيا|إيطاليا|إسبانيا|اليونان|البحر الأسود|البلقان|الاتحاد الأوروبي|nato)/i]
    ];
    for (const [name, rx] of rules){ if (rx.test(hay)) return name; }
    return 'ساحات التوتر العالمية';
}
function detectImpactDimensions(ev){
    const hay = [ev.title, ev.context_v2, ev.target_v2, ev.actor_v2, ev.region].map(v=>String(v||'')).join(' | ');
    const out = new Set();
    const add = (name, rx) => { if (rx.test(hay)) out.add(name); };
    add('عسكرية', /(غارة|قصف|صاروخ|مسيرة|مسيّرة|اشتباك|هجوم|دبابة|قاعدة|جبهة|توغل|بحري|دفاع جوي|طائرة|استهداف)/i);
    add('أمنية', /(أمني|أمن|شرطة|اعتقال|تفتيش|خلية|تفجير|إرهاب|حرس|حماية|تهديد)/i);
    add('اقتصادية', /(عقوبات|اقتصاد|عملة|بورصة|تضخم|تمويل|استثمار|تجارة|ممر تجاري|رسوم|بنك)/i);
    add('إعلامية', /(إعلام|تصريح|بيان|رواية|بروباغندا|تضليل|خبر عاجل|منصة|حملة|قناة)/i);
    add('الأمن الاجتماعي', /(نزوح|لاجئين|لجوء|احتجاج|اضطراب|مدنيين|مجاعة|أزمة إنسانية|مخيم)/i);
    add('الهجرة', /(هجرة|لاجئين|لجوء|نزوح جماعي|عبور الحدود)/i);
    add('سياسية', /(مفاوضات|وساطة|قمة|اتفاق|قرار|انتخابات|حكومة|برلمان|وزير|رئيس|ديبلوماس|دبلوماس)/i);
    add('سيبرانية', /(سيبراني|اختراق|هجوم إلكتروني|برمجيات|تعطيل شبكة|Cyber|malware|phishing)/i);
    add('طاقة', /(نفط|غاز|كهرباء|مصفاة|أنبوب|حقل|أوبك|طاقة)/i);
    add('استخباراتية', /(استخبارات|تجسس|اغتيال|رصد|اعتراض|تسريب|جاسوس)/i);
    if (!out.size) out.add('أمنية');
    return Array.from(out);
}
function relationTypeByAxes(a,b){
    const resistance = ['إيران','سوريا','حزب الله','حماس','الجهاد الإسلامي','الحوثيون','فصائل المقاومة العراقية'];
    const western = ['الولايات المتحدة','إسرائيل','المملكة المتحدة','فرنسا','الناتو'];
    const east = ['روسيا','الصين'];
    const A = normalizeStateName(a), B = normalizeStateName(b);
    const hardHostile = new Set(['إيران|إسرائيل','إسرائيل|إيران','إيران|الولايات المتحدة','الولايات المتحدة|إيران','السعودية|إيران','إيران|السعودية','حزب الله|إسرائيل','إسرائيل|حزب الله','حماس|إسرائيل','إسرائيل|حماس']);
    if (A===B) return 'self';
    if (hardHostile.has(`${A}|${B}`)) return 'hostile';
    const inRes = x => resistance.includes(x), inWest = x => western.includes(x), inEast = x => east.includes(x);
    if ((inRes(A) && inWest(B)) || (inWest(A) && inRes(B))) return 'hostile';
    if ((inRes(A) && inRes(B)) || (inWest(A) && inWest(B))) return 'allied';
    if ((A==='إيران' && B==='الصين') || (A==='الصين' && B==='إيران') || (A==='روسيا' && B==='الصين') || (A==='الصين' && B==='روسيا')) return 'strategic';
    if ((inEast(A) && inWest(B)) || (inWest(A) && inEast(B))) return 'competitive';
    return 'linked';
}
function inferActorsFromEvent(ev){
    const seen = new Set();
    const out = [];
    const raw = [ev.actor_v2, ev.actor_primary, ev.target_v2, ev.source_name];
    raw.forEach(v=>{
        const n = normalizeStateName(String(v||'').trim());
        if (n && n!=='غير محدد' && n!=='فاعل غير محسوم' && !seen.has(n) && n.length < 40){ seen.add(n); out.push(n); }
    });
    const title = String(ev.title||'');
    ['إيران','إسرائيل','الولايات المتحدة','روسيا','الصين','أوكرانيا','السعودية','تركيا','لبنان','سوريا','العراق','اليمن','حزب الله','حماس','الحوثيون','فرنسا','المملكة المتحدة','الناتو'].forEach(name=>{
        if (title.includes(name) && !seen.has(name)){ seen.add(name); out.push(name); }
    });
    return out;
}
function classifyAxisCluster(name){
    const n = normalizeStateName(String(name||''));
    if (!n) return 'other';
    const resistance = ['إيران','سوريا','حزب الله','حماس','الجهاد الإسلامي','الحوثيون','فصائل المقاومة العراقية','العراق','اليمن','لبنان'];
    const western = ['الولايات المتحدة','إسرائيل','الناتو','المملكة المتحدة','فرنسا','ألمانيا','إيطاليا','إسبانيا','بولندا','رومانيا','اليونان'];
    const east = ['روسيا','الصين','بيلاروسيا','كوريا الشمالية'];
    const europe = ['أوكرانيا','أوروبا','الاتحاد الأوروبي','فرنسا','ألمانيا','المملكة المتحدة','إيطاليا','إسبانيا','اليونان','بولندا','رومانيا','فنلندا','إستونيا','لاتفيا','ليتوانيا'];
    const pacific = ['الصين','تايوان','اليابان','كوريا الجنوبية','كوريا الشمالية','أستراليا','الفلبين','إندونيسيا','الهند'];
    if (resistance.includes(n)) return 'resistance';
    if (pacific.includes(n)) return 'pacific';
    if (east.includes(n)) return 'east';
    if (western.includes(n)) return 'western';
    if (europe.includes(n)) return 'europe';
    return 'other';
}
function buildHybridRelations(events, centralState){
    const theaters = {}, activeStates = {}, influentialStates = {}, adversaries = {}, impacts = {}, relationEdges = {}, nodeEvents = {}, axisBuckets = {
        resistance:{}, western:{}, east:{}, europe:{}, pacific:{}, other:{}
    };
    function addCount(obj,key,val){ if(!key) return; obj[key]=(obj[key]||0)+(val||1); }
    function pushEvent(key, ev){
        if(!key) return;
        if(!nodeEvents[key]) nodeEvents[key] = [];
        if(nodeEvents[key].length < 5){
            nodeEvents[key].push({title:String(ev.title||'بدون عنوان'), score:Number(ev.score||0), region:String(ev.region||'غير محدد')});
        }
    }
    (events||[]).forEach(ev=>{
        const theater = detectConflictTheater(ev);
        addCount(theaters, theater, 1);
        pushEvent(theater, ev);
        const dimensions = detectImpactDimensions(ev);
        dimensions.forEach(dim=> addCount(impacts, dim, 1));
        const actors = inferActorsFromEvent(ev);
        actors.forEach((actor, idx)=>{
            addCount(activeStates, actor, idx===0 ? 3 : 2);
            pushEvent(actor, ev);
            const bucket = classifyAxisCluster(actor);
            addCount(axisBuckets[bucket], actor, idx===0 ? 3 : 2);
            if (['الولايات المتحدة','إسرائيل','إيران','روسيا','الصين','المملكة المتحدة','فرنسا','السعودية','تركيا','الناتو','ألمانيا','اليابان'].includes(actor)) addCount(influentialStates, actor, 2);
        });
        for (let i=0; i<actors.length; i++){
            for (let j=i+1; j<actors.length; j++){
                const a = actors[i], b = actors[j];
                const type = relationTypeByAxes(a,b);
                if (type==='self') continue;
                const key = [a,b].sort().join(' ↔ ');
                if(!relationEdges[key]) relationEdges[key] = {count:0,type};
                relationEdges[key].count += 1;
                if (type==='hostile') { addCount(adversaries, a, 1); addCount(adversaries, b, 1); }
                pushEvent(key, ev);
            }
        }
    });
    const topTheaters = Object.entries(theaters).sort((a,b)=>b[1]-a[1]).slice(0,6);
    const active = Object.entries(activeStates).filter(([n])=>n!==centralState).sort((a,b)=>b[1]-a[1]).slice(0,10);
    const influential = Object.entries(influentialStates).filter(([n])=>n!==centralState).sort((a,b)=>b[1]-a[1]).slice(0,8);
    const hostile = Object.entries(adversaries).filter(([n])=>n!==centralState).sort((a,b)=>b[1]-a[1]).slice(0,8);
    const effectList = Object.entries(impacts).sort((a,b)=>b[1]-a[1]).slice(0,8);
    const edges = Object.entries(relationEdges).sort((a,b)=>b[1].count-a[1].count).slice(0,16);
    const centralTheater = topTheaters[0]?.[0] || detectConflictTheater({region:centralState});
    const axisClusters = Object.fromEntries(Object.entries(axisBuckets).map(([k,v])=>[k, Object.entries(v).sort((a,b)=>b[1]-a[1]).slice(0,8)]));
    return {theaters:topTheaters, activeStates:active, influentialStates:influential, adversaries:hostile, impacts:effectList, edges, centralTheater, nodeEvents, axisClusters};
}
function renderRelationGraph(graphEl, centralState, relations){
    if(!graphEl) return;
    const svgNS = 'http://www.w3.org/2000/svg';
    const width = 1200, height = 680, cx = 600, cy = 320;
    const svg = graphEl;
    svg.innerHTML = '';

    function addText(x,y,textValue,cls,anchor='middle'){
        const t = document.createElementNS(svgNS,'text');
        t.setAttribute('x', x); t.setAttribute('y', y);
        t.setAttribute('text-anchor', anchor);
        t.setAttribute('class', cls);
        t.textContent = textValue;
        svg.appendChild(t);
        return t;
    }
    function makeNode(id,label,sub,x,y,r,fill,group){ return {id,label,sub,x,y,r,fill,group}; }
    function pathBetween(a,b,curve){
        const mx = (a.x + b.x)/2 + (curve||0);
        const my = (a.y + b.y)/2 + ((a.group===b.group)?-18:0);
        return `M ${a.x} ${a.y} Q ${mx} ${my} ${b.x} ${b.y}`;
    }
    function setRelationEvents(title, subtitle, rows){
        const box = document.getElementById(UID+'-relation-events');
        if(!box) return;
        const items = (rows||[]).slice(0,6);
        if(!items.length){
            box.innerHTML = `<div class="sod-relation-event-card"><div class="sod-relation-event-title">${esc(title)}</div><div class="sod-relation-event-meta"><span>${esc(subtitle||'')}</span><span>لا توجد أخبار كافية مرتبطة بهذا العنصر.</span></div></div>`;
            return;
        }
        box.innerHTML = items.map((row,i)=>`<div class="sod-relation-event-card"><div class="sod-relation-event-title">${ar(i+1)}. ${esc(row.title||'بدون عنوان')}</div><div class="sod-relation-event-meta"><span>${esc(row.region||'غير محدد')}</span><span>الخطورة: ${ar(row.score||0)}</span><span>${esc(subtitle||'')}</span></div></div>`).join('');
    }

    const theaterCenter = makeNode('center', relations.centralTheater || centralState || 'ساحة الصراع', 'العقدة المركزية للمسرح', cx, cy, 44, '#d4a74f', 'center');
    const nodes = [theaterCenter];
    const nodeByLabel = {};

    const clusters = [
        {key:'resistance', label:'محور المقاومة', x:260, y:180, color:'#d4a74f', ring:'#6b4f1d'},
        {key:'western', label:'المحور الغربي', x:940, y:180, color:'#60a5fa', ring:'#1d4ed8'},
        {key:'east', label:'الشرق', x:600, y:122, color:'#22c55e', ring:'#166534'},
        {key:'europe', label:'أوروبا', x:930, y:450, color:'#a78bfa', ring:'#6d28d9'},
        {key:'pacific', label:'الهادئ', x:270, y:450, color:'#14b8a6', ring:'#0f766e'}
    ];

    clusters.forEach(cluster=>{
        const halo = document.createElementNS(svgNS,'circle');
        halo.setAttribute('cx', cluster.x); halo.setAttribute('cy', cluster.y); halo.setAttribute('r', '96');
        halo.setAttribute('fill', 'none'); halo.setAttribute('stroke', cluster.ring); halo.setAttribute('stroke-width', '1.3');
        halo.setAttribute('stroke-dasharray', '8 8'); halo.setAttribute('opacity', '0.35');
        svg.appendChild(halo);
        addText(cluster.x, cluster.y - 108, cluster.label, 'sod-rel-group-label', 'middle');
    });

    const theaters = (relations.theaters||[]).slice(0,5);
    theaters.forEach(([name,count], idx)=>{
        const angle = (-145 + idx*72) * Math.PI / 180;
        const r = 250;
        const x = cx + Math.cos(angle) * r;
        const y = cy + Math.sin(angle) * r;
        const node = makeNode('theater'+idx, name, `ساحة · ${count}`, x, y, 17 + Math.min(4,count), '#8b5cf6', 'theater');
        nodes.push(node); nodeByLabel[name] = node;
    });

    const impacts = (relations.impacts||[]).slice(0,6);
    impacts.forEach(([name,count], idx)=>{
        const x = 860 + (idx%3)*110;
        const y = 540 + Math.floor(idx/3)*42;
        const node = makeNode('impact'+idx, name, `تأثير · ${count}`, x, y, 13 + Math.min(3,count), '#94a3b8', 'impact');
        nodes.push(node); nodeByLabel[name] = node;
    });
    addText(970, 512, 'التأثيرات', 'sod-rel-group-label', 'middle');

    clusters.forEach(cluster=>{
        const entries = (relations.axisClusters?.[cluster.key] || []).slice(0,6);
        entries.forEach(([name,count], idx)=>{
            const angle = ((360/Math.max(1,entries.length))*idx - 90) * Math.PI / 180;
            const radius = 56 + (idx%2)*16;
            const x = cluster.x + Math.cos(angle)*radius;
            const y = cluster.y + Math.sin(angle)*radius;
            const node = makeNode(`${cluster.key}-${idx}`, name, `${cluster.label} · ${count}`, x, y, 18 + Math.min(8, Math.round(count/2)), cluster.color, cluster.key);
            nodes.push(node); nodeByLabel[name] = node;
        });
    });

    nodeByLabel[theaterCenter.label] = theaterCenter;

    const allLinks = [];
    clusters.forEach(cluster=>{
        const entries = (relations.axisClusters?.[cluster.key] || []).slice(0,6);
        entries.forEach(([name,count], idx)=>{
            const node = nodeByLabel[name];
            if(!node) return;
            allLinks.push({a:theaterCenter,b:node,type:(cluster.key==='resistance'?'allied':(cluster.key==='western'?'hostile':(cluster.key==='east'?'strategic':'linked'))),width:2.4 + Math.min(3,count/2),curve:(cluster.x<cx?-26:26)+(idx*6),label:`${theaterCenter.label} ↔ ${name}`,key:name});
        });
    });

    theaters.forEach(([name,count], idx)=>{
        const node = nodeByLabel[name];
        if(node) allLinks.push({a:theaterCenter,b:node,type:'theater',width:1.8 + Math.min(2,count/3),curve:-10 + idx*10,label:`ساحة مرتبطة: ${name}`,key:name});
    });

    (relations.edges||[]).slice(0,14).forEach(([edgeKey, edgeData], idx)=>{
        const parts = String(edgeKey).split(' ↔ ');
        if(parts.length!==2) return;
        const a = nodeByLabel[parts[0]], b = nodeByLabel[parts[1]];
        if(!a || !b || a.id===b.id) return;
        allLinks.push({a,b,type:edgeData.type||'linked',width:1.3 + Math.min(4,Number(edgeData.count||1)),curve:(idx%2===0?24:-24),label:edgeKey,key:edgeKey});
    });

    const relationLayer = document.createElementNS(svgNS,'g');
    relationLayer.setAttribute('class','sod-rel-links-layer');
    svg.appendChild(relationLayer);

    allLinks.forEach(link=>{
        const p = document.createElementNS(svgNS,'path');
        p.setAttribute('d', pathBetween(link.a, link.b, link.curve));
        const stroke = link.type==='hostile' ? '#ef4444' : (link.type==='strategic' ? '#22c55e' : (link.type==='theater' ? '#8b5cf6' : (link.type==='competitive' ? '#f59e0b' : (link.type==='allied' ? '#3b82f6' : '#94a3b8'))));
        p.setAttribute('fill','none');
        p.setAttribute('stroke', stroke);
        p.setAttribute('stroke-width', String(link.width||2));
        p.setAttribute('opacity', link.type==='theater' ? '0.45' : '0.82');
        p.setAttribute('class','sod-rel-link');
        if (link.type==='hostile') p.setAttribute('stroke-dasharray','10 6');
        relationLayer.appendChild(p);
        p.addEventListener('click', function(){
            setRelationEvents(link.label, 'أخبار مرتبطة بالخط المختار', relations.nodeEvents[link.key] || []);
            const analysisEl = document.getElementById(UID+'-relation-analysis');
            if(analysisEl){ analysisEl.innerHTML = `<strong>${esc(link.label)}</strong><div style="margin-top:8px">تم اختيار علاقة شبكية من نوع: <strong>${esc(link.type)}</strong>.</div>`; }
        });
    });

    const nodeLayer = document.createElementNS(svgNS,'g');
    nodeLayer.setAttribute('class','sod-rel-nodes-layer');
    svg.appendChild(nodeLayer);

    nodes.forEach(node=>{
        const g = document.createElementNS(svgNS,'g');
        g.setAttribute('class','sod-rel-node');
        const halo = document.createElementNS(svgNS,'circle');
        halo.setAttribute('cx', node.x); halo.setAttribute('cy', node.y); halo.setAttribute('r', node.r + (node.group==='center'?8:5));
        halo.setAttribute('fill', 'none'); halo.setAttribute('stroke', '#ffffff1f'); halo.setAttribute('stroke-width', node.group==='center' ? '9' : '5');
        const c = document.createElementNS(svgNS,'circle');
        c.setAttribute('cx', node.x); c.setAttribute('cy', node.y); c.setAttribute('r', node.r);
        c.setAttribute('fill', node.fill); c.setAttribute('stroke', '#fff'); c.setAttribute('stroke-width', node.group==='center' ? '2.2' : '1.6');
        const t = document.createElementNS(svgNS,'text');
        t.setAttribute('x', node.x); t.setAttribute('y', node.y + 4); t.setAttribute('text-anchor','middle');
        t.setAttribute('class','sod-rel-label'); t.textContent = node.label;
        const s = document.createElementNS(svgNS,'text');
        s.setAttribute('x', node.x); s.setAttribute('y', node.y + node.r + 18); s.setAttribute('text-anchor','middle');
        s.setAttribute('class','sod-rel-sub'); s.textContent = node.sub;
        g.appendChild(halo); g.appendChild(c); g.appendChild(t); g.appendChild(s);
        g.addEventListener('click', function(){
            setRelationEvents(node.label, node.sub, relations.nodeEvents[node.label] || []);
            const analysisEl = document.getElementById(UID+'-relation-analysis');
            if(analysisEl){ analysisEl.innerHTML = `<strong>${esc(node.label)}</strong> — ${esc(node.sub)}<div style="margin-top:8px">تم اختيار هذه العقدة من الرسم، وآخر الأخبار المرتبطة بها ظهرت الآن أسفل الرسم مباشرة.</div>`; }
        });
        nodeLayer.appendChild(g);
    });

    setRelationEvents(theaterCenter.label, theaterCenter.sub, relations.nodeEvents[theaterCenter.label] || []);
}

function renderHybridWar(analytics,events){
    const total=Math.max(1, analytics?.total || events?.length || 1);
    const layers=analytics?.hybrid_layers_count || analytics?.hybrid_layers || {};
    const layerMap={
        military:'عسكري',security:'أمني',political:'سياسي',economic:'اقتصادي',cyber:'سيبراني',
        media_psychological:'إعلامي / نفسي',social:'اجتماعي',geostrategic:'جيوسياسي',energy:'طاقة',
        intelligence:'استخباراتي',legal:'قانوني',diplomatic:'دبلوماسي',logistics:'لوجستي',cultural:'ثقافي'
    };
    const layerEntries=Object.entries(layers).map(([k,v])=>({key:k,label:layerMap[k]||k,count:Number(v)||0,pct:Math.min(100,Math.round(((Number(v)||0)/total)*100))})).sort((a,b)=>b.count-a.count).filter(x=>x.count>0);
    const bars=$id('hybrid-bars');
    if(bars){
        bars.innerHTML=layerEntries.length?layerEntries.slice(0,8).map(item=>`<div class="sod-hybrid-bar-row"><strong>${esc(item.label)}</strong><div class="sod-hybrid-bar-track"><div class="sod-hybrid-bar-fill" style="width:${item.pct}%"></div></div><span>${ar(item.count)}</span></div>`).join(''):'<div class="sod-loading-row">لا توجد بيانات مركبة كافية.</div>';
    }
    const theaters=analytics?.top_hybrid_theaters || analytics?.hybrid_theater_index || {};
    const theaterEntries=Array.isArray(theaters)?theaters:Object.entries(theaters).map(([name,val])=>({name, index: Number(val?.index||val||0), alert: val?.alert||''})).sort((a,b)=>b.index-a.index).slice(0,5);
    const theatersEl=$id('hybrid-theaters');
    if(theatersEl){
        theatersEl.innerHTML=theaterEntries.length?theaterEntries.map((item,i)=>`<div class="sod-hybrid-mini-item"><span>${ar(i+1)}. ${esc(item.name)}</span><strong>${ar(item.index)}${item.alert?` — ${esc(item.alert)}`:''}</strong></div>`).join(''):'<div class="sod-loading-row">لا توجد ساحات مركبة كافية.</div>';
    }
    const combos=analytics?.hybrid_combinations || {};
    const comboEntries=Object.entries(combos).sort((a,b)=>b[1]-a[1]).slice(0,5);
    const translateCombo=(combo)=>combo.split('+').map(part=>layerMap[part]||part).join(' + ');
    const combosEl=$id('hybrid-combos');
    if(combosEl){
        combosEl.innerHTML=comboEntries.length?comboEntries.map(([combo,count])=>`<div class="sod-hybrid-mini-item"><span>${esc(translateCombo(combo))}</span><strong>${ar(count)}</strong></div>`).join(''):'<div class="sod-loading-row">لا توجد توليفات مركبة كافية.</div>';
    }
    const hybridActors={};
    (events||[]).forEach(ev=>{
        let layersEv=[];
        try{
            const field=typeof ev.field_data==='string'?JSON.parse(ev.field_data||'{}'):(ev.field_data||{});
            const war=typeof ev.war_data==='string'?JSON.parse(ev.war_data||'{}'):(ev.war_data||{});
            layersEv=(field.hybrid_layers||war.hybrid_layers||ev.hybrid_layers||[]);
            if(typeof layersEv==='string'){layersEv=layersEv.split(/[,+|\/]/).map(s=>s.trim()).filter(Boolean);}
        }catch(_e){layersEv=[];}
        if(Array.isArray(layersEv) && layersEv.length){
            const actor=ev.actor_v2||ev.actor_primary||'فاعل غير محسوم';
            hybridActors[actor]=(hybridActors[actor]||0)+1;
        }
    });
    const actorEntries=Object.entries(hybridActors).sort((a,b)=>b[1]-a[1]).slice(0,6);
    const actorsEl=$id('hybrid-actors');
    if(actorsEl){
        actorsEl.innerHTML=actorEntries.length?actorEntries.map(([name,count],i)=>`<div class="sod-hybrid-mini-item"><span>${ar(i+1)}. ${esc(name)}</span><strong>${ar(count)}</strong></div>`).join(''):'<div class="sod-loading-row">لا توجد بيانات كافية.</div>';
    }
    const topLayer=layerEntries[0]?.label || '—';
    const topTheater=theaterEntries[0]?.name || (analytics?.hot_region || '—');
    const topCombo=comboEntries[0]?.[0] ? translateCombo(comboEntries[0][0]) : '—';
    const multi=(events||[]).filter(ev=>{
        try{
            const field=typeof ev.field_data==='string'?JSON.parse(ev.field_data||'{}'):(ev.field_data||{});
            const war=typeof ev.war_data==='string'?JSON.parse(ev.war_data||'{}'):(ev.war_data||{});
            let l=field.hybrid_layers||war.hybrid_layers||ev.hybrid_layers||[];
            if(typeof l==='string') l=l.split(/[,+|\/]/).map(s=>s.trim()).filter(Boolean);
            return Array.isArray(l) && l.length>=2;
        }catch(_e){return false;}
    }).length;
    const set=(id,val)=>{const el=$id(id); if(el) el.textContent=val;};
    set('hybrid-top-layer', topLayer);
    set('hybrid-top-theater', topTheater);
    set('hybrid-top-combo', topCombo);
    set('hybrid-multi', ar(multi));
    const briefEl=$id('hybrid-brief');
    if(briefEl){
        const escalation=Math.round(analytics?.escalation_index||0);
        const deception=Math.round(analytics?.deception_index||0);
        briefEl.innerHTML=`تُظهر القراءة الحالية أن <strong>${esc(topLayer)}</strong> هي الطبقة الأبرز، مع تمركز النشاط المركب في <strong>${esc(topTheater)}</strong>. التوليفة الأكثر تكرارًا هي <strong>${esc(topCombo)}</strong>، فيما يبلغ مستوى التصعيد <strong>${ar(escalation)}%</strong> والتضليل <strong>${ar(deception)}%</strong>.`; 
    }

    const centralCandidates = inferCentralStates(events||[]);
    const centralState = centralCandidates[0]?.[0] || topTheater || '—';
    const relations = buildHybridRelations(events||[], centralState);
    set('relation-central-state', relations.centralTheater || '—');
    set('relation-top-ally', relations.activeStates[0]?.[0] || '—');
    set('relation-top-theater', relations.adversaries[0]?.[0] || '—');
    set('relation-top-link', relations.impacts[0]?.[0] || '—');

    const stateTheatersEl = $id('relation-state-theaters');
    if(stateTheatersEl){
        const rows = [];
        relations.theaters.forEach(([name,count],i)=>{
            rows.push(`<div class="sod-rel-item"><div><div class="left">${ar(i+1)}. ${esc(name)}</div><div class="meta">ساحة صراع مرصودة ضمن المسرح الحالي</div></div><span class="badge">${ar(count)} حدث</span></div>`);
        });
        relations.activeStates.slice(0,3).forEach(([name,count])=>{
            rows.push(`<div class="sod-rel-item"><div><div class="left">${esc(name)}</div><div class="meta">دولة/جهة فاعلة في الميدان</div></div><span class="badge">${ar(count)} وزن</span></div>`);
        });
        stateTheatersEl.innerHTML = rows.length ? rows.join('') : '<div class="sod-loading-row">لا توجد بيانات ساحات كافية.</div>';
    }

    const alliesEl = $id('relation-allies');
    if(alliesEl){
        const rows = [];
        relations.adversaries.forEach(([name,count],i)=>{
            rows.push(`<div class="sod-rel-item"><div><div class="left">${ar(i+1)}. ${esc(name)}</div><div class="meta">طرف متصارع / محور مقابل</div></div><span class="badge">${ar(count)} احتكاك</span></div>`);
        });
        relations.influentialStates.forEach(([name,count])=>{
            rows.push(`<div class="sod-rel-item"><div><div class="left">${esc(name)}</div><div class="meta">دولة مؤثرة في التوازنات</div></div><span class="badge">${ar(count)} تأثير</span></div>`);
        });
        relations.impacts.slice(0,4).forEach(([name,count])=>{
            rows.push(`<div class="sod-rel-item"><div><div class="left">${esc(name)}</div><div class="meta">تأثير بيني على المشهد</div></div><span class="badge">${ar(count)} مؤشر</span></div>`);
        });
        alliesEl.innerHTML = rows.length ? rows.join('') : '<div class="sod-loading-row">لا توجد علاقات بينية كافية.</div>';
    }

    const graphEl = $id('relation-graph');
    if(graphEl){ renderRelationGraph(graphEl, centralState, relations); }

    const analysisEl = $id('relation-analysis');
    if(analysisEl){
        const actor = relations.activeStates[0]?.[0] || 'طرف غير محسوم';
        const opponent = relations.adversaries[0]?.[0] || 'خصم غير محسوم';
        const theater = relations.centralTheater || 'ساحة غير محسومة';
        const effect = relations.impacts[0]?.[0] || 'تأثير غير محسوم';
        analysisEl.innerHTML = `تُظهر القراءة الحالية أن <strong>${esc(theater)}</strong> هي الساحة المحورية، مع بروز <strong>${esc(actor)}</strong> كأكثر الأطراف حضورًا و<strong>${esc(opponent)}</strong> كأوضح محور اشتباك. التأثير الغالب في هذا المسرح هو <strong>${esc(effect)}</strong>.<div style="margin-top:8px">تم وضع هذا التحليل أعلى الرسم مباشرة ليقود القراءة قبل النظر إلى توزيع العقد، ثم تظهر الأخبار المرتبطة أسفل الرسم عند الضغط على أي عقدة أو خط.</div>`;
    }
}

/* ── News page ── */
function renderNews(){
    const grid=$id('news-grid');if(!grid)return;
    const scoreF=parseInt($id('news-filter-score')?.value||0);
    const searchT=($id('news-search')?.value||'').toLowerCase().trim();
    let filtered=allEvents.filter(e=>{
        if(e.score<scoreF)return false;
        if(searchT&&!e.title.toLowerCase().includes(searchT)&&!(e.actor_v2||'').toLowerCase().includes(searchT))return false;
        return true;
    });
    const pages=Math.ceil(filtered.length/NEWS_PER_PAGE);
    newsPage=Math.min(newsPage,Math.max(0,pages-1));
    const slice=filtered.slice(newsPage*NEWS_PER_PAGE,(newsPage+1)*NEWS_PER_PAGE);
    if(!slice.length){grid.innerHTML='<div class="sod-loading-row">لا توجد أخبار مطابقة</div>';return;}
    grid.innerHTML=slice.map(ev=>{
        const col=scoreColor(ev.score);
        const lbl=scoreLabel(ev.score);
        const bc=scoreBadgeClass(ev.score);
        const conf=Math.min(100,Math.round((ev.score/300)*100));
        const aiB=ev.llm_verified?'<span class="sod-badge sod-badge-blue" title="تم التحقق بالذكاء الاصطناعي">🤖 AI</span>':'';
        const evalB=ev.has_manual_override?'<span class="sod-badge sod-badge-orange" title="العنصر محفوظ يدويًا ومقفل من إعادة التحليل">✍️ يدوي</span>':`<span class="sod-badge sod-badge-green" title="آخر تقييم مسجل">${esc(ev.evaluation_label||'آلي')}</span>`;
        return `<div class="sod-news-card">
            <div class="sod-news-card-meta">
                <span class="sod-badge ${bc}">${ar(ev.score)} — ${lbl}</span>
                ${ev.actor_v2?`<span class="sod-badge sod-badge-gray">${esc(ev.actor_v2.substring(0,25))}</span>`:''}
                ${ev.region?`<span class="sod-badge sod-badge-purple">${esc(ev.region)}</span>`:''}
                ${ev.intel_type?`<span class="sod-badge sod-badge-blue">${esc(ev.intel_type.substring(0,20))}</span>`:''}
                ${evalB}${aiB}
            </div>
            <div class="sod-news-title">
                <a href="${esc(ev.link)}" target="_blank" rel="noopener noreferrer">${esc(ev.title)}</a>
            </div>
            <div class="sod-confidence-bar-wrap">
                <span class="sod-confidence-label">الثقة:</span>
                <div class="sod-confidence-bar"><div class="sod-confidence-fill" style="width:${conf}%;background:${col};"></div></div>
                <span style="font-size:10px;color:#64748b;">${ar(conf)}%</span>
            </div>
            <div class="sod-news-footer">
                <span>${timeAgo(ev.event_timestamp)}</span>
                ${ev.source_name?`<span>· ${esc(ev.source_name)}</span>`:''}
                ${ev.tactical_level?`<span class="sod-level-chip">${esc(ev.tactical_level)}</span>`:''}
            </div>
        </div>`;
    }).join('');
    const pag=$id('news-pagination');
    if(pag&&pages>1){pag.innerHTML=Array.from({length:pages},(_,i)=>`<button class="sod-page-btn${i===newsPage?' active':''}" onclick="sod_newspage_${UID}(${i})">${ar(i+1)}</button>`).join('');}
    else if(pag)pag.innerHTML='';
}
window['sod_newspage_'+UID]=(p)=>{newsPage=p;renderNews();};

/* ── Alerts page ── */
function renderAlerts(){
    const list=$id('alerts-list');if(!list)return;
    const critical=allEvents.filter(e=>e.score>=140).slice(0,30);
    if(!critical.length){list.innerHTML='<div class="sod-loading-row">لا توجد تنبيهات حرجة في الوقت الحالي.</div>';return;}
    list.innerHTML=critical.map(ev=>{
        const col=scoreColor(ev.score);
        return `<div class="sod-alert-card${ev.score>=200?' critical':''}">
            <div class="sod-alert-score-circle" style="background:${col}20;color:${col};border:1px solid ${col}40;">
                <div style="text-align:center;"><div style="font-size:13px;font-weight:700;">${ar(ev.score)}</div><div style="font-size:9px;">${scoreLabel(ev.score)}</div></div>
            </div>
            <div style="flex:1;">
                <div style="font-size:13px;font-weight:600;color:#f8fafc;margin-bottom:4px;">
                    <a href="${esc(ev.link)}" target="_blank" rel="noopener noreferrer" style="color:#f8fafc;text-decoration:none;">${esc(ev.title)}</a>
                </div>
                <div style="display:flex;gap:8px;flex-wrap:wrap;font-size:10px;color:#64748b;">
                    ${ev.actor_v2?`<span>🎭 ${esc(ev.actor_v2)}</span>`:''}
                    ${ev.region?`<span>📍 ${esc(ev.region)}</span>`:''}
                    <span>⏱ ${timeAgo(ev.event_timestamp)}</span>
                    ${ev.llm_verified?'<span>🤖 AI محقق</span>':''}
                </div>
            </div>
        </div>`;
    }).join('');
}

