/* ── Reports page ── */
function renderReports(analytics,events){
    const el=$id('report-content');if(!el||!analytics)return;
    const esc_idx=analytics.escalation_index||0;
    const statusLabel=esc_idx>=70?'أزمة حادة 🔴':esc_idx>=40?'توتر متصاعد 🟠':esc_idx>=20?'حذر 🟡':'استقرار نسبي 🟢';
    const tl=analytics.truth_layers||{};
    const total=analytics.total||1;
    const field_pct=Math.round(((tl.field_action||0)/total)*100);
    const dirs=analytics.war_directions||{};
    const warDir=(dirs.escalating||0)>(dirs['de-escalating']||0)?'تصاعدي ↑':((dirs['de-escalating']||0)>(dirs.escalating||0)?'انفراجي ↓':'مستقر ↔');
    el.innerHTML=`<div class="sod-settings-grid">
        <div class="sod-setting-item"><div class="sod-setting-label">الوضع العام</div><div class="sod-setting-value" style="font-size:16px;">${esc(statusLabel)}</div></div>
        <div class="sod-setting-item"><div class="sod-setting-label">اتجاه الصراع</div><div class="sod-setting-value">${esc(warDir)}</div></div>
        <div class="sod-setting-item"><div class="sod-setting-label">مؤشر التصعيد</div><div class="sod-setting-value" style="color:#c084fc;">${ar(esc_idx)}%</div></div>
        <div class="sod-setting-item"><div class="sod-setting-label">نسبة الأحداث الميدانية</div><div class="sod-setting-value" style="color:#f87171;">${ar(field_pct)}%</div></div>
        <div class="sod-setting-item"><div class="sod-setting-label">إجمالي الأحداث</div><div class="sod-setting-value">${ar(total)}</div></div>
        <div class="sod-setting-item"><div class="sod-setting-label">أحداث حرجة</div><div class="sod-setting-value" style="color:#f87171;">${ar(analytics.critical||0)}</div></div>
    </div>`;
    const brief=$id('report-brief');
    if(brief){brief.innerHTML=`<div style="font-size:12px;color:#94a3b8;line-height:1.8;">
        <p>يشهد المشهد الاستخباراتي في الفترة المرصودة <strong style="color:#e2e8f0;">${ar(total)} حدثاً</strong>، منها <strong style="color:#f87171;">${ar(analytics.critical||0)} حدثاً حرجاً</strong>.</p>
        <p>اتجاه الصراع: <strong style="color:#f97316;">${esc(warDir)}</strong> مع مؤشر تصعيد بلغ <strong style="color:#c084fc;">${ar(esc_idx)}%</strong>.</p>
        <p>نسبة الأحداث الميدانية من إجمالي الأحداث: <strong style="color:#f87171;">${ar(field_pct)}%</strong>.</p>
    </div>`;}
}

/* ── Video page — Live Streams + Media ── */
const ADMIN_STREAMS=<?php
    $streams=get_option('so_video_streams',[]);
    echo json_encode(is_array($streams)?array_values($streams):[]);
?>;
/* ── YouTube URL → embed converter ── */
function convertYouTubeURL(url){
    if(!url)return url;
    url=url.trim();
    // Already an embed URL — return as-is
    if(url.includes('/embed/'))return url;
    const base='https://www.youtube.com/embed/';
    const params='?rel=0&playsinline=1&enablejsapi=1';
    // youtu.be/ID
    let m=url.match(/youtu\.be\/([a-zA-Z0-9_-]{11})/);
    if(m)return base+m[1]+params;
    // ?v=ID or &v=ID
    m=url.match(/[?&]v=([a-zA-Z0-9_-]{11})/);
    if(m)return base+m[1]+params;
    // /live/ID
    m=url.match(/youtube\.com\/live\/([a-zA-Z0-9_-]{11})/);
    if(m)return base+m[1]+params;
    // /shorts/ID
    m=url.match(/youtube\.com\/shorts\/([a-zA-Z0-9_-]{11})/);
    if(m)return base+m[1]+params;
    // Channel live: youtube.com/channel/CHANNEL_ID/live or /@handle/live
    m=url.match(/youtube\.com\/(?:channel\/|c\/|@)?([^/?\s]+)\/live/);
    if(m)return 'https://www.youtube.com/embed/live_stream?channel='+encodeURIComponent(m[1])+'&rel=0';
    // Generic YouTube channel or page — embed as-is
    return url;
}
function parseTelegramWidget(stream){
    const raw=((stream&&stream.embed_code)||'')+' '+(((stream&&stream.url)||'')+'');
    let m=raw.match(/data-telegram-post=['"]([^'"]+)['"]/i);
    if(m&&m[1]) return {post:m[1]};
    m=((stream&&stream.url)||'').match(/https?:\/\/t\.me\/([^\/?#]+)\/(\d+)/i);
    if(m) return {post:m[1]+'/'+m[2]};
    return null;
}

function renderVideo(){
    const grid=$id('video-grid');
    if(!grid)return;
    let html='';
    const streams=Array.isArray(ADMIN_STREAMS)?ADMIN_STREAMS:[];
    const liveStreams=[];
    const embeddedStreams=[];
    streams.forEach(stream=>{
        const t=(stream.type||'live');
        const tgWidget=parseTelegramWidget(stream);
        if(tgWidget || stream.embed_code || t==='embed'){
            embeddedStreams.push(stream);
        } else {
            liveStreams.push(stream);
        }
    });
    const streamCard=(stream,isFeatured)=>{
        const t=stream.type||'live';
        let inner='';
        const isYT=(stream.url||'').includes('youtube.com')||(stream.url||'').includes('youtu.be');
        if(t==='embed'||isYT){
            const embedSrc=isYT?convertYouTubeURL(stream.url):stream.url;
            inner=`<iframe src="${esc(embedSrc)}" style="width:100%;height:100%;border:0;" allow="autoplay;encrypted-media;picture-in-picture" allowfullscreen referrerpolicy="strict-origin-when-cross-origin"></iframe>`;
        } else {
            const vid_id='hls-'+Math.random().toString(36).slice(2);
            inner=`<video id="${vid_id}" style="width:100%;height:100%;object-fit:cover;" controls muted playsinline data-hls="${esc(stream.url)}">
                <source src="${esc(stream.url)}" type="application/x-mpegURL">
                <source src="${esc(stream.url)}" type="video/mp4">
            </video>
            <div class="sod-stream-err" style="display:none;position:absolute;inset:0;background:#0a1929;color:#ef4444;font-size:13px;align-items:center;justify-content:center;text-align:center;padding:16px;"></div>`;
        }
        const wrapClass=isFeatured?'sod-video-featured':'';
        const mediaClass=isFeatured?'sod-video-featured-media':'';
        return `<div class="${wrapClass}" style="background:#0a1929;border:2px solid #dc2626;border-radius:10px;overflow:hidden;">
            <div class="${mediaClass}" style="aspect-ratio:16/9;overflow:hidden;position:relative;">${inner}</div>
            <div class="${isFeatured?'sod-video-featured-meta':''}" style="padding:8px 10px;display:flex;align-items:center;gap:6px;">
                <span style="width:8px;height:8px;border-radius:50%;background:#dc2626;animation:sod-pulse 1s infinite;flex-shrink:0;"></span>
                <span style="font-size:12px;color:#e0f2ff;font-weight:600;">${esc(stream.name||'بث مباشر')}</span>
                <span style="font-size:10px;color:#64748b;margin-right:auto;">${t==='camera'?'📷':'🔴'} ${t==='camera'?'كاميرا':'بث حي'}</span>
            </div>
        </div>`;
    };

    if(liveStreams.length){
        html+='<div class="sod-video-section-title sod-video-section-live"><span style="width:10px;height:10px;border-radius:50%;background:#dc2626;animation:sod-pulse 1.5s infinite;display:inline-block;"></span>البث المباشر</div>';
        const featuredLive=liveStreams[0];
        const sideLives=liveStreams.slice(1,5);
        html+='<div class="sod-video-wall">';
        html+=streamCard(featuredLive,true);
        html+='<div class="sod-video-stack">';
        if(sideLives.length){
            sideLives.forEach(stream=>{ html+=streamCard(stream,false); });
        } else {
            html+='<div class="sod-loading-row" style="height:100%;display:flex;align-items:center;justify-content:center;">لا توجد بثوث إضافية</div>';
        }
        html+='</div></div>';
    }
    if(embeddedStreams.length){
        if(html) html+='<div style="grid-column:1/-1;height:1px;background:#1e293b;margin:8px 0;"></div>';
        html+='<div class="sod-video-section-title sod-video-section-embed"><span style="width:10px;height:10px;border-radius:50%;background:#60a5fa;display:inline-block;"></span>الفيديوهات المضمنة</div><div class="sod-video-embed-grid">';
        embeddedStreams.forEach(stream=>{
            const tgWidget=parseTelegramWidget(stream);
            let inner='';
            if(tgWidget){
                inner=`<div class="sod-tg-widget" data-post="${esc(tgWidget.post)}"></div>`;
            } else if(stream.embed_code){
                inner=`<div class="sod-video-embed-frame">${stream.embed_code}</div>`;
            } else {
                const embedSrc=convertYouTubeURL(stream.url||'');
                inner=`<div class="sod-video-embed-frame"><iframe src="${esc(embedSrc)}" style="width:100%;height:100%;border:0;" allow="autoplay;encrypted-media;picture-in-picture" allowfullscreen referrerpolicy="strict-origin-when-cross-origin"></iframe></div>`;
            }
            html+=`<div class="sod-video-embed-card">
                ${inner}
                <div style="padding:10px 12px;display:flex;align-items:center;gap:6px;background:#0f172a;border-top:1px solid #1e293b;">
                    <span style="width:8px;height:8px;border-radius:50%;background:#60a5fa;flex-shrink:0;"></span>
                    <span style="font-size:12px;color:#e0f2ff;font-weight:600;">${esc(stream.name||'فيديو مضمن')}</span>
                    <span style="font-size:10px;color:#64748b;margin-right:auto;">Embed</span>
                </div>
            </div>`;
        });
        html+='</div>';
    }
    // إذا لم تكن هناك مصادر يدوية — رسالة توجيهية
    if(!streams.length){
        html='<div class="sod-loading-row" style="grid-column:1/-1;text-align:center;padding:32px 16px;">'
            +'<div style="font-size:32px;margin-bottom:12px;">📺</div>'
            +'<div style="font-size:13px;color:#60a5fa;font-weight:700;margin-bottom:6px;">لا توجد مصادر بث مضافة</div>'
            +'<div style="font-size:12px;color:#475569;">أضف روابط البث المباشر أو قنوات يوتيوب من <strong style="color:#94a3b8;">لوحة الإدارة ← إعدادات الفيديو</strong></div>'
            +'</div>';
    }
    grid.innerHTML=html;
    grid.querySelectorAll('.sod-tg-widget').forEach(function(box){
        const post=box.getAttribute('data-post');
        if(!post)return;
        const script=document.createElement('script');
        script.async=true;
        script.src='https://telegram.org/js/telegram-widget.js?22';
        script.setAttribute('data-telegram-post', post);
        script.setAttribute('data-width', '100%');
        script.setAttribute('data-userpic', 'false');
        script.setAttribute('data-dark', '1');
        box.appendChild(script);
    });
    // تشغيل HLS.js للبثوث
    grid.querySelectorAll('video[data-hls]').forEach(function(v){
        const src=v.getAttribute('data-hls');
        const errBox=v.parentElement?v.parentElement.querySelector('.sod-stream-err'):null;
        function showErr(msg){v.style.display='none';if(errBox){errBox.textContent='⚠️ '+msg;errBox.style.display='flex';}}
        try{
            if(window.Hls&&Hls.isSupported()){
                const hls=new Hls({debug:false,enableWorker:true,lowLatencyMode:true,maxBufferLength:10});
                hls.loadSource(src);
                hls.attachMedia(v);
                hls.on(Hls.Events.ERROR,function(_,data){
                    if(data.fatal){
                        switch(data.type){
                            case Hls.ErrorTypes.NETWORK_ERROR:hls.startLoad();break;
                            case Hls.ErrorTypes.MEDIA_ERROR:hls.recoverMediaError();break;
                            default:showErr('فشل تحميل البث — تحقق من الرابط');break;
                        }
                    }
                });
                hls.on(Hls.Events.MANIFEST_PARSED,function(){v.play().catch(()=>{});});
            } else if(v.canPlayType('application/vnd.apple.mpegurl')){
                v.src=src;
                v.addEventListener('error',()=>showErr('فشل تحميل البث على هذا المتصفح'));
                v.play().catch(()=>{});
            } else {
                showErr('المتصفح لا يدعم HLS — استخدم Chrome أو Edge');
            }
        }catch(e){showErr(e.message||'خطأ غير متوقع في تحميل البث');console.error('[SOD HLS]',e);}
    });
    const srcEl=$id('video-sources');
    if(srcEl){
        const sources=[...new Set(allEvents.map(e=>e.source_name).filter(Boolean))].slice(0,20);
        srcEl.innerHTML=sources.length?`<div style="display:flex;gap:6px;flex-wrap:wrap;">${sources.map(s=>`<span class="sod-badge sod-badge-gray">${esc(s)}</span>`).join('')}</div>`:'<div class="sod-loading-row">لا توجد مصادر</div>';
    }
}

/* ── Actors / Regions / Cats ── */
function renderActors(analytics){
    const el=$id('actors-list');if(!el)return;
    const actors=analytics.actors||{};const top=Object.entries(actors).slice(0,10);
    if(!top.length){el.innerHTML='<div class="sod-brief-loading">لا بيانات</div>';return;}
    const maxScore=top[0][1]||1;
    el.innerHTML=top.map(([a,s],i)=>{const pct=Math.round((s/maxScore)*100);const col=scoreColor(pct*3);return`<div class="sod-actor-row"><div class="sod-actor-name">${i+1}. ${esc(a.substring(0,28))}<div class="sod-actor-bar"><div class="sod-actor-bar-fill" style="width:${pct}%;background:${col};"></div></div></div><div class="sod-actor-score" style="color:${col};">${ar(s)}</div></div>`;}).join('');
}
function renderRegions(analytics){
    const el=$id('regions-list');if(!el)return;
