function renderTopMarquee(events){
    const track=$id('marquee-track');
    if(!track) return;
    const speedSel=$id('marquee-speed');
    const top=(events||[]).slice(0,14);
    const rows=top.length?top.map(ev=>{
        const title=esc(String(ev.title||'خبر استخباراتي').substring(0,120));
        const region=esc(String(ev.region||'غير محدد'));
        const score=ar(parseInt(ev.score||0,10));
        return `<span class="sod-live-marquee-item"><b>${score}</b><span>${title}</span><small style="color:#93c5fd">(${region})</small></span>`;
    }).join(' <span style="color:#334155">•</span> '):'<span class="sod-live-marquee-item">لا توجد أخبار كافية لعرض الشريط</span>';
    track.innerHTML=rows+' '+rows;
    const applySpeed=(val)=>{
        const speed=Math.max(8,Math.min(120,parseInt(val||MARQUEE_DEFAULT_SPEED,10)||MARQUEE_DEFAULT_SPEED));
        track.style.setProperty('--sod-marquee-speed',speed+'s');
    };
    applySpeed(MARQUEE_DEFAULT_SPEED);
    if(speedSel&&!speedSel.dataset.bound){
        speedSel.value=String(MARQUEE_DEFAULT_SPEED);
        speedSel.addEventListener('change',()=>applySpeed(speedSel.value));
        speedSel.dataset.bound='1';
    }
}

/* ── Ticker — خبر واحد يصعد للأعلى كل 4 ثوانٍ ── */
function renderTicker(events){
    const wrap=$id('ticker-scroll');if(!wrap)return;
    const criticals=events.filter(e=>e.score>=100).slice(0,40);
    if(!criticals.length){wrap.innerHTML='<div class="sod-tick-item sod-active" style="color:#fecdd3;">لا توجد تنبيهات حرجة</div>';return;}
    function col(s){return s>=200?'#fca5a5':s>=140?'#fb923c':s>=80?'#fde68a':'#bbf7d0';}
    let idx=0;
    function flip(){
        // إنشاء العنصر الجديد (يدخل من الأسفل)
        const ev=criticals[idx%criticals.length];idx++;
        const nxt=document.createElement('div');
        nxt.className='sod-tick-item sod-entering';
        nxt.innerHTML=`<span style="color:${col(ev.score)};font-size:10px;font-weight:800;margin-left:6px;flex-shrink:0;">[${ar(ev.score)}]</span><span style="overflow:hidden;text-overflow:ellipsis;">${esc(ev.title.substring(0,120))}</span>`;
        wrap.appendChild(nxt);
        // حرّك العنصر القديم للأعلى
        wrap.querySelectorAll('.sod-active').forEach(el=>{el.classList.remove('sod-active');el.classList.add('sod-leaving');setTimeout(()=>el.remove(),650);});
        // بعد إعادة رسم DOM → فعّل الانتقال
        requestAnimationFrame(()=>requestAnimationFrame(()=>{nxt.classList.remove('sod-entering');nxt.classList.add('sod-active');}));
    }
    wrap.innerHTML='';
    flip();
    if(wrap._sodFlip)clearInterval(wrap._sodFlip);
    wrap._sodFlip=setInterval(flip,TICKER_FLIP_MS);
}

/* ── Alert Strip — خبر واحد حرج يصعد للأعلى ── */
function renderAlertStrip(events){
    const strip=$id('alert-strip');if(!strip)return;
    const critEvents=events.filter(e=>e.score>=140).slice(0,30);
    if(!critEvents.length){strip.style.display='none';return;}
    const marqueeWrap=$id('alert-marquee');
    if(!marqueeWrap){strip.style.display='flex';return;}
    marqueeWrap.style.cssText='flex:1;overflow:hidden;position:relative;height:30px;';
    let idx=0;
    function flipAlert(){
        const ev=critEvents[idx%critEvents.length];idx++;
        const nxt=document.createElement('div');
        nxt.className='sod-alert-flip sod-entering';
        nxt.textContent=`🔴 [${ar(ev.score)}] ${ev.title.substring(0,100)}${ev.title.length>100?'...':''}`;
        nxt.style.cssText='position:absolute;width:100%;height:30px;display:flex;align-items:center;font-size:12px;color:#fca5a5;font-weight:700;direction:rtl;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;transition:transform .5s ease,opacity .4s ease;transform:translateY(110%);opacity:0;';
        marqueeWrap.appendChild(nxt);
        marqueeWrap.querySelectorAll('.sod-active').forEach(el=>{
            el.style.transform='translateY(-110%)';el.style.opacity='0';
            setTimeout(()=>el.remove(),600);el.classList.remove('sod-active');
        });
        requestAnimationFrame(()=>requestAnimationFrame(()=>{nxt.style.transform='translateY(0)';nxt.style.opacity='1';nxt.classList.add('sod-active');}));
    }
    marqueeWrap.innerHTML='';
    flipAlert();
    if(marqueeWrap._sodFlip)clearInterval(marqueeWrap._sodFlip);
    marqueeWrap._sodFlip=setInterval(flipAlert,4500);
    strip.style.display='flex';
}

/* ── Critical Popup ── */
function checkPopup(events){
    const key='sod_popup_v15_'+UID;
    if(sessionStorage.getItem(key))return;
    const critical=events.filter(e=>e.score>=200);
    if(!critical.length)return;
    const ev=critical[0];
    popupEventLink=ev.link||'#';
    const titleEl=$id('popup-title');
    const descEl=$id('popup-desc');
    if(titleEl)titleEl.textContent='تحذير عاجل: '+ev.title.substring(0,60)+(ev.title.length>60?'...':'');
    if(descEl)descEl.textContent=(ev.actor_v2?'الفاعل: '+ev.actor_v2+' — ':'')+(ev.region?ev.region+' — ':'')+scoreLabel(ev.score)+' ('+ar(ev.score)+' نقطة). يُرجى الحذر وتجنب المنطقة.';
    const popup=$id('popup');
    if(popup)popup.classList.remove('hidden');
}

/* ── Main fetch ── */
async function parseAjaxJson(res){
    const text=await res.text();
    try{return JSON.parse(text);}catch(e){
        const trimmed=String(text||'').trim();
        const objStart=trimmed.indexOf('{');
        const arrStart=trimmed.indexOf('[');
        let start=-1;
        if(objStart>=0&&arrStart>=0) start=Math.min(objStart,arrStart);
        else start=objStart>=0?objStart:arrStart;
        if(start>=0) return JSON.parse(trimmed.slice(start));
        throw new Error(trimmed.slice(0,220)||('HTTP '+res.status));
    }
}

async function parseDeckAjaxJson(res){
    const text=await res.text();
    try{return JSON.parse(text);}catch(e){
        const trimmed=String(text||'').trim();
        const objStart=trimmed.indexOf('{');
        const arrStart=trimmed.indexOf('[');
        let start=-1;
        if(objStart>=0&&arrStart>=0) start=Math.min(objStart,arrStart);
        else start=objStart>=0?objStart:arrStart;
        if(start>=0) return JSON.parse(trimmed.slice(start));
        throw new Error(trimmed.slice(0,220)||('HTTP '+res.status));
    }
}

async function fetchData(){
    const hours=parseInt($id('filter-hours')?.value||24);
    const region=$id('filter-region')?.value||'all';
    const minScore=parseInt($id('filter-score')?.value||0);
    try{
        const fd=new FormData();
        fd.append('action','sod_get_dashboard_data');
        fd.append('nonce',NONCE);
        fd.append('hours',hours);
        fd.append('region',region);
        fd.append('min_score',minScore);
        const res=await fetch(AJAX_URL,{method:'POST',body:fd,credentials:'same-origin'});
        const json=await parseAjaxJson(res);
        if(json.success&&json.data){
            const{events,analytics}=json.data;
            allEvents=events||[];
            /* تم تعطيل الصافرة المولدة من المتصفح للسماح فقط بالصوت المخصص من الإدارة */
            prevTotal=analytics.critical||0;
            // KPIs
            renderKPI('total',ar(analytics.total||0));
            renderKPI('critical',ar(analytics.critical||0));
            renderKPI('avg_score',ar(analytics.avg_score||0));
            renderKPI('hot_region',analytics.hot_region||'—');
            renderKPI('gci',ar(analytics.gci||0));
            renderKPI('escalation',ar(analytics.escalation_index||0)+'%');
            renderKPI('deception',ar(analytics.deception_index||0)+'%');
            renderKPI('kinetic',ar(analytics.truth_layers?.field_action||0));
            // Dashboard page
            feedPage=0;renderFeed();
            renderActors(analytics);
            renderRegions(analytics);
            renderCats(analytics);
            renderBrief(analytics);
            renderCommandDeck(analytics,allEvents);
            renderHybridWar(analytics,allEvents);
            renderAlertStrip(allEvents);
            lastAnalytics=analytics; // cache for chart modal
            if(SHOW_CHARTS){updateCharts(analytics,'');updateCharts(analytics,'-kpi');}
            if(SHOW_MAP)updateMap(allEvents);
            // Ticker
            renderTopMarquee(allEvents);
            renderTicker(allEvents);
            // Popup (only once per session)
            checkPopup(allEvents);
            // Active page refresh
            if(currentPage==='hybrid')renderHybridWar(analytics,allEvents);
            if(currentPage==='news')renderNews();
            if(currentPage==='alerts')renderAlerts();
            if(currentPage==='commanddeck')renderCommandDeck(analytics,allEvents);
            if(currentPage==='kpis')renderKpisPage(analytics);
            if(currentPage==='reports')renderReports(analytics,allEvents);
            if(currentPage==='video')renderVideo();
            // Update time
            const upd=$id('last-update');if(upd)upd.textContent='آخر تحديث: '+new Date().toLocaleTimeString('ar-SA');
        }
    }catch(e){console.error('[SOD V15 PBI]',e);}
}


function sodCleanupMobileLeak(){
    try{
        const markers = ['function renderFeed','function renderNews','2026 BeirutTime','Live from the International Space Station'];
        const walker = document.createTreeWalker(document.body, NodeFilter.SHOW_TEXT, null);
        let n; const kill=[];
        while((n=walker.nextNode())){
            const v=(n.nodeValue||'').trim();
            if(!v) continue;
            if(markers.some(m=>v.includes(m))){
                kill.push(n);
            }
        }
        kill.forEach(node=>{
            const parent=node.parentElement;
            if(parent && !parent.closest('.sod-powerbi-wrap')){
                parent.style.display='none';
            }else if(parent){
                parent.remove();
            }
        });
        document.documentElement.style.overflowX='hidden';
        document.body.style.overflowX='hidden';
    }catch(e){}
}

/* ── Init — Jannah theme compat: run if DOM already ready ── */
function sodDeckInit(){
    sodCleanupMobileLeak();

    initMap();
    fetchData();
    setInterval(fetchData,AUTO_REFRESH*1000);

    // Refresh button
    const rbtn=$id('refresh-btn');if(rbtn)rbtn.addEventListener('click',fetchData);

    // Feed filters
    const fs=$id('feed-filter-score');if(fs)fs.addEventListener('change',()=>{feedPage=0;renderFeed();});
    const fse=$id('feed-search');if(fse)fse.addEventListener('input',()=>{feedPage=0;renderFeed();});

    // News filters
    const nfs=$id('news-filter-score');if(nfs)nfs.addEventListener('change',()=>{newsPage=0;renderNews();});
    const nse=$id('news-search');if(nse)nse.addEventListener('input',()=>{newsPage=0;renderNews();});

    // Global filters
    [$id('filter-hours'),$id('filter-region'),$id('filter-score')].forEach(el=>{
        if(el)el.addEventListener('change',()=>{feedPage=0;newsPage=0;fetchData();});
    });

    // Map buttons
    const mh=$id('map-heat');const mm=$id('map-markers');
    if(mh)mh.addEventListener('click',()=>{mapMode='heat';mh.classList.add('active');mm?.classList.remove('active');updateMap(allEvents);});
    if(mm)mm.addEventListener('click',()=>{mapMode='markers';mm.classList.add('active');mh?.classList.remove('active');updateMap(allEvents);});

    // Popup buttons
    const popupClose=$id('popup-close');
    const popupDismiss=$id('popup-dismiss');
    const popupGo=$id('popup-go');
    const popup=$id('popup');
    if(popupClose)popupClose.addEventListener('click',(ev)=>{if(ev){ev.preventDefault();ev.stopPropagation();}if(popup){popup.classList.add('hidden');sessionStorage.setItem('sod_popup_v15_'+UID,'1');}});
    if(popupDismiss)popupDismiss.addEventListener('click',(ev)=>{if(ev){ev.preventDefault();ev.stopPropagation();}if(popup){popup.classList.add('hidden');sessionStorage.setItem('sod_popup_v15_'+UID,'1');}});
    if(popupGo)popupGo.addEventListener('click',()=>{if(popupEventLink&&popupEventLink!=='#')window.open(popupEventLink,'_blank','noopener,noreferrer');if(popup){popup.classList.add('hidden');sessionStorage.setItem('sod_popup_v15_'+UID,'1');}});

    // Settings: test connection
    const testBtn=$id('test-conn');
    if(testBtn)testBtn.addEventListener('click',async()=>{
        const diagEl=$id('diag-result');
        if(diagEl)diagEl.innerHTML='⏳ جارٍ الاختبار...';
        try{
            const fd=new FormData();fd.append('action','sod_get_ticker_data');fd.append('nonce',NONCE);
            const res=await fetch(AJAX_URL,{method:'POST',body:fd,credentials:'same-origin'});
            const json=await parseAjaxJson(res);
            if(diagEl)diagEl.innerHTML=json.success?'✅ الاتصال ناجح. البيانات تُحمَّل بشكل صحيح.':'⚠️ الاستجابة غير متوقعة: '+JSON.stringify(json).substring(0,100);
        }catch(e){if(diagEl)diagEl.innerHTML='❌ خطأ: '+esc(e.message);}
    });
}
// Jannah theme compat: run if DOM already ready, otherwise wait
if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',sodDeckInit);}
else{sodDeckInit();}
})();
</script>
    <?php return ob_get_clean();
}

