        <!-- شريط العنوان -->
        <div style="display:flex;align-items:center;background:#dc2626;padding:0 14px;gap:10px;height:42px;">
            <span style="font-size:10px;font-weight:800;color:#fff;white-space:nowrap;flex-shrink:0;">⚡ عاجل:</span>
            <div id="<?php echo esc_attr($uid); ?>-flip-wrap" style="flex:1;overflow:hidden;position:relative;height:36px;">
                <div id="<?php echo esc_attr($uid); ?>-loading" style="position:absolute;width:100%;height:36px;display:flex;align-items:center;font-size:12px;color:#fecdd3;">جارٍ تحميل التنبيهات...</div>
            </div>
            <button id="<?php echo esc_attr($uid); ?>-sound-btn" style="background:transparent;border:1px solid rgba(255,255,255,.4);color:#fff;padding:3px 8px;border-radius:6px;cursor:pointer;font-size:12px;flex-shrink:0;">🔇</button>
        </div>
        <!-- شريط الحرج (≥140) -->
        <div id="<?php echo esc_attr($uid); ?>-critical-bar" style="display:none;background:rgba(220,38,38,.15);border-bottom:1px solid rgba(220,38,38,.3);padding:0 14px;height:34px;align-items:center;gap:8px;">
            <span style="font-size:13px;animation:sod-blink 1.4s infinite;flex-shrink:0;">🚨</span>
            <div id="<?php echo esc_attr($uid); ?>-critical-flip" style="flex:1;overflow:hidden;position:relative;height:28px;"></div>
        </div>
        <style>
        #<?php echo esc_attr($uid); ?> .sot-item{position:absolute;width:100%;display:flex;align-items:center;gap:6px;font-size:12px;transition:transform .5s cubic-bezier(.4,0,.2,1),opacity .4s ease;}
        #<?php echo esc_attr($uid); ?> .sot-item.sot-in{transform:translateY(110%);opacity:0;}
        #<?php echo esc_attr($uid); ?> .sot-item.sot-on{transform:translateY(0);opacity:1;}
        #<?php echo esc_attr($uid); ?> .sot-item.sot-out{transform:translateY(-110%);opacity:0;}
        @keyframes sod-blink{0%,100%{opacity:1}50%{opacity:.2}}
        </style>
    </div>
    <script>
    (function(){
setTimeout(()=>{try{hideOuterPageTitle&&hideOuterPageTitle();}catch(e){}},50);
    'use strict';
    const UID='<?php echo esc_js($uid); ?>';
    const AJAX_URL=(typeof SOD_CONFIG!=='undefined')?SOD_CONFIG.ajaxUrl:'<?php echo esc_js(admin_url('admin-ajax.php')); ?>';
    const NONCE=(typeof SOD_CONFIG!=='undefined')?SOD_CONFIG.nonce:'<?php echo esc_js(wp_create_nonce(SOD_AJAX_NONCE_ACTION)); ?>';
    const AUTO_REFRESH=<?php echo (int)$auto_refresh; ?>;
    const $=id=>document.getElementById(id);
    let soundOn=false,allItems=[],critItems=[],mIdx=0,cIdx=0,mTimer=null,cTimer=null,fetchTimer=null;
    function esc(s){const d=document.createElement('div');d.textContent=s;return d.innerHTML;}
    function scoreColor(s){return s>=200?'#ef4444':s>=140?'#f97316':s>=80?'#f59e0b':'#22c55e';}
    function playBeep(){try{const ctx=new(window.AudioContext||window.webkitAudioContext)();const osc=ctx.createOscillator();const g=ctx.createGain();osc.connect(g);g.connect(ctx.destination);osc.frequency.value=880;osc.type='square';g.gain.setValueAtTime(.05,ctx.currentTime);g.gain.exponentialRampToValueAtTime(.001,ctx.currentTime+.3);osc.start();osc.stop(ctx.currentTime+.3);}catch(e){}}
    // ── دالة Flip عامة: خبر واحد يصعد للأعلى ─────────────────────────────────
    function buildFlip(container,data,idx){
        if(!container||!data.length)return;
        const e=data[idx%data.length];
        const sc=parseInt(e.score||0);
        const col=scoreColor(sc);
        const title=e.title.length>90?e.title.substring(0,90)+'…':e.title;
        const src=e.source?`<span style="font-size:10px;color:rgba(255,255,255,.6);flex-shrink:0;">${esc(e.source)}</span>`:'';
        const html=`<div class="sot-item sot-in" style="color:#fff;right:0;top:0;">
            <span style="background:${col}33;color:${col};border:1px solid ${col}66;font-size:10px;font-weight:700;padding:1px 5px;border-radius:4px;white-space:nowrap;flex-shrink:0;">${sc}</span>
            ${src}
            <a href="${esc(e.link)}" target="_blank" rel="noopener noreferrer" style="color:#fff;text-decoration:none;flex:1;overflow:hidden;white-space:nowrap;text-overflow:ellipsis;">${esc(title)}</a>
        </div>`;
        const old=container.querySelector('.sot-item.sot-on');
        if(old){old.classList.remove('sot-on');old.classList.add('sot-out');setTimeout(()=>{if(old.parentNode===container)container.removeChild(old);},520);}
        container.insertAdjacentHTML('beforeend',html);
        const newest=container.lastElementChild;
        requestAnimationFrame(()=>{requestAnimationFrame(()=>{if(newest)newest.classList.replace('sot-in','sot-on');});});
    }
    function flipMain(){buildFlip($(UID+'-flip-wrap'),allItems,mIdx);mIdx=(mIdx+1)%Math.max(1,allItems.length);}
    function flipCrit(){buildFlip($(UID+'-critical-flip'),critItems,cIdx);cIdx=(cIdx+1)%Math.max(1,critItems.length);}
    function startTimers(){
        if(mTimer)clearInterval(mTimer);if(cTimer)clearInterval(cTimer);
        if(allItems.length){flipMain();mTimer=setInterval(flipMain,4500);}
        const cbar=$(UID+'-critical-bar');
        if(critItems.length){if(cbar)cbar.style.display='flex';flipCrit();cTimer=setInterval(flipCrit,4800);}
        else if(cbar){cbar.style.display='none';}
    }
    async function parseTickerAjaxJson(res){
        const text=await res.text();
        try{return JSON.parse(text);}catch(e){
            const trimmed=String(text||'').trim();
            const objStart=trimmed.indexOf('{');
            const arrStart=trimmed.indexOf('[');
            let start=-1;
            if(objStart>=0&&arrStart>=0) start=Math.min(objStart,arrStart);
            else start=objStart>=0?objStart:arrStart;
            if(start>=0) return JSON.parse(trimmed.slice(start));
            throw new Error(trimmed.slice(0,220)||('HTTP '+res.status));
        }
    }
    async function fetchData(){
        try{
            const fd=new FormData();fd.append('action','sod_get_ticker_data');fd.append('nonce',NONCE);
            const res=await fetch(AJAX_URL,{method:'POST',body:fd,credentials:'same-origin'});
            const json=await parseTickerAjaxJson(res);
            if(json.success&&json.data){
                const headlines=json.data.headlines||json.data.critical||[];
                const wasEmpty=!allItems.length;
                allItems=headlines;
                critItems=(json.data.critical||[]).filter(e=>parseInt(e.score||0)>=140);
                const loading=$(UID+'-loading');if(loading)loading.style.display='none';
                if(wasEmpty)startTimers();
                if(soundOn&&critItems.length)playBeep();
            }
        }catch(e){console.error('[SOD Ticker]',e);}
    }
    function sodTickerInit(){
        fetchData();if(fetchTimer)clearInterval(fetchTimer);fetchTimer=setInterval(fetchData,AUTO_REFRESH*1000);
        const sb=$(UID+'-sound-btn');if(sb)sb.addEventListener('click',()=>{soundOn=!soundOn;sb.textContent=soundOn?'🔊':'🔇';});
    }
    // Jannah theme compat: run immediately if DOM ready, else wait
    if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',sodTickerInit);}
    else{sodTickerInit();}
    })();
    </script>
