                    <span id="<?php echo esc_attr($uid); ?>-gauge-val" style="position:absolute;top:50%;right:50%;transform:translate(50%,-50%);font-size:13px;font-weight:900;color:#fff;text-shadow:0 1px 3px rgba(0,0,0,.7);">٠%</span>
