            <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;">
                <?php $meta_items=[['id'=>'momentum','icon'=>'📈','label'=>'الزخم (٢٤س مقابل ٧٢س)'],['id'=>'critical24h','icon'=>'💥','label'=>'الأحداث الحرجة (٢٤س)'],['id'=>'hot-region','icon'=>'🔥','label'=>'ساحة التصعيد'],['id'=>'esc-idx','icon'=>'⚠️','label'=>'مؤشر التصعيد']];
                foreach($meta_items as $m): ?>
                <div style="display:flex;align-items:center;gap:8px;background:rgba(255,255,255,.03);border:1px solid rgba(30,58,95,.5);border-radius:8px;padding:10px;">
                    <span style="font-size:17px;flex-shrink:0;"><?php echo $m['icon']; ?></span>
