        </div>
        <div class="sod-threat-tables">
            <div class="sod-card"><div class="sod-card-header">🎭 أخطر الفاعلين (٢٤س)</div><div style="padding:12px;max-height:260px;overflow-y:auto;" id="<?php echo esc_attr($uid); ?>-actor-threats"><div style="color:#4a6a8a;font-size:12px;text-align:center;padding:20px;">⏳ جارٍ التحليل...</div></div></div>
            <div class="sod-card"><div class="sod-card-header">📊 منحنى التهديد (١٢ ساعة)</div><div style="padding:8px;height:220px;position:relative;"><canvas id="<?php echo esc_attr($uid); ?>-trend-chart"></canvas></div></div>
            <div class="sod-card"><div class="sod-card-header">🌍 أكثر الساحات ضغطاً</div><div style="padding:12px;max-height:260px;overflow-y:auto;" id="<?php echo esc_attr($uid); ?>-regions-threat"><div style="color:#4a6a8a;font-size:12px;text-align:center;padding:20px;">⏳ جارٍ التحليل...</div></div></div>
        </div>
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;padding:0 20px 20px;">
            <div class="sod-card"><div class="sod-card-header">🧭 تقييم الوضع الأمني</div><div style="padding:12px;" id="<?php echo esc_attr($uid); ?>-assessment"><div style="color:#4a6a8a;font-size:12px;text-align:center;padding:20px;">⏳ جارٍ التحليل...</div></div></div>
            <div class="sod-card"><div class="sod-card-header">📋 طبقات المعلومات</div><div style="padding:12px;" id="<?php echo esc_attr($uid); ?>-layers"><div style="color:#4a6a8a;font-size:12px;text-align:center;padding:20px;">⏳ جارٍ التحليل...</div></div></div>
        </div>
        <style>
        #<?php echo esc_attr($uid); ?>{font-family:'Cairo','Tajawal',sans-serif;direction:rtl;background:linear-gradient(135deg,#070f1a,#0a1628);border:1px solid #1e3a5f;border-radius:14px;overflow:hidden;margin-bottom:20px;color:#e0f2ff;}
        .sod-threat-header{display:flex;justify-content:space-between;align-items:center;padding:16px 20px;background:linear-gradient(135deg,#0a1628,#0d1f3c);border-bottom:2px solid #1e3a5f;flex-wrap:wrap;gap:10px;}
        .sod-threat-title{display:flex;align-items:center;gap:12px;}
        .sod-threat-gauge-section{display:grid;grid-template-columns:1fr 2fr;gap:16px;padding:20px;align-items:center;}
        .sod-threat-tables{display:grid;grid-template-columns:1fr 1fr 1fr;gap:12px;padding:0 20px 16px;}
        @media(max-width:1000px){.sod-threat-tables{grid-template-columns:1fr;}.sod-threat-gauge-section{grid-template-columns:1fr;}}
        </style>
    </div>
    <script>
    (function(){
setTimeout(()=>{try{hideOuterPageTitle&&hideOuterPageTitle();}catch(e){}},50);
    'use strict';
    const UID='<?php echo esc_js($uid); ?>';
    const AJAX_URL=(typeof SOD_CONFIG!=='undefined')?SOD_CONFIG.ajaxUrl:'<?php echo esc_js(admin_url('admin-ajax.php')); ?>';
    const NONCE=(typeof SOD_CONFIG!=='undefined')?SOD_CONFIG.nonce:'<?php echo esc_js(wp_create_nonce(SOD_AJAX_NONCE_ACTION)); ?>';
    const AUTO_REFRESH=<?php echo (int)$auto_refresh; ?>;
    const $=id=>document.getElementById(UID+'-'+id);
    let trendChart=null;
    function ar(n){return Number(n).toLocaleString('en-US');}
    function esc(s){const d=document.createElement('div');d.textContent=s;return d.innerHTML;}
    function scoreColor(s){if(s>=75)return '#ef4444';if(s>=50)return '#f97316';if(s>=30)return '#f59e0b';return '#22c55e';}
    async function parseThreatAjaxJson(res){
        const text=await res.text();
        try{return JSON.parse(text);}catch(e){
            const trimmed=String(text||'').trim();
            const objStart=trimmed.indexOf('{');
            const arrStart=trimmed.indexOf('[');
            let start=-1;
            if(objStart>=0&&arrStart>=0) start=Math.min(objStart,arrStart);
            else start=objStart>=0?objStart:arrStart;
            if(start>=0) return JSON.parse(trimmed.slice(start));
            throw new Error(trimmed.slice(0,220)||('HTTP '+res.status));
        }
    }
    async function fetchData(){
        try{
            const fd=new FormData();fd.append('action','sod_get_threat_analysis');fd.append('nonce',NONCE);
            const res=await fetch(AJAX_URL,{method:'POST',body:fd,credentials:'same-origin'});
            const json=await parseThreatAjaxJson(res);
            if(json.success&&json.data)render(json.data);
        }catch(e){console.error('[SOD Threat]',e);}
    }
    function render(data){
        const a24=data.analytics_24h||{};const mc=data.momentum_change||0;const actors=data.actor_threats||[];const regions=data.top_regions||{};const trend=data.trend_data||{};
        const escIdx=a24.escalation_index||0;
        const gaugeBar=$('gauge-bar');const gaugeVal=$('gauge-val');
        if(gaugeBar){gaugeBar.style.width=escIdx+'%';const gc=escIdx>=70?'#ef4444':escIdx>=40?'#f97316':escIdx>=20?'#f59e0b':'#22c55e';gaugeBar.style.background=`linear-gradient(90deg,#22c55e,${gc})`;}
        if(gaugeVal)gaugeVal.textContent=ar(escIdx)+'%';
        const setVal=(id,v)=>{const el=$(id);if(el)el.textContent=v;};
        const momSign=mc>=0?'+':'';const momColor=mc>15?'#ef4444':mc>0?'#f59e0b':'#22c55e';
        const momEl=$('momentum');if(momEl){momEl.textContent=momSign+ar(mc)+'%';momEl.style.color=momColor;}
        setVal('critical24h',ar(a24.critical||0));setVal('hot-region',a24.hot_region||'—');
        const escEl=$('esc-idx');if(escEl){escEl.textContent=ar(escIdx)+'%';escEl.style.color=escIdx>=70?'#ef4444':escIdx>=40?'#f97316':'#22c55e';}
        const actorContainer=$('actor-threats');
        if(actorContainer){
            if(!actors.length){actorContainer.innerHTML='<div style="color:#4a6a8a;font-size:12px;text-align:center;padding:20px;">لا بيانات</div>';}
            else{const maxScore=actors[0]?.score||1;actorContainer.innerHTML=actors.slice(0,8).map((a,i)=>{const pct=Math.round((a.score/maxScore)*100);const color=scoreColor(pct);return`<div style="display:flex;align-items:center;justify-content:space-between;padding:8px 0;border-bottom:1px solid rgba(30,58,95,.3);"><span style="font-size:12px;color:#c8dff2;flex:1;">${i+1}. ${esc((a.actor||'غير محدد').substring(0,30))}</span><div style="text-align:left;"><div style="font-size:13px;font-weight:700;color:${color};">${ar(a.score)}</div><div style="font-size:10px;color:#6a90b4;">${ar(a.events)} حدث</div></div></div>`;}).join('');}
        }
        if(typeof Chart!=='undefined'){
            const canvas=document.getElementById(UID+'-trend-chart');
            if(canvas){
                const labels=Object.keys(trend).map(k=>k.substring(11,16));const tdata=Object.values(trend);
                if(trendChart)trendChart.destroy();
                trendChart=new Chart(canvas,{type:'line',data:{labels,datasets:[{label:'الأحداث',data:tdata,borderColor:'#3b82f6',backgroundColor:'rgba(59,130,246,.15)',borderWidth:2,fill:true,tension:.3,pointRadius:3,pointBackgroundColor:'#3b82f6'}]},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{display:false}},scales:{x:{ticks:{color:'#6a90b4',font:{size:9}},grid:{color:'rgba(30,58,95,.3)'}},y:{ticks:{color:'#6a90b4',font:{size:9},callback:v=>ar(v)},grid:{color:'rgba(30,58,95,.3)'},beginAtZero:true}},animation:{duration:400}}});
            }
        }
        const regContainer=$('regions-threat');
        if(regContainer){
            const sorted=Object.entries(regions).sort((a,b)=>b[1]-a[1]).slice(0,8);const maxRegScore=sorted[0]?.[1]||1;
            if(!sorted.length){regContainer.innerHTML='<div style="color:#4a6a8a;font-size:12px;text-align:center;padding:20px;">لا بيانات</div>';}
            else{regContainer.innerHTML=sorted.map(([r,s])=>{const pct=Math.round((s/maxRegScore)*100);const color=pct>=70?'#ef4444':pct>=40?'#f97316':pct>=20?'#f59e0b':'#22c55e';return`<div style="margin-bottom:10px;"><div style="display:flex;justify-content:space-between;margin-bottom:3px;"><span style="font-size:12px;color:#c8dff2;">${esc(r)}</span><span style="font-size:12px;font-weight:700;color:${color};">${ar(s)}</span></div><div style="height:4px;background:#1e3a5f;border-radius:2px;"><div style="width:${pct}%;height:100%;border-radius:2px;background:${color};transition:width .6s;"></div></div></div>`;}).join('');}
        }
        const assContainer=$('assessment');
        if(assContainer){
            const esc_idx=a24.escalation_index||0;const dec_idx=a24.deception_index||0;const dirs=a24.war_directions||{};
            const statusLabel=esc_idx>=70?'أزمة حادة':esc_idx>=40?'توتر متصاعد':esc_idx>=20?'حذر':'استقرار نسبي';
            const statusColor=esc_idx>=70?'#ef4444':esc_idx>=40?'#f97316':esc_idx>=20?'#f59e0b':'#22c55e';
            const warDir=(dirs.escalating||0)>(dirs['de-escalating']||0)?'تصاعدي ⬆️':((dirs['de-escalating']||0)>(dirs.escalating||0)?'انفراجي ⬇️':'مستقر ↔️');
            const warColor=(dirs.escalating||0)>(dirs['de-escalating']||0)?'#ef4444':((dirs['de-escalating']||0)>(dirs.escalating||0)?'#22c55e':'#f59e0b');
            const momLabel=mc>20?'تصاعد حاد':mc>5?'تصاعد طفيف':mc<-5?'تراجع':'مستقر';const momColor2=mc>20?'#ef4444':mc>5?'#f97316':mc<-5?'#22c55e':'#f59e0b';
            assContainer.innerHTML=[['الوضع العام',`<span style="color:${statusColor}">${statusLabel} (${ar(esc_idx)}%)</span>`],['اتجاه الصراع',`<span style="color:${warColor}">${warDir}</span>`],['زخم الأحداث',`<span style="color:${momColor2}">${momLabel} (${mc>=0?'+':''}${ar(mc)}%)</span>`],['مؤشر التضليل',`<span style="color:#f59e0b">${ar(dec_idx)}% تصريحات</span>`]].map(([l,v])=>`<div style="padding:7px 0;border-bottom:1px solid rgba(30,58,95,.3);"><div style="font-size:10px;color:#6a90b4;margin-bottom:2px;">${l}</div><div style="font-size:13px;font-weight:600;">${v}</div></div>`).join('');
        }
        const layContainer=$('layers');
        if(layContainer){
            const tl=a24.truth_layers||{};const total=a24.total||1;
            const layerNames={'field_action':'ميداني ⚔️','statement':'تصريح 🗣️','report':'تقرير 📄','defensive_alert':'إنذار 🔔','rumor':'شائعة ⚠️','general':'عام 📰'};
            const layerColors={'field_action':'#ef4444','statement':'#f59e0b','report':'#3b82f6','defensive_alert':'#f97316','rumor':'#8b5cf6','general':'#22c55e'};
            layContainer.innerHTML=Object.entries(tl).map(([k,v])=>{const pct=total>0?Math.round((v/total)*100):0;const col=layerColors[k]||'#9db4c8';return`<div style="display:flex;align-items:center;justify-content:space-between;padding:6px 0;border-bottom:1px solid rgba(30,58,95,.3);"><span style="font-size:12px;color:#9db4c8;">${layerNames[k]||k}</span><span style="font-size:10px;font-weight:700;padding:2px 8px;border-radius:10px;background:${col}20;color:${col};">${ar(v)} (${ar(pct)}%)</span></div>`;}).join('');
        }
        const timeEl=$('time');if(timeEl)timeEl.textContent='آخر تحديث: '+new Date().toLocaleTimeString('ar-SA');
    }
    document.addEventListener('DOMContentLoaded',function(){
        fetchData();setInterval(fetchData,AUTO_REFRESH*1000);
        const rb=$('refresh');if(rb)rb.addEventListener('click',fetchData);
    });
    })();
    </script>
    <?php return ob_get_clean();
}

