        <div id="so-critical-popup" aria-hidden="true" style="position:fixed;inset:0;display:none;align-items:center;justify-content:center;z-index:999999;font-family:'Cairo','Tajawal',sans-serif;">
            <div class="so-critical-backdrop" style="position:absolute;inset:0;background:rgba(7,12,18,.56);backdrop-filter:blur(2px);"></div>
            <div class="so-critical-card" style="position:relative;max-width:620px;width:min(94vw,620px);background:linear-gradient(180deg,#102032,#0b1520);color:#fff;border:1px solid rgba(255,255,255,.12);border-radius:18px;box-shadow:0 18px 45px rgba(0,0,0,.35);padding:18px;cursor:default;" tabindex="0">
                <button type="button" style="position:absolute;top:10px;left:10px;width:34px;height:34px;border-radius:50%;border:none;background:#ef4444;color:#fff;font-size:18px;cursor:pointer;z-index:2;" class="so-critical-close" aria-label="إغلاق">×</button>
                <div style="display:flex;align-items:center;justify-content:space-between;gap:10px;margin:0 44px 12px 0;">
                    <div style="font-size:17px;font-weight:800;color:#fff;">🚨 خبر حرج</div>
                    <button type="button" class="so-critical-sound-toggle" style="border:1px solid rgba(255,255,255,.18);background:#13283d;color:#dbeafe;border-radius:999px;padding:8px 12px;font-size:12px;cursor:pointer;white-space:nowrap;">🔊 إيقاف الصوت</button>
