                    <button type="button" class="so-critical-open" style="border:none;background:#2563eb;color:#fff;border-radius:12px;padding:10px 16px;font-weight:700;cursor:pointer;">فتح الخبر</button>
                    <button type="button" class="so-critical-silent-day" style="border:1px solid rgba(255,255,255,.16);background:#0f172a;color:#dbeafe;border-radius:12px;padding:10px 16px;font-weight:700;cursor:pointer;">كتم اليوم</button>
                    <button type="button" class="so-critical-dismiss" style="border:1px solid rgba(255,255,255,.16);background:#111827;color:#cbd5e1;border-radius:12px;padding:10px 16px;font-weight:700;cursor:pointer;">إغلاق</button>
                </div>
                <div style="margin-top:10px;font-size:12px;color:#93c5fd;text-align:center;">يمكن للمستخدم إيقاف الصوت أو كتمه مؤقتًا حتى لا يزعجه.</div>
            </div>
            <?php if ($sound_url): ?><audio id="so-critical-popup-audio" src="<?php echo $sound_url; ?>" preload="auto"></audio><?php endif; ?>
        </div>
        <script>
        document.addEventListener('DOMContentLoaded',function(){
            const wrap=document.getElementById('so-critical-popup');
            if(!wrap)return;
            const card=wrap.querySelector('.so-critical-card');
            const closeBtn=wrap.querySelector('.so-critical-close');
            const meta=wrap.querySelector('.so-critical-meta');
            const text=wrap.querySelector('.so-critical-text');
            const openBtn=wrap.querySelector('.so-critical-open');
            const dismissBtn=wrap.querySelector('.so-critical-dismiss');
            const soundBtn=wrap.querySelector('.so-critical-sound-toggle');
            const silentDayBtn=wrap.querySelector('.so-critical-silent-day');
            const audio=document.getElementById('so-critical-popup-audio');
            const ajaxUrl=<?php echo wp_json_encode($ajax_url); ?>;
            const tgLink=<?php echo wp_json_encode($tg_link); ?>;
            const muteKey='so_critical_popup_sound_muted';
            const muteUntilKey='so_critical_popup_sound_muted_until';
            let popupEventLink=tgLink;
            let lastSeen=Number(localStorage.getItem('so_critical_popup_last_seen')||'0');
            let activeTs=0;
            function ar(n){return Number(n).toLocaleString('en-US');}
            function isSoundMuted(){
                const hard=localStorage.getItem(muteKey)==='1';
                const until=Number(localStorage.getItem(muteUntilKey)||'0');
                if(until && Date.now()>until){ localStorage.removeItem(muteUntilKey); return hard; }
                return hard || (until && Date.now()<=until);
            }
            function refreshSoundButton(){
                if(!soundBtn)return;
                soundBtn.textContent=isSoundMuted()?'🔈 تشغيل الصوت':'🔊 إيقاف الصوت';
            }
            function stopAudio(){if(audio){audio.pause();audio.currentTime=0;}}
            function closePopup(ev){if(ev)ev.preventDefault();wrap.style.display='none';if(activeTs)localStorage.setItem('so_critical_popup_last_seen',String(activeTs));stopAudio();}
            function openPopup(ev){
                activeTs=Number(ev.event_timestamp||0);
                popupEventLink=ev.link||ev.telegram_link||tgLink||'#';
                meta.textContent=(ev.source_name||'مصدر')+'  •  '+(ev.region||'غير محدد')+'  •  '+ar(ev.score||0);
                text.textContent=ev.title||'';
                wrap.style.display='flex';
                if(audio && !isSoundMuted()){audio.currentTime=0;audio.play().catch(()=>{});}
                refreshSoundButton();
            }
            if(openBtn)openBtn.addEventListener('click',function(ev){ev.preventDefault();ev.stopPropagation(); if(popupEventLink&&popupEventLink!=='#') window.open(popupEventLink,'_blank','noopener,noreferrer'); closePopup();});
            if(soundBtn) soundBtn.addEventListener('click',function(ev){ev.preventDefault();ev.stopPropagation(); if(isSoundMuted()){ localStorage.removeItem(muteKey); localStorage.removeItem(muteUntilKey); } else { localStorage.setItem(muteKey,'1'); } stopAudio(); refreshSoundButton(); });
            if(silentDayBtn) silentDayBtn.addEventListener('click',function(ev){ev.preventDefault();ev.stopPropagation(); localStorage.removeItem(muteKey); localStorage.setItem(muteUntilKey, String(Date.now()+24*60*60*1000)); stopAudio(); refreshSoundButton(); closePopup(); });
            if(closeBtn)closeBtn.addEventListener('click',function(ev){ev.preventDefault();ev.stopPropagation();closePopup(ev);});
            if(dismissBtn)dismissBtn.addEventListener('click',function(ev){ev.preventDefault();ev.stopPropagation();closePopup(ev);});
            const backdrop=wrap.querySelector('.so-critical-backdrop'); if(backdrop) backdrop.addEventListener('click',closePopup);
            document.addEventListener('keydown',function(e){if(e.key==='Escape')closePopup();});
            async function parsePopupAjaxJson(res){
                const text=await res.text();
                try{return JSON.parse(text);}catch(e){
                    const trimmed=String(text||'').trim();
                    const objStart=trimmed.indexOf('{');
                    const arrStart=trimmed.indexOf('[');
                    let start=-1;
                    if(objStart>=0&&arrStart>=0) start=Math.min(objStart,arrStart);
                    else start=objStart>=0?objStart:arrStart;
                    if(start>=0) return JSON.parse(trimmed.slice(start));
                    throw new Error(trimmed.slice(0,220)||('HTTP '+res.status));
                }
            }
            async function poll(){
                try{
                    const fd=new FormData();fd.append('action','so_get_critical_popup');
                    const res=await fetch(ajaxUrl,{method:'POST',body:fd,credentials:'same-origin'});
                    const json=await parsePopupAjaxJson(res);
                    const ev=json&&json.success&&json.data?json.data.event:null;
                    if(ev&&Number(ev.event_timestamp||0)>lastSeen){openPopup(ev);}
                }catch(e){}
            }
            refreshSoundButton();
            poll();setInterval(poll,45000);
        });
        </script>
        <?php
    }
}
}

