            </div>
            <script>
            (function(){
                const app = document.getElementById('sod-registry-app');
                if (!app) return;
                const ajaxUrl = window.ajaxurl || '<?php echo esc_js(admin_url('admin-ajax.php')); ?>';
                const nonce = app.getAttribute('data-registry-nonce') || '';
                const noticeBox = document.getElementById('sod-registry-notice');
                const tableBody = document.getElementById('sod-registry-table-body');
                const logArea = document.getElementById('sod-registry-log-area');
                const learningArea = document.getElementById('sod-registry-learning-area');
                const searchForm = document.getElementById('sod-registry-search-form');
                const bulkForm = document.getElementById('sod-registry-bulk-merge-form');
                const selectedCount = document.getElementById('sod-registry-selected-count');
                const masterCheck = document.getElementById('sod-registry-master-check');
                const bulkCanonical = document.getElementById('sod-registry-bulk-canonical');
                const exportOutput = document.getElementById('sod-registry-export-output');
                const typeSwitcher = document.getElementById('sod-registry-type-switcher');
                const showBankBtn = document.getElementById('sod-registry-show-bank');
                const activeBankLabel = document.getElementById('sod-registry-active-bank-label');
                const activeBankNote = document.getElementById('sod-registry-active-bank-note');
                const registryLabels = <?php echo wp_json_encode($registry_labels, JSON_UNESCAPED_UNICODE); ?>;
                let activeType = app.getAttribute('data-registry-type') || 'actors';

                function currentType(){
                    return activeType || 'actors';
                }
                function currentLabel(){
                    return registryLabels[currentType()] || 'الجهات الفاعلة';
                }
                function currentSearch(){
                    const searchInput = searchForm ? searchForm.querySelector('[name="registry_search"]') : null;
                    return searchInput ? searchInput.value : (app.getAttribute('data-registry-search') || '');
                }
                function syncTypeFields(){
                    document.querySelectorAll('#sod-registry-app [name="registry_type"]').forEach(function(el){ el.value = currentType(); });
                    document.querySelectorAll('.sod-registry-tab').forEach(function(btn){
                        btn.classList.toggle('button-primary', btn.getAttribute('data-registry-tab') === currentType());
                    });
                    if (typeSwitcher) typeSwitcher.value = currentType();
                    if (activeBankLabel) activeBankLabel.textContent = currentLabel();
                    if (activeBankNote) activeBankNote.textContent = 'المعروض الآن: ' + currentLabel() + '. لاختيار بنك آخر من القائمة، اضغط زر "عرض البنك المختار".';
                }
                function showNotice(message, ok){
                    if (!noticeBox) return;
                    noticeBox.style.display = 'block';
                    noticeBox.className = ok ? 'notice notice-success inline' : 'notice notice-error inline';
                    noticeBox.innerHTML = '<p>' + (message || '') + '</p>';
                }
                function collectSelected(){
                    return Array.from(document.querySelectorAll('.sod-registry-row-check:checked')).map(el => el.value).filter(Boolean);
                }
                function syncSelectedCount(){
                    const selected = collectSelected();
                    if (selectedCount) selectedCount.textContent = selected.length + ' محدد';
                    if (selected.length === 1 && bulkCanonical && bulkCanonical.value.trim() === '') bulkCanonical.value = selected[0];
                }
                function bindRowChecks(){
                    document.querySelectorAll('.sod-registry-row-check').forEach(el => el.addEventListener('change', syncSelectedCount));
                    syncSelectedCount();
                }
                function refreshFromPayload(payload){
                    if (tableBody && payload.rows_html !== undefined) tableBody.innerHTML = payload.rows_html;
                    if (logArea && payload.log_html !== undefined) logArea.innerHTML = payload.log_html;
                    if (learningArea && payload.learning_html !== undefined) learningArea.innerHTML = payload.learning_html;
                    if (payload.type) {
                        activeType = payload.type;
                        app.setAttribute('data-registry-type', payload.type);
                    }
                    syncTypeFields();
                    bindRowChecks();
                    if (exportOutput && payload.export_data) {
                        exportOutput.style.display = 'block';
                        exportOutput.value = JSON.stringify(payload.export_data, null, 2);
                        exportOutput.focus();
                        exportOutput.select();
                    }
                    if (masterCheck) masterCheck.checked = false;
                }
                async function sendRequest(data){
                    const formData = new URLSearchParams();
                    formData.append('action', 'sod_registry_manage');
                    formData.append('nonce', nonce);
                    Object.keys(data).forEach(key => {
                        const value = data[key];
                        if (Array.isArray(value)) {
                            value.forEach(v => formData.append(key + '[]', v));
                        } else {
                            formData.append(key, value);
                        }
                    });
                    const res = await fetch(ajaxUrl, {method:'POST', headers:{'Content-Type':'application/x-www-form-urlencoded; charset=UTF-8'}, body:formData.toString()});
                    return res.json();
                }
                document.querySelectorAll('.sod-registry-ajax-form').forEach(form => {
                    form.addEventListener('submit', async function(e){
                        e.preventDefault();
                        const actionKind = form.getAttribute('data-registry-action') || '';
                        const data = {registry_action_kind: actionKind, registry_type: currentType(), registry_search: currentSearch()};
                        new FormData(form).forEach((value, key) => { if (key !== '_wp_http_referer' && key !== '_wpnonce' && key !== 'sod_registry_action') data[key] = value; });
                        if (actionKind === 'bulk_merge') data['selected_rows'] = collectSelected();
                        if (actionKind === 'bulk_merge' && (!data['selected_rows'] || data['selected_rows'].length < 2)) { showNotice('اختر سطرين على الأقل قبل تنفيذ الدمج الجماعي.', false); return; }
                        const json = await sendRequest(data);
                        showNotice((json.data && json.data.message) || 'تم التحديث.', !!json.success);
                        if (json.data) refreshFromPayload(json.data);
                    });
                });
                if (searchForm) {
                    searchForm.addEventListener('submit', async function(e){
                        e.preventDefault();
                        const json = await sendRequest({registry_action_kind:'search', registry_type: currentType(), registry_search: currentSearch()});
                        showNotice((json.data && json.data.message) || 'تم تحديث الفلتر.', !!json.success);
                        if (json.data) refreshFromPayload(json.data);
                    });
                }
                if (masterCheck) {
                    masterCheck.addEventListener('change', function(){
                        document.querySelectorAll('.sod-registry-row-check').forEach(el => { el.checked = masterCheck.checked; });
                        syncSelectedCount();
                    });
                }
                async function switchRegistryType(newType){
                    activeType = newType || 'actors';
                    syncTypeFields();
                    const json = await sendRequest({registry_action_kind:'switch_type', registry_type: currentType(), registry_search: currentSearch()});
                    showNotice((json.data && json.data.message) || 'تم تحديث القسم.', !!json.success);
                    if (json.data) refreshFromPayload(json.data);
                }
                document.querySelectorAll('.sod-registry-tab').forEach(function(btn){
                    btn.addEventListener('click', async function(){
                        await switchRegistryType(btn.getAttribute('data-registry-tab') || 'actors');
                    });
                });
                if (typeSwitcher) {
                    typeSwitcher.addEventListener('change', function(){
                        if (activeBankNote) {
                            const pendingLabel = registryLabels[typeSwitcher.value || 'actors'] || 'الجهات الفاعلة';
                            activeBankNote.textContent = 'تم اختيار: ' + pendingLabel + '. اضغط زر "عرض البنك المختار" لتحديث الجدول.';
                        }
                    });
                }
                if (showBankBtn) {
                    showBankBtn.addEventListener('click', async function(){
                        const selectedType = typeSwitcher ? (typeSwitcher.value || 'actors') : currentType();
                        showBankBtn.disabled = true;
                        const originalText = showBankBtn.textContent;
                        showBankBtn.textContent = 'جارٍ العرض...';
                        try {
                            await switchRegistryType(selectedType);
                        } finally {
                            showBankBtn.disabled = false;
                            showBankBtn.textContent = originalText;
                        }
                    });
                }
                const selectAllBtn = document.getElementById('sod-registry-select-all');
                const clearAllBtn = document.getElementById('sod-registry-clear-all');
                if (selectAllBtn) selectAllBtn.addEventListener('click', function(){ document.querySelectorAll('.sod-registry-row-check').forEach(el => el.checked = true); if (masterCheck) masterCheck.checked = true; syncSelectedCount(); });
                if (clearAllBtn) clearAllBtn.addEventListener('click', function(){ document.querySelectorAll('.sod-registry-row-check').forEach(el => el.checked = false); if (masterCheck) masterCheck.checked = false; syncSelectedCount(); });
                syncTypeFields();
                bindRowChecks();
            })();
            </script>
        </div>
        <?php
        // Local Intelligence Section - قسم المحرك الذكي المحلي
        if (class_exists('SO_Local_Intelligence_Admin')) {
            SO_Local_Intelligence_Admin::render_section();
        }
        echo '</div></div>';
    }

    private static function get_reindexable_columns($table_name) {
        global $wpdb;
        static $cache = [];
        if (isset($cache[$table_name])) {
            return $cache[$table_name];
        }
        $columns = $wpdb->get_col("SHOW COLUMNS FROM {$table_name}");
        if (!is_array($columns)) {
            $columns = [];
        }
        $cache[$table_name] = array_fill_keys($columns, true);
        return $cache[$table_name];
    }

    private static function get_reindex_pending_sql($allowed_columns) {
        $parts = ["(COALESCE(hybrid_layers, '') = '' OR COALESCE(threat_score, 0) = 0)"];
        if (isset($allowed_columns['reindexed_at'])) {
            $parts[] = "(reindexed_at IS NULL OR reindexed_at = '0000-00-00 00:00:00')";
        }
        return implode(' AND ', $parts);
    }

    private static function get_reindex_counts($table_name) {
        global $wpdb;
        $allowed_columns = self::get_reindexable_columns($table_name);
        $total = (int) $wpdb->get_var("SELECT COUNT(*) FROM {$table_name}");
        $pending_sql = self::get_reindex_pending_sql($allowed_columns);
        $pending = (int) $wpdb->get_var("SELECT COUNT(*) FROM {$table_name} WHERE {$pending_sql}");
        return [
            'total' => $total,
            'pending' => max(0, $pending),
            'done' => max(0, $total - $pending),
            'allowed_columns' => $allowed_columns,
            'pending_sql' => $pending_sql,
        ];
    }

    private static function get_reindex_dynamic_delay($auto_throttle = true) {
        $delay = 350;
        if (!$auto_throttle) return $delay;
        if (function_exists('sys_getloadavg')) {
            $load = sys_getloadavg();
            $one = isset($load[0]) ? (float) $load[0] : 0.0;
            if ($one >= 12) return 3000;
            if ($one >= 8) return 1800;
            if ($one >= 4) return 900;
        }
        $mem_limit = trim((string) ini_get('memory_limit'));
        if ($mem_limit && $mem_limit !== '-1') {
            $bytes = wp_convert_hr_to_bytes($mem_limit);
            if ($bytes > 0) {
                $usage = memory_get_usage(true);
                $ratio = $usage / $bytes;
                if ($ratio >= 0.85) return max($delay, 2200);
                if ($ratio >= 0.70) return max($delay, 1100);
            }
        }
        return $delay;
    }

    
public static function ajax_reindex_batch() {
    if (!current_user_can('manage_options')) {
        wp_send_json_error(['message' => 'غير مصرح لك.'], 403);
    }
    check_ajax_referer('bt_reindex_ajax_nonce');

    global $wpdb;
    $table_name = $wpdb->prefix . 'so_news_events';
    $limit = isset($_POST['batch_limit']) ? intval($_POST['batch_limit']) : 100;
    if ($limit < 1) $limit = 100;
    if ($limit > 500) $limit = 500;

    $cursor_id = isset($_POST['cursor_id']) ? max(0, intval($_POST['cursor_id'])) : 0;
    $reset_progress = !empty($_POST['reset_progress']);
    $live_only = !empty($_POST['live_only']);
    $auto_send_report = !empty($_POST['auto_send_report']);
    $auto_throttle = !empty($_POST['auto_throttle']);
    $progress_option = 'bt_reindex_progress_' . get_current_user_id();
    $allowed_columns = self::get_reindexable_columns($table_name);
    $last_completed_id = (int) get_option('bt_reindex_last_completed_id', 0);
    $live_sql = $live_only && $last_completed_id > 0 ? $wpdb->prepare(' AND id > %d', $last_completed_id) : '';

    $where_sql = '1=1' . $live_sql;
    if ($reset_progress || !is_array(get_option($progress_option))) {
        $initial_total = (int) $wpdb->get_var("SELECT COUNT(*) FROM {$table_name} WHERE {$where_sql}");
        update_option($progress_option, [
            'initial_total' => $initial_total,
            'last_cursor_id' => $live_only ? $last_completed_id : 0,
            'processed_total' => 0,
            'errors_total' => 0,
            'updated_total' => 0,
            'started_at' => current_time('mysql'),
            'live_only' => $live_only ? 1 : 0,
        ], false);
        $cursor_id = $live_only ? $last_completed_id : 0;
    }

    $progress = get_option($progress_option, []);
    if ($cursor_id <= 0 && !empty($progress['last_cursor_id'])) {
        $cursor_id = (int) $progress['last_cursor_id'];
    }

    $processed = 0;
    $errors = 0;
    $updated_rows = 0;
    $published_hooks = 0;
    $last_error = '';
    $next_cursor_id = $cursor_id;
    $delay = self::get_reindex_dynamic_delay($auto_throttle);

    $events = $wpdb->get_results($wpdb->prepare(
        "SELECT * FROM {$table_name} WHERE {$where_sql} AND id > %d ORDER BY id ASC LIMIT %d",
        $cursor_id,
        $limit
    ), ARRAY_A);

    if (!empty($events)) {
        foreach ($events as $event) {
            $event_id = (int) ($event['id'] ?? 0);
            $next_cursor_id = max($next_cursor_id, $event_id);
            try {
                if ($event_id <= 0) {
                    throw new Exception('معرّف الحدث غير صالح.');
                }

                $item = function_exists('sod_prepare_reindex_item_from_row')
                    ? sod_prepare_reindex_item_from_row($event)
                    : [
                        'title' => (string)($event['title'] ?? ''),
                        'content' => (string)($event['content'] ?? ''),
                        'link' => (string)($event['link'] ?? ''),
                        'source' => (string)($event['source_name'] ?? ($event['source'] ?? '')), 
                        'source_name' => (string)($event['source_name'] ?? ($event['source'] ?? '')), 
                        'date' => (string)($event['event_timestamp'] ?? ($event['processed_at'] ?? time())),
                        'image_url' => (string)($event['image_url'] ?? ''),
                        'agency_loc' => (string)($event['agency_loc'] ?? ''),
                    ];

                $pipeline = function_exists('sod_ingest_and_publish_canonical_item')
                    ? sod_ingest_and_publish_canonical_item($item, $event, ['status' => (string)($event['status'] ?? 'published'), 'decision_source' => 'reindex_pipeline'])
                    : ['ok' => false, 'error' => 'canonical_pipeline_missing'];

                if (empty($pipeline['ok'])) {
                    throw new Exception('فشل canonical pipeline للحدث #' . $event_id . (!empty($pipeline['error']) ? ': ' . $pipeline['error'] : ''));
                }

                $canonical = is_array($pipeline['canonical'] ?? null) ? $pipeline['canonical'] : [];
                $analyzed = is_array($pipeline['analyzed'] ?? null) ? $pipeline['analyzed'] : [];

                if (function_exists('sod_build_reindex_update_payload')) {
                    $safe_data = sod_build_reindex_update_payload($event, $canonical, $analyzed, $allowed_columns);
                } else {
                    $safe_data = [];
                    foreach (array_merge($analyzed, $canonical) as $key => $value) {
                        if ($key !== 'id' && isset($allowed_columns[$key])) $safe_data[$key] = $value;
                    }
                }

                if (empty($safe_data)) {
                    throw new Exception('لا توجد بيانات قابلة للحفظ للحدث #' . $event_id);
                }

                $updated = $wpdb->update($table_name, $safe_data, ['id' => $event_id]);
                if ($updated === false) {
                    throw new Exception('فشل تحديث قاعدة البيانات للحدث #' . $event_id . ': ' . $wpdb->last_error);
                }

                $updated_rows += (int) $updated;
                $processed++;

                if (function_exists('sod_after_reindex_pipeline_update')) {
                    sod_after_reindex_pipeline_update($event_id, $event, $safe_data);
                } else {
                    do_action('so_reclassify_event_after_insert', $event_id);
                }
                $published_hooks++;
            } catch (Throwable $e) {
                $errors++;
                $last_error = $e->getMessage();
                error_log('Unified Reindex AJAX Error: ' . $last_error);
            }
        }
    }

    $progress['last_cursor_id'] = $next_cursor_id;
    $progress['processed_total'] = (int) ($progress['processed_total'] ?? 0) + $processed;
    $progress['errors_total'] = (int) ($progress['errors_total'] ?? 0) + $errors;
    $progress['updated_total'] = (int) ($progress['updated_total'] ?? 0) + $updated_rows;
    update_option($progress_option, $progress, false);

    $remaining = (int) $wpdb->get_var($wpdb->prepare(
        "SELECT COUNT(*) FROM {$table_name} WHERE {$where_sql} AND id > %d",
        $next_cursor_id
    ));
    $initial_total = (int) ($progress['initial_total'] ?? ($processed + $remaining));
    $message = sprintf('تمت معالجة %d حدث عبر canonical pipeline وربطها بالبنوك والنشر، حدّثت %d سجلًا، وشُغّل post-insert على %d حدث. الأخطاء: %d. المتبقي: %d', $processed, $updated_rows, $published_hooks, $errors, $remaining);
    $report_sent = false;
    $report_send_message = '';

    if ($remaining <= 0) {
        delete_option($progress_option);
        update_option('bt_reindex_last_completed_id', (int) $next_cursor_id, false);
        if (class_exists('SO_Executive_Reports')) {
            $report = SO_Executive_Reports::refresh_cached_report(true);
            if ($auto_send_report && is_array($report) && !empty($report['text'])) {
                $report_sent = SO_Executive_Reports::send_to_telegram((string) $report['text']);
                $report_send_message = $report_sent ? 'تم إرسال التقرير إلى تيليغرام.' : 'تعذر إرسال التقرير تلقائيًا. تأكد من إعدادات تيليغرام.';
                if ($report_send_message) {
                    $message .= ' ' . $report_send_message;
                }
            }
        }
    }

    wp_send_json_success([
        'processed' => $processed,
        'errors' => $errors,
        'remaining' => max(0, $remaining),
        'total' => max($initial_total, $processed + $remaining),
        'last_error' => $last_error,
        'message' => $message,
        'next_cursor_id' => (int) $next_cursor_id,
        'last_completed_id' => $remaining <= 0 ? (int) $next_cursor_id : (int) get_option('bt_reindex_last_completed_id', 0),
        'server_suggested_delay' => (int) $delay,
        'report_sent' => $report_sent ? 1 : 0,
        'report_send_message' => $report_send_message,
        'updated_rows' => $updated_rows,
        'published_hooks' => $published_hooks,
    ]);
}


    public static function handle_saves() {
        if (!current_user_can('manage_options')) return;

        if (isset($_POST['sod_registry_action']) && check_admin_referer('sod_unified_registry_save')) {
            $action_kind = sanitize_key($_POST['sod_registry_action'] ?? '');
            $type = sanitize_key($_POST['registry_type'] ?? 'actors');
            $result = ['ok' => false, 'message' => 'إجراء غير معروف.'];
            if ($action_kind === 'add') {
                $result = sod_registry_upsert_term($type, (string)($_POST['registry_value'] ?? ''));
            } elseif ($action_kind === 'remove') {
                $result = sod_registry_remove_term($type, (string)($_POST['registry_value'] ?? ''));
            } elseif ($action_kind === 'merge') {
                $result = sod_registry_merge_term($type, (string)($_POST['registry_alias'] ?? ''), (string)($_POST['registry_canonical'] ?? ''));
            } elseif ($action_kind === 'rollback') {
                $result = sod_registry_rollback_merge((int)($_POST['registry_log_index'] ?? -1));
            }
            $redirect = add_query_arg([
                'page' => 'strategic-osint-reindex',
                'registry_type' => $type,
                'registry_notice' => rawurlencode((string)($result['message'] ?? 'تم التحديث.')),
            ], admin_url('admin.php'));
            wp_safe_redirect($redirect); exit;
        }

        // Save hybrid axis matrix
        if (isset($_POST['so_save_hybrid_matrix']) && check_admin_referer('so_save_hybrid_matrix_nonce')) {
            $payload = [
                'axis_resistance' => sanitize_textarea_field(wp_unslash($_POST['axis_resistance'] ?? '')),
                'axis_west' => sanitize_textarea_field(wp_unslash($_POST['axis_west'] ?? '')),
                'axis_east' => sanitize_textarea_field(wp_unslash($_POST['axis_east'] ?? '')),
                'hard_hostilities' => sanitize_textarea_field(wp_unslash($_POST['hard_hostilities'] ?? '')),
                'sponsor_relations' => sanitize_textarea_field(wp_unslash($_POST['sponsor_relations'] ?? '')),
                'strategic_partnerships' => sanitize_textarea_field(wp_unslash($_POST['strategic_partnerships'] ?? '')),
                'negotiation_keywords' => sanitize_textarea_field(wp_unslash($_POST['negotiation_keywords'] ?? '')),
                'hostility_keywords' => sanitize_textarea_field(wp_unslash($_POST['hostility_keywords'] ?? '')),
            ];
            update_option('so_hybrid_axis_matrix', $payload);
            wp_safe_redirect(add_query_arg('saved','1', admin_url('admin.php?page=strategic-osint-hybrid-matrix'))); exit;
        }

        // Save general settings
        if (isset($_POST['so_save_general']) && check_admin_referer('so_save_general_nonce')) {
            $opts = ['so_enable_logging','so_fetch_latest_only','so_filter_keywords','so_openweather_api_key','so_twitter_bearer_token','so_alert_threshold','so_popup_enabled','so_popup_threshold','so_popup_recent_minutes','so_popup_telegram_link','so_alert_sound_url'];
            foreach ($opts as $opt) if (isset($_POST[$opt])) update_option($opt, sanitize_text_field(wp_unslash($_POST[$opt])));
            update_option('so_popup_enabled', isset($_POST['so_popup_enabled']) ? 1 : 0);
            update_option('so_enable_logging', isset($_POST['so_enable_logging']) ? 1 : 0);
            update_option('so_fetch_latest_only', isset($_POST['so_fetch_latest_only']) ? 1 : 0);
            wp_safe_redirect(add_query_arg('saved','1', admin_url('admin.php?page=strategic-osint'))); exit;
        }

        // Save sources
        if (isset($_POST['so_save_sources']) && check_admin_referer('so_save_sources_nonce')) {
            $types = ['so_sources'=>'rss','so_tg_sources'=>'tg','so_x_sources'=>'x'];
            foreach ($types as $option => $prefix) {
                $names  = array_map('sanitize_text_field', (array)($_POST[$prefix.'_name']??[]));
                $urls   = array_map('esc_url_raw', (array)($_POST[$prefix.'_url']??[]));
                $colors = array_map('sanitize_hex_color', (array)($_POST[$prefix.'_color']??[]));
                $locs   = array_map('sanitize_text_field', (array)($_POST[$prefix.'_location']??[]));
