            $custom_names = array_map('sanitize_text_field', (array)($_POST['so_llm_custom_name'] ?? []));
            $custom_urls = array_map(static function($v){ return esc_url_raw(wp_unslash((string)$v)); }, (array)($_POST['so_llm_custom_url'] ?? []));
