            wp_safe_redirect(add_query_arg('saved','1', admin_url('admin.php?page=strategic-osint-alerts'))); exit;
        }

        // Save reports settings
        if (isset($_POST['so_save_reports']) && check_admin_referer('so_save_reports_nonce')) {
            $opts3 = ['so_exec_reports_frequency','so_exec_reports_window_hours','so_exec_reports_critical_threshold','so_exec_reports_chat_id','so_exec_reports_footer'];
            foreach ($opts3 as $opt) if (isset($_POST[$opt])) update_option($opt, sanitize_text_field(wp_unslash($_POST[$opt])));
            update_option('so_exec_reports_custom_hours', max(1, (int)($_POST['so_exec_reports_custom_hours']??6)));
            update_option('so_exec_reports_enabled', isset($_POST['so_exec_reports_enabled']) ? 1 : 0);
            update_option('so_exec_reports_force_repeat', isset($_POST['so_exec_reports_force_repeat']) ? 1 : 0);
            update_option('so_exec_report_generation_mode', in_array(sanitize_key((string)($_POST['so_exec_report_generation_mode'] ?? 'local')), ['local','ai'], true) ? sanitize_key((string)($_POST['so_exec_report_generation_mode'])) : 'local');
            if (class_exists('SO_Executive_Reports')) SO_Executive_Reports::reschedule();
            wp_safe_redirect(add_query_arg('saved','1', admin_url('admin.php?page=strategic-osint-reports'))); exit;
        }

        // Save appearance settings
        if (isset($_POST['so_save_appearance']) && check_admin_referer('so_save_appearance_nonce')) {
            update_option('so_custom_primary_color', sanitize_hex_color($_POST['so_custom_primary_color']??'#dc2626')?:'#dc2626');
            update_option('so_custom_bg_color', sanitize_hex_color($_POST['so_custom_bg_color']??'#0f172a')?:'#0f172a');
            update_option('so_custom_font', sanitize_text_field(wp_unslash($_POST['so_custom_font']??'Noto Naskh Arabic')));
            update_option('so_frontend_default_theme', in_array(sanitize_text_field(wp_unslash($_POST['so_frontend_default_theme'] ?? 'dark')), ['dark','light'], true) ? sanitize_text_field(wp_unslash($_POST['so_frontend_default_theme'])) : 'dark');
            // Font colors
            $fc_fields = ['so_text_color_heading'=>'#e0f2ff','so_text_color_body'=>'#94a3b8','so_text_color_accent'=>'#60a5fa','so_text_color_muted'=>'#64748b','so_text_color_score'=>'#ef4444'];
            foreach ($fc_fields as $opt => $def) { update_option($opt, sanitize_hex_color($_POST[$opt]??$def)?:$def); }
            wp_safe_redirect(add_query_arg('saved','1', admin_url('admin.php?page=strategic-osint-appearance'))); exit;
        }

        // Save manual post (news or video)
        if (isset($_POST['so_save_manual_post']) && check_admin_referer('so_manual_post_nonce')) {
            global $wpdb;
            $type = sanitize_text_field($_POST['manual_type']??'news');
            if ($type === 'video') {
                $streams = get_option('so_video_streams', []);
                $streams[] = ['name'=>sanitize_text_field(wp_unslash($_POST['manual_title']??'بث يدوي')),'url'=>esc_url_raw($_POST['manual_url']??''),'type'=>sanitize_text_field($_POST['manual_stream_type']??'embed'),'embed_code'=>(string)wp_unslash($_POST['manual_embed_code']??''),'manual'=>true];
                update_option('so_video_streams', $streams);
            } else {
                $table = $wpdb->prefix.'so_news_events';
                $ts = time();
                $title_clean = sanitize_text_field(wp_unslash($_POST['manual_title']??''));
                $manual_content = sanitize_textarea_field(wp_unslash($_POST['manual_content']??''));
                $manual_url = esc_url_raw($_POST['manual_url']??'');
                $manual_media_url = esc_url_raw($_POST['manual_media_url']??'');
                $manual_score = min(500, max(0, intval($_POST['manual_score']??50)));
                $item = [
                    'title' => $title_clean . ($manual_content !== '' ? ' — ' . $manual_content : ''),
                    'link' => $manual_url,
                    'source' => 'يدوي',
                    'source_name' => 'يدوي',
                    'date' => gmdate('c', $ts),
                    'image_url' => $manual_media_url,
                ];
                $pipeline = sod_ingest_and_publish_canonical_item($item, [], ['status' => 'published', 'decision_source' => 'manual_override']);
                $analyzed = is_array($pipeline['analyzed'] ?? null) ? (array)$pipeline['analyzed'] : [];
                $canonical = is_array($pipeline['canonical'] ?? null) ? (array)$pipeline['canonical'] : [];

                $final_intel = sanitize_text_field(wp_unslash($_POST['manual_intel_type']??'')) ?: (string)($canonical['intel_type'] ?? 'عام');
                $final_level = sanitize_text_field(wp_unslash($_POST['manual_tactical_level']??'')) ?: (string)($canonical['tactical_level'] ?? 'عملياتي');
                $final_region = sanitize_text_field(wp_unslash($_POST['manual_region']??'')) ?: (string)($canonical['region'] ?? '');
                $final_actor = sanitize_text_field(wp_unslash($_POST['manual_actor']??'')) ?: (string)($canonical['actor_v2'] ?? '');
                $final_target = sanitize_text_field(wp_unslash($_POST['manual_target']??'')) ?: (string)($canonical['target_v2'] ?? '');
                $final_context = sanitize_text_field(wp_unslash($_POST['manual_context']??'')) ?: (string)($canonical['context_actor'] ?? '');
                $final_intent = sanitize_text_field(wp_unslash($_POST['manual_intent']??'')) ?: (string)($canonical['intent'] ?? '');
                $final_weapon = sanitize_text_field(wp_unslash($_POST['manual_weapon']??'')) ?: (string)($canonical['weapon_v2'] ?? '');
                $war_data = sod_parse_json_array($canonical['war_data'] ?? ($analyzed['war_data'] ?? '{}'));
                $field_data = sod_parse_json_array($canonical['field_data'] ?? '{}');
                if ($manual_content !== '') $war_data['manual_content'] = $manual_content;
                $war_data['evaluation_mode'] = 'manual_saved';
                $war_data['evaluation_label'] = 'يدوي محفوظ';
                $war_data['actor'] = $final_actor;
                if ($final_target !== '') $war_data['target'] = $final_target;
                if ($final_context !== '') $war_data['context_actor'] = $final_context;
                if ($final_intent !== '') $war_data['intent'] = $final_intent;
                if ($final_weapon !== '') $war_data['weapon_means'] = $final_weapon;
                $field_data['manual_post'] = 1;
                $field_data['manual_content'] = $manual_content;
                $field_data['decision_source'] = 'manual_override';

                $canonical = array_merge($canonical, [
                    'hash_id' => md5(uniqid($title_clean, true)),
                    'title' => $title_clean,
                    'war_data' => wp_json_encode($war_data, JSON_UNESCAPED_UNICODE),
                    'field_data' => wp_json_encode($field_data, JSON_UNESCAPED_UNICODE),
                    'link' => $manual_url,
                    'image_url' => $manual_media_url,
                    'source_name' => 'يدوي',
                    'score' => $manual_score > 0 ? $manual_score : (int)($canonical['score'] ?? 100),
                    'threat_score' => $manual_score > 0 ? $manual_score : (int)($canonical['threat_score'] ?? $canonical['score'] ?? 100),
                    'region' => $final_region,
                    'actor_v2' => $final_actor,
                    'target_v2' => $final_target,
                    'context_actor' => $final_context,
                    'intent' => $final_intent,
                    'weapon_v2' => $final_weapon,
                    'intel_type' => $final_intel,
                    'event_timestamp' => $ts,
                    'tactical_level' => $final_level,
                    'status' => 'published',
                    'llm_verified' => 1,
                    'title_fingerprint' => so_build_title_fingerprint($title_clean),
                    'processed_at' => current_time('mysql'),
                    'analysis_status' => 'complete',
                    'decision_source' => 'manual_override',
                ]);
                $save = sod_save_canonical_event_state($table, $canonical);
                $new_id = !empty($save['ok']) ? (int)($save['insert_id'] ?? 0) : 0;
                foreach ([['types',$final_intel],['levels',$final_level],['regions',$final_region],['actors',$final_actor],['targets',$final_target],['contexts',$final_context],['intents',$final_intent],['weapons',$final_weapon]] as $pair) {
                    if (!empty($pair[1])) sod_add_bank_value($pair[0], $pair[1]);
                }
                if (!empty($_POST['manual_send_telegram']) && $new_id > 0) {
                    so_send_news_event_to_channels_by_id($new_id);
                }
                $has_manual_override = !empty($_POST['manual_actor']) || !empty($_POST['manual_region']) || !empty($_POST['manual_intel_type']) || !empty($_POST['manual_tactical_level']) || !empty($_POST['manual_target']) || !empty($_POST['manual_context']) || !empty($_POST['manual_intent']) || !empty($_POST['manual_weapon']);
                if ($new_id > 0 && !$has_manual_override) {
                    wp_schedule_single_event(time() + 5, 'so_reclassify_event_after_insert', [$new_id]);
                }
            }
            wp_safe_redirect(add_query_arg(['saved'=>'1','type'=>$type], admin_url('admin.php?page=strategic-osint-manual'))); exit;
        }

        // Save video streams settings
        if (isset($_POST['so_save_video_streams']) && check_admin_referer('so_save_video_nonce', '_wpnonce_video')) {
            $stream_names  = array_map('sanitize_text_field', (array)($_POST['stream_name']??[]));
            $stream_urls   = array_map('esc_url_raw', (array)($_POST['stream_url']??[]));
            $stream_types  = array_map('sanitize_text_field', (array)($_POST['stream_type']??[]));
            $streams = [];
            for ($i = 0; $i < count($stream_names); $i++) {
                if (!empty($stream_names[$i]) && !empty($stream_urls[$i])) {
                    $streams[] = ['name' => $stream_names[$i], 'url' => $stream_urls[$i], 'type' => $stream_types[$i]??'live'];
                }
            }
            update_option('so_video_streams', $streams);
            wp_safe_redirect(add_query_arg('saved','1', admin_url('admin.php?page=strategic-osint-video'))); exit;
        }

        // Save external cron key
        if (isset($_POST['so_save_cron_key']) && check_admin_referer('so_save_cron_key_nonce', '_wpnonce_cron')) {
            $key = sanitize_text_field(wp_unslash($_POST['so_external_cron_key']??''));
            if (isset($_POST['so_generate_cron_key'])) $key = wp_generate_password(40, false, false);
            update_option('so_external_cron_key', $key);
            wp_safe_redirect(add_query_arg('saved','1', admin_url('admin.php?page=strategic-osint'))); exit;
        }

        // Save dashboard settings
        if (isset($_POST['so_save_dashboards']) && check_admin_referer('so_save_dashboards_nonce')) {
            $opts4 = ['sod_powerbi_default_hours','sod_powerbi_auto_refresh','sod_ticker_auto_refresh','sod_threat_auto_refresh','sod_ticker_flip_speed','sod_news_ticker_marquee_duration'];
            foreach ($opts4 as $opt) if (isset($_POST[$opt])) update_option($opt, (int)$_POST[$opt]);
            $text_opts = [
                'sod_dashboard_designer_name',
                'sod_dashboard_designer_phone',
                'sod_dashboard_whatsapp_url',
                'sod_dashboard_x_url',
                'sod_dashboard_instagram_url',
                'sod_dashboard_facebook_url',
                'sod_dashboard_pinterest_url',
                'sod_dashboard_discord_url',
            ];
            foreach ($text_opts as $opt) {
                if (isset($_POST[$opt])) update_option($opt, sanitize_text_field(wp_unslash($_POST[$opt])));
            }
            if (isset($_POST['sod_dashboard_top_ad_code'])) update_option('sod_dashboard_top_ad_code', wp_kses_post(wp_unslash($_POST['sod_dashboard_top_ad_code'])));
            if (isset($_POST['sod_dashboard_bottom_ad_code'])) update_option('sod_dashboard_bottom_ad_code', wp_kses_post(wp_unslash($_POST['sod_dashboard_bottom_ad_code'])));
            if (isset($_POST['sod_dashboard_ga_code'])) update_option('sod_dashboard_ga_code', wp_kses_post(wp_unslash($_POST['sod_dashboard_ga_code'])));

            $old_slug = sod_dashboard_slug();
            $route_enabled = !empty($_POST['sod_dashboard_route_enabled']) ? 1 : 0;
            $route_slug = sanitize_title(wp_unslash($_POST['sod_dashboard_slug'] ?? 'osint-dashboard'));
            $route_slug = $route_slug !== '' ? $route_slug : 'osint-dashboard';
            $display_mode = sanitize_key(wp_unslash($_POST['sod_dashboard_display_mode'] ?? 'command_deck'));
            if (!in_array($display_mode, ['powerbi','world_monitor','command_deck','all','custom'], true)) $display_mode = 'world_monitor';
            $display_order = sanitize_key(wp_unslash($_POST['sod_dashboard_display_order'] ?? 'powerbi_command'));
            if (!in_array($display_order, ['powerbi_command','command_powerbi'], true)) $display_order = 'powerbi_command';

            $available_panels = sod_available_dashboard_panels();
            $selected_panels_raw = isset($_POST['sod_dashboard_selected_panels']) ? (array) $_POST['sod_dashboard_selected_panels'] : [];
            $selected_panels = array_values(array_filter(array_map('sanitize_key', $selected_panels_raw), function($key) use ($available_panels){
                return isset($available_panels[$key]);
            }));
            if (empty($selected_panels)) $selected_panels = ['world_monitor'];

            update_option('sod_dashboard_route_enabled', $route_enabled);
            update_option('sod_dashboard_slug', $route_slug);
            update_option('sod_dashboard_display_mode', $display_mode);
            update_option('sod_dashboard_display_order', $display_order);
            update_option('sod_dashboard_selected_panels', $selected_panels);

            if ($old_slug !== $route_slug || (int) get_option('sod_dashboard_route_enabled', 1) !== $route_enabled) {
                sod_register_dashboard_rewrite_rule();
                flush_rewrite_rules();
            }

            wp_safe_redirect(add_query_arg('saved','1', admin_url('admin.php?page=strategic-osint-dashboards'))); exit;
        }

        // Manual sync via URL
        if (isset($_GET['action']) && $_GET['action'] === 'so_manual_sync' && isset($_GET['_wpnonce']) && wp_verify_nonce($_GET['_wpnonce'], 'so_manual_sync')) {
            $inserted = SO_Cron_Manager::safe_sync_news();
            wp_safe_redirect(add_query_arg(['synced'=>'1','inserted'=>$inserted], admin_url('admin.php?page=strategic-osint'))); exit;
        }

        // ── EXPORT SETTINGS ──────────────────────────────────────────────────
        if (isset($_GET['so_action']) && $_GET['so_action'] === 'export_settings' && isset($_GET['_wpnonce']) && wp_verify_nonce(sanitize_text_field(wp_unslash($_GET['_wpnonce'])), 'so_export_settings')) {
            $data = self::get_all_plugin_options();
            $json = wp_json_encode($data, JSON_PRETTY_PRINT | JSON_UNESCAPED_UNICODE);
            $filename = 'beiruttime-settings-'.gmdate('Y-m-d').'.json';
            header('Content-Type: application/json; charset=utf-8');
            header('Content-Disposition: attachment; filename="'.$filename.'"');
            header('Content-Length: '.strlen($json));
            header('Cache-Control: no-cache, must-revalidate');
            header('Pragma: no-cache');
            echo $json; // phpcs:ignore WordPress.Security.EscapeOutput
            exit;
        }

        // ── IMPORT SETTINGS ──────────────────────────────────────────────────
        if (isset($_POST['so_import_settings']) && check_admin_referer('so_import_settings_nonce')) {
            $errors = [];
            $file_input = $_FILES['so_settings_file'] ?? null;
            
            // Use secure file uploader
            $upload_result = \BeirutTime\OSINTPro\UploadHandlers\SecureFileUploader::handle_upload(
                $file_input, 
                'json', 
                'خطأ في رفع ملف الإعدادات.'
            );
            
            if (is_wp_error($upload_result)) {
                $errors[] = $upload_result->get_error_message();
            } else {
                $decoded = \BeirutTime\OSINTPro\UploadHandlers\SecureFileUploader::read_json_file(
                    $upload_result['tmp_name'],
                    ['_plugin']
                );
                
                if (is_wp_error($decoded)) {
                    $errors[] = $decoded->get_error_message();
                } elseif (!is_array($decoded) || !isset($decoded['_plugin'])) {
                    $errors[] = 'الملف غير صالح — يرجى استخدام ملف JSON من هذه الإضافة فقط.';
                } else {
                    $allowed = array_keys(self::get_all_plugin_options());
                    $restored = 0;
                    foreach ($decoded as $key => $value) {
                        if ($key === '_plugin' || $key === '_exported_at') continue;
                        if (in_array($key, $allowed, true)) {
                            update_option($key, $value);
                            $restored++;
                        }
                    }
                    wp_safe_redirect(add_query_arg(['saved'=>'1','restored'=>$restored], admin_url('admin.php?page=strategic-osint-io'))); exit;
                }
            }
            if (!empty($errors)) {
                wp_safe_redirect(add_query_arg(['io_error'=>rawurlencode(implode(' | ', $errors))], admin_url('admin.php?page=strategic-osint-io'))); exit;
            }
        }


        // ── EXPORT ENTITY BANKS (CSV) ─────────────────────────────────────────
        if (isset($_GET['so_action']) && $_GET['so_action'] === 'export_banks' && isset($_GET['_wpnonce']) && wp_verify_nonce(sanitize_text_field(wp_unslash($_GET['_wpnonce'])), 'so_export_banks')) {
            global $wpdb;
            $rows = $wpdb->get_results("SELECT actor_name, target_name, region, weight FROM {$wpdb->prefix}so_entity_graph WHERE actor_name LIKE 'people:%' OR actor_name LIKE 'places:%' OR actor_name LIKE 'weapons:%' OR actor_name LIKE 'operations:%' ORDER BY actor_name", ARRAY_A);
            $filename = 'beiruttime-banks-'.gmdate('Y-m-d').'.csv';
            header('Content-Type: text/csv; charset=utf-8');
            header('Content-Disposition: attachment; filename="'.$filename.'"');
            header('Cache-Control: no-cache, must-revalidate');
            // BOM for Excel Arabic support
            echo "\xEF\xBB\xBF"; // phpcs:ignore WordPress.Security.EscapeOutput
            $cols = ['البنك','الاسم','الانتماء','التفاصيل','الوزن'];
            echo implode(',', array_map(fn($c)=>'"'.str_replace('"','""',$c).'"', $cols))."\n"; // phpcs:ignore WordPress.Security.EscapeOutput
            foreach ($rows as $row) {
                $parts = explode(':', $row['actor_name'], 2);
                $bank = $parts[0] ?? '';
                $name = $parts[1] ?? $row['actor_name'];
                $line = [
                    '"'.str_replace('"','""',$bank).'"',
                    '"'.str_replace('"','""',$name).'"',
                    '"'.str_replace('"','""',$row['target_name']).'"',
                    '"'.str_replace('"','""',$row['region']).'"',
                    number_format((float)$row['weight'], 1),
                ];
                echo implode(',', $line)."\n"; // phpcs:ignore WordPress.Security.EscapeOutput
            }
            exit;
        }


        // ── EXPORT ARCHIVE (JSON) ──────────────────────────────────────────────
        if (isset($_GET['so_action']) && $_GET['so_action'] === 'export_archive' && isset($_GET['_wpnonce']) && wp_verify_nonce(sanitize_text_field(wp_unslash($_GET['_wpnonce'])), 'so_export_archive')) {
            global $wpdb;
            $table = $wpdb->prefix . 'so_news_events';
            $limit = min(10000, max(100, (int)($_GET['limit'] ?? 2000)));
            $status = sanitize_key($_GET['status'] ?? 'published');
            $where = $status === 'all' ? '1=1' : $wpdb->prepare('status = %s', $status);
            $rows = $wpdb->get_results($wpdb->prepare("SELECT * FROM {$table} WHERE {$where} ORDER BY event_timestamp DESC LIMIT %d", $limit), ARRAY_A);
            $payload = [
                '_plugin' => 'beiruttime-osint-pro',
                '_type' => 'archive_export',
                '_exported_at' => gmdate('c'),
                '_site' => home_url('/'),
                '_count' => count($rows),
                'events' => array_map(['SO_Admin_UI','prepare_archive_event_export'], is_array($rows) ? $rows : []),
            ];
            $json = wp_json_encode($payload, JSON_PRETTY_PRINT | JSON_UNESCAPED_UNICODE);
            $filename = 'beiruttime-archive-'.gmdate('Y-m-d-His').'.json';
            header('Content-Type: application/json; charset=utf-8');
            header('Content-Disposition: attachment; filename="'.$filename.'"');
            header('Content-Length: '.strlen($json));
            header('Cache-Control: no-cache, must-revalidate');
            header('Pragma: no-cache');
            echo $json; // phpcs:ignore WordPress.Security.EscapeOutput
            exit;
        }

        // ── IMPORT ARCHIVE (JSON) ──────────────────────────────────────────────
        if (isset($_POST['so_import_archive']) && check_admin_referer('so_import_archive_nonce')) {
            $file_input = $_FILES['so_archive_file'] ?? null;
            
            // Use secure file uploader
            $upload_result = \BeirutTime\OSINTPro\UploadHandlers\SecureFileUploader::handle_upload(
                $file_input, 
                'json', 
                'خطأ في رفع ملف الأرشيف.'
            );
            
            if (is_wp_error($upload_result)) {
                wp_safe_redirect(add_query_arg(['io_error'=>rawurlencode($upload_result->get_error_message())], admin_url('admin.php?page=strategic-osint-archive-transfer'))); exit;
            }
            
            $decoded = \BeirutTime\OSINTPro\UploadHandlers\SecureFileUploader::read_json_file(
                $upload_result['tmp_name'],
                ['_type', 'events']
            );
            
            if (is_wp_error($decoded)) {
                wp_safe_redirect(add_query_arg(['io_error'=>rawurlencode($decoded->get_error_message())], admin_url('admin.php?page=strategic-osint-archive-transfer'))); exit;
            }
            
            if (!is_array($decoded) || ($decoded['_type'] ?? '') !== 'archive_export' || !isset($decoded['events']) || !is_array($decoded['events'])) {
                wp_safe_redirect(add_query_arg(['io_error'=>rawurlencode('ملف الأرشيف غير صالح.')], admin_url('admin.php?page=strategic-osint-archive-transfer'))); exit;
            }
            
            $result = self::import_archive_events($decoded['events']);
            wp_safe_redirect(add_query_arg(['saved'=>'1','archive_imported'=>(int)($result['inserted'] ?? 0),'archive_updated'=>(int)($result['updated'] ?? 0),'archive_skipped'=>(int)($result['skipped'] ?? 0)], admin_url('admin.php?page=strategic-osint-archive-transfer'))); exit;
        }


        // ── PULL ARCHIVE FROM REMOTE SITE ────────────────────────────────────────
        if (isset($_POST['so_pull_archive_remote']) && check_admin_referer('so_pull_archive_remote_nonce')) {
            $target_url = esc_url_raw(trim((string)($_POST['source_url'] ?? '')));
            $target_key = sanitize_text_field((string)($_POST['source_api_key'] ?? ''));
            $limit = min(5000, max(50, (int)($_POST['archive_pull_limit'] ?? 1000)));
            $status = sanitize_key((string)($_POST['archive_pull_status'] ?? 'published')) ?: 'published';
            if (!$target_url || !$target_key) {
                wp_safe_redirect(add_query_arg(['io_error'=>rawurlencode('أدخل رابط الموقع المصدر ومفتاح API.')], admin_url('admin.php?page=strategic-osint-archive-transfer'))); exit;
            }
            $endpoint = rtrim($target_url, '/') . '/wp-json/osint/v1/export';
            $request_url = add_query_arg(['key'=>$target_key,'type'=>'news_events','limit'=>$limit,'status'=>$status], $endpoint);
            $response = wp_remote_get($request_url, ['timeout'=>60,'redirection'=>3]);
            if (is_wp_error($response)) {
                wp_safe_redirect(add_query_arg(['io_error'=>rawurlencode('فشل جلب الأرشيف من الموقع المصدر: ' . $response->get_error_message())], admin_url('admin.php?page=strategic-osint-archive-transfer'))); exit;
            }
            $body = json_decode((string)wp_remote_retrieve_body($response), true);
            if (!is_array($body) || empty($body['items']) || !is_array($body['items'])) {
                wp_safe_redirect(add_query_arg(['io_error'=>rawurlencode('لم يتم العثور على عناصر قابلة للاستيراد من الموقع المصدر.')], admin_url('admin.php?page=strategic-osint-archive-transfer'))); exit;
            }
            $mapped = [];
            foreach ($body['items'] as $row) {
                if (!is_array($row)) continue;
                $mapped[] = self::prepare_archive_event_export([
                    'title' => (string)($row['title'] ?? ''),
                    'link' => (string)($row['link'] ?? ''),
                    'source_name' => (string)($row['source'] ?? $row['source_name'] ?? 'موقع خارجي'),
                    'source_color' => (string)($row['source_color'] ?? '#1d4ed8'),
                    'intel_type' => (string)($row['intel_type'] ?? 'عام'),
                    'tactical_level' => (string)($row['tactical_level'] ?? 'عملياتي'),
                    'region' => (string)($row['region'] ?? ''),
                    'actor_v2' => (string)($row['actor_v2'] ?? 'فاعل غير محسوم'),
                    'score' => (int)($row['score'] ?? 0),
                    'status' => (string)($row['status'] ?? 'published'),
                    'event_timestamp' => (int)($row['date'] ?? $row['event_timestamp'] ?? time()),
                    'war_data' => is_array($row['war_data'] ?? null) ? wp_json_encode($row['war_data'], JSON_UNESCAPED_UNICODE) : (string)($row['war_data'] ?? '{}'),
                    'field_data' => is_array($row['field_data'] ?? null) ? wp_json_encode($row['field_data'], JSON_UNESCAPED_UNICODE) : (string)($row['field_data'] ?? '{}'),
                    'weapon_v2' => (string)($row['weapon_v2'] ?? ''),
                    'target_v2' => (string)($row['target_v2'] ?? ''),
                    'context_actor' => (string)($row['context_actor'] ?? ''),
                    'intent' => (string)($row['intent'] ?? ''),
                    'title_fingerprint' => (string)($row['title_fingerprint'] ?? ''),
                    'hybrid_layers' => is_array($row['hybrid_layers'] ?? null) ? wp_json_encode($row['hybrid_layers'], JSON_UNESCAPED_UNICODE) : (string)($row['hybrid_layers'] ?? '[]'),
                    'image_url' => (string)($row['image_url'] ?? ''),
                    'agency_loc' => (string)($row['agency_loc'] ?? ''),
                ]);
            }
            $result = self::import_archive_events($mapped);
            wp_safe_redirect(add_query_arg(['saved'=>'1','archive_imported'=>(int)($result['inserted'] ?? 0),'archive_updated'=>(int)($result['updated'] ?? 0),'archive_skipped'=>(int)($result['skipped'] ?? 0),'archive_remote_pulled'=>count($mapped)], admin_url('admin.php?page=strategic-osint-archive-transfer'))); exit;
        }

        // ── PUSH ARCHIVE TO REMOTE SITE ────────────────────────────────────────
        if (isset($_POST['so_push_archive_remote']) && check_admin_referer('so_push_archive_remote_nonce')) {
            $target_url = esc_url_raw(trim((string)($_POST['target_url'] ?? '')));
            $api_key = sanitize_text_field(wp_unslash($_POST['target_api_key'] ?? ''));
            $limit = min(5000, max(50, (int)($_POST['archive_limit'] ?? 1000)));
            if (!$target_url || !$api_key) {
                wp_safe_redirect(add_query_arg(['io_error'=>rawurlencode('أدخل رابط الموقع الآخر ومفتاح API.')], admin_url('admin.php?page=strategic-osint-archive-transfer'))); exit;
            }
            global $wpdb;
            $table = $wpdb->prefix . 'so_news_events';
            $rows = $wpdb->get_results($wpdb->prepare("SELECT * FROM {$table} WHERE status='published' ORDER BY event_timestamp DESC LIMIT %d", $limit), ARRAY_A);
            $payload = [
                '_plugin' => 'beiruttime-osint-pro',
                '_type' => 'archive_export',
                '_exported_at' => gmdate('c'),
                '_site' => home_url('/'),
                '_count' => count($rows),
                'events' => array_map(['SO_Admin_UI','prepare_archive_event_export'], is_array($rows) ? $rows : []),
            ];
            $endpoint = rtrim($target_url, '/') . '/wp-json/osint/v1/archive-import';
            $response = wp_remote_post($endpoint, [
                'timeout' => 45,
                'headers' => [
                    'Content-Type' => 'application/json; charset=utf-8',
                    'X-OSINT-API-KEY' => $api_key,
                ],
                'body' => wp_json_encode($payload, JSON_UNESCAPED_UNICODE),
            ]);
            if (is_wp_error($response)) {
                wp_safe_redirect(add_query_arg(['io_error'=>rawurlencode('فشل الاتصال بالموقع الآخر: ' . $response->get_error_message())], admin_url('admin.php?page=strategic-osint-archive-transfer'))); exit;
            }
            $code = (int)wp_remote_retrieve_response_code($response);
            $body = json_decode((string)wp_remote_retrieve_body($response), true);
            if ($code < 200 || $code >= 300 || empty($body['success'])) {
                $msg = is_array($body) ? (string)($body['message'] ?? 'رفض الموقع الآخر الطلب.') : 'رفض الموقع الآخر الطلب.';
                wp_safe_redirect(add_query_arg(['io_error'=>rawurlencode($msg)], admin_url('admin.php?page=strategic-osint-archive-transfer'))); exit;
            }
            wp_safe_redirect(add_query_arg(['saved'=>'1','archive_remote_sent'=>(int)($body['received'] ?? count($rows))], admin_url('admin.php?page=strategic-osint-archive-transfer'))); exit;
        }

        // ── IMPORT ENTITY BANKS (CSV) ─────────────────────────────────────────
        if (isset($_POST['so_import_banks']) && check_admin_referer('so_import_banks_nonce')) {
            global $wpdb;
            $file_input = $_FILES['so_banks_file'] ?? null;
            
            // Use secure file uploader for CSV
            $upload_result = \BeirutTime\OSINTPro\UploadHandlers\SecureFileUploader::handle_upload(
                $file_input, 
                'csv', 
                'خطأ في رفع الملف.'
            );
            
            if (is_wp_error($upload_result)) {
                wp_safe_redirect(add_query_arg(['io_error'=>rawurlencode($upload_result->get_error_message())], admin_url('admin.php?page=strategic-osint-io'))); exit;
            }
            
            $rows = \BeirutTime\OSINTPro\UploadHandlers\SecureFileUploader::read_csv_file($upload_result['tmp_name'], 1);
            
            if (is_wp_error($rows)) {
                wp_safe_redirect(add_query_arg(['io_error'=>rawurlencode($rows->get_error_message())], admin_url('admin.php?page=strategic-osint-io'))); exit;
            }
            
            $imported = 0; $skipped = 0;
            $valid_banks = ['people','places','weapons','operations'];
            
            foreach ($rows as $cols) {
                if (count($cols) < 3) { $skipped++; continue; }
                $bank  = sanitize_key(trim($cols[0]));
                $name  = sanitize_text_field(trim($cols[1]));
                $affil = sanitize_text_field(trim($cols[2]));
                $notes = sanitize_text_field(trim($cols[3] ?? ''));
                $weight = isset($cols[4]) ? abs((float)$cols[4]) : 5.0;
                if (!in_array($bank, $valid_banks, true) || empty($name)) { $skipped++; continue; }
                $key = $bank.':'.$name;
                $hash = md5($key);
                $exists = $wpdb->get_var($wpdb->prepare("SELECT id FROM {$wpdb->prefix}so_entity_graph WHERE edge_hash=%s", $hash));
                if ($exists) {
                    $wpdb->update("{$wpdb->prefix}so_entity_graph", ['target_name'=>$affil,'region'=>$notes,'weight'=>$weight,'last_seen'=>time()], ['edge_hash'=>$hash]);
                } else {
                    $ts = time();
                    $wpdb->insert("{$wpdb->prefix}so_entity_graph", ['edge_hash'=>$hash,'actor_name'=>$key,'target_name'=>$affil,'region'=>$notes,'weight'=>$weight,'event_count'=>0,'first_seen'=>$ts,'last_seen'=>$ts]);
                }
                $imported++;
            }
            wp_safe_redirect(add_query_arg(['saved'=>'1','banks_imported'=>$imported,'banks_skipped'=>$skipped], admin_url('admin.php?page=strategic-osint-io'))); exit;
        }


        // ── RESEED ENTITY BANKS ───────────────────────────────────────────────
        if (isset($_POST['so_reseed_banks']) && check_admin_referer('so_reseed_banks_nonce')) {
            delete_option('so_entity_banks_seeded_v17');
            SO_V7_Upgrade::seed_entity_banks();
            update_option('so_entity_banks_seeded_v17', true);
            wp_safe_redirect(add_query_arg(['saved'=>'1','reseeded'=>'1'], admin_url('admin.php?page=strategic-osint-io'))); exit;
        }
    }

    // ── Helper: list of all plugin option keys + their current values ────────
    private static function get_all_plugin_options(): array {
        $keys = [
            'so_enable_logging','so_fetch_latest_only','so_filter_keywords','so_openweather_api_key',
            'so_twitter_bearer_token','so_alert_threshold','so_popup_enabled','so_popup_threshold',
            'so_popup_recent_minutes','so_popup_telegram_link','so_alert_sound_url',
            'so_sources','so_tg_sources','so_x_sources',
            'so_llm_api_key','so_llm_brief_enabled','so_llm_provider','so_llm_model',
            'so_llm_anthropic_api_key','so_llm_anthropic_model',
            'so_llm_gemini_api_key','so_llm_gemini_model',
            'so_llm_openrouter_api_key','so_llm_openrouter_model',
            'so_llm_groq_api_key','so_llm_groq_model',
            'so_llm_perplexity_api_key','so_llm_perplexity_model',
            'so_llm_unli_api_key','so_llm_unli_model','so_llm_unli_base_url',
            'so_llm_custom_providers',
            'so_tg_token','so_tg_chat','so_telegram_enabled','so_discord_webhook','so_tg_min_score','so_discord_min_score','so_tg_allowed_types','so_discord_allowed_types','so_tg_allowed_actors','so_discord_allowed_actors','so_tg_allowed_regions','so_discord_allowed_regions',
            'so_exec_reports_frequency','so_exec_reports_window_hours','so_exec_reports_critical_threshold',
            'so_exec_reports_chat_id','so_exec_reports_footer','so_exec_reports_custom_hours','so_exec_report_generation_mode',
            'so_exec_reports_enabled','so_exec_reports_force_repeat',
            'so_custom_primary_color','so_custom_bg_color','so_custom_font',
            'so_video_streams','so_external_cron_key',
            'sod_powerbi_default_hours','sod_powerbi_auto_refresh',
            'sod_ticker_auto_refresh','sod_threat_auto_refresh',
            'so_powerbi_header_text','so_powerbi_logo_url','so_powerbi_footer_text',
