        $data = ['_plugin'=>'beiruttime-osint-pro','_exported_at'=>gmdate('c')];
        foreach ($keys as $k) $data[$k] = get_option($k);
        return $data;
    }

    public static function ajax_test_telegram() {
        if (!current_user_can('manage_options') || !check_ajax_referer('so_test_telegram','nonce',false)) { wp_send_json_error(['message'=>'غير مصرح']); }
        $token = trim(get_option('so_tg_token',''));
        $chats = array_filter(array_map('trim', explode(',', get_option('so_tg_chat',''))));
        if (empty($token) || empty($chats)) { wp_send_json_error(['message'=>'يرجى إدخال التوكن وقائمة الغرف أولاً']); }
        $ok = false;
        foreach ($chats as $chat_id) {
            $res = so_safe_remote_post("https://api.telegram.org/bot{$token}/sendMessage", ['headers'=>['Content-Type'=>'application/json'],'body'=>wp_json_encode(['chat_id'=>$chat_id,'text'=>'✅ اختبار ناجح من Beiruttime OSINT System V19.1.3 — نظام الرصد الاستخباراتي الموحد','parse_mode'=>'HTML']),'timeout'=>10]);
            if (!is_wp_error($res)) { $body = json_decode(wp_remote_retrieve_body($res),true); if (!empty($body['ok'])) $ok = true; }
        }
        $ok ? wp_send_json_success(['message'=>'تم الإرسال بنجاح']) : wp_send_json_error(['message'=>'فشل الإرسال — تحقق من التوكن وصلاحيات البوت']);
    }

    private static function get_custom_llm_providers(): array {
        $rows = get_option('so_llm_custom_providers', []);
        if (!is_array($rows)) return [];
        $out = [];
        foreach ($rows as $row) {
            if (!is_array($row)) continue;
            $id = sanitize_key((string)($row['id'] ?? ''));
            $name = sanitize_text_field((string)($row['name'] ?? ''));
            $url = esc_url_raw((string)($row['url'] ?? ''));
            $api_key = sanitize_text_field((string)($row['api_key'] ?? ''));
            $model = sanitize_text_field((string)($row['model'] ?? ''));
            if ($id === '' || $name === '' || $url === '' || $api_key === '') continue;
            $out[] = [
                'id' => str_starts_with($id, 'custom_') ? $id : ('custom_' . $id),
                'name' => $name,
                'url' => $url,
                'api_key' => $api_key,
                'model' => $model !== '' ? $model : 'gpt-4o-mini',
            ];
        }
        return $out;
    }

    public static function ajax_test_ai_service() {
        if (!current_user_can('manage_options') || !check_ajax_referer('so_test_ai_service', 'nonce', false)) {
            wp_send_json_error(['message' => 'غير مصرح'], 403);
        }
        $provider = sanitize_key((string)($_POST['provider'] ?? ''));
        $providers = [
            'openai' => ['key' => 'so_llm_api_key', 'url' => 'https://api.openai.com/v1/models', 'header' => 'Authorization'],
            'anthropic' => ['key' => 'so_llm_anthropic_api_key', 'url' => 'https://api.anthropic.com/v1/models', 'header' => 'x-api-key'],
            'gemini' => ['key' => 'so_llm_gemini_api_key', 'url' => 'https://generativelanguage.googleapis.com/v1/models', 'header' => 'none'],
            'openrouter' => ['key' => 'so_llm_openrouter_api_key', 'url' => 'https://openrouter.ai/api/v1/models', 'header' => 'Authorization'],
            'groq' => ['key' => 'so_llm_groq_api_key', 'url' => 'https://api.groq.com/openai/v1/models', 'header' => 'Authorization'],
            'perplexity' => ['key' => 'so_llm_perplexity_api_key', 'url' => 'https://api.perplexity.ai/chat/completions', 'header' => 'Authorization'],
            'unli' => ['key' => 'so_llm_unli_api_key', 'url' => (string)get_option('so_llm_unli_base_url', 'https://unli.dev/api/v1/chat/completions'), 'header' => 'Authorization'],
        ];
        foreach (self::get_custom_llm_providers() as $custom) {
            $providers[$custom['id']] = ['url' => (string)$custom['url'], 'header' => 'Authorization', 'api_key_raw' => (string)$custom['api_key'], 'model' => (string)$custom['model']];
        }
        if (!isset($providers[$provider])) {
            if (str_starts_with($provider, 'custom_')) {
                $tmp_url = esc_url_raw(wp_unslash((string)($_POST['custom_url'] ?? '')));
                $tmp_key = sanitize_text_field(wp_unslash((string)($_POST['custom_api_key'] ?? '')));
                $tmp_model = sanitize_text_field(wp_unslash((string)($_POST['custom_model'] ?? 'gpt-4o-mini')));
                if ($tmp_url !== '' && $tmp_key !== '') {
                    $providers[$provider] = ['url' => $tmp_url, 'header' => 'Authorization', 'api_key_raw' => $tmp_key, 'model' => ($tmp_model !== '' ? $tmp_model : 'gpt-4o-mini')];
                }
            }
            if (!isset($providers[$provider])) wp_send_json_error(['message' => 'مزود غير معروف'], 400);
        }
        $cfg = $providers[$provider];
        $api_key = isset($cfg['api_key_raw']) ? trim((string)$cfg['api_key_raw']) : trim((string)get_option($cfg['key'], ''));
        if ($api_key === '') {
            wp_send_json_error(['message' => 'مفتاح API غير مُدخل لهذه الخدمة'], 400);
        }
        $url = $cfg['url'];
        $args = ['timeout' => 15, 'headers' => []];
        if ($provider === 'gemini') {
            $url = add_query_arg('key', rawurlencode($api_key), $url);
        } elseif ($provider === 'anthropic') {
            $args['headers']['x-api-key'] = $api_key;
            $args['headers']['anthropic-version'] = '2023-06-01';
        } else {
            $args['headers']['Authorization'] = 'Bearer ' . $api_key;
        }
        if (in_array($provider, ['perplexity', 'unli'], true) || str_starts_with($provider, 'custom_')) {
            $model_value = '';
            if (str_starts_with($provider, 'custom_')) {
                $raw = (string)($cfg['model'] ?? 'gpt-4o-mini');
                $parts = preg_split('/[\r\n,]+/', $raw) ?: [];
                foreach ($parts as $part) {
                    $candidate = sanitize_text_field(trim((string)$part));
                    if ($candidate !== '') { $model_value = $candidate; break; }
                }
                if ($model_value === '') $model_value = 'gpt-4o-mini';
            }
            $args['headers']['Content-Type'] = 'application/json';
            $args['method'] = 'POST';
            $args['body'] = wp_json_encode([
                'model' => str_starts_with($provider, 'custom_') ? $model_value : ($provider === 'perplexity' ? (string)get_option('so_llm_perplexity_model', 'sonar') : (string)get_option('so_llm_unli_model', 'gpt-4o-mini')),
                'messages' => [['role' => 'user', 'content' => 'ping']],
                'max_tokens' => 8,
            ]);
        }
        $res = wp_remote_request($url, $args);
        if (is_wp_error($res)) {
            wp_send_json_error(['message' => $res->get_error_message()], 500);
        }
        $code = (int)wp_remote_retrieve_response_code($res);
        if ($code >= 200 && $code < 300) {
            wp_send_json_success(['message' => 'الخدمة تعمل بنجاح (' . $code . ')']);
        }
        wp_send_json_error(['message' => 'فشل الاتصال (' . $code . '): ' . wp_strip_all_tags((string)wp_remote_retrieve_body($res))], 500);
    }

