            'strategic-osint-reports' => '📊 التقارير التنفيذية',
            'strategic-osint-dashboards' => '🗺️ الخرائط واللوحات',
            'strategic-osint-video' => '📹 الفيديو والبث',
            'strategic-osint-newslog' => '📰 سجل الأخبار',
            'strategic-osint-banks' => '🏛️ بنوك المعلومات',
            'strategic-osint-db' => '🗄️ البيانات والصيانة',
            'strategic-osint-io' => '📦 الاستيراد والتصدير',
            'strategic-osint-archive-transfer' => '🔁 نقل الأرشيف',
            'strategic-osint-hybrid-matrix' => '🧭 مصفوفة المحاور',
            'strategic-osint-manual' => '📝 النشر اليدوي',
            'strategic-osint-appearance' => '🎨 المظهر والخطوط',
            'strategic-osint-diag' => '🔎 التشخيص والسجلات',
        ];
        echo '<div class="so-nav-tabs">';
        foreach ($pages as $slug => $label) {
            $active = $slug === $current_page ? ' active' : '';
            echo '<a href="' . esc_url(admin_url('admin.php?page='.$slug)) . '" class="so-nav-tab' . $active . '">' . esc_html($label) . '</a>';
