        <script>
        (function(){
            const result = document.getElementById('so-ai-test-result');
            const testHandler = function(btn){
                    const provider = this.getAttribute('data-provider');
                    this.disabled = true;
                    if (result) { result.style.color='#475569'; result.textContent='⏳ جارٍ فحص ' + provider + '...'; }
                    const fd = new FormData();
                    fd.append('action', 'so_test_ai_service');
                    fd.append('provider', provider);
                    if ((provider || '').startsWith('custom_')) {
                        const row = this.closest('tr');
                        const rowUrl = row ? row.querySelector('input[name="so_llm_custom_url[]"]') : null;
                        const rowKey = row ? row.querySelector('input[name="so_llm_custom_api_key[]"]') : null;
                        const rowModel = row ? row.querySelector('input[name="so_llm_custom_model[]"]') : null;
                        if (rowUrl) fd.append('custom_url', rowUrl.value || '');
                        if (rowKey) fd.append('custom_api_key', rowKey.value || '');
                        if (rowModel) fd.append('custom_model', rowModel.value || '');
                    }
                    fd.append('nonce', '<?php echo wp_create_nonce('so_test_ai_service'); ?>');
                    fetch('<?php echo esc_js(admin_url('admin-ajax.php')); ?>', {method:'POST', body:fd, credentials:'same-origin'})
                        .then(r=>r.json())
                        .then(j=>{
                            if (result) {
                                if (j && j.success) { result.style.color='#15803d'; result.textContent='✅ ' + (j.data?.message || 'نجح الفحص'); }
                                else { result.style.color='#b91c1c'; result.textContent='❌ ' + (j?.data?.message || 'فشل الفحص'); }
                            }
                        })
                        .catch(()=>{
                            if (result) { result.style.color='#b91c1c'; result.textContent='❌ خطأ في الاتصال أثناء الفحص'; }
                        })
                        .finally(()=>{ this.disabled = false; });
                };
            document.querySelectorAll('.so-ai-test-btn').forEach(function(btn){
                if (btn.closest('#so-custom-llm-wrap')) return;
                btn.addEventListener('click', testHandler);
            });
            const customWrap = document.getElementById('so-custom-llm-wrap');
            const addCustomBtn = document.getElementById('so-add-custom-llm');
            if (customWrap && addCustomBtn) {
                addCustomBtn.addEventListener('click', function(){
                    const idx = customWrap.querySelectorAll('tr').length + 1;
                    const row = document.createElement('tr');
                    row.className = 'so-custom-llm-row';
                    row.innerHTML = `
                        <td><input type="text" class="so-input" name="so_llm_custom_name[]" placeholder="اسم الوكيل ${idx}"></td>
                        <td><input type="text" class="so-input" name="so_llm_custom_id[]" placeholder="custom_agent_${idx}"></td>
                        <td><input type="url" class="so-input" name="so_llm_custom_url[]" placeholder="https://host/v1/chat/completions"></td>
                        <td><input type="password" class="so-input" name="so_llm_custom_api_key[]" placeholder="API Key"></td>
                        <td><input type="text" class="so-input" name="so_llm_custom_model[]" placeholder="gpt-4o-mini, llama-3.1-70b"></td>
                        <td><button type="button" class="button so-ai-test-btn">فحص</button></td>
                        <td><button type="button" class="button so-remove-custom-btn">✕</button></td>
                    `;
                    customWrap.appendChild(row);
                });
                customWrap.addEventListener('click', function(e){
                    const t = e.target;
                    if (!(t instanceof HTMLElement)) return;
                    if (t.classList.contains('so-remove-custom-btn')) {
                        const tr = t.closest('tr'); if (tr) tr.remove();
                    }
                    if (t.classList.contains('so-ai-test-btn')) {
                        const tr = t.closest('tr');
                        if (!tr) return;
                        const idInput = tr.querySelector('input[name="so_llm_custom_id[]"]');
                        if (idInput) {
                            let val = (idInput.value || '').trim().toLowerCase().replace(/[^a-z0-9_]/g,'_');
                            if (val && !val.startsWith('custom_')) val = 'custom_' + val;
                            if (val) { idInput.value = val; t.setAttribute('data-provider', val); }
                            else t.removeAttribute('data-provider');
                        }
                        if (!t.getAttribute('data-provider')) {
                            if (result) { result.style.color='#b91c1c'; result.textContent='❌ أدخل معرّف الوكيل أولاً'; }
                            return;
                        }
                        testHandler.call(t);
                    }
                });
            }
	        })();
	        </script>
        <?php self::admin_wrap_close();
    }

