        document.getElementById('so-test-tg-btn').addEventListener('click',function(){
            const btn=this;const result=document.getElementById('so-test-tg-result');
            btn.disabled=true;result.textContent='⏳ جارٍ الاختبار...';result.style.color='#7aa0c4';
            const fd=new FormData();fd.append('action','so_test_telegram');fd.append('nonce','<?php echo wp_create_nonce('so_test_telegram'); ?>');
            fetch('<?php echo esc_js(admin_url('admin-ajax.php')); ?>',{method:'POST',body:fd,credentials:'same-origin'})
            .then(r=>r.json()).then(j=>{if(j.success){result.textContent='✅ '+j.data.message;result.style.color='#22c55e';}else{result.textContent='❌ '+(j.data?.message||'فشل');result.style.color='#ef4444';}btn.disabled=false;}).catch(()=>{result.textContent='❌ خطأ في الاتصال';result.style.color='#ef4444';btn.disabled=false;});
        });
        </script>
        <?php self::admin_wrap_close();
    }

    public static function page_reports() {
        self::admin_wrap_open('التقارير التنفيذية');
        self::admin_nav('strategic-osint-reports');
        // Handle manual send via form submit
        if (isset($_GET['exec_report_sent'])) {
            $ok = $_GET['exec_report_sent'] === '1';
            echo '<div style="background:' . ($ok ? '#14532d' : '#7f1d1d') . ';color:#fff;padding:12px 16px;border-radius:8px;margin-bottom:16px;">';
            echo $ok ? '✅ تم إرسال التقرير إلى تيليغرام بنجاح.' : '❌ فشل إرسال التقرير. تحقق من إعدادات تيليغرام.';
            echo '</div>';
        }
        $last_sent = get_option('so_exec_last_report_time', 0);
        $last_sent_str = $last_sent ? wp_date('Y-m-d H:i', $last_sent) : 'لم يُرسل بعد';
        $report = [];
        $report_html = '';
        $report_error = '';
        try {
            $report = SO_Executive_Reports::build_report();
            $report_html = SO_Executive_Reports::render_exec_report_html($report);
        } catch (\Throwable $e) {
            $report_error = $e->getMessage();
            if (function_exists('so_log_event')) {
                so_log_event('exec_report_error', [
                    'message' => $e->getMessage(),
                    'file' => $e->getFile(),
                    'line' => $e->getLine(),
                ]);
            }
        }
        ?>
        <!-- إرسال يدوي فوري -->
        <div class="so-admin-card" style="border:2px solid #dc2626;">
            <h3>🚀 إرسال تقرير فوري الآن</h3>
            <p style="color:#94a3b8;font-size:13px;margin-bottom:12px;">آخر إرسال: <strong style="color:#60a5fa;"><?php echo esc_html($last_sent_str); ?></strong></p>
            <div style="display:flex;gap:12px;align-items:center;flex-wrap:wrap;">
                <button type="button" id="so-exec-generate-ai-btn" class="so-btn" style="background:#0ea5e9;">🧠 توليد التقرير (AI/محلي)</button>
                <button type="button" id="so-exec-send-now-btn" class="so-btn" style="background:#dc2626;">📤 إرسال التقرير الآن</button>
                <button type="button" id="so-exec-send-word-btn" class="so-btn" style="background:#1d4ed8;">📄 إرسال Word إلى تيليغرام</button>
                <button type="button" id="so-exec-send-pdf-btn" class="so-btn" style="background:#7c3aed;">ارسال PDF الى تيليغرام</button>
                <span id="so-exec-send-result" style="font-size:13px;color:#7aa0c4;"></span>
            </div>
        </div>
        <div class="so-admin-card so-exec-preview-card">
            <div class="so-exec-preview-actions">
                <div>
                    <h3>🖨️ معاينة التقرير التنفيذي للطباعة</h3>
                    <p style="color:#94a3b8;font-size:13px;margin:6px 0 0;">صيغة مختصرة واحترافية قابلة للتقديم والنسخ والطباعة المباشرة.</p>
                </div>
                <div style="display:flex;gap:10px;flex-wrap:wrap;">
                    <button type="button" class="button button-primary" id="so-exec-print-btn">طباعة التقرير</button>
