                    <button type="button" class="button" id="so-exec-word-btn">تنزيل Word</button>
                    <button type="button" class="button" id="so-exec-copy-btn">نسخ النص التنفيذي</button>
                </div>
            </div>
            <?php if ($report_error !== ''): ?>
                <div style="background:#7f1d1d;color:#fff;padding:14px 16px;border-radius:10px;line-height:1.9;">
                    تعذر بناء التقرير التنفيذي حاليًا.
