        @media print{
            body.wp-admin #wpadminbar,body.wp-admin #adminmenumain,body.wp-admin #screen-meta,body.wp-admin #screen-meta-links,body.wp-admin .notice,body.wp-admin .update-nag,body.wp-admin .so-admin-nav,body.wp-admin .so-exec-preview-actions,body.wp-admin form,.so-admin-card:not(.so-exec-preview-card){display:none !important}
