        </style>
        <script>
        function soExecAjax(actionName, button, progressText) {
            const result = document.getElementById('so-exec-send-result');
            button.disabled = true;
            result.textContent = progressText;
            result.style.color = '#7aa0c4';
            const fd = new FormData();
            fd.append('action', actionName);
            fd.append('nonce', '<?php echo wp_create_nonce('so_exec_report_ajax'); ?>');
            fetch('<?php echo esc_js(admin_url('admin-ajax.php')); ?>', {method:'POST', body:fd, credentials:'same-origin'})
            .then(r => r.text().then(t => ({status:r.status, text:t})))
            .then(({status, text}) => {
                let j = null;
                try { j = JSON.parse(text); }
                catch (e) {
                    const trimmed = String(text || '').trim();
                    const start = trimmed.indexOf('{');
                    if (start >= 0) {
                        try { j = JSON.parse(trimmed.slice(start)); } catch (e2) {}
                    }
                }
                if (!j) {
                    result.textContent = '❌ ' + (text ? text.slice(0, 220) : ('HTTP ' + status));
                    result.style.color = '#ef4444';
                    button.disabled = false;
                    return;
                }
                if (j.success) {
                    result.textContent = '✅ ' + (j.data?.message || 'تم بنجاح');
                    result.style.color = '#22c55e';
                } else {
                    result.textContent = '❌ ' + (j.data?.message || 'فشل');
                    result.style.color = '#ef4444';
                }
                button.disabled = false;
            }).catch((err) => {
                result.textContent = '❌ ' + (err && err.message ? err.message : 'خطأ في الاتصال');
                result.style.color = '#ef4444';
                button.disabled = false;
            });
        }
        document.getElementById('so-exec-send-now-btn').addEventListener('click', function(){
            soExecAjax('so_send_exec_report_ajax', this, '⏳ جارٍ البناء والإرسال...');
        });
        const soExecGenerateBtn = document.getElementById('so-exec-generate-ai-btn');
        if (soExecGenerateBtn) {
            soExecGenerateBtn.addEventListener('click', function(){
                const btn = this;
                const result = document.getElementById('so-exec-send-result');
                btn.disabled = true;
                result.textContent = '⏳ جارٍ توليد التقرير عبر وكيل الذكاء الاصطناعي المتاح...';
                result.style.color = '#7aa0c4';
                const fd = new FormData();
                fd.append('action', 'so_exec_generate_report_ajax');
                fd.append('nonce', '<?php echo wp_create_nonce('so_exec_report_ajax'); ?>');
                fetch('<?php echo esc_js(admin_url('admin-ajax.php')); ?>', {method:'POST', body:fd, credentials:'same-origin'})
                    .then(r=>r.json())
                    .then(j=>{
                        if (j && j.success && j.data) {
                            const holder = document.getElementById('so-exec-brief-print');
                            if (holder && j.data.report_html) {
                                const tmp = document.createElement('div');
                                tmp.innerHTML = j.data.report_html;
                                const next = tmp.querySelector('#so-exec-brief-print');
                                if (next) holder.replaceWith(next);
                            }
                            const textArea = document.getElementById('so-exec-report-text');
                            if (textArea) textArea.value = j.data.report_text || '';
                            const htmlArea = document.getElementById('so-exec-report-html');
                            if (htmlArea && j.data.report_html) htmlArea.value = j.data.report_html;
                            result.textContent = '✅ ' + (j.data.message || 'تم توليد التقرير');
                            result.style.color = '#22c55e';
                        } else {
                            result.textContent = '❌ ' + (j && j.data && j.data.message ? j.data.message : 'فشل التوليد');
                            result.style.color = '#ef4444';
                        }
                    })
                    .catch((err)=>{
                        result.textContent = '❌ ' + (err && err.message ? err.message : 'خطأ في الاتصال');
                        result.style.color = '#ef4444';
                    })
                    .finally(()=>{ btn.disabled = false; });
            });
        }
        document.getElementById('so-exec-send-word-btn').addEventListener('click', function(){
            soExecAjax('so_send_exec_report_word_ajax', this, '⏳ جارٍ إنشاء ملف Word وإرساله...');
        });
        function soExecLoadScript(src){
            return new Promise(function(resolve,reject){
                const existing = document.querySelector('script[data-so-src="'+src+'"]');
                if (existing) {
                    if (window.html2pdf) return resolve();
                    existing.addEventListener('load', function(){ resolve(); }, {once:true});
                    existing.addEventListener('error', function(){ reject(new Error('failed to load script')); }, {once:true});
                    return;
                }
                const s = document.createElement('script');
                s.src = src;
                s.async = true;
                s.dataset.soSrc = src;
                s.onload = function(){ resolve(); };
                s.onerror = function(){ reject(new Error('failed to load script')); };
                document.head.appendChild(s);
            });
        }
        async function soExecBuildPdfDataUri() {
            if (!window.html2pdf) {
                await soExecLoadScript('https://cdnjs.cloudflare.com/ajax/libs/html2pdf.js/0.10.1/html2pdf.bundle.min.js');
            }
            const el = document.getElementById('so-exec-brief-print');
            if (!el) throw new Error('report element not found');
            const worker = window.html2pdf().set({
                margin: [8,8,8,8],
                filename: 'beiruttime-executive-brief.pdf',
                image: { type: 'jpeg', quality: 0.98 },
                html2canvas: { scale: 2, useCORS: true, backgroundColor: '#ffffff' },
                jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' },
                pagebreak: { mode: ['css', 'legacy'] }
            }).from(el).toPdf();
            const pdf = await worker.get('pdf');
            return pdf.output('datauristring');
        }
        const soExecSendPdfBtn = document.getElementById('so-exec-send-pdf-btn');
        if (soExecSendPdfBtn) {
            soExecSendPdfBtn.addEventListener('click', async function(){
                const btn = this;
                const result = document.getElementById('so-exec-send-result');
                btn.disabled = true;
                result.textContent = '⏳ جارٍ توليد PDF وإرساله...';
                result.style.color = '#7aa0c4';
                try {
                    const pdfData = await soExecBuildPdfDataUri();
                    const fd = new FormData();
                    fd.append('action', 'so_send_exec_report_pdf_ajax');
                    fd.append('nonce', '<?php echo wp_create_nonce('so_exec_report_ajax'); ?>');
                    fd.append('pdf_base64', pdfData);
                    const res = await fetch('<?php echo esc_js(admin_url('admin-ajax.php')); ?>', {method:'POST', body:fd, credentials:'same-origin'});
                    const text = await res.text();
                    let j = null;
                    try { j = JSON.parse(text); } catch(e) {
                        const trimmed = String(text || '').trim();
                        const start = trimmed.indexOf('{');
                        if (start >= 0) {
                            try { j = JSON.parse(trimmed.slice(start)); } catch(e2) {}
                        }
                    }
                    if (j && j.success) {
                        result.textContent = '✅ ' + (j.data?.message || 'تم إرسال PDF بنجاح');
                        result.style.color = '#22c55e';
                    } else {
                        result.textContent = '❌ ' + ((j && j.data && j.data.message) ? j.data.message : (text ? text.slice(0, 220) : 'فشل إرسال PDF'));
                        result.style.color = '#ef4444';
                    }
                } catch (err) {
                    result.textContent = '❌ ' + (err && err.message ? err.message : 'فشل توليد PDF');
                    result.style.color = '#ef4444';
                } finally {
                    btn.disabled = false;
                }
            });
        }
        function soExecBuildStandaloneDoc() {
            const htmlEl = document.getElementById('so-exec-report-html');
            const previewHtml = htmlEl ? htmlEl.value : '';
            const style = `
                <style>
                body{background:#fff;margin:0;padding:24px;font-family:'Segoe UI',Tahoma,sans-serif;color:#0f172a}
                .so-exec-brief-print{background:#fff;color:#0f172a}
                .so-exec-classification-bar{display:flex;justify-content:space-between;gap:12px;align-items:center;margin-bottom:16px;padding-bottom:12px;border-bottom:1px dashed #cbd5e1;flex-wrap:wrap}
                .so-exec-classification{display:inline-flex;align-items:center;padding:7px 12px;border-radius:999px;background:#7f1d1d;color:#fff7ed;font-size:10px;font-weight:800;letter-spacing:.08em}
                .so-exec-classification-en{background:#0f172a;color:#e2e8f0;direction:ltr}
                .so-exec-brief-head{display:flex;justify-content:space-between;gap:18px;align-items:flex-start;border-bottom:2px solid #e2e8f0;padding-bottom:18px;margin-bottom:18px}
                .so-exec-kicker{font-size:12px;font-weight:800;letter-spacing:.14em;text-transform:uppercase;color:#64748b;margin-bottom:8px}
                .so-exec-subtitle{font-size:12px;font-weight:700;letter-spacing:.08em;text-transform:uppercase;color:#1d4ed8;margin-bottom:8px}
                .so-exec-brief-head h1{margin:0;font-size:24px;line-height:1.2;color:#0f172a}
