                .so-exec-threat{min-width:180px;background:#fff1f2;border:1px solid #fecdd3;color:#9f1239;border-radius:16px;padding:14px 16px;text-align:center}
                .so-exec-threat-label{display:block;font-size:12px;color:#be123c;margin-bottom:6px}
                .so-exec-threat strong{display:block;font-size:20px;line-height:1.15}
                .so-exec-threat span:last-child{display:block;margin-top:6px;font-size:13px}
                .so-exec-summary-box,.so-exec-card{background:#fff;border:1px solid #e2e8f0;border-radius:16px;padding:18px;margin-bottom:14px}
                .so-exec-card-accent{background:linear-gradient(180deg,#fff 0%,#f8fbff 100%);border-top:4px solid #2563eb}
                .so-exec-english-box{background:linear-gradient(135deg,#0f172a 0%,#1e293b 100%);border:1px solid #1e3a5f;border-radius:16px;padding:18px;margin-bottom:18px;color:#e2e8f0}
                .so-exec-english-head{display:flex;justify-content:space-between;gap:12px;align-items:center;margin-bottom:12px;flex-wrap:wrap}
                .so-exec-english-head strong{font-size:15px;letter-spacing:.04em;text-transform:uppercase}
                .so-exec-english-head span{font-size:12px;color:#93c5fd}
                .so-exec-summary-box h3,.so-exec-card h3{margin:0 0 12px;font-size:17px;color:#0f172a}
                .so-exec-summary-box p{margin:0 0 10px;line-height:1.9;font-size:15px}
                .so-exec-summary-box ul,.so-exec-bullets{margin:0;padding-right:18px}
                .so-exec-summary-box li,.so-exec-bullets li{margin:0 0 8px;line-height:1.8}
                .so-exec-bullets-english{padding-right:0;padding-left:18px;direction:ltr}
                .so-exec-bullets-english li{color:#e2e8f0}
                .so-exec-kpis-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:12px;margin-bottom:18px}
                .so-exec-kpi{background:#0f172a;color:#f8fafc;border-radius:16px;padding:16px;text-align:center}
                .so-exec-kpi span{display:block;font-size:12px;color:#cbd5e1;margin-bottom:8px}
                .so-exec-kpi strong{display:block;font-size:24px;line-height:1}
                .so-exec-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:14px;margin-bottom:14px}
                .so-exec-grid-wide{grid-template-columns:1.2fr 1fr}
                .so-exec-major-event{font-size:18px;line-height:1.8;font-weight:700;margin:0 0 8px}
                .so-exec-minor{font-size:13px;color:#64748b}
                .so-exec-stat-list{list-style:none;margin:0;padding:0}
                .so-exec-stat-list li{display:flex;justify-content:space-between;gap:14px;padding:10px 0;border-bottom:1px solid #eef2f7}
                .so-exec-stat-list li:last-child{border-bottom:0}
                .so-exec-footer{margin-top:20px;padding-top:12px;border-top:1px solid #e2e8f0;color:#64748b;font-size:12px;text-align:left;direction:ltr}
                </style>`;
            return '<!doctype html><html dir=\"rtl\" lang=\"ar\"><head><meta charset=\"utf-8\"><title>Executive Brief</title>' + style + '</head><body>' + previewHtml + '</body></html>';
        }
        function soExecOpenStandalone(autoprint) {
            const w = window.open('', '_blank', 'width=1100,height=900');
            if (!w) return;
            w.document.open();
            w.document.write(soExecBuildStandaloneDoc());
            w.document.close();
            if (autoprint) {
                w.onload = function(){ w.focus(); w.print(); };
            }
        }
        document.getElementById('so-exec-print-btn').addEventListener('click', function(){ soExecOpenStandalone(true); });
        document.getElementById('so-exec-pdf-btn').addEventListener('click', function(){ soExecOpenStandalone(false); });
        document.getElementById('so-exec-word-btn').addEventListener('click', function(){
            const blob = new Blob([soExecBuildStandaloneDoc()], {type:'application/msword'});
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = 'beiruttime-executive-brief.doc';
            document.body.appendChild(a);
            a.click();
            a.remove();
            setTimeout(function(){
setTimeout(()=>{try{hideOuterPageTitle&&hideOuterPageTitle();}catch(e){}},50); URL.revokeObjectURL(url); }, 1000);
        });
        document.getElementById('so-exec-copy-btn').addEventListener('click', function(){
            const el = document.getElementById('so-exec-report-text');
            if (!el) return;
            el.select();
            el.setSelectionRange(0, el.value.length);
            document.execCommand('copy');
            this.textContent = 'تم النسخ';
            const btn = this;
            setTimeout(function(){
setTimeout(()=>{try{hideOuterPageTitle&&hideOuterPageTitle();}catch(e){}},50); btn.textContent = 'نسخ النص التنفيذي'; }, 1400);
        });
        </script>
        <?php self::admin_wrap_close();
    }

