        <script>
        function updateFontColors(){
            <?php foreach ($fc_defs as $opt => $cfg): ?>
            const v_<?php echo str_replace('-','_',esc_js($opt)); ?>=document.querySelector('[name="<?php echo esc_js($opt); ?>"]').value;
            <?php endforeach; ?>
            document.getElementById('fc-prev-heading').style.color=v_so_text_color_heading;
            document.getElementById('fc-prev-body').style.color=v_so_text_color_body;
            document.getElementById('fc-prev-accent').style.color=v_so_text_color_accent;
            document.getElementById('fc-prev-muted').style.color=v_so_text_color_muted;
            document.getElementById('fc-prev-score').style.color=v_so_text_color_score;
        }
        </script>
        <script>
        document.querySelectorAll('input[type="color"]').forEach(function(picker){
            picker.addEventListener('input', function(){
                const id = this.name === 'so_custom_primary_color' ? 'primary-hex' : 'bg-hex';
                document.getElementById(id).value = this.value;
                updateFontPreview();
            });
        });
        document.getElementById('font-select').addEventListener('change', function(){
            const row = document.getElementById('custom-font-row');
            if(this.value==='custom'){row.style.display='flex';}else{row.style.display='none'; updateFontPreview(this.value);}
        });
        function updateFontPreview(fontName){
            fontName = fontName || document.getElementById('font-select').value;
