public static function ajax_duplicate_cleanup_batch() {
    if (!current_user_can('manage_options')) wp_send_json_error(['message' => 'forbidden'], 403);
    check_ajax_referer('so_ajax_v13', 'nonce');

    global $wpdb;
    $table = $wpdb->prefix . 'so_news_events';

    $batch = isset($_POST['batch']) ? max(5, min(2000, intval($_POST['batch']))) : 10;
    $reset = !empty($_POST['reset']);
    $cursor = (int) get_option('so_duplicate_cleanup_cursor', 0);

    if ($reset) {
        $cursor = 0;
        update_option('so_duplicate_cleanup_cursor', 0, false);
        update_option('so_duplicate_cleanup_seen', [], false);
    }

    $total = (int) $wpdb->get_var("SELECT COUNT(*) FROM {$table}");
    if ($cursor > 0) {
        $rows = $wpdb->get_results($wpdb->prepare(
            "SELECT id,title,actor_v2,region,intel_type,event_timestamp,title_fingerprint,image_url
             FROM {$table}
             WHERE id < %d
             ORDER BY id DESC
             LIMIT %d",
            (int)$cursor,
            (int)$batch
        ), ARRAY_A);
    } else {
        $rows = $wpdb->get_results($wpdb->prepare(
            "SELECT id,title,actor_v2,region,intel_type,event_timestamp,title_fingerprint,image_url
             FROM {$table}
             ORDER BY id DESC
             LIMIT %d",
            (int)$batch
        ), ARRAY_A);
    }
    $seen = get_option('so_duplicate_cleanup_seen', []);
    if (!is_array($seen)) $seen = [];
    $delete_ids = [];
    $scanned = 0;
    $last_id = 0;

    foreach ($rows as $row) {
        $scanned++;
        $last_id = (int)($row['id'] ?? 0);
        $title = (string)($row['title'] ?? '');
        $actor = (string)($row['actor_v2'] ?? '');
        $region = (string)($row['region'] ?? '');
        $intel = (string)($row['intel_type'] ?? '');
        $tfp = (string)($row['title_fingerprint'] ?? '');
        if ($tfp === '') $tfp = so_build_title_fingerprint($title);
        $sig = so_duplicate_candidate_signature($title, $actor, $region, $intel);
        $bucket = floor(((int)$row['event_timestamp']) / 14400);
        $image = trim((string)($row['image_url'] ?? ''));
        $key = ($tfp ?: $sig) . '|' . $bucket;

        $is_dup = false;
        if ($image !== '' && isset($seen['img:' . $image])) {
            $is_dup = true;
        } elseif (isset($seen[$key])) {
            $is_dup = true;
        } else {
            foreach ($seen as $prevKey => $prev) {
                if (!is_array($prev) || empty($prev['title'])) continue;
                if (($prev['region'] ?? '') !== $region) continue;
                $a = so_normalize_title_for_dedupe($title);
                $b = so_normalize_title_for_dedupe($prev['title']);
                similar_text($a, $b, $sim);
                if ($sim >= 92) { $is_dup = true; break; }
            }
        }

        if ($is_dup) {
            $delete_ids[] = (int)$row['id'];
            continue;
        }

        $seen[$key] = ['title' => $title, 'region' => $region, 'actor' => $actor];
        if ($image !== '') $seen['img:' . $image] = ['title' => $title, 'region' => $region, 'actor' => $actor];
    }

    if (!empty($delete_ids)) {
        $in = implode(',', array_map('intval', $delete_ids));
        $wpdb->query("DELETE FROM {$table} WHERE id IN ({$in})");
    }

    // keep seen bounded
    if (count($seen) > 4000) {
        $seen = array_slice($seen, -4000);
    }

    $next_cursor = !empty($rows) ? $last_id : 0;
    $prev_progress = get_option('so_duplicate_cleanup_progress', []);
    $processed_before = (!$reset && is_array($prev_progress)) ? (int)($prev_progress['processed'] ?? 0) : 0;
    $processed_now = $processed_before + count($rows);
    $done = empty($rows) || count($rows) < $batch || $next_cursor <= 0;

    update_option('so_duplicate_cleanup_cursor', $done ? 0 : $next_cursor, false);
    update_option('so_duplicate_cleanup_seen', $done ? [] : $seen, false);

    $deleted_now = count($delete_ids);
    $progress = get_option('so_duplicate_cleanup_progress', []);
    if (!is_array($progress) || $reset) {
        $progress = ['deleted_total' => 0, 'processed' => 0];
    }
    $progress['time'] = time();
    $progress['batch'] = $batch;
    $progress['processed'] = min($total, $processed_now);
    $progress['total'] = $total;
    $progress['percent'] = $total > 0 ? (int) round((min($total, $processed_now) / $total) * 100) : 100;
    $progress['deleted_now'] = $deleted_now;
    $progress['deleted_total'] = (int)($progress['deleted_total'] ?? 0) + $deleted_now;
    $progress['done'] = $done ? 1 : 0;
    $progress['running'] = $done ? 0 : 1;
    $progress['next_cursor'] = $done ? 0 : $next_cursor;
    update_option('so_duplicate_cleanup_progress', $progress, false);

    wp_send_json_success($progress);
}

public static function ajax_duplicate_cleanup_reset() {
    if (!current_user_can('manage_options')) wp_send_json_error(['message' => 'forbidden'], 403);
    check_ajax_referer('so_ajax_v13', 'nonce');
    global $wpdb;
    $table = $wpdb->prefix . 'so_news_events';
    $total = (int) $wpdb->get_var("SELECT COUNT(*) FROM {$table}");
    update_option('so_duplicate_cleanup_cursor', 0, false);
    update_option('so_duplicate_cleanup_seen', [], false);
    update_option('so_duplicate_cleanup_progress', [
        'time' => time(),
        'batch' => 0,
        'processed' => 0,
        'total' => $total,
        'percent' => 0,
        'deleted_now' => 0,
        'deleted_total' => 0,
        'done' => 0,
        'running' => 0,
        'next_cursor' => 0,
    ], false);
    wp_send_json_success(['reset' => 1, 'total' => $total]);
}



