    private static function archive_export_columns(): array {
        return ['id','title','link','source_name','source_color','intel_type','tactical_level','region','actor_v2','score','status','event_timestamp','war_data','field_data','weapon_v2','target_v2','context_actor','intent','title_fingerprint','hybrid_layers','image_url','agency_loc'];
    }

    public static function prepare_archive_event_export(array $row): array {
        $clean = [];
        foreach (self::archive_export_columns() as $key) {
            $clean[$key] = $row[$key] ?? null;
        }
        $clean['title'] = sanitize_text_field((string)($clean['title'] ?? ''));
        $clean['link'] = esc_url_raw((string)($clean['link'] ?? ''));
        $clean['source_name'] = sanitize_text_field((string)($clean['source_name'] ?? ''));
        $clean['source_color'] = sanitize_hex_color((string)($clean['source_color'] ?? '')) ?: '#1d4ed8';
        $clean['status'] = sanitize_key((string)($clean['status'] ?? 'published')) ?: 'published';
        $clean['title_fingerprint'] = !empty($clean['title_fingerprint']) ? sanitize_text_field((string)$clean['title_fingerprint']) : (function_exists('so_build_title_fingerprint') ? so_build_title_fingerprint((string)$clean['title']) : md5((string)$clean['title']));
        return $clean;
    }

    public static function import_archive_events(array $events): array {
        global $wpdb;
        $table = $wpdb->prefix . 'so_news_events';
        $inserted = 0; $updated = 0; $skipped = 0;
        foreach ($events as $event) {
            if (!is_array($event)) { $skipped++; continue; }
            $title = sanitize_text_field((string)($event['title'] ?? ''));
            if ($title === '') { $skipped++; continue; }
            $fingerprint = sanitize_text_field((string)($event['title_fingerprint'] ?? (function_exists('so_build_title_fingerprint') ? so_build_title_fingerprint($title) : md5($title))));
            $link = esc_url_raw((string)($event['link'] ?? ''));
            $existing_id = 0;
            if ($fingerprint !== '') {
                $existing_id = (int)$wpdb->get_var($wpdb->prepare("SELECT id FROM {$table} WHERE title_fingerprint = %s ORDER BY id DESC LIMIT 1", $fingerprint));
            }
            if (!$existing_id && $link !== '') {
                $existing_id = (int)$wpdb->get_var($wpdb->prepare("SELECT id FROM {$table} WHERE link = %s ORDER BY id DESC LIMIT 1", $link));
            }
            $payload = [
                'title' => $title,
                'link' => $link,
                'source_name' => sanitize_text_field((string)($event['source_name'] ?? 'مستورد')),
                'source_color' => sanitize_hex_color((string)($event['source_color'] ?? '')) ?: '#1d4ed8',
                'intel_type' => sanitize_text_field((string)($event['intel_type'] ?? 'عام')),
                'tactical_level' => sanitize_text_field((string)($event['tactical_level'] ?? 'عملياتي')),
                'region' => sanitize_text_field((string)($event['region'] ?? '')),
                'actor_v2' => sanitize_text_field((string)($event['actor_v2'] ?? 'فاعل غير محسوم')),
                'score' => min(300, max(0, (int)($event['score'] ?? 0))),
                'status' => sanitize_key((string)($event['status'] ?? 'published')) ?: 'published',
                'event_timestamp' => max(0, (int)($event['event_timestamp'] ?? time())),
                'war_data' => wp_json_encode(json_decode((string)($event['war_data'] ?? '{}'), true) ?: [], JSON_UNESCAPED_UNICODE),
                'field_data' => wp_json_encode(json_decode((string)($event['field_data'] ?? '{}'), true) ?: [], JSON_UNESCAPED_UNICODE),
                'weapon_v2' => sanitize_text_field((string)($event['weapon_v2'] ?? '')),
                'target_v2' => sanitize_text_field((string)($event['target_v2'] ?? '')),
                'context_actor' => sanitize_text_field((string)($event['context_actor'] ?? '')),
                'intent' => sanitize_text_field((string)($event['intent'] ?? '')),
                'title_fingerprint' => $fingerprint,
                'hybrid_layers' => wp_json_encode(json_decode((string)($event['hybrid_layers'] ?? '[]'), true) ?: [], JSON_UNESCAPED_UNICODE),
                'image_url' => esc_url_raw((string)($event['image_url'] ?? '')),
                'agency_loc' => sanitize_text_field((string)($event['agency_loc'] ?? '')),
            ];
            if ($existing_id > 0) {
                $ok = $wpdb->update($table, $payload, ['id' => $existing_id]);
                if ($ok !== false) $updated++; else $skipped++;
            } else {
                $ok = $wpdb->insert($table, $payload);
                if ($ok) $inserted++; else $skipped++;
            }
        }
        return ['inserted' => $inserted, 'updated' => $updated, 'skipped' => $skipped];
    }

