            <div class="so-io-card" id="so-archive-reanalyze-card">
                <h3>🧠 إعادة تقييم الأرشيف الحالي (مجزأة وآمنة)</h3>
                <p>تُطبّق قواعد القرار الموحّد الجديدة على السجل القديم كله على دفعات AJAX صغيرة، مع احترام الأخبار المقفلة يدويًا وعدم تجميد الصفحة.</p>
                <div class="so-field-row" style="grid-template-columns:140px 1fr;margin-bottom:8px;">
                    <label class="so-field-label">حجم الدفعة</label>
                    <input type="number" min="25" max="500" step="25" id="so-archive-reanalyze-batch" value="100" class="so-input">
                </div>
                <div style="display:flex;gap:8px;flex-wrap:wrap;">
                    <button type="button" class="so-io-btn so-io-btn-green" id="so-archive-reanalyze-start">▶️ ابدأ / أكمل</button>
                    <button type="button" class="so-io-btn so-io-btn-blue" id="so-archive-reanalyze-reset">↺ تصفير التقدم</button>
                </div>
                <div style="margin-top:12px;background:#0f172a;border-radius:999px;height:12px;overflow:hidden;">
                    <div id="so-archive-reanalyze-bar" style="width:0%;height:12px;background:linear-gradient(90deg,#22c55e,#3b82f6);transition:width .25s ease;"></div>
                </div>
                <div id="so-archive-reanalyze-meta" class="so-io-note" style="margin-top:10px;">جاهز لإعادة تقييم الأرشيف الحالي على دفعات.</div>
            </div>
        </div>

        <script>
        (function(){
            const startBtn = document.getElementById('so-archive-reanalyze-start');
            const resetBtn = document.getElementById('so-archive-reanalyze-reset');
            const batchInput = document.getElementById('so-archive-reanalyze-batch');
            const bar = document.getElementById('so-archive-reanalyze-bar');
            const meta = document.getElementById('so-archive-reanalyze-meta');
            const dirtyStartBtn = document.getElementById('so-archive-dirty-start');
            const dirtyResetBtn = document.getElementById('so-archive-dirty-reset');
            const dirtyBatchInput = document.getElementById('so-archive-dirty-batch');
            const dirtyBar = document.getElementById('so-archive-dirty-bar');
            const dirtyMeta = document.getElementById('so-archive-dirty-meta');
            if((!startBtn || !resetBtn || !batchInput || !bar || !meta) && (!dirtyStartBtn || !dirtyResetBtn || !dirtyBatchInput || !dirtyBar || !dirtyMeta) || typeof ajaxurl === 'undefined') return;
            const nonce = <?php echo json_encode(wp_create_nonce('so_ajax_v13')); ?>;
            let running = false;
            function fmt(n){ try { return Number(n||0).toLocaleString('ar'); } catch(e){ return String(n||0); } }
            function setState(progress){
                const percent = Math.max(0, Math.min(100, parseInt(progress.percent || 0, 10) || 0));
                bar.style.width = percent + '%';
                meta.innerHTML = 'التقدّم: <strong>' + percent + '%</strong> — تمت معالجة <strong>' + fmt(progress.processed || 0) + '</strong> من أصل <strong>' + fmt(progress.total || 0) + '</strong> | آخر دفعة حدّثت <strong>' + fmt(progress.updated || 0) + '</strong> | التالي من <strong>' + fmt(progress.next_offset || 0) + '</strong>' + (progress.done ? ' — <span style=\"color:#16a34a\">اكتملت العملية</span>' : '');
            }
            function post(data){
                return fetch(ajaxurl,{
                    method:'POST',
                    headers:{'Content-Type':'application/x-www-form-urlencoded; charset=UTF-8'},
                    body:new URLSearchParams(data)
                }).then(r=>r.json());
            }
            async function run(reset){
                if(running) return;
                running = true;
                startBtn.disabled = true;
                resetBtn.disabled = true;
                startBtn.textContent = '⏳ جارٍ التنفيذ...';
                try {
                    let first = true;
                    while(true){
                        const batch = Math.max(25, Math.min(500, parseInt(batchInput.value || '100', 10) || 100));
                        const res = await post({
                            action:'so_ajax_reanalyze_batch',
                            nonce:nonce,
                            batch:String(batch),
                            reset:(reset && first) ? '1' : '0'
                        });
                        first = false;
                        if(!res || !res.success){
                            throw new Error((res && res.data && res.data.message) ? res.data.message : 'فشل تنفيذ دفعة إعادة التقييم');
                        }
                        const data = res.data || {};
                        setState(data);
                        if(data.done){
                            break;
                        }
                    }
                } catch(err){
                    meta.innerHTML = '<span style=\"color:#b91c1c\">' + String(err && err.message ? err.message : err) + '</span>';
                } finally {
                    running = false;
                    startBtn.disabled = false;
                    resetBtn.disabled = false;
                    startBtn.textContent = '▶️ ابدأ / أكمل';
                }
            }
            startBtn.addEventListener('click', function(){ run(false); });
            resetBtn.addEventListener('click', async function(){
                if(running) return;
                if(!confirm('سيتم تصفير مؤشر التقدّم فقط، ثم يمكنك بدء إعادة التقييم من جديد. هل تريد المتابعة؟')) return;
                try {
                    const res = await post({ action:'so_ajax_reanalyze_reset', nonce:nonce });
                    if(!res || !res.success) throw new Error((res && res.data && res.data.message) ? res.data.message : 'تعذر تصفير التقدّم');
                    setState({percent:0,processed:0,total:(res.data && res.data.total) || 0,updated:0,next_offset:0,done:false});
                } catch(err){
                    meta.innerHTML = '<span style=\"color:#b91c1c\">' + String(err && err.message ? err.message : err) + '</span>';
                }
            });

            function setDirtyState(progress){
                const percent = Math.max(0, Math.min(100, parseInt(progress.percent || 0, 10) || 0));
                if (dirtyBar) dirtyBar.style.width = percent + '%';
                if (dirtyMeta) dirtyMeta.innerHTML = 'التقدّم: <strong>' + percent + '%</strong> — تمت معالجة <strong>' + fmt(progress.processed || 0) + '</strong> من أصل <strong>' + fmt(progress.total || 0) + '</strong> | آخر دفعة حدّثت <strong>' + fmt(progress.updated || 0) + '</strong> | التالي من <strong>' + fmt(progress.next_offset || 0) + '</strong>' + (progress.done ? ' — <span style="color:#f59e0b">اكتملت العملية</span>' : '');
            }
            async function runDirty(reset){
                if(running) return;
                running = true;
                dirtyStartBtn.disabled = true;
                dirtyResetBtn.disabled = true;
                dirtyStartBtn.textContent = '⏳ جارٍ التنظيف...';
                try {
                    let first = true;
                    while(true){
                        const batch = Math.max(25, Math.min(300, parseInt(dirtyBatchInput.value || '100', 10) || 100));
                        const res = await post({
                            action:'so_ajax_dirty_reanalyze_batch',
                            nonce:nonce,
                            batch:String(batch),
                            reset:(reset && first) ? '1' : '0'
                        });
                        first = false;
                        if(!res || !res.success){
                            throw new Error((res && res.data && res.data.message) ? res.data.message : 'فشل تنفيذ دفعة التنظيف الموجّه');
                        }
                        const data = res.data || {};
                        setDirtyState(data);
                        if(data.done) break;
                    }
                } catch(err){
                    dirtyMeta.innerHTML = '<span style="color:#b91c1c">' + String(err && err.message ? err.message : err) + '</span>';
                } finally {
                    running = false;
                    dirtyStartBtn.disabled = false;
                    dirtyResetBtn.disabled = false;
                    dirtyStartBtn.textContent = '🧹 ابدأ التنظيف الموجّه';
                }
            }
            if (dirtyStartBtn && dirtyResetBtn && dirtyBatchInput && dirtyBar && dirtyMeta) {
                dirtyStartBtn.addEventListener('click', function(){ runDirty(false); });
                dirtyResetBtn.addEventListener('click', async function(){
                    if(running) return;
                    if(!confirm('سيتم تصفير تقدّم التنظيف الموجّه فقط. هل تريد المتابعة؟')) return;
                    try {
                        const res = await post({ action:'so_ajax_dirty_reanalyze_reset', nonce:nonce });
                        if(!res || !res.success) throw new Error((res && res.data && res.data.message) ? res.data.message : 'تعذر تصفير تقدّم التنظيف الموجّه');
                        setDirtyState({percent:0,processed:0,total:(res.data && res.data.total) || 0,updated:0,next_offset:0,done:false});
                    } catch(err){
                        dirtyMeta.innerHTML = '<span style="color:#b91c1c">' + String(err && err.message ? err.message : err) + '</span>';
                    }
                });
            }
        })();
        </script>

        <hr class="so-io-sep">

        <!-- ── إعادة زرع البنوك ── -->
        <div class="so-io-card" style="max-width:480px;">
            <h3>🔄 إعادة زرع البنوك الافتراضية</h3>
            <p>إعادة إدراج جميع الكيانات الأصلية المدمجة (117 كياناً) في البنوك. الكيانات الموجودة لا تتأثر — يُضاف فقط الناقص.</p>
            <form method="post" action="">
                <?php wp_nonce_field('so_reseed_banks_nonce'); ?>
                <button type="submit" name="so_reseed_banks" class="so-io-btn so-io-btn-orange" onclick="return confirm('إعادة زرع البنوك؟')">🌱 إعادة الزرع الآن</button>
            </form>
        </div>
        <?php
        self::admin_wrap_close();
    }
}
}

// ==========================================================================
// 24. SO_V7_Upgrade — جداول الكيانات والمواقع الجغرافية
// ==========================================================================
if (!class_exists('SO_V7_Upgrade')) {
class SO_V7_Upgrade {
    public static function maybe_upgrade() {
        $installed = get_option('so_db_version', '0');
        if (version_compare((string)$installed, '7.0.0', '<')) {
            self::create_additional_tables();
            update_option('so_db_version', SOD_VERSION);
        }
        // Always ensure entity banks are seeded (idempotent — uses edge_hash unique key)
        if (!get_option('so_entity_banks_seeded_v17', false)) {
            self::seed_entity_banks();
            update_option('so_entity_banks_seeded_v17', true);
        }
        // Ensure title_fingerprint column exists for installs upgraded through multiple versions
        global $wpdb;
        $cols = $wpdb->get_col("SHOW COLUMNS FROM {$wpdb->prefix}so_news_events");
        if (is_array($cols) && !in_array('title_fingerprint', $cols, true)) {
            $wpdb->query("ALTER TABLE {$wpdb->prefix}so_news_events ADD COLUMN title_fingerprint varchar(64) DEFAULT NULL, ADD KEY title_fp (title_fingerprint)");
        }
    }
    public static function create_additional_tables() {
        global $wpdb;
        require_once ABSPATH . 'wp-admin/includes/upgrade.php';
        // Add title_fingerprint to existing so_news_events if missing
        $cols = $wpdb->get_col("SHOW COLUMNS FROM {$wpdb->prefix}so_news_events");
        if (is_array($cols) && !in_array('title_fingerprint', $cols, true)) {
            $wpdb->query("ALTER TABLE {$wpdb->prefix}so_news_events ADD COLUMN title_fingerprint varchar(64) DEFAULT NULL, ADD KEY title_fp (title_fingerprint)");
        }
        $c = $wpdb->get_charset_collate();
        dbDelta("CREATE TABLE {$wpdb->prefix}so_entity_graph (
            id bigint(20) NOT NULL AUTO_INCREMENT,
            edge_hash varchar(64) NOT NULL,
            actor_name varchar(191) NOT NULL,
            target_name varchar(191) NOT NULL,
            region varchar(100) DEFAULT '',
            weight float DEFAULT 0,
            event_count int(11) DEFAULT 1,
            first_seen bigint(20) NOT NULL,
            last_seen bigint(20) NOT NULL,
            PRIMARY KEY (id),
            UNIQUE KEY edge_hash (edge_hash),
            KEY actor_name (actor_name),
            KEY target_name (target_name),
            KEY last_seen (last_seen)
        ) $c;");
        dbDelta("CREATE TABLE {$wpdb->prefix}so_geo_cache (
            id bigint(20) NOT NULL AUTO_INCREMENT,
            place_hash varchar(64) NOT NULL,
            place_name varchar(191) NOT NULL,
            lat decimal(10,6) DEFAULT NULL,
            lon decimal(10,6) DEFAULT NULL,
            confidence float DEFAULT 0,
            source varchar(50) DEFAULT 'seed',
            updated_at bigint(20) NOT NULL,
            PRIMARY KEY (id),
            UNIQUE KEY place_hash (place_hash),
            KEY place_name (place_name)
        ) $c;");
        self::seed_geo_cache();
        self::seed_entity_banks();
        self::rebuild_entity_graph();
    }

