            $exists = $wpdb->get_var($wpdb->prepare("SELECT id FROM $t WHERE edge_hash=%s", $hash));
            if ($exists) continue;
            $wpdb->insert($t, [
                'edge_hash'   => $hash,
                'actor_name'  => $key,
                'target_name' => $affil,
                'region'      => $details,
                'weight'      => $weight,
                'event_count' => 0,
                'first_seen'  => $ts,
                'last_seen'   => $ts,
            ]);
        }
    }
    private static function seed_geo_cache() {
        global $wpdb;
        $t = "{$wpdb->prefix}so_geo_cache";
        $seed = [
