// 25. SO_V7_Intelligence — محرك التحليل الاستخباراتي الحي
// ==========================================================================
if (!class_exists('SO_V7_Intelligence')) {
class SO_V7_Intelligence {
    private static function region_coords($label) {
        global $wpdb;
        $label=trim((string)$label); if ($label==='') return null;
        $t="{$wpdb->prefix}so_geo_cache";
        $row=$wpdb->get_row($wpdb->prepare("SELECT lat,lon,confidence FROM $t WHERE place_name=%s OR place_hash=%s LIMIT 1",$label,md5(mb_strtolower($label))),ARRAY_A);
        if ($row&&$row['lat']!==null&&$row['lon']!==null) return ['lat'=>(float)$row['lat'],'lon'=>(float)$row['lon'],'confidence'=>(float)$row['confidence']];
        return null;
    }
    public static function build_live_summary($limit=80) {
        global $wpdb;
        $events=$wpdb->get_results($wpdb->prepare("SELECT * FROM {$wpdb->prefix}so_news_events WHERE status='published' ORDER BY event_timestamp DESC LIMIT %d",$limit),ARRAY_A);
        if (empty($events)) return ['events'=>[],'meta'=>['count'=>0]];
        $rc=[];$ac=[];$xc=[];$crit=0;$vf=0;$sum=0;
        foreach ($events as $ev) {
            $sum+=(int)$ev['score'];
            if ((int)$ev['score']>=140) $crit++;
            if (!empty($ev['llm_verified'])) $vf++;
            $r=$ev['region']?:'غير محدد'; $a=so_normalize_actor_label($ev['actor_v2']?:'فاعل قيد التقييم'); $x=$ev['intel_type']?:'تكتيكي/ميداني';
            $rc[$r]=($rc[$r]??0)+1; $ac[$a]=($ac[$a]??0)+1; $xc[$x]=($xc[$x]??0)+1;
        }
        arsort($rc);arsort($ac);arsort($xc);
        return [
            'meta'=>['count'=>count($events),'average_score'=>round($sum/max(count($events),1),2),'critical_count'=>$crit,'llm_verified_count'=>$vf,'generated_at'=>time()],
            'top_regions'=>array_slice($rc,0,10,true),'top_actors'=>array_slice($ac,0,10,true),
            'strategic_axes'=>array_slice($xc,0,10,true),
            'predictive_flags'=>self::build_predictive_flags($events),
        ];
    }
    public static function build_predictive_flags($events) {
        $flags=[];$rw=[];
        foreach ($events as $ev) {
            $r=(string)($ev['region']?:'غير محدد');
            if (!isset($rw[$r])) $rw[$r]=['count'=>0,'score_sum'=>0,'max_score'=>0];
            $rw[$r]['count']+=1; $rw[$r]['score_sum']+=(int)$ev['score'];
            $rw[$r]['max_score']=max($rw[$r]['max_score'],(int)$ev['score']);
        }
        foreach ($rw as $r=>$s) {
            $avg=$s['score_sum']/max($s['count'],1);
            if ($s['count']>=6&&$avg>=120) $flags[]=['region'=>$r,'level'=>'مرتفع','signal'=>'زخم عملياتي مرتفع','avg_score'=>round($avg,2),'peak_score'=>$s['max_score'],'event_count'=>$s['count']];
            elseif ($s['count']>=3&&$avg>=80) $flags[]=['region'=>$r,'level'=>'متوسط','signal'=>'قابلية تصعيد','avg_score'=>round($avg,2),'peak_score'=>$s['max_score'],'event_count'=>$s['count']];
        }
        usort($flags,function($a,$b){$o=['مرتفع'=>2,'متوسط'=>1,'منخفض'=>0];return($o[$b['level']]<=>$o[$a['level']])?:($b['avg_score']<=>$a['avg_score']);});
        return array_slice($flags,0,12);
    }
    public static function render_brief_shortcode() {
        $s=self::build_live_summary(60);ob_start();?>
        <div class="so-v7-brief" dir="rtl" style="background:#07111f;color:#e5eefc;border:1px solid #0d2035;border-radius:18px;padding:20px;font-family:Cairo,Tahoma,sans-serif;">
            <div style="display:flex;justify-content:space-between;gap:15px;flex-wrap:wrap;align-items:center;margin-bottom:16px;">
                <div><div style="font-size:24px;font-weight:700;">⚡ الملخص الاستخباراتي الحي — V17</div><div style="color:#93c5fd;font-size:13px;">مبني على أحدث الأحداث المرصودة</div></div>
                <div style="display:flex;gap:10px;flex-wrap:wrap;">
                    <div style="background:#0d1f3c;padding:10px 14px;border-radius:14px;min-width:100px;text-align:center;"><div style="font-size:10px;color:#94a3b8;">الأحداث</div><div style="font-size:20px;font-weight:700;"><?php echo esc_html($s['meta']['count']??0);?></div></div>
                    <div style="background:#0d1f3c;padding:10px 14px;border-radius:14px;min-width:100px;text-align:center;"><div style="font-size:10px;color:#94a3b8;">متوسط الدرجة</div><div style="font-size:20px;font-weight:700;"><?php echo esc_html($s['meta']['average_score']??0);?></div></div>
                    <div style="background:#0d1f3c;padding:10px 14px;border-radius:14px;min-width:100px;text-align:center;"><div style="font-size:10px;color:#94a3b8;">حرجة</div><div style="font-size:20px;font-weight:700;color:#f87171;"><?php echo esc_html($s['meta']['critical_count']??0);?></div></div>
                </div>
            </div>
            <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:14px;">
                <div style="background:#0b1220;border:1px solid #1f2937;border-radius:12px;padding:14px;">
                    <div style="font-weight:700;margin-bottom:8px;color:#7dd3fc;">🌍 الساحات الأعلى نشاطاً</div>
                    <?php foreach(($s['top_regions']??[]) as $rg=>$cnt):?><div style="display:flex;justify-content:space-between;padding:5px 0;border-bottom:1px solid rgba(148,163,184,.1);"><span><?php echo esc_html($rg);?></span><strong><?php echo esc_html($cnt);?></strong></div><?php endforeach;?>
                </div>
                <div style="background:#0b1220;border:1px solid #1f2937;border-radius:12px;padding:14px;">
                    <div style="font-weight:700;margin-bottom:8px;color:#86efac;">🎯 الجهات الأبرز</div>
                    <?php foreach(($s['top_actors']??[]) as $ac=>$cnt):?><div style="display:flex;justify-content:space-between;padding:5px 0;border-bottom:1px solid rgba(148,163,184,.1);"><span><?php echo esc_html($ac);?></span><strong><?php echo esc_html($cnt);?></strong></div><?php endforeach;?>
                </div>
                <div style="background:#0b1220;border:1px solid #1f2937;border-radius:12px;padding:14px;">
                    <div style="font-weight:700;margin-bottom:8px;color:#fcd34d;">⚠️ إشارات تصعيد</div>
