                        <div style="padding:7px 0;border-bottom:1px solid rgba(148,163,184,.1);"><strong><?php echo esc_html($fl['region']);?></strong> — <?php echo esc_html($fl['level']);?><div style="font-size:10px;color:#94a3b8;"><?php echo esc_html($fl['signal']);?> | Avg <?php echo esc_html($fl['avg_score']);?></div></div>
                    <?php endforeach;else:?><div style="color:#94a3b8;">لا إشارات تصعيد كافية</div><?php endif;?>
