// ==========================================================================
// 26. SO_V7_API_Manager — نقاط REST API الاستخباراتية
// ==========================================================================
if (!class_exists('SO_V7_API_Manager')) {
class SO_V7_API_Manager {
    public static function init() {
        add_action('rest_api_init', [__CLASS__,'register_routes']);
    }
    public static function register_routes() {
        register_rest_route('beiruttime/v7','/summary',['methods'=>'GET','callback'=>[__CLASS__,'get_summary'],'permission_callback'=>function(){ return is_user_logged_in(); }]);
        register_rest_route('beiruttime/v7','/network',['methods'=>'GET','callback'=>[__CLASS__,'get_network'],'permission_callback'=>function(){ return is_user_logged_in(); }]);
    }
    public static function get_summary(\WP_REST_Request $req) {
        $limit=min(200,(int)($req->get_param('limit')?:80));
        return rest_ensure_response(SO_V7_Intelligence::build_live_summary($limit));
    }
    public static function get_network(\WP_REST_Request $req) {
        global $wpdb;
        $limit=min(300,(int)($req->get_param('limit')?:150));
        $edges=$wpdb->get_results($wpdb->prepare("SELECT actor_name,target_name,region,weight,event_count,last_seen FROM {$wpdb->prefix}so_entity_graph ORDER BY weight DESC,last_seen DESC LIMIT %d",$limit),ARRAY_A);
        if(empty($edges)){SO_V7_Upgrade::rebuild_entity_graph();$edges=[];}
        $nodes=[];
        foreach($edges as $e){foreach(['actor_name'=>'actor','target_name'=>'target'] as $f=>$tp){$n=(string)$e[$f];if(!$n)continue;if(!isset($nodes[$n])){$nodes[$n]=['id'=>$n,'label'=>$n,'type'=>$tp,'score'=>0,'connections'=>0];}$nodes[$n]['score']+=(float)$e['weight'];$nodes[$n]['connections']+=1;}}
        uasort($nodes,function($a,$b){return $b['score']<=>$a['score'];});
        return rest_ensure_response(['nodes'=>array_values(array_slice($nodes,0,100)),'edges'=>array_values($edges),'generated_at'=>time()]);
    }
}
}

