            function saveSeen(){try{sessionStorage.setItem(SEEN_KEY,JSON.stringify(seen));}catch(e){}}
            function isClosed(){return sessionStorage.getItem(CLOSED_KEY)==='1';}
            function markClosed(){sessionStorage.setItem(CLOSED_KEY,'1');}
            function scoreBorder(s){return s>=400?'#ef4444':s>=250?'#f59e0b':'#20324f';}
            function makeCard(e){const d=document.createElement('div');d.className='so-v11-pbi-item';d.style.borderColor=scoreBorder(e.score||0);d.innerHTML='<div class="t">'+(e.title||'')+'</div><div class="m">📍 '+(e.region||'غير محدد')+' — '+(e.actor_v2||'غير محدد')+'</div><div class="s">درجة: '+(e.score||0)+'</div>';return d;}
            function ensureBoxes(){
                if(isClosed())return[]; // user closed — do NOT recreate until next page session
                const dashes=document.querySelectorAll('[id^="pbi-dashboard-"]');
                if(!dashes.length)return[];
                const boxes=[];
                dashes.forEach((dash)=>{
                    let box=dash.querySelector('.so-v11-pbi-live-box');
                    if(box){boxes.push(box);return;}
                    box=document.createElement('aside');
                    box.className='so-v11-pbi-live-box';
                    box.innerHTML='<div class="so-v11-pbi-live-hd"><div><div class="so-v11-pbi-live-title">⚡ Live Intelligence</div><span class="so-v11-pbi-live-sub">شريط استخباري مباشر</span></div><div class="so-v11-pbi-live-ctrls"><button class="so-v11-pbi-btn so-v11-pbi-collapse">طي</button><button class="so-v11-pbi-btn so-v11-pbi-close">إغلاق</button></div></div><div class="so-v11-pbi-live-body"></div>';
                    dash.style.position='relative';
                    dash.appendChild(box);
                    box.querySelector('.so-v11-pbi-collapse').addEventListener('click',()=>box.classList.toggle('collapsed'));
                    box.querySelector('.so-v11-pbi-close').addEventListener('click',()=>{
                        box.remove();
                        markClosed(); // persists closed state for this browser session
                    });
                    boxes.push(box);
                });
                return boxes;
            }
            function poll(){
                if(isClosed())return; // skip polling entirely when closed
                const fd=new FormData();fd.append('action','so_v11_inside_pbi_snapshot');fd.append('nonce',(typeof SOD_CONFIG!=='undefined'&&SOD_CONFIG.nonce)?SOD_CONFIG.nonce:'<?php echo esc_js(wp_create_nonce(SOD_AJAX_NONCE_ACTION)); ?>');
                fetch(ajaxUrl,{method:'POST',body:fd,credentials:'same-origin'}).then(r=>r.text().then(t=>{
                    try{return JSON.parse(t);}catch(e){
                        const trimmed=String(t||'').trim();const start=trimmed.indexOf('{');
                        if(start>=0){return JSON.parse(trimmed.slice(start));}
                        throw e;
                    }
                })).then(json=>{
                    if(!json.success||!json.data||!json.data.events)return;
                    if(isClosed())return;
                    const boxes=ensureBoxes();if(!boxes.length)return;
                    let added=false;
                    json.data.events.forEach(e=>{
                        if(seen[e.id])return;
                        seen[e.id]=true;added=true;
                        boxes.forEach(box=>{
                            const body=box.querySelector('.so-v11-pbi-live-body');
                            if(!body)return;
                            body.insertBefore(makeCard(e),body.firstChild);
                            if(body.children.length>12)body.removeChild(body.lastChild);
                        });
                    });
                    if(added)saveSeen();
                }).catch(()=>{});
            }
            document.addEventListener('DOMContentLoaded',()=>{poll();setInterval(poll,45000);});
        })();
        </script>
        <?php
    }
}
}

