        </style>

        <script id="so-modern-enhancements-js">
        (function() {
            'use strict';

            // 1. تم تعطيل شاشة التحميل الافتتاحية بطلب المستخدم
            sessionStorage.setItem('so_splash_shown', '1');

            // 2. شريط تقدم علوي عند أي طلب AJAX للإضافة
            let progressBar = null;
            function showProgress() {
                if (!progressBar) {
                    progressBar = document.createElement('div');
                    progressBar.className = 'so-progress-bar';
                    document.body.appendChild(progressBar);
                }
                progressBar.style.width = '70%';
            }
            function hideProgress() {
                if (progressBar) {
                    progressBar.style.width = '100%';
                    setTimeout(() => {
                        if (progressBar) progressBar.style.width = '0%';
                    }, 200);
                }
            }
            // مراقبة fetch
            const originalFetch = window.fetch;
            window.fetch = function(...args) {
                const url = args[0];
                if (typeof url === 'string' && (url.includes('admin-ajax.php') || url.includes('so_'))) {
                    let isOsintCall = false;
                    if (args[1] && args[1].body) {
                        const bodyStr = args[1].body.toString();
                        if (bodyStr.includes('sod_') || bodyStr.includes('so_')) isOsintCall = true;
                    }
                    if (isOsintCall) showProgress();
                    return originalFetch.apply(this, args).finally(() => hideProgress());
                }
                return originalFetch.apply(this, args);
            };
            // مراقبة XMLHttpRequest
            const XHR = XMLHttpRequest.prototype;
            const originalOpen = XHR.open;
            XHR.open = function(method, url) {
                this._soUrl = url;
                return originalOpen.apply(this, arguments);
            };
            const originalSend = XHR.send;
            XHR.send = function(body) {
                if (this._soUrl && (this._soUrl.includes('admin-ajax.php') || this._soUrl.includes('so_'))) {
                    if (body && (body.includes('sod_') || body.includes('so_'))) {
                        showProgress();
                        this.addEventListener('loadend', () => hideProgress());
                    }
                }
                return originalSend.apply(this, arguments);
            };

            // 3. نظام الإشعارات (Toast)
            window.soToast = function(message, type = 'info', duration = 3000) {
                const toast = document.createElement('div');
                toast.className = 'so-toast';
                toast.style.borderLeftColor = type === 'error' ? '#ef4444' : (type === 'success' ? '#22c55e' : '#3b82f6');
                toast.innerHTML = message;
                document.body.appendChild(toast);
                setTimeout(() => toast.remove(), duration);
            };

            // 4. وضع Dark/Light مع تذكر التفضيل
            function applyTheme(theme) {
                const root = document.documentElement;
                if (theme === 'light') {
                    root.style.setProperty('--sod-bg', '#f1f5f9');
                    root.style.setProperty('--sod-tc-heading', '#0f172a');
                    root.style.setProperty('--sod-tc-body', '#1e293b');
                    root.style.setProperty('--sod-tc-accent', '#2563eb');
                    root.style.setProperty('--sod-tc-muted', '#475569');
                    document.querySelectorAll('.sod-card, .sod-kpi-card, .sod-news-card, .sod-cd-card').forEach(el => {
                        el.style.background = '#ffffff';
                        el.style.color = '#0f172a';
                    });
                } else {
                    root.style.removeProperty('--sod-bg');
                    root.style.removeProperty('--sod-tc-heading');
                    root.style.removeProperty('--sod-tc-body');
                    root.style.removeProperty('--sod-tc-accent');
                    root.style.removeProperty('--sod-tc-muted');
                    document.querySelectorAll('.sod-card, .sod-kpi-card, .sod-news-card, .sod-cd-card').forEach(el => {
                        el.style.background = '';
                        el.style.color = '';
                    });
                    location.reload();
                }
                localStorage.setItem('so_theme', theme);
            }
            function addThemeToggle() {
                if (document.querySelector('.so-dark-mode-toggle')) return;
                const target = document.querySelector('.sod-topbar, .sod-cd-header, .sod-powerbi-wrap .sod-topbar');
                if (!target) return;
                const btn = document.createElement('div');
                btn.className = 'so-dark-mode-toggle';
                btn.innerHTML = '🌙 <span style="font-size:10px;">Dark/Light</span>';
                btn.addEventListener('click', () => {
                    const current = localStorage.getItem('so_theme') || 'dark';
                    const newTheme = current === 'dark' ? 'light' : 'dark';
                    applyTheme(newTheme);
                    soToast(`تم التبديل إلى الوضع ${newTheme === 'dark' ? 'المظلم' : 'الفاتح'}`, 'success', 1500);
                });
                const container = target.querySelector('.sod-topbar-controls, .sod-cd-header-actions');
                if (container) container.appendChild(btn);
                else target.appendChild(btn);
            }
            const savedTheme = localStorage.getItem('so_theme');
            if (savedTheme === 'light') applyTheme('light');
            if (document.readyState === 'loading') {
                document.addEventListener('DOMContentLoaded', addThemeToggle);
            } else {
                addThemeToggle();
            }

            // 5. تأثير ظهور البطاقات عند التمرير
            const observer = new IntersectionObserver((entries) => {
                entries.forEach(entry => {
                    if (entry.isIntersecting) {
                        entry.target.style.opacity = '1';
                        entry.target.style.transform = 'translateY(0)';
                        observer.unobserve(entry.target);
                    }
                });
            }, { threshold: 0.1 });
            document.querySelectorAll('.sod-card, .sod-kpi-card, .sod-news-card, .sod-cd-card').forEach(el => {
                el.style.opacity = '0';
                el.style.transform = 'translateY(15px)';
                el.style.transition = 'opacity 0.4s ease, transform 0.4s ease';
                observer.observe(el);
            });

            // 6. إشعار ترحيبي أول مرة
            if (!localStorage.getItem('so_welcome_shown')) {
                setTimeout(() => {
                    soToast('✨ مرحباً بك في Beiruttime OSINT System V19.1.3 — تجربة استخباراتية عصرية', 'info', 5000);
                    localStorage.setItem('so_welcome_shown', '1');
                }, 2000);
            }

            // 7. تحسين أداء التمرير
            window.addEventListener('touchstart', function(){}, { passive: true });
            window.addEventListener('touchmove', function(){}, { passive: false });

            // 8. تأثير نبض للبيانات الحية
            setInterval(() => {
                const liveBadge = document.querySelector('.sod-live-dot, .sod-live-badge .sod-live-dot');
                if (liveBadge) {
                    liveBadge.style.animation = 'none';
                    setTimeout(() => liveBadge.style.animation = '', 10);
                }
            }, 30000);
        })();
        </script>
        <?php
    }
}
// ==========================================================================
// 26. إشعارات فورية وتنبيهات للمستخدم (Toasts + Desktop Notifications)
// ==========================================================================
if (!function_exists('so_add_live_notifications')) {
    add_action('wp_footer', 'so_add_live_notifications');
    function so_add_live_notifications() {
        if (is_admin()) return;
        // إيقاف الإشعارات في الصفحة الرئيسية - تعمل فقط في لوحة العرض المستقلة
        if (!sod_is_dashboard_route() && !sod_should_inject_frontend_ui()) return;
        ?>
        <script id="so-live-notifications">
        (function() {
            'use strict';

            let lastSeenEventId = localStorage.getItem('so_last_seen_event_id') || '';
            let lastHandledCriticalId = localStorage.getItem('so_last_handled_critical_id') || '';
            let notificationPermission = false;
            let soundEnabled = localStorage.getItem('so_sound_enabled') === 'true';

            if ('Notification' in window) {
                if (Notification.permission === 'granted') notificationPermission = true;
                else if (Notification.permission !== 'denied') {
                    document.body.addEventListener('click', function requestNotif() {
                        if (Notification.permission !== 'granted') {
                            Notification.requestPermission().then(perm => {
                                notificationPermission = perm === 'granted';
                            });
                        }
                        document.body.removeEventListener('click', requestNotif);
                    }, { once: true });
                }
            }

            window.soToast = window.soToast || function(msg, type, duration = 4000) {
                const toast = document.createElement('div');
                toast.className = 'so-toast';
                toast.style.borderLeftColor = type === 'error' ? '#ef4444' : (type === 'success' ? '#22c55e' : '#3b82f6');
                toast.innerHTML = msg;
                document.body.appendChild(toast);
                setTimeout(() => toast.remove(), duration);
            };

            function playBeep() {
                if (!soundEnabled) return;
                try {
                    const audioCtx = new (window.AudioContext || window.webkitAudioContext)();
                    const osc = audioCtx.createOscillator();
                    const gain = audioCtx.createGain();
                    osc.connect(gain);
                    gain.connect(audioCtx.destination);
                    osc.frequency.value = 880;
                    osc.type = 'sine';
                    gain.gain.setValueAtTime(0.1, audioCtx.currentTime);
                    gain.gain.exponentialRampToValueAtTime(0.0001, audioCtx.currentTime + 0.5);
                    osc.start();
                    osc.stop(audioCtx.currentTime + 0.5);
                } catch(e) { console.warn('Audio not supported'); }
            }

            function showDesktopNotification(title, body) {
                if (!notificationPermission) return;
                const notif = new Notification(title, {
                    body: body,
                    icon: 'https://cdn-icons-png.flaticon.com/512/5337/5337691.png',
                    silent: false,
                    vibrate: [200, 100, 200]
                });
                notif.onclick = () => window.focus();
                setTimeout(() => notif.close(), 8000);
            }

            function getEventId(ev) {
                return String(ev?.id || ev?.hash_id || ev?.event_timestamp || ev?.title || '');
            }

            function goToCriticalNews(ev) {
                if (!ev) return;
                const evId = getEventId(ev);
                markCriticalHandled(evId);

                const routeUrl = (window.soDisplayPageUrl || window.location.pathname || '').toString();
                const currentPath = window.location.pathname || '';
                const isOnDisplayPage = routeUrl && (currentPath === routeUrl || currentPath === routeUrl.replace(window.location.origin, ''));

                if (!isOnDisplayPage && routeUrl) {
                    const url = routeUrl + (routeUrl.indexOf('#') === -1 ? '#critical-news' : '');
                    window.location.href = url;
                    return;
                }

                const selectors = [
                    '.sod-news-card[data-event-id="' + evId + '"]',
                    'tr[data-event-id="' + evId + '"]',
                    '[data-hash-id="' + evId + '"]',
                    '[data-id="' + evId + '"]',
                    '.sod-news-card',
                    '.sod-feed-table tr'
                ];

                let target = null;
                for (const sel of selectors) {
                    target = document.querySelector(sel);
                    if (target) break;
                }

                if (target) {
                    target.scrollIntoView({ behavior: 'smooth', block: 'center' });
                    target.classList.add('so-critical-highlight');
                    setTimeout(() => target.classList.remove('so-critical-highlight'), 2500);
                } else {
                    window.location.hash = 'critical-news';
                }
            }


            function checkForNewEvents(events) {
                if (!Array.isArray(events) || !events.length) return;

                const latestEvent = events.reduce((a,b) => ((parseInt(a.event_timestamp) || 0) > (parseInt(b.event_timestamp) || 0) ? a : b), events[0]);
                const latestId = getEventId(latestEvent);

                const newEvents = [];
                if (!lastSeenEventId) {
                    lastSeenEventId = latestId;
                    localStorage.setItem('so_last_seen_event_id', lastSeenEventId);
                } else {
                    for (let i = 0; i < events.length; i++) {
                        const e = events[i];
                        const eId = getEventId(e);
                        if (eId === lastSeenEventId) break;
                        newEvents.push(e);
                    }
                    if (latestId) {
                        lastSeenEventId = latestId;
                        localStorage.setItem('so_last_seen_event_id', lastSeenEventId);
                    }
                }

                newEvents.reverse().forEach(ev => {
                    const score = parseInt(ev.score) || 0;
                    const title = ev.title || 'خبر جديد';
                    const region = ev.region || '';
                    const actor = ev.actor_v2 || ev.actor || '';
                    let msg = `📰 ${title.substring(0, 80)}${title.length > 80 ? '…' : ''}`;
                    if (region) msg += `\n📍 ${region}`;
                    if (actor) msg += `\n🎭 ${actor}`;
                    msg += `\n⚠️ درجة: ${score}`;

                    if (score >= 140) {
                        soToast(`🚨 خَبَر حَرِج! ${title.substring(0,60)}...`, 'error', 8000);
                        if (soundEnabled) playBeep();
                        showDesktopNotification('🚨 تنبيه استخباراتي حرج', title.substring(0,100));
                    } else {
                        soToast(msg, 'info', 5000);
                    }
                });

                // تم إزالة إشعار الأخبار الحرجة السفلي (Critical Banner)
                removeCriticalBanner();
            }

            const originalFetch = window.fetch;
            window.fetch = function(...args) {
                return originalFetch.apply(this, args).then(async (response) => {
                    const cloned = response.clone();
                    const url = args[0];
                    if (typeof url === 'string' && url.includes('admin-ajax.php')) {
                        try {
                            const bodyText = args[1]?.body?.toString() || '';
                            if (bodyText.includes('sod_get_dashboard_data') || bodyText.includes('sod_get_ticker_data')) {
                                const json = await cloned.json();
                                if (json.success && json.data && (json.data.events || json.data.headlines)) {
                                    checkForNewEvents(json.data.events || json.data.headlines || []);
                                }
                            }
                        } catch(e) { }
                    }
                    return response;
                });
            };

            const XHR = XMLHttpRequest.prototype;
            const originalSend = XHR.send;
            XHR.send = function(body) {
                this.addEventListener('load', () => {
                    try {
                        if (this._soUrl && this._soUrl.includes('admin-ajax.php') && this.responseText) {
                            if (body && (body.includes('sod_get_dashboard_data') || body.includes('sod_get_ticker_data'))) {
                                const json = JSON.parse(this.responseText);
                                if (json.success && json.data && (json.data.events || json.data.headlines)) {
                                    checkForNewEvents(json.data.events || json.data.headlines || []);
                                }
                            }
                        }
                    } catch(e) {}
                });
                return originalSend.apply(this, arguments);
            };

            function addSoundToggle() {
                const target = document.querySelector('.sod-topbar, .sod-cd-header, .sod-powerbi-wrap .sod-topbar');
                if (!target) return;
                if (document.querySelector('.so-sound-toggle')) return;
                const btn = document.createElement('div');
                btn.className = 'so-dark-mode-toggle so-sound-toggle';
                btn.innerHTML = soundEnabled ? '🔊 صوت' : '🔇 صامت';
                btn.style.marginRight = '8px';
                btn.addEventListener('click', () => {
                    soundEnabled = !soundEnabled;
                    localStorage.setItem('so_sound_enabled', soundEnabled);
                    btn.innerHTML = soundEnabled ? '🔊 صوت' : '🔇 صامت';
                    soToast(`تم ${soundEnabled ? 'تفعيل' : 'إيقاف'} الصوت`, 'info', 1500);
                });
                const container = target.querySelector('.sod-topbar-controls, .sod-cd-header-actions');
                if (container) container.appendChild(btn);
                else target.appendChild(btn);
            }

            }

            setTimeout(() => {
                const fd = new FormData();
                fd.append('action', 'sod_get_ticker_data');
                fd.append('nonce', window.SOD_CONFIG?.nonce || '');
                fetch(window.SOD_CONFIG?.ajaxUrl || '/wp-admin/admin-ajax.php', {
                    method: 'POST',
                    body: fd,
                    credentials: 'same-origin'
                }).then(res => res.text().then(text => {
                    try { return JSON.parse(text); } catch(e) {
                        const trimmed = String(text || '').trim();
                        const start = trimmed.indexOf('{');
                        if (start >= 0) return JSON.parse(trimmed.slice(start));
                        throw e;
                    }
                })).then(json => {
                    const events = json?.data?.events || json?.data?.headlines || [];
                    if (events.length) {
                        const latest = events.reduce((a,b) => ((parseInt(a.event_timestamp) || 0) > (parseInt(b.event_timestamp) || 0) ? a : b), events[0]);
                        lastSeenEventId = getEventId(latest);
                        localStorage.setItem('so_last_seen_event_id', lastSeenEventId);
                        checkForNewEvents(events);
                    }
                }).catch(()=>{});
            }, 3000);
        })();
        </script>
        <?php
    }
}
