        }
        @keyframes spin { to { transform: rotate(360deg); } }
        </style>

        <script id="so-ultimate-features">
        (function() {
            'use strict';

            // ============================================================
            // 0. شاشة تحميل متقدمة (تختفي بعد تحميل الصفحة)
            // ============================================================
            // تم تعطيل شاشة التحميل الكاملة لأنها قد تسبب تعارضاً مع جنة وتؤدي إلى شاشة بيضاء على الهاتف.
            // الإضافة تعمل الآن بدون أي overlay عند فتح الصفحة.

            // ============================================================
            // 1. Toast محسّن (إشعارات منبثقة)
            // ============================================================
            window.soToast = function(message, type = 'info', duration = 3000) {
                const toast = document.createElement('div');
                toast.className = 'so-toast';
                toast.style.cssText = 'position:fixed; bottom:20px; left:20px; background:#1e293b; color:#e2e8f0; padding:10px 18px; border-radius:12px; font-size:13px; z-index:99999; backdrop-filter:blur(8px); border-left:4px solid ' + (type === 'error' ? '#ef4444' : (type === 'success' ? '#22c55e' : '#3b82f6')) + '; box-shadow:0 8px 20px rgba(0,0,0,0.3); animation: slideIn 0.3s ease;';
                toast.innerHTML = message;
                document.body.appendChild(toast);
                setTimeout(() => toast.remove(), duration);
            };
            // إضافة تعريف الحركة إذا لم تكن موجودة
            if (!document.querySelector('#so-toast-keyframes')) {
                const style = document.createElement('style');
                style.id = 'so-toast-keyframes';
                style.textContent = '@keyframes slideIn { from { opacity:0; transform:translateX(-30px); } to { opacity:1; transform:translateX(0); } }';
                document.head.appendChild(style);
            }

            // ============================================================
            // 2. إشعارات فورية عند ظهور أخبار جديدة
            // ============================================================
            let lastEventIds = new Set();
            let lastCriticalIds = new Set();
            function checkForNewEvents() {
                const newsItems = document.querySelectorAll('.sod-news-card, .sod-feed-table tbody tr, .sod-cd-feed-table tbody tr');
                if (!newsItems.length) return;
                const currentIds = [], currentCriticalIds = [];
                newsItems.forEach(item => {
                    let id = item.querySelector('a')?.href || item.innerText;
                    if (id) currentIds.push(id);
                    const scoreSpan = item.querySelector('.sod-score-badge, .nl-score, .sod-cd-score-badge');
                    let score = 0;
                    if (scoreSpan) {
                        const match = scoreSpan.innerText.match(/\d+/);
                        if (match) score = parseInt(match[0]);
                    }
                    if (score >= 140) currentCriticalIds.push(id);
                });
                const newIds = currentIds.filter(id => !lastEventIds.has(id));
                const newCritical = currentCriticalIds.filter(id => !lastCriticalIds.has(id));
                if (newIds.length > 0 && typeof soToast !== 'undefined') {
                    soToast(`📰 ${newIds.length} خبر جديد`, 'info', 3000);
                    if (newCritical.length > 0) soToast(`🚨 ${newCritical.length} حدث حرج`, 'error', 5000);
                }
                lastEventIds = new Set(currentIds);
                lastCriticalIds = new Set(currentCriticalIds);
            }
            setInterval(checkForNewEvents, 5000);
            setTimeout(checkForNewEvents, 3000);

            // ============================================================
            // 3. نيون حول البطاقات الحرجة (يضاف كلاس تلقائياً)
            // ============================================================
            function addNeonToCritical() {
                document.querySelectorAll('.sod-news-card, .sod-alert-card, .sod-cd-alert-strip').forEach(el => {
                    const isCritical = el.innerText.includes('حرج') || el.innerText.includes('140') || el.querySelector('.sod-score-badge')?.innerText >= 140;
                    if (isCritical) el.classList.add('critical');
                });
            }
            setInterval(addNeonToCritical, 3000);
            addNeonToCritical();

            // ============================================================
            // 4. عداد تنازلي للحدث التالي المتوقع (تحليل توقيت بسيط)
            // ============================================================
            function addCountdownTimer() {
                const target = document.querySelector('.sod-topbar-controls, .sod-cd-header-actions');
                if (!target || document.querySelector('.so-countdown')) return;
                const container = document.createElement('div');
                container.className = 'so-countdown';
                container.style.cssText = 'background:#0f172a; border-radius:20px; padding:4px 12px; font-size:12px; margin-left:8px; white-space:nowrap;';
                container.innerHTML = '⏳ التوقع: <span id="so-timer-val">--:--</span>';
                target.appendChild(container);
                function updateTimer() {
                    // محاكاة: نحسب متوسط الفرق بين آخر 5 أحداث ونضيفه للوقت الحالي
                    const times = Array.from(document.querySelectorAll('.sod-feed-table td:first-child, .sod-cd-feed-table td:first-child')).slice(0,10).map(td => {
                        const txt = td.innerText;
                        const match = txt.match(/\d{2}:\d{2}/);
                        if (match) {
                            const [h,m] = match[0].split(':');
                            const now = new Date();
                            let d = new Date();
                            d.setHours(parseInt(h), parseInt(m), 0);
                            if (d > now) d.setDate(d.getDate() - 1);
                            return d.getTime();
                        }
                        return 0;
                    }).filter(t => t > 0);
                    if (times.length >= 2) {
                        let diffs = [];
                        for (let i = 1; i < times.length; i++) diffs.push(times[i-1] - times[i]);
                        const avgDiff = diffs.reduce((a,b)=>a+b,0) / diffs.length;
                        const nextTime = times[0] + avgDiff;
                        const diffSec = Math.max(0, Math.floor((nextTime - Date.now()) / 1000));
                        const minutes = Math.floor(diffSec / 60);
                        const seconds = diffSec % 60;
                        const timerSpan = document.getElementById('so-timer-val');
                        if (timerSpan) timerSpan.innerText = `${minutes.toString().padStart(2,'0')}:${seconds.toString().padStart(2,'0')}`;
                    } else {
                        const timerSpan = document.getElementById('so-timer-val');
                        if (timerSpan) timerSpan.innerText = 'بيانات كافية';
                    }
                }
                setInterval(updateTimer, 1000);
                updateTimer();
            }
            setTimeout(addCountdownTimer, 2000);

            // ============================================================
            // 5. خريطة حرارية متحركة (تحاكي زحف الأحداث)
            // ============================================================
            function addAnimatedHeatmap() {
                const mapDiv = document.querySelector('.sod-map-container');
                if (!mapDiv || mapDiv.querySelector('.so-heatmap-canvas')) return;
                const canvas = document.createElement('canvas');
                canvas.className = 'so-heatmap-canvas';
                canvas.width = mapDiv.clientWidth;
                canvas.height = mapDiv.clientHeight;
                mapDiv.style.position = 'relative';
                mapDiv.appendChild(canvas);
                const ctx = canvas.getContext('2d');
                let particles = [];
                for (let i = 0; i < 30; i++) {
                    particles.push({
                        x: Math.random() * canvas.width,
                        y: Math.random() * canvas.height,
                        radius: Math.random() * 15 + 5,
                        alpha: Math.random() * 0.5,
                        speedX: (Math.random() - 0.5) * 1.5,
                        speedY: (Math.random() - 0.5) * 1.5
                    });
                }
                function animateHeatmap() {
                    if (!canvas.parentNode) return;
                    ctx.clearRect(0, 0, canvas.width, canvas.height);
                    particles.forEach(p => {
                        p.x += p.speedX;
                        p.y += p.speedY;
                        if (p.x < 0) p.x = canvas.width;
                        if (p.x > canvas.width) p.x = 0;
                        if (p.y < 0) p.y = canvas.height;
                        if (p.y > canvas.height) p.y = 0;
                        const gradient = ctx.createRadialGradient(p.x, p.y, 0, p.x, p.y, p.radius);
                        gradient.addColorStop(0, `rgba(239,68,68,${p.alpha})`);
                        gradient.addColorStop(1, 'rgba(239,68,68,0)');
                        ctx.fillStyle = gradient;
                        ctx.beginPath();
                        ctx.arc(p.x, p.y, p.radius, 0, Math.PI*2);
                        ctx.fill();
                    });
                    requestAnimationFrame(animateHeatmap);
                }
                animateHeatmap();
                window.addEventListener('resize', () => {
                    canvas.width = mapDiv.clientWidth;
                    canvas.height = mapDiv.clientHeight;
                });
            }
            setTimeout(addAnimatedHeatmap, 1000);

            // ============================================================
            // 6. زر الكرة الأرضية 3D (تم نقله من القسم 7)
            // ============================================================
            function add3DGlobe() {
                const mapContainer = document.querySelector('.sod-map-container');
                if (!mapContainer || document.querySelector('.so-globe-btn')) return;
                const btn = document.createElement('button');
                btn.innerHTML = '🌍 3D Globe';
                btn.className = 'so-globe-btn';
                btn.style.cssText = 'position:absolute; bottom:10px; right:10px; z-index:1000; background:#0f172a; border:1px solid #3b82f6; color:#fff; border-radius:8px; padding:6px 12px; cursor:pointer; font-size:12px; backdrop-filter:blur(4px);';
                btn.onclick = () => {
                    window.open('https://earth3dmap.com/?lat=33.8&lon=35.5&zoom=5', '_blank');
                    soToast('🪐 كرة أرضية ثلاثية الأبعاد - استكشف النقاط الساخنة', 'info', 4000);
                };
                mapContainer.style.position = 'relative';
                mapContainer.appendChild(btn);
            }
            setTimeout(add3DGlobe, 1500);

            // ============================================================
            // 8. تحويل النص إلى كلام (Voice Alerts) مع زر تفعيل
            // ============================================================
            let voiceEnabled = localStorage.getItem('so_voice_alerts') === 'true';
            function addVoiceButton() {
                const target = document.querySelector('.sod-topbar-controls, .sod-cd-header-actions');
                if (!target || document.querySelector('.so-voice-btn')) return;
                const btn = document.createElement('button');
                btn.className = 'so-voice-btn';
                btn.innerHTML = voiceEnabled ? '🔊 إيقاف الصوت' : '🔇 تفعيل الصوت';
                btn.style.cssText = 'background:rgba(0,0,0,0.6); border:1px solid #3b82f6; border-radius:20px; padding:4px 10px; font-size:10px; cursor:pointer; margin-left:8px;';
                btn.onclick = () => {
                    voiceEnabled = !voiceEnabled;
                    localStorage.setItem('so_voice_alerts', voiceEnabled);
                    btn.innerHTML = voiceEnabled ? '🔊 إيقاف الصوت' : '🔇 تفعيل الصوت';
                    soToast(`الصوت ${voiceEnabled ? 'مفعل' : 'معطل'}`, 'success', 1500);
                };
                target.appendChild(btn);
            }
            function speakCritical(){}
            /* تم تعطيل النطق الصوتي وأزرار الصوت الافتراضية */

            // ============================================================
            // 9. دمج ChatGPT (تحليل فوري عند النقر على الخبر)
            // ============================================================
            async function analyzeWithAI(title, content) {
                const apiKey = localStorage.getItem('so_openai_key');
                if (!apiKey) {
                    soToast('🔑 يرجى إدخال مفتاح OpenAI في الإعدادات أولاً', 'error', 5000);
                    return;
                }
                soToast('🤖 جاري تحليل الخبر بالذكاء الاصطناعي...', 'info', 3000);
                try {
                    const response = await fetch('https://api.openai.com/v1/chat/completions', {
                        method: 'POST',
                        headers: {
                            'Authorization': `Bearer ${apiKey}`,
                            'Content-Type': 'application/json'
                        },
                        body: JSON.stringify({
                            model: 'gpt-4o-mini',
                            messages: [{ role: 'user', content: `حلل هذا الخبر استخباراتياً: ${title}\n${content}` }],
                            temperature: 0.3,
                            max_tokens: 300
                        })
                    });
                    const data = await response.json();
                    const analysis = data.choices[0].message.content;
                    alert(`تحليل الذكاء الاصطناعي:\n${analysis}`);
                    soToast('✅ تم التحليل', 'success', 3000);
                } catch (err) {
                    soToast('❌ فشل الاتصال بـ OpenAI', 'error', 4000);
                }
            }
            function addAIAnalysisToNews() {
                document.querySelectorAll('.so-ai-btn').forEach(btn => btn.remove());
                return;
                document.querySelectorAll('.sod-news-card, .sod-feed-table tbody tr').forEach(card => {
                    if (card.querySelector('.so-ai-btn')) return;
                    const btn = document.createElement('button');
                    btn.innerHTML = '🤖 تحليل AI';
                    btn.className = 'so-ai-btn';
                    btn.style.cssText = 'background:#8b5cf6; border:none; border-radius:12px; padding:2px 8px; font-size:10px; margin-left:6px; cursor:pointer;';
                    const titleEl = card.querySelector('.sod-news-title, td:nth-child(6)');
                    const title = titleEl ? titleEl.innerText : '';
                    const content = card.innerText;
                    btn.onclick = (e) => {
                        e.stopPropagation();
                        analyzeWithAI(title, content);
                    };
                    const metaDiv = card.querySelector('.sod-news-card-meta, .sod-news-footer');
                    if (metaDiv) metaDiv.appendChild(btn);
                    else card.appendChild(btn);
                });
            }
            setInterval(addAIAnalysisToNews, 5000);
            setTimeout(addAIAnalysisToNews, 4000);
            addAIAnalysisToNews = function() {
                document.querySelectorAll('.so-ai-btn').forEach(btn => btn.remove());
            };

            // ============================================================
            // 10. طائرة بدون طيار (مسارات على الخريطة)
            // ============================================================
            function addDronePath() {
                const mapDiv = document.querySelector('.sod-map-container');
                if (!mapDiv || mapDiv.querySelector('.so-drone-canvas')) return;
                const canvas = document.createElement('canvas');
                canvas.className = 'so-drone-canvas';
                canvas.style.cssText = 'position:absolute; top:0; left:0; width:100%; height:100%; pointer-events:none; z-index:20;';
                canvas.width = mapDiv.clientWidth;
                canvas.height = mapDiv.clientHeight;
                mapDiv.appendChild(canvas);
                const ctx = canvas.getContext('2d');
                let t = 0;
                function drawDrone() {
                    if (!canvas.parentNode) return;
                    ctx.clearRect(0, 0, canvas.width, canvas.height);
                    const points = [
                        { x: canvas.width * 0.2, y: canvas.height * 0.3 },
                        { x: canvas.width * 0.5, y: canvas.height * 0.5 },
                        { x: canvas.width * 0.8, y: canvas.height * 0.4 },
                        { x: canvas.width * 0.6, y: canvas.height * 0.7 },
                        { x: canvas.width * 0.3, y: canvas.height * 0.6 }
                    ];
                    const index = Math.floor(t) % points.length;
                    const p = points[index];
                    ctx.beginPath();
                    ctx.arc(p.x, p.y, 6, 0, Math.PI*2);
                    ctx.fillStyle = '#ef4444';
                    ctx.fill();
                    ctx.shadowBlur = 10;
                    ctx.shadowColor = '#ef4444';
                    ctx.font = '12px monospace';
                    ctx.fillStyle = '#fff';
                    ctx.fillText('✈️', p.x-4, p.y-4);
                    t += 0.02;
                    requestAnimationFrame(drawDrone);
                }
                drawDrone();
                window.addEventListener('resize', () => {
                    canvas.width = mapDiv.clientWidth;
                    canvas.height = mapDiv.clientHeight;
                });
            }
            setTimeout(addDronePath, 2000);
        })();
        </script>
        <?php
    }
}

