add_shortcode('osint_map', function(){

    global $wpdb;

    $rows = $wpdb->get_results("
        SELECT id, title, region, actor_v2, score, event_timestamp, source_name
        FROM {$wpdb->prefix}so_news_events
        WHERE title IS NOT NULL AND title <> ''
        ORDER BY event_timestamp DESC
        LIMIT 5000
    ");

    if (!$rows) {
        return '<div class="so-map-wrap"><div class="so-map-empty">لا توجد بيانات خريطة حالياً. شغّل أولاً زر <strong>إعادة التحليل الكامل</strong> من صفحة قاعدة البيانات أو أدخل أخباراً جديدة ثم أعد تحميل الصفحة.</div></div>';
    }

    $centroids = so_lebanon_district_centroids();
    $district_stats = [];
    $points = [];
    $regional_points = [];
    $regional_stats = [];

    foreach ($rows as $r) {
        $title = wp_strip_all_tags((string)$r->title);
        $region = trim((string)$r->region);
        $actor = wp_strip_all_tags((string)$r->actor_v2);
        $score = (int)$r->score;
        $district = so_extract_lebanon_district($title, $region, $actor, (string)$r->intel_type);

        if ($district !== '' && isset($centroids[$district])) {
            if (!isset($district_stats[$district])) {
                $district_stats[$district] = ['count' => 0, 'score' => 0, 'events' => []];
            }
            $district_stats[$district]['count']++;
            $district_stats[$district]['score'] += $score;

            if (count($district_stats[$district]['events']) < 8) {
                $district_stats[$district]['events'][] = [
                    'title' => $title,
                    'actor' => $actor,
                    'score' => $score,
                    'time'  => (int)$r->event_timestamp,
                    'source'=> (string)$r->source_name,
                ];
            }

            $c = $centroids[$district];
            $points[] = [
                'lat' => (float)$c[0] + (((int)$r->id % 7) - 3) * 0.01,
                'lng' => (float)$c[1] + (((int)$r->id % 9) - 4) * 0.01,
                'district' => $district,
                'title' => $title,
                'actor' => $actor,
                'score' => $score,
                'time' => (int)$r->event_timestamp,
                'source' => (string)$r->source_name,
            ];
        } elseif ($region !== '' && $region !== 'غير محدد') {
            if (!isset($regional_stats[$region])) {
                $regional_stats[$region] = ['count' => 0, 'score' => 0];
            }
            $regional_stats[$region]['count']++;
            $regional_stats[$region]['score'] += $score;

            $c = so_region_to_coords($region);
            $regional_points[] = [
                'lat' => (float)$c[0] + (((int)$r->id % 5) - 2) * 0.05,
                'lng' => (float)$c[1] + (((int)$r->id % 7) - 3) * 0.05,
                'region' => $region,
                'title' => $title,
                'actor' => $actor,
                'score' => $score,
                'time' => (int)$r->event_timestamp,
                'source' => (string)$r->source_name,
            ];
        }
    }

    $geojson_path = plugin_dir_path(__FILE__) . 'assets/Lebanon_Level2.json';
    $geojson_url = file_exists($geojson_path)
        ? plugin_dir_url(__FILE__) . 'assets/Lebanon_Level2.json?v=' . @filemtime($geojson_path)
        : '';

    ob_start();
    ?>
    <div class="so-map-wrap so-real-map-wrap">
        <div class="so-map-head">
            <div>
                <h3>🗺️ خريطة لبنان الاستخباراتية — الأقضية</h3>
                <div class="so-map-sub">خريطة احترافية فعلية مبنية على طبقة أقضية لبنان مع تلوين حسب كثافة الأحداث وخطورتها، مع عرض أوسع للتاريخ وإظهار الأحداث الإقليمية بطبقة مستقلة.</div>
            </div>
            <div class="so-map-legend">
                <span class="legend low">منخفض</span>
                <span class="legend medium">متوسط</span>
                <span class="legend high">مرتفع</span>
                <span class="legend veryhigh">حرج</span>
            </div>
        </div>

        <div class="so-map-stage leaf-stage">
            <div class="so-map-board leaf-board">
                <div id="so-real-map"></div>
            </div>
            <div class="so-map-panel" id="so-map-panel">
                <div class="panel-title">اختر قضاء من الخريطة</div>
                <div class="panel-meta">ستظهر هنا إحصاءات القضاء، عدد الأحداث، مجموع النقاط، وآخر الأخبار المختصرة.</div>
            </div>
        </div>
    </div>

    <style>
    .so-real-map-wrap{font-family:Arial,sans-serif;background:#0f172a;color:#e5e7eb;border-radius:14px;padding:14px;overflow:hidden}
    .so-real-map-wrap .so-map-head{display:flex;justify-content:space-between;gap:12px;align-items:flex-start;margin-bottom:12px;flex-wrap:wrap}
    .so-real-map-wrap .so-map-head h3{margin:0 0 4px 0;font-size:20px}
    .so-real-map-wrap .so-map-sub{opacity:.75;font-size:13px}
    .so-real-map-wrap .so-map-legend{display:flex;gap:8px;flex-wrap:wrap}
    .so-real-map-wrap .so-map-legend .legend{padding:6px 10px;border-radius:999px;font-size:12px;font-weight:700}
    .so-real-map-wrap .legend.low{background:#14532d}
    .so-real-map-wrap .legend.medium{background:#92400e}
    .so-real-map-wrap .legend.high{background:#7f1d1d}
    .so-real-map-wrap .legend.veryhigh{background:#7e22ce}
    .so-real-map-wrap .leaf-stage{display:grid;grid-template-columns:1.45fr .9fr;gap:14px}
    @media (max-width:900px){.so-real-map-wrap .leaf-stage{grid-template-columns:1fr}}
    .so-real-map-wrap .leaf-board{position:relative;min-height:620px;border-radius:14px;border:1px solid rgba(255,255,255,.08);overflow:hidden;background:#07111f}
    #so-real-map{height:620px;width:100%}
    .so-real-map-wrap .so-map-panel{border-radius:14px;background:#111827;border:1px solid rgba(255,255,255,.08);padding:14px;min-height:620px}
    .so-real-map-wrap .panel-title{font-size:17px;font-weight:700;margin-bottom:8px}
    .so-real-map-wrap .panel-meta{font-size:13px;opacity:.78;margin-bottom:14px}
    .so-real-map-wrap .panel-kpis{display:grid;grid-template-columns:repeat(3,1fr);gap:8px;margin:10px 0 14px 0}
    .so-real-map-wrap .kpi{background:#0b1220;border-radius:12px;padding:10px;text-align:center}
    .so-real-map-wrap .kpi .n{display:block;font-size:17px;font-weight:800}
    .so-real-map-wrap .kpi .t{display:block;font-size:10px;opacity:.72}
    .so-real-map-wrap .heat-tag{display:inline-block;padding:4px 10px;border-radius:999px;font-size:12px;font-weight:700;margin-bottom:10px}
    .so-real-map-wrap .heat-low{background:#14532d}
    .so-real-map-wrap .heat-medium{background:#92400e}
    .so-real-map-wrap .heat-high{background:#7f1d1d}
    .so-real-map-wrap .heat-veryhigh{background:#7e22ce}
    .so-real-map-wrap .event-item{padding:10px 0;border-bottom:1px solid rgba(255,255,255,.08)}
    .so-real-map-wrap .event-item:last-child{border-bottom:0}
    .so-real-map-wrap .event-actor{font-size:12px;font-weight:700;color:#93c5fd}
    .so-real-map-wrap .event-title{margin:4px 0 5px 0;line-height:1.5}
    .so-real-map-wrap .event-foot{font-size:10px;opacity:.7}
    .so-map-empty{background:#111827;color:#e5e7eb;padding:16px;border-radius:12px}
    .so-leaflet-popup b{font-size:13px}
    </style>

    <script>
    (function(){
setTimeout(()=>{try{hideOuterPageTitle&&hideOuterPageTitle();}catch(e){}},50);
        const panel = document.getElementById('so-map-panel');
        if (!panel || typeof L === 'undefined') return;

        const map = L.map('so-real-map', {
            zoomControl: true,
            minZoom: 7,
            maxZoom: 12,
            preferCanvas: true
        }).setView([33.90, 35.80], 8);

        L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png', {
            attribution: 'OSINT / Carto'
        }).addTo(map);

        const districtStats = <?php echo wp_json_encode($district_stats, JSON_UNESCAPED_UNICODE); ?>;
        const points = <?php echo wp_json_encode($points, JSON_UNESCAPED_UNICODE); ?>;
        const regionalPoints = <?php echo wp_json_encode($regional_points, JSON_UNESCAPED_UNICODE); ?>;
        const regionalStats = <?php echo wp_json_encode($regional_stats, JSON_UNESCAPED_UNICODE); ?>;
        const geoUrl = <?php echo wp_json_encode($geojson_url); ?>;

        function esc(str){
            return String(str || '')
                .replace(/&/g,'&amp;')
                .replace(/</g,'&lt;')
                .replace(/>/g,'&gt;')
                .replace(/"/g,'&quot;')
                .replace(/'/g,'&#039;');
        }

        function heatLevel(score){
            if (score >= 1200) return {label:'حرج', cls:'heat-veryhigh', color:'#7e22ce'};
            if (score >= 700) return {label:'مرتفع', cls:'heat-high', color:'#ef4444'};
            if (score >= 300) return {label:'متوسط', cls:'heat-medium', color:'#f59e0b'};
            return {label:'منخفض', cls:'heat-low', color:'#22c55e'};
        }

        function renderPanel(name){
            const data = districtStats[name] || {count:0, score:0, events:[]};
            const level = heatLevel(parseInt(data.score || 0));

            let html = ''
                + '<div class="panel-title">' + esc(name) + '</div>'
                + '<span class="heat-tag ' + level.cls + '">مستوى السخونة: ' + esc(level.label) + '</span>'
                + '<div class="panel-kpis">'
                + '<div class="kpi"><span class="n">' + esc(data.count || 0) + '</span><span class="t">عدد الأحداث</span></div>'
                + '<div class="kpi"><span class="n">' + esc(data.score || 0) + '</span><span class="t">مجموع النقاط</span></div>'
                + '<div class="kpi"><span class="n">' + esc(level.label) + '</span><span class="t">التقييم</span></div>'
                + '</div>';

            if (data.events && data.events.length){
                html += '<div class="panel-meta">آخر الأحداث في هذا القضاء:</div>';
                data.events.forEach(function(ev){
                    let dt = '';
                    try { if (ev.time) dt = new Date(ev.time * 1000).toLocaleString(); } catch(e){}
                    html += '<div class="event-item">'
                        + '<div class="event-actor">' + esc(ev.actor || 'غير محدد') + '</div>'
                        + '<div class="event-title">' + esc(ev.title || '') + '</div>'
                        + '<div class="event-foot">Score: ' + esc(ev.score || 0) + (ev.source ? ' • ' + esc(ev.source) : '') + (dt ? ' • ' + esc(dt) : '') + '</div>'
                        + '</div>';
                });
            } else {
                html += '<div class="panel-meta">لا توجد أحداث مرتبطة بهذا القضاء في العينة الحالية.</div>';
            }
            panel.innerHTML = html;
        }

        fetch(geoUrl)
            .then(r => r.json())
            .then(topology => {
                if (typeof topojson === 'undefined') throw new Error('topojson_missing');
                const objKey = Object.keys(topology.objects || {})[0];
                const featureCollection = topojson.feature(topology, topology.objects[objKey]);

                const districtLayer = L.geoJSON(featureCollection, {
                    style: function(feature){
                        const ar = (feature.properties && feature.properties.Arabic_NAME_2) ? feature.properties.Arabic_NAME_2 : '';
                        const en = (feature.properties && feature.properties.NAME_2) ? feature.properties.NAME_2 : '';
                        const name = ar || en || 'غير محدد';
                        const stats = districtStats[name] || districtStats[en] || {score:0};
                        const level = heatLevel(parseInt(stats.score || 0));
                        return {
                            color: 'rgba(255,255,255,.5)',
                            weight: 1,
                            fillColor: level.color,
                            fillOpacity: (stats.score || stats.count) ? 0.45 : 0.10
                        };
                    },
                    onEachFeature: function(feature, layer){
                        const ar = (feature.properties && feature.properties.Arabic_NAME_2) ? feature.properties.Arabic_NAME_2 : '';
                        const en = (feature.properties && feature.properties.NAME_2) ? feature.properties.NAME_2 : '';
                        const gov = (feature.properties && (feature.properties.Arabic_NAME_1 || feature.properties.NAME_1)) ? (feature.properties.Arabic_NAME_1 || feature.properties.NAME_1) : '';
                        const name = ar || en || 'غير محدد';
                        const stats = districtStats[name] || districtStats[en] || {count:0, score:0, events:[]};
                        const level = heatLevel(parseInt(stats.score || 0));

                        layer.bindPopup(
                            '<div class="so-leaflet-popup"><b>' + esc(name) + '</b><br>'
                            + (gov ? esc(gov) + '<br>' : '')
                            + 'الأحداث: ' + esc(stats.count || 0) + '<br>'
                            + 'مجموع النقاط: ' + esc(stats.score || 0) + '<br>'
                            + 'المستوى: ' + esc(level.label) + '</div>'
                        );

                        layer.on('click', function(){
                            renderPanel(name);
                        });

                        layer.on('mouseover', function(){
                            layer.setStyle({weight:2, fillOpacity:0.60});
                        });
                        layer.on('mouseout', function(){
                            districtLayer.resetStyle(layer);
                        });
                    }
                }).addTo(map);

                const bounds = districtLayer.getBounds();
                if (bounds.isValid()) map.fitBounds(bounds.pad(0.03));

                // lebanon markers
                const markerLayer = L.layerGroup();
                points.forEach(function(p){
                    const level = heatLevel(parseInt(p.score || 0));
                    const marker = L.circleMarker([p.lat, p.lng], {
                        radius: 5,
                        color: '#0b1220',
                        weight: 1,
                        fillColor: level.color,
                        fillOpacity: 0.95
                    }).bindPopup(
                        '<b>' + esc(p.district || '') + '</b><br>'
                        + esc(p.title || '') + '<br>'
                        + '<small>' + esc(p.actor || '') + ' • Score: ' + esc(p.score || 0) + '</small>'
                    );
                    markerLayer.addLayer(marker);
                }).addTo(map);

                // regional markers for non-Lebanon events
                const regionalLayer = L.layerGroup();
                regionalPoints.forEach(function(p){
                    const marker = L.circleMarker([p.lat, p.lng], {
                        radius: 4,
                        color: '#0b1220',
                        weight: 1,
                        fillColor: '#38bdf8',
                        fillOpacity: 0.9
                    }).bindPopup(
                        '<b>' + esc(p.region || '') + '</b><br>'
                        + esc(p.title || '') + '<br>'
                        + '<small>' + esc(p.actor || '') + ' • Score: ' + esc(p.score || 0) + '</small>'
                    );
                    regionalLayer.addLayer(marker);
                }).addTo(map);

                // heat
                const heatData = points.map(function(p){
                    return [p.lat, p.lng, Math.max(0.15, Math.min(1, (parseInt(p.score || 0) / 200)))];
                });
                const heatLayer = L.heatLayer(heatData, {radius: 22, blur: 18, maxZoom: 10});

                L.control.layers({}, {
                    'الأقضية اللبنانية': districtLayer,
                    'الأحداث اللبنانية': markerLayer,
                    'الأحداث الإقليمية': regionalLayer,
                    'الحرارة اللبنانية': heatLayer
                }, {collapsed:false}).addTo(map);

                const firstDistrict = Object.keys(districtStats)[0];
                if (firstDistrict) renderPanel(firstDistrict);
                else panel.innerHTML = '<div class="panel-title">لا توجد أحداث لبنانية محلية كافية</div><div class="panel-meta">تم عرض الأحداث الإقليمية على الخريطة بالنقاط الزرقاء.</div>';
            })
            .catch(function(){
setTimeout(()=>{try{hideOuterPageTitle&&hideOuterPageTitle();}catch(e){}},50);
                // fallback: still show regional markers even if qadaa layer fails
                const regionalLayer = L.layerGroup();
                regionalPoints.forEach(function(p){
                    const marker = L.circleMarker([p.lat, p.lng], {
                        radius: 4,
                        color: '#0b1220',
                        weight: 1,
                        fillColor: '#38bdf8',
                        fillOpacity: 0.9
                    }).bindPopup(
                        '<b>' + esc(p.region || '') + '</b><br>'
                        + esc(p.title || '') + '<br>'
                        + '<small>' + esc(p.actor || '') + ' • Score: ' + esc(p.score || 0) + '</small>'
                    );
                    regionalLayer.addLayer(marker);
                }).addTo(map);

                const markerLayer = L.layerGroup();
                points.forEach(function(p){
                    const level = heatLevel(parseInt(p.score || 0));
                    const marker = L.circleMarker([p.lat, p.lng], {
                        radius: 5,
                        color: '#0b1220',
                        weight: 1,
                        fillColor: level.color,
                        fillOpacity: 0.95
                    }).bindPopup(
                        '<b>' + esc(p.district || '') + '</b><br>'
                        + esc(p.title || '') + '<br>'
                        + '<small>' + esc(p.actor || '') + ' • Score: ' + esc(p.score || 0) + '</small>'
                    );
                    markerLayer.addLayer(marker);
                }).addTo(map);

                L.control.layers({}, {
                    'الأحداث اللبنانية': markerLayer,
                    'الأحداث الإقليمية': regionalLayer
                }, {collapsed:false}).addTo(map);

                panel.innerHTML = '<div class="panel-title">تعذر تحميل طبقة الأقضية</div><div class="panel-meta">تم عرض الأخبار كنقاط بدل الأقضية. تأكد من وجود ملف assets/Lebanon_Level2.json داخل الإضافة.</div>';
            });
    })();
    </script>
    <?php
    return ob_get_clean();
});

