if (!function_exists('so_ai_brain')) {
function so_ai_brain() {
    return get_option('so_ai_brain', [
        'patterns' => [],
        'actors' => [],
        'weights' => [],
        'timeline' => []
    ]);
}
}

if (!function_exists('so_ai_learn')) {
function so_ai_learn($event) {
    $brain = so_ai_brain();

    $key = trim((string)($event['actor'] ?? '')) . '|' . trim((string)($event['type'] ?? ''));
    if (!isset($brain['patterns'][$key])) $brain['patterns'][$key] = 0;
    $brain['patterns'][$key]++;

    $title = so_clean_text((string)($event['title'] ?? ''));
    foreach (preg_split('/\s+/u', $title) as $w) {
        $w = trim($w);
        if (mb_strlen($w) < 4) continue;
        if (!isset($brain['actors'][$w])) $brain['actors'][$w] = [];
        $actor = trim((string)($event['actor'] ?? ''));
        if (!isset($brain['actors'][$w][$actor])) $brain['actors'][$w][$actor] = 0;
        $brain['actors'][$w][$actor]++;
    }

    $hour = !empty($event['time']) ? date('H', (int)$event['time']) : date('H');
    if (!isset($brain['timeline'][$hour])) $brain['timeline'][$hour] = 0;
    $brain['timeline'][$hour]++;

    $type = trim((string)($event['type'] ?? ''));
    if (!isset($brain['weights'][$type])) $brain['weights'][$type] = 50;
    $brain['weights'][$type] += 1;

    update_option('so_ai_brain', $brain, false);
}
}

if (!function_exists('so_ai_correct')) {
function so_ai_correct($title, $analysis) {
    $brain = so_ai_brain();
    $title = so_clean_text((string)$title);
    $votes = [];

    foreach (preg_split('/\s+/u', $title) as $w) {
        $w = trim($w);
        if ($w === '' || empty($brain['actors'][$w])) continue;
        foreach ((array)$brain['actors'][$w] as $actor => $count) {
            if (!isset($votes[$actor])) $votes[$actor] = 0;
            $votes[$actor] += (int)$count;
        }
    }

    if (!empty($votes)) {
        arsort($votes);
        $analysis['actor'] = key($votes);
    }

    return $analysis;
}
}

if (!function_exists('so_ai_score')) {
function so_ai_score($event) {
    $brain = so_ai_brain();
    $type = trim((string)($event['type'] ?? 'عام'));
    $actor = trim((string)($event['actor'] ?? ''));
    $title = so_clean_text((string)($event['title'] ?? ''));

    $base = [
        'عسكري/أمني' => 90,
        'تكتيكي/ميداني' => 70,
        'رصد/إنذار' => 55,
        'سياسي' => 20,
        'اقتصادي/لوجستي' => 25,
        'إعلامي' => 10,
        'عام' => 10
    ];

    $score = (int)($base[$type] ?? 10);
    if (isset($brain['weights'][$type])) $score += (int)round(((int)$brain['weights'][$type]) * 0.1);

    if ($actor === 'جيش العدو الإسرائيلي') $score += 50;
    if ($actor === 'المقاومة الإسلامية (حزب الله)' || $actor === 'حزب الله') $score += 35;
    if (preg_match('/شهداء|جرحى|إصابات|اغتيال|غارة|قصف|تصعيد|حرب/ui', $title)) $score += 40;

    return max(0, min(250, (int)$score));
}
}

if (!function_exists('so_predict_next')) {
function so_predict_next($events) {
    $patterns = [];
    $actors = [];
    $timeline = [];

    foreach ((array)$events as $e) {
        $actor = trim((string)($e['actor'] ?? ''));
        $type  = trim((string)($e['type'] ?? ''));
        $time  = (int)($e['time'] ?? time());

        $key = $actor . '|' . $type;
        if (!isset($patterns[$key])) $patterns[$key] = 0;
        $patterns[$key]++;

        if (!isset($actors[$actor])) $actors[$actor] = 0;
        $actors[$actor]++;

        $hour = date('H', $time);
        if (!isset($timeline[$hour])) $timeline[$hour] = 0;
        $timeline[$hour]++;
    }

    if (!empty($patterns)) arsort($patterns);
    if (!empty($actors)) arsort($actors);
    if (!empty($timeline)) arsort($timeline);

    return [
        'next_actor' => !empty($actors) ? key($actors) : 'غير محدد',
        'next_pattern' => !empty($patterns) ? key($patterns) : 'غير محدد',
        'hot_time' => !empty($timeline) ? key($timeline) : date('H'),
    ];
}
}

if (!function_exists('so_ai_report')) {
function so_ai_report($events) {
    $prediction = so_predict_next($events);
    return [
        'prediction_actor' => $prediction['next_actor'],
        'prediction_pattern' => $prediction['next_pattern'],
        'expected_time' => $prediction['hot_time']
    ];
}
}

if (!function_exists('so_basic_early_warning_engine')) {
function so_basic_early_warning_engine($events) {
    $score_total = 0;
    $military = 0;
    $recent_spike = 0;
    $now = time();

    foreach ((array)$events as $e) {
        $score_total += (int)($e['score'] ?? 0);
        if (($now - (int)($e['time'] ?? $now)) < 7200) $recent_spike++;
        $type = trim((string)($e['type'] ?? ''));
        if (in_array($type, ['عسكري/أمني','تكتيكي/ميداني','رصد/إنذار','ميداني','أمني'], true)) $military++;
    }

    $level = 'منخفض';
    $confidence = 0;
    if ($score_total > 3000 || $military > 20 || $recent_spike > 30) {
        $level = 'حرج'; $confidence = 90;
    } elseif ($score_total > 1500 || $military > 10) {
        $level = 'مرتفع'; $confidence = 70;
    } elseif ($score_total > 700) {
        $level = 'متوسط'; $confidence = 50;
    }

    return [
        'level' => $level,
        'confidence' => $confidence,
        'spike' => $recent_spike,
        'military' => $military
    ];
}
}

