if (!class_exists('SO_Instant_Alerts')) {
class SO_Instant_Alerts {
    const OPT = 'so_instant_alerts_settings';
    const LAST_ID_OPT = 'so_instant_alerts_last_id';

    public static function init() {
        add_action('admin_menu', [__CLASS__, 'admin_menu']);
        add_action('admin_init', [__CLASS__, 'register_settings']);
        add_action('init', [__CLASS__, 'maybe_schedule']);
        add_action('so_instant_alerts_cron', [__CLASS__, 'cron_check']);
        add_shortcode('osint_live_alerts', [__CLASS__, 'shortcode_live_alerts']);
        add_shortcode('osint_browser_notifier', [__CLASS__, 'shortcode_browser_notifier']);
    }

    public static function defaults() {
        return [
            'enabled' => 1,
            'telegram_enabled' => 1,
            'browser_enabled' => 1,
            'bot_token' => '',
            'chat_id' => '',
            'min_score' => 120,
            'allowed_types' => ['عسكري/أمني', 'رصد/إنذار', 'تكتيكي/ميداني'],
            'poll_minutes' => 2,
            'send_limit_per_run' => 10,
            'site_label' => get_bloginfo('name'),
        ];
    }

    public static function get_settings() {
        $saved = get_option(self::OPT, []);
        return wp_parse_args(is_array($saved) ? $saved : [], self::defaults());
    }

    public static function admin_menu() {
        add_options_page('OSINT Instant Alerts','OSINT Alerts','manage_options','so-instant-alerts',[__CLASS__, 'settings_page']);
    }

    public static function register_settings() {
        register_setting('so_instant_alerts_group', self::OPT, [__CLASS__, 'sanitize_settings']);
    }

    public static function sanitize_settings($input) {
        $d = self::defaults();
        $out = [];
        $out['enabled'] = empty($input['enabled']) ? 0 : 1;
        $out['telegram_enabled'] = empty($input['telegram_enabled']) ? 0 : 1;
        $out['browser_enabled'] = empty($input['browser_enabled']) ? 0 : 1;
        $out['bot_token'] = sanitize_text_field($input['bot_token'] ?? '');
        $out['chat_id'] = sanitize_text_field($input['chat_id'] ?? '');
        $out['min_score'] = max(0, intval($input['min_score'] ?? $d['min_score']));
        $out['poll_minutes'] = max(1, min(60, intval($input['poll_minutes'] ?? $d['poll_minutes'])));
        $out['send_limit_per_run'] = max(1, min(50, intval($input['send_limit_per_run'] ?? $d['send_limit_per_run'])));
        $out['site_label'] = sanitize_text_field($input['site_label'] ?? $d['site_label']);

        $allowed = ['عسكري/أمني', 'رصد/إنذار', 'تكتيكي/ميداني', 'سياسي', 'اقتصادي/لوجستي', 'إعلامي', 'شجب/استنكار', 'بيان', 'نووي'];
        $types = isset($input['allowed_types']) && is_array($input['allowed_types']) ? array_map('sanitize_text_field', $input['allowed_types']) : [];
        $out['allowed_types'] = array_values(array_intersect($types, $allowed));
        if (empty($out['allowed_types'])) $out['allowed_types'] = $d['allowed_types'];

        self::reschedule($out['poll_minutes']);
        return $out;
    }

    public static function maybe_schedule() {
        add_filter('cron_schedules', [__CLASS__, 'cron_schedules']);
        $s = self::get_settings();
        self::reschedule($s['poll_minutes']);
    }

    public static function cron_schedules($schedules) {
        foreach ([1,2,3,5,10,15,20,30,60] as $m) {
            $key = 'so_every_' . $m . '_minutes';
            if (!isset($schedules[$key])) {
                $schedules[$key] = [
                    'interval' => $m * 60,
                    'display' => "Every {$m} minutes",
                ];
            }
        }
        return $schedules;
    }

    public static function reschedule($minutes) {
        $hook = 'so_instant_alerts_cron';
        $target = 'so_every_' . max(1, min(60, intval($minutes))) . '_minutes';
        $next = wp_next_scheduled($hook);
        if ($next) {
            $current = wp_get_schedule($hook);
            if ($current !== $target) {
                wp_clear_scheduled_hook($hook);
                wp_schedule_event(time() + 30, $target, $hook);
            }
        } else {
            wp_schedule_event(time() + 30, $target, $hook);
        }
    }

