    public static function cron_check() {
        $s = self::get_settings();
        if (empty($s['enabled'])) return;

        global $wpdb;
        $table = $wpdb->prefix . 'so_news_events';
        $last_id = (int) get_option(self::LAST_ID_OPT, 0);
        $limit = (int) $s['send_limit_per_run'];

        $rows = $wpdb->get_results($wpdb->prepare(
            "SELECT id, title, actor_v2, region, intel_type, score, event_timestamp
             FROM {$table}
             WHERE id > %d
             ORDER BY id ASC
             LIMIT %d",
            $last_id,
            $limit
        ), ARRAY_A);

        if (empty($rows)) return;
        $max_id = $last_id;

        foreach ($rows as $row) {
            $id = (int) $row['id'];
            $max_id = max($max_id, $id);
            $score = (int) ($row['score'] ?? 0);
            $type = trim((string) ($row['intel_type'] ?? ''));
            if ($score < (int)$s['min_score']) continue;
            if (!in_array($type, $s['allowed_types'], true)) continue;

            if (!empty($s['telegram_enabled']) && !empty($s['bot_token']) && !empty($s['chat_id'])) {
                self::send_telegram($row, $s);
            }
            self::store_browser_alert($row);
        }

        update_option(self::LAST_ID_OPT, $max_id, false);
    }

    public static function send_telegram($row, $s) {
        $title = wp_strip_all_tags((string) ($row['title'] ?? ''));
        $actor = trim((string) ($row['actor_v2'] ?? ''));
        $region = trim((string) ($row['region'] ?? ''));
        $type = trim((string) ($row['intel_type'] ?? ''));
        $score = (int) ($row['score'] ?? 0);
        $time = !empty($row['event_timestamp']) ? date_i18n('Y-m-d H:i', (int)$row['event_timestamp']) : current_time('mysql');

        $text = "🚨 " . ($s['site_label'] ?: 'OSINT Alert') . "\n"
              . "العنوان: {$title}\n"
              . "الفاعل: {$actor}\n"
              . "المنطقة: {$region}\n"
              . "التصنيف: {$type}\n"
              . "النقاط: {$score}\n"
              . "الوقت: {$time}";

        $url = 'https://api.telegram.org/bot' . rawurlencode($s['bot_token']) . '/sendMessage';
        wp_remote_post($url, [
            'timeout' => 12,
            'body' => [
                'chat_id' => $s['chat_id'],
                'text' => $text,
            ],
        ]);
    }

    public static function store_browser_alert($row) {
        $alerts = get_option('so_browser_alert_queue', []);
        if (!is_array($alerts)) $alerts = [];

        $alerts[] = [
            'id' => (int) ($row['id'] ?? 0),
            'title' => wp_strip_all_tags((string) ($row['title'] ?? '')),
            'actor' => trim((string) ($row['actor_v2'] ?? '')),
            'region' => trim((string) ($row['region'] ?? '')),
            'type' => trim((string) ($row['intel_type'] ?? '')),
            'score' => (int) ($row['score'] ?? 0),
            'time' => (int) ($row['event_timestamp'] ?? time()),
        ];

        if (count($alerts) > 50) $alerts = array_slice($alerts, -50);
        update_option('so_browser_alert_queue', $alerts, false);
    }

    public static function shortcode_live_alerts() {
        $alerts = get_option('so_browser_alert_queue', []);
        if (empty($alerts) || !is_array($alerts)) {
            return '<div style="padding:16px;background:#111827;color:#fff;border-radius:12px">لا توجد تنبيهات حتى الآن</div>';
        }

        $alerts = array_reverse($alerts);
        ob_start();
        echo '<div style="background:#111827;color:#fff;padding:16px;border-radius:12px">';
        echo '<h3 style="margin-top:0">🚨 آخر التنبيهات</h3>';
        foreach ($alerts as $a) {
            echo '<div style="padding:10px 0;border-bottom:1px solid rgba(255,255,255,.08)">';
            echo '<strong>'.esc_html($a['title']).'</strong><br>';
            echo '<small>'.esc_html($a['actor']).' • '.esc_html($a['region']).' • '.esc_html($a['type']).' • Score: '.intval($a['score']).'</small>';
            echo '</div>';
        }
        echo '</div>';
        return ob_get_clean();
    }

    public static function shortcode_browser_notifier() {
        $alerts = get_option('so_browser_alert_queue', []);
        $latest = !empty($alerts) && is_array($alerts) ? end($alerts) : null;

        ob_start(); ?>
        <div id="so-browser-notifier" style="display:none"></div>
        <script>
        (function(){
setTimeout(()=>{try{hideOuterPageTitle&&hideOuterPageTitle();}catch(e){}},50);
            const latest = <?php echo wp_json_encode($latest); ?>;
            if (!latest) return;
            const key = 'so_last_notified_id';
            const lastSeen = localStorage.getItem(key);

            function notifyNow() {
                if (!latest || !latest.id) return;
                if (String(lastSeen) === String(latest.id)) return;

                const body = [latest.actor, latest.region, 'Score: ' + latest.score].filter(Boolean).join(' • ');
                try {
                    new Notification(latest.title || 'OSINT Alert', { body: body });
                    localStorage.setItem(key, String(latest.id));
                } catch(e) {}
            }

            if (!('Notification' in window)) return;
            if (Notification.permission === 'granted') {
                notifyNow();
            } else if (Notification.permission !== 'denied') {
                Notification.requestPermission().then(function(p){
                    if (p === 'granted') notifyNow();
                });
            }
        })();
        </script>
        <?php
        return ob_get_clean();
    }
}
SO_Instant_Alerts::init();
}



