if (!function_exists('so_dynamic_bank')) {
function so_dynamic_bank() {
    $brain = get_option('so_ai_brain', []);
    $learned_actors = [];
    if (!empty($brain['actors']) && is_array($brain['actors'])) {
        foreach ($brain['actors'] as $word => $actorCounts) {
            if (!is_array($actorCounts)) continue;
            arsort($actorCounts);
            $top_actor = key($actorCounts);
            if (!$top_actor || trim((string)$word) === '') continue;
            if (!isset($learned_actors[$top_actor])) $learned_actors[$top_actor] = [];
            $learned_actors[$top_actor][] = trim((string)$word);
        }
    }

    return [
        'actors' => array_merge_recursive([
            'المقاومة الإسلامية (حزب الله)' => ['حزب الله','المقاومة الإسلامية','المقاومة الاسلامية','المقاومة','مجاهدونا','مجاهدو المقاومة','الاعلام الحربي','الإعلام الحربي','مراسل المنار'],
            'جيش العدو الإسرائيلي' => ['طيران الاحتلال','قصف إسرائيلي','قصف اسرائيلي','غارة إسرائيلية','غارة اسرائيلية','عدوان إسرائيلي','عدوان اسرائيلي','مقاتلات الاحتلال','مدفعية الاحتلال','الدبابات الإسرائيلية','المسيّرات الإسرائيلية','مسيّرة إسرائيلية','مسيرة إسرائيلية'],
            'الولايات المتحدة' => ['أمريكا','امريكا','أميركا','الولايات المتحدة','واشنطن','البنتاغون'],
            'إيران' => ['إيران','ايران','طهران','الحرس الثوري','خاتم الأنبياء','خاتم الانبياء','الخامنئي','مجتبى خامنئي'],
            'لبنان' => ['لبنان','الجيش اللبناني','وزارة الصحة اللبنانية','مصدر رسمي لبناني'],
        ], $learned_actors),
        'patterns' => [
            'عسكري/أمني' => ['غارة','قصف','استهداف','مسيّرة','مسيرة','اشتباك','صاروخ','صواريخ','صلية','رشقة','صفارات','إنذار','انذار','تحليق','حربي فوق','تسلل طائرة'],
