            'أمني' => ['اعتقال','مداهمة','اغتيال','تفجير','اقتحام'],
            'اقتصادي/لوجستي' => ['نفط','مرفأ','مطار','شحن','اسعار','أسعار','اقتصاد','إمداد','امداد'],
            'إعلامي' => ['تغطية خاصة','بالفيديو','مقابلة','برنامج','حلقة','تتابعون'],
        ],
        'regions' => [
            'لبنان' => ['لبنان','بيروت','الضاحية','الجنوب','النبطية','صور','صيدا','بعلبك','الهرمل','البقاع','الخيام','مرجعيون','بنت جبيل','حاصبيا','بشامون','عرمون','سوق الغرب','سن الفيل'],
