if (!function_exists('so_detect_with_confidence')) {
function so_detect_with_confidence($text, $bank) {
    $text = so_clean_text((string)$text);
    $scores = [];
    foreach ((array)$bank as $label => $words) {
        $scores[$label] = 0;
        foreach ((array)$words as $w) {
            $w = trim((string)$w);
            if ($w === '') continue;
            if (mb_stripos($text, $w) !== false) {
                $scores[$label] += max(8, mb_strlen($w));
            }
        }
    }
    arsort($scores);
    return [
        'label' => !empty($scores) ? key($scores) : 'غير محدد',
        'confidence' => !empty($scores) ? (int) current($scores) : 0,
        'scores' => $scores,
    ];
}
}

if (!function_exists('so_fusion_analysis')) {
function so_fusion_analysis($title) {
    $bank = so_dynamic_bank();
    $title = so_clean_text((string)$title);

    $actor = so_detect_with_confidence($title, $bank['actors']);
    $type  = so_detect_with_confidence($title, $bank['patterns']);
    $region = so_detect_with_confidence($title, $bank['regions']);

    $result = [
        'title' => $title,
        'actor' => $actor['label'],
        'actor_conf' => (int)$actor['confidence'],
        'type' => $type['label'],
        'type_conf' => (int)$type['confidence'],
        'region' => $region['label'],
        'region_conf' => (int)$region['confidence'],
    ];

    // smart fallbacks
    if ($result['actor_conf'] < 10) {
        // لا تُنسب الأحداث الدبلوماسية/السياسية لإسرائيل أبداً
        $is_diplomatic = preg_match('/(مفاوضات|محادثات|وفد|اجتماع|لقاء|قمة|مؤتمر|تصريح|قال|أكد|صرح|أعلن|وزارة الخارجية|الرئيس|رئيس الوزراء)/ui', $title);
        $is_political = preg_match('/(بيان|موقف|شجب|استنكار|إدانة|رحب|حث|دعا|طالب)/ui', $title);
        $is_media_report = preg_match('/(وسائل إعلام|تقرير إعلامي|تحليل|صحيفة|قناة|رويترز|غارديان|نيويورك تايمز)/ui', $title);
        
        if (!$is_diplomatic && !$is_political && !$is_media_report) {
            // لبنان: غارات/قصف → إسرائيل (فقط مع أفعال عسكرية صريحة وبدون كلمات دبلوماسية)
            if (preg_match('/(غارة|غارات|قصف|طيران حربي|حربي فوق|اعتداء إسرائيلي|اعتداء اسرائيلي)/ui', $title)
                && !preg_match('/(قال|أكد|صرح|أعلن|أفاد|نقل عن|بحسب|وفق|ذكر|كشف)/ui', $title)) {
                $result['actor'] = 'جيش العدو الإسرائيلي';
                $result['actor_conf'] = 18;
            } elseif (preg_match('/(صاروخ|صواريخ|صلية|رشقة)/ui', $title)) {
                $result['actor'] = 'جهة مقاومة من لبنان';
                $result['actor_conf'] = 15;
            } else {
                $result['actor'] = 'فاعل سياقي غير مباشر';
            }
        } else {
            $result['actor'] = 'فاعل غير محسوم';
        }
    }

    if ($result['type_conf'] < 8) {
        $result['type'] = preg_match('/(غارة|قصف|استهداف|صواريخ|صفارات|إنذار|تحليق)/ui', $title) ? 'عسكري/أمني' : 'عام';
    }

    if ($result['region_conf'] < 8) {
        if (preg_match('/(بيروت|الضاحية|الجنوب|النبطية|صور|صيدا|بعلبك|الهرمل|الخيام|حاصبيا|مرجعيون|بنت جبيل)/ui', $title)) {
            $result['region'] = 'لبنان';
            $result['region_conf'] = 14;
        } elseif (preg_match('/(الجليل|حيفا|تل أبيب|تل ابيب|كريات شمونة|المطلة|أفيفيم|عكا|نهاريا)/ui', $title)) {
            $result['region'] = 'الأراضي المحتلة (إسرائيل)';
            $result['region_conf'] = 14;
        } else {
            $result['region'] = 'غير محدد';
        }
    }

    return $result;
}
}

if (!function_exists('so_confidence_filter')) {
function so_confidence_filter($event) {
    if (($event['actor_conf'] ?? 0) < 10) {
        $event['actor'] = 'فاعل سياقي غير مباشر';
    }
    if (($event['region_conf'] ?? 0) < 8 && empty($event['region'])) {
        $event['region'] = 'غير محدد';
    }
    return $event;
}
}

if (!function_exists('so_advanced_score')) {
function so_advanced_score($event) {
    $score = 0;
    $type = trim((string)($event['type'] ?? 'عام'));
    $title = so_clean_text((string)($event['title'] ?? ''));
    $actor = trim((string)($event['actor'] ?? ''));

    $type_weights = [
        'عسكري/أمني' => 85,
        'تكتيكي/ميداني' => 65,
        'أمني' => 60,
        'رصد/إنذار' => 45,
        'سياسي' => 20,
        'اقتصادي/لوجستي' => 25,
        'إعلامي' => 8,
        'عام' => 10,
    ];
    $score += (int)($type_weights[$type] ?? 10);

    $score += (int)round(((int)($event['actor_conf'] ?? 0)) * 0.5);
    $score += (int)round(((int)($event['type_conf'] ?? 0)) * 0.4);
    $score += (int)round(((int)($event['region_conf'] ?? 0)) * 0.3);

    if (in_array($actor, ['جيش العدو الإسرائيلي'], true)) $score += 35;
    if (in_array($actor, ['المقاومة الإسلامية (حزب الله)','حزب الله','جهة مقاومة من لبنان'], true)) $score += 25;
    if (preg_match('/(شهداء|شهيد|جرحى|إصابات|اغتيال|تصعيد|حرب|قصف|غارة|استهداف)/ui', $title)) $score += 35;
    if (preg_match('/(صفارات|إنذار|انذار)/ui', $title)) $score += 12;

    return max(0, min(300, (int)$score));
}
}

if (!function_exists('so_behavior_analysis')) {
function so_behavior_analysis($events) {
    $behavior = [];
    foreach ((array)$events as $e) {
        $actor = trim((string)($e['actor'] ?? 'غير محدد'));
        if (!isset($behavior[$actor])) {
            $behavior[$actor] = ['count' => 0, 'score' => 0, 'types' => []];
        }
        $behavior[$actor]['count']++;
        $behavior[$actor]['score'] += (int)($e['score'] ?? 0);
        $type = trim((string)($e['type'] ?? 'عام'));
        if (!isset($behavior[$actor]['types'][$type])) $behavior[$actor]['types'][$type] = 0;
        $behavior[$actor]['types'][$type]++;
    }
    uasort($behavior, function($a, $b){
        return ($b['score'] <=> $a['score']) ?: ($b['count'] <=> $a['count']);
    });
    return $behavior;
}
}

if (!function_exists('so_real_executive_report')) {
function so_real_executive_report($events) {
    $behavior = so_behavior_analysis($events);
    if (empty($behavior)) {
        return ['actor' => 'غير محدد', 'activity' => 0, 'threat' => 'منخفض', 'score' => 0];
    }

    $top_actor = array_key_first($behavior);
    $top_score = (int)$behavior[$top_actor]['score'];
    $top_count = (int)$behavior[$top_actor]['count'];

    $level = 'منخفض';
    if ($top_score > 2000) $level = 'حرج';
    elseif ($top_score > 1000) $level = 'مرتفع';
    elseif ($top_score > 500) $level = 'متوسط';

    $dominant_type = 'عام';
    if (!empty($behavior[$top_actor]['types'])) {
        arsort($behavior[$top_actor]['types']);
        $dominant_type = key($behavior[$top_actor]['types']);
    }

    return [
        'actor' => $top_actor,
        'activity' => $top_count,
        'threat' => $level,
        'score' => $top_score,
        'dominant_type' => $dominant_type
    ];
}
}

