if (!function_exists('so_ti_temporal_pressure')) {
function so_ti_temporal_pressure($events) {
    $now = time();
    $last_2h = 0;
    $last_6h = 0;
    foreach ((array)$events as $e) {
        $t = (int)($e['time'] ?? $now);
        if (($now - $t) <= 7200) $last_2h++;
        if (($now - $t) <= 21600) $last_6h++;
    }
    $ratio = $last_6h > 0 ? ($last_2h / max(1, $last_6h)) : 0;
    return [
        'last_2h' => $last_2h,
        'last_6h' => $last_6h,
        'ratio' => $ratio
    ];
}
}

