if (!function_exists('sod_hybrid_theater_alert_label')) {
    function sod_hybrid_theater_alert_label($score) {
        $score = (float)$score;
        if ($score >= 90) return 'إنذار مركب';
        if ($score >= 75) return 'قريب من الإنذار';
        if ($score >= 60) return 'مرتفع';
        if ($score >= 40) return 'متوسط';
        return 'منخفض';
    }
}

if (!function_exists('sod_compute_hybrid_theater_index')) {
    function sod_compute_hybrid_theater_index(array $events, $critical_threshold = 140) {
        $regions = [];
        foreach ($events as $e) {
            $u = function_exists('sod_get_unified_event_state') ? sod_get_unified_event_state($e) : $e;
            $region = trim((string)($u['region'] ?? ''));
            if ($region === '') $region = 'ساحة الصراع (استنتاج)';
            $score = (int)max((int)($u['threat_score'] ?? 0), (int)($u['score'] ?? 0));
            $layers = array_values(array_unique(array_filter((array)($u['hybrid_layers'] ?? []))));
            if (!isset($regions[$region])) {
                $regions[$region] = [
                    'count' => 0,
                    'sum_score' => 0,
                    'critical' => 0,
                    'layer_counts' => [],
                    'combos' => [],
                    'active_layers' => [],
                ];
            }
            $regions[$region]['count']++;
            $regions[$region]['sum_score'] += $score;
            if ($score >= $critical_threshold) $regions[$region]['critical']++;
            foreach ($layers as $layer) {
                $regions[$region]['layer_counts'][$layer] = ($regions[$region]['layer_counts'][$layer] ?? 0) + 1;
                $regions[$region]['active_layers'][$layer] = true;
            }
            if (count($layers) >= 2) {
                sort($layers);
                $combo = implode('+', array_slice($layers, 0, 2));
                $regions[$region]['combos'][$combo] = ($regions[$region]['combos'][$combo] ?? 0) + 1;
            }
        }
        $result = [];
        foreach ($regions as $region => $data) {
            $count = max(1, (int)$data['count']);
            $avg = $data['sum_score'] / $count;
            $critical_ratio = $data['critical'] / $count;
            $combo_count = array_sum($data['combos']);
            $active_count = count($data['active_layers']);
            $index = ($avg * 0.35) + (min(100, $combo_count * 10) * 0.25) + (min(100, $active_count * 10) * 0.20) + (($critical_ratio * 100) * 0.20);
            $index = max(0, min(100, round($index, 1)));
            arsort($data['combos']);
            $top_combo = (string)(array_key_first($data['combos']) ?: '');
            $result[$region] = [
                'index' => $index,
                'alert' => sod_hybrid_theater_alert_label($index),
                'events' => $count,
                'avg_score' => round($avg, 1),
                'critical_ratio' => round($critical_ratio * 100, 1),
                'active_layers' => $active_count,
                'top_combo' => $top_combo,
                'top_combo_label' => $top_combo !== '' && function_exists('sod_translate_hybrid_combo_label') ? sod_translate_hybrid_combo_label($top_combo) : $top_combo,
            ];
        }
        uasort($result, fn($a,$b) => ($b['index'] <=> $a['index']) ?: ($b['events'] <=> $a['events']));
        return $result;
    }
}
}

