/* ===== External Flexible News Ticker ===== */
if (!function_exists('so_external_ticker_get_option')) {
    function so_external_ticker_get_option(string $key, $default = '') {
        $value = get_option($key, $default);
        return $value === '' ? $default : $value;
    }
}

if (!function_exists('so_external_ticker_normalize_list')) {
    function so_external_ticker_normalize_list(string $raw): array {
        $raw = str_replace(["\r\n", "\r"], "\n", $raw);
        $parts = preg_split('/[\n,]+/u', $raw) ?: [];
        $out = [];
        foreach ($parts as $part) {
            $part = trim(wp_strip_all_tags((string)$part));
            if ($part !== '') $out[] = $part;
        }
        return array_values(array_unique($out));
    }
}

if (!function_exists('so_external_ticker_allowed_event')) {
    function so_external_ticker_allowed_event(array $row): bool {
        $min_score = max(0, (int)so_external_ticker_get_option('so_external_ticker_min_score', 0));
        if ((int)($row['score'] ?? 0) < $min_score) return false;
        $allowed_types = so_external_ticker_normalize_list((string)so_external_ticker_get_option('so_external_ticker_allowed_types', ''));
        if (!empty($allowed_types)) {
            $intel = (string)($row['intel_type'] ?? '');
            $ok = false;
            foreach ($allowed_types as $allowed) {
                if ($allowed !== '' && mb_stripos($intel, $allowed) !== false) { $ok = true; break; }
            }
            if (!$ok) return false;
        }
        return true;
    }
}

if (!function_exists('so_external_ticker_fetch_items')) {
    function so_external_ticker_fetch_items(int $limit = 20): array {
        global $wpdb;
        $table = $wpdb->prefix . 'so_news_events';
        $limit = max(1, min(60, $limit));
        $rows = $wpdb->get_results($wpdb->prepare("SELECT id,title,link,source_name,intel_type,region,actor_v2,score,event_timestamp,image_url,field_data FROM {$table} WHERE status = %s ORDER BY event_timestamp DESC LIMIT %d", 'published', $limit * 3), ARRAY_A);
        $items = [];
        foreach ((array)$rows as $row) {
            if (!so_external_ticker_allowed_event($row)) continue;
            $field = json_decode((string)($row['field_data'] ?? '{}'), true);
            $summary = '';
            if (is_array($field) && !empty($field['manual_content'])) $summary = (string)$field['manual_content'];
            if ($summary === '') $summary = (string)($row['title'] ?? '');
            $items[] = [
                'id' => (int)$row['id'],
                'title' => wp_strip_all_tags((string)$row['title']),
                'summary' => wp_trim_words(wp_strip_all_tags((string)$summary), 24, '…'),
                'source_name' => sanitize_text_field((string)($row['source_name'] ?? '')),
                'intel_type' => sanitize_text_field((string)($row['intel_type'] ?? '')),
                'region' => sanitize_text_field((string)($row['region'] ?? '')),
                'actor' => sanitize_text_field((string)($row['actor_v2'] ?? '')),
                'score' => (int)($row['score'] ?? 0),
                'event_timestamp' => (int)($row['event_timestamp'] ?? 0),
                'time_ago' => human_time_diff((int)($row['event_timestamp'] ?? time()), time()) . ' مضت',
                'image_url' => esc_url_raw((string)($row['image_url'] ?? '')),
                'source_url' => esc_url_raw((string)($row['link'] ?? '')),
                'story_url' => add_query_arg(['so_external_story' => (int)$row['id']], home_url('/')),
            ];
            if (count($items) >= $limit) break;
        }
        return $items;
    }
}

if (!function_exists('so_external_ticker_story_payload')) {
    function so_external_ticker_story_payload(int $id): array {
        global $wpdb;
        $table = $wpdb->prefix . 'so_news_events';
        $row = $wpdb->get_row($wpdb->prepare("SELECT * FROM {$table} WHERE id = %d LIMIT 1", $id), ARRAY_A);
        if (!$row) return [];
        $field = json_decode((string)($row['field_data'] ?? '{}'), true);
        $war = json_decode((string)($row['war_data'] ?? '{}'), true);
        $body = '';
        if (is_array($field) && !empty($field['manual_content'])) $body = (string)$field['manual_content'];
        if ($body === '' && is_array($war) && !empty($war['manual_content'])) $body = (string)$war['manual_content'];
        if ($body === '' && !empty($row['content'])) $body = (string)$row['content'];
        if ($body === '') $body = (string)($row['title'] ?? '');
        return [
            'id' => (int)$row['id'],
            'title' => wp_strip_all_tags((string)$row['title']),
            'summary' => wp_trim_words(wp_strip_all_tags((string)$body), 60, '…'),
            'body' => wpautop(esc_html((string)$body)),
            'source_name' => sanitize_text_field((string)($row['source_name'] ?? '')),
            'intel_type' => sanitize_text_field((string)($row['intel_type'] ?? '')),
            'region' => sanitize_text_field((string)($row['region'] ?? '')),
            'actor' => sanitize_text_field((string)($row['actor_v2'] ?? '')),
            'score' => (int)($row['score'] ?? 0),
            'event_timestamp' => (int)($row['event_timestamp'] ?? 0),
            'date' => !empty($row['event_timestamp']) ? wp_date('Y-m-d H:i', (int)$row['event_timestamp']) : '',
            'image_url' => esc_url_raw((string)($row['image_url'] ?? '')),
            'source_url' => esc_url_raw((string)($row['link'] ?? '')),
            'story_url' => add_query_arg(['so_external_story' => (int)$row['id']], home_url('/')),
        ];
    }
}

if (!function_exists('so_external_ticker_rest_register')) {
    function so_external_ticker_rest_register(): void {
        return; // removed in v22 stable

        register_rest_route('osint/v1', '/external-ticker/items', [
            'methods' => 'GET',
            'callback' => function(\WP_REST_Request $request) {
                $limit = (int)$request->get_param('limit');
                if ($limit <= 0) $limit = (int)so_external_ticker_get_option('so_external_ticker_limit', 12);
                return rest_ensure_response(['success' => true, 'items' => so_external_ticker_fetch_items($limit)]);
            },
            'permission_callback' => ['SO_API_Manager', 'check_auth'],
        ]);
        register_rest_route('osint/v1', '/external-ticker/story/(?P<id>\d+)', [
            'methods' => 'GET',
            'callback' => function(\WP_REST_Request $request) {
                $payload = so_external_ticker_story_payload((int)$request['id']);
                if (empty($payload)) return new \WP_Error('not_found', 'Story not found', ['status' => 404]);
                return rest_ensure_response(['success' => true, 'story' => $payload]);
            },
            'permission_callback' => ['SO_API_Manager', 'check_auth'],
        ]);
        register_rest_route('osint/v1', '/external-ticker/embed', [
            'methods' => 'GET',
            'callback' => function(\WP_REST_Request $request) {
                $key = sanitize_text_field((string)$request->get_param('key'));
                $mount = sanitize_html_class((string)$request->get_param('mount'));
                $base = esc_url_raw(rest_url('osint/v1/'));
                $cfg = [
                    'base' => untrailingslashit($base),
                    'itemsUrl' => rest_url('osint/v1/external-ticker/items'),
                    'storyBase' => rest_url('osint/v1/external-ticker/story/'),
                    'key' => $key,
                    'mountId' => $mount !== '' ? $mount : 'bt-live-ticker',
                    'title' => (string)so_external_ticker_get_option('so_external_ticker_title', 'آخر الأخبار'),
                    'speed' => max(12, min(120, (int)so_external_ticker_get_option('so_external_ticker_speed', 38))),
                    'showTime' => (bool)so_external_ticker_get_option('so_external_ticker_show_time', 1),
                    'showSource' => (bool)so_external_ticker_get_option('so_external_ticker_show_source', 1),
                    'bg' => (string)so_external_ticker_get_option('so_external_ticker_bg', '#06152a'),
                    'text' => (string)so_external_ticker_get_option('so_external_ticker_text', '#ecfeff'),
                    'accent' => (string)so_external_ticker_get_option('so_external_ticker_accent', '#7c3aed'),
                    'position' => (string)so_external_ticker_get_option('so_external_ticker_position', 'top'),
                ];
                $js = 'window.BEIRUTTIME_TICKER_CFG = ' . wp_json_encode($cfg, JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES) . ';';
                $js .= <<<'JS'
(function(){
  const C = window.BEIRUTTIME_TICKER_CFG || {};
  const doc = document;
  function el(tag, attrs, html){ const n=doc.createElement(tag); if(attrs){Object.keys(attrs).forEach(k=>{ if(k==='style') n.style.cssText=attrs[k]; else n.setAttribute(k, attrs[k]);}); } if(html!==undefined) n.innerHTML=html; return n; }
  function ensureMount(){
    let m = doc.getElementById(C.mountId || 'bt-live-ticker');
    if(!m){ m = el('div', {id: C.mountId || 'bt-live-ticker'}); const ref = doc.body.firstChild; if((C.position||'top')==='top' && ref) doc.body.insertBefore(m, ref); else doc.body.appendChild(m); }
    return m;
  }
  function injectStyle(){
    if(doc.getElementById('bt-external-ticker-style')) return;
    const s = el('style', {id:'bt-external-ticker-style'}, `
      .btxt-wrap{direction:rtl;font-family:Tahoma,Arial,sans-serif;background:${C.bg};color:${C.text};border:1px solid rgba(255,255,255,.08);border-radius:14px;overflow:hidden;box-shadow:0 12px 28px rgba(2,8,23,.28);position:relative}
      .btxt-inner{display:flex;align-items:center;gap:14px;padding:10px 14px;min-height:54px;box-sizing:border-box}
      .btxt-badge{flex:0 0 auto;background:${C.accent};color:#fff;padding:6px 12px;border-radius:999px;font-size:13px;font-weight:700;white-space:nowrap;line-height:1.1}
      .btxt-track{position:relative;overflow:hidden;flex:1 1 auto;direction:ltr;min-width:0;height:34px;display:flex;align-items:center}
      .btxt-marquee{display:inline-flex;align-items:center;gap:26px;white-space:nowrap;flex-wrap:nowrap;width:max-content;min-width:max-content;will-change:transform;animation:btxtMove ${C.speed}s linear infinite;transform:translateX(-50%)}
      .btxt-wrap:hover .btxt-marquee{animation-play-state:paused}
      .btxt-item,.btxt-sep{flex:0 0 auto}
      .btxt-item{direction:rtl;display:inline-flex;align-items:center;gap:10px;color:${C.text};text-decoration:none;font-size:13px;font-weight:700;cursor:pointer;white-space:nowrap;line-height:1.2}
      .btxt-item:hover{opacity:.92}
      .btxt-title{display:inline-block;white-space:nowrap}
      .btxt-meta{font-size:12px;opacity:.75;font-weight:600;white-space:nowrap}
      .btxt-sep{opacity:.35;display:inline-flex;align-items:center;white-space:nowrap}
      .btxt-modal-bg{display:none;position:fixed;inset:0;background:rgba(2,8,23,.72);z-index:999999;align-items:center;justify-content:center;padding:18px}
      .btxt-modal{width:min(760px,96vw);max-height:88vh;overflow:auto;background:#08172a;color:#ecfeff;border-radius:18px;border:1px solid rgba(255,255,255,.08);box-shadow:0 18px 50px rgba(0,0,0,.45)}
      .btxt-modal-hd{display:flex;justify-content:space-between;gap:12px;align-items:center;padding:16px 18px;border-bottom:1px solid rgba(255,255,255,.08)}
      .btxt-modal-bd{padding:18px;line-height:1.9;font-size:15px}
      .btxt-modal-actions{display:flex;gap:10px;flex-wrap:wrap;margin-top:16px}
      .btxt-btn{display:inline-flex;align-items:center;justify-content:center;padding:10px 14px;border-radius:10px;text-decoration:none;font-weight:700;border:1px solid rgba(255,255,255,.1)}
      .btxt-btn-main{background:${C.accent};color:#fff}.btxt-btn-alt{background:#0f2742;color:#ecfeff}
      .btxt-close{background:none;border:none;color:#fff;font-size:24px;cursor:pointer;line-height:1}
      @keyframes btxtMove{0%{transform:translateX(-50%)}100%{transform:translateX(0)}}
      @media(max-width:640px){.btxt-inner{padding:8px 10px;min-height:48px}.btxt-badge{font-size:12px;padding:5px 10px}.btxt-item{font-size:13px}.btxt-modal-bd{font-size:13px;padding:14px}}
    `); doc.head.appendChild(s);
  }
  async function fetchJson(url){ const res = await fetch(url, {headers:{'X-OSINT-API-KEY':C.key}}); if(!res.ok) throw new Error('HTTP '+res.status); return await res.json(); }
  function render(items){ const mount = ensureMount(); if(!items || !items.length){ mount.innerHTML = `<div class="btxt-wrap"><div class="btxt-inner"><span class="btxt-badge">${C.title||'آخر الأخبار'}</span><div style="font-size:13px;opacity:.85;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">لا توجد أخبار متاحة حاليًا.</div></div></div>`; return; } const repeated = items.concat(items); const itemHtml = repeated.map(item=>{
      const meta = [];
      if(C.showSource && item.source_name) meta.push(item.source_name);
      if(C.showTime && item.time_ago) meta.push(item.time_ago);
      return `<span class="btxt-item" data-id="${item.id}" title="${(item.title||'').replace(/"/g,'&quot;')}"><span class="btxt-title">${item.title}</span>${meta.length?`<span class="btxt-meta">${meta.join(' • ')}</span>`:''}</span><span class="btxt-sep">✦</span>`;
    }).join('');
    mount.innerHTML = `<div class="btxt-wrap"><div class="btxt-inner"><span class="btxt-badge">${C.title||'آخر الأخبار'}</span><div class="btxt-track"><div class="btxt-marquee">${itemHtml}</div></div></div></div><div class="btxt-modal-bg" id="btxt-modal-bg"><div class="btxt-modal"><div class="btxt-modal-hd"><strong>تفاصيل الخبر</strong><button class="btxt-close" type="button">×</button></div><div class="btxt-modal-bd" id="btxt-modal-bd">جاري التحميل...</div></div></div>`;
    mount.querySelectorAll('.btxt-item').forEach(node=>node.addEventListener('click', e=>{ e.preventDefault(); const id=node.getAttribute('data-id'); openStory(id); }));
    const bg = mount.querySelector('#btxt-modal-bg');
    if(bg) bg.addEventListener('click', e=>{ if(e.target===bg || e.target.classList.contains('btxt-close')) bg.style.display='none'; });
  }
  async function openStory(id){
    const wrap = ensureMount(); const bg = wrap.querySelector('#btxt-modal-bg'); const bd = wrap.querySelector('#btxt-modal-bd'); if(!bg||!bd) return; bg.style.display='flex'; bd.innerHTML='جاري التحميل...';
    try { const data = await fetchJson(C.storyBase + id + '?key=' + encodeURIComponent(C.key)); const s = data.story || {}; bd.innerHTML = `${s.image_url?`<img src="${s.image_url}" style="max-width:100%;height:auto;border-radius:12px;margin-bottom:14px;">`:''}<h3 style="margin:0 0 10px;font-size:24px;color:#fff">${s.title||''}</h3><div style="font-size:12px;opacity:.8;margin-bottom:12px">${s.source_name||''}${s.date?` • ${s.date}`:''}</div><div>${s.body||s.summary||''}</div><div class="btxt-modal-actions"><a class="btxt-btn btxt-btn-main" href="${s.story_url||'#'}" target="_blank" rel="noopener">فتح الخبر على الموقع</a>${s.source_url?`<a class="btxt-btn btxt-btn-alt" href="${s.source_url}" target="_blank" rel="noopener">المصدر الأصلي</a>`:''}</div>`;
    } catch(err){ bd.innerHTML='<div>تعذر تحميل تفاصيل الخبر.</div>'; }
  }
  async function boot(){ injectStyle(); try{ const data = await fetchJson(C.itemsUrl + '?key=' + encodeURIComponent(C.key)); render(data.items || []); }catch(err){ const mount = ensureMount(); mount.innerHTML = '<div class="btxt-wrap"><div class="btxt-inner"><span class="btxt-badge">الشريط الإخباري</span><div style="font-size:13px;opacity:.85">تعذر جلب الأخبار.</div></div></div>'; } }
  if(doc.readyState==='loading') doc.addEventListener('DOMContentLoaded', boot); else boot();
})();
JS;
                $response = new \WP_REST_Response($js, 200);
                $response->header('Content-Type', 'application/javascript; charset=' . get_option('blog_charset'));
                return $response;
            },
            'permission_callback' => '__return_true',
        ]);

        register_rest_route('osint/v1', '/external-ticker/frame', [
            'methods' => 'GET',
            'callback' => function(\WP_REST_Request $request) {
                $key = sanitize_text_field((string)$request->get_param('key'));
                if ($key === '') {
                    $response = new \WP_REST_Response('<!doctype html><html lang="ar" dir="rtl"><head><meta charset="' . esc_attr(get_option('blog_charset')) . '"><meta name="viewport" content="width=device-width, initial-scale=1"></head><body style="margin:0;font-family:Tajawal,Tahoma,Arial,sans-serif;background:transparent"><div style="padding:10px 14px;font-size:13px">مفتاح API غير صالح.</div></body></html>', 403);
                    $response->header('Content-Type', 'text/html; charset=' . get_option('blog_charset'));
                    return $response;
                }
                if (!class_exists('SO_API_Manager') || !is_callable(['SO_API_Manager', 'check_auth']) || !call_user_func(['SO_API_Manager', 'check_auth'], $request)) {
                    $response = new \WP_REST_Response('<!doctype html><html lang="ar" dir="rtl"><head><meta charset="' . esc_attr(get_option('blog_charset')) . '"><meta name="viewport" content="width=device-width, initial-scale=1"></head><body style="margin:0;font-family:Tajawal,Tahoma,Arial,sans-serif;background:transparent"><div style="padding:10px 14px;font-size:13px">تعذر التحقق من المفتاح.</div></body></html>', 403);
                    $response->header('Content-Type', 'text/html; charset=' . get_option('blog_charset'));
                    return $response;
                }
                $limit = max(3, min(20, (int)so_external_ticker_get_option('so_external_ticker_limit', 12)));
                $items = so_external_ticker_fetch_items($limit);
                $title = (string)so_external_ticker_get_option('so_external_ticker_title', 'آخر الأخبار');
                $bg = (string)so_external_ticker_get_option('so_external_ticker_bg', '#06152a');
                $text = (string)so_external_ticker_get_option('so_external_ticker_text', '#ecfeff');
                $accent = (string)so_external_ticker_get_option('so_external_ticker_accent', '#7c3aed');
                $speed = max(12, min(120, (int)so_external_ticker_get_option('so_external_ticker_speed', 38)));
                $showTime = (bool)so_external_ticker_get_option('so_external_ticker_show_time', 1);
                $showSource = (bool)so_external_ticker_get_option('so_external_ticker_show_source', 1);
                $story_base = rest_url('osint/v1/external-ticker/story/');
                $parts = [];
                foreach (array_merge($items, $items) as $item) {
                    $meta = [];
                    if ($showSource && !empty($item['source_name'])) $meta[] = esc_html($item['source_name']);
                    if ($showTime && !empty($item['time_ago'])) $meta[] = esc_html($item['time_ago']);
                    $meta_html = $meta ? '<span class="btxtf-meta">' . implode(' • ', $meta) . '</span>' : '';
                    $story_url = esc_url(add_query_arg('key', rawurlencode($key), $story_base . (int)$item['id']));
                    $parts[] = '<a class="btxtf-item" href="' . $story_url . '" target="_blank" rel="noopener"><span class="btxtf-title">' . esc_html((string)$item['title']) . '</span>' . $meta_html . '</a><span class="btxtf-sep">✦</span>';
                }
                if (empty($parts)) {
                    $parts[] = '<span class="btxtf-item"><span class="btxtf-title">لا توجد أخبار متاحة حاليًا.</span></span>';
                }
                $html = '<!doctype html><html lang="ar" dir="rtl"><head><meta charset="' . esc_attr(get_option('blog_charset')) . '"><meta name="viewport" content="width=device-width, initial-scale=1"><style>'
                    . 'html,body{margin:0;padding:0;background:transparent;overflow:hidden;height:70px}'
                    . 'body{font-family:Tajawal,Tahoma,Arial,sans-serif}'
                    . '.btxtf-wrap{direction:rtl;background:' . esc_attr($bg) . ';color:' . esc_attr($text) . ';border:1px solid rgba(255,255,255,.08);border-radius:14px;overflow:hidden;box-shadow:0 12px 28px rgba(2,8,23,.18);height:68px;box-sizing:border-box}'
                    . '.btxtf-inner{display:flex;align-items:center;gap:14px;padding:10px 14px;height:68px;box-sizing:border-box}'
                    . '.btxtf-badge{flex:0 0 auto;background:' . esc_attr($accent) . ';color:#fff;padding:6px 12px;border-radius:999px;font-size:13px;font-weight:700;white-space:nowrap;line-height:1.1}'
                    . '.btxtf-track{position:relative;overflow:hidden;flex:1 1 auto;direction:ltr;min-width:0;height:34px;display:flex;align-items:center}'
                    . '.btxtf-marquee{display:inline-flex;align-items:center;gap:26px;white-space:nowrap;flex-wrap:nowrap;width:max-content;min-width:max-content;will-change:transform;animation:btxtFrameMove ' . (int)$speed . 's linear infinite;transform:translateX(-50%)}'
                    . '.btxtf-wrap:hover .btxtf-marquee{animation-play-state:paused}'
                    . '.btxtf-item,.btxtf-sep{flex:0 0 auto}'
                    . '.btxtf-item{direction:rtl;display:inline-flex;align-items:center;gap:10px;color:' . esc_attr($text) . ';text-decoration:none;font-size:13px;font-weight:700;white-space:nowrap;line-height:1.2}'
                    . '.btxtf-title,.btxtf-meta,.btxtf-sep{white-space:nowrap}'
                    . '.btxtf-meta{font-size:12px;opacity:.75;font-weight:600}'
                    . '.btxtf-sep{opacity:.35;display:inline-flex;align-items:center}'
                    . '@keyframes btxtFrameMove{0%{transform:translateX(-50%)}100%{transform:translateX(0)}}'
                    . '@media(max-width:640px){html,body{height:58px}.btxtf-wrap{height:58px}.btxtf-inner{padding:8px 10px;height:58px}.btxtf-badge{font-size:12px;padding:5px 10px}.btxtf-item{font-size:13px}}'
                    . '</style></head><body><div class="btxtf-wrap"><div class="btxtf-inner"><span class="btxtf-badge">' . esc_html($title) . '</span><div class="btxtf-track"><div class="btxtf-marquee">' . implode('', $parts) . '</div></div></div></div></body></html>';
                $response = new \WP_REST_Response($html, 200);
                $response->header('Content-Type', 'text/html; charset=' . get_option('blog_charset'));
                return $response;
            },
            'permission_callback' => '__return_true',
        ]);
    }
    // external ticker removed in v21.6
}

if (!function_exists('so_external_ticker_story_template')) {
    function so_external_ticker_story_template(): void {
        return; // removed in v22 stable

        $id = isset($_GET['so_external_story']) ? (int)$_GET['so_external_story'] : 0;
        if ($id <= 0) return;
        $story = so_external_ticker_story_payload($id);
        if (empty($story)) {
            status_header(404);
            wp_die('Story not found');
        }
        nocache_headers();
        echo '<!doctype html><html lang="ar" dir="rtl"><head><meta charset="' . esc_attr(get_bloginfo('charset')) . '"><meta name="viewport" content="width=device-width, initial-scale=1"><title>' . esc_html($story['title']) . '</title><style>body{font-family:Tajawal,Tahoma,Arial,sans-serif;background:#071220;color:#ecfeff;padding:24px;line-height:1.9} .w{max-width:860px;margin:0 auto;background:#0b1728;border:1px solid rgba(255,255,255,.08);border-radius:18px;padding:22px;box-shadow:0 20px 60px rgba(0,0,0,.35)} a.btn{display:inline-flex;padding:10px 14px;border-radius:10px;background:#7c3aed;color:#fff;text-decoration:none;margin-left:10px} a.alt{background:#17324f} img{max-width:100%;height:auto;border-radius:12px;margin:0 0 16px}</style></head><body><div class="w">';
        if (!empty($story['image_url'])) echo '<img src="' . esc_url($story['image_url']) . '" alt="">';
        echo '<h1 style="margin:0 0 8px">' . esc_html($story['title']) . '</h1>';
        echo '<div style="opacity:.8;font-size:13px;margin-bottom:12px">' . esc_html($story['source_name']) . ' • ' . esc_html($story['date']) . '</div>';
        echo wp_kses_post($story['body']);
        echo '<div style="margin-top:16px">';
        echo '<a class="btn" href="' . esc_url(home_url('/')) . '">العودة للموقع</a>';
        if (!empty($story['source_url'])) echo '<a class="btn alt" href="' . esc_url($story['source_url']) . '" target="_blank" rel="noopener">المصدر الأصلي</a>';
        echo '</div></div></body></html>';
        exit;
    }
    // external ticker removed in v21.6
}

if (!function_exists('so_external_ticker_shortcode')) {
    function so_external_ticker_shortcode($atts = []): string {
        return ''; // removed in v22 stable

        $atts = shortcode_atts(['height' => '70'], $atts, 'beiruttime_external_ticker');
        $key = (string)get_option('so_external_api_key', '');
        if ($key === '') {
            return '<div style="padding:10px 14px;border:1px solid rgba(255,255,255,.08);border-radius:12px;background:#06152a;color:#ecfeff">يرجى ضبط External API Key أولًا.</div>';
        }
        $height = max(50, min(120, (int)$atts['height']));
        $src = add_query_arg(['key' => $key], rest_url('osint/v1/external-ticker/frame'));
        return '<iframe src="' . esc_url($src) . '" width="100%" height="' . esc_attr((string)$height) . '" style="border:0;overflow:hidden;background:transparent;display:block" scrolling="no" loading="lazy"></iframe>';
    }
    add_shortcode('beiruttime_external_ticker', 'so_external_ticker_shortcode');
}

if (!function_exists('so_external_ticker_admin_save')) {
    function so_external_ticker_admin_save(): void {
        return; // removed in v22 stable

        if (!is_admin() || !current_user_can('manage_options')) return;
        if (!isset($_POST['so_save_external_ticker']) || !check_admin_referer('so_save_external_ticker_nonce')) return;
        update_option('so_external_ticker_enabled', isset($_POST['so_external_ticker_enabled']) ? 1 : 0);
        update_option('so_external_ticker_title', sanitize_text_field(wp_unslash($_POST['so_external_ticker_title'] ?? 'آخر الأخبار')));
        update_option('so_external_ticker_limit', max(3, min(30, (int)($_POST['so_external_ticker_limit'] ?? 12))));
        update_option('so_external_ticker_speed', max(12, min(120, (int)($_POST['so_external_ticker_speed'] ?? 38))));
        update_option('so_external_ticker_position', in_array((string)($_POST['so_external_ticker_position'] ?? 'top'), ['top','bottom'], true) ? (string)$_POST['so_external_ticker_position'] : 'top');
        update_option('so_external_ticker_show_time', isset($_POST['so_external_ticker_show_time']) ? 1 : 0);
        update_option('so_external_ticker_show_source', isset($_POST['so_external_ticker_show_source']) ? 1 : 0);
        update_option('so_external_ticker_min_score', max(0, (int)($_POST['so_external_ticker_min_score'] ?? 0)));
        update_option('so_external_ticker_allowed_types', sanitize_textarea_field(wp_unslash($_POST['so_external_ticker_allowed_types'] ?? '')));
        update_option('so_external_ticker_bg', sanitize_hex_color($_POST['so_external_ticker_bg'] ?? '#06152a') ?: '#06152a');
        update_option('so_external_ticker_text', sanitize_hex_color($_POST['so_external_ticker_text'] ?? '#ecfeff') ?: '#ecfeff');
        update_option('so_external_ticker_accent', sanitize_hex_color($_POST['so_external_ticker_accent'] ?? '#7c3aed') ?: '#7c3aed');
        wp_safe_redirect(add_query_arg('saved', '1', admin_url('admin.php?page=strategic-osint-external-ticker')));
        exit;
    }
    // external ticker removed in v21.6
}

if (!function_exists('so_external_ticker_admin_page')) {
    function so_external_ticker_admin_page(): void {
        if (!current_user_can('manage_options')) wp_die('غير مسموح');
        echo '<div class="wrap" dir="rtl"><h1>📢 الشريط الخارجي</h1><div class="notice notice-warning"><p>تم إيقاف هذه الميزة في النسخة المستقرة الحالية لحين إعادة بنائها بشكل آمن.</p></div></div>';
        return;

        if (!current_user_can('manage_options')) wp_die('غير مسموح');
        $api_key = (string)get_option('so_external_api_key', '');
        $mount_example = 'bt-live-ticker';
        $script_src = add_query_arg(['key' => $api_key, 'mount' => $mount_example], rest_url('osint/v1/external-ticker/embed'));
        $embed_code = '<div id="' . $mount_example . '"></div>' . "\n" . '<script src="' . esc_url($script_src) . '" defer></script>';
        echo '<div class="wrap" dir="rtl"><h1 style="margin-bottom:18px">📢 الشريط الخارجي</h1>';
        if (isset($_GET['saved'])) echo '<div class="notice notice-success"><p>تم حفظ إعدادات الشريط الخارجي.</p></div>';
        echo '<div style="max-width:1100px;display:grid;grid-template-columns:1.1fr .9fr;gap:18px;align-items:start">';
        echo '<form method="post" style="background:#0b1728;color:#e0f2ff;padding:20px;border-radius:18px;border:1px solid #1e3a5f">';
