/* WORLD MONITOR LIVE PATCH */
if (!function_exists('sod_wm_live_get_coords')) {
function sod_wm_live_get_coords(string $region): ?array {
    global $wpdb;
    $region = trim(wp_strip_all_tags($region));
    if ($region === '') return null;
    $geo = $wpdb->prefix . 'so_geo_cache';
    $hash = md5(mb_strtolower($region));
    $row = $wpdb->get_row($wpdb->prepare("SELECT lat, lon, confidence FROM {$geo} WHERE place_name = %s OR place_hash = %s ORDER BY confidence DESC LIMIT 1", $region, $hash), ARRAY_A);
    if (!$row) {
        $like = '%' . $wpdb->esc_like($region) . '%';
        $row = $wpdb->get_row($wpdb->prepare("SELECT lat, lon, confidence FROM {$geo} WHERE place_name LIKE %s ORDER BY confidence DESC LIMIT 1", $like), ARRAY_A);
    }
    if (!$row || $row['lat'] === null || $row['lon'] === null) return null;
    return ['lat' => (float)$row['lat'], 'lon' => (float)$row['lon'], 'confidence' => (float)($row['confidence'] ?? 0)];
}
}

if (!function_exists('sod_wm_live_snapshot')) {
function sod_wm_live_snapshot(int $days = 7, int $limit = 120): array {
    global $wpdb;
    $days = max(1, min(365, $days));
    $limit = max(20, min(400, $limit));
    $events_table = $wpdb->prefix . 'so_news_events';
    $cutoff = time() - ($days * DAY_IN_SECONDS);
    $rows = $wpdb->get_results($wpdb->prepare("SELECT id,title,region,actor_v2,intel_type,score,event_timestamp,status,source_name,source,war_data FROM {$events_table} WHERE event_timestamp >= %d AND (status = 'published' OR status = '' OR status IS NULL) ORDER BY event_timestamp DESC LIMIT %d", $cutoff, $limit), ARRAY_A);
    if (empty($rows)) {
        $rows = $wpdb->get_results($wpdb->prepare("SELECT id,title,region,actor_v2,intel_type,score,event_timestamp,status,source_name,source,war_data FROM {$events_table} ORDER BY event_timestamp DESC LIMIT %d", $limit), ARRAY_A);
    }
    $total = count($rows);
    $critical = $high = $moderate = $low = 0;
    $regions = []; $actors = []; $types = []; $trend = []; $markers = []; $feed = [];
    foreach ($rows as $row) {
        $score = (int)($row['score'] ?? 0);
        if ($score >= 140) $critical++;
        elseif ($score >= 100) $high++;
        elseif ($score >= 60) $moderate++;
        else $low++;
        $region = sanitize_text_field((string)($row['region'] ?: 'غير محدد'));
        $actor = sanitize_text_field((string)($row['actor_v2'] ?: 'غير محدد'));
        $type = sanitize_text_field((string)($row['intel_type'] ?: 'غير محدد'));
        $ts = (int)($row['event_timestamp'] ?: time());
        $dayKey = gmdate('Y-m-d', $ts + (3 * HOUR_IN_SECONDS));
        $regions[$region] = ($regions[$region] ?? 0) + 1;
        $actors[$actor] = ($actors[$actor] ?? 0) + 1;
        $types[$type] = ($types[$type] ?? 0) + 1;
        $trend[$dayKey] = ($trend[$dayKey] ?? 0) + 1;
        $coords = sod_wm_live_get_coords($region);
        if ($coords && count($markers) < 120) {
            $markers[] = [
                'id' => (int)$row['id'],
                'title' => wp_strip_all_tags((string)$row['title']),
                'region' => $region,
                'actor' => $actor,
                'type' => $type,
                'score' => $score,
                'lat' => $coords['lat'],
                'lon' => $coords['lon'],
                'severity' => ($score >= 140 ? 'critical' : ($score >= 100 ? 'high' : ($score >= 60 ? 'moderate' : 'low'))),
                'time' => $ts,
            ];
        }
        if (count($feed) < 25) {
            $feed[] = [
                'id' => (int)$row['id'],
                'title' => wp_strip_all_tags((string)$row['title']),
                'region' => $region,
                'actor' => $actor,
                'type' => $type,
                'score' => $score,
                'source' => sanitize_text_field((string)($row['source_name'] ?: $row['source'] ?: 'المحرر الآلي')),
                'time' => $ts,
            ];
        }
    }
    arsort($regions); arsort($actors); arsort($types); ksort($trend);
    return [
        'kpi' => [
            'total' => $total,
            'critical' => $critical,
            'high' => $high,
            'moderate' => $moderate,
            'low' => $low,
            'countries' => count($regions),
            'hotspots' => count(array_filter($regions, function($v){ return $v >= 2; })),
            'updated_at' => time(),
        ],
        'trend' => array_map(function($d, $v){ return ['date' => $d, 'count' => $v]; }, array_keys($trend), array_values($trend)),
        'regions' => array_slice(array_map(function($n,$v){ return ['name'=>$n,'count'=>$v]; }, array_keys($regions), array_values($regions)), 0, 12),
        'actors' => array_slice(array_map(function($n,$v){ return ['name'=>$n,'count'=>$v]; }, array_keys($actors), array_values($actors)), 0, 12),
        'types' => array_slice(array_map(function($n,$v){ return ['name'=>$n,'count'=>$v]; }, array_keys($types), array_values($types)), 0, 12),
        'markers' => $markers,
        'feed' => $feed,
        'days' => $days,
    ];
}
}

if (!function_exists('sod_wm_live_ajax_snapshot')) {
function sod_wm_live_ajax_snapshot(): void {
    $days = isset($_REQUEST['days']) ? (int)$_REQUEST['days'] : 7;
    $nonce = isset($_REQUEST['nonce']) ? sanitize_text_field(wp_unslash($_REQUEST['nonce'])) : '';
    if ($nonce !== '' && defined('SOD_AJAX_NONCE_ACTION') && wp_verify_nonce($nonce, SOD_AJAX_NONCE_ACTION) === false) {
        wp_send_json_error(['message' => 'nonce_failed'], 403);
    }
    wp_send_json_success(sod_wm_live_snapshot($days));
}
}
add_action('wp_ajax_so_world_monitor_snapshot', 'sod_wm_live_ajax_snapshot');
add_action('wp_ajax_nopriv_so_world_monitor_snapshot', 'sod_wm_live_ajax_snapshot');

