    <script>
    (function(){
      const root=document.getElementById(<?php echo wp_json_encode($uid); ?>);
      if(!root) return;
      const state={data:<?php echo wp_json_encode($data); ?>,days:<?php echo (int)$days; ?>,maps:{},trend:null};
      const ajaxUrl=<?php echo wp_json_encode(admin_url('admin-ajax.php')); ?>;
      const nonce=<?php echo wp_json_encode(defined('SOD_AJAX_NONCE_ACTION') ? wp_create_nonce(SOD_AJAX_NONCE_ACTION) : ''); ?>;
      function esc(s){return String(s||'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[m]));}
      function sevColor(s){return s==='critical'?'#ef4444':(s==='high'?'#f97316':(s==='moderate'?'#eab308':'#22c55e'));}
      function rel(ts){try{return new Date(ts*1000).toLocaleString('ar-LB');}catch(e){return '';}}
      function renderKPIs(){const k=state.data.kpi||{};const items=[['إجمالي الأحداث',k.total||0],['حرج',k.critical||0],['مرتفع',k.high||0],['متوسط',k.moderate||0],['منخفض',k.low||0],['الدول',k.countries||0],['البؤر',k.hotspots||0]];root.querySelector('.wm-kpis').innerHTML=items.map(i=>`<div class="wm-kpi"><b>${i[1]}</b><span>${i[0]}</span></div>`).join('');}
      function renderFeed(targetId, rows){const el=document.getElementById(targetId); if(!el) return; el.innerHTML=(rows||[]).map(r=>`<article class="wm-item"><h4>${esc(r.title)}</h4><div class="wm-meta"><span class="wm-badge">${esc(r.region)}</span><span class="wm-badge">${esc(r.actor)}</span><span class="wm-badge">${esc(r.type)}</span><span class="wm-badge">${esc(r.score)}</span><span>${esc(r.source||'')}</span><span>${esc(rel(r.time))}</span></div></article>`).join('') || '<div class="wm-item">لا توجد بيانات بعد</div>';}
      function renderRank(targetId, rows){const el=document.getElementById(targetId); if(!el) return; const max=Math.max(1,...(rows||[]).map(r=>parseInt(r.count||0,10))); el.innerHTML=(rows||[]).map(r=>`<div class="wm-list-row"><strong>${esc(r.name)}</strong><div class="wm-bar"><i style="width:${Math.max(8,Math.round((r.count/max)*100))}%"></i></div><b>${esc(r.count)}</b></div>`).join('') || '<div class="wm-item">لا توجد بيانات</div>';}
      function initMap(id){if(state.maps[id]||typeof L==='undefined') return; const map=L.map(id,{zoomControl:true}).setView([27,28],3); L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png',{subdomains:'abcd',maxZoom:19}).addTo(map); state.maps[id]={map:map,layer:L.layerGroup().addTo(map)}; setTimeout(()=>map.invalidateSize(),180);}
      function renderMap(id){initMap(id); const obj=state.maps[id]; if(!obj) return; obj.layer.clearLayers(); const pts=[]; (state.data.markers||[]).forEach(m=>{ if(!m.lat||!m.lon) return; pts.push([m.lat,m.lon]); const marker=L.circleMarker([m.lat,m.lon],{radius:7,color:sevColor(m.severity),fillColor:sevColor(m.severity),fillOpacity:.85,weight:1}).addTo(obj.layer); marker.bindPopup(`<div style="direction:rtl;text-align:right"><b>${esc(m.title)}</b><br>${esc(m.region)} — ${esc(m.actor)}<br>Score: ${esc(m.score)}</div>`);}); if(pts.length){obj.map.fitBounds(pts,{padding:[24,24]});} else {obj.map.setView([27,28],3);} }
      function renderTrend(){const cvs=document.getElementById(<?php echo wp_json_encode($uid . '_trend'); ?>); if(!cvs || typeof Chart==='undefined') return; const labels=(state.data.trend||[]).map(x=>x.date); const values=(state.data.trend||[]).map(x=>x.count); if(state.trend){state.trend.destroy();} state.trend=new Chart(cvs.getContext('2d'),{type:'line',data:{labels:labels,datasets:[{label:'الأحداث',data:values,borderColor:'#60a5fa',backgroundColor:'rgba(96,165,250,.18)',fill:true,tension:.35}]},options:{responsive:true,plugins:{legend:{display:false}},scales:{x:{ticks:{color:'#9fc0dd'}},y:{ticks:{color:'#9fc0dd'},beginAtZero:true}}}});}
      function renderAll(){renderKPIs(); renderFeed(<?php echo wp_json_encode($uid . '_feed_home'); ?>, state.data.feed||[]); renderFeed(<?php echo wp_json_encode($uid . '_feed_full'); ?>, state.data.feed||[]); renderRank(<?php echo wp_json_encode($uid . '_regions'); ?>, state.data.regions||[]); renderRank(<?php echo wp_json_encode($uid . '_actors'); ?>, state.data.actors||[]); renderRank(<?php echo wp_json_encode($uid . '_types'); ?>, state.data.types||[]); renderMap(<?php echo wp_json_encode($uid . '_map_home'); ?>); renderMap(<?php echo wp_json_encode($uid . '_map_full'); ?>); renderTrend(); }
      function load(days){state.days=days||state.days; const body=new URLSearchParams({action:'so_world_monitor_snapshot',days:String(state.days),nonce:nonce}); fetch(ajaxUrl,{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded; charset=UTF-8'},body:body.toString()}).then(r=>r.json()).then(j=>{if(j&&j.success&&j.data){state.data=j.data; renderAll();}}).catch(()=>{});}
      root.querySelectorAll('.wm-tab').forEach(btn=>btn.addEventListener('click',()=>{root.querySelectorAll('.wm-tab').forEach(b=>b.classList.remove('is-active'));btn.classList.add('is-active');const page=btn.getAttribute('data-page');root.querySelectorAll('.wm-live-page').forEach(p=>p.classList.toggle('is-active',p.getAttribute('data-page')===page)); setTimeout(()=>{renderMap(<?php echo wp_json_encode($uid . '_map_home'); ?>);renderMap(<?php echo wp_json_encode($uid . '_map_full'); ?>);},120);}));
      root.querySelectorAll('.wm-range').forEach(btn=>btn.addEventListener('click',()=>{root.querySelectorAll('.wm-range').forEach(b=>b.classList.remove('is-active'));btn.classList.add('is-active');load(parseInt(btn.getAttribute('data-days')||'7',10));}));
      renderAll(); setInterval(function(){load(state.days);}, <?php echo (int)$refresh * 1000; ?>);
    })();
    </script>
    <?php
    return (string)ob_get_clean();
}
}

