if (!function_exists('sod_wm_v2_guess_coords')) {
function sod_wm_v2_guess_coords(string $region): ?array {
    $region = trim(wp_strip_all_tags($region));
    if ($region === '') return null;
    $known = sod_wm_v2_known_coords();
    if (isset($known[$region])) return ['lat'=>(float)$known[$region][0],'lon'=>(float)$known[$region][1],'confidence'=>0.4];
    foreach ($known as $name => $coords) {
        if (mb_stripos($region, $name) !== false || mb_stripos($name, $region) !== false) {
            return ['lat'=>(float)$coords[0],'lon'=>(float)$coords[1],'confidence'=>0.25];
        }
    }
    return null;
}
}

if (!function_exists('sod_wm_v2_table_exists')) {
function sod_wm_v2_table_exists(string $table): bool {
    global $wpdb;
    $found = $wpdb->get_var($wpdb->prepare('SHOW TABLES LIKE %s', $table));
    return $found === $table;
}
}

if (!function_exists('sod_wm_v2_source_rows')) {
function sod_wm_v2_source_rows(int $days = 7, int $limit = 120): array {
    global $wpdb;
    $days = max(1, min(365, $days));
    $limit = max(20, min(500, $limit));
    $cutoff = time() - ($days * DAY_IN_SECONDS);
    $rows = [];
    $events_table = $wpdb->prefix . 'so_news_events';
    if (sod_wm_v2_table_exists($events_table)) {
        $sql = $wpdb->prepare("SELECT id,title,region,actor_v2,intel_type,score,event_timestamp,status,source_name,source,link FROM {$events_table} WHERE event_timestamp >= %d ORDER BY event_timestamp DESC LIMIT %d", $cutoff, $limit);
        $rows = (array) $wpdb->get_results($sql, ARRAY_A);
        if (!$rows) {
            $rows = (array) $wpdb->get_results($wpdb->prepare("SELECT id,title,region,actor_v2,intel_type,score,event_timestamp,status,source_name,source,link FROM {$events_table} ORDER BY event_timestamp DESC LIMIT %d", $limit), ARRAY_A);
        }
    }
    if (!$rows) {
        $posts = $wpdb->posts;
        $rows = (array) $wpdb->get_results($wpdb->prepare(
            "SELECT ID as id, post_title as title, UNIX_TIMESTAMP(COALESCE(post_date_gmt, post_date)) as event_timestamp, post_name as source_name, guid as link FROM {$posts} WHERE post_status='publish' AND post_type='post' ORDER BY post_date_gmt DESC LIMIT %d",
            $limit
        ), ARRAY_A);
        foreach ($rows as &$r) {
            $r['region'] = get_post_meta((int)$r['id'], 'region', true) ?: get_post_meta((int)$r['id'], 'so_region', true) ?: 'عام';
            $r['actor_v2'] = get_post_meta((int)$r['id'], 'actor_v2', true) ?: get_post_meta((int)$r['id'], 'so_actor', true) ?: 'غير محدد';
            $r['intel_type'] = get_post_meta((int)$r['id'], 'intel_type', true) ?: get_post_meta((int)$r['id'], 'so_intel_type', true) ?: 'عام';
            $r['score'] = (int)(get_post_meta((int)$r['id'], 'score', true) ?: get_post_meta((int)$r['id'], 'so_score', true) ?: 0);
            $r['source'] = 'WordPress';
            $r['status'] = 'publish';
        }
        unset($r);
    }
    return $rows;
}
}

if (!function_exists('sod_wm_v2_coords')) {
function sod_wm_v2_coords(string $region): ?array {
    global $wpdb;
    $region = trim(wp_strip_all_tags($region));
    if ($region === '') return null;
    $geo = $wpdb->prefix . 'so_geo_cache';
    if (sod_wm_v2_table_exists($geo)) {
        $hash = md5(function_exists('mb_strtolower') ? mb_strtolower($region) : strtolower($region));
        $row = $wpdb->get_row($wpdb->prepare("SELECT lat, lon, confidence FROM {$geo} WHERE place_name=%s OR place_hash=%s ORDER BY confidence DESC LIMIT 1", $region, $hash), ARRAY_A);
        if (!$row) {
            $like = '%' . $wpdb->esc_like($region) . '%';
            $row = $wpdb->get_row($wpdb->prepare("SELECT lat, lon, confidence FROM {$geo} WHERE place_name LIKE %s ORDER BY confidence DESC LIMIT 1", $like), ARRAY_A);
        }
        if ($row && $row['lat'] !== null && $row['lon'] !== null) {
            return ['lat'=>(float)$row['lat'],'lon'=>(float)$row['lon'],'confidence'=>(float)($row['confidence'] ?? 0)];
        }
    }
    return sod_wm_v2_guess_coords($region);
}
}

if (!function_exists('sod_wm_v2_snapshot')) {
function sod_wm_v2_snapshot(int $days = 7, int $limit = 120): array {
    $rows = sod_wm_v2_source_rows($days, $limit);
    $total = count($rows); $critical = 0; $high = 0; $moderate = 0; $low = 0;
    $regions = []; $actors = []; $types = []; $trend = []; $markers = []; $feed = [];
    foreach ($rows as $row) {
        $score = (int)($row['score'] ?? 0);
        if ($score >= 140) $critical++; elseif ($score >= 100) $high++; elseif ($score >= 60) $moderate++; else $low++;
        $region = sanitize_text_field((string)($row['region'] ?: 'غير محدد'));
        $actor = sanitize_text_field((string)($row['actor_v2'] ?: 'غير محدد'));
        $type = sanitize_text_field((string)($row['intel_type'] ?: 'عام'));
        $ts = (int)($row['event_timestamp'] ?: time());
        $dayKey = wp_date('Y-m-d', $ts, wp_timezone());
        $regions[$region] = ($regions[$region] ?? 0) + 1;
        $actors[$actor] = ($actors[$actor] ?? 0) + 1;
        $types[$type] = ($types[$type] ?? 0) + 1;
        $trend[$dayKey] = ($trend[$dayKey] ?? 0) + 1;
        $coords = sod_wm_v2_coords($region);
        if ($coords && count($markers) < 180) {
            $markers[] = ['id'=>(int)$row['id'],'title'=>wp_strip_all_tags((string)$row['title']),'region'=>$region,'actor'=>$actor,'type'=>$type,'score'=>$score,'lat'=>$coords['lat'],'lon'=>$coords['lon'],'severity'=>($score>=140?'critical':($score>=100?'high':($score>=60?'moderate':'low'))),'time'=>$ts,'link'=>esc_url_raw((string)($row['link'] ?? ''))];
        }
        if (count($feed) < 30) {
            $feed[] = ['id'=>(int)$row['id'],'title'=>wp_strip_all_tags((string)$row['title']),'region'=>$region,'actor'=>$actor,'type'=>$type,'score'=>$score,'source'=>sanitize_text_field((string)($row['source_name'] ?: $row['source'] ?: 'النظام')),'time'=>$ts,'link'=>esc_url_raw((string)($row['link'] ?? ''))];
        }
    }
    arsort($regions); arsort($actors); arsort($types); ksort($trend);
    return [
        'kpi' => ['total'=>$total,'critical'=>$critical,'high'=>$high,'moderate'=>$moderate,'low'=>$low,'countries'=>count($regions),'hotspots'=>count(array_filter($regions, fn($v)=>$v>=2)),'updated_at'=>time()],
        'trend' => array_map(fn($d,$v)=>['date'=>$d,'count'=>$v], array_keys($trend), array_values($trend)),
        'regions' => array_slice(array_map(fn($n,$v)=>['name'=>$n,'count'=>$v], array_keys($regions), array_values($regions)), 0, 12),
        'actors' => array_slice(array_map(fn($n,$v)=>['name'=>$n,'count'=>$v], array_keys($actors), array_values($actors)), 0, 12),
        'types' => array_slice(array_map(fn($n,$v)=>['name'=>$n,'count'=>$v], array_keys($types), array_values($types)), 0, 12),
        'markers' => $markers,
        'feed' => $feed,
        'days' => $days,
        'source_count' => count($rows),
    ];
}
}

if (!function_exists('sod_wm_v2_ajax_snapshot')) {
function sod_wm_v2_ajax_snapshot(): void {
    $days = isset($_REQUEST['days']) ? (int)$_REQUEST['days'] : 7;
    wp_send_json_success(sod_wm_v2_snapshot($days));
}
