if (!function_exists('sod_wm_v2_render_rank_rows')) {
function sod_wm_v2_render_rank_rows(array $rows): string {
    if (!$rows) return '<div class="wm-item">لا توجد بيانات</div>';
    $max = max(1, ...array_map(fn($r)=>(int)($r['count'] ?? 0), $rows));
    $html = '';
    foreach ($rows as $r) {
        $pct = max(8, (int) round(((int)$r['count'] / $max) * 100));
        $html .= '<div class="wm-list-row"><strong>'.esc_html((string)$r['name']).'</strong><div class="wm-bar"><i style="width:'.$pct.'%"></i></div><b>'.esc_html((string)$r['count']).'</b></div>';
    }
    return $html;
}
}

if (!function_exists('sod_wm_v2_render_feed_rows')) {
function sod_wm_v2_render_feed_rows(array $rows): string {
    if (!$rows) return '<div class="wm-item">لا توجد بيانات بعد</div>';
    $html = '';
    foreach ($rows as $r) {
        $title = esc_html((string)($r['title'] ?? ''));
        $link  = !empty($r['link']) ? esc_url((string)$r['link']) : '';
        $headline = $link ? '<a href="'.$link.'" target="_blank" rel="noopener">'.$title.'</a>' : $title;
        $html .= '<article class="wm-item"><h4>'.$headline.'</h4><div class="wm-meta">'
            .'<span class="wm-badge">'.esc_html((string)($r['region'] ?? '')).'</span>'
            .'<span class="wm-badge">'.esc_html((string)($r['actor'] ?? '')).'</span>'
            .'<span class="wm-badge">'.esc_html((string)($r['type'] ?? '')).'</span>'
            .'<span class="wm-badge">'.esc_html((string)($r['score'] ?? 0)).'</span>'
            .'<span>'.esc_html((string)($r['source'] ?? '')).'</span>'
            .'<span>'.esc_html(wp_date('Y-m-d H:i', (int)($r['time'] ?? time()))).'</span>'
            .'</div></article>';
    }
    return $html;
}
}

