    <script>
    (function(){
      const root=document.getElementById(<?php echo wp_json_encode($uid); ?>); if(!root) return;
      const ajaxUrl=<?php echo wp_json_encode(admin_url('admin-ajax.php')); ?>;
      const state={data:<?php echo wp_json_encode($data); ?>,days:<?php echo (int)$days; ?>,maps:{},charts:{}};
      function esc(s){return String(s==null?'':s).replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[m]));}
      function arabicTime(ts){try{return new Date(ts*1000).toLocaleString('ar-LB');}catch(e){return ''}}
      function sevColor(sev){if(sev==='critical') return '#ef4444'; if(sev==='high') return '#f59e0b'; if(sev==='moderate') return '#eab308'; return '#22c55e';}
      function listRows(rows){if(!rows||!rows.length) return '<div class="wmx-item">لا توجد بيانات</div>'; const max=Math.max(1,...rows.map(r=>parseInt(r.count||0,10))); return rows.map(r=>`<div class="wmx-row"><strong>${esc(r.name)}</strong><div class="wmx-bar"><i style="width:${Math.max(8,Math.round((parseInt(r.count||0,10)/max)*100))}%"></i></div><b>${esc(r.count)}</b></div>`).join('');}
      function feedRows(rows){if(!rows||!rows.length) return '<div class="wmx-item">لا توجد بيانات بعد</div>'; return rows.map(r=>{const t=esc(r.title); const link=r.link?`<a href="${esc(r.link)}" target="_blank" rel="noopener">${t}</a>`:t; return `<article class="wmx-item"><h4>${link}</h4><div class="wmx-meta"><span class="wmx-badge">${esc(r.region||'عام')}</span><span class="wmx-badge">${esc(r.actor||'غير محدد')}</span><span class="wmx-badge">${esc(r.type||'عام')}</span><span class="wmx-badge">النقاط: ${esc(r.score||0)}</span><span>${esc(r.source||'النظام')}</span><span>${esc(arabicTime(r.time||0))}</span></div></article>`}).join('');}
      function setHtml(id,html){const el=document.getElementById(id); if(el) el.innerHTML=html;}
      function setText(id,val){const el=document.getElementById(id); if(el) el.textContent=val;}
      function initMap(id){if(state.maps[id]||typeof L==='undefined') return; const map=L.map(id,{zoomControl:true}).setView([28,20],3); L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png',{subdomains:'abcd',maxZoom:19}).addTo(map); state.maps[id]={map:map,layer:L.layerGroup().addTo(map)}; setTimeout(()=>map.invalidateSize(),160);}
      function renderMap(id){initMap(id); const obj=state.maps[id]; if(!obj) return; obj.layer.clearLayers(); const points=[]; (state.data.markers||[]).forEach(m=>{ if(!m.lat||!m.lon) return; points.push([m.lat,m.lon]); const marker=L.circleMarker([m.lat,m.lon],{radius:6,color:sevColor(m.severity),fillColor:sevColor(m.severity),fillOpacity:.85,weight:1}).addTo(obj.layer); marker.bindPopup(`<div style="direction:rtl;text-align:right;min-width:180px"><b>${esc(m.title)}</b><br>${esc(m.region)} — ${esc(m.actor)}<br>النوع: ${esc(m.type)}<br>النقاط: ${esc(m.score)}</div>`);}); if(points.length){obj.map.fitBounds(points,{padding:[20,20]});} else {obj.map.setView([28,20],3);} }
      function chart(id,config){const el=document.getElementById(id); if(!el||typeof Chart==='undefined') return; if(state.charts[id]) state.charts[id].destroy(); state.charts[id]=new Chart(el.getContext('2d'),config);}
      function topN(rows,n){return (rows||[]).slice(0,n||8)}
      function renderCharts(){const k=state.data.kpi||{}; chart(<?php echo wp_json_encode($uid.'_severity'); ?>,{type:'doughnut',data:{labels:['حرج','مرتفع','متوسط','منخفض'],datasets:[{data:[k.critical||0,k.high||0,k.moderate||0,k.low||0],backgroundColor:['#ef4444','#f59e0b','#eab308','#22c55e'],borderWidth:0}]},options:{plugins:{legend:{position:'bottom',labels:{color:'#cbd5e1',boxWidth:10}}}}}); chart(<?php echo wp_json_encode($uid.'_types'); ?>,{type:'bar',data:{labels:topN(state.data.types,8).map(x=>x.name),datasets:[{data:topN(state.data.types,8).map(x=>x.count),backgroundColor:'#38bdf8',borderRadius:6}]},options:{plugins:{legend:{display:false}},scales:{x:{ticks:{color:'#94a3b8'}},y:{ticks:{color:'#94a3b8'},beginAtZero:true}}}}); chart(<?php echo wp_json_encode($uid.'_trend'); ?>,{type:'line',data:{labels:(state.data.trend||[]).map(x=>x.date),datasets:[{data:(state.data.trend||[]).map(x=>x.count),borderColor:'#f97316',backgroundColor:'rgba(249,115,22,.15)',fill:true,tension:.35}]},options:{plugins:{legend:{display:false}},scales:{x:{ticks:{color:'#94a3b8'}},y:{ticks:{color:'#94a3b8'},beginAtZero:true}}}}); chart(<?php echo wp_json_encode($uid.'_regions2'); ?>,{type:'bar',data:{labels:topN(state.data.regions,10).map(x=>x.name),datasets:[{data:topN(state.data.regions,10).map(x=>x.count),backgroundColor:'#22c55e',borderRadius:6}]},options:{indexAxis:'y',plugins:{legend:{display:false}},scales:{x:{ticks:{color:'#94a3b8'},beginAtZero:true},y:{ticks:{color:'#cbd5e1'}}}}}); }
      function renderAll(){const d=state.data||{}; const k=d.kpi||{}; setText(<?php echo wp_json_encode($uid . '_k_total'); ?>, k.total||0); setText(<?php echo wp_json_encode($uid . '_k_critical'); ?>, k.critical||0); setText(<?php echo wp_json_encode($uid . '_k_high'); ?>, k.high||0); setText(<?php echo wp_json_encode($uid . '_k_moderate'); ?>, k.moderate||0); setText(<?php echo wp_json_encode($uid . '_k_low'); ?>, k.low||0); setText(<?php echo wp_json_encode($uid . '_k_countries'); ?>, k.countries||0); setText(<?php echo wp_json_encode($uid . '_k_hotspots'); ?>, k.hotspots||0); setText(<?php echo wp_json_encode($uid . '_k_updated'); ?>, arabicTime(k.updated_at||0)); setText(<?php echo wp_json_encode($uid . '_days_lbl'); ?>, state.days); setText(<?php echo wp_json_encode($uid . '_range_text'); ?>, state.days+' يوم'); setText(<?php echo wp_json_encode($uid . '_marker_count'); ?>, (d.markers||[]).length); setHtml(<?php echo wp_json_encode($uid . '_feed_overview'); ?>, feedRows((d.feed||[]).slice(0,12))); setHtml(<?php echo wp_json_encode($uid . '_feed_full'); ?>, feedRows(d.feed||[])); setHtml(<?php echo wp_json_encode($uid . '_regions_list'); ?>, listRows(d.regions||[])); setHtml(<?php echo wp_json_encode($uid . '_actors_list'); ?>, listRows(d.actors||[])); setHtml(<?php echo wp_json_encode($uid . '_regions_feed'); ?>, listRows(d.regions||[])); setHtml(<?php echo wp_json_encode($uid . '_actors_feed'); ?>, listRows(d.actors||[])); renderMap(<?php echo wp_json_encode($uid . '_map_overview'); ?>); renderMap(<?php echo wp_json_encode($uid . '_map_full'); ?>); renderCharts(); }
      function load(days){state.days=days||state.days; const body=new URLSearchParams({action:'so_world_monitor_snapshot_v2',days:String(state.days)}); fetch(ajaxUrl,{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded; charset=UTF-8'},body:body.toString()}).then(r=>r.json()).then(j=>{if(j&&j.success&&j.data){state.data=j.data; renderAll();}}).catch(()=>{});}
      root.querySelectorAll('.wmx-tab').forEach(btn=>btn.addEventListener('click',function(){root.querySelectorAll('.wmx-tab').forEach(b=>b.classList.remove('is-active')); this.classList.add('is-active'); const key=this.getAttribute('data-target'); const target=document.getElementById(<?php echo wp_json_encode($uid); ?>+'_'+key); if(target){target.scrollIntoView({behavior:'smooth',block:'start'});} }));
      root.querySelectorAll('.wmx-range').forEach(btn=>btn.addEventListener('click',function(){root.querySelectorAll('.wmx-range').forEach(b=>b.classList.remove('is-active')); btn.classList.add('is-active'); load(parseInt(btn.getAttribute('data-days')||'7',10));}));
      renderAll(); setInterval(function(){load(state.days);}, <?php echo (int)$refresh * 1000; ?>);
    })();
    </script>
    <?php return (string)ob_get_clean();
}
}

