/* WORLD MONITOR DATA HOTFIX */
if (!function_exists('sod_wm_hotfix_columns')) {
function sod_wm_hotfix_columns(string $table): array {
    global $wpdb;
    $cols = [];
    $rows = (array) $wpdb->get_results("SHOW COLUMNS FROM {$table}", ARRAY_A);
    foreach ($rows as $row) {
        $name = (string)($row['Field'] ?? '');
        if ($name !== '') $cols[$name] = true;
    }
    return $cols;
}
}

if (!function_exists('sod_wm_hotfix_pick')) {
function sod_wm_hotfix_pick(array $cols, array $candidates, string $default = "''"): string {
    foreach ($candidates as $c) {
        if (isset($cols[$c])) return $c;
    }
    return $default;
}
}

if (!function_exists('sod_wm_hotfix_snapshot')) {
function sod_wm_hotfix_snapshot(int $days = 7, int $limit = 250): array {
    global $wpdb;
    $days = max(1, min(365, $days));
    $limit = max(20, min(500, $limit));
    $table = $wpdb->prefix . 'so_news_events';
    $rows = [];
    if ($wpdb->get_var($wpdb->prepare('SHOW TABLES LIKE %s', $table)) === $table) {
        $cols = sod_wm_hotfix_columns($table);
        $title_col  = sod_wm_hotfix_pick($cols, ['title'], "''");
        $region_col = sod_wm_hotfix_pick($cols, ['region','agency_loc'], "''");
        $actor_col  = sod_wm_hotfix_pick($cols, ['actor_v2','primary_actor'], "''");
        $type_col   = sod_wm_hotfix_pick($cols, ['intel_type','event_type'], "''");
        $score_col  = sod_wm_hotfix_pick($cols, ['score','threat_score'], '0');
        $ts_col     = sod_wm_hotfix_pick($cols, ['event_timestamp','created_at'], 'UNIX_TIMESTAMP()');
        $status_col = sod_wm_hotfix_pick($cols, ['status'], "''");
        $source_col = sod_wm_hotfix_pick($cols, ['source_name','source'], "''");
        $link_col   = sod_wm_hotfix_pick($cols, ['link'], "''");
        $field_col  = sod_wm_hotfix_pick($cols, ['field_data'], "''");
        $hybrid_col = sod_wm_hotfix_pick($cols, ['hybrid_layers'], "''");
        $war_col    = sod_wm_hotfix_pick($cols, ['war_data'], "''");
        $where = [];
        if ($status_col != "''") {
            $where[] = "({$status_col}='published' OR {$status_col}='publish' OR {$status_col}='approved' OR {$status_col}='active' OR {$status_col}='')";
        }
        if ($ts_col != 'UNIX_TIMESTAMP()') {
            $cutoff = time() - ($days * DAY_IN_SECONDS);
            $where[] = $wpdb->prepare("{$ts_col} >= %d", $cutoff);
        }
        $where_sql = $where ? ('WHERE ' . implode(' AND ', $where)) : '';
        $sql = "SELECT id,
            {$title_col} AS title,
            {$region_col} AS region,
            {$actor_col} AS actor,
            {$type_col} AS intel_type,
            {$score_col} AS score,
            {$ts_col} AS event_timestamp,
            {$source_col} AS source_name,
            {$link_col} AS link,
            {$field_col} AS field_data,
            {$hybrid_col} AS hybrid_layers,
            {$war_col} AS war_data
            FROM {$table}
            {$where_sql}
            ORDER BY " . ($ts_col != 'UNIX_TIMESTAMP()' ? $ts_col : 'id') . " DESC
            LIMIT " . intval($limit);
        $rows = (array) $wpdb->get_results($sql, ARRAY_A);
        if (!$rows && $status_col != "''") {
            $sql = "SELECT id,
                {$title_col} AS title,
                {$region_col} AS region,
                {$actor_col} AS actor,
                {$type_col} AS intel_type,
                {$score_col} AS score,
                {$ts_col} AS event_timestamp,
                {$source_col} AS source_name,
                {$link_col} AS link,
                {$field_col} AS field_data,
                {$hybrid_col} AS hybrid_layers,
                {$war_col} AS war_data
                FROM {$table}
                WHERE ({$status_col}='published' OR {$status_col}='publish' OR {$status_col}='approved' OR {$status_col}='active' OR {$status_col}='')
                ORDER BY " . ($ts_col != 'UNIX_TIMESTAMP()' ? $ts_col : 'id') . " DESC
                LIMIT " . intval($limit);
            $rows = (array) $wpdb->get_results($sql, ARRAY_A);
        }
    }
    if (!$rows) {
        $posts = $wpdb->posts;
        $rows = (array) $wpdb->get_results($wpdb->prepare("SELECT ID AS id, post_title AS title, post_date_gmt, guid AS link FROM {$posts} WHERE post_status='publish' AND post_type='post' ORDER BY post_date_gmt DESC LIMIT %d", $limit), ARRAY_A);
        foreach ($rows as &$row) {
            $id = (int)($row['id'] ?? 0);
            $row['event_timestamp'] = !empty($row['post_date_gmt']) ? strtotime((string)$row['post_date_gmt']) : time();
            $row['region'] = get_post_meta($id, 'region', true) ?: get_post_meta($id, 'so_region', true) ?: 'عام';
            $row['actor'] = get_post_meta($id, 'actor_v2', true) ?: get_post_meta($id, 'primary_actor', true) ?: get_post_meta($id, 'so_actor', true) ?: 'غير محدد';
            $row['intel_type'] = get_post_meta($id, 'intel_type', true) ?: get_post_meta($id, 'event_type', true) ?: 'عام';
            $row['score'] = (int)(get_post_meta($id, 'score', true) ?: get_post_meta($id, 'threat_score', true) ?: get_post_meta($id, 'so_score', true) ?: 0);
            $row['source_name'] = 'WordPress';
            $row['field_data'] = get_post_meta($id, 'field_data', true) ?: '';
            $row['hybrid_layers'] = get_post_meta($id, 'hybrid_layers', true) ?: '';
            $row['war_data'] = get_post_meta($id, 'war_data', true) ?: '';
        }
        unset($row);
    }

    $known = function_exists('sod_wm_v2_known_coords') ? sod_wm_v2_known_coords() : [];
    $total = $critical = $high = $moderate = $low = 0;
    $regions = []; $actors = []; $types = []; $trend = []; $markers = []; $feed = []; $hybrid_layers = [];
    foreach ($rows as $row) {
        $title = wp_strip_all_tags((string)($row['title'] ?? ''));
        if ($title === '') continue;
        $total++;
        $score = (int)($row['score'] ?? 0);
        if ($score >= 140) $critical++; elseif ($score >= 100) $high++; elseif ($score >= 60) $moderate++; else $low++;
        $region = sanitize_text_field((string)($row['region'] ?: 'عام'));
        $actor = sanitize_text_field((string)($row['actor'] ?: 'غير محدد'));
        $type = sanitize_text_field((string)($row['intel_type'] ?: 'عام'));
        $ts = (int)($row['event_timestamp'] ?: time());
        if ($ts < 1000000000) $ts = time();
        $regions[$region] = ($regions[$region] ?? 0) + 1;
        $actors[$actor] = ($actors[$actor] ?? 0) + 1;
        $types[$type] = ($types[$type] ?? 0) + 1;
        $layers = [];
        $raw_layers = (string)($row['hybrid_layers'] ?? '');
        if ($raw_layers !== '') {
            $decoded_layers = json_decode($raw_layers, true);
            if (is_array($decoded_layers)) {
                $layers = $decoded_layers;
            } else {
                $layers = preg_split('/[,\|،]+/u', $raw_layers) ?: [];
            }
        }
        if (!$layers) {
            $war_data = json_decode((string)($row['war_data'] ?? ''), true);
            if (is_array($war_data) && !empty($war_data['hybrid_layers'])) {
                $tmp_layers = $war_data['hybrid_layers'];
                $layers = is_array($tmp_layers) ? $tmp_layers : preg_split('/[,\|،]+/u', (string)$tmp_layers);
            }
        }
        foreach ((array)$layers as $layer_item) {
            $layer = sanitize_text_field(trim((string)$layer_item));
            if ($layer === '') continue;
            $hybrid_layers[$layer] = ($hybrid_layers[$layer] ?? 0) + 1;
        }
        $dayKey = wp_date('Y-m-d', $ts, wp_timezone());
        $trend[$dayKey] = ($trend[$dayKey] ?? 0) + 1;
        $coords = function_exists('sod_wm_v2_coords') ? sod_wm_v2_coords($region) : null;
        if (!$coords && isset($known[$region])) $coords = ['lat'=>(float)$known[$region][0],'lon'=>(float)$known[$region][1]];
        if ($coords && count($markers) < 200) {
            $markers[] = [
                'id' => (int)($row['id'] ?? 0),
                'title' => $title,
                'region' => $region,
                'actor' => $actor,
                'type' => $type,
                'score' => $score,
                'lat' => (float)$coords['lat'],
                'lon' => (float)$coords['lon'],
                'severity' => ($score >= 140 ? 'critical' : ($score >= 100 ? 'high' : ($score >= 60 ? 'moderate' : 'low'))),
                'time' => $ts,
                'link' => esc_url_raw((string)($row['link'] ?? '')),
            ];
        }
        if (count($feed) < 40) {
            $feed[] = [
                'id' => (int)($row['id'] ?? 0),
                'title' => $title,
                'region' => $region,
                'actor' => $actor,
                'type' => $type,
                'score' => $score,
                'source' => sanitize_text_field((string)($row['source_name'] ?? 'النظام')),
                'time' => $ts,
                'link' => esc_url_raw((string)($row['link'] ?? '')),
            ];
        }
    }
    arsort($regions); arsort($actors); arsort($types); arsort($hybrid_layers); ksort($trend);
    $risk_index = min(100, (int) round(
        (($critical * 4) + ($high * 3) + ($moderate * 2) + ($low)) / max(1, ($total * 4)) * 100
    ));
    $hybrid_intensity = min(100, (int) round((array_sum($hybrid_layers) / max(1, $total)) * 100));
    $top_layer = '';
    if (!empty($hybrid_layers)) {
        $top_layer = (string) array_key_first($hybrid_layers);
    }
    $recent_72h = array_values(array_filter($rows, static function ($row): bool {
        $ts = (int)($row['event_timestamp'] ?? 0);
        if ($ts < 1000000000) $ts = time();
        return $ts >= (time() - (72 * HOUR_IN_SECONDS));
    }));
    $threat_events_72h = array_map(static function ($row): array {
        $field_data = (string)($row['field_data'] ?? '');
        $war_data = (string)($row['war_data'] ?? '');
        if ($field_data === '') {
            $truth_layer = 'general';
            $score = (int)($row['score'] ?? 0);
            if ($score >= 140) $truth_layer = 'field_action';
            elseif ($score >= 100) $truth_layer = 'defensive_alert';
            elseif ($score >= 60) $truth_layer = 'report';
            $layers_seed = [];
            $raw_layers = (string)($row['hybrid_layers'] ?? '');
            if ($raw_layers !== '') {
                $decoded = json_decode($raw_layers, true);
                if (is_array($decoded)) {
                    $layers_seed = $decoded;
                } else {
                    $layers_seed = preg_split('/[,\|،]+/u', $raw_layers) ?: [];
                }
            }
            $field_data = wp_json_encode([
                'truth_layer' => $truth_layer,
                'hybrid_layers' => array_values(array_filter(array_map('strval', (array)$layers_seed))),
            ]);
        }
        return [
            'score' => (int)($row['score'] ?? 0),
            'region' => sanitize_text_field((string)($row['region'] ?? 'عام')),
            'actor_v2' => sanitize_text_field((string)($row['actor'] ?? 'غير محدد')),
            'intel_type' => sanitize_text_field((string)($row['intel_type'] ?? 'عام')),
            'tactical_level' => 'تكتيكي',
            'event_timestamp' => (int)($row['event_timestamp'] ?? time()),
            'field_data' => (string)$field_data,
            'war_data' => (string)$war_data,
        ];
    }, $recent_72h);
    $threat_events_24h = array_values(array_filter($threat_events_72h, static function ($event): bool {
        return (int)($event['event_timestamp'] ?? 0) >= (time() - DAY_IN_SECONDS);
    }));
    $analytics_24h = sod_build_analytics($threat_events_24h);
    $analytics_72h = sod_build_analytics($threat_events_72h);
    $actor_threats = [];
    foreach ((array)($analytics_24h['actors'] ?? []) as $actor_name => $score_total) {
        $actor_threats[] = [
            'actor' => (string)$actor_name,
            'score' => (int)$score_total,
            'events' => count(array_filter($threat_events_24h, static function ($event) use ($actor_name): bool {
                return (string)($event['actor_v2'] ?? '') === (string)$actor_name;
            })),
        ];
    }
    usort($actor_threats, static function ($a, $b): int {
        $score_cmp = ((int)($b['score'] ?? 0)) <=> ((int)($a['score'] ?? 0));
        if ($score_cmp !== 0) return $score_cmp;
        return ((int)($b['events'] ?? 0)) <=> ((int)($a['events'] ?? 0));
    });
    $trend_data = [];
    for ($i = 11; $i >= 0; $i--) {
        $h_start = strtotime("-{$i} hours");
        $h_key = gmdate('Y-m-d H:00', $h_start);
        $trend_data[$h_key] = (int)($analytics_72h['hourly'][$h_key] ?? 0);
    }
    $top_regions_24h = [];
    foreach (array_slice((array)($analytics_24h['region_scores'] ?? []), 0, 8, true) as $region_name => $score_total) {
        $top_regions_24h[] = ['name' => (string)$region_name, 'score' => (int)$score_total];
    }
    $momentum_change = 0;
    if (!empty($analytics_72h['total']) && !empty($analytics_24h['total'])) {
        $expected_24h = (float)$analytics_72h['total'] / 3;
        $momentum_change = $expected_24h > 0 ? (int)round((((int)$analytics_24h['total'] - $expected_24h) / $expected_24h) * 100) : 0;
    }
    $ticker_items = $feed;
    usort($ticker_items, static function ($a, $b): int {
        $score_cmp = ((int)($b['score'] ?? 0)) <=> ((int)($a['score'] ?? 0));
        if ($score_cmp !== 0) return $score_cmp;
        return ((int)($b['time'] ?? 0)) <=> ((int)($a['time'] ?? 0));
    });
    $ticker_items = array_slice(array_map(static function ($item): array {
        return [
            'title' => (string)($item['title'] ?? ''),
            'score' => (int)($item['score'] ?? 0),
            'region' => (string)($item['region'] ?? 'عام'),
            'type' => (string)($item['type'] ?? 'عام'),
            'time' => (int)($item['time'] ?? time()),
        ];
    }, $ticker_items), 0, 20);
    $video_streams = function_exists('sod_wm_hotfix_video_streams') ? sod_wm_hotfix_video_streams(6) : [];
    return [
        'kpi' => [
            'total' => $total,
            'critical' => $critical,
            'high' => $high,
            'moderate' => $moderate,
            'low' => $low,
            'countries' => count($regions),
            'hotspots' => count(array_filter($regions, static fn($v) => (int)$v >= 2)),
            'risk_index' => $risk_index,
            'hybrid_intensity' => $hybrid_intensity,
            'top_hybrid_layer' => $top_layer,
            'updated_at' => time(),
        ],
        'trend' => array_map(static fn($d,$v) => ['date'=>$d,'count'=>$v], array_keys($trend), array_values($trend)),
        'regions' => array_slice(array_map(static fn($n,$v) => ['name'=>$n,'count'=>$v], array_keys($regions), array_values($regions)), 0, 12),
        'actors' => array_slice(array_map(static fn($n,$v) => ['name'=>$n,'count'=>$v], array_keys($actors), array_values($actors)), 0, 12),
        'types' => array_slice(array_map(static fn($n,$v) => ['name'=>$n,'count'=>$v], array_keys($types), array_values($types)), 0, 12),
        'hybrid_layers' => array_slice(array_map(static fn($n,$v) => ['name'=>$n,'count'=>$v], array_keys($hybrid_layers), array_values($hybrid_layers)), 0, 12),
        'markers' => $markers,
        'feed' => $feed,
        'ticker_items' => $ticker_items,
        'threat_overview' => [
            'analytics_24h' => [
                'total' => (int)($analytics_24h['total'] ?? 0),
                'critical' => (int)($analytics_24h['critical'] ?? 0),
                'avg_score' => (int)($analytics_24h['avg_score'] ?? 0),
                'hot_region' => (string)($analytics_24h['hot_region'] ?? ''),
                'escalation_index' => (int)($analytics_24h['escalation_index'] ?? 0),
                'deception_index' => (int)($analytics_24h['deception_index'] ?? 0),
                'gci' => (int)($analytics_24h['gci'] ?? 0),
                'truth_layers' => (array)($analytics_24h['truth_layers'] ?? []),
                'war_directions' => (array)($analytics_24h['war_directions'] ?? []),
                'early_warnings' => array_values(array_slice((array)($analytics_24h['early_warnings'] ?? []), 0, 3)),
            ],
            'analytics_72h' => [
                'total' => (int)($analytics_72h['total'] ?? 0),
                'critical' => (int)($analytics_72h['critical'] ?? 0),
                'avg_score' => (int)($analytics_72h['avg_score'] ?? 0),
            ],
            'actor_threats' => array_values(array_slice($actor_threats, 0, 8)),
            'top_regions' => $top_regions_24h,
            'trend_data' => $trend_data,
            'momentum_change' => $momentum_change,
        ],
        'video_streams' => $video_streams,
        'days' => $days,
        'source_count' => $total,
    ];
}
}

if (!function_exists('sod_wm_hotfix_video_streams')) {
function sod_wm_hotfix_video_streams(int $limit = 6): array {
    $limit = max(1, min(12, $limit));
    $streams = get_option('so_video_streams', []);
    if (!is_array($streams)) return [];
    $out = [];
    foreach ($streams as $stream) {
        if (!is_array($stream)) continue;
        $name = sanitize_text_field((string)($stream['name'] ?? ''));
        $url = esc_url_raw((string)($stream['url'] ?? ''));
        $type = sanitize_key((string)($stream['type'] ?? 'live'));
        if ($name === '' || $url === '') continue;
        if (!in_array($type, ['live', 'camera', 'embed'], true)) $type = 'live';
        $out[] = [
            'name' => $name,
            'url' => $url,
            'type' => $type,
        ];
        if (count($out) >= $limit) break;
    }
    return $out;
}
}

if (!function_exists('sod_wm_hotfix_ajax_snapshot')) {
function sod_wm_hotfix_ajax_snapshot(): void {
    $days = isset($_REQUEST['days']) ? (int) $_REQUEST['days'] : 7;
    wp_send_json_success(sod_wm_hotfix_snapshot($days));
}
}
add_action('wp_ajax_so_world_monitor_snapshot_hotfix', 'sod_wm_hotfix_ajax_snapshot');
add_action('wp_ajax_nopriv_so_world_monitor_snapshot_hotfix', 'sod_wm_hotfix_ajax_snapshot');


