              <article class="wmv5-panel"><div class="wmv5-panel-hd"><h3>البث الاستخباراتي</h3><small>آخر الأحداث من المصدر</small></div><div class="wmv5-feed" id="<?php echo esc_attr($uid.'_feed1'); ?>"><?php echo sod_wm_v2_render_feed_rows($data['feed'] ?? []); ?></div></article>
              <div class="wmv5-grid-3" style="grid-template-columns:1fr;">
                <article class="wmv5-panel"><div class="wmv5-panel-hd"><h3>يوتيوب والبث المرئي</h3><small>قنوات مضمنة وروابط مباشرة</small></div><div id="<?php echo esc_attr($uid.'_video_live'); ?>"></div></article>
                <article class="wmv5-panel"><div class="wmv5-panel-hd"><h3>أفضل الجهات</h3><small>تكرار حي</small></div><div class="wmv5-ranks" id="<?php echo esc_attr($uid.'_actors_live'); ?>"></div></article>
                <article class="wmv5-panel"><div class="wmv5-panel-hd"><h3>القطاعات الرئيسية</h3><small>نشاط اللحظة</small></div><div class="wmv5-ranks" id="<?php echo esc_attr($uid.'_types_live'); ?>"></div></article>
              </div>
            </div>
          </div>

          <div class="wmv5-view" data-panel="analysis">
            <div class="wmv5-grid-4">
              <article class="wmv5-panel"><div class="wmv5-panel-hd"><h3>اتجاه الأحداث</h3><small>حسب الأيام</small></div><div class="wmv5-chart"><canvas id="<?php echo esc_attr($uid.'_trend'); ?>"></canvas></div></article>
              <article class="wmv5-panel"><div class="wmv5-panel-hd"><h3>توزيع القطاعات</h3><small>أكثر الأنواع</small></div><div class="wmv5-chart"><canvas id="<?php echo esc_attr($uid.'_types'); ?>"></canvas></div></article>
              <article class="wmv5-panel"><div class="wmv5-panel-hd"><h3>الدول / المناطق</h3><small>Top انتشار</small></div><div class="wmv5-chart"><canvas id="<?php echo esc_attr($uid.'_regions3'); ?>"></canvas></div></article>
              <article class="wmv5-panel"><div class="wmv5-panel-hd"><h3>المناطق الأكثر نشاطًا</h3><small>ترتيب سريع</small></div><div class="wmv5-ranks" id="<?php echo esc_attr($uid.'_regions_analysis'); ?>"></div></article>
              <article class="wmv5-panel"><div class="wmv5-panel-hd"><h3>طبقات الحرب المركبة</h3><small>أكثر الطبقات نشاطًا</small></div><div class="wmv5-chart"><canvas id="<?php echo esc_attr($uid.'_hybrid_layers'); ?>"></canvas></div></article>
              <article class="wmv5-panel"><div class="wmv5-panel-hd"><h3>قياس المخاطر</h3><small>Risk + Hybrid KPI</small></div><div class="wmv5-risk"><div class="wmv5-risk-meter"><i id="<?php echo esc_attr($uid.'_risk_meter'); ?>" style="width:0%"></i></div><div class="wmv5-risk-kpi"><div><b id="<?php echo esc_attr($uid.'_risk_level'); ?>">—</b><span>تصنيف المخاطر</span></div><div><b id="<?php echo esc_attr($uid.'_top_hybrid'); ?>">—</b><span>أعلى طبقة مركبة</span></div><div><b id="<?php echo esc_attr($uid.'_marker_density'); ?>">0%</b><span>كثافة النقاط</span></div></div></div></article>
            </div>
          </div>
        </section>
      </div>
    <script>
    (function(){
      const root=document.getElementById(<?php echo wp_json_encode($uid); ?>); if(!root) return;
      const ajaxUrl=<?php echo wp_json_encode(admin_url('admin-ajax.php')); ?>;
      const state={days:<?php echo (int)$days; ?>,data:<?php echo wp_json_encode($data); ?>,charts:{},map:null,layer:null,active:'overview'};
      function esc(s){return String(s==null?'':s).replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[m]));}
      function text(id,v){const el=document.getElementById(id); if(el) el.textContent=v;}
      function html(id,v){const el=document.getElementById(id); if(el) el.innerHTML=v;}
      function when(ts){try{return new Date(ts*1000).toLocaleString('ar-LB');}catch(e){return ''}}
      function sevColor(s){return s==='critical'?'#ef4444':(s==='high'?'#f59e0b':(s==='moderate'?'#eab308':'#22c55e'));}
      function riskLabel(v){const n=parseInt(v||0,10); if(n>=80) return 'حرج'; if(n>=60) return 'مرتفع'; if(n>=35) return 'متوسط'; return 'منخفض';}
      function rankRows(rows){if(!rows||!rows.length) return '<div class="wmv5-item">لا توجد بيانات</div>'; const max=Math.max(1,...rows.map(r=>parseInt(r.count||0,10))); return rows.map(r=>`<div class="wmv5-row"><strong>${esc(r.name)}</strong><div class="wmv5-bar"><i style="width:${Math.max(8,Math.round((parseInt(r.count||0,10)/max)*100))}%"></i></div><b>${esc(r.count)}</b></div>`).join('');}
      function feedRows(rows){if(!rows||!rows.length) return '<div class="wmv5-item">لا توجد بيانات بعد</div>'; return rows.map(r=>{const title=esc(r.title||''); const link=r.link?`<a href="${esc(r.link)}" target="_blank" rel="noopener">${title}</a>`:title; return `<article class="wmv5-item"><h4>${link}</h4><div class="wmv5-meta"><span class="wmv5-badge">${esc(r.region||'عام')}</span><span class="wmv5-badge">${esc(r.actor||'غير محدد')}</span><span class="wmv5-badge">${esc(r.type||'عام')}</span><span class="wmv5-badge">${esc(r.score||0)} نقطة</span><span>${esc(r.source||'النظام')}</span><span>${esc(when(r.time||0))}</span></div></article>`}).join('');}
      function summaryCards(){const k=state.data.kpi||{}; const a=(((state.data.actors||[])[0] && (state.data.actors||[])[0].name) ? (state.data.actors||[])[0].name : '')||'—'; const r=(((state.data.regions||[])[0] && (state.data.regions||[])[0].name) ? (state.data.regions||[])[0].name : '')||'—'; const t=(((state.data.types||[])[0] && (state.data.types||[])[0].name) ? (state.data.types||[])[0].name : '')||'—'; const h=(((state.data.hybrid_layers||[])[0] && (state.data.hybrid_layers||[])[0].name) ? (state.data.hybrid_layers||[])[0].name : '')||'—'; const rows=[['أعلى جهة',a],['أهم منطقة',r],['أبرز قطاع',t],['أعلى طبقة مركبة',h],['مؤشر المخاطر',String(k.risk_index||0)],['شدة الحرب المركبة',String(k.hybrid_intensity||0)+'%']]; return rows.map(x=>`<div class="wmv5-summary-card"><b>${esc(x[0])}</b><span>${esc(x[1])}</span></div>`).join('');}
      function shortText(s,n){const t=String(s==null?'':s);return t.length>n?t.slice(0,Math.max(0,n-1))+'…':t;}
      function signedPct(v){const n=parseInt(v||0,10);return `${n>0?'+':''}${n}%`;}
      function toYouTubeEmbed(url){
        const raw=String(url||'').trim(); if(!raw) return '';
        if(raw.includes('/embed/')) return raw;
        let m=raw.match(/youtu\.be\/([a-zA-Z0-9_-]{11})/); if(m) return `https://www.youtube.com/embed/${m[1]}?rel=0&playsinline=1`;
        m=raw.match(/[?&]v=([a-zA-Z0-9_-]{11})/); if(m) return `https://www.youtube.com/embed/${m[1]}?rel=0&playsinline=1`;
        m=raw.match(/youtube\.com\/live\/([a-zA-Z0-9_-]{11})/); if(m) return `https://www.youtube.com/embed/${m[1]}?rel=0&playsinline=1`;
        m=raw.match(/youtube\.com\/shorts\/([a-zA-Z0-9_-]{11})/); if(m) return `https://www.youtube.com/embed/${m[1]}?rel=0&playsinline=1`;
        return raw;
      }
      function tickerRows(items){
        if(!items||!items.length) return '<span class="wmv5-tick">لا توجد أحداث متحركة حاليًا</span>';
        const cells=items.slice(0,12).map(item=>`<span class="wmv5-tick"><b>${esc(item.score||0)}</b><span>${esc(shortText(item.title||'',72))}</span><em>${esc(item.region||'عام')}</em></span>`);
        return cells.concat(cells).join('');
      }
      function commandDeck(){
        const d=state.data||{}, k=d.kpi||{}, th=d.threat_overview||{}, a24=th.analytics_24h||{};
        const topActor=(((th.actor_threats||[])[0] && (th.actor_threats||[])[0].actor) ? (th.actor_threats||[])[0].actor : '') || (((d.actors||[])[0] && (d.actors||[])[0].name) ? (d.actors||[])[0].name : '') || '—';
        const topRegion=(((th.top_regions||[])[0] && (th.top_regions||[])[0].name) ? (th.top_regions||[])[0].name : '') || a24.hot_region || (((d.regions||[])[0] && (d.regions||[])[0].name) ? (d.regions||[])[0].name : '') || '—';
        const momentum=parseInt(th.momentum_change||0,10);
        const warDirs=a24.war_directions||{};
        const trendLabel=(warDirs.escalating||0)>(warDirs['de-escalating']||0)?'تصاعدي':((warDirs['de-escalating']||0)>(warDirs.escalating||0)?'انفراجي':'متوازن');
        const action=(k.risk_index||0)>=80?'رفع وتيرة الإنذار ومراقبة الساحة الأعلى أولوية.':(momentum>=15?'زيادة التحديث على مدار الساعة مع متابعة الفاعل الأعلى نشاطًا.':((k.hybrid_intensity||0)>=45?'تركيز الرصد على الطبقات المركبة والتقاطعات الإعلامية/السياسية.':'الاستمرار في المراقبة والتحقق مع تحديث دوري للساحة الأهم.'));
        return `<div class="wmv5-command">
          <div class="wmv5-command-hero">
            <div class="wmv5-command-title"><b>المشهد الآن: ${esc(riskLabel(k.risk_index||0))}</b><span>GCI ${esc(a24.gci||0)} • تصعيد ${esc(a24.escalation_index||0)}%</span></div>
            <div class="wmv5-command-note">الساحة الأكثر سخونة الآن هي <b>${esc(topRegion)}</b>، بينما الجهة الأعلى تأثيرًا هي <b>${esc(topActor)}</b>. اتجاه الصراع الحالي <b>${esc(trendLabel)}</b> مع زخم <b>${esc(signedPct(momentum))}</b>. التوصية التشغيلية: <b>${esc(action)}</b></div>
            <div class="wmv5-summary">${summaryCards()}</div>
          </div>
          <div class="wmv5-command-side">
            <div class="wmv5-mini-grid">
              <div class="wmv5-mini-card"><b>${esc(k.risk_index||0)}</b><span>مؤشر المخاطر</span></div>
              <div class="wmv5-mini-card"><b>${esc(a24.escalation_index||0)}%</b><span>التصعيد 24س</span></div>
              <div class="wmv5-mini-card"><b>${esc(signedPct(momentum))}</b><span>الزخم</span></div>
              <div class="wmv5-mini-card"><b>${esc(a24.deception_index||0)}%</b><span>الخداع</span></div>
            </div>
            <div class="wmv5-chip-row">
              <span class="wmv5-chip">الفاعل: ${esc(topActor)}</span>
              <span class="wmv5-chip">الساحة: ${esc(topRegion)}</span>
              <span class="wmv5-chip">الحرب المركبة: ${esc(k.top_hybrid_layer||'—')}</span>
              <span class="wmv5-chip">الخطورة الحرجة: ${esc(k.critical||0)}</span>
            </div>
          </div>
        </div>`;
      }
      function threatDeck(){
        const th=state.data.threat_overview||{}, a24=th.analytics_24h||{}, actors=(th.actor_threats||[]).slice(0,4), warnings=(a24.early_warnings||[]).slice(0,2), regions=(th.top_regions||[]).slice(0,4);
        const stats=[['التصعيد',`${a24.escalation_index||0}%`],['الزخم',signedPct(th.momentum_change||0)],['الخداع',`${a24.deception_index||0}%`],['الحرج',String(a24.critical||0)]];
        const actorHtml=actors.length?actors.map(item=>`<div class="wmv5-text-item"><b>${esc(item.actor||'غير محدد')}</b><small>${esc(item.score||0)} نقطة • ${esc(item.events||0)} حدث</small></div>`).join(''):'<div class="wmv5-text-item">لا توجد جهات مهددة بارزة خلال آخر 24 ساعة.</div>';
        const warningHtml=warnings.length?warnings.map(item=>`<div class="wmv5-text-item"><b>${esc(item.message||'تحذير')}</b><small>${esc(item.recommendation||'استمر بالمراقبة')}</small></div>`).join(''):regions.map(item=>`<div class="wmv5-text-item"><b>${esc(item.name||'عام')}</b><small>${esc(item.score||0)} نقطة ضغط</small></div>`).join('');
        return `<div class="wmv5-threat-wrap">
          <div class="wmv5-threat-stats">${stats.map(item=>`<div class="wmv5-threat-stat"><b>${esc(item[1])}</b><span>${esc(item[0])}</span></div>`).join('')}</div>
          <div class="wmv5-split-2">
            <div class="wmv5-text-list">${actorHtml}</div>
            <div class="wmv5-text-list">${warningHtml}</div>
          </div>
        </div>`;
      }
      function hybridDeck(){
        const d=state.data||{}, th=d.threat_overview||{}, a24=th.analytics_24h||{}, layers=(d.hybrid_layers||[]).slice(0,6), truth=a24.truth_layers||{}, dirs=a24.war_directions||{};
        const dirChips=[
          `ميداني ${truth.field_action||0}`,
          `تصريحات ${truth.statement||0}`,
          `تقارير ${truth.report||0}`,
          `اتجاه تصاعدي ${dirs.escalating||0}`
        ];
        const rows=layers.length?layers.map(item=>`<div class="wmv5-text-item"><b>${esc(item.name||'—')}</b><small>${esc(item.count||0)} تكرار • شدة عامة ${esc(((d.kpi && d.kpi.hybrid_intensity) ? d.kpi.hybrid_intensity : 0))}%</small></div>`).join(''):'<div class="wmv5-text-item">لا توجد طبقات حرب مركبة مرصودة حاليًا.</div>';
        return `<div class="wmv5-hybrid-wrap">
          <div class="wmv5-chip-row">${dirChips.map(label=>`<span class="wmv5-chip">${esc(label)}</span>`).join('')}</div>
          <div class="wmv5-text-list">${rows}</div>
        </div>`;
      }
      function videoCards(limit){
        const rows=(state.data.video_streams||[]).slice(0,limit||3);
        if(!rows.length) return '<div class="wmv5-video-stack"><div class="wmv5-text-item">لا توجد مصادر يوتيوب أو بث مضافة من إعدادات الفيديو داخل الإضافة.</div></div>';
        const labelMap={embed:'تضمين / يوتيوب',camera:'كاميرا',live:'بث مباشر'};
        return `<div class="wmv5-video-stack">${rows.map((item,index)=>{const rawUrl=String(item.url||''); const embedSrc=toYouTubeEmbed(rawUrl); const canEmbed=Boolean(embedSrc) && (embedSrc.includes('youtube.com') || embedSrc.includes('/embed/') || (item.type||'')==='embed'); const media=canEmbed?`<div class="wmv5-video-frame"><iframe src="${esc(embedSrc)}" allow="autoplay; encrypted-media; picture-in-picture" allowfullscreen referrerpolicy="strict-origin-when-cross-origin"></iframe></div>`:`<div class="wmv5-video-fallback"><a href="${esc(rawUrl)}" target="_blank" rel="noopener">فتح البث</a></div>`; return `<article class="wmv5-video-card ${index===0?'is-featured':''}">${media}<div class="wmv5-video-meta"><b>${esc(item.name||'بث مرئي')}</b><span>${esc(labelMap[item.type]||'بث')}</span></div></article>`;}).join('')}</div>`;
      }
      function ensureMap(){
        if(state.map||typeof L==='undefined') return;
        state.map=L.map(<?php echo wp_json_encode($uid.'_map1'); ?>,{zoomControl:true,worldCopyJump:true,minZoom:2,maxZoom:18}).setView([29,24],3);
        state.base=L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png',{
          subdomains:'abc',
          maxZoom:19,
          attribution:'&copy; OpenStreetMap contributors'
        }).addTo(state.map);
        state.layer=L.layerGroup().addTo(state.map);
        setTimeout(function(){ if(state.map){ state.map.invalidateSize(); } },250);
      }
      function renderMap(){
        if(state.active!=='map' && state.active!=='all') return;
        ensureMap();
        if(!state.map||!state.layer) return;
        state.layer.clearLayers();
        const pts=[];
        (state.data.markers||[]).forEach(m=>{
          if(!(m.lat&&m.lon)) return;
          pts.push([m.lat,m.lon]);
          const c=sevColor(m.severity);
          const mk=L.circleMarker([m.lat,m.lon],{radius:6,color:c,fillColor:c,fillOpacity:.9,weight:1}).addTo(state.layer);
          const link=m.url?`<div style="margin-top:6px"><a href="${esc(m.url)}" target="_blank" rel="noopener" style="color:#2563eb;text-decoration:none;font-weight:700">فتح الحدث</a></div>`:'';
          mk.bindPopup(`<div style="direction:rtl;text-align:right;min-width:190px"><b>${esc(m.title)}</b><br>${esc(m.region||'عام')} — ${esc(m.actor||'غير محدد')}<br>النوع: ${esc(m.type||'عام')}<br>النقاط: ${esc(m.score||0)}${link}</div>`);
        });
        if(pts.length){state.map.fitBounds(pts,{padding:[20,20]});} else {state.map.setView([29,24],3);}
        setTimeout(function(){ if(state.map){ state.map.invalidateSize(); } },100);
      }
      function draw(id,cfg){const el=document.getElementById(id); if(!el||typeof Chart==='undefined') return; if(state.charts[id]) state.charts[id].destroy(); state.charts[id]=new Chart(el.getContext('2d'),cfg);}
      function topN(rows,n){return (rows||[]).slice(0,n)}
      function renderCharts(){
        draw(<?php echo wp_json_encode($uid.'_types'); ?>,{type:'bar',data:{labels:topN(state.data.types,8).map(x=>x.name),datasets:[{data:topN(state.data.types,8).map(x=>x.count),backgroundColor:'#38bdf8',borderRadius:8}]},options:{plugins:{legend:{display:false}},scales:{x:{ticks:{color:'#9fb4cb'}},y:{ticks:{color:'#9fb4cb'},beginAtZero:true}}}});
        draw(<?php echo wp_json_encode($uid.'_trend'); ?>,{type:'line',data:{labels:(state.data.trend||[]).map(x=>x.date),datasets:[{data:(state.data.trend||[]).map(x=>x.count),borderColor:'#f97316',backgroundColor:'rgba(249,115,22,.14)',fill:true,tension:.35}]},options:{plugins:{legend:{display:false}},scales:{x:{ticks:{color:'#9fb4cb'}},y:{ticks:{color:'#9fb4cb'},beginAtZero:true}}}});
        const regionLabels=topN(state.data.regions,10).map(x=>x.name), regionData=topN(state.data.regions,10).map(x=>x.count);
        draw(<?php echo wp_json_encode($uid.'_regions2'); ?>,{type:'bar',data:{labels:regionLabels,datasets:[{data:regionData,backgroundColor:'#22c55e',borderRadius:8}]},options:{indexAxis:'y',plugins:{legend:{display:false}},scales:{x:{ticks:{color:'#9fb4cb'},beginAtZero:true},y:{ticks:{color:'#dbeafe'}}}}});
        draw(<?php echo wp_json_encode($uid.'_regions3'); ?>,{type:'bar',data:{labels:regionLabels,datasets:[{data:regionData,backgroundColor:'#22c55e',borderRadius:8}]},options:{plugins:{legend:{display:false}},scales:{x:{ticks:{color:'#9fb4cb'}},y:{ticks:{color:'#9fb4cb'},beginAtZero:true}}}});
        draw(<?php echo wp_json_encode($uid.'_hybrid_layers'); ?>,{type:'bar',data:{labels:topN(state.data.hybrid_layers,8).map(x=>x.name),datasets:[{data:topN(state.data.hybrid_layers,8).map(x=>x.count),backgroundColor:'#f43f5e',borderRadius:8}]},options:{plugins:{legend:{display:false}},scales:{x:{ticks:{color:'#9fb4cb'}},y:{ticks:{color:'#9fb4cb'},beginAtZero:true}}}});
        draw(<?php echo wp_json_encode($uid.'_severity'); ?>,{type:'doughnut',data:{labels:['حرج','مرتفع','متوسط','منخفض'],datasets:[{data:[parseInt(((state.data.kpi && state.data.kpi.critical) ? state.data.kpi.critical : 0),10),parseInt(((state.data.kpi && state.data.kpi.high) ? state.data.kpi.high : 0),10),parseInt(((state.data.kpi && state.data.kpi.moderate) ? state.data.kpi.moderate : 0),10),parseInt(((state.data.kpi && state.data.kpi.low) ? state.data.kpi.low : 0),10)],backgroundColor:['#ef4444','#f59e0b','#eab308','#22c55e'],borderWidth:0}]},options:{cutout:'58%',plugins:{legend:{display:false}}}});
      }
      function activateTab(key){state.active=key; root.querySelectorAll('.wmv5-tab').forEach(b=>b.classList.toggle('is-active',b.getAttribute('data-view')===key)); root.querySelectorAll('.wmv5-view').forEach(v=>v.classList.toggle('is-active',key==='all'||v.getAttribute('data-panel')===key)); if(key==='map'||key==='all'){setTimeout(function(){ renderMap(); },120);} if(key==='analysis'||key==='overview'||key==='map'||key==='all'){setTimeout(function(){ renderCharts(); },60);} }
      function renderAll(){const d=state.data||{},k=d.kpi||{}; text(<?php echo wp_json_encode($uid.'_days'); ?>,state.days); text(<?php echo wp_json_encode($uid.'_updated'); ?>,when(k.updated_at||0)); text(<?php echo wp_json_encode($uid.'_countries'); ?>,k.countries||0); text(<?php echo wp_json_encode($uid.'_hotspots'); ?>,k.hotspots||0); text(<?php echo wp_json_encode($uid.'_total'); ?>,k.total||0); text(<?php echo wp_json_encode($uid.'_critical'); ?>,k.critical||0); text(<?php echo wp_json_encode($uid.'_high'); ?>,k.high||0); text(<?php echo wp_json_encode($uid.'_moderate'); ?>,k.moderate||0); text(<?php echo wp_json_encode($uid.'_low'); ?>,k.low||0); text(<?php echo wp_json_encode($uid.'_actors_count'); ?>,(d.actors||[]).length); text(<?php echo wp_json_encode($uid.'_types_count'); ?>,(d.types||[]).length); text(<?php echo wp_json_encode($uid.'_markers_count'); ?>,(d.markers||[]).length); text(<?php echo wp_json_encode($uid.'_risk_index'); ?>,k.risk_index||0); text(<?php echo wp_json_encode($uid.'_hybrid_intensity'); ?>,String(k.hybrid_intensity||0)+'%'); html(<?php echo wp_json_encode($uid.'_ticker_track'); ?>,tickerRows(d.ticker_items||[])); text(<?php echo wp_json_encode($uid.'_ticker_meta'); ?>,`${(d.ticker_items||[]).length} عنوانًا • تحديث ${when(k.updated_at||0)}`); html(<?php echo wp_json_encode($uid.'_command_brief'); ?>,commandDeck()); html(<?php echo wp_json_encode($uid.'_threat_brief'); ?>,threatDeck()); html(<?php echo wp_json_encode($uid.'_hybrid_brief'); ?>,hybridDeck()); html(<?php echo wp_json_encode($uid.'_video_overview'); ?>,videoCards(2)); html(<?php echo wp_json_encode($uid.'_video_live'); ?>,videoCards(4)); html(<?php echo wp_json_encode($uid.'_feed1'); ?>,feedRows(d.feed||[])); html(<?php echo wp_json_encode($uid.'_regions'); ?>,rankRows(d.regions||[])); html(<?php echo wp_json_encode($uid.'_actors'); ?>,rankRows(d.actors||[])); html(<?php echo wp_json_encode($uid.'_actors_live'); ?>,rankRows(d.actors||[])); html(<?php echo wp_json_encode($uid.'_types_list'); ?>,rankRows(d.types||[])); html(<?php echo wp_json_encode($uid.'_types_live'); ?>,rankRows(d.types||[])); html(<?php echo wp_json_encode($uid.'_regions_analysis'); ?>,rankRows(d.regions||[])); text(<?php echo wp_json_encode($uid.'_sev_critical'); ?>,k.critical||0); text(<?php echo wp_json_encode($uid.'_sev_high'); ?>,k.high||0); text(<?php echo wp_json_encode($uid.'_sev_moderate'); ?>,k.moderate||0); text(<?php echo wp_json_encode($uid.'_sev_low'); ?>,k.low||0); text(<?php echo wp_json_encode($uid.'_risk_level'); ?>,riskLabel(k.risk_index||0)); text(<?php echo wp_json_encode($uid.'_top_hybrid'); ?>,k.top_hybrid_layer||'—'); text(<?php echo wp_json_encode($uid.'_marker_density'); ?>,Math.round(((d.markers||[]).length/Math.max(1,k.total||1))*100)+'%'); const meter=document.getElementById(<?php echo wp_json_encode($uid.'_risk_meter'); ?>); if(meter) meter.style.width=Math.max(2,Math.min(100,parseInt(k.risk_index||0,10)))+'%'; renderCharts(); renderMap(); }
      function load(days){state.days=days||state.days; const body=new URLSearchParams({action:'so_world_monitor_snapshot_hotfix',days:String(state.days)}); fetch(ajaxUrl,{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded; charset=UTF-8'},body:body.toString()}).then(r=>r.json()).then(j=>{if(j&&j.success&&j.data){state.data=j.data; renderAll();}}).catch(()=>{});}
      root.querySelectorAll('.wmv5-range').forEach(btn=>btn.addEventListener('click',function(){root.querySelectorAll('.wmv5-range').forEach(b=>b.classList.remove('is-active')); this.classList.add('is-active'); load(parseInt(this.getAttribute('data-days')||'7',10));}));
      root.querySelectorAll('.wmv5-tab').forEach(btn=>btn.addEventListener('click',function(){activateTab(this.getAttribute('data-view')||'overview');}));
      renderAll(); activateTab('all'); setInterval(function(){ load(state.days); }, <?php echo (int)$refresh * 1000; ?>);
    })();
    </script>
    <?php return (string) ob_get_clean();
}
}
